# Collector heat query lanes are auction-intake only; valuation/truth gates stay downstream.
_COLLECTOR_HEAT_QUERY_CASE_HIT_TERMS: Tuple[str, ...] = (
    "downtown", "kaboom", "color blast", "stained glass", "manga",
    "genesis", "honeycomb", "zebra", "tiger", "elephant", "peacock",
    "superfractor",
)
_COLLECTOR_HEAT_QUERY_GRADE_TERMS: Tuple[str, ...] = ("PSA 10", "BGS 10", "SGC 10")
_COLLECTOR_HEAT_QUERY_ROOKIE_TERMS: Tuple[str, ...] = ("rookie", "RC", "1st bowman", "1st chrome")
_COLLECTOR_HEAT_QUERY_SERIAL_TERMS: Tuple[str, ...] = ("/10", "/25", "/50", "/99")
_COLLECTOR_HEAT_QUERY_AUTO_TERMS: Tuple[str, ...] = ("auto", "autograph")
_COLLECTOR_HEAT_QUERY_MAX_PER_PLAYER = 3


def _collector_heat_query_catalog() -> List[Tuple[str, str]]:
    _catalog: List[Tuple[str, str]] = []
    _max_len = max(
        len(_COLLECTOR_HEAT_QUERY_CASE_HIT_TERMS),
        len(_COLLECTOR_HEAT_QUERY_GRADE_TERMS),
        len(_COLLECTOR_HEAT_QUERY_ROOKIE_TERMS),
        len(_COLLECTOR_HEAT_QUERY_AUTO_TERMS),
        len(_COLLECTOR_HEAT_QUERY_SERIAL_TERMS),
    )
    for _idx in range(_max_len):
        if _idx < len(_COLLECTOR_HEAT_QUERY_CASE_HIT_TERMS):
            _catalog.append(("case_hit", _COLLECTOR_HEAT_QUERY_CASE_HIT_TERMS[_idx]))
        if _idx < len(_COLLECTOR_HEAT_QUERY_GRADE_TERMS):
            _catalog.append(("psa10", _COLLECTOR_HEAT_QUERY_GRADE_TERMS[_idx]))
        if _idx < len(_COLLECTOR_HEAT_QUERY_ROOKIE_TERMS):
            _catalog.append(("rookie", _COLLECTOR_HEAT_QUERY_ROOKIE_TERMS[_idx]))
        if _idx < len(_COLLECTOR_HEAT_QUERY_AUTO_TERMS):
            _catalog.append(("auto", _COLLECTOR_HEAT_QUERY_AUTO_TERMS[_idx]))
        if _idx < len(_COLLECTOR_HEAT_QUERY_SERIAL_TERMS):
            _catalog.append(("serial", _COLLECTOR_HEAT_QUERY_SERIAL_TERMS[_idx]))
    return _catalog


def _collector_heat_query_player_is_elite(player_name: str, specs: List[Dict[str, Any]]) -> bool:
    _player_name = " ".join(str(player_name or "").split()).strip()
    if not _player_name:
        return False
    try:
        if int(_player_heat_tier(_player_name) or 99) in {1, 2}:
            return True
    except Exception:
        pass
    for _spec in list(specs or []):
        try:
            if int((_spec or {}).get("whatnot_tier") or 99) <= 2:
                return True
        except Exception:
            continue
    return False


def _collector_heat_product_candidates(player_specs: List[Dict[str, Any]], sport: str) -> List[str]:
    _seen: set[str] = set()
    _products: List[str] = []

    def _add_product(_product: str) -> None:
        _clean = " ".join(str(_product or "").split()).strip()
        _key = _normalize_family_probe(_clean)
        if not _clean or not _key or _key in {"other", "unknown"} or _key in _seen:
            return
        _seen.add(_key)
        _products.append(_clean)

    for _spec in list(player_specs or []):
        _add_product(
            _lane_product_family_value(_spec)
            or str((_spec or {}).get("target_product_family") or "")
            or str((_spec or {}).get("product_family") or "")
            or str((_spec or {}).get("product") or "")
        )
    for _product in _default_product_families_for_sport(str(sport or "").strip().upper()):
        _add_product(_product)
    return _products[:4]


def _build_collector_heat_query_lane(
    base_spec: Dict[str, Any],
    *,
    product_family: str,
    heat_term: str,
    reason: str,
) -> Dict[str, Any]:
    _spec = dict(base_spec or {})
    _product = " ".join(str(product_family or "").split()).strip()
    _term = " ".join(str(heat_term or "").split()).strip()
    _reason = str(reason or "").strip().lower()
    _player_name = _sanitize_query_player_name(" ".join(
        str(_spec.get("player_name") or (_spec.get("tracked_target") or {}).get("player_name") or "").split()
    ).strip())
    _sport = str(_spec.get("sport") or "").strip().upper()
    if not _player_name or not _product or not _term:
        return {}

    # ── Defensive product/parallel compatibility guard ───────────────────────
    # Belt-and-suspenders: even if a caller bypasses the cross-product loop in
    # _append_collector_heat_query_lanes, we still kill known-impossible combos
    # here before any query is built.
    if not _is_valid_product_parallel_combo(_product, _term):
        print(
            f"[INVALID_LANE_KILLED] product={_product} parallel={_term} "
            f"player={_player_name} reason=invalid_product_parallel_combo"
        )
        return {}

    _query_parts = [_player_name, _product, _term] if _reason == "case_hit" else [_player_name, _term, _product]
    _raw_query_text = " ".join(_query_parts).strip()
    _query_text = " ".join(_clean_query_tokens(_query_parts)).strip()
    if not _query_text:
        return {}
    if _raw_query_text != _query_text:
        print(f"[QUERY_CLEAN] raw={_raw_query_text} clean={_query_text}")

    _target_meta = dict(_spec.get("target_meta") or {})
    _target_meta["set_name"] = _product
    _target_meta["brand"] = str(_target_meta.get("brand") or _product)
    _target_meta["product_family"] = _product

    _tracked_target = dict(_spec.get("tracked_target") or {})
    _tracked_target["player_name"] = _player_name
    _tracked_target["product_family"] = _product
    _tracked_target["product_keywords"] = [_product]
    _tracked_target["card_keywords"] = [_term]
    _tracked_target["target_meta"] = dict(_target_meta)

    _variant_query = _apply_junk_exclusions(_query_text)
    _spec["query"] = _query_text
    _spec["seed_text"] = _query_text
    _spec["player_name"] = _player_name
    _spec["sport"] = _sport
    _spec["tracked_target"] = _tracked_target
    _spec["target_meta"] = dict(_target_meta)
    _spec["target_label"] = f"{_player_name} | {_product} | collector heat {_term}"
    _spec["lane_product"] = _product
    _spec["target_product_family"] = _product
    _spec["product_family"] = _product
    _spec["product"] = _product
    _spec["lane_subset"] = ""
    _spec["subset_name"] = ""
    _spec["lane_parallel"] = ""
    _spec["parallel_name"] = ""
    _spec["parallel_bucket"] = ""
    _spec["subset_binding_override"] = False
    _spec["subset_product_family"] = ""
    _spec["query_kind"] = f"collector_heat_{_reason}"
    _spec["target_lane_type"] = "collector_heat"
    _spec["query_contract_type"] = "collector_heat_auction"
    _spec["lane_tier"] = "primary"
    _spec["lane_augmented"] = True
    _spec["premium_lane_allowed"] = True
    _spec["spec_premium_lane"] = True
    _spec["spec_lane_class"] = "collector_heat"
    _spec["_intake_type"] = "collector_heat"
    _spec["_collector_heat_query"] = True
    _spec["_collector_heat_query_reason"] = _reason
    _spec["_collector_heat_query_term"] = _term
    _spec["listing_mode"] = "auction"
    _spec["buying_options"] = ["AUCTION"]
    _spec["query_variants"] = [{
        "variant_name": f"collector_heat_{_reason}",
        "query": _variant_query,
        "relax_parallel": True,
        "recall_stage": "collector_heat",
        "query_spec_quality_score": 70,
    }]
    _heat_score = float(_endgame_lane_score(_query_text))
    _spec["endgame_lane_score"] = int(max(float(_spec.get("endgame_lane_score") or 0.0), _heat_score))
    _spec["premium_lane_priority"] = max(float(_spec.get("premium_lane_priority") or 0.0), 34.0 + _heat_score)
    _spec["lane_priority"] = max(float(_spec.get("lane_priority") or 0.0), 34.0 + _heat_score)
    return _spec


def _append_collector_heat_query_lanes(specs: List[Dict[str, Any]]) -> Tuple[List[Dict[str, Any]], Dict[str, int]]:
    _summary = {
        "players": 0,
        "queries_added": 0,
        "case_hit": 0,
        "psa10": 0,
        "rookie": 0,
        "auto": 0,
        "serial": 0,
    }
    _catalog = _collector_heat_query_catalog()
    if not specs or not _catalog:
        print("[HEAT_QUERY_SUMMARY] players=0 queries_added=0 case_hit=0 psa10=0 rookie=0 auto=0 serial=0")
        return list(specs or []), _summary

    _existing_queries = {
        _normalized_query_text(str((_spec or {}).get("query") or ""))
        for _spec in list(specs or [])
        if str((_spec or {}).get("query") or "").strip()
    }
    _grouped: Dict[Tuple[str, str], List[Dict[str, Any]]] = {}
    for _spec in list(specs or []):
        _player = " ".join(str((_spec or {}).get("player_name") or "").split()).strip()
        _sport = str((_spec or {}).get("sport") or "").strip().upper()
        if not _player or not _sport:
            continue
        _grouped.setdefault((_player, _sport), []).append(_spec)

    _cycle = int(time.time() // max(1, int(_ES_ROTATION_INTERVAL_SECS or 300)))
    _added_specs: List[Dict[str, Any]] = []
    _global_reduction_before = 0
    _global_reduction_after = 0
    _global_kill_count = 0
    for (_player_name, _sport), _player_specs in sorted(_grouped.items(), key=lambda item: (item[0][1], item[0][0])):
        if not _collector_heat_query_player_is_elite(_player_name, _player_specs):
            continue
        _products = _collector_heat_product_candidates(_player_specs, _sport)
        if not _products:
            continue
        _base_spec = dict(_player_specs[0] or {})
        _candidates_raw: List[Tuple[str, str, str]] = []
        for _product in _products:
            for _reason, _term in _catalog:
                _candidates_raw.append((_product, _reason, _term))
        # ── Kill impossible product/parallel combos before query creation ──
        _candidates: List[Tuple[str, str, str]] = []
        _before_count = len(_candidates_raw)
        for _product, _reason, _term in _candidates_raw:
            # Only validate parallel-style terms (case_hit / serial); leave
            # generic recall terms (rookie, psa10, auto) to pass through —
            # the universal-term whitelist inside the validator covers them.
            if not _is_valid_product_parallel_combo(_product, _term):
                _global_kill_count += 1
                print(
                    f"[INVALID_LANE_KILLED] product={_product} parallel={_term} "
                    f"player={_player_name} reason=invalid_product_parallel_combo"
                )
                continue
            _candidates.append((_product, _reason, _term))
        _after_count = len(_candidates)
        _global_reduction_before += _before_count
        _global_reduction_after += _after_count
        if not _candidates:
            continue
        _rotation_seed = sum(ord(_ch) for _ch in f"{_sport}:{_player_name}".lower())
        _start = (_cycle + _rotation_seed) % len(_candidates)
        _rotated = _candidates[_start:] + _candidates[:_start]
        _added_for_player = 0
        for _product, _reason, _term in _rotated:
            if _added_for_player >= _COLLECTOR_HEAT_QUERY_MAX_PER_PLAYER:
                break
            _heat_spec = _build_collector_heat_query_lane(
                _base_spec,
                product_family=_product,
                heat_term=_term,
                reason=_reason,
            )
            _qkey = _normalized_query_text(str((_heat_spec or {}).get("query") or ""))
            if not _heat_spec or not _qkey or _qkey in _existing_queries:
                continue
            _existing_queries.add(_qkey)
            _added_specs.append(_heat_spec)
            _added_for_player += 1
            _summary["queries_added"] += 1
            _summary[_reason] = int(_summary.get(_reason) or 0) + 1
            print(
                f"[HEAT_QUERY_EXPANSION] player={_player_name} "
                f"sport={_sport} query={str(_heat_spec.get('query') or '')} reason={_reason}"
            )
        if _added_for_player:
            _summary["players"] += 1

    print(
        f"[HEAT_QUERY_SUMMARY] players={_summary['players']} "
        f"queries_added={_summary['queries_added']} "
        f"case_hit={_summary['case_hit']} "
        f"psa10={_summary['psa10']} "
        f"rookie={_summary['rookie']} "
        f"auto={_summary['auto']} "
        f"serial={_summary['serial']}"
    )
    print(
        f"[SYNTHETIC_LANE_REDUCTION] before={_global_reduction_before} "
        f"after={_global_reduction_after} killed={_global_kill_count}"
    )
    return list(specs or []) + _added_specs, _summary


