def _emit_runtime_func_stamp(fn_name: str) -> None:
    _fn = str(fn_name or "").strip()
    if not _fn or _fn in _RUNTIME_FUNC_STAMPS_EMITTED:
        return
    _RUNTIME_FUNC_STAMPS_EMITTED.add(_fn)
    print(f"[ES_FUNC_STAMP] fn={_fn} build={RUNTIME_BUILD_STAMP}")

# Controlled family-executor batch size.
# Reduced to 2 so the active future count stays at 4 per batch (2 families ×
# auction + BIN).  Surviving eBay rate limits requires staying well below
# burst threshold; speed is secondary to retrieval survival.
_FAMILY_BATCH_SIZE  = 4

# ---------------------------------------------------------------------------
# Proof-of-life (POL) warmup mode
# ---------------------------------------------------------------------------
# Fully serial, single-lane scan capped at _POL_MAX_FAMILIES families.
# Purpose: verify eBay Browse API returns any listings at all before re-enabling
# the batched parallel executor.
# Set _POL_MODE = False to restore the normal batched-executor path.
