def _detect_case_hit(title: str) -> Tuple[bool, str]:
    """
    Returns (is_case_hit, matched_token). Used by `_tb_row_is_premium` and
    `_prepare_target_admission_check` to flag rows whose titles contain any
    confirmed case-hit insert name. Caller emits [CASE_HIT_DETECTED] log.
    """
    if not title:
        return False, ""
    try:
        _m = _CASE_HIT_TOKENS_PATTERN.search(title)
        if _m:
            return True, str(_m.group(0)).strip()
    except Exception:
        pass
    return False, ""


# DEFENSIVE-PATCH (PHASE-1) — Title-based premium parallel/insert pattern.
# Closes the false-negative class observed across four PREPARE scans where
# rows had clean identity but hydration left insert_family / parallel_family
# / serial_denominator empty even when the title plainly named a premium
# parallel ("Holo Prizm", "Silver Prizm", "Topps Chrome Black", "Chain
# Reaction") or insert ("Tuddys", "Dingers", "Stars Prizm").
#
# Domain note: in the Panini parallel hierarchy, "Holo" (Optic) and "Silver
# Prizm" (Prizm) are both *parallels* — rarer pulls than the unadorned base
# card, which is just the regular un-modified Donruss Optic / Panini Prizm.
# This matches parallel_vocab.PARALLEL_PHRASES_BY_SET which already treats
# them as parallels. Earlier draft of this regex deliberately omitted them
# under a mistaken assumption that they were base; corrected 2026-05-06.
#
# Curated against PREPARE_TARGET_REJECT samples for Bo Nix, Anthony Edwards,
# Gunnar Henderson, James Wood, Jalen Walker, Aidan Hutchinson, Jason Taylor,
# Pete Crow-Armstrong, Brock Bowers, Jackson Holliday. Coverage widens as new
# false negatives surface in scan logs.
_PREMIUM_INSERT_PARALLEL_TITLE_PATTERN = re.compile(
    r"\b("
    # Premium parallel name keywords — universally non-base
    r"refractor|x[\s\-]?fractor|superfractor|sapphire|atomic|cosmic|"
    r"cracked\s+ice|press\s+proof|shimmer|"
    # Holo and silver-prizm parallel families. Both are confirmed parallels
    # (NOT base) per Panini hierarchy and per parallel_vocab.py.
    r"holo(?:graphic)?(?:\s+(?:prizm|optic|silver|gold))?|"
    r"(?:prizm|optic)\s+holo|"
    r"(?:true\s+)?silver\s+prizm|prizm\s+silver|"
    # Unprefixed parallel names that are followed (or preceded) by "prizm" /
    # "optic" — e.g. "Lazer Prizm", "Hyper Prizm", "Pulsar Prizm", "Disco
    # Prizm", "Wave Prizm", "Mojo Prizm", "Lava Prizm".
    r"(?:lazer|laser|hyper|pulsar|disco|wave|mojo|lava|reactive|fast\s*break)"
    r"\s+(?:prizm|optic)|"
    r"(?:prizm|optic)\s+"
    r"(?:lazer|laser|hyper|pulsar|disco|wave|mojo|lava|reactive|fast\s*break)|"
    # Color-prefixed parallel families. Color must be paired with a parallel-
    # name word so generic color words alone (e.g. "blue" in a team name) do
    # not match.
    r"(?:red|blue|green|orange|purple|pink|gold|black|sepia|teal|"
    r"neon\s+(?:red|blue|green|orange|pink|purple))"
    r"\s+(?:wave|mojo|lava|pulsar|hyper|laser|lazer|disco|ice|fractor|"
    r"reactive|swirl|scope|fast\s*break|cracked\s*ice|refractor|prizm)|"
    # Topps Chrome premium parallels
    r"chrome\s+(?:black|gold|orange|red|sepia|wave|x[\s\-]?fractor|"
    r"sapphire|atomic|cosmic)|"
    # Curated premium insert names — confirmed against Beckett, Topps Ripped,
    # Cardlines for late-2024 / 2025 product releases. Each token is a named
    # insert that does not exist as a base card.
    r"chain\s+reaction|stars\s+prizm|color\s+blast|stained\s+glass|"
    r"splash|color\s+rush|fireworks|future\s+stars|new\s+age|pop\s+stars|"
    r"disco\s+inferno|action\s+packed|net\s+marvels|my\s+house|"
    r"express\s+lane|lights\s+out|rising\s+suns|tuddys|dingers|"
    r"instant\s+impact|shadow\s+etch|night\s+terrors|young\s+guns|"
    r"hometown\s+heroes|electric|emoji"
    r")\b",
    re.IGNORECASE,
)


def _detect_premium_insert_parallel_in_title(title: str) -> Tuple[bool, str]:
    """
    Returns (matched, matched_token). DEFENSIVE-PATCH (PHASE-1): used by the
    prepare-target admission contract as a third title-rescue path alongside
    `_has_serial_in_title` and `_has_grade_in_title`. Matches only when the
    title contains a parallel/insert keyword that virtually never appears on
    base cards.
    """
    if not title:
        return False, ""
    try:
        _m = _PREMIUM_INSERT_PARALLEL_TITLE_PATTERN.search(title)
        if _m:
            return True, str(_m.group(0)).strip().lower()
    except Exception:
        pass
    return False, ""


