def _is_valid_product_parallel_combo(product: Any, parallel: Any) -> bool:
    """Return False when the (product, parallel) combo is known-impossible.

    Strategy:
      1. Normalize both values to lowercase, single-spaced strings.
      2. Empty inputs are allowed (caller upstream handles missing data).
      3. Universal terms (auto, rookie, PSA 10, generic serial counts, etc.)
         are always allowed.
      4. If the parallel is product-exclusive, the product must contain one
         of the owning families.
      5. If the product is in the strict whitelist, the parallel must appear
         in that product's allowed set (substring match either direction so
         compound terms like "patch auto" match "auto").
      6. Otherwise (unknown product, non-exclusive parallel) — allow.
    """
    try:
        _p = " ".join(str(product or "").lower().split()).strip()
        _t = " ".join(str(parallel or "").lower().split()).strip()
    except Exception:
        return True
    if not _p or not _t:
        return True
    if _t in _UNIVERSAL_PARALLEL_TERMS:
        return True

    _excl_owners = _PARALLEL_PRODUCT_EXCLUSIVE.get(_t)
    if _excl_owners is not None:
        for _owner in _excl_owners:
            if _owner and (_owner in _p or _p in _owner):
                return True
        return False

    for _key, _allowed in _PRODUCT_PARALLEL_COMPATIBILITY.items():
        if _key and _key in _p:
            if _t in _allowed:
                return True
            for _a in _allowed:
                if _a and (_a in _t or _t in _a):
                    return True
            return False

    return True


