# ---------------------------------------------------------------------------
# PATCH 1 — Hard Product Tier System
# Classifies rows into ENDGAME / PREMIUM / MID / LOW.
# ENDGAME: cross-product SSPs, gold /10, logoman, superfractor
# PREMIUM: top products (Prizm, NT, Immaculate, Spectra…) with premium signals
# MID:     Mosaic, Donruss, Chronicles (base/common parallel)
# LOW:     generic base, paper, non-premium inserts
# ---------------------------------------------------------------------------
_PRODUCT_TIER_ENDGAME_KEYWORDS: frozenset = frozenset({
    "kaboom", "downtown", "color blast", "stained glass", "manga",
    "gold vinyl", "logoman", "superfractor",
})
_PRODUCT_TIER_PREMIUM_PRODUCTS: frozenset = frozenset({
    "national treasures", "flawless", "immaculate", "spectra",
    "prizm", "optic", "select", "contenders",
    "topps chrome", "bowman chrome", "absolute", "certified",
})
_PRODUCT_TIER_MID_PRODUCTS: frozenset = frozenset({
    "mosaic", "donruss", "chronicles",
})
# Any of these in the title upgrades a premium/mid product row to PREMIUM tier
_PRODUCT_TIER_PREMIUM_SIGNALS: frozenset = frozenset({
    "auto", "gold prizm", "gold refractor", "silver prizm", "silver",
    "refractor", "holo", "mojo", "neon", "nebula",
    "peacock", "reactive", "genesis", "honeycomb",
    "cracked ice", "tie dye", "field level", "premier level",
    "zebra", "numbered",
})


def _classify_product_tier(row: Dict[str, Any]) -> str:
    """Return ENDGAME / PREMIUM / MID / LOW for a board row."""
    _title = str(row.get("source_title") or row.get("title") or "").lower()
    _lane_product = str(
        row.get("lane_product") or row.get("target_product_family")
        or row.get("product_family") or ""
    ).lower()
    _subset = str(row.get("lane_subset") or row.get("subset_name") or "").lower()
    _scarcity = str(row.get("scarcity_class") or "").lower()
    _serial_raw = str(row.get("serial") or row.get("serial_denominator") or "").strip()

    # ENDGAME: iconic cross-product SSP subsets
    for _kw in _PRODUCT_TIER_ENDGAME_KEYWORDS:
        if _kw in _title or _kw in _subset:
            return "ENDGAME"

    # ENDGAME: serials ≤10 or SSP scarcity class
    if _serial_raw:
        try:
            _m = re.search(r"\d+", _serial_raw)
            if _m and int(_m.group()) <= 10:
                return "ENDGAME"
        except Exception:
            pass
    if _scarcity == "ssp_insert":
        return "ENDGAME"

    # PREMIUM products with premium signals, auto, or serial
    _has_auto = "auto" in _title
    _has_serial = bool(_serial_raw)
    _has_premium_signal = any(_sig in _title for _sig in _PRODUCT_TIER_PREMIUM_SIGNALS)
    for _pk in _PRODUCT_TIER_PREMIUM_PRODUCTS:
        if _pk in _lane_product or _pk in _title:
            if _has_auto or _has_serial or _has_premium_signal:
                return "PREMIUM"
            # Premium product but bare base card
            return "MID"

    # MID: Mosaic/Donruss/Chronicles
    for _mk in _PRODUCT_TIER_MID_PRODUCTS:
        if _mk in _lane_product or _mk in _title:
            if _has_auto or _has_serial or _has_premium_signal:
                return "PREMIUM"
            return "MID"

    # LOW: everything else
    return "LOW"


def _lane_spec_product_tier(spec: Dict[str, Any]) -> str:
    """Return ENDGAME / PREMIUM / MID / LOW for a target lane spec."""
    _lane_product = str(spec.get("lane_product") or spec.get("target_product_family") or spec.get("product_family") or "").lower()
    _lane_subset = str(spec.get("lane_subset") or "").lower()
    _lane_type = str(spec.get("target_lane_type") or "").lower()

    if _lane_subset in _PRODUCT_TIER_ENDGAME_KEYWORDS:
        return "ENDGAME"
    if _lane_type in {"premium_subset", "ssp_case_hit"}:
        return "ENDGAME"
    if _lane_type == "auto":
        for _pk in _PRODUCT_TIER_PREMIUM_PRODUCTS:
            if _pk in _lane_product:
                return "PREMIUM"
        return "PREMIUM"
    for _pk in _PRODUCT_TIER_PREMIUM_PRODUCTS:
        if _pk in _lane_product:
            if _lane_type in {"premium_parallel", "serial_parallel"}:
                return "PREMIUM"
            return "MID"
    for _mk in _PRODUCT_TIER_MID_PRODUCTS:
        if _mk in _lane_product:
            return "MID"
    return "LOW"


