def _is_premium_card(row: Dict[str, Any]) -> bool:
    _row = dict(row or {})
    _title = " ".join(
        str(_part or "").strip().lower()
        for _part in [
            _row.get("title"),
            _row.get("source_title"),
            _row.get("subset_name"),
            _row.get("lane_subset"),
            _row.get("parallel_name"),
            _row.get("parallel"),
            _row.get("product_family"),
            _row.get("target_product_family"),
            _row.get("lane_product"),
        ]
        if str(_part or "").strip()
    )
    _premium_signals = [
        "rpa", "patch", "auto", "autograph",
        "/25", "/10", "/5", "1/1",
        "kaboom", "downtown", "color blast",
        "national treasures", "nt",
        "immaculate", "flawless", "spectra",
    ]
    return any(_signal in _title for _signal in _premium_signals)


