def _fallback_promotion_eligible(row: Dict[str, Any]) -> bool:
    """
    Returns True if a row with fallback/anchor MV has enough structural signal
    to warrant SPECULATIVE promotion to the board.

    This opens a SECOND promotion path alongside strict comp-backed MV.
    It does NOT weaken comp matching — it activates only when comps fail.

    Qualifying signals (any one is sufficient):
      1. Serial numbered (any /XX)
      2. Recognized premium player
      3. Recognized premium product family
      4. Auction price >= 40% below estimated anchor
    """
    _row = dict(row or {})
    _src = str(_row.get("mv_source") or _row.get("market_value_source") or "").strip().lower()
    # Only activate for fallback/anchor rows — strong comp-backed rows don't need this path
    _is_fallback_src = (
        _src in {"price_anchor_fallback", "structured_fallback", "fallback_comp_support",
                 "near_family_support", "soft_watchlist_estimate", "none", ""}
        or "fallback" in _src
    )
    if not _is_fallback_src:
        return False

    _title = str(_row.get("title") or _row.get("source_title") or "").lower()
    _player = str(_row.get("player_name") or _row.get("target_player_name") or "").lower().strip()
    _product = str(_row.get("product_family") or _row.get("target_product_family") or _row.get("lane_product") or "").lower()

    # Signal 1: serial numbered (any /XX in title or structured field)
    _serial_str = str(_row.get("serial") or _row.get("serial_denominator") or "").strip()
    _has_serial = (
        bool(_serial_str)
        or any(_s in _title for _s in (
            "/1 ", "/5 ", "/10 ", "/15 ", "/25 ", "/49 ", "/50 ",
            "/75 ", "/99 ", "/100 ", "/150 ", "/199 ", "/250 ",
        ))
    )
    if _has_serial:
        return True

    # Signal 2: recognized premium player
    _player_tokens = {_t.strip() for _t in _player.split() if len(_t.strip()) >= 3}
    _has_premium_player = (
        any(_p in _player for _p in _FALLBACK_PROMO_PLAYERS)
        or any(_p in _title for _p in _FALLBACK_PROMO_PLAYERS)
        or bool(_player_tokens.intersection(_FALLBACK_PROMO_PLAYERS))
    )
    if _has_premium_player:
        return True

    # Signal 3: recognized premium product family
    _has_premium_product = (
        any(_prod in _product for _prod in _FALLBACK_PROMO_PRODUCTS)
        or any(_prod in _title for _prod in _FALLBACK_PROMO_PRODUCTS)
    )
    if _has_premium_product:
        return True

    # Signal 4: >= 40% price gap vs anchor estimate
    _current_price = float(_row.get("current_price") or _row.get("current_bid") or 0.0) or 0.0
    _anchor = (
        float(_row.get("review_estimate_value") or 0.0)
        or float(_row.get("anchored_estimate_value") or 0.0)
        or float(_row.get("market_value") or 0.0)
        or float(_row.get("market_value_raw") or 0.0)
    ) or 0.0
    if _anchor > 0 and _current_price > 0 and ((_anchor - _current_price) / _anchor) >= 0.40:
        return True

    return False


def _is_memorabilia_junk(row: Dict[str, Any]) -> Tuple[bool, str]:
    """Return (is_junk, reason). True for generic memorabilia lanes that are not true chase cards."""
    _fake_serial_structural_block, _fake_serial_structural_reason = _is_fake_serial_base_promo_row(row)
    if _fake_serial_structural_block and not bool(row.get("identity_is_clean") or row.get("_hydrated_identity_is_clean")):
        row["identity_clean_reason"] = str(row.get("identity_clean_reason") or "fake_serial_base_promo")
    _early_title = str(row.get("source_title") or row.get("title") or "").strip().lower()
    _early_parallel = str(row.get("parallel_family") or row.get("_hydrated_parallel_family") or "").strip().lower()
    _early_insert = str(row.get("insert_family") or row.get("_hydrated_insert_family") or "").strip().lower()
    if (
        "draft selections memorabilia" in _early_title
        and re.search(r"/\s*(?:25|50|99)\b", _early_title)
        and "auto" not in _early_title
        and "autograph" not in _early_title
        and _early_parallel in {"", "base", "none"}
        and not _early_insert
        and not bool(row.get("identity_is_clean") or row.get("_hydrated_identity_is_clean"))
    ):
        row["identity_clean_reason"] = str(row.get("identity_clean_reason") or "fake_serial_base_promo")
    if _apply_fake_serial_base_promo_hard_block(row, stage="memorabilia_junk_override", junk_override_allowed=0):
        return True, "fake_serial_base_promo"
    _title = str(row.get("source_title") or row.get("title") or "").lower()
    _title_padded = f" {_title} "
    _serial_raw = str(row.get("serial") or row.get("serial_denominator") or "").strip()
    _product = str(
        row.get("product_family") or row.get("target_product_family") or row.get("lane_product") or ""
    ).lower()
    _player = str(row.get("player_name") or row.get("target_player_name") or "").lower().strip()
    _has_mem_term = any(_jt in _title_padded for _jt in _MEMORABILIA_JUNK_TERMS)
    if not _has_mem_term:
        return False, ""

    _has_auto = any(_ov in _title_padded for _ov in (" auto ", " autograph ", " patch auto ", " auto patch ", " rpa ", " auto rpa "))
    _has_patch_auto = any(_ov in _title_padded for _ov in (" patch auto ", " auto patch ", " rpa ", " auto rpa ", " rookie patch autograph "))
    _has_iconic_mem = any(_ov in _title_padded for _ov in _MEMORABILIA_ICONIC_CHASE_TERMS)
    _has_patch_term = " patch " in _title_padded
    _is_veteran_player = any(_v in _player for _v in _VETERAN_STAR_PLAYERS)
    _is_premium_product = any(_pk in _product for _pk in _PRODUCT_TIER_PREMIUM_PRODUCTS) or any(_pk in _title for _pk in _PRODUCT_TIER_PREMIUM_PRODUCTS)

    # Serial denominator
    _serial_den = _extract_serial_ceiling(f"{_serial_raw} {_title}") or 0
    _low_numbered_premium_patch = bool(
        _has_patch_term
        and _serial_den > 0
        and _serial_den <= 25
        and _is_premium_product
        and " materials " not in _title_padded
        and " material " not in _title_padded
        and " jersey " not in _title_padded
        and " relic " not in _title_padded
        and " mem " not in _title_padded
        and " memorabilia " not in _title_padded
    )

    # Check for override terms first
    for _ov in _MEMORABILIA_JUNK_OVERRIDE_TERMS:
        if _ov in _title_padded:
            return False, ""
    if _has_iconic_mem:
        return False, ""

    if _has_patch_auto:
        return False, ""
    if _has_auto and _serial_den > 0 and _serial_den <= 50:
        return False, ""
    if _is_veteran_player:
        if _is_premium_card(row):
            if _apply_fake_serial_base_promo_hard_block(row, stage="junk_override_veteran", junk_override_allowed=0):
                return True, "fake_serial_base_promo"
            print(f"[JUNK_OVERRIDE] Keeping premium card: {row.get('title')}")
            return False, ""
        return True, "generic_mem_junk"
    if _low_numbered_premium_patch:
        return False, ""

    if _is_premium_card(row):
        if _apply_fake_serial_base_promo_hard_block(row, stage="junk_override_premium", junk_override_allowed=0):
            return True, "fake_serial_base_promo"
        print(f"[JUNK_OVERRIDE] Keeping premium card: {row.get('title')}")
        return False, ""
    return True, "generic_mem_junk"


def _is_veteran_non_chase(row: Dict[str, Any]) -> Tuple[bool, str]:
    """
    Return (is_veteran_non_chase, reason).
    True for veteran star rows that lack endgame class signals.
    """
    _player = str(row.get("player_name") or row.get("target_player_name") or "").lower().strip()
    if not any(_v in _player for _v in _VETERAN_STAR_PLAYERS):
        return False, ""

    _title = str(row.get("source_title") or row.get("title") or "").lower()
    _serial_raw = str(row.get("serial") or row.get("serial_denominator") or "").strip()
    _scarcity = str(row.get("scarcity_class") or "").lower()
    _subset = str(row.get("subset_name") or row.get("lane_subset") or "").lower()
    _endgame_tier = str(row.get("endgame_tier") or "").lower()

    # Already classified endgame → allow
    if _endgame_tier == "endgame":
        return False, ""

    # Has endgame subset → allow
    if _subset and _ENDGAME_SUBSET_REGISTRY.get(_subset, {}).get("endgame"):
        return False, ""
    for _kw in _PRODUCT_TIER_ENDGAME_KEYWORDS:
        if _kw in _title:
            return False, ""

    # Has auto → allow (autograph cards are valid)
    _has_auto = "auto" in _title or "autograph" in _title
    if _has_auto:
        return False, ""

    # Has rare serial ≤99 → allow
    if _serial_raw:
        _m = re.search(r"[/\\]?(\d+)", _serial_raw)
        if _m and int(_m.group(1)) <= 99:
            return False, ""

    # SSP scarcity → allow
    if _scarcity in {"ssp_insert", "ssp", "case_hit"}:
        return False, ""

    return True, f"veteran_non_chase:{_player}"


def _is_plain_parallel_without_endgame_support(row: Dict[str, Any]) -> Tuple[bool, str]:
    _r = row or {}
    _title = str(_r.get("source_title") or _r.get("title") or "").lower()
    _parallel = str(_r.get("parallel_name") or _r.get("parallel") or _r.get("parallel_bucket") or "").lower()
    _subset = str(_r.get("subset_name") or _r.get("lane_subset") or "").lower()
    _product = str(_r.get("product_family") or _r.get("target_product_family") or _r.get("lane_product") or "").lower()
    _serial_raw = str(_r.get("serial") or _r.get("serial_denominator") or "").strip()
    _scarcity = str(_r.get("scarcity_class") or "").lower()
    _endgame_tier = str(_r.get("endgame_tier") or "").lower()
    _player_name = str(_r.get("player_name") or _r.get("target_player_name") or "").strip()
    _comp_count = int(_r.get("comp_count") or _r.get("mv_comp_count") or _r.get("comps") or 0)
    _text = f" {_title} {_parallel} {_subset} "
    _has_plain_parallel = any(_tok in _text for _tok in _ELITE_PLAIN_PARALLEL_TERMS)
    if not _has_plain_parallel:
        return False, ""

    _has_auto = any(_tok in _text for _tok in (" auto ", " autograph ", " patch auto ", " rpa "))
    _has_endgame_subset = any(_tok in _subset or _tok in _title for _tok in _ELITE_ENDGAME_SUBSET_KEYWORDS)
    _serial_cap = _extract_serial_ceiling(f"{_serial_raw} {_text}")
    _has_serial = bool(_serial_raw or _serial_cap > 0)
    _rookie_signal = any(_tok in _text for _tok in (" rookie ", " rc ", " rookie card ", " prospect ", " debut "))
    _tier_a_product = any(str(_p).lower() in _product for _p in _ELITE_PRODUCT_TIER_A)
    _young_high_demand = _player_heat_tier(_player_name) in {1, 2}
    _strong_comp_depth = _comp_count >= 4
    _scarce = _scarcity in {"ssp", "ssp_insert", "case_hit", "rare_parallel"}
    _strong_color = any(_tok in _text for _tok in _ELITE_COLOR_SIGNAL_TERMS)

    if _has_auto or _has_serial or _has_endgame_subset or _scarce or _strong_color:
        return False, ""
    if _rookie_signal and _tier_a_product and _young_high_demand:
        return False, ""
    if _endgame_tier in {"endgame", "premium_secondary"} and _strong_comp_depth:
        return False, ""
    return True, "plain_parallel_without_endgame_support"


def _classify_true_chase_class(row: Dict[str, Any]) -> Tuple[str, List[str]]:
    """
    PATCH 1 — True Chase Class Classifier.

    Returns:
        (chase_class, reasons)

    chase_class in:
        'ENDGAME_CHASE'       — SSP subsets, patch autos, serial ≤99, ultra-rares
        'PREMIUM_SECONDARY'   — autos (no rare serial), /100-/499, premium parallels
        'GENERIC_PREMIUM_JUNK'— inserts in premium products, generic mem, veteran filler
        'COMMODITY'           — base, common inserts, cheap paper

    This sits ABOVE product_tier. A National Treasures jersey (no auto, no rare serial)
    is GENERIC_PREMIUM_JUNK regardless of brand prestige.
    """
    _r = row or {}
    _title = " " + str(_r.get("source_title") or _r.get("title") or "").lower() + " "
    _subset = str(_r.get("subset_name") or _r.get("lane_subset") or "").lower().replace("_", " ").strip()
    _product = str(
        _r.get("product_family") or _r.get("target_product_family")
        or _r.get("lane_product") or _r.get("product") or ""
    ).lower().strip()
    _parallel = str(
        _r.get("parallel_name") or _r.get("parallel")
        or _r.get("parallel_bucket") or ""
    ).lower().strip()
    _serial_raw = str(_r.get("serial") or _r.get("serial_denominator") or "").strip()
    _scarcity = str(_r.get("scarcity_class") or "").lower()
    _product_tier = str(_r.get("product_tier") or "").upper()
    _endgame_tier = str(_r.get("endgame_tier") or "").lower()

    reasons: List[str] = []

    # Serial denominator extraction
    _serial_den = 9999
    _has_serial = bool(_serial_raw and _serial_raw not in {"0", "none", "n/a", ""})
    if _has_serial:
        _m = re.search(r"[/\\]?(\d+)", _serial_raw)
        if _m:
            _serial_den = int(_m.group(1))

    _has_auto = "auto" in _title or "autograph" in _title
    _has_patch_auto = ("patch auto" in _title or "rpa" in _title
                       or "auto rpa" in _title or "auto patch" in _title)
    _is_ultra_premium = any(_t in _product for _t in _ULTRA_PREMIUM_PRODUCTS) or any(_t in _title for _t in _ULTRA_PREMIUM_PRODUCTS)
    _is_ssp = _scarcity in {"ssp_insert", "ssp", "case_hit"}

    # ── Memorabilia junk check (PATCH 2) ──────────────────────────────────────
    _mem_junk, _mem_reason = _is_memorabilia_junk(_r)
    if _mem_junk:
        reasons.append(_mem_reason)
        return "GENERIC_PREMIUM_JUNK", reasons

    # ── Insert junk taxonomy (PATCH 4) ───────────────────────────────────────
    for _jt in _INSERT_JUNK_TAXONOMY:
        if _jt in _title or _jt in _subset:
            # No rescue unless serial ≤25 or strong scarcity signal
            if not (_serial_den <= 25 or _is_ssp or _has_patch_auto):
                reasons.append(f"insert_junk:{_jt}")
                return "GENERIC_PREMIUM_JUNK", reasons

    # ── Veteran non-chase check (PATCH 3) ────────────────────────────────────
    _vet_block, _vet_reason = _is_veteran_non_chase(_r)
    if _vet_block:
        reasons.append(_vet_reason)
        return "GENERIC_PREMIUM_JUNK", reasons

    # ── Junk product families without premium card signals ────────────────────
    for _jf in _JUNK_PRODUCT_FAMILIES:
        if _jf in _product or _jf in _title:
            if not (_has_auto or _has_serial or _is_ssp):
                reasons.append(f"junk_product_family:{_jf}")
                return "GENERIC_PREMIUM_JUNK", reasons

    # ── ENDGAME_CHASE ─────────────────────────────────────────────────────────
    # 1. Endgame subset (kaboom, downtown, color blast, etc.)
    if _subset and _ENDGAME_SUBSET_REGISTRY.get(_subset, {}).get("endgame"):
        reasons.append(f"endgame_subset:{_subset}")
        return "ENDGAME_CHASE", reasons
    for _kw in _PRODUCT_TIER_ENDGAME_KEYWORDS:
        if _kw in _title:
            reasons.append(f"endgame_keyword:{_kw}")
            return "ENDGAME_CHASE", reasons

    # 2. SSP/case-hit scarcity class
    if _is_ssp:
        reasons.append("ssp_case_hit")
        return "ENDGAME_CHASE", reasons

    # 3. Serial ≤99 (true rarity)
    if _has_serial and _serial_den <= 99:
        reasons.append(f"serial_rare:{_serial_den}")
        return "ENDGAME_CHASE", reasons

    # 4. Patch auto in premium product (true collector target)
    if _has_patch_auto and (_is_ultra_premium or _product_tier == "PREMIUM"):
        reasons.append("patch_auto_premium")
        return "ENDGAME_CHASE", reasons

    # 5. Ultra-premium product + auto + any serial
    if _is_ultra_premium and _has_auto and _has_serial:
        reasons.append("ultra_premium_auto_serial")
        return "ENDGAME_CHASE", reasons

    # ── COMMODITY ─────────────────────────────────────────────────────────────
    # Base card with no premium signal at all
    _is_base = not _parallel or _parallel in {"", "base"} or "base" in _parallel
    _has_premium_parallel = any(_t in _parallel for _t in _PREMIUM_PARALLEL_TOKENS)
    if (not _has_serial and not _has_auto and not _is_ssp
            and not _has_premium_parallel and _is_base and not _subset):
        reasons.append("base_no_premium")
        return "COMMODITY", reasons

    # Common inserts
    if any(_ci in _title for _ci in _COMMON_INSERT_TERMS):
        reasons.append("common_insert")
        return "COMMODITY", reasons

    # ── PREMIUM_SECONDARY ─────────────────────────────────────────────────────
    # Auto in good product
    if _has_auto:
        reasons.append("auto")
        return "PREMIUM_SECONDARY", reasons

    # Serial /100-/499 in premium product
    if _has_serial and _serial_den <= 499 and _product_tier in {"PREMIUM", "MID"}:
        reasons.append(f"serial_color:{_serial_den}")
        return "PREMIUM_SECONDARY", reasons

    # Premium named parallel (silver prizm, holo, etc.)
    if _has_premium_parallel and _product_tier in {"PREMIUM", "ENDGAME"}:
        reasons.append("premium_parallel")
        return "PREMIUM_SECONDARY", reasons

    # Anything else with serial
    if _has_serial and _serial_den <= 999:
        reasons.append(f"serial_any:{_serial_den}")
        return "PREMIUM_SECONDARY", reasons

    # Default: premium product filler
    if _product_tier in {"PREMIUM", "ENDGAME"}:
        reasons.append("premium_product_no_signal")
        return "GENERIC_PREMIUM_JUNK", reasons

    reasons.append("commodity_default")
    return "COMMODITY", reasons


# PATCH 7: Lane chase prior — biases cold-start lane scoring by expected card quality
def _lane_chase_prior(meta: Dict[str, Any]) -> float:
    """
    Return a cold-start prior score based on the lane's expected chase class.
    Applied in _lane_supply_score so premium subset lanes rank above junk lanes
    even before any yield history accumulates.
    """
    _lane_type = str(meta.get("target_lane_type") or "").lower()
    _lane_subset = str(meta.get("lane_subset") or "").lower()
    _lane_product = str(meta.get("lane_product") or "").lower()

    # Junk insert lanes — strong negative prior
    for _jt in _INSERT_JUNK_TAXONOMY:
        if _jt in _lane_subset:
            return -25.0

    # Junk product families
    for _jf in _JUNK_PRODUCT_FAMILIES:
        if _jf in _lane_product:
            return -15.0

    # Endgame subset lanes — strong positive prior
    if _lane_subset in _PRODUCT_TIER_ENDGAME_KEYWORDS:
        return 20.0
    if _lane_type in {"premium_subset", "ssp_case_hit"}:
        return 20.0

    # Premium auto lanes
    if _lane_type == "auto":
        for _pk in _PRODUCT_TIER_PREMIUM_PRODUCTS:
            if _pk in _lane_product:
                return 12.0
        return 8.0

    # Serial / premium parallel lanes
    if _lane_type in {"serial_parallel", "premium_parallel"}:
        for _pk in _PRODUCT_TIER_PREMIUM_PRODUCTS:
            if _pk in _lane_product:
                return 6.0
        return 2.0

    # Product base fallback — negative prior (commodity-risk lanes)
    if _lane_type in {"product_base", "broad_fallback"}:
        return -12.0

    return 0.0


