def _board_heat_mode_from_total(total_rows: int, *, updated: bool = True) -> str:
    if not updated:
        return "normal"
    return "broad_bias" if int(total_rows or 0) < _BOARD_HEAT_BROAD_THRESHOLD else "normal"


def get_recent_board_heat_state() -> Dict[str, Any]:
    with _BOARD_HEAT_LOCK:
        _state = dict(_BOARD_HEAT_STATE)
    _updated = float(_state.get("updated_at") or 0.0) > 0.0
    _rows = max(0, int(_state.get("last_total_rows") or 0))
    _state["last_total_rows"] = _rows
    _state["mode"] = _board_heat_mode_from_total(_rows, updated=_updated)
    return _state


def record_board_heat_result(
    total_rows: int,
    *,
    source: str = "streamlit_board",
    prepare: int = 0,
    monitor: int = 0,
    watch: int = 0,
) -> Dict[str, Any]:
    _rows = max(0, int(total_rows or 0))
    _mode = _board_heat_mode_from_total(_rows, updated=True)
    with _BOARD_HEAT_LOCK:
        _BOARD_HEAT_STATE.update({
            "last_total_rows": _rows,
            "mode": _mode,
            "updated_at": time.time(),
            "source": str(source or ""),
            "prepare": max(0, int(prepare or 0)),
            "monitor": max(0, int(monitor or 0)),
            "watch": max(0, int(watch or 0)),
        })
        _state = dict(_BOARD_HEAT_STATE)
    print(
        f"[BOARD_HEAT_RESULT] total_rows={_rows} mode={_mode} "
        f"threshold={_BOARD_HEAT_BROAD_THRESHOLD} source={str(source or '')} "
        f"prepare={max(0, int(prepare or 0))} monitor={max(0, int(monitor or 0))} "
        f"watch={max(0, int(watch or 0))}"
    )
    return _state


def _ending_soon_row_key(item: Dict[str, Any]) -> str:
    _iid = str((item or {}).get("item_id") or "").strip()
    if _iid:
        return f"id:{_iid}"
    _url = str((item or {}).get("url") or "").strip().lower()
    if _url:
        return f"url:{_url}"
    _title = re.sub(r"\s+", " ", str((item or {}).get("title") or "").strip().lower())[:140]
    _end = str((item or {}).get("end_iso") or "").strip()
    return f"title:{_title}|end:{_end}"


def _row_has_live_review_readiness(item: Dict[str, Any]) -> Tuple[bool, str]:
    _row = dict(item or {})
    _promotion_status = str(_row.get("premium_review_status") or "").strip().lower()
    if (
        bool(_row.get("promoted_live_candidate"))
        or bool(_row.get("mv_resolved"))
        or bool(_row.get("target_bid_ready"))
        or _promotion_status in {"resolved", "partial"}
    ):
        return True, "existing_review_ready"
    _anchor_value, _anchor_mode = _get_final_display_anchor(_row)
    _target_bid_ready = bool(_row.get("bid_ceiling_ready")) or bool(_row.get("target_bid_ready")) or _row_target_bid_ready(_row)
    if _anchor_value is None or _anchor_value <= 0:
        return False, "no_final_anchor"
    if not _target_bid_ready:
        _bid_probe = dict(_row)
        _bid_probe["market_value"] = float(_anchor_value)
        _bid_probe["mv_value"] = float(_anchor_value)
        _bid_probe["mv"] = float(_anchor_value)
        if _anchor_mode == "review_estimate":
            if not str(_bid_probe.get("valuation_confidence") or "").strip():
                _bid_probe["valuation_confidence"] = "LOW"
            if not str(_bid_probe.get("confidence") or "").strip():
                _bid_probe["confidence"] = "LOW"
            if not str(_bid_probe.get("mv_source") or _bid_probe.get("market_value_source") or "").strip():
                _bid_probe["mv_source"] = "review_estimate"
                _bid_probe["market_value_source"] = "review_estimate"
        _probe_bid, _probe_mode = _build_provisional_target_bid(_bid_probe)
        if _probe_bid is not None and _probe_bid > 0:
            if _anchor_mode == "review_estimate":
                return True, f"review_anchor_plus_bid_path:{_probe_mode}"
            if _anchor_mode == "true_market_value":
                return True, f"true_anchor_plus_bid_path:{_probe_mode}"
        return False, "no_bid_state"
    if _anchor_mode == "review_estimate":
        return True, "review_anchor_plus_bid"
    if _anchor_mode == "true_market_value":
        return True, "true_anchor_plus_bid"
    return False, "not_review_ready"


