def _normalize_geo_token(value: Any) -> str:
    _raw = str(value or "").strip()
    if not _raw:
        return ""
    return re.sub(r"[^A-Z0-9]+", " ", _raw.upper()).strip()


def _is_us_country_token(value: Any) -> bool:
    _norm = _normalize_geo_token(value)
    return _norm in _US_COUNTRY_ALIASES


def _looks_like_foreign_country_token(value: Any) -> bool:
    _raw = str(value or "").strip()
    _norm = _normalize_geo_token(_raw)
    if not _norm or _is_us_country_token(_norm):
        return False
    if _norm in {"WORLDWIDE", "INTERNATIONAL", "DOMESTIC", "NORTH AMERICA"}:
        return False
    if _norm in _FOREIGN_COUNTRY_CODES:
        return True
    _lower = _raw.lower()
    for _hint in _FOREIGN_LOCATION_HINTS:
        if re.search(rf"\b{re.escape(_hint)}\b", _lower):
            return True
    return False


def _collect_text_leaves(value: Any, *, max_depth: int = 3) -> List[str]:
    if max_depth < 0 or value is None:
        return []
    if isinstance(value, str):
        _text = value.strip()
        return [_text] if _text else []
    if isinstance(value, list):
        _out: List[str] = []
        for _entry in value:
            _out.extend(_collect_text_leaves(_entry, max_depth=max_depth - 1))
        return _out
    if isinstance(value, dict):
        _out: List[str] = []
        for _entry in value.values():
            _out.extend(_collect_text_leaves(_entry, max_depth=max_depth - 1))
        return _out
    return []


def _extract_currency_code(row: Dict[str, Any]) -> str:
    _row = row or {}
    for _key in ("currency", "currencyCode", "priceCurrency", "price_currency", "current_price_currency", "current_bid_currency"):
        _value = _row.get(_key)
        if str(_value or "").strip():
            return str(_value).strip().upper()
    for _container_key in ("price", "currentBidPrice", "bidPrice", "current_bid_price", "current_price_detail"):
        _container = _row.get(_container_key)
        if isinstance(_container, list) and _container:
            _container = _container[0]
        if not isinstance(_container, dict):
            continue
        for _field in ("currency", "currencyCode", "priceCurrency"):
            _value = _container.get(_field)
            if str(_value or "").strip():
                return str(_value).strip().upper()
    return ""


def _location_payload_text(value: Any) -> str:
    if isinstance(value, str):
        return str(value or "").strip()
    if isinstance(value, list):
        _parts: List[str] = []
        for _entry in value:
            _text = _location_payload_text(_entry)
            if _text:
                _parts.append(_text)
        return ", ".join(_parts)
    if isinstance(value, dict):
        _parts: List[str] = []
        for _field in (
            "fullLocation",
            "location",
            "city",
            "stateOrProvince",
            "stateOrProvinceName",
            "region",
            "regionName",
            "postalCode",
            "country",
            "countryCode",
        ):
            _part = str(value.get(_field) or "").strip()
            if _part:
                _parts.append(_part)
        return ", ".join(_parts)
    return ""


def _extract_listing_country(row: Dict[str, Any]) -> str:
    _row = row or {}
    for _key in ("country", "countryCode", "country_code", "listingCountry", "listingCountryCode", "itemCountry", "sellerCountry", "sellerCountryCode"):
        _value = _row.get(_key)
        if str(_value or "").strip():
            return str(_value).strip()
    for _container_key in ("itemLocation", "item_location", "sellerLocation", "seller_location"):
        _container = _row.get(_container_key)
        if isinstance(_container, list) and _container:
            _container = _container[0]
        if not isinstance(_container, dict):
            continue
        for _field in ("country", "countryCode", "country_code"):
            _value = _container.get(_field)
            if str(_value or "").strip():
                return str(_value).strip()
    return ""


def _extract_location_text(row: Dict[str, Any]) -> str:
    _row = row or {}
    _parts: List[str] = []
    for _key in (
        "location",
        "itemLocation",
        "item_location",
        "itemLocationText",
        "item_location_text",
        "sellerLocation",
        "seller_location",
        "sellerLocationText",
        "seller_location_text",
    ):
        _value = _row.get(_key)
        _text = _location_payload_text(_value)
        if _text:
            _parts.append(_text)
    return " | ".join(_parts)


def _location_text_clearly_non_us(location_text: str) -> bool:
    _text = str(location_text or "").strip().lower()
    if not _text:
        return False
    for _hint in _FOREIGN_LOCATION_HINTS:
        if re.search(rf"\b{re.escape(_hint)}\b", _text):
            return True
    return False


def _shipping_domestic_block_reason(row: Dict[str, Any]) -> str:
    _row = row or {}
    _shipping_nodes: List[Any] = []
    for _key in (
        "shippingOptions",
        "shipping",
        "shippingOptionSummary",
        "shipToLocations",
        "shipToLocationUsedForEstimate",
        "shipToCountries",
        "regionIncluded",
        "regionsIncluded",
        "regionExcluded",
        "regionsExcluded",
    ):
        _value = _row.get(_key)
        if _value not in (None, "", [], {}):
            _shipping_nodes.append(_value)
    if not _shipping_nodes:
        return ""

    _has_us = False
    _has_foreign = False
    _has_international_hint = False
    for _node in _shipping_nodes:
        for _text in _collect_text_leaves(_node, max_depth=4):
            _norm = _normalize_geo_token(_text)
            if not _norm:
                continue
            if _is_us_country_token(_norm) or "DOMESTIC" in _norm or "LOCAL PICKUP" in _norm:
                _has_us = True
            if "INTERNATIONAL" in _norm or "WORLDWIDE" in _norm:
                _has_international_hint = True
            if _looks_like_foreign_country_token(_text):
                _has_foreign = True
    if (_has_foreign or _has_international_hint) and not _has_us:
        return "international_shipping"
    return ""


def _international_board_mode_enabled(row: Dict[str, Any]) -> bool:
    _row = row or {}
    for _key in (
        "international_mode",
        "allow_international_mode",
        "international_board_mode",
        "board_allow_international",
    ):
        if bool(_row.get(_key)):
            return True
    return False


def _stamp_domestic_eligibility(row: Dict[str, Any], *, emit_log: bool = True) -> Dict[str, Any]:
    _row = row or {}
    _currency = _extract_currency_code(_row)
    _country = _extract_listing_country(_row)
    _location = _extract_location_text(_row)
    _reason = ""
    if _currency and _currency != "USD":
        _reason = "non_us_currency"
    elif _country and not _is_us_country_token(_country):
        _reason = "non_us_listing"
    elif _location_text_clearly_non_us(_location):
        _reason = "non_us_listing"
    else:
        _reason = _shipping_domestic_block_reason(_row)

    _override = _international_board_mode_enabled(_row)
    _eligible = bool(_override or not _reason)
    _row["listing_price_currency"] = _currency
    _row["listing_country"] = _country
    _row["listing_location_text"] = _location
    _row["domestic_eligible"] = bool(_eligible)
    _row["domestic_block_reason"] = "" if _eligible else _reason
    _row["international_board_mode"] = bool(_override)
    if emit_log and not bool(_row.get("_domestic_eligibility_logged")):
        print(
            f"[DOMESTIC_ELIGIBILITY] "
            f"title={str(_row.get('title') or _row.get('source_title') or '')[:140]} "
            f"item={str(_row.get('item_id') or _row.get('source_item_id') or _row.get('itemId') or '')[:24]} "
            f"currency={_currency or ''} "
            f"country={_country or ''} "
            f"location={_location[:120] if _location else ''} "
            f"domestic_eligible={1 if _eligible else 0}"
        )
        _row["_domestic_eligibility_logged"] = True
    return _row


def _mark_domestic_block(row: Dict[str, Any], *, reason: str, caller: str = "") -> Dict[str, Any]:
    _row = _stamp_domestic_eligibility(row, emit_log=False)
    _reason_key = str(reason or _row.get("domestic_block_reason") or "").strip() or "non_us_listing"
    _reason_text = {
        "non_us_currency": "Hidden — non-US currency",
        "non_us_listing": "Hidden — non-US listing",
        "international_shipping": "Hidden — international shipping",
    }.get(_reason_key, "Hidden — domestic eligibility failed")
    _row["domestic_eligible"] = False
    _row["domestic_block_reason"] = _reason_key
    _row["blocked_reason"] = _reason_key
    _row["live_board_reject_reason"] = _reason_key
    _row["hidden_reason"] = _reason_text
    _row["commercial_visibility"] = "hidden"
    _row["commercially_visible"] = False
    _row["board_visible"] = False
    _row["execution_admission_bucket"] = "hidden"
    _row["execution_admission_reason"] = _reason_text
    _row["commercial_visibility_reason"] = _reason_text
    _row["_render_live_watchlist"] = False
    _row["hero_board_eligible"] = False
    if not bool(_row.get("_domestic_block_logged")):
        print(
            f"[DOMESTIC_BLOCK] "
            f"title={str(_row.get('title') or _row.get('source_title') or '')[:140]} "
            f"item={str(_row.get('item_id') or _row.get('source_item_id') or _row.get('itemId') or '')[:24]} "
            f"reason={_reason_key} "
            f"currency={str(_row.get('listing_price_currency') or '')} "
            f"country={str(_row.get('listing_country') or '')}"
        )
        _row["_domestic_block_logged"] = True
    if caller:
        _row["domestic_block_caller"] = caller
    return _row


def _apply_domestic_board_gate(row: Dict[str, Any], *, caller: str) -> bool:
    _row = _stamp_domestic_eligibility(row, emit_log=False)
    _reason = str(_row.get("domestic_block_reason") or "").strip()
    if not _reason:
        return True
    _mark_domestic_block(_row, reason=_reason, caller=caller)
    return False


def _log_domestic_summary(rows: List[Dict[str, Any]]) -> None:
    _checked = 0
    _eligible = 0
    _blocked = 0
    for _row in list(rows or []):
        if not isinstance(_row, dict):
            continue
        _checked += 1
        _stamp_domestic_eligibility(_row, emit_log=False)
        if bool(_row.get("domestic_eligible")):
            _eligible += 1
        else:
            _blocked += 1
    print(f"[DOMESTIC_SUMMARY] checked={_checked} eligible={_eligible} blocked={_blocked}")


def _stamp_feed_row(item: Dict[str, Any], *, feed_type: str, scan_source: str) -> Dict[str, Any]:
    _row = dict(item or {})
    _row["feed_type"] = feed_type
    _row["scan_source"] = scan_source
    _row["row_key"] = _ending_soon_row_key(_row)
    _row["target_player_name"] = str(_row.get("player_name") or "")
    _row["target_sport"] = str(
        _row.get("target_sport")
        or _row.get("sport")
        or (_row.get("target_meta") or {}).get("sport")
        or ""
    )
    _row["target_id"] = str(_row.get("target_id") or "")
    _row["target_entity_id"] = str(_row.get("target_entity_id") or _row.get("player_id") or "")
    _row["target_label"] = str(_row.get("target_label") or _row.get("player_name") or "")
    _row["target_family"] = str(_row.get("target_label") or _row.get("player_name") or "")
    _row["target_product_family"] = str(
        _row.get("subset_product_family")
        or (_row.get("target_meta") or {}).get("subset_product_family")
        or _row.get("product_family")
        or (_row.get("target_meta") or {}).get("set_name")
        or ""
    )
    _row["lane_tier"] = str(_row.get("lane_tier") or "primary")
    _row["route_stage"] = str(_row.get("route_stage") or ("tracked_exact" if bool(_row.get("lane_approved")) else "route_rejected"))
    _row["route_reason"] = str(_row.get("route_reason") or ("Exact tracked lane match" if bool(_row.get("lane_approved")) else str(_row.get("entity_gate_reason") or "")))
    _row["entity_match_status"] = str(_row.get("entity_match_status") or ("EXACT_MATCH" if bool(_row.get("exact_entity_match")) else "NO_MATCH")).strip().upper()
    try:
        _row["entity_match_score"] = float(_row.get("entity_match_score") or (1.0 if _row["entity_match_status"] == "EXACT_MATCH" else 0.0))
    except (TypeError, ValueError):
        _row["entity_match_score"] = 0.0
    _row["normalized_entity"] = str(
        _row.get("normalized_entity")
        or _row.get("target_entity_id")
        or _row.get("player_id")
        or player_hub.resolve_hub_player_id_from_display_name(str(_row.get("player_name") or _row.get("target_player_name") or ""))
        or ""
    ).strip()
    _row["exact_entity_match"] = bool(_row.get("exact_entity_match", False))
    _row["lane_approved"] = bool(_row.get("lane_approved", False))
    _defaulted_deal_class = not str(_row.get("deal_class") or "").strip()
    _row["deal_class"] = str(_row.get("deal_class") or "UNKNOWN").strip().upper()
    _row["_defaulted_deal_class"] = bool(_row.get("_defaulted_deal_class")) or _defaulted_deal_class
    _promotion_status = str(_row.get("premium_review_status") or "").strip().lower()
    _premium_review_ready, _premium_review_reason = _row_has_live_review_readiness(_row)
    if _premium_review_ready and _promotion_status not in {"resolved", "partial"}:
        print(
            f"[REVIEW_READY_DERIVED] caller=stamp_feed_row "
            f"title={str(_row.get('title') or '')[:120]} "
            f"reason={_premium_review_reason}"
        )
    if _premium_review_ready:
        _row["forced_surface"] = False
        _row["forced_surface_stage"] = ""
        _row["forced_surface_reason"] = ""
        _row["route_stage"] = str(_row.get("route_stage") or "promoted_live_candidate")
        _row["live_signal_tier"] = str(_row.get("live_signal_tier") or "promoted")
    _row["action_label"] = str(_row.get("action_label") or "")
    _row["subset_name"] = str(_row.get("subset_name") or (_row.get("target_meta") or {}).get("subset_name") or _row.get("lane_subset") or "")
    _row["subset_product_family"] = str(_row.get("subset_product_family") or (_row.get("target_meta") or {}).get("subset_product_family") or "")
    _row["subset_binding_override"] = bool(_row.get("subset_binding_override") or (_row.get("target_meta") or {}).get("subset_binding_override"))
    if _row["subset_product_family"] and not str(_row.get("target_product_family") or "").strip():
        _row["target_product_family"] = str(_row.get("subset_product_family") or "")
    _tracked_target = _row.get("tracked_target") or {}
    _stamp_domestic_eligibility(_row, emit_log=True)
    if isinstance(_tracked_target, dict) and _tracked_target:
        _row.update(player_hub.compute_target_action_prices(_row, _tracked_target, listing_mode=feed_type))
    return _row


def _is_auction_listing(item: Dict[str, Any]) -> bool:
    _row = item or {}
    if _parse_browse_listing_mode(_row) in {"auction", "auction_or_bin"}:
        return True
    _listing_type = str(_row.get("listing_type") or "").strip().upper()
    if _listing_type:
        return _listing_type == "AUCTION"
    _buying_options = _row.get("buyingOptions")
    if isinstance(_buying_options, list):
        _opts = {str(v or "").strip().upper() for v in _buying_options}
        if _opts:
            return "AUCTION" in _opts and "FIXED_PRICE" not in _opts
    return True


def _filter_auction_only_candidates(items: List[Dict[str, Any]]) -> Tuple[List[Dict[str, Any]], int]:
    _auction_rows: List[Dict[str, Any]] = []
    _non_auction = 0
    for _item in list(items or []):
        if _is_auction_listing(_item):
            _auction_rows.append(_item)
        else:
            _non_auction += 1
    return _auction_rows, _non_auction


def _parse_browse_listing_mode(item: Dict[str, Any]) -> str:
    _row = item or {}
    _buying_options = _row.get("buyingOptions") or []
    if isinstance(_buying_options, str):
        _buying_options = [_buying_options]
    _opts = {str(v or "").strip().upper() for v in list(_buying_options or []) if str(v or "").strip()}
    if "AUCTION" in _opts and "FIXED_PRICE" in _opts:
        return "auction_or_bin"
    if "AUCTION" in _opts:
        return "auction"
    if "FIXED_PRICE" in _opts:
        return "fixed_price"
    _listing_type = str(_row.get("listing_type") or "").strip().upper()
    if _listing_type == "AUCTION":
        return "auction"
    if _listing_type == "BIN":
        return "fixed_price"
    return "unknown"


def _is_true_auction_row(item: Dict[str, Any]) -> bool:
    return _parse_browse_listing_mode(item) in {"auction", "auction_or_bin"}


def _browse_utc_iso(dt: datetime) -> str:
    return dt.astimezone(timezone.utc).replace(microsecond=0).isoformat().replace("+00:00", "Z")


def _build_auction_fetch_filter(
    *,
    window_start: Optional[datetime] = None,
    window_end: Optional[datetime] = None,
    scoped: bool = True,
) -> str:
    _filters: List[str] = ["buyingOptions:{AUCTION}"]
    if scoped and isinstance(window_start, datetime) and isinstance(window_end, datetime):
        _filters.append(f"itemEndDate:[{_browse_utc_iso(window_start)}..{_browse_utc_iso(window_end)}]")
    return ",".join(_filters)


def _extract_browse_auction_rows(raw_items: List[Dict[str, Any]]) -> Tuple[List[Dict[str, Any]], Dict[str, int]]:
    _raw_listing_type_counts: Dict[str, int] = {}
    _auction_shaped_rows: List[Dict[str, Any]] = []
    for _raw in list(raw_items or []):
        if not isinstance(_raw, dict):
            continue
        _mode = _parse_browse_listing_mode(_raw)
        _raw_listing_type_counts[_mode] = int(_raw_listing_type_counts.get(_mode, 0) or 0) + 1
        if _is_true_auction_row(_raw):
            _auction_shaped_rows.append(_raw)
    return _auction_shaped_rows, _raw_listing_type_counts


def _validate_scoped_auction_response(
    rows: List[Dict[str, Any]],
    *,
    now_dt: datetime,
    window_seconds: float,
    sample_size: int = 10,
) -> Dict[str, Any]:
    _rows = [dict(_row) for _row in list(rows or []) if isinstance(_row, dict)]
    _decisions: List[Dict[str, Any]] = []
    for _row in _rows:
        _decision = _window_filter_decision(
            _row,
            now_dt=now_dt,
            window_seconds=window_seconds,
        )
        _decisions.append({
            "keep": bool(_decision.get("keep")),
            "remaining_seconds": _safe_float(_decision.get("remaining_seconds")),
        })
    _row_count = len(_decisions)
    _in_window = sum(1 for _d in _decisions if bool(_d.get("keep")))
    _out_of_window = max(0, _row_count - _in_window)
    _sample = _decisions[: max(0, min(int(sample_size or 0), _row_count))]
    _sample_out = sum(1 for _d in _sample if not bool(_d.get("keep")))
    _sample_invalid = bool(_sample) and _sample_out >= max(1, int(math.ceil(len(_sample) * 0.8)))
    _response_scope_valid = not (_row_count > 0 and (_in_window == 0 or _sample_invalid))
    _remaining_values = [
        float(_d.get("remaining_seconds"))
        for _d in _decisions
        if _d.get("remaining_seconds") is not None
    ]
    return {
        "rows": _row_count,
        "in_window": int(_in_window),
        "out_of_window": int(_out_of_window),
        "response_scope_valid": bool(_response_scope_valid),
        "nearest_remaining": min(_remaining_values) if _remaining_values else None,
        "furthest_remaining": max(_remaining_values) if _remaining_values else None,
    }


def _nearest_ending_auction_slice(
    rows: List[Dict[str, Any]],
    *,
    now_dt: datetime,
    slice_size: int = 20,
) -> List[Dict[str, Any]]:
    _slice_size = max(1, int(slice_size or 20))
    _decorated: List[Tuple[float, Dict[str, Any]]] = []
    for _row in list(rows or []):
        if not isinstance(_row, dict):
            continue
        _remaining = _safe_float(_window_filter_decision(
            _row,
            now_dt=now_dt,
            window_seconds=float("inf"),
        ).get("remaining_seconds"))
        _sort_remaining = float(_remaining) if _remaining is not None and _remaining >= 0 else float("inf")
        _decorated.append((_sort_remaining, _row))
    _decorated.sort(key=lambda _entry: _entry[0])
    return [dict(_entry[1]) for _entry in _decorated[:_slice_size]]


def _build_auction_fetch_params(
    variant: Dict[str, Any],
    *,
    window_start: Optional[datetime] = None,
    window_end: Optional[datetime] = None,
    scoped: bool = True,
) -> Dict[str, Any]:
    return {
        "q": str(variant.get("query") or "").strip(),
        "filter": _build_auction_fetch_filter(
            window_start=window_start,
            window_end=window_end,
            scoped=scoped,
        ),
        "sort": "endingSoonest",
        "limit": 100,
    }


def _build_zero_result_relaxed_auction_variant(spec: Dict[str, Any], variant: Dict[str, Any]) -> Dict[str, Any]:
    _tracked_target = dict((spec or {}).get("tracked_target") or {})
    _player = " ".join(
        str(
            (spec or {}).get("player_name")
            or (spec or {}).get("target_label")
            or _tracked_target.get("player_name")
            or ""
        ).split()
    ).strip()
    _player = _sanitize_query_player_name(_player) if _player else ""
    _product = " ".join(
        str(
            (spec or {}).get("lane_product")
            or (spec or {}).get("target_product_family")
            or _tracked_target.get("product_family")
            or ""
        ).split()
    ).strip()
    _blob = " ".join(
        str(_value or "")
        for _value in (
            (variant or {}).get("query"),
            (spec or {}).get("query"),
            (spec or {}).get("lane_parallel"),
            (spec or {}).get("lane_subset"),
            (spec or {}).get("target_lane_type"),
            _tracked_target.get("parallel_name"),
            _tracked_target.get("insert_family"),
        )
    ).lower()
    _premium_term = ""
    for _term in ("auto", "/10", "/25", "/50", "kaboom", "downtown", "zebra", "gold", "color blast", "genesis", "honeycomb"):
        if _term == "auto":
            if re.search(r"\b(auto|autograph|autographs|signed|signature)\b", _blob):
                _premium_term = "auto"
                break
            continue
        if _term in _blob:
            _premium_term = _term
            break
    _parts = [_player, _product, _premium_term]
    _query = " ".join(_part for _part in _parts if _part).strip()
    if not _query:
        _query = re.sub(r"\s+", " ", re.sub(r"(?:^|\s)-\S+", " ", str((variant or {}).get("query") or ""))).strip()
    _relaxed = dict(variant or {})
    _relaxed["variant_name"] = f"{str((variant or {}).get('variant_name') or 'variant')}_zero_relaxed"
    _relaxed["query"] = _query[:240]
    _relaxed["relax_parallel"] = True
    _relaxed["recall_stage"] = "zero_result_relaxed"
    _relaxed["query_spec_quality_score"] = min(int(_safe_float((variant or {}).get("query_spec_quality_score")) or 35), 35)
    _relaxed["_zero_result_relaxed"] = True
    return _relaxed


