def _is_valid_tier_b_survivor(
    row,
    *,
    identity_is_clean=None,
    tier=None,
    lane_type=None,
    insert_family=None,
    parallel_family=None,
    card_number=None,
    grade=None,
):
    try:
        if not isinstance(row, dict):
            return False

        identity_is_clean = bool(
            identity_is_clean
            if identity_is_clean is not None
            else (
                row.get("_hydrated_identity_is_clean")
                or row.get("identity_is_clean")
                or row.get("identity_clean")
            )
        )
        tier = str(
            tier
            if tier is not None
            else (
                row.get("_hydrated_subscription_lane_tier")
                or row.get("subscription_lane_tier")
                or row.get("_subscription_lane_tier")
                or ""
            )
        ).strip().upper()
        lane_type = str(
            lane_type
            if lane_type is not None
            else (
                row.get("_hydrated_lane_type")
                or row.get("lane_type")
                or row.get("_lane_type")
                or row.get("query_mode")
                or ""
            )
        ).strip().lower()
        insert_family = str(
            insert_family
            if insert_family is not None
            else (
                row.get("_hydrated_insert_family")
                or row.get("insert_family")
                or row.get("subset")
                or row.get("subset_family")
                or row.get("legacy_subset")
                or ""
            )
        ).strip().lower()
        parallel_family = str(
            parallel_family
            if parallel_family is not None
            else (
                row.get("_hydrated_parallel_family")
                or row.get("parallel_family")
                or row.get("parallel")
                or row.get("parallel_name")
                or ""
            )
        ).strip().lower()
        card_number = str(
            card_number
            if card_number is not None
            else (
                row.get("_hydrated_card_number")
                or row.get("card_number")
                or row.get("card_no")
                or row.get("parsed_card_number")
                or ""
            )
        ).strip()
        grade = str(
            grade
            if grade is not None
            else (
                row.get("_hydrated_grade")
                or row.get("grade")
                or row.get("grade_key")
                or row.get("grade_label")
                or ""
            )
        ).strip().lower()

        graded = any(x in grade for x in ["psa", "bgs", "sgc", "graded"])

        if not identity_is_clean:
            return False

        if tier == "TIER_B":
            return True

        if lane_type == "insert" and insert_family in {"image_variation", "variation"} and card_number:
            return True

        if graded and lane_type in {"insert", "parallel", "parallel_serial", "insert_parallel"} and card_number:
            return True

        if parallel_family in {"refractor", "purple", "blue", "green", "pink", "sepia", "silver"} and card_number:
            return True

        return False
    except Exception:
        return False


def _is_clean_premium_watchlist_survivor(row):
    try:
        if not isinstance(row, dict):
            return False, "not_dict"

        identity_is_clean = bool(
            row.get("_hydrated_identity_is_clean")
            or row.get("identity_is_clean")
        )
        lane_type = str(
            row.get("_hydrated_lane_type")
            or row.get("lane_type")
            or ""
        ).strip().lower()
        insert_family = str(
            row.get("_hydrated_insert_family")
            or row.get("insert_family")
            or ""
        ).strip().lower()
        parallel_family = str(
            row.get("_hydrated_parallel_family")
            or row.get("parallel_family")
            or ""
        ).strip().lower()
        serial_denominator = str(
            row.get("serial_denominator")
            or row.get("serial")
            or ""
        ).strip()
        grade = str(
            row.get("_hydrated_grade")
            or row.get("grade")
            or ""
        ).strip().lower()
        tier = str(
            row.get("_hydrated_subscription_lane_tier")
            or row.get("subscription_lane_tier")
            or ""
        ).strip().upper()

        graded = any(x in grade for x in ["psa", "bgs", "sgc", "graded", "10", "9"])

        if not identity_is_clean:
            return False, "identity_not_clean"

        if tier in {"TIER_A", "TIER_B"}:
            if serial_denominator:
                return True, "tier_serialed"

        if lane_type in {"insert_parallel", "parallel_serial", "insert"}:
            if parallel_family in {"logofractor", "gold", "orange", "red", "black", "refractor", "purple", "blue", "green"}:
                if serial_denominator or graded:
                    return True, "premium_parallel_or_serial"

        if insert_family in {"future stars", "image_variation", "variation"}:
            if serial_denominator or graded:
                return True, "named_insert_watchlist"

        return False, "not_clean_premium_survivor"
    except Exception as e:
        return False, f"error:{e}"


