    row["_identity_not_clean_truth_block"] = True
    row["_identity_not_clean_truth_block_stage"] = stage
    row["truth"] = "NONE"
    row["truth_level"] = "NONE"
    row["valuation_truth_tier"] = "NONE"
    row["_valuation_truth_tier"] = "NONE"
    row["valuation_truth_level"] = "NONE"
    row["_valuation_truth_level"] = "NONE"
    row["exact_truth_rescued"] = False
    row["_final_true_contract_allow"] = False
    row["final_true_contract_allow"] = False

    print(
        f"[IDENTITY_NOT_CLEAN_TRUTH_BLOCK] "
        f"title={str((row or {}).get('title') or '')[:160]} "
        f"identity_is_clean={row.get('identity_is_clean') or row.get('_hydrated_identity_is_clean')} "
        f"identity_clean_reason={row.get('identity_clean_reason') or row.get('_identity_clean_reason')} "
        f"stage={stage}"
    )
    return True


