        _current = _safe_float(_row.get("current_price") if _row.get("current_price") is not None else _row.get("current_bid"))
        _target = _safe_float(_row.get("target_bid") or _row.get("target_bid_price") or _row.get("bid_ceiling_value") or _row.get("adjusted_max_bid"))
        _verified_value = bool(
            (_safe_float(_row.get("true_mv") or _row.get("true_market_value") or _row.get("market_value_true")) or 0) > 0
            or (_safe_float(_row.get("review_estimate") or _row.get("review_estimate_value")) or 0) > 0
            or (_safe_float(_row.get("reference_value") or _row.get("market_value")) or 0) > 0
        )
        _edge_pct = 0.0
        if _current is not None and _current > 0 and _target is not None and _target > 0:
            _edge_pct = ((_target - _current) / _current) * 100.0
        _bucket = ""
        _reason = "late_live_surface_no_bucket"
        if _verified_value and _current is not None and _target is not None and _current <= (_target * 0.90):
            _bucket, _reason = "sniper", "late_live_surface_sniper"
        elif _verified_value and _current is not None and _target is not None and _current <= _target:
            _bucket, _reason = "watchlist", "late_live_surface_watch"
        elif _verified_value and _live_actionable_premium_shape(_row):
            _bucket, _reason = "watchlist", "late_live_surface_monitor_watch"
