    _end_iso = (
        str(_row.get("source_end_time") or "").strip()
        or str(_row.get("end_iso") or "").strip()
        or str(_row.get("itemEndDate") or "").strip()
        or str(_row.get("end_time") or "").strip()
        or str(_row.get("endDate") or "").strip()
        or str(_source_contract.get("source_end_time") or "").strip()
        or str(_source_contract.get("end_iso") or "").strip()
        or str(_source_contract.get("itemEndDate") or "").strip()
        or (_end_dt.astimezone(timezone.utc).isoformat().replace("+00:00", "Z") if isinstance(_end_dt, datetime) else "")
    )
    _item_id = (
        str(_row.get("source_item_id") or "").strip()
        or str(_row.get("item_id") or "").strip()
        or str(_row.get("itemId") or "").strip()
        or str(_source_contract.get("source_item_id") or "").strip()
        or str(_source_contract.get("item_id") or "").strip()
        or str(_source_contract.get("itemId") or "").strip()
    )
    _title = (
        str(_row.get("source_title") or "").strip()
        or str(_row.get("title") or "").strip()
        or str(_source_contract.get("source_title") or "").strip()
        or str(_source_contract.get("title") or "").strip()
    )
    _listing_type = (
        str(_row.get("source_listing_type") or "").strip()
        or str(_row.get("listing_type") or "").strip()
        or str(_row.get("format") or "").strip()
        or str(_row.get("buying_option") or "").strip()
        or str(_row.get("sale_type") or "").strip()
        or str(_source_contract.get("source_listing_type") or "").strip()
        or str(_source_contract.get("listing_type") or "").strip()
        or str(_source_contract.get("format") or "").strip()
        or str(_source_contract.get("buying_option") or "").strip()
        or str(_source_contract.get("sale_type") or "").strip()
    )
    _url = (
        str(_row.get("source_view_url") or "").strip()
        or str(_row.get("url") or "").strip()
        or str(_row.get("itemWebUrl") or "").strip()
        or str(_source_contract.get("source_view_url") or "").strip()
        or str(_source_contract.get("url") or "").strip()
        or str(_source_contract.get("itemWebUrl") or "").strip()
    )
    _thumb = (
        str(_row.get("source_image_url") or "").strip()
        or str(_row.get("thumbnail") or "").strip()
        or str(_row.get("image_url") or "").strip()
        or str((_row.get("image") or {}).get("imageUrl") or "").strip()
        or str(_source_contract.get("source_image_url") or "").strip()
        or str(_source_contract.get("thumbnail") or "").strip()
    )
    _remaining = _row_remaining_seconds(_row)
    if _remaining is None:
        _remaining = _row_remaining_seconds(_source_contract)
    _normalized_entity = _canonical_normalized_entity(_row)
    if not _normalized_entity:
        _normalized_entity = str(_source_contract.get("normalized_entity") or "").strip()
    _current_bid_price = _row.get("currentBidPrice")
    if not isinstance(_current_bid_price, dict) or not _current_bid_price:
        _current_bid_price = _source_contract.get("currentBidPrice") if isinstance(_source_contract.get("currentBidPrice"), dict) else {}
    _buying_options = _row.get("buyingOptions")
    if not isinstance(_buying_options, list) or not _buying_options:
        _buying_options = list(_source_contract.get("buyingOptions") or [])
    _current_price = _row.get("current_price")
    if _current_price is None:
        _current_price = _row.get("current_bid")
    if _current_price is None:
        _current_price = _row.get("source_display_price")
    if _current_price is None:
        _current_price = _source_contract.get("current_price")
    if _current_price is None:
        _current_price = _source_contract.get("current_bid")
    _bid_count = (
        _row.get("bid_count")
        if _row.get("bid_count") is not None
        else _source_contract.get("bid_count")
    )
    _end_time = (
        str(_row.get("source_end_time") or "").strip()
        or str(_row.get("end_time") or "").strip()
        or str(_row.get("end_datetime") or "").strip()
        or str(_row.get("auction_end_time") or "").strip()
        or _end_iso
    )
    _price_source = (
        str(_row.get("current_price_source") or "").strip()
        or str(_row.get("price_source") or "").strip()
        or str(_row.get("display_price_source") or "").strip()
        or str(_row.get("source_price_kind") or "").strip()
        or str(_source_contract.get("current_price_source") or "").strip()
        or str(_source_contract.get("price_source") or "").strip()
        or str(_source_contract.get("display_price_source") or "").strip()
        or str(_source_contract.get("source_price_kind") or "").strip()
    )
    _listing_type_lower = str(_listing_type or "").strip().lower()
    _normalized_listing_type = _listing_type_lower.replace(" ", "_")
    _buying_option_tokens = {
        str(_opt or "").strip().lower().replace(" ", "_")
        for _opt in list(_buying_options or [])
        if str(_opt or "").strip()
    }
    _is_auction_like = bool(
        _normalized_listing_type in {"auction", "auctionwithbin", "auction_with_bin", "auction_or_bin"}
        or "auction" in _buying_option_tokens
    )
    _has_authoritative_price = _current_price is not None
    _has_authoritative_end = bool(_end_time) or _remaining is not None
    if not _is_auction_like:
        _auth_ok = False
        _auth_reason = "not_auction_listing_type"
    elif not _has_authoritative_price:
        _auth_ok = False
        _auth_reason = "missing_current_price"
    elif not _has_authoritative_end:
        _auth_ok = False
        _auth_reason = "missing_auction_end"
    else:
        _auth_ok = True
        _auth_reason = "authoritative_auction"
    return {
        "item_id": _item_id,
        "title": _title,
        "listing_type": _listing_type,
        "end_dt": _end_dt,
        "end_iso": _end_iso,
        "end_time": _end_time,
        "remaining_seconds": _remaining,
        "normalized_entity": _normalized_entity,
        "url": _url,
        "thumbnail": _thumb,
        "current_price": _current_price,
        "bid_count": _bid_count,
        "price_source": _price_source,
        "ok": _auth_ok,
        "reason": _auth_reason,
        "currentBidPrice": dict(_current_bid_price or {}),
        "buyingOptions": list(_buying_options or []),
        "_source_contract": dict(_source_contract or {}),
    }


