def _classify_common_modern_row(
    *,
    product: str,
    year_num: int,
    card_no: str,
    subset: str,
    parallel: str,
    serial_bucket: str,
    grade_state: str,
    is_auto: bool,
    is_mem: bool,
    title: str,
) -> Tuple[bool, str]:
    _product_norm = _normalize_exact_product_family(product)
    _parallel_norm = str(parallel or "").strip().lower().replace("_", " ")
    _subset_norm = _normalize_subset_name(subset)
    _title_lower = str(title or "").strip().lower()
    _modern = year_num >= 2019 if year_num else bool(_product_norm in _COMMON_MODERN_EXACT_PRODUCTS)
    if not _modern or _product_norm not in _COMMON_MODERN_EXACT_PRODUCTS:
        return False, ""
    if grade_state != "raw" or not card_no or serial_bucket or is_auto or is_mem:
        return False, ""
    if _subset_norm in _COMMON_MODERN_RARE_SUBSETS:
        return False, ""
    _parallel_commodity = _parallel_norm in _COMMON_MODERN_COMMODITY_PARALLELS
    _subset_commodity = _subset_norm in _COMMON_MODERN_COMMODITY_SUBSETS
    if not _parallel_commodity and not _subset_commodity and _parallel_norm not in {"", "base"}:
        return False, ""
    _reason_bits: List[str] = []
    if _parallel_norm and _parallel_norm not in {"", "base"}:
        _reason_bits.append(_parallel_norm.replace(" ", "_"))
    if _subset_norm:
        _reason_bits.append(_subset_norm)
    if not _reason_bits:
        _reason_bits.append("base")
    _reason_bits.append("raw")
    return True, "_".join(_reason_bits[:3])


def _normalize_product_probe_text(value: Any) -> str:
    _raw = str(value or "").strip().lower().replace("-", " ").replace("_", " ")
    _raw = re.sub(r"[^a-z0-9\s]+", " ", _raw)
    return " ".join(_raw.split())


def _resolve_cosmic_product_family(
    title: Any,
    existing_product_family: Any = "",
    *,
    emit_log: bool = True,
) -> Dict[str, str]:
    _title = str(title or "").strip()
    _existing = str(existing_product_family or "").strip()
    _title_norm = _normalize_product_probe_text(_title)
    _existing_norm = _normalize_product_probe_text(_existing)
    _hay = " ".join(_part for _part in (_existing_norm, _title_norm) if _part).strip()
    _resolved = ""
    _reason = ""
    if _existing_norm == "topps cosmic chrome black":
        _resolved = "topps_cosmic_chrome_black"
        _reason = "existing_cosmic_black"
    elif _existing_norm in {"topps cosmic chrome", "topps chrome cosmic"}:
        _resolved = "topps_cosmic_chrome"
        _reason = "existing_cosmic_host"
    elif any(_needle in _hay for _needle in ("topps cosmic chrome black", "topps chrome cosmic black")):
        _resolved = "topps_cosmic_chrome_black"
        _reason = "title_cosmic_black_host"
    elif any(_needle in _hay for _needle in ("topps cosmic chrome", "topps chrome cosmic", "cosmic chrome", "chrome cosmic")):
        _resolved = "topps_cosmic_chrome"
        _reason = "title_cosmic_host"
    if emit_log and (_resolved or "cosmic" in _hay):
        print(
            f"[COSMIC_PRODUCT_RESOLVE] title={_title[:140]} "
            f"existing_product_family={_existing[:64]} "
            f"resolved_product_family={_resolved[:64]} "
            f"reason={_reason or 'none'}"
        )
    return {
        "product_family": _resolved,
        "resolution_reason": _reason,
    }


def _resolve_sapphire_product_family(
    title: Any,
    existing_product_family: Any = "",
    *,
    emit_log: bool = True,
) -> Dict[str, str]:
    _title = str(title or "").strip()
    _existing = str(existing_product_family or "").strip()
    _title_norm = _normalize_product_probe_text(_title)
    _existing_norm = _normalize_product_probe_text(_existing)
    _hay = " ".join(_part for _part in (_existing_norm, _title_norm) if _part).strip()
    _resolved = ""
    _reason = ""
    if _existing_norm == "topps chrome sapphire":
        _resolved = "topps_chrome_sapphire"
        _reason = "existing_sapphire_host"
    elif any(
        _needle in _hay
        for _needle in (
            "topps chrome sapphire edition",
            "topps chrome sapphire",
            "chrome sapphire edition",
        )
    ):
        _resolved = "topps_chrome_sapphire"
        _reason = "title_sapphire_host"
    elif "chrome sapphire" in _hay and "topps chrome" in _hay:
        _resolved = "topps_chrome_sapphire"
        _reason = "chrome_sapphire_host"
    if emit_log and (_resolved or "sapphire" in _hay):
        print(
            f"[SAPPHIRE_PRODUCT_RESOLVE] title={_title[:140]} "
            f"existing_product_family={_existing[:64]} "
            f"resolved_product_family={_resolved[:64]} "
            f"reason={_reason or 'none'}"
        )
    return {
        "product_family": _resolved,
        "resolution_reason": _reason,
    }


def _guard_sapphire_product_family(
    title: Any,
    previous_product_family: Any,
    candidate_product_family: Any,
    *,
    reason: str,
    emit_log: bool = True,
) -> str:
    _title = str(title or "").strip()
    _previous = str(previous_product_family or "").strip()
    _candidate = str(candidate_product_family or "").strip()
    _previous_sapphire = str(
        _resolve_sapphire_product_family(_title, _previous, emit_log=False).get("product_family") or ""
    ).strip()
    _candidate_sapphire = str(
        _resolve_sapphire_product_family(_title, _candidate, emit_log=False).get("product_family") or ""
    ).strip()
    if _candidate_sapphire:
        if emit_log and _candidate and _candidate_sapphire != _previous_sapphire:
            print(
                f"[SAPPHIRE_PRODUCT_OVERWRITE] title={_title[:140]} "
                f"previous_product_family={_previous[:64]} "
                f"new_product_family={_candidate_sapphire[:64]} blocked=0 reason={reason}"
            )
        return _candidate_sapphire
    if _previous_sapphire:
        _candidate_norm = _normalize_product_probe_text(_candidate)
        if not _candidate:
            return _previous_sapphire
        if _candidate_norm in {
            "topps",
            "topps chrome",
            "topps chrome black",
            "topps chrome update",
            "topps chrome logofractor",
        }:
            if emit_log:
                print(
                    f"[SAPPHIRE_PRODUCT_OVERWRITE] title={_title[:140]} "
                    f"previous_product_family={_previous_sapphire[:64]} "
                    f"new_product_family={_candidate[:64]} blocked=1 reason={reason}"
                )
            return _previous_sapphire
    return _candidate or _previous or _previous_sapphire


def _guard_cosmic_product_family(
    title: Any,
    previous_product_family: Any,
    candidate_product_family: Any,
    *,
    reason: str,
    emit_log: bool = True,
) -> str:
    _title = str(title or "").strip()
    _previous = str(previous_product_family or "").strip()
    _candidate = str(candidate_product_family or "").strip()
    _previous_cosmic = str(
        _resolve_cosmic_product_family(_title, _previous, emit_log=False).get("product_family") or ""
    ).strip()
    _candidate_cosmic = str(
        _resolve_cosmic_product_family(_title, _candidate, emit_log=False).get("product_family") or ""
    ).strip()
    if _candidate_cosmic:
        return _candidate_cosmic
    if _previous_cosmic:
        _candidate_norm = _normalize_product_probe_text(_candidate)
        if not _candidate:
            return _previous_cosmic
        if _candidate_norm in {
            "topps",
            "topps chrome",
            "topps chrome black",
            "topps chrome update",
            "topps chrome logofractor",
        }:
            if emit_log and _candidate != _previous_cosmic:
                print(
                    f"[COSMIC_PRODUCT_OVERWRITE] title={_title[:140]} "
                    f"previous_product_family={_previous_cosmic[:64]} "
                    f"new_product_family={_candidate[:64]} "
                    f"reason={reason}"
                )
            return _previous_cosmic
    return _candidate or _previous or _previous_cosmic


def _resolve_topps_product_family(
    value: Any,
    *,
    title: str = "",
    parallel_family: Any = "",
    emit_log: bool = True,
) -> Dict[str, str]:
    _title = str(title or "").strip()
    _parallel = str(parallel_family or "").strip().lower().replace("_", " ")
    _value_norm = _normalize_product_probe_text(value)
    _title_norm = _normalize_product_probe_text(_title)
    _hay = " ".join(_part for _part in (_value_norm, _title_norm) if _part).strip()
    _cosmic_ctx = _resolve_cosmic_product_family(_title, value, emit_log=emit_log)
    if str(_cosmic_ctx.get("product_family") or "").strip():
        return {
            "product_family": str(_cosmic_ctx.get("product_family") or "").strip(),
            "resolution_reason": str(_cosmic_ctx.get("resolution_reason") or "").strip(),
        }
    _sapphire_ctx = _resolve_sapphire_product_family(_title, value, emit_log=emit_log)
    if str(_sapphire_ctx.get("product_family") or "").strip():
        return {
            "product_family": str(_sapphire_ctx.get("product_family") or "").strip(),
            "resolution_reason": str(_sapphire_ctx.get("resolution_reason") or "").strip(),
        }
    _resolved = ""
    _reason = ""
    if not _hay:
        return {"product_family": "", "resolution_reason": ""}
    if "topps transcendent icons chrome black" in _hay or "transcendent icons chrome black" in _hay:
        _resolved = "topps transcendent icons chrome black"
        _reason = "transcendent_icons_chrome_black"
    elif "topps transcendent icons" in _hay or "transcendent icons" in _hay:
        _resolved = "topps transcendent icons"
        _reason = "transcendent_icons"
    elif "topps chrome black" in _hay or (
        "chrome black" in _hay and "topps chrome" in _hay and "transcendent icons" not in _hay
    ):
        _resolved = "topps chrome black"
        _reason = "topps_chrome_black"
    elif any(
        _needle in _hay
        for _needle in (
            "topps chrome sapphire edition",
            "topps chrome sapphire",
            "chrome sapphire edition",
        )
    ):
        _resolved = "topps_chrome_sapphire"
        _reason = "topps_chrome_sapphire"
    elif (
        "topps chrome update series" in _hay
        or "topps chrome update" in _hay
        or ("update series" in _hay and "topps chrome" in _hay)
    ):
        _resolved = "topps chrome update"
        _reason = "topps_chrome_update"
    elif (
        "topps chrome logofractor edition" in _hay
        or "topps chrome logofractor" in _hay
        or ("logofractor" in _hay and "topps chrome" in _hay)
    ):
        _resolved = "topps chrome logofractor"
        _reason = "topps_chrome_logofractor"
    elif "topps chrome" in _hay:
        _resolved = "topps chrome"
        _reason = "topps_chrome"
    elif "topps" in _hay:
        _resolved = "topps"
        _reason = "generic_topps"
    _premium_hint = "transcendent icons" in _hay
    _too_generic = 1 if _premium_hint and _resolved in {"", "topps"} else 0
    _log_candidate = any(
        _token in _hay
        for _token in ("transcendent icons", "chrome black", "sapphire", "logofractor", "update series", "topps chrome")
    )
    if emit_log and _log_candidate:
        _resolved_log = str(_resolved or "").replace(" ", "_")
        print(
            f"[PREMIUM_TOPPS_PRODUCT_RESOLVE] title={_title[:140]} "
            f"resolved_product_family={_resolved_log[:64]} resolution_reason={_reason or 'none'} "
            f"parallel_family={_parallel[:32]}"
        )
        _assert_reason = "resolved_specific_host_product"
        if _too_generic:
            _assert_reason = "premium_title_collapsed_to_generic"
        elif _premium_hint and not _resolved:
            _assert_reason = "premium_title_unresolved"
        elif _resolved == "topps":
            _assert_reason = "generic_topps_only"
        print(
            f"[PREMIUM_TOPPS_PRODUCT_ASSERT] title={_title[:140]} "
            f"resolved_product_family={_resolved_log[:64]} too_generic={_too_generic} "
            f"reason={_assert_reason}"
        )
    return {
        "product_family": _resolved,
        "resolution_reason": _reason,
    }


def _is_specific_topps_identity_product_family(value: Any) -> bool:
    _product = _normalize_exact_product_family(str(value or "")).replace("_", " ").strip().lower()
    if not _product or _product == "topps":
        return False
    return bool(
        "topps chrome" in _product
        or "transcendent icons" in _product
        or _product in {"topps finest", "topps cosmic chrome", "topps chrome sapphire"}
    )


def _normalize_exact_product_family(value: str) -> str:
    _raw = _normalize_product_probe_text(value)
    if not _raw:
        return ""
    _sapphire_ctx = _resolve_sapphire_product_family(_raw, value, emit_log=False)
    if str(_sapphire_ctx.get("product_family") or "").strip():
        return str(_sapphire_ctx.get("product_family") or "").strip()
    _cosmic_ctx = _resolve_cosmic_product_family(_raw, value, emit_log=False)
    if str(_cosmic_ctx.get("product_family") or "").strip():
        return str(_cosmic_ctx.get("product_family") or "").strip()
    _topps_product = _resolve_topps_product_family(_raw, title=_raw, emit_log=False)
    if str(_topps_product.get("product_family") or "").strip():
        return str(_topps_product.get("product_family") or "").strip()
    _aliases = {
        "panini prizm": "prizm",
        "panini mosaic": "mosaic",
        "panini select": "select",
        "panini phoenix": "phoenix",
        "donruss optic": "donruss optic",
        "optic": "donruss optic",
        "topps transcendent icons chrome black": "topps transcendent icons chrome black",
        "transcendent icons chrome black": "topps transcendent icons chrome black",
        "topps transcendent icons": "topps transcendent icons",
        "transcendent icons": "topps transcendent icons",
        "topps chrome black": "topps chrome black",
        "topps cosmic chrome black": "topps_cosmic_chrome_black",
        "topps chrome cosmic black": "topps_cosmic_chrome_black",
        "topps cosmic chrome": "topps_cosmic_chrome",
        "topps chrome cosmic": "topps_cosmic_chrome",
        "cosmic chrome": "topps_cosmic_chrome",
        "chrome cosmic": "topps_cosmic_chrome",
        "topps chrome sapphire edition": "topps_chrome_sapphire",
        "topps chrome sapphire": "topps_chrome_sapphire",
        "chrome sapphire edition": "topps_chrome_sapphire",
        "chrome sapphire": "topps_chrome_sapphire",
        "topps chrome update series": "topps chrome update",
        "topps chrome update": "topps chrome update",
        "topps chrome logofractor edition": "topps chrome logofractor",
        "topps chrome logofractor": "topps chrome logofractor",
        "topps chrome": "topps chrome",
        "bowman chrome": "bowman chrome",
        "bowman draft": "bowman draft",
    }
    if _raw in _aliases:
        return _aliases[_raw]
    for _phrase in sorted(_aliases.keys(), key=len, reverse=True):
        if _phrase in _raw:
            return _aliases[_phrase]
    _raw = re.sub(r"^(panini|topps|bowman)\s+", "", _raw)
    return _raw


