def _normalize_topps_insert_card_number(value: Any) -> str:
    _raw = str(value or "").strip().upper()
    if not _raw:
        return ""
    _raw = _raw.replace(" ", "")
    _raw = re.sub(r"^[#]+", "", _raw)
    _raw = re.sub(r"[^A-Z0-9-]", "", _raw)
    if re.fullmatch(r"[A-Z0-9]{1,6}(?:-[A-Z0-9]{1,3})?", _raw):
        return _raw
    return ""


def _looks_like_serial_only_token(value: Any) -> bool:
    _raw = str(value or "").strip().lower()
    if not _raw:
        return False
    return bool(re.fullmatch(r"/?\d{1,3}", _raw) or re.fullmatch(r"\d{1,3}/\d{1,3}", _raw))


def _is_topps_insert_style_card_number(value: Any) -> bool:
    _card_number = _normalize_topps_insert_card_number(value)
    if not _card_number:
        return False
    return bool(re.search(r"[A-Z]", _card_number) or "-" in _card_number)


def _title_contains_hash_serial_fragment(title: Any) -> bool:
    return bool(re.search(r"#\s*\d{1,3}\s*/\s*\d{1,3}\b", str(title or ""), flags=re.IGNORECASE))


def _should_preserve_topps_card_number(
    title: Any,
    product_family: Any,
    card_number: Any,
    *,
    insert_family: Any = "",
) -> bool:
    _title = str(title or "").strip()
    _title_norm = re.sub(r"[^a-z0-9\s]+", " ", _title.lower())
    _title_norm = " ".join(_title_norm.split())
    _product_norm = _normalize_exact_product_family(str(product_family or "").strip() or _title)
    _card = _normalize_topps_insert_card_number(card_number)
    if not _card:
        return False
    if "topps chrome" not in f"{_product_norm} {_title_norm}" and "topps cosmic chrome" not in f"{_product_norm} {_title_norm}":
        return False
    if _title_contains_hash_serial_fragment(_title) and bool(re.fullmatch(r"\d{1,3}", _card)):
        return False
    if _is_topps_insert_style_card_number(_card):
        return True
    if str(insert_family or "").strip():
        return True
    return bool(re.fullmatch(r"\d{1,4}", _card))


def _repair_topps_player_from_title(title: str, cleaned_player: Any) -> str:
    _title = str(title or "").strip()
    _candidate = str(cleaned_player or "").strip()
    if not _title or not _candidate:
        return _candidate
    if "topps chrome" not in _title.lower() and "topps cosmic chrome" not in _title.lower():
        return _candidate
    _title_tokens = re.findall(r"[A-Za-z][A-Za-z'.-]*", _title)
    _title_tokens_lower = [str(_tok or "").lower() for _tok in _title_tokens]
    _candidate_tokens = [
        str(_tok or "").lower()
        for _tok in re.findall(r"[A-Za-z][A-Za-z'.-]*", _candidate)
        if str(_tok or "").strip()
    ]
    _anchor = ""
    for _tok in _candidate_tokens:
        if _tok not in {
            "topps",
            "chrome",
            "cosmic",
            "sapphire",
            "edition",
            "update",
            "series",
            "logofractor",
            "black",
            "baseball",
            "football",
            "basketball",
            "card",
            "rookie",
            "rc",
            "flagship",
        }:
            _anchor = _tok
            break
    if not _anchor:
        return _candidate
    _start_idx = next((idx for idx, tok in enumerate(_title_tokens_lower) if tok == _anchor), -1)
    if _start_idx < 0:
        return _candidate
    _connectors = {"de", "da", "del", "la", "le", "van", "von", "jr", "sr", "ii", "iii", "iv"}
    _name_parts: List[str] = []
    _main_parts = 0
    for _idx in range(_start_idx, len(_title_tokens)):
        _token = str(_title_tokens[_idx] or "").strip()
        _token_lower = _token.lower()
        if not _token:
            break
        if _token_lower in {
            "topps",
            "chrome",
            "cosmic",
            "sapphire",
            "edition",
            "update",
            "series",
            "baseball",
            "football",
            "basketball",
            "card",
            "rookie",
            "rc",
            "flagship",
            "auto",
            "autograph",
            "refractor",
            "parallel",
            "psa",
            "sgc",
            "bgs",
            "gem",
            "mint",
        }:
            break
        if _token_lower in _connectors:
            if not _name_parts:
                break
            _name_parts.append(_token.capitalize())
            continue
        _name_parts.append(_token)
        _main_parts += 1
        if _main_parts >= 2:
            break
    _rebuilt = " ".join(_name_parts).strip()
    return _rebuilt or _candidate


