def _is_premium_insert_family(value: Any) -> bool:
    _family = _normalize_subset_name(str(value or "").strip())
    return bool(_family and _family in _PANINI_PREMIUM_INSERT_FAMILIES)


def _first_premium_insert_family(*values: Any) -> str:
    for _value in values:
        _family = _normalize_subset_name(str(_value or "").strip())
        if _family and not _looks_like_serial_only_token(_family) and _is_premium_insert_family(_family):
            return _family
    return ""


def _player_anchor_stop_tokens() -> set[str]:
    return set(_PLAYER_ANCHOR_HOST_TOKENS).union(_PLAYER_ANCHOR_CONTEXT_TOKENS)


def _filter_player_anchor_tokens(text: Any) -> List[str]:
    _stop_tokens = _player_anchor_stop_tokens()
    _tokens = re.findall(r"[A-Za-z][A-Za-z'.-]*", str(text or ""))
    return [
        str(_token or "").strip()
        for _token in _tokens
        if str(_token or "").strip()
        and str(_token or "").lower() not in _stop_tokens
        and not re.fullmatch(r"(?:19|20)\d{2}", str(_token or "").strip())
    ]


def _is_panini_identity_product_family(product_family: Any, title: Any = "") -> bool:
    _product = _normalize_exact_product_family(str(product_family or title or "")).replace("_", " ").strip().lower()
    _hay = f" {_product} {str(title or '').lower().replace('-', ' ')} "
    return _product in _PANINI_PRODUCT_FAMILIES or any(
        f" {_token} " in _hay
        for _token in ("panini", "prizm", "mosaic", "select", "optic", "donruss")
    )


def _implied_brand_from_product_family(product_family: Any, title: Any = "") -> Tuple[str, str]:
    _product = _normalize_exact_product_family(str(product_family or title or "")).replace("_", " ").strip().lower()
    if _product in _PANINI_PRODUCT_FAMILIES:
        return "panini", "product_family_implies_panini"
    # Also check normalized underscore form (topps_chrome, topps_chrome_sapphire, etc.)
    _product_us = _product.replace(" ", "_")
    if _product.startswith("topps chrome") or _product.startswith("topps cosmic chrome"):
        return "topps", "product_family_implies_topps"
    if _product_us.startswith("topps_chrome") or _product_us.startswith("topps_cosmic_chrome"):
        return "topps", "product_family_implies_topps_underscore"
    if _product in {"topps chrome sapphire", "topps cosmic chrome", "topps cosmic chrome black",
                    "topps_chrome_sapphire", "topps_cosmic_chrome", "topps_cosmic_chrome_black"}:
        return "topps", "product_family_implies_topps"
    # Fallback: check if product contains Panini brand tokens directly
    _title_norm = str(title or "").lower()
    if any(f" {_tok} " in f" {_product} " for _tok in ("prizm", "mosaic", "select", "optic", "donruss")):
        return "panini", "product_family_contains_panini_token"
    return "", "no_brand_inference"


def _promote_identity_brand(title: Any, product_family: Any, brand: Any) -> str:
    _title = str(title or "").strip()
    _product = _normalize_exact_product_family(str(product_family or _title or ""))
    _brand_before = str(brand or "").strip().lower()
    _brand_after = _brand_before
    _reason = "brand_present_preserved" if _brand_before else "no_brand_inference"
    # Attempt canonical inference from product family
    _implied, _implied_reason = _implied_brand_from_product_family(_product, _title)
    if not _brand_after:
        # Brand is blank — fill from product family or title
        if _implied:
            _brand_after = _implied
            _reason = _implied_reason
        elif "topps" in f"{_product} {_title.lower()}":
            _brand_after = "topps"
            _reason = "topps_title_token"
        elif "panini" in _title.lower() and _is_panini_identity_product_family(_product, _title):
            _brand_after = "panini"
            _reason = "panini_title_token"
        elif any(f" {_tok} " in f" {_title.lower()} " for _tok in ("prizm", "mosaic", "select", "optic", "donruss")):
            _brand_after = "panini"
            _reason = "panini_product_token_in_title"
    else:
        # Brand is already set — correct it when product family definitively implies a different brand
        if _implied and _implied != _brand_after:
            _brand_after = _implied
            _reason = f"brand_corrected_to_{_implied}_by_product_family"
    if _brand_before != _brand_after or _reason not in {"brand_present_preserved", "no_brand_inference"}:
        print(
            f"[BRAND_PROMOTION] title={_title[:140]} product_family={str(_product or '')[:48]} "
            f"brand_before={_brand_before[:24]} brand_after={_brand_after[:24]} reason={_reason}"
        )
    return _brand_after


def _repair_player_from_title_anchor(
    title: Any,
    candidate_player: Any,
    product_family: Any,
    brand: Any,
) -> str:
    """Strip host-product tokens from candidate, then anchor longest real person-name
    span found in the filtered title.  Never allow product tokens to survive in the
    final player string.

    Success targets:
        Chrome Juan   -> Juan Soto   (title anchor extension)
        Emergent Brock -> Brock Bowers (host-token strip + title anchor extension)
    """
    _title = str(title or "").strip()
    _candidate_raw = str(candidate_player or "").strip()
    _product = _normalize_exact_product_family(str(product_family or _title or ""))
    _brand_norm = str(brand or "").strip().lower()
    # --- strip brand/product tokens from title and candidate ---
    _filtered_title_tokens = _filter_player_anchor_tokens(_title)
    _filtered_title_lowers = [str(_token or "").lower() for _token in _filtered_title_tokens]
    _candidate_tokens = _filter_player_anchor_tokens(_candidate_raw)
    _candidate_clean = _sanitize_query_player_name(" ".join(_candidate_tokens).strip()) if _candidate_tokens else ""
    _candidate_key_tokens = _normalize_person_key(_candidate_clean).split()
    _canon_map = _query_name_canonical_map()
    # Start with the stripped candidate; do NOT fall back to raw yet (raw may be contaminated)
    _repaired = ""
    _reason = "no_candidate"
    # --- canonical span search: prefer the longest real person-name span in the title ---
    _best_name = ""
    _best_score: Tuple[int, int, int] = (-1, -1, -9999)
    _max_span = min(4, len(_filtered_title_tokens))
    for _size in range(_max_span, 1, -1):
        for _idx in range(0, max(0, len(_filtered_title_tokens) - _size + 1)):
            _span_tokens = _filtered_title_tokens[_idx:_idx + _size]
            if not _span_tokens:
                continue
            _span_key = _normalize_person_key(_ascii_fold_query_name(" ".join(_span_tokens)))
            if not _span_key:
                continue
            _canonical_name = str(_canon_map.get(_span_key) or "").strip()
            if not _canonical_name:
                continue
            # overlap = 0 is still valid when candidate was fully contaminated
            _overlap = len(set(_candidate_key_tokens).intersection(set(_span_key.split()))) if _candidate_key_tokens else 0
            _score = (_overlap, len(_span_key.split()), -_idx)
            if _score > _best_score:
                _best_score = _score  # fixed: was incorrectly assigning _best_score to itself
                _best_name = _canonical_name
    if _best_name:
        _repaired = _best_name
        _reason = "title_canonical_span_exact" if _best_score[0] > 0 else "title_canonical_span"
    elif _candidate_key_tokens:
        # anchor-based extension: find candidate tokens in the filtered title, then
        # extend forward to capture the full name (first + last = 2 main parts min)
        _anchor_positions = [
            _idx
            for _idx, _token in enumerate(_filtered_title_lowers)
            if _token in set(_candidate_key_tokens)
        ]
        for _start_idx in _anchor_positions:
            _span_parts: List[str] = []
            _main_parts = 0
            for _token in _filtered_title_tokens[_start_idx:]:
                _span_parts.append(str(_token or "").strip())
                _main_parts += 1
                if _main_parts >= max(2, len(_candidate_key_tokens)):
                    break
            _fallback_span = _sanitize_query_player_name(" ".join(_span_parts).strip())
            if _fallback_span:
                _repaired = _fallback_span
                _reason = "candidate_anchor_following_title_tokens"
                break
    # --- full-title leading-span fallback (fires when candidate was fully contaminated) ---
    if not _repaired and len(_filtered_title_tokens) >= 2:
        _repaired = _sanitize_query_player_name(" ".join(_filtered_title_tokens[:2]).strip())
        _reason = "filtered_title_leading_span_fallback"
    # --- FINAL HARD-STRIP: never allow product/brand tokens to survive in result ---
    _hard_strip_set = _PLAYER_ANCHOR_HOST_TOKENS
    _hard_stripped_parts = [
        _tok for _tok in re.findall(r"[A-Za-z][A-Za-z'.-]*", _repaired)
        if _tok.lower() not in _hard_strip_set
    ]
    if not _hard_stripped_parts and _repaired:
        # entire result was product tokens — fall back to filtered title
        if len(_filtered_title_tokens) >= 2:
            _repaired = _sanitize_query_player_name(" ".join(_filtered_title_tokens[:2]).strip())
            _reason = "hard_strip_all_product_tokens_title_fallback"
    elif _hard_stripped_parts:
        _hard_stripped = _sanitize_query_player_name(" ".join(_hard_stripped_parts).strip())
        if _hard_stripped and _hard_stripped != _repaired:
            # product token(s) were stripped — re-anchor in the filtered title for full name
            _stripped_key_tokens = _normalize_person_key(_hard_stripped).split()
            _reanchored = ""
            if _stripped_key_tokens and _filtered_title_tokens:
                _reanchor_positions = [
                    _idx
                    for _idx, _token in enumerate(_filtered_title_lowers)
                    if _token in set(_stripped_key_tokens)
                ]
                for _start_idx in _reanchor_positions:
                    _span_parts2: List[str] = []
                    _main_parts2 = 0
                    for _token in _filtered_title_tokens[_start_idx:]:
                        _span_parts2.append(str(_token or "").strip())
                        _main_parts2 += 1
                        if _main_parts2 >= max(2, len(_stripped_key_tokens)):
                            break
                    _candidate_span = _sanitize_query_player_name(" ".join(_span_parts2).strip())
                    if _candidate_span:
                        _reanchored = _candidate_span
                        break
            _repaired = _reanchored or _hard_stripped
            _reason = "hard_strip_then_reanchor" if _reanchored else "hard_strip_product_token"
    # --- re-filter and canonicalize ---
    _repaired_tokens = _filter_player_anchor_tokens(_repaired)
    if _repaired_tokens:
        _repaired = _sanitize_query_player_name(" ".join(_repaired_tokens).strip())
    _repaired_key = _normalize_person_key(_ascii_fold_query_name(_repaired))
    if _repaired_key and _canon_map.get(_repaired_key):
        _repaired = str(_canon_map.get(_repaired_key) or _repaired).strip()
    if not _repaired and _candidate_clean:
        _candidate_tokens = set(
            _normalize_person_key(_candidate_clean or "").split()
        )
        _title_tokens = set(
            _normalize_person_key(" ".join(_filtered_title_tokens or [])).split()
        )

        if _candidate_tokens and _candidate_tokens.issubset(_title_tokens):
            _repaired = _candidate_clean or ""
            _reason = "candidate_preserved"
        else:
            _repaired = ""
            _reason = "candidate_not_in_title"
    print(
        f"[PLAYER_ANCHOR_REPAIR] title={_title[:140]} candidate_player={_candidate_raw[:48]} "
        f"repaired_player={str(_repaired or '')[:48]} reason={_reason}"
    )
    return str(_repaired or _candidate_clean or _candidate_raw).strip()


def _emit_base_card_number_carry(title: Any, parsed_card_number: Any, carried_card_number: Any, source: str) -> None:
    print(
        f"[BASE_CARD_NUMBER_CARRY] title={str(title or '')[:140]} "
        f"parsed_card_number={str(parsed_card_number or '')[:16]} "
        f"carried_card_number={str(carried_card_number or '')[:16]} "
        f"source={source}"
    )


def _stamp_base_card_number_before_identity(row: Dict[str, Any]) -> Dict[str, Any]:
    _row = row if isinstance(row, dict) else dict(row or {})
    _title = str(_row.get("title") or _row.get("source_title") or "").strip()
    _existing_card = str(_row.get("card_number") or _row.get("identity_card_number") or "").strip().upper()
    _insertish = bool(
        str(
            _row.get("identity_insert_family")
            or _row.get("fingerprint_insert_family")
            or _row.get("fingerprint_subset")
            or _row.get("subset_name")
            or _row.get("subset_family")
            or ""
        ).strip()
    )
    _lane_type = str(_row.get("identity_lane_type") or _row.get("lane_type") or "").strip().lower()
    if _existing_card or _insertish or _lane_type == "insert" or _is_topps_insert_candidate(_row.get("product_family") or _row.get("target_product_family") or "", _title):
        return _row
    _profile = parse_listing_profile(_title) if _title else None
    _sources = (
        ("parsed_card_number", _row.get("parsed_card_number")),
        ("fingerprint_card_number", _row.get("fingerprint_card_number")),
        ("subset_parse_card_number", (_row.get("_subset_parse_result") or {}).get("card_number") if isinstance(_row.get("_subset_parse_result"), dict) else ""),
        ("exact_rescue_card_number", _row.get("exact_card_number")),
        ("target_card_number", _row.get("target_card_number")),
        ("profile_card_number", getattr(_profile, "card_number", "") if _profile is not None else ""),
    )
    for _source, _value in _sources:
        _normalized = _normalize_topps_insert_card_number(_value)
        if _normalized:
            _row["card_number"] = _normalized
            _row["_pre_identity_card_number"] = _normalized
            _row["_pre_identity_card_number_source"] = _source
            print(
                f"[BASE_CARD_NUMBER_PRESTAMP] title={_title[:140]} card_number={_normalized[:16]} source={_source}"
            )
            break
    return _row


def _stamp_insert_identity_before_clean_identity(row: Dict[str, Any]) -> Dict[str, Any]:
    _row = row if isinstance(row, dict) else dict(row or {})
    _title = str(_row.get("title") or _row.get("source_title") or "").strip()
    _grade_state = str(_row.get("identity_grade") or _row.get("grade") or _row.get("grade_value") or "").strip()
    _insert_family = str(
        _row.get("identity_insert_family")
        or _row.get("fingerprint_insert_family")
        or _row.get("insert_family")
        or _row.get("subset_name")
        or _row.get("subset_family")
        or ""
    ).strip()
    _card_number = str(
        _row.get("identity_card_number")
        or _row.get("fingerprint_card_number")
        or _row.get("card_number")
        or ""
    ).strip().upper()
    if _insert_family and _card_number:
        _row["_insert_identity_persisted"] = True
        if _grade_state:
            print(
                f"[GRADED_INSERT_ROUTE] title={_title[:140]} insert_family={_insert_family[:32]} "
                f"card_number={_card_number[:16]} route=insert_aware"
            )
        return _row
    _product_family = str(_row.get("product_family") or _row.get("target_product_family") or "").strip()
    _player = str(_row.get("player_name") or _row.get("target_player_name") or "").strip()
    _year = str(_row.get("year") or _row.get("card_year") or "").strip()
    _topps_insert_ctx = _extract_topps_insert_context(
        _title,
        product_family=_product_family,
        card_number=_card_number or _row.get("target_card_number") or "",
        player=_player,
        year=_year,
        grade_state=_grade_state,
    )
    _promoted_insert = str(_topps_insert_ctx.get("insert_family") or "").strip()
    _promoted_card = str(_topps_insert_ctx.get("card_number") or "").strip().upper()
    if _promoted_insert:
        _row["insert_family"] = _promoted_insert
        _row["subset_name"] = str(_row.get("subset_name") or _promoted_insert)
        _row["subset_family"] = str(_row.get("subset_family") or _promoted_insert)
        _row["identity_insert_family"] = str(_row.get("identity_insert_family") or _promoted_insert)
        _row["fingerprint_insert_family"] = str(_row.get("fingerprint_insert_family") or _promoted_insert)
        if _promoted_card:
            _row["card_number"] = _promoted_card
            _row["identity_card_number"] = str(_row.get("identity_card_number") or _promoted_card)
            _row["fingerprint_card_number"] = str(_row.get("fingerprint_card_number") or _promoted_card)
        _row["_insert_identity_persisted"] = True
        print(
            f"[INSERT_IDENTITY_PERSIST] title={_title[:140]} insert_family={_promoted_insert[:32]} "
            f"card_number={_promoted_card[:16]} reason=graded_insert_pre_identity"
        )
        if _grade_state:
            print(
                f"[GRADED_INSERT_ROUTE] title={_title[:140]} insert_family={_promoted_insert[:32]} "
                f"card_number={_promoted_card[:16]} route=insert_aware"
            )
    return _row


def _resolve_insert_card_locator(title: Any, insert_family: Any, product_family: Any) -> str:
    _title = str(title or "").strip()
    _insert_family = str(insert_family or "").strip()
    _product_family = str(product_family or "").strip()
    if not _title or not _insert_family:
        return ""
    _card_match = _TOPPS_INSERT_CARD_NUMBER_RE.search(_title)
    _card_token = _normalize_topps_insert_card_number(_card_match.group(1)) if _card_match else ""
    if _card_token and _is_topps_insert_style_card_number(_card_token):
        return _card_token
    return ""


def _has_valid_insert_locator(row):
    try:
        if not isinstance(row, dict):
            return False, "not_dict"
        _carry_canonical_serial_identity(row)

        insert_family = str(
            row.get("_hydrated_insert_family")
            or row.get("insert_family")
            or ""
        ).strip().lower()

        parallel_family = str(
            row.get("_hydrated_parallel_family")
            or row.get("parallel_family")
            or ""
        ).strip().lower()

        serial_denominator = str(
            row.get("_canonical_serial_denominator")
            or row.get("_lane_serial_denominator")
            or row.get("_hydrated_serial_denominator")
            or row.get("serial_denominator")
            or ""
        ).strip()

        serial = str(
            row.get("_hydrated_serial")
            or row.get("serial")
            or ""
        ).strip()

        card_number = str(
            row.get("_hydrated_card_number")
            or row.get("card_number")
            or ""
        ).strip()

        product_family = str(
            row.get("_hydrated_product_family")
            or row.get("product_family")
            or ""
        ).strip().lower()

        identity_is_clean = bool(
            row.get("_hydrated_identity_is_clean")
            or row.get("identity_is_clean")
        )

        if _has_valid_auto_parallel_locator(
            {
                **dict(row or {}),
                "lane_type": str(row.get("_hydrated_lane_type") or row.get("lane_type") or ""),
                "insert_family": insert_family,
                "parallel_family": parallel_family,
                "product_family": product_family,
            }
        ):
            return True, "auto_parallel_locator"

        if card_number:
            return True, "card_number_present"

        if parallel_family and parallel_family != "base" and serial_denominator:
            return True, "parallel_serial_locator"

        if (
            identity_is_clean
            and insert_family
            and parallel_family in {"logofractor", "gold", "orange", "red", "black", "refractor", "x-fractor"}
            and serial_denominator
        ):
            return True, "named_insert_parallel_serial"

        if (
            identity_is_clean
            and insert_family in {"future stars", "image_variation", "variation"}
            and serial_denominator
        ):
            return True, "named_insert_serial"

        _serial_auto_allow, _serial_auto_reason = _serial_auto_base_parallel_contract(
            {
                **dict(row or {}),
                "insert_family": insert_family,
                "parallel_family": parallel_family,
                "serial_denominator": serial_denominator,
                "product_family": product_family,
                "identity_is_clean": identity_is_clean,
            }
        )
        if _serial_auto_allow:
            return True, _serial_auto_reason

        return False, "missing_locator"
    except Exception as e:
        return False, f"error:{e}"


def _stamp_insert_card_locator_before_comp_query(row: Dict[str, Any]) -> Dict[str, Any]:
    _row = row if isinstance(row, dict) else dict(row or {})
    _carry_canonical_serial_identity(_row)
    _title = str(_row.get("title") or _row.get("source_title") or "").strip()
    _insert_family = str(
        _row.get("identity_insert_family")
        or _row.get("fingerprint_insert_family")
        or _row.get("insert_family")
        or _row.get("subset_name")
        or _row.get("subset_family")
        or ""
    ).strip()
    _parallel_family = str(
        _row.get("identity_parallel_family")
        or _row.get("parallel_family")
        or _row.get("parallel_name")
        or _row.get("parallel")
        or ""
    ).strip()
    _serial_denominator = str(
        _row.get("_canonical_serial_denominator")
        or _row.get("_lane_serial_denominator")
        or _row.get("serial_denominator")
        or _row.get("fingerprint_serial_denominator")
        or _row.get("serial")
        or ""
    ).strip()
    if not (_insert_family and ((_parallel_family and _parallel_family.lower() != "base") or _serial_denominator)):
        return _row
    _existing_card = _normalize_topps_insert_card_number(
        _row.get("identity_card_number")
        or _row.get("fingerprint_card_number")
        or _row.get("card_number")
        or ""
    )
    if _existing_card:
        return _row
    _resolved_card = _resolve_insert_card_locator(
        _title,
        _insert_family,
        _row.get("product_family") or _row.get("target_product_family") or "",
    )
    if not _resolved_card:
        _locator_ok, _locator_reason = _has_valid_insert_locator(_row)
        print(
            f"[INSERT_LOCATOR_CHECK] title={str((_row or {}).get('title') or '')[:160]} "
            f"ok={_locator_ok} "
            f"reason={_locator_reason} "
            f"insert_family={_row.get('_hydrated_insert_family') or _row.get('insert_family')} "
            f"parallel_family={_row.get('_hydrated_parallel_family') or _row.get('parallel_family')} "
            f"serial_denominator={_row.get('_hydrated_serial_denominator') or _row.get('serial_denominator')} "
            f"serial={_row.get('_hydrated_serial') or _row.get('serial')} "
            f"parsed_serial={_row.get('parsed_serial')} "
            f"card_number={_row.get('_hydrated_card_number') or _row.get('card_number')}"
        )
        if _locator_ok:
            _row["_insert_locator_override"] = True
            _row["_insert_locator_override_reason"] = _locator_reason
            print(
                f"[INSERT_LOCATOR_OVERRIDE] title={str((_row or {}).get('title') or '')[:160]} "
                f"reason={_locator_reason}"
            )
            return _row
        print(
            f"[INSERT_CARD_LOCATOR_MISSING] title={_title[:140]} insert_family={_insert_family[:32]}"
        )
        return _row
    _row["card_number"] = _resolved_card
    if not str(_row.get("identity_card_number") or "").strip():
        _row["identity_card_number"] = _resolved_card
    if not str(_row.get("fingerprint_card_number") or "").strip():
        _row["fingerprint_card_number"] = _resolved_card
    print(
        f"[INSERT_CARD_LOCATOR_RESOLVE] title={_title[:140]} insert_family={_insert_family[:32]} "
        f"card_number={_resolved_card[:16]} reason=title_token"
    )
    print(
        f"[COMP_QUERY_CARD_PRESTAMP] title={_title[:140]} card_number={_resolved_card[:16]} lane_type="
        f"{str(_row.get('identity_lane_type') or _row.get('lane_type') or 'insert_parallel')[:24]}"
    )
    return _row


def _clean_topps_identity_player(
    title: str,
    raw_player: Any,
    row: Optional[Dict[str, Any]] = None,
    product_family: Any = "",
    brand: Any = "",
) -> str:
    _title = str(title or "").strip()
    _raw_player = str(raw_player or "").strip()
    _row = row or {}
    _clean_player = _raw_player
    try:
        _entity = _canonical_normalized_entity(_row) if isinstance(_row, dict) else ""
    except Exception:
        _entity = ""
    _seed = (player_hub.players_by_id() or {}).get(_entity) if _entity else None
    _seed_player = str((_seed or {}).get("player_name") or (_seed or {}).get("display_name") or "").strip()
    if _seed_player:
        _clean_player = _seed_player
    if not _clean_player:
        _clean_player = str(
            _row.get("player_name")
            or _row.get("target_player_name")
            or _row.get("player_display")
            or ""
        ).strip()
    _clean_candidate = " ".join(_filter_player_anchor_tokens(_clean_player)).strip()
    if _clean_candidate:
        _clean_player = _clean_candidate
    _repaired_player = _repair_topps_player_from_title(_title, _clean_player)
    if _repaired_player:
        _clean_player = _repaired_player
    _anchored_player = _repair_player_from_title_anchor(
        _title,
        _clean_player,
        product_family or _row.get("product_family") or _row.get("target_product_family") or "",
        brand or _row.get("identity_brand") or _row.get("fingerprint_brand") or "",
    )
    if _anchored_player:
        _clean_player = _anchored_player
    _clean_player = _sanitize_query_player_name(_clean_player)
    if _clean_player:
        _player_tokens = set(_normalize_person_key(_clean_player).split())
        _title_tokens = set(_normalize_person_key(_title).split())

        if not _player_tokens.issubset(_title_tokens):
            print(f"[PLAYER_INVALIDATED_NOT_IN_TITLE] title={_title[:120]} player={_clean_player}")
            _clean_player = ""
            _identity_clean = False
    if _clean_player and _clean_player == _clean_player.lower():
        _clean_player = " ".join(_part.capitalize() for _part in _clean_player.split())
    if "topps chrome" in _title.lower() and _clean_player != _raw_player:
        print(
            f"[BASE_PLAYER_CLEANUP] title={_title[:140]} raw_player={_raw_player[:48]} "
            f"clean_player={_clean_player[:48]}"
        )
    if _clean_player != _raw_player:
        print(
            f"[PLAYER_PARSE_CLEANUP] title={_title[:140]} raw_player={_raw_player[:48]} "
            f"clean_player={_clean_player[:48]}"
        )
    return _clean_player.strip()


def _is_topps_insert_candidate(product_family: Any, title: str = "") -> bool:
    _product = str(product_family or "").lower().replace("_", " ")
    _title = str(title or "").lower()
    _title_norm = re.sub(r"[^a-z0-9\s]+", " ", _title)
    _title_norm = " ".join(_title_norm.split())
    if "topps chrome" not in f"{_product} {_title_norm}":
        return False
    _card_match = _TOPPS_INSERT_CARD_NUMBER_RE.search(_title)
    _card_token = _normalize_topps_insert_card_number(_card_match.group(1)) if _card_match else ""
    return bool(
        any(_needle in _title_norm for _needle, _ in _TOPPS_INSERT_FAMILY_TOKENS)
        or _is_topps_insert_style_card_number(_card_token)
    )


def _resolve_named_insert_family(title: Any, product_family: Any, card_number: Any) -> Dict[str, str]:
    _title = str(title or "").strip()
    _title_norm = re.sub(r"[^a-z0-9\s-]+", " ", _title.lower())
    _title_norm = " ".join(_title_norm.split())
    _product_norm = _normalize_exact_product_family(str(product_family or "").strip() or _title)
    _card = _normalize_topps_insert_card_number(card_number)
    _card_prefix = str(_card.split("-", 1)[0] if _card else "").strip().upper()
    _topps_chrome_like = _product_norm in {"topps chrome", "topps chrome update", "topps chrome logofractor", "topps_chrome", "topps_chrome_update", "topps_chrome_logofractor"} or "topps chrome" in _product_norm.replace("_", " ")
    _named_mappings: Tuple[Tuple[str, str, str], ...] = (
        ("lightning leaders", "LL", "lightning leaders"),
        ("future stars", "FS", "future stars"),
        ("all etch", "AE", "all etch"),
    )
    for _phrase, _prefix, _family in _named_mappings:
        if _phrase in _title_norm:
            if _card_prefix == _prefix:
                return {
                    "insert_family": _family,
                    "reason": "title_card_prefix_match",
                }
            if _topps_chrome_like:
                return {
                    "insert_family": _family,
                    "reason": "title_phrase_match",
                }
    return {
        "insert_family": "",
        "reason": "",
    }


def _extract_topps_insert_context(
    title: str,
    *,
    product_family: Any = "",
    card_number: Any = "",
    player: Any = "",
    year: Any = "",
    grade_state: Any = "",
) -> Dict[str, str]:
    _title = str(title or "").strip()
    _title_lower = _title.lower()
    _title_norm = re.sub(r"[^a-z0-9\s]+", " ", _title_lower)
    _title_norm = " ".join(_title_norm.split())
    _product_raw = str(product_family or "").strip()
    _product_norm = _normalize_exact_product_family(_product_raw or _title)
    if any(_needle in _title_norm for _needle in ("topps chrome sapphire", "chrome sapphire edition")):
        _product_norm = "topps_chrome_sapphire"
    elif "update series" in _title_norm and "topps chrome" in _title_norm:
        _product_norm = "topps chrome update"
    elif "logofractor" in _title_norm and "topps chrome" in _title_norm:
        _product_norm = "topps chrome logofractor"
    elif "topps chrome" in _title_norm and not _product_norm:
        _product_norm = "topps chrome"
    _insert_family = ""
    for _needle, _family in _TOPPS_INSERT_FAMILY_TOKENS:
        if _needle in _title_norm:
            _insert_family = _family
            break
    _insert_signal_ctx = _resolve_insert_family_signals(_title, _product_norm, _insert_family)
    if str(_insert_signal_ctx.get("insert_family") or "").strip():
        _insert_family = str(_insert_signal_ctx.get("insert_family") or "").strip()
    _card_number = _normalize_topps_insert_card_number(card_number)
    if not _card_number:
        _m = _TOPPS_INSERT_CARD_NUMBER_RE.search(_title)
        if _m:
            _matched_card = _normalize_topps_insert_card_number(_m.group(1))
            if _is_topps_insert_style_card_number(_matched_card) or _insert_family:
                _card_number = _matched_card
    if _looks_like_serial_only_token(_card_number) and not _should_preserve_topps_card_number(
        _title,
        _product_norm,
        _card_number,
        insert_family=_insert_family,
    ):
        _card_number = ""
    if not _insert_family and _card_number:
        if _card_number.startswith("ASGC-"):
            _insert_family = "all_star_game"
        elif _card_number.startswith("SITP-"):
            _insert_family = "summertime_in_the_park"
        elif _card_number.startswith("F15-"):
            _insert_family = "fortune_15"
        elif _card_number.startswith("90CB-"):
            _insert_family = "90cb"
        elif _card_number.startswith("89CU-"):
            _insert_family = "1989_topps_baseball"
    if not _insert_family:
        _named_insert_ctx = _resolve_named_insert_family(_title, _product_norm, _card_number)
        if str(_named_insert_ctx.get("insert_family") or "").strip():
            _insert_family = str(_named_insert_ctx.get("insert_family") or "").strip()
            print(
                f"[NAMED_INSERT_RESOLVE] title={_title[:140]} insert_family={_insert_family} "
                f"card_number={_card_number} reason={str(_named_insert_ctx.get('reason') or 'title_phrase_match')}"
            )
            print(
                f"[INSERT_PROMOTION_FROM_TITLE] title={_title[:140]} insert_family={_insert_family}"
            )
    _promoted = 1 if _insert_family else 0
    _promotion_reason = str(_insert_signal_ctx.get("reason") or "").strip()
    if not _promotion_reason:
        _promotion_reason = "title_token" if _insert_family else "no_insert_family"
    _player_name = _clean_topps_identity_player(_title, player, {"title": _title, "player_name": str(player or "").strip()})
    _year_value = str(year or "").strip()
    _grade = str(grade_state or "").strip().lower()
    _missing: List[str] = []
    if not _player_name:
        _missing.append("player")
    if not _year_value:
        _missing.append("year")
    if not _product_norm or "topps chrome" not in _product_norm:
        _missing.append("product_family")
    if not _insert_family:
        _missing.append("insert_family")
    if not _card_number:
        _missing.append("card_number")
    _identity_clean = not _missing
    if _year_value:
        try:
            _year_num = int(_year_value)
        except (TypeError, ValueError):
            _year_num = 0
        if _year_num >= 2026 and "topps chrome" in _product_norm:
            print(f"[YEAR_SANITY_FLAG] title={_title[:140]} year={_year_value} product_family={_product_norm}")
    print(
        f"[TOPPS_INSERT_PARSE] title={_title[:140]} product_family={_product_norm} "
        f"insert_family={_insert_family} card_number={_card_number} player={_player_name[:40]} "
        f"year={_year_value} identity_clean={1 if _identity_clean else 0}"
    )
    print(
        f"[INSERT_CONTRACT_PROMOTION] title={_title[:140]} insert_family={_insert_family[:32]} "
        f"card_number={_card_number[:16]} promoted={_promoted} reason={_promotion_reason}"
    )
    if not _identity_clean and _is_topps_insert_candidate(_product_norm, _title):
        print(
            f"[TOPPS_INSERT_ASSERT] title={_title[:140]} reason=missing_insert_contract "
            f"missing_fields={','.join(_missing)}"
        )
    return {
        "product_family": _product_norm,
        "insert_family": _insert_family,
        "card_number": _card_number,
        "player": _player_name,
        "year": _year_value,
        "grade_state": _grade,
        "identity_clean": "1" if _identity_clean else "",
    }


def _resolve_insert_family_signals(
    title: Any,
    product_family: Any,
    insert_family: Any,
) -> Dict[str, Any]:
    _title = str(title or "").strip()
    _title_norm = re.sub(r"[^a-z0-9\s]+", " ", _title.lower().replace("-", " "))
    _title_norm = f" {' '.join(_title_norm.split())} "
    _product = _normalize_exact_product_family(str(product_family or _title or ""))
    _insert_before = _normalize_subset_name(str(insert_family or "").strip())
    if _looks_like_serial_only_token(_insert_before):
        _insert_before = ""
    _insert_after = _insert_before
    _detected = ""
    _reason = "no_insert_family"
    _is_toppsish = "topps" in f"{_product} {_title_norm}"
    _is_paniniish = _is_panini_identity_product_family(_product, _title)
    _variation_patterns: Tuple[Tuple[str, str], ...] = (
        (r"\bimage variation\b", "Image Variation"),
        (r"\bphoto variation\b", "Image Variation"),
        (r"\bvariation(?:s)?\b", "Image Variation"),
        (r"\bssp\b", "Image Variation"),
        (r"\bsp\b", "Image Variation"),
    )
    if _insert_before in {"image_variation", "photo_variation", "variation", "ssp", "sp"}:
        _insert_after = "image_variation"
        _detected = "Image Variation"
        _reason = "variation_detected"
    elif not _insert_after and _is_toppsish:
        for _pattern, _label in _variation_patterns:
            if re.search(_pattern, _title_norm, flags=re.IGNORECASE):
                _insert_after = "image_variation"
                _detected = _label
                _reason = "variation_detected"
                break
    _panini_known_families = {
        "fractal", "emergent", "fireworks", "hype", "instant_impact", "brilliance",
        *_PANINI_PREMIUM_INSERT_FAMILIES,
    }
    # Detect Panini brand tokens directly in the title — covers cards where product_family
    # is blank, an insert name, or not yet recognized as Panini by _is_paniniish
    _panini_title_signal = _is_paniniish or any(
        f" {_tok} " in _title_norm
        for _tok in ("panini", "prizm", "mosaic", "select", "optic", "donruss")
    )
    if _insert_after in _panini_known_families:
        _detected = _detected or _insert_after.replace("_", " ").title()
        if _reason == "no_insert_family":
            _reason = "normalize_existing_panini_insert"
    elif not _insert_after and _panini_title_signal:
        for _pattern, _label, _family in _PANINI_INSERT_PROMOTION_PATTERNS:
            if re.search(_pattern, _title_norm, flags=re.IGNORECASE):
                _insert_after = _family
                _detected = _label
                _reason = "panini_insert_token_promoted"
                break
    if not _insert_after:
        _card_match = _TOPPS_INSERT_CARD_NUMBER_RE.search(_title)
        _card_token = _normalize_topps_insert_card_number(_card_match.group(1)) if _card_match else ""
        _named_insert_ctx = _resolve_named_insert_family(_title, _product, _card_token)
        if str(_named_insert_ctx.get("insert_family") or "").strip():
            _insert_after = str(_named_insert_ctx.get("insert_family") or "").strip()
            _detected = _insert_after.replace("_", " ").title()
            _reason = str(_named_insert_ctx.get("reason") or "title_phrase_match")
            print(
                f"[NAMED_INSERT_RESOLVE] title={_title[:140]} insert_family={_insert_after} "
                f"card_number={_card_token[:16]} reason={_reason}"
            )
            print(
                f"[INSERT_PROMOTION_FROM_TITLE] title={_title[:140]} insert_family={_insert_after}"
            )
    _promoted = bool(not _insert_before and _insert_after and _insert_after != _insert_before)
    if _panini_title_signal and _insert_after in _panini_known_families and (_detected or _promoted or _insert_before != _insert_after):
        print(
            f"[PANINI_INSERT_PROMOTION] title={_title[:140]} detected={_detected[:32]} "
            f"promoted_insert_family={_insert_after[:32]} reason={_reason}"
        )
    return {
        "product_family": _product,
        "insert_family_before": _insert_before,
        "insert_family": _insert_after,
        "detected": _detected,
        "promoted": _promoted,
        "reason": _reason,
    }


def _title_has_auto_negation(title: Any) -> bool:
    _title = f" {str(title or '').strip().lower().replace('-', ' ')} "
    return any(
        _phrase in _title
        for _phrase in (
            " non auto ",
            " no auto ",
            " not auto ",
            " not an auto ",
            " no autograph ",
            " non autograph ",
            " non autographs ",
        )
    )


def _is_fake_serial_base_promo_row(row):
    try:
        if not isinstance(row, dict):
            return False, "not_dict"

        title = str(row.get("title") or row.get("raw_title") or "").strip().lower()
        lane_type = str(row.get("lane_type") or "").strip().lower()
        parallel_family = str(row.get("parallel_family") or "").strip().lower()
        insert_family = str(row.get("insert_family") or "").strip().lower()
        serial_denominator = str(row.get("serial_denominator") or row.get("serial") or "").strip()
        if not serial_denominator:
            try:
                serial_denominator = str(_extract_serial_denominator(title) or "").strip()
            except Exception:
                serial_denominator = ""
        card_number = str(row.get("card_number") or "").strip()

        promo_terms = {
            "hrc winner",
            "home run challenge",
            "winner",
            "bai-",
            "hrcw-",
            "redemption",
            "lottery",
            "sweepstakes",
        }

        if not serial_denominator:
            return False, "no_serial"

        if parallel_family not in {"", "base", "none"}:
            return False, "has_real_parallel"

        if card_number:
            return False, "has_card_number"

        if insert_family:
            return False, "has_insert_family"

        if any(term in title for term in promo_terms):
            return True, "promo_serial_base"

        if lane_type == "parallel_serial" and parallel_family in {"base", "", "none"} and not card_number:
            return True, "serial_base_without_locator"

        return False, "not_fake_serial_base"
    except Exception as e:
        return False, f"error:{e}"


def _is_fake_serial_base_promo_hard_block(row):
    try:
        if not isinstance(row, dict):
            return False
        _identity_is_clean = bool(row.get("identity_is_clean") or row.get("_hydrated_identity_is_clean"))
        _reason = str(
            row.get("identity_clean_reason")
            or row.get("_identity_clean_reason")
            or ""
        ).strip().lower()
        return bool((not _identity_is_clean) and _reason == "fake_serial_base_promo")
    except Exception:
        return False


def _apply_fake_serial_base_promo_hard_block(row, *, stage, seed_allowed=0, junk_override_allowed=0, final_true_allowed=0):
    if not isinstance(row, dict) or not _is_fake_serial_base_promo_hard_block(row):
        return False
    _title = str(row.get("title") or row.get("source_title") or "").strip()
    _identity_is_clean = bool(row.get("identity_is_clean") or row.get("_hydrated_identity_is_clean"))
    _reason = str(row.get("identity_clean_reason") or row.get("_identity_clean_reason") or "").strip()
    row["truth"] = "NONE"
    row["truth_level"] = "NONE"
    row["_valuation_truth_tier"] = "NONE"
    row["valuation_truth_tier"] = "NONE"
    row["valuation_truth_level"] = "NONE"
    row["exact_truth_rescued"] = False
    row["_exact_truth_rescued"] = False
    row["exact_truth_rescue_reason"] = "fake_serial_base_promo"
    row["true_market_value"] = None
    row["market_value_true"] = None
    row["has_true_market_value"] = False
    row["_fake_serial_base_promo_hard_block"] = True
    row["_fake_serial_base_promo_hard_block_stage"] = str(stage or "")
    print(
        f"[FAKE_SERIAL_HARD_BLOCK] "
        f"title={_title[:160]} "
        f"identity_is_clean={1 if _identity_is_clean else 0} "
        f"identity_clean_reason={_reason} "
        f"stage={str(stage or '')}"
    )
    print(
        f"[FAKE_SERIAL_HARD_ASSERT] "
        f"title={_title[:160]} "
        f"truth={row.get('valuation_truth_tier') or row.get('truth') or 'NONE'} "
        f"truth_level={row.get('valuation_truth_level') or row.get('truth_level') or 'NONE'} "
        f"seed_allowed={int(bool(seed_allowed))} "
        f"junk_override_allowed={int(bool(junk_override_allowed))} "
        f"final_true_allowed={int(bool(final_true_allowed))}"
    )
    return True


def _resolve_autograph_lane_signals(
    title: Any,
    product_family: Any,
    insert_family: Any,
    parallel_family: Any,
) -> Dict[str, Any]:
    _title = str(title or "").strip()
    _title_lower = f" {_title.lower().replace('-', ' ')} "
    _product = _normalize_exact_product_family(str(product_family or _title or ""))
    _insert_before = _normalize_subset_name(str(insert_family or "").strip())
    if _looks_like_serial_only_token(_insert_before):
        _insert_before = ""
    _parallel = str(parallel_family or "").strip().lower().replace(" ", "_")
    _auto_negated = _title_has_auto_negation(_title)
    if _auto_negated:
        print(
            f"[AUTO_NEGATION_GUARD] title={_title[:140]} reason=non_auto_phrase"
        )
    _has_auto = bool(
        not _auto_negated
        and (
            re.search(r"\b(auto|autograph|autographs|signed|signature|signatures)\b", _title_lower, flags=re.IGNORECASE)
            or any(
                _tok in _title_lower
                for _tok in (
                    " on card auto ",
                    " on-card auto ",
                    " sticker auto ",
                    " auto rc ",
                    " patch auto ",
                    " auto patch ",
                    " rookie patch autograph ",
                    " rpa ",
                )
            )
        )
    )
    _insert_after = _insert_before
    if _has_auto:
        if not _insert_after:
            _insert_after = "auto"
            _reason = "title_token_promote_auto_insert"
        elif _insert_before in {"auto", "autograph", "autographs"}:
            _insert_after = "auto"
            _reason = "normalize_existing_auto_insert"
        else:
            _reason = "title_token_preserve_existing_insert"
    else:
        _reason = "no_auto_signal"
    if _auto_negated:
        _insert_after = _insert_before
        _reason = "auto_negation"
        print(
            f"[AUTO_PROMOTION_BLOCKED] title={_title[:140]} reason=auto_negation"
        )
    if _has_auto or _insert_before != _insert_after:
        print(
            f"[AUTO_LANE_PROMOTION] title={_title[:140]} "
            f"product_family={_product[:48]} "
            f"insert_family_before={_insert_before[:24]} "
            f"insert_family_after={_insert_after[:24]} "
            f"has_auto={1 if _has_auto else 0} reason={_reason} "
            f"parallel_family={_parallel[:24]}"
        )
    return {
        "product_family": _product,
        "insert_family_before": _insert_before,
        "insert_family": _insert_after,
        "parallel_family": _parallel,
        "has_auto": bool(_has_auto),
        "reason": _reason,
    }


def _has_valid_auto_parallel_locator(row: Dict[str, Any]) -> bool:
    if not isinstance(row, dict):
        return False
    _title = str(row.get("title") or row.get("source_title") or "").strip().lower()
    _lane_type = str(
        row.get("identity_lane_type")
        or row.get("query_contract_lane_type")
        or row.get("lane_type")
        or row.get("_hydrated_lane_type")
        or ""
    ).strip().lower()
    _insert_family = str(
        row.get("identity_insert_family")
        or row.get("query_contract_insert_family")
        or row.get("insert_family")
        or row.get("_hydrated_insert_family")
        or row.get("fingerprint_insert_family")
        or ""
    ).strip().lower().replace(" ", "_")
    _parallel_family = str(
        row.get("identity_parallel_family")
        or row.get("query_contract_parallel_family")
        or row.get("parallel_family")
        or row.get("_hydrated_parallel_family")
        or row.get("fingerprint_parallel")
        or row.get("parallel")
        or ""
    ).strip().lower().replace(" ", "_")
    _product_family = str(
        row.get("identity_product_family")
        or row.get("query_contract_product_family")
        or row.get("product_family")
        or row.get("_hydrated_product_family")
        or row.get("fingerprint_product_family")
        or row.get("target_product_family")
        or ""
    ).strip()
    _player = str(
        row.get("identity_player")
        or row.get("query_contract_player")
        or row.get("player_name")
        or row.get("target_player_name")
        or row.get("player")
        or row.get("fingerprint_player")
        or row.get("player_display")
        or ""
    ).strip()
    _year = str(
        row.get("identity_year")
        or row.get("query_contract_year")
        or row.get("year")
        or row.get("card_year")
        or row.get("fingerprint_year")
        or ""
    ).strip()
    _has_auto = bool(
        _insert_family == "auto"
        or re.search(r"\b(auto|autograph|signatures?)\b", _title)
    )
    return bool(
        _lane_type in {"insert_parallel", "insert"}
        and _has_auto
        and _parallel_family
        and _parallel_family not in {"base", "none", "raw"}
        and _product_family
        and _player
        and _year
    )


def _log_auto_parallel_locator_allow(row: Dict[str, Any], *, reason: str = "auto_parallel_locator") -> None:
    _row = dict(row or {})
    print(
        f"[AUTO_PARALLEL_LOCATOR_ALLOW] title={str(_row.get('title') or _row.get('source_title') or '')[:140]} "
        f"product_family={str(_row.get('product_family') or _row.get('identity_product_family') or _row.get('query_contract_product_family') or '')[:48]} "
        f"insert_family={str(_row.get('insert_family') or _row.get('identity_insert_family') or _row.get('query_contract_insert_family') or '')[:32]} "
        f"parallel_family={str(_row.get('parallel_family') or _row.get('identity_parallel_family') or _row.get('query_contract_parallel_family') or '')[:32]} "
        f"player={str(_row.get('player_name') or _row.get('identity_player') or _row.get('query_contract_player') or _row.get('target_player_name') or '')[:48]} "
        f"year={str(_row.get('year') or _row.get('identity_year') or _row.get('query_contract_year') or '')[:8]} "
        f"reason={reason}"
    )


def _has_parallel_identity_completion_contract(row):
    try:
        if not isinstance(row, dict):
            return False
        _lane_type = str(row.get("lane_type") or row.get("_hydrated_lane_type") or "").strip().lower()
        _parallel_family = str(row.get("parallel_family") or row.get("_hydrated_parallel_family") or "").strip().lower()
        _card_number = str(row.get("card_number") or row.get("_hydrated_card_number") or "").strip()
        _player = str(row.get("player") or row.get("clean_player") or "").strip()
        _year = str(row.get("year") or row.get("_hydrated_year") or "").strip()
        _product_family = str(row.get("product_family") or row.get("_hydrated_product_family") or "").strip().lower()

        return bool(
            _lane_type in {"parallel_serial", "graded", "insert_parallel"}
            and _parallel_family not in {"", "base", "none"}
            and _card_number
            and _player
            and _year
            and _product_family
        )
    except Exception:
        return False


def _build_clean_identity_contract(row_or_title: Any) -> Dict[str, Any]:
    _row = row_or_title if isinstance(row_or_title, dict) else {"title": str(row_or_title or "")}
    if isinstance(_row, dict):
        _row = _stamp_base_card_number_before_identity(_row)
        _row = _stamp_insert_identity_before_clean_identity(_row)
    _title = str(_row.get("title") or _row.get("source_title") or row_or_title or "").strip()
    _profile = parse_listing_profile(_title) if _title else None
    _grade_ctx = _extract_grade_context(_title)
    _product_family = str(
        _row.get("identity_product_family")
        or _row.get("fingerprint_product_family")
        or _row.get("fingerprint_product")
        or _row.get("product_family")
        or _row.get("target_product_family")
        or getattr(_profile, "product_family", "")
        or getattr(_profile, "primary_set", "")
        or ""
    ).strip()
    _product_family = _normalize_exact_product_family(_product_family or _title)
    _sapphire_product_ctx = _resolve_sapphire_product_family(_title, _product_family)
    if str(_sapphire_product_ctx.get("product_family") or "").strip():
        _product_family = _guard_sapphire_product_family(
            _title,
            _product_family,
            str(_sapphire_product_ctx.get("product_family") or "").strip(),
            reason="clean_identity_initial_sapphire_preserve",
        )
    _cosmic_product_ctx = _resolve_cosmic_product_family(_title, _product_family)
    if str(_cosmic_product_ctx.get("product_family") or "").strip():
        _product_family = _guard_cosmic_product_family(
            _title,
            _product_family,
            str(_cosmic_product_ctx.get("product_family") or "").strip(),
            reason="clean_identity_initial_cosmic_preserve",
        )
    _brand = str(
        _row.get("identity_brand")
        or _row.get("fingerprint_brand")
        or ""
    ).strip().lower()
    _brand = _promote_identity_brand(_title, _product_family, _brand)
    _raw_player = str(
        _row.get("identity_player")
        or _row.get("player_display")
        or _row.get("player_name")
        or _row.get("target_player_name")
        or _row.get("player")
        or _row.get("fingerprint_player")
        or getattr(_profile, "player_guess", "")
        or ""
    ).strip()
    _player_display = str(
        _row.get("player_name")
        or _row.get("target_player_name")
        or getattr(_profile, "player_guess", "")
        or ""
    ).strip()
    _player = _clean_topps_identity_player(_title, _raw_player or _player_display, _row, _product_family, _brand)
    if not _player and _player_display:
        _player = _clean_topps_identity_player(_title, _player_display, _row, _product_family, _brand)
    _year = str(
        _row.get("identity_year")
        or _row.get("fingerprint_year")
        or _row.get("year")
        or _row.get("card_year")
        or getattr(_profile, "year", "")
        or ""
    ).strip()
    _insert_family = str(
        _row.get("identity_insert_family")
        or _row.get("fingerprint_insert_family")
        or _row.get("insert_family")
        or _row.get("fingerprint_subset")
        or _row.get("subset_name")
        or _row.get("subset_family")
        or _row.get("subset_product_family")
        or ""
    ).strip()
    _initial_insert_family = _insert_family
    if _looks_like_serial_only_token(_insert_family):
        _insert_family = ""
    _card_number = _normalize_topps_insert_card_number(
        _row.get("identity_card_number")
        or _row.get("fingerprint_card_number")
        or _row.get("card_number")
        or _row.get("target_card_number")
        or getattr(_profile, "card_number", "")
        or ""
    )
    _parsed_card_number = _card_number
    _pre_identity_card_number = str(_row.get("_pre_identity_card_number") or "").strip().upper()
    print(
        f"[IDENTITY_INPUT_ASSERT] title={_title[:140]} insert_family={_insert_family[:32]} "
        f"card_number={_card_number[:16]} lane_type={str(_row.get('identity_lane_type') or _row.get('lane_type') or '')[:24]}"
    )
    if _looks_like_serial_only_token(_card_number) and not _should_preserve_topps_card_number(
        _title,
        _product_family,
        _card_number,
        insert_family=_insert_family,
    ) and not _pre_identity_card_number:
        _card_number = ""
    _profile_parallel = normalize_parallel_bucket(_profile) if _profile is not None else ""
    _parallel_family = str(
        _row.get("identity_parallel_family")
        or _row.get("fingerprint_parallel")
        or _row.get("parallel_family")
        or _row.get("parallel_name")
        or (_row.get("target_meta") or {}).get("parallel")
        or _profile_parallel
        or _detect_parallel_in_title(_title)
        or ""
    ).strip().lower().replace("_", " ")
    _parallel_ctx = _normalize_parallel_family(_title, _product_family, _parallel_family)
    _parallel_family = str(_parallel_ctx.get("parallel_family") or _parallel_family or "").strip().lower().replace(" ", "_")
    if "topps chrome" in str(_product_family or "").lower() and _parallel_family == "purple_speckle" and re.search(
        r"\b(auto|autograph|autographs|signed|signature)\b",
        _normalize_product_probe_text(_title),
    ):
        print(
            f"[TOPPS_AUTO_PARALLEL_ASSERT] title={_title[:140]} parallel_family={_parallel_family[:24]}"
        )
    _grade_company = str(
        _row.get("identity_grade_company")
        or _row.get("grade_company")
        or _grade_ctx.get("grade_company")
        or ""
    ).strip().upper()
    _grade = str(
        _row.get("identity_grade")
        or _row.get("grade")
        or _row.get("grade_value")
        or _grade_ctx.get("grade_value")
        or ""
    ).strip().upper()
    _serial_denominator = str(
        _row.get("serial_denominator")
        or _row.get("serial_bucket")
        or _extract_serial_denominator(_title)
        or ""
    ).strip()
    _topps_product_ctx = _resolve_topps_product_family(
        _product_family or _title,
        title=_title,
        parallel_family=_parallel_family,
    )
    if str(_topps_product_ctx.get("product_family") or "").strip():
        _product_family = _guard_sapphire_product_family(
            _title,
            _product_family,
            str(_topps_product_ctx.get("product_family") or "").strip(),
            reason="clean_identity_topps_resolver_overwrite_blocked",
        )
        _product_family = _guard_cosmic_product_family(
            _title,
            _product_family,
            str(_topps_product_ctx.get("product_family") or "").strip(),
            reason="clean_identity_topps_resolver_overwrite_blocked",
        )
    if _product_family == "topps chrome black" and not _parallel_family:
        _parallel_family = "black"
    _product_key = _product_family.replace("_", " ").lower()
    _is_specific_topps_product = _brand == "topps" and _is_specific_topps_identity_product_family(_product_family)
    _is_topps_chrome = _brand == "topps" and "topps chrome" in _product_key
    _insert_candidate = _is_topps_insert_candidate(_product_family, _title)
    if _insert_candidate:
        _topps_insert_ctx = _extract_topps_insert_context(
            _title,
            product_family=_product_family,
            card_number=_card_number,
            player=_player or _player_display,
            year=_year,
            grade_state=_extract_grade_bucket(_title),
        )
        if str(_topps_insert_ctx.get("product_family") or "").strip():
            _product_family = _guard_sapphire_product_family(
                _title,
                _product_family,
                str(_topps_insert_ctx.get("product_family") or "").strip(),
                reason="clean_identity_insert_ctx_sapphire_preserve",
            )
            _product_family = _guard_cosmic_product_family(
                _title,
                _product_family,
                str(_topps_insert_ctx.get("product_family") or "").strip(),
                reason="clean_identity_insert_ctx_overwrite_blocked",
            )
        if str(_topps_insert_ctx.get("insert_family") or "").strip():
            _insert_family = str(_topps_insert_ctx.get("insert_family") or "").strip()
        if str(_topps_insert_ctx.get("card_number") or "").strip():
            _card_number = str(_topps_insert_ctx.get("card_number") or "").strip().upper()
        if str(_topps_insert_ctx.get("player") or "").strip():
            _player = str(_topps_insert_ctx.get("player") or "").strip()
        if str(_topps_insert_ctx.get("year") or "").strip():
            _year = str(_topps_insert_ctx.get("year") or "").strip()
    _topps_product_ctx = _resolve_topps_product_family(
        _product_family or _title,
        title=_title,
        parallel_family=_parallel_family,
    )
    if str(_topps_product_ctx.get("product_family") or "").strip():
        _product_family = _guard_sapphire_product_family(
            _title,
            _product_family,
            str(_topps_product_ctx.get("product_family") or "").strip(),
            reason="clean_identity_final_topps_overwrite_blocked",
        )
        _product_family = _guard_cosmic_product_family(
            _title,
            _product_family,
            str(_topps_product_ctx.get("product_family") or "").strip(),
            reason="clean_identity_final_topps_overwrite_blocked",
        )
    _brand = _promote_identity_brand(_title, _product_family, _brand)
    _player = _repair_player_from_title_anchor(_title, _player or _player_display, _product_family, _brand)
    _product_key = _product_family.replace("_", " ").lower()
    _is_specific_topps_product = _brand == "topps" and _is_specific_topps_identity_product_family(_product_family)
    _is_topps_chrome = _brand == "topps" and "topps chrome" in _product_key
    _insert_signal_ctx = _resolve_insert_family_signals(_title, _product_family, _insert_family)
    _identity_insert_promoted = False
    if str(_insert_signal_ctx.get("insert_family") or "").strip() and not _insert_family:
        _insert_family = str(_insert_signal_ctx.get("insert_family") or "").strip()
        _identity_insert_promoted = bool(_insert_signal_ctx.get("promoted"))
    if (
        str(_insert_signal_ctx.get("insert_family") or "").strip() == "image_variation"
        and not _initial_insert_family
        and str(_insert_signal_ctx.get("detected") or "").strip()
    ):
        _identity_insert_promoted = True
        print(
            f"[INSERT_PROMOTION] title={_title[:140]} "
            f"detected={str(_insert_signal_ctx.get('detected') or 'Image Variation')[:32]} "
            f"promoted_insert_family={_insert_family[:32]} "
            f"reason={str(_insert_signal_ctx.get('reason') or 'variation_detected')[:48]}"
        )
    _auto_ctx = _resolve_autograph_lane_signals(_title, _product_family, _insert_family, _parallel_family)
    _row_auto_signal = bool(
        _row.get("identity_has_auto")
        or _row.get("fingerprint_has_auto")
        or _row.get("query_contract_has_auto")
        or _row.get("has_auto")
        or _row.get("is_auto")
        or _row.get("autograph")
        or _row.get("is_autograph")
    )
    if str(_auto_ctx.get("insert_family") or "").strip() and (not _insert_family or _insert_family in {"auto", "autograph", "autographs"}):
        _insert_family = str(_auto_ctx.get("insert_family") or "").strip()
    _has_auto = bool(
        _row_auto_signal
        or _auto_ctx.get("has_auto")
        or _insert_family in {"auto", "autograph", "autographs"}
    )
    if _has_auto and not _insert_family:
        _insert_family = "auto"
    _has_parallel_signal = bool(_parallel_family and _parallel_family not in {"", "base"})
    _has_grade_signal = bool(_grade_company or _grade)
    # Lock in the structural base-lane flag BEFORE lane_type routing.
    # A card is structurally base if all post-enrichment signals are absent:
    # no insert family, no true parallel, no serial denominator.
    # This flag is used as a guard in the validation block so that a card
    # which is genuinely base can never be pushed into a stricter lane check
    # by an incidental signal (e.g. auto-insert promotion, grade number mis-parsed
    # as serial, etc.).
    _is_base_lane = (
        not _insert_family
        and (_parallel_family in {None, "", "base"})
        and not _serial_denominator
    )
    _lane_type = "base"
    if _insert_family and (_has_parallel_signal or _serial_denominator):
        _lane_type = "insert_parallel"
        _row["_premium_insert_parallel"] = True
        print(
            f"[PREMIUM_INSERT_LANE_OVERRIDE] title={_title[:140]} insert_family={_insert_family[:32]} "
            f"parallel={_parallel_family[:24]} serial={_serial_denominator[:16]}"
        )
    elif _has_parallel_signal or _serial_denominator:
        _lane_type = "parallel_serial"
    elif _insert_family:
        _lane_type = "insert"
    elif _has_grade_signal:
        _lane_type = "graded"
    if _row.get("serial") is not None and str(_row.get("serial")).strip():
        _serial_den = str(_row.get("serial")).strip()
    elif locals().get("serial_denominator") is not None and str(locals().get("serial_denominator")).strip():
        _serial_den = str(locals().get("serial_denominator")).strip()
    elif locals().get("_serial_denominator") is not None and str(locals().get("_serial_denominator")).strip():
        _serial_den = str(locals().get("_serial_denominator")).strip()
    else:
        _serial_den = ""

    if _serial_den:
        _row["_canonical_serial_denominator"] = _serial_den
        _row["_lane_serial_denominator"] = _serial_den
        _row["_hydrated_serial_denominator"] = _serial_den
        _row["serial_denominator"] = _serial_den
        _row["_hydrated_serial"] = _serial_den
        _row["serial"] = _serial_den

    print(
        f"[LANE_SERIAL_HARDSTAMP] title={str((_row or {}).get('title') or '')[:160]} "
        f"serial_denominator={_row.get('serial_denominator')} "
        f"canonical={_row.get('_canonical_serial_denominator')} "
        f"lane={_row.get('_lane_serial_denominator')} "
        f"serial={_row.get('serial')}"
    )
    print(
        f"[LANE_TYPE_CLASSIFY] title={_title[:140]} lane_type={_lane_type} "
        f"is_base_lane={1 if _is_base_lane else 0} "
        f"product_family={_product_family[:40]} insert_family={_insert_family[:32]} "
        f"parallel_family={_parallel_family[:24]} serial={_serial_denominator[:16]} "
        f"card_number={_card_number[:16]}"
    )
    _missing_player = 0 if _player else 1
    _missing_year = 0 if _year else 1
    _missing_brand = 0 if _brand else 1
    _missing_product = 0 if _product_family else 1
    _missing_insert = 0 if _insert_family else 1
    _missing_card = 0 if _card_number else 1
    _missing_parallel = 0 if _parallel_family else 1
    _missing_serial = 0 if _serial_denominator else 1
    _missing_parallel_locator = 0 if (_serial_denominator or _card_number) else 1
    _auto_parallel_locator_row = {
        **dict(_row or {}),
        "title": _title,
        "lane_type": _lane_type,
        "identity_lane_type": _lane_type,
        "product_family": _product_family,
        "identity_product_family": _product_family,
        "insert_family": _insert_family,
        "identity_insert_family": _insert_family,
        "parallel_family": _parallel_family,
        "identity_parallel_family": _parallel_family,
        "player_name": _player,
        "identity_player": _player,
        "year": _year,
        "identity_year": _year,
    }
    _serial_auto_base_allow, _serial_auto_base_reason = _serial_auto_base_parallel_contract(_auto_parallel_locator_row)
    _auto_parallel_locator = bool(_has_valid_auto_parallel_locator(_auto_parallel_locator_row))
    _core_identity_valid = bool(_player and _year and _product_family and _card_number)
    # Lane-specific contract definitions:
    #   base / graded : player + year + brand + product_family + card_number
    #   insert        : base fields + insert_family
    #   parallel_serial: player + year + brand + product_family + parallel_family + (serial OR card)
    _base_contract_clean = not any((_missing_player, _missing_year, _missing_brand, _missing_product, _missing_card))
    _insert_contract_clean = not any((_missing_player, _missing_year, _missing_brand, _missing_product, _missing_insert, _missing_card))
    _parallel_contract_clean = not any((_missing_player, _missing_year, _missing_brand, _missing_product, _missing_parallel, _missing_parallel_locator))
    if _lane_type == "parallel_serial" and not _is_base_lane:
        # True parallel / serial card — needs parallel_family + locator
        _identity_is_clean = _parallel_contract_clean
        _identity_clean_reason = "parallel_identity_contract" if _identity_is_clean else "missing_parallel_identity_fields"
    elif _lane_type == "insert" and not _is_base_lane:
        # True insert card — needs insert_family in addition to base fields
        _identity_is_clean = _insert_contract_clean
        _identity_clean_reason = "insert_identity_contract" if _identity_is_clean else "missing_insert_identity_fields"
    elif _is_base_lane or _lane_type in {"base", "graded"}:
        # Base or graded card — sufficient: player + year + brand + product_family + card_number
        _identity_is_clean = _base_contract_clean
        _identity_clean_reason = "base_identity_contract" if _identity_is_clean else "missing_base_identity_fields"
    else:
        _legacy_valid = bool(_base_contract_clean or _insert_contract_clean or _parallel_contract_clean)
        _identity_is_clean = _legacy_valid
        _identity_clean_reason = "legacy_identity_contract" if _legacy_valid else "missing_identity_fields"
    _completion_card_number = str(
        _card_number
        or _row.get("card_number")
        or _row.get("_hydrated_card_number")
        or _row.get("identity_card_number")
        or _row.get("target_card_number")
        or _pre_identity_card_number
        or ""
    ).strip()
    _parallel_completion_row = {
        **dict(_row or {}),
        "title": _title,
        "lane_type": _lane_type,
        "_hydrated_lane_type": _lane_type,
        "parallel_family": _parallel_family,
        "_hydrated_parallel_family": _parallel_family,
        "card_number": _completion_card_number,
        "_hydrated_card_number": _completion_card_number,
        "player": _player,
        "clean_player": _player,
        "year": _year,
        "_hydrated_year": _year,
        "product_family": _product_family,
        "_hydrated_product_family": _product_family,
    }
    if (
        not _identity_is_clean
        and _identity_clean_reason == "missing_parallel_identity_fields"
        and _has_parallel_identity_completion_contract(_parallel_completion_row)
    ):
        _identity_is_clean = True
        _identity_clean_reason = "parallel_identity_completion_contract"
        _card_number = _completion_card_number
        print(
            f"[PARALLEL_IDENTITY_COMPLETION] "
            f"title={_title[:160]} "
            f"lane_type={_lane_type} "
            f"parallel_family={_parallel_family} "
            f"card_number={_card_number} "
            f"player={_player} "
            f"year={_year} "
            f"product_family={_product_family}"
        )
    if (
        not _identity_is_clean
        and _auto_parallel_locator
        and _missing_player == 0
        and _missing_year == 0
        and _missing_product == 0
        and _missing_insert == 0
        and _missing_parallel == 0
        and _missing_card == 1
    ):
        _lane_type = "insert_parallel"
        _identity_is_clean = True
        _identity_clean_reason = "auto_parallel_locator"
        _row["identity_is_clean"] = True
        _row["identity_clean_reason"] = "auto_parallel_locator"
        _row["query_mode"] = "insert_parallel"
        _log_auto_parallel_locator_allow(_auto_parallel_locator_row)
    if (
        _lane_type in {"parallel_serial", "parallel"}
        and _core_identity_valid
        and _identity_clean_reason == "missing_parallel_identity_fields"
    ):
        _identity_is_clean = True
        _identity_clean_reason = "parallel_relaxed_core_identity"
        print(
            f"[IDENTITY_RELAX_PARALLEL] title={_title[:140]} reason=core_identity_valid"
        )
    if _lane_type == "base" and _card_number:
        _emit_base_card_number_carry(_title, _parsed_card_number, _card_number, "clean_identity_contract")
    if _lane_type == "base" and _pre_identity_card_number and _card_number == _pre_identity_card_number:
        print(
            f"[BASE_IDENTITY_RECOVER] title={_title[:140]} card_number={_card_number[:16]} "
            f"reason=pre_identity_card_number"
        )
    _fake_serial_probe = dict(_row or {})
    _fake_serial_probe.update(
        {
            "title": _title,
            "lane_type": _lane_type,
            "parallel_family": _parallel_family,
            "insert_family": _insert_family,
            "serial_denominator": _serial_denominator,
            "card_number": _card_number,
        }
    )
    if _is_fake_serial_base_promo_row(_fake_serial_probe)[0]:
        _identity_is_clean = False
        _identity_clean_reason = "fake_serial_base_promo"
        _row["identity_is_clean"] = False
        _row["identity_clean_reason"] = "fake_serial_base_promo"
    print(
        f"[CLEAN_IDENTITY_CONTRACT] title={_title[:140]} player={_player[:40]} year={_year} brand={_brand} "
        f"product_family={_product_family[:48]} insert_family={_insert_family[:32]} card_number={_card_number[:16]} "
        f"parallel_family={_parallel_family[:24]} identity_is_clean={1 if _identity_is_clean else 0} "
        f"identity_clean_reason={_identity_clean_reason}"
    )
    print(
        f"[PARALLEL_IDENTITY_ASSERT] "
        f"title={_title[:160]} "
        f"identity_is_clean={1 if _identity_is_clean else 0} "
        f"identity_clean_reason={_identity_clean_reason} "
        f"lane_type={_lane_type} "
        f"parallel_family={_parallel_family} "
        f"card_number={_card_number}"
    )
    if _lane_type == "base" and not _identity_is_clean:
        print(
            f"[BASE_IDENTITY_ASSERT] title={_title[:140]} missing_player={_missing_player} "
            f"missing_year={_missing_year} missing_brand={_missing_brand} "
            f"missing_product_family={_missing_product} missing_card_number={_missing_card} "
            f"reason={_identity_clean_reason}"
        )
    if not _identity_is_clean and (_is_specific_topps_product or _insert_family or _insert_candidate):
        print(
            f"[CLEAN_IDENTITY_ASSERT] title={_title[:140]} lane_type={_lane_type} "
            f"missing_player={_missing_player} missing_year={_missing_year} missing_brand={_missing_brand} "
            f"missing_product_family={_missing_product} missing_insert_family={_missing_insert} "
            f"missing_card_number={_missing_card} reason={_identity_clean_reason}"
        )
    return {
        "identity_player": _player,
        "identity_year": _year,
        "identity_brand": _brand,
        "identity_product_family": _product_family,
        "identity_insert_family": _insert_family,
        "identity_card_number": _card_number,
        "identity_parallel_family": _parallel_family,
        "identity_has_auto": bool(_has_auto),
        "identity_insert_promoted": bool(_identity_insert_promoted),
        "identity_grade_company": _grade_company,
        "identity_grade": _grade,
        "identity_is_clean": bool(_identity_is_clean),
        "identity_clean_reason": _identity_clean_reason,
        "identity_lane_type": _lane_type,
        "identity_is_base_lane": bool(_is_base_lane),
    }


def _parse_comp_rejection_summary(summary: str) -> Dict[str, int]:
    _counts: Dict[str, int] = {}
    for _part in str(summary or "").split(";"):
        _chunk = str(_part or "").strip()
        if not _chunk or ":" not in _chunk:
            continue
        _key, _value = _chunk.rsplit(":", 1)
        _key = str(_key or "").strip().lower()
        try:
            _counts[_key] = int(float(str(_value or "").strip()))
        except (TypeError, ValueError):
            continue
    return _counts


def _fingerprint_key_part(value: Any) -> str:
    _raw = str(value or "").strip().lower()
    if not _raw:
        return "na"
    return re.sub(r"[^a-z0-9]+", "_", _raw).strip("_") or "na"


def _build_card_fingerprint(row: Dict[str, Any]) -> Dict[str, Any]:
    _emit_runtime_func_stamp("_build_card_fingerprint")
    _row = row or {}
    _title = str(_row.get("title") or "").strip()
    print(f"[SUBSET_PARSE_BRANCH] branch_id=build_card_fingerprint title={_title[:140]}")
    _profile = parse_listing_profile(_title)
    _scarcity = _rarity_signals_from_row(_row)
    _entity = _canonical_normalized_entity(_row)
    _seed = (player_hub.players_by_id() or {}).get(_entity) if _entity else None
    _player_display = str(
        (_seed or {}).get("player_name")
        or _row.get("player_name")
        or _row.get("target_player_name")
        or getattr(_profile, "player_guess", "")
        or ""
    ).strip()
    _player = str(_entity or "").strip().lower() or _fingerprint_key_part(_player_display)
    _year = str(
        _row.get("year")
        or _row.get("card_year")
        or getattr(_profile, "year", "")
        or ""
    ).strip() or None
    _product = _normalize_exact_product_family(
        str(
            _row.get("product_family")
            or _row.get("target_product_family")
            or (_row.get("target_meta") or {}).get("set_name")
            or getattr(_profile, "product_family", "")
            or getattr(_profile, "primary_set", "")
            or ""
        )
    ) or None
    _sapphire_product_ctx = _resolve_sapphire_product_family(_title, _product or "")
    if str(_sapphire_product_ctx.get("product_family") or "").strip():
        _product = _guard_sapphire_product_family(
            _title,
            _product or "",
            str(_sapphire_product_ctx.get("product_family") or "").strip(),
            reason="fingerprint_initial_sapphire_preserve",
        ) or None
    _cosmic_product_ctx = _resolve_cosmic_product_family(_title, _product or "")
    if str(_cosmic_product_ctx.get("product_family") or "").strip():
        _product = _guard_cosmic_product_family(
            _title,
            _product or "",
            str(_cosmic_product_ctx.get("product_family") or "").strip(),
            reason="fingerprint_initial_cosmic_preserve",
        ) or None
    _card_number = str(
        _scarcity.get("card_number")
        or _row.get("card_number")
        or getattr(_profile, "card_number", "")
        or ""
    ).strip().upper() or None
    _subset = _normalize_subset_name(
        str(
            _scarcity.get("subset_name")
            or (_row.get("target_meta") or {}).get("subset_name")
            or getattr(_profile, "subset_family", "")
            or ""
        )
    ) or None
    _subset_source = str(_scarcity.get("subset_source") or "").strip()
    _topps_insert_ctx = _extract_topps_insert_context(
        _title,
        product_family=_product or _row.get("product_family") or _row.get("target_product_family") or "",
        card_number=_card_number or _row.get("card_number") or "",
        player=_player_display,
        year=_year or "",
        grade_state=_extract_grade_bucket(_title),
    )
    if _is_topps_insert_candidate(_product or "", _title):
        if str(_topps_insert_ctx.get("product_family") or "").strip():
            _product = _guard_sapphire_product_family(
                _title,
                _product or "",
                str(_topps_insert_ctx.get("product_family") or "").strip(),
                reason="fingerprint_insert_ctx_sapphire_preserve",
            ) or None
            _product = _guard_cosmic_product_family(
                _title,
                _product or "",
                str(_topps_insert_ctx.get("product_family") or "").strip(),
                reason="fingerprint_insert_ctx_overwrite_blocked",
            ) or None
        if str(_topps_insert_ctx.get("insert_family") or "").strip():
            _subset = str(_topps_insert_ctx.get("insert_family") or "").strip()
            _subset_source = "topps_insert_parser"
        if str(_topps_insert_ctx.get("card_number") or "").strip():
            _card_number = str(_topps_insert_ctx.get("card_number") or "").strip().upper()
    _cosmic_tokens = _cosmic_subset_tokens_in_title(_title)
    if _is_cosmic_family_identity_row(_product, _title) or bool(_cosmic_tokens):
        _cosmic_subset = _extract_cosmic_subset_family(_title, _subset or "")
        if _cosmic_subset and _subset != _cosmic_subset:
            print(
                f"[COSMIC_SUBSET_OVERWRITE] title={_title[:140]} previous_subset={str(_subset or '')[:32]} "
                f"new_subset={_cosmic_subset[:32]} reason=fingerprint_merge_override"
            )
            _subset = _cosmic_subset
            _subset_source = "cosmic_parser"
        elif _subset_source == "cosmic_parser" and not _subset and _cosmic_subset:
            _subset = _cosmic_subset
    if _is_cosmic_family_identity_row(_product, _title) or bool(_cosmic_tokens):
        print(
            f"[COSMIC_SUBSET_ASSIGN] title={_title[:140]} subset_before_assign={str(_scarcity.get('subset_name') or '')[:32]} "
            f"subset_after_assign={str(_subset or '')[:32]} source={_subset_source or 'fallback'}"
        )
        if not _subset and _cosmic_tokens:
            print(
                f"[COSMIC_SUBSET_ASSERT_FAIL] title={_title[:140]} branch_id=build_card_fingerprint "
                f"tokens_found={','.join(_cosmic_tokens[:8])}"
            )
    _parallel = str(
        (_row.get("target_meta") or {}).get("parallel")
        or _row.get("parallel_family")
        or _scarcity.get("parallel_name")
        or _scarcity.get("parallel_bucket")
        or normalize_parallel_bucket(_profile)
        or _detect_parallel_in_title(_title)
        or ""
    ).strip().lower().replace("_", " ") or None
    _parallel_ctx = _normalize_parallel_family(_title, _product or "", _parallel or "")
    _parallel = str(_parallel_ctx.get("parallel_family") or _parallel or "").strip().lower().replace("_", " ") or None
    _topps_product_ctx = _resolve_topps_product_family(
        _product or _title,
        title=_title,
        parallel_family=_parallel or "",
    )
    if str(_topps_product_ctx.get("product_family") or "").strip():
        _product = _guard_sapphire_product_family(
            _title,
            _product or "",
            str(_topps_product_ctx.get("product_family") or "").strip(),
            reason="fingerprint_topps_resolver_overwrite_blocked",
        ) or None
        _product = _guard_cosmic_product_family(
            _title,
            _product or "",
            str(_topps_product_ctx.get("product_family") or "").strip(),
            reason="fingerprint_topps_resolver_overwrite_blocked",
        ) or None
    _serial_den = str(
        _scarcity.get("serial_denominator")
        or _row.get("serial_denominator")
        or ""
    ).strip() or None
    _identity_contract = _build_clean_identity_contract(
        {
            **dict(_row),
            "title": _title,
            "player_name": _player_display or _row.get("player_name") or _row.get("target_player_name") or "",
            "fingerprint_player": _player_display or _player,
            "fingerprint_year": _year or "",
            "fingerprint_product_family": _product or "",
            "fingerprint_insert_family": _subset or "",
            "fingerprint_card_number": _card_number or "",
            "fingerprint_parallel": _parallel or "",
            "serial_denominator": _serial_den or "",
        }
    )
    _player_display = str(_identity_contract.get("identity_player") or _player_display or "").strip() or None
    _year = str(_identity_contract.get("identity_year") or _year or "").strip() or None
    _product = str(_identity_contract.get("identity_product_family") or _product or "").strip() or None
    _subset = str(_identity_contract.get("identity_insert_family") or _subset or "").strip() or None
    _card_number = str(_identity_contract.get("identity_card_number") or _card_number or "").strip().upper() or None
    _parallel = str(_identity_contract.get("identity_parallel_family") or _parallel or "").strip().lower().replace("_", " ") or None
    if str(_identity_contract.get("identity_lane_type") or "").strip().lower() == "base" and _card_number:
        _emit_base_card_number_carry(
            _title,
            _row.get("card_number") or getattr(_profile, "card_number", "") or "",
            _card_number,
            "build_card_fingerprint",
        )
    _fingerprint_brand = str(_identity_contract.get("identity_brand") or "").strip().lower()
    _fingerprint_product_family = str(_identity_contract.get("identity_product_family") or _product or "").strip()
    _fingerprint_insert_family = str(_identity_contract.get("identity_insert_family") or _subset or "").strip()
    _fingerprint_card_number = str(_identity_contract.get("identity_card_number") or _card_number or "").strip().upper()
    _fingerprint_year = str(_identity_contract.get("identity_year") or _year or "").strip()
    _fingerprint_player = _fingerprint_key_part(str(_identity_contract.get("identity_player") or _player_display or _player or "").strip())
    _fingerprint_has_auto = bool(_identity_contract.get("identity_has_auto"))
    _serial_numbered = bool(_serial_den)
    _one_of_one = bool(str(_scarcity.get("one_of_one") or _row.get("one_of_one") or "").strip())
    _grade_state = "graded" if _extract_grade_bucket(_title) != "RAW" else "raw"
    _scarcity_class = str(_scarcity.get("scarcity_class") or _row.get("scarcity_class") or "").strip().lower() or "unknown"
    _fingerprint_key = "|".join(
        [
            _fingerprint_key_part(_year),
            _fingerprint_key_part(_fingerprint_player),
            _fingerprint_key_part(_product),
            _fingerprint_key_part(_card_number),
            _fingerprint_key_part(_subset),
            _fingerprint_key_part(_parallel if _parallel and _parallel != "base" else ("base" if _scarcity_class == "base" else None)),
            _fingerprint_key_part(_serial_den),
            _fingerprint_key_part(_grade_state),
        ]
    )
    print(
        f"[SUBSET_PARSE_RESULT] branch_id=build_card_fingerprint title={_title[:140]} "
        f"subset={str(_subset or '')[:32]} card_number={str(_card_number or '')[:16]} "
        f"grade={_grade_state[:24]} product_family={str(_product or '')[:40]} "
        f"parallel_name={str(_parallel or '')[:32]}"
    )
    return {
        "player": _fingerprint_player if _fingerprint_player != "na" else None,
        "player_display": _player_display or None,
        "year": _year,
        "product": _product,
        "card_number": _card_number,
        "subset": _subset,
        "subset_source": _subset_source,
        "parallel": _parallel,
        "serial_denominator": _serial_den,
        "serial_numbered": _serial_numbered,
        "one_of_one": _one_of_one,
        "grade_state": _grade_state,
        "scarcity_class": _scarcity_class,
        "scarcity_confidence": float(str(_scarcity.get("scarcity_confidence") or "0") or 0.0),
        "scarcity_tokens": str(_scarcity.get("scarcity_tokens") or ""),
        "fingerprint_brand": _fingerprint_brand,
        "fingerprint_product_family": _fingerprint_product_family,
        "fingerprint_insert_family": _fingerprint_insert_family,
        "fingerprint_card_number": _fingerprint_card_number,
        "fingerprint_year": _fingerprint_year,
        "fingerprint_player": _fingerprint_player,
        "identity_player": str(_identity_contract.get("identity_player") or ""),
        "identity_year": str(_identity_contract.get("identity_year") or ""),
        "identity_brand": str(_identity_contract.get("identity_brand") or ""),
        "identity_product_family": str(_identity_contract.get("identity_product_family") or ""),
        "identity_insert_family": str(_identity_contract.get("identity_insert_family") or ""),
        "identity_card_number": str(_identity_contract.get("identity_card_number") or ""),
        "identity_parallel_family": str(_identity_contract.get("identity_parallel_family") or ""),
        "fingerprint_has_auto": bool(_fingerprint_has_auto),
        "identity_has_auto": bool(_identity_contract.get("identity_has_auto")),
        "identity_grade_company": str(_identity_contract.get("identity_grade_company") or ""),
        "identity_grade": str(_identity_contract.get("identity_grade") or ""),
        "identity_is_clean": bool(_identity_contract.get("identity_is_clean")),
        "identity_clean_reason": str(_identity_contract.get("identity_clean_reason") or ""),
        "fingerprint_key": _fingerprint_key,
    }


def _build_canonical_comp_query_contract(row: Dict[str, Any]) -> Dict[str, Any]:
    _row = row or {}
    if isinstance(_row, dict):
        _row = _stamp_insert_identity_before_clean_identity(_row)
        _row = _stamp_insert_card_locator_before_comp_query(_row)
    _title = str(_row.get("title") or _row.get("source_title") or "").strip()
    _fingerprint = dict(_row.get("card_fingerprint") or _build_card_fingerprint(_row))
    _identity = _build_clean_identity_contract({**dict(_row), **dict(_fingerprint)})
    _lane_type = str(_identity.get("identity_lane_type") or "base").strip().lower() or "base"
    _player = str(
        _identity.get("identity_player")
        or _fingerprint.get("identity_player")
        or _fingerprint.get("player_display")
        or _row.get("query_contract_player")
        or _row.get("player_name")
        or _row.get("target_player_name")
        or ""
    ).strip()
    _year = str(
        _identity.get("identity_year")
        or _fingerprint.get("fingerprint_year")
        or _fingerprint.get("year")
        or _row.get("year")
        or _row.get("card_year")
        or ""
    ).strip()
    _brand = str(
        _identity.get("identity_brand")
        or _fingerprint.get("fingerprint_brand")
        or _row.get("identity_brand")
        or _row.get("fingerprint_brand")
        or ""
    ).strip().lower()
    _parallel_seed = str(
        _identity.get("identity_parallel_family")
        or _row.get("fingerprint_parallel")
        or _fingerprint.get("parallel")
        or _row.get("parallel_family")
        or _row.get("parallel_name")
        or ""
    ).strip().lower().replace("_", " ")
    _product_family = str(
        _identity.get("identity_product_family")
        or _fingerprint.get("fingerprint_product_family")
        or _fingerprint.get("product")
        or _row.get("product_family")
        or _row.get("target_product_family")
        or ""
    ).strip()
    _sapphire_product_ctx = _resolve_sapphire_product_family(_title, _product_family)
    if str(_sapphire_product_ctx.get("product_family") or "").strip():
        _product_family = _guard_sapphire_product_family(
            _title,
            _product_family,
            str(_sapphire_product_ctx.get("product_family") or "").strip(),
            reason="canonical_query_initial_sapphire_preserve",
        )
    _cosmic_product_ctx = _resolve_cosmic_product_family(_title, _product_family)
    if str(_cosmic_product_ctx.get("product_family") or "").strip():
        _product_family = _guard_cosmic_product_family(
            _title,
            _product_family,
            str(_cosmic_product_ctx.get("product_family") or "").strip(),
            reason="canonical_query_initial_cosmic_preserve",
        )
    _topps_product_ctx = _resolve_topps_product_family(
        _product_family or _title,
        title=_title,
        parallel_family=_parallel_seed,
    )
    if str(_topps_product_ctx.get("product_family") or "").strip():
        _product_family = _guard_sapphire_product_family(
            _title,
            _product_family,
            str(_topps_product_ctx.get("product_family") or "").strip(),
            reason="canonical_query_topps_overwrite_blocked",
        )
        _product_family = _guard_cosmic_product_family(
            _title,
            _product_family,
            str(_topps_product_ctx.get("product_family") or "").strip(),
            reason="canonical_query_topps_overwrite_blocked",
        )
    _brand = _promote_identity_brand(_title, _product_family, _brand)
    _parallel_ctx = _normalize_parallel_family(_title, _product_family, _parallel_seed)
    _parallel_seed = str(_parallel_ctx.get("parallel_family") or _parallel_seed or "").strip().lower().replace(" ", "_")
    _legacy_subset = str(
        _row.get("fingerprint_subset")
        or _fingerprint.get("subset")
        or _row.get("subset_name")
        or _row.get("subset_family")
        or ""
    ).strip()
    _insert_family = str(
        _identity.get("identity_insert_family")
        or _row.get("insert_family")
        or _row.get("identity_insert_family")
        or _row.get("fingerprint_insert_family")
        or ""
    ).strip()
    _insert_signal_ctx = _resolve_insert_family_signals(
        _title,
        _product_family,
        _insert_family or _legacy_subset,
    )
    if str(_insert_signal_ctx.get("insert_family") or "").strip() and (
        not _insert_family or _insert_family in {"image_variation", "variation", "photo_variation", "ssp", "sp"}
    ):
        _insert_family = str(_insert_signal_ctx.get("insert_family") or "").strip()
    _auto_ctx = _resolve_autograph_lane_signals(_title, _product_family, _insert_family, _parallel_seed)
    _insert_family_before = _insert_family
    _auto_negated = _title_has_auto_negation(_title)
    if _auto_negated:
        print(
            f"[AUTO_NEGATION_GUARD] title={_title[:140]} reason=non_auto_phrase"
        )
    _row_auto_signal = bool(
        _identity.get("identity_has_auto")
        or _row.get("identity_has_auto")
        or _row.get("fingerprint_has_auto")
        or _fingerprint.get("fingerprint_has_auto")
        or bool((_row.get("_final_quality_contract") or {}).get("final_has_auto"))
        or _row.get("final_has_auto")
        or _row.get("query_contract_has_auto")
        or _row.get("has_auto")
        or _row.get("is_auto")
        or _row.get("autograph")
        or _row.get("is_autograph")
    )
    if str(_auto_ctx.get("insert_family") or "").strip() and (not _insert_family or _insert_family in {"auto", "autograph", "autographs"}):
        _insert_family = str(_auto_ctx.get("insert_family") or "").strip()
    _has_auto = bool(
        not _auto_negated
        and (
            _row_auto_signal
            or _auto_ctx.get("has_auto")
            or _insert_family in {"auto", "autograph", "autographs"}
        )
    )
    _query_has_auto = bool(_has_auto)
    if _auto_negated:
        _query_has_auto = False
        if _insert_family in {"auto", "autograph", "autographs"}:
            _insert_family = ""
        print(
            f"[AUTO_PROMOTION_BLOCKED] title={_title[:140]} reason=auto_negation"
        )
    _blocked_subset = 0
    if _lane_type == "parallel_serial":
        if _query_has_auto:
            if not _insert_family or _insert_family in {"auto", "autograph", "autographs"}:
                _insert_family = "auto"
            _blocked_subset = 1 if bool(_legacy_subset and _legacy_subset != _insert_family) else 0
        elif _insert_family:
            _blocked_subset = 1 if bool(_legacy_subset and _legacy_subset != _insert_family) else 0
        else:
            _blocked_subset = 1 if bool(_legacy_subset) else 0
            _insert_family = ""
    elif not _insert_family:
        _insert_family = _legacy_subset
    _auto_preserve_reason = "no_auto_signal"
    if _query_has_auto:
        if _insert_family_before != _insert_family:
            _auto_preserve_reason = "preserved_auto_insert_family"
        else:
            _auto_preserve_reason = "kept_existing_auto_insert_family"
    elif _insert_family_before != _insert_family:
        _auto_preserve_reason = "legacy_insert_promote"
    if _query_has_auto or _insert_family_before != _insert_family:
        print(
            f"[AUTO_QUERY_PRESERVE] title={_title[:140]} "
            f"identity_has_auto={1 if bool(_identity.get('identity_has_auto')) else 0} "
            f"insert_family_before={_insert_family_before[:24]} "
            f"insert_family_after={_insert_family[:24]} "
            f"query_has_auto={1 if _query_has_auto else 0} "
            f"reason={_auto_preserve_reason}"
        )
    print(
        f"[STALE_SUBSET_LEAK] title={_title[:140]} lane_type={_lane_type} "
        f"legacy_subset={_legacy_subset[:24]} blocked={_blocked_subset}"
    )
    _parallel_family = _parallel_seed
    _serial_denominator = str(
        _row.get("serial_denominator")
        or _row.get("fingerprint_serial_denominator")
        or _fingerprint.get("serial_denominator")
        or ""
    ).strip()
    if _lane_type == "insert_parallel":
        _card_number = str(
            _identity.get("identity_card_number")
            or _row.get("fingerprint_card_number")
            or _row.get("card_number")
            or _fingerprint.get("card_number")
            or ""
        ).strip().upper()
    else:
        _card_number = str(
            _identity.get("identity_card_number")
            or _row.get("fingerprint_card_number")
            or _fingerprint.get("card_number")
            or _row.get("card_number")
            or ""
        ).strip().upper()
    _grade_company = str(
        _identity.get("identity_grade_company")
        or _row.get("grade_company")
        or ""
    ).strip().upper()
    _grade_value = str(
        _identity.get("identity_grade")
        or _row.get("grade")
        or _row.get("grade_value")
        or ""
    ).strip().upper()
    _auto_parallel_locator_row = {
        **dict(_row or {}),
        "title": _title,
        "lane_type": _lane_type,
        "identity_lane_type": _lane_type,
        "product_family": _product_family,
        "identity_product_family": _product_family,
        "insert_family": _insert_family,
        "identity_insert_family": _insert_family,
        "parallel_family": _parallel_family,
        "identity_parallel_family": _parallel_family,
        "player_name": _player,
        "identity_player": _player,
        "year": _year,
        "identity_year": _year,
    }
    _serial_auto_base_allow, _serial_auto_base_reason = _serial_auto_base_parallel_contract(_auto_parallel_locator_row)
    _auto_parallel_locator = bool(_has_valid_auto_parallel_locator(_auto_parallel_locator_row))
    _auto_parallel_override = bool(
        (
            _lane_type == "insert_parallel"
            and _insert_family == "auto"
            and _parallel_family not in {"", "base", "none"}
            and _safe_float(_serial_denominator) not in {None, 0.0}
        )
        or (
            _query_has_auto
            and "topps chrome" in str(_product_family or "").lower()
            and _parallel_family not in {"", "base", "none"}
            and _safe_float(_serial_denominator) not in {None, 0.0}
        )
    )
    _old_query_mode = _lane_type if _lane_type in {"base", "insert", "parallel_serial"} else "base"
    if _serial_auto_base_allow:
        _query_mode = "insert_parallel"
        print(
            f"[SERIAL_AUTO_QUERY_OVERRIDE] "
            f"title={_title[:160]} "
            f"old_query_mode={_old_query_mode} "
            f"new_query_mode=insert_parallel "
            f"missing_card_number={0 if _card_number else 1} "
            f"reason={_serial_auto_base_reason}"
        )
    elif _auto_parallel_locator:
        _query_mode = "insert_parallel"
        print(
            f"[COMP_QUERY_MODE_OVERRIDE] title={_title[:140]} old_query_mode={_old_query_mode} "
            f"new_query_mode=insert_parallel reason=auto_parallel_locator"
        )
        _log_auto_parallel_locator_allow(_auto_parallel_locator_row)
    elif _auto_parallel_override:
        _query_mode = "insert_parallel_serial"
        print(
            f"[AUTO_PARALLEL_QUERYMODE_OVERRIDE] title={_title[:140]} lane_type={_lane_type} "
            f"insert_family={_insert_family[:24]} parallel_family={_parallel_family[:24]} "
            f"serial_denominator={_serial_denominator[:12]} query_mode=insert_parallel_serial"
        )
    elif _lane_type in {"parallel_serial", "insert_parallel"} and _insert_family and not _query_has_auto:
        _query_mode = "insert_parallel_serial"
    else:
        _query_mode = _lane_type if _lane_type in {"base", "insert", "parallel_serial"} else "base"
    print(
        f"[COMP_QUERY_MODE_ASSERT] title={_title[:140]} lane_type={_lane_type} query_mode={_query_mode}"
    )
    if _query_has_auto and "topps chrome" in str(_product_family or "").lower() and _parallel_family == "purple_speckle":
        print(
            f"[TOPPS_AUTO_PARALLEL_ASSERT] title={_title[:140]} parallel_family={_parallel_family[:24]}"
        )
    _missing_player = 0 if _player else 1
    _missing_year = 0 if _year else 1
    _missing_brand = 0 if _brand else 1
    _missing_product = 0 if _product_family else 1
    _missing_insert = 0 if _insert_family else 1
    _missing_parallel = 0 if _parallel_family else 1
    _missing_serial = 0 if _serial_denominator else 1
    _missing_card = 0 if _card_number else 1
    _missing_parallel_locator = 0 if (_serial_denominator or _card_number) else 1
    _core_identity_valid = bool(_player and _year and _product_family and _card_number)
    if _query_mode == "insert_parallel_serial":
        _query_ready = not any((_missing_player, _missing_year, _missing_brand, _missing_product, _missing_insert, _missing_parallel, _missing_parallel_locator))
        _query_reason = "insert_parallel_serial_contract" if _query_ready else "missing_insert_parallel_serial_query_fields"
    elif _query_mode == "insert_parallel":
        if _serial_auto_base_allow:
            _query_ready = not any((_missing_player, _missing_year, _missing_product, _missing_insert, _missing_serial))
            _query_reason = _serial_auto_base_reason if _query_ready else "missing_serial_auto_query_fields"
        else:
            _query_ready = not any((_missing_player, _missing_year, _missing_product, _missing_insert, _missing_parallel))
            _query_reason = "auto_parallel_locator" if _query_ready else "missing_insert_parallel_query_fields"
    elif _query_mode == "parallel_serial":
        _query_ready = not any((_missing_player, _missing_year, _missing_brand, _missing_product, _missing_parallel, _missing_parallel_locator))
        _query_reason = "parallel_serial_contract" if _query_ready else "missing_parallel_serial_query_fields"
    elif _query_mode == "insert":
        _query_ready = not any((_missing_player, _missing_year, _missing_brand, _missing_product, _missing_insert, _missing_card))
        _query_reason = "insert_contract" if _query_ready else "missing_insert_query_fields"
    else:
        _query_ready = not any((_missing_player, _missing_year, _missing_brand, _missing_product, _missing_card))
        _query_reason = "base_contract" if _query_ready else "missing_base_query_fields"
    if (
        _lane_type in {"parallel_serial", "parallel"}
        and _query_mode == "parallel_serial"
        and _core_identity_valid
        and (_missing_parallel or _missing_parallel_locator)
    ):
        _query_ready = True
        _query_reason = "parallel_relaxed_core_identity"
        print(
            f"[COMP_QUERY_RELAX_PARALLEL] title={_title[:140]} reason=core_identity_valid"
        )
    if _query_mode == "base" and _card_number:
        _emit_base_card_number_carry(
            _title,
            _row.get("fingerprint_card_number") or _fingerprint.get("card_number") or _row.get("card_number") or "",
            _card_number,
            "canonical_comp_query_contract",
        )
    print(
        f"[COMP_QUERY_CONTRACT] title={_title[:140]} lane_type={_lane_type} player={_player[:40]} "
        f"year={_year} brand={_brand[:20]} product_family={_product_family[:40]} insert_family={_insert_family[:32]} "
        f"parallel_family={_parallel_family[:24]} serial_denominator={_serial_denominator[:12]} "
        f"card_number={_card_number[:16]} query_mode={_query_mode} "
        f"query_has_auto={1 if _query_has_auto else 0}"
    )
    if _has_auto:
        print(
            f"[AUTO_COMP_CONTRACT] title={_title[:140]} lane_type={_lane_type[:24]} "
            f"product_family={_product_family[:48]} parallel_family={_parallel_family[:24]} "
            f"serial_denominator={_serial_denominator[:12]} has_auto={1 if _has_auto else 0} "
            f"query_mode={_query_mode}"
        )
    if not _query_ready:
        print(
            f"[COMP_QUERY_ASSERT] title={_title[:140]} lane_type={_lane_type} "
            f"missing_player={_missing_player} missing_year={_missing_year} missing_brand={_missing_brand} "
            f"missing_product_family={_missing_product} missing_insert_family={_missing_insert} "
            f"missing_parallel_family={_missing_parallel} missing_serial_denominator={_missing_serial} "
            f"missing_card_number={_missing_card} missing_parallel_locator={_missing_parallel_locator} "
            f"reason={_query_reason}"
        )
    return {
        "title": _title,
        "lane_type": _lane_type,
        "query_mode": _query_mode,
        "player": _player,
        "year": _year,
        "brand": _brand,
        "product_family": _product_family,
        "insert_family": _insert_family,
        "query_insert_family": _insert_family,
        "parallel_family": _parallel_family,
        "serial_denominator": _serial_denominator,
        "card_number": _card_number,
        "has_auto": bool(_has_auto),
        "query_has_auto": bool(_query_has_auto),
        "grade_company": _grade_company,
        "grade_value": _grade_value,
        "query_ready": bool(_query_ready),
        "query_reason": _query_reason,
        "serial_auto_base_parallel_contract": bool(_serial_auto_base_allow),
    }


def _comp_query_family_variants(product_family: Any) -> List[str]:
    _product = _normalize_exact_product_family(str(product_family or ""))
    if not _product:
        return []
    _variants: List[str] = []
    def _push(value: str) -> None:
        _clean = " ".join(str(value or "").replace("_", " ").split()).strip()
        if _clean and _clean.lower() not in {v.lower() for v in _variants}:
            _variants.append(_clean)
    _push(_product)
    if _product == "topps chrome black":
        _push("chrome black")
        _push("topps chrome")
    elif _product == "topps chrome update":
        _push("chrome update")
        _push("topps chrome")
    elif _product == "topps chrome logofractor":
        _push("logofractor")
        _push("topps chrome")
    elif _product.startswith("topps chrome"):
        _push("topps chrome")
    else:
        _brandless = re.sub(r"^(topps|panini|bowman)\s+", "", _product.replace("_", " ")).strip()
        _push(_brandless)
    return _variants


def _build_operator_comp_plan(row: Dict[str, Any]) -> Dict[str, Any]:
    _fp = _build_card_fingerprint(row)
    _contract = _build_canonical_comp_query_contract({**dict(row or {}), "card_fingerprint": dict(_fp)})
    _player_display = str(_contract.get("player") or _fp.get("player_display") or "").strip()
    _year = str(_contract.get("year") or _fp.get("year") or "").strip()
    _product = str(_contract.get("product_family") or _fp.get("product") or "").strip().replace("_", " ")
    _subset = str(_contract.get("query_insert_family") or _contract.get("insert_family") or "").strip().replace("_", " ")
    _parallel = str(_contract.get("parallel_family") or _fp.get("parallel") or "").strip().replace("_", " ")
    _card_no = str(_contract.get("card_number") or _fp.get("card_number") or "").strip()
    _serial_den = str(_contract.get("serial_denominator") or _fp.get("serial_denominator") or "").strip()
    _has_auto = bool(
        _contract.get("has_auto")
        or _contract.get("query_has_auto")
        or _fp.get("identity_has_auto")
        or _fp.get("fingerprint_has_auto")
    )
    _lane_type = str(_contract.get("lane_type") or "base").strip().lower()
    _query_mode = str(_contract.get("query_mode") or _lane_type or "base").strip().lower()
    _grade_state = str(_fp.get("grade_state") or "raw").strip().lower()
    _strict_fields: List[str] = ["player", "product"]
    if _card_no:
        _strict_fields.append("card_number")
    if _query_mode in {"insert", "insert_parallel", "insert_parallel_serial"} and _subset:
        _strict_fields.append("subset")
    if _query_mode in {"parallel_serial", "insert_parallel", "insert_parallel_serial"} and _parallel and _parallel not in {"base"}:
        _strict_fields.append("parallel")
    if _query_mode in {"parallel_serial", "insert_parallel_serial"} and _serial_den:
        _strict_fields.append("serial_denominator")
    if _has_auto:
        _strict_fields.append("auto")
    if _grade_state:
        _strict_fields.append("grade_state")
    _exact_parts: List[str] = [_year, _player_display, _product.title() if _product else ""]
    if _query_mode in {"insert", "insert_parallel", "insert_parallel_serial"} and _subset:
        _exact_parts.append(_subset.title())
    if _card_no:
        _exact_parts.append(f"#{_card_no}")
    if _query_mode in {"parallel_serial", "insert_parallel", "insert_parallel_serial"}:
        if _parallel and _parallel not in {"base"}:
            _exact_parts.append(_parallel.title())
        if _serial_den:
            _exact_parts.append(f"/{_serial_den}".replace("//", "/"))
    if _has_auto:
        _exact_parts.append("Auto")
    if _grade_state:
        _exact_parts.append(_grade_state)
    _query_primary = " ".join([_p for _p in _exact_parts if _p]).strip()
    _backup_1_parts = [p for p in _exact_parts if p and p != _year]
    _backup_2_parts = [p for p in _backup_1_parts if p != _grade_state]
    return {
        "player": str(_fp.get("player") or ""),
        "player_display": _player_display or None,
        "year": _fp.get("year"),
        "product": _contract.get("product_family") or _fp.get("product"),
        "card_number": _contract.get("card_number") or _fp.get("card_number"),
        "subset": _contract.get("insert_family") or "",
        "parallel": _contract.get("parallel_family") or _fp.get("parallel"),
        "serial_denominator": _contract.get("serial_denominator") or _fp.get("serial_denominator"),
        "has_auto": bool(_has_auto),
        "grade_state": _fp.get("grade_state"),
        "scarcity_class": _fp.get("scarcity_class"),
        "lane_type": _lane_type,
        "fingerprint_key": _fp.get("fingerprint_key"),
        "query_primary": _query_primary,
        "query_backup_1": " ".join(_backup_1_parts).strip(),
        "query_backup_2": " ".join(_backup_2_parts).strip(),
        "strict_fields": _strict_fields,
    }


def _build_exact_comp_identity(lookup_contract: Dict[str, Any]) -> Dict[str, Any]:
    _lookup = lookup_contract or {}
    _title = str(_lookup.get("title") or "").strip()
    _profile = parse_listing_profile(_title)
    _fingerprint = dict(_lookup.get("card_fingerprint") or _build_card_fingerprint(_lookup))
    _query_contract = _build_canonical_comp_query_contract({**dict(_lookup), **dict(_fingerprint)})
    _player = str(
        _query_contract.get("player")
        or _fingerprint.get("identity_player")
        or _fingerprint.get("player_display")
        or _lookup.get("identity_player")
        or _lookup.get("query_contract_player")
        or _lookup.get("player_name")
        or ""
    ).strip()
    _product = _normalize_exact_product_family(
        str(
            _query_contract.get("product_family")
            or _lookup.get("identity_product_family")
            or _fingerprint.get("fingerprint_product_family")
            or _fingerprint.get("product")
            or ""
        ).strip()
    )
    _sapphire_product_ctx = _resolve_sapphire_product_family(_title, _product)
    if str(_sapphire_product_ctx.get("product_family") or "").strip():
        _product = _guard_sapphire_product_family(
            _title,
            _product,
            str(_sapphire_product_ctx.get("product_family") or "").strip(),
            reason="exact_comp_identity_sapphire_preserve",
        )
    _card_no = str(
        _query_contract.get("card_number")
        or _lookup.get("identity_card_number")
        or _fingerprint.get("fingerprint_card_number")
        or _fingerprint.get("card_number")
        or ""
    ).strip().upper()
    _subset = str(
        _query_contract.get("query_insert_family")
        or _query_contract.get("insert_family")
        or _lookup.get("identity_insert_family")
        or _fingerprint.get("fingerprint_insert_family")
        or ""
    ).strip()
    _parallel = str(_query_contract.get("parallel_family") or _fingerprint.get("parallel") or "").strip().lower().replace("_", " ")
    _serial_bucket = str(_lookup.get("serial_bucket") or "").strip().lower()
    _grade_bucket = _extract_grade_bucket(_title)
    _grade_state = str(_fingerprint.get("grade_state") or ("graded" if _grade_bucket != "RAW" else "raw")).strip().lower()
    _scarcity_class = str(_fingerprint.get("scarcity_class") or _lookup.get("scarcity_class") or "").strip().lower()
    _is_auto = bool(
        _query_contract.get("has_auto")
        or _query_contract.get("query_has_auto")
        or _lookup.get("query_contract_has_auto")
        or _lookup.get("identity_has_auto")
        or _lookup.get("fingerprint_has_auto")
        or getattr(_profile, "is_auto", False)
        or bool(re.search(r"\b(auto|autograph|signed|signature)\b", _title, flags=re.IGNORECASE))
    )
    if _is_auto and not _subset:
        _subset = "auto"
    _is_mem = bool(getattr(_profile, "is_memorabilia", False)) or bool(re.search(r"\b(patch|relic|materials|memorabilia|jersey)\b", _title, flags=re.IGNORECASE))
    _year = str(_query_contract.get("year") or _fingerprint.get("fingerprint_year") or _fingerprint.get("year") or getattr(_profile, "year", "") or "").strip()
    _lane_type = str(_query_contract.get("lane_type") or "base").strip().lower()
    _query_mode = str(_query_contract.get("query_mode") or _lane_type or "base").strip().lower()
    if _query_mode == "base" and _card_no:
        _emit_base_card_number_carry(
            _title,
            _query_contract.get("card_number") or _fingerprint.get("fingerprint_card_number") or _fingerprint.get("card_number") or "",
            _card_no,
            "build_exact_comp_identity",
        )
    try:
        _year_num = int(_year) if _year else 0
    except ValueError:
        _year_num = 0
    _modern = _year_num >= 2019 if _year_num else bool(_product in _COMMON_MODERN_EXACT_PRODUCTS)
    _common_modern_exact_required, _common_modern_reason = _classify_common_modern_row(
        product=_product,
        year_num=_year_num,
        card_no=_card_no,
        subset=_subset,
        parallel=_parallel,
        serial_bucket=_serial_bucket,
        grade_state=_grade_state,
        is_auto=_is_auto,
        is_mem=_is_mem,
        title=_title,
    )
    _parallel_required = bool(_lane_type == "parallel_serial" and _parallel and _parallel not in {"base"})
    _subset_required = bool(_query_mode in {"insert", "insert_parallel", "insert_parallel_serial"} and _subset)
    _identity_bits = [
        _year,
        _player,
        _product,
        f"#{_card_no}" if _card_no else "",
        _subset.replace("_", " ") if _query_mode in {"insert", "insert_parallel", "insert_parallel_serial"} and _subset else "",
        _parallel if _query_mode in {"parallel_serial", "insert_parallel", "insert_parallel_serial"} and _parallel else ("base" if _common_modern_exact_required else ""),
        "auto" if _is_auto else "",
        _grade_state,
    ]
    _identity_label = " ".join([_bit for _bit in _identity_bits if _bit]).strip()
    if _common_modern_exact_required:
        print(
            f"[COMMON_MODERN] item={str(_lookup.get('itemId') or '')[:24]} "
            f"class=1 reason=\"{_common_modern_reason}\""
        )
    return {
        "exact_product_family": _product,
        "exact_card_number": _card_no,
        "exact_subset_name": _subset,
        "exact_parallel": _parallel,
        "exact_lane_type": _lane_type,
        "exact_grade_bucket": _grade_bucket,
        "exact_grade_state": _grade_state,
        "exact_year": _year,
        "exact_has_auto": bool(_is_auto),
        "common_modern_exact_required": _common_modern_exact_required,
        "common_modern_reason": _common_modern_reason,
        "exact_parallel_required": _parallel_required,
        "exact_subset_required": _subset_required,
        "exact_identity_label": _identity_label,
        "card_fingerprint_key": str(_fingerprint.get("fingerprint_key") or ""),
    }


def _row_price_anchor(item: Dict[str, Any]) -> float:
    _row = item or {}
    for _field in ("current_price", "current_bid", "price"):
        try:
            _val = float(_row.get(_field) or 0.0)
        except (TypeError, ValueError):
            _val = 0.0
        if _val > 0:
            return _val
    return 0.0


def _safe_float(value: Any) -> Optional[float]:
    if isinstance(value, dict):
        value = value.get("value")
    try:
        _value = float(str(value or 0).replace(",", ""))
    except (TypeError, ValueError, AttributeError):
        return None
    return _value if _value > 0 else None


def _coerce_price_scalar(value):
    """
    Return float-compatible scalar or None.
    Accept:
    - int
    - float
    - numeric strings
    - dicts with common price keys
    Reject:
    - non-numeric dicts/lists/objects
    """
    try:
        if value is None:
            return None
        if isinstance(value, (int, float)):
            return float(value)
        if isinstance(value, str):
            _s = value.strip().replace("$", "").replace(",", "")
            if not _s:
                return None
            return float(_s)
        if isinstance(value, dict):
            for _k in [
                "value", "price", "amount", "current_price",
                "display_price", "converted_current_price",
                "raw", "usd", "buyItNowPrice", "bidPrice",
            ]:
                _v = value.get(_k)
                if _v is not None:
                    _coerced = _coerce_price_scalar(_v)
                    if _coerced is not None:
                        return _coerced
            return None
        return None
    except Exception:
        return None


def _normalize_row_price_fields(_row, *, stage):
    if not isinstance(_row, dict):
        return _row
    _before = {
        "current_price": _row.get("current_price"),
        "authoritative_current_price": _row.get("authoritative_current_price"),
        "_board_current_price": _row.get("_board_current_price"),
        "_rescued_source_current_price": _row.get("_rescued_source_current_price"),
    }

    _current = _coerce_price_scalar(_row.get("current_price"))
    _auth = _coerce_price_scalar(_row.get("authoritative_current_price"))
    _board = _coerce_price_scalar(_row.get("_board_current_price"))
    _rescued = _coerce_price_scalar(_row.get("_rescued_source_current_price"))

    _best = next((x for x in [_current, _auth, _board, _rescued] if x is not None), None)

    if _best is not None:
        _row["current_price"] = _best
        _row["current_bid"] = _best
        _row["authoritative_current_price"] = _best
        _row["_authoritative_current_price"] = _best
        _row["_board_current_price"] = _best
        _row["board_current_price"] = _best

    print(
        f"[PRICE_SCALAR_NORMALIZE] stage={stage} "
        f"title={str((_row or {}).get('title') or '')[:160]} "
        f"before_current_type={type(_before['current_price']).__name__ if _before['current_price'] is not None else 'None'} "
        f"before_auth_type={type(_before['authoritative_current_price']).__name__ if _before['authoritative_current_price'] is not None else 'None'} "
        f"before_board_type={type(_before['_board_current_price']).__name__ if _before['_board_current_price'] is not None else 'None'} "
        f"before_rescued_type={type(_before['_rescued_source_current_price']).__name__ if _before['_rescued_source_current_price'] is not None else 'None'} "
        f"final_price={_best}"
    )
    print(
        f"[PRICE_SCALAR_ASSERT] stage={stage} "
        f"title={str((_row or {}).get('title') or '')[:160]} "
        f"current_price={_row.get('current_price')} "
        f"current_price_type={type(_row.get('current_price')).__name__ if _row.get('current_price') is not None else 'None'} "
        f"authoritative_current_price={_row.get('authoritative_current_price')} "
        f"authoritative_current_price_type={type(_row.get('authoritative_current_price')).__name__ if _row.get('authoritative_current_price') is not None else 'None'} "
        f"_board_current_price={_row.get('_board_current_price')} "
        f"_board_current_price_type={type(_row.get('_board_current_price')).__name__ if _row.get('_board_current_price') is not None else 'None'} "
        f"rescued_source_current_price={_row.get('_rescued_source_current_price')} "
        f"rescued_source_current_price_type={type(_row.get('_rescued_source_current_price')).__name__ if _row.get('_rescued_source_current_price') is not None else 'None'}"
    )
    print(
        f"[PRICE_CHAIN_TRACE] stage=normalize_row_price_fields:{stage} "
        f"item_id={str(_row.get('item_id') or _row.get('itemId') or '')} "
        f"title={str(_row.get('title') or '')[:80]} "
        f"current_price={_row.get('current_price')} "
        f"current_price_type={type(_row.get('current_price')).__name__ if _row.get('current_price') is not None else 'None'} "
        f"current_bid={_row.get('current_bid')} "
        f"_board_current_price={_row.get('_board_current_price')} "
        f"authoritative_current_price={_row.get('authoritative_current_price')}"
    )
    return _row


def _safe_int(value: Any, default: int = 0) -> int:
    """Safe integer conversion used in hybrid valuation and serial extraction paths."""
    try:
        if value is None:
            return default
        return int(str(value).replace(",", "").split(".")[0])
    except (TypeError, ValueError, AttributeError):
        return default


# Seller / storefront tokens that are appended to eBay titles as spam.
# These must be stripped before valuation so they don't create fake auto or
# premium signals in entity extraction, comp query construction, or routing.
_TITLE_NOISE_TOKENS: tuple = (
    "autographden",
    "read free shipping",
    "read free ship",
    "free shipping",   # only when spam-appended — substring match against full trailing noise
    "autograph den",
)


def _strip_title_noise(title: str) -> tuple:
    """
    Remove known seller-spam tokens from a card title.
    Returns the cleaned title. Does NOT remove 'auto' or 'autograph' when they
    are part of a real card identity — only removes full storefront names.
    """
    _cleaned = title
    _removed: list = []
    for _tok in _TITLE_NOISE_TOKENS:
        _idx = _cleaned.lower().find(_tok)
        if _idx != -1:
            # Strip the token and any leading/trailing whitespace/punctuation around it
            _before = _cleaned[:_idx].rstrip(" -|/,;")
            _after = _cleaned[_idx + len(_tok):].lstrip(" -|/,;")
            _cleaned = (_before + " " + _after).strip()
            _removed.append(_tok)
    return _cleaned, _removed


def _strip_title_noise_inplace(row: dict) -> None:
    """
    Strip seller noise tokens from row['title'] and row['source_title'] in-place.
    Emits [TITLE_NOISE_STRIP] log when anything is removed.
    """
    _original = str(row.get("title") or row.get("source_title") or "")
    _cleaned, _removed = _strip_title_noise(_original)
    if _removed:
        row["title"] = _cleaned
        if "source_title" in row:
            _src_cleaned, _ = _strip_title_noise(str(row.get("source_title") or ""))
            row["source_title"] = _src_cleaned
        print(
            f"[TITLE_NOISE_STRIP] title={_cleaned[:100]} "
            f"removed_tokens={_removed}"
        )


def _is_non_single_inventory_title(title: Any, row: Optional[Dict[str, Any]] = None) -> Tuple[bool, str]:
    _title = f" {str(title or '').strip().lower().replace('-', ' ')} "
    _row = row or {}
    _packaging_phrases = (
        " mega box ",
        " blaster ",
        " hobby box ",
        " jumbo box ",
        " box break ",
        " sealed ",
        " factory sealed ",
        " wax ",
        " hanger ",
        " fat pack ",
        " cello ",
        " retail box ",
        " team set ",
        " lot ",
        " bundle ",
        " mystery pack ",
        " repack ",
        " packs ",
        " boxes ",
    )
    _pack_terms = (
        " pack ",
        " packs ",
        " box ",
        " boxes ",
        " break ",
        " case ",
    )
    _qty_terms = (
        " [1x] ",
        " 1x ",
        " x1 ",
        " qty ",
        " quantity ",
    )
    if " case hit " in _title:
        _title = _title.replace(" case hit ", " ")
    if " pack pulled " in _title or " pack fresh " in _title:
        _title = _title.replace(" pack pulled ", " ").replace(" pack fresh ", " ")
    if " box topper " in _title:
        _title = _title.replace(" box topper ", " ")
    if any(_phrase in _title for _phrase in _packaging_phrases):
        return True, "packaging_inventory"
    if any(_qty in _title for _qty in _qty_terms) and any(_term in _title for _term in _pack_terms):
        return True, "packaging_inventory"
    _insert_family = str(
        _row.get("insert_family")
        or _row.get("identity_insert_family")
        or _row.get("fingerprint_insert_family")
        or _row.get("subset_name")
        or _row.get("subset_family")
        or ""
    ).strip()
    _parallel_family = str(
        _row.get("parallel_family")
        or _row.get("parallel_name")
        or _row.get("parallel")
        or _row.get("identity_parallel_family")
        or ""
    ).strip().lower()
    _serial_denominator = str(
        _row.get("serial_denominator")
        or _row.get("serial")
        or _row.get("serial_bucket")
        or ""
    ).strip()
    _product_family = _normalize_exact_product_family(
        str(_row.get("product_family") or _row.get("target_product_family") or title or "")
    ).replace("_", " ").strip().lower()
    _generic_break_phrases = (
        " break insert ",
        " insert #",
        " team break ",
        " player break ",
        " break card ",
        " break spot ",
        " case break ",
    )
    _broad_generic_products = {
        "prizm",
        "mosaic",
        "select",
        "phoenix",
        "donruss optic",
        "optic",
        "panini",
        "topps",
        "bowman",
    }
    _generic_checklist_like = bool(
        (" insert #" in _title or " break insert " in _title)
        and any(_tok in _title for _tok in (" nfl ", " mlb ", " nba ", " raiders ", " chiefs ", " yankees ", " dodgers "))
    )
    if (
        any(_phrase in _title for _phrase in _generic_break_phrases)
        and not _insert_family
        and not _serial_denominator
        and _parallel_family in {"", "base"}
        and (_product_family in _broad_generic_products or any(f" {_tok} " in _title for _tok in (" panini prizm ", " prizm ", " mosaic ", " select ", " optic ")))
        and _generic_checklist_like
    ):
        return True, "generic_break_insert"
    return False, ""


LOW_VALUE_INSERT_FAMILIES = {
    "emergent",
    "notoriety",
    "green_ice_base_insert",
    "base_insert",
    "generic_insert",
}


def _resolve_panini_low_value_insert_family(title: Any) -> str:
    _title_norm = f" {re.sub(r'[^a-z0-9\\s]+', ' ', str(title or '').lower()).strip()} "
    _title_norm = f" {' '.join(_title_norm.split())} "
    if " emergent " in _title_norm:
        return "emergent"
    if " notoriety " in _title_norm:
        return "notoriety"
    return ""


def _is_low_value_insert_row(row: Optional[Dict[str, Any]]) -> Tuple[bool, str]:
    _row = row or {}
    _title = str(_row.get("title") or _row.get("source_title") or "").strip()
    _product_family = str(
        _row.get("product_family")
        or _row.get("target_product_family")
        or _row.get("lane_product")
        or ""
    ).strip()
    _insert_seed = str(
        _row.get("insert_family")
        or _row.get("identity_insert_family")
        or _row.get("fingerprint_insert_family")
        or _row.get("subset_name")
        or _row.get("subset_family")
        or ""
    ).strip()
    _insert_ctx = _resolve_insert_family_signals(_title, _product_family, _insert_seed)
    _insert_family = _normalize_subset_name(
        str(_insert_ctx.get("insert_family") or _insert_seed or "").strip()
    )
    _panini_low_value_insert = _resolve_panini_low_value_insert_family(_title)
    if _panini_low_value_insert and not _insert_family:
        _insert_family = _panini_low_value_insert
        print(
            f"[PANINI_LOW_VALUE_INSERT_RESOLVE] title={_title[:140]} insert_family={_insert_family[:32]} reason=title_phrase"
        )
    _parallel_family = str(
        _row.get("parallel_family")
        or _row.get("parallel_name")
        or _row.get("parallel")
        or _row.get("identity_parallel_family")
        or ""
    ).strip().lower()
    _parallel_ctx = _normalize_parallel_family(_title, _product_family, _parallel_family)
    _parallel_family = str(_parallel_ctx.get("parallel_family") or _parallel_family or "").strip().lower().replace(" ", "_")
    _serial_denominator = str(
        _row.get("serial_denominator")
        or _row.get("serial")
        or _row.get("serial_bucket")
        or ""
    ).strip()
    _product_norm = _normalize_exact_product_family(_product_family or _title).replace("_", " ").strip().lower()
    _cheap_parallel_families = {
        "",
        "base",
        "green",
        "mosaic_prizm",
        "reactive_blue",
        "pink",
        "red_ice",
        "silver_prizm",
    }
    _cheap_products = {"prizm", "mosaic", "select", "phoenix", "donruss optic", "optic"}
    if (
        _insert_family in LOW_VALUE_INSERT_FAMILIES
        and not _serial_denominator
        and _parallel_family in _cheap_parallel_families
        and not _serial_denominator
        and not _is_premium_card(_row)
        and _product_norm in _cheap_products
    ):
        return True, "low_value_insert_parallel"
    return False, ""


def _mv_price_anchor(item: Dict[str, Any]) -> Optional[float]:
    _price = _row_price_anchor(item)
    if _price > 0:
        return round(_price, 2)
    for _field in ("currentBidPrice", "price"):
        _value = _safe_float((item or {}).get(_field) or {})
        if _value:
            return round(_value, 2)
    return None


def _extract_debug_comp_rows(raw_comps: Any) -> List[Dict[str, Any]]:
    if isinstance(raw_comps, list):
        _parsed = raw_comps
    elif not raw_comps:
        _parsed = []
    else:
        try:
            _parsed = json.loads(str(raw_comps))
        except (TypeError, ValueError, json.JSONDecodeError):
            _parsed = []
    _rows: List[Dict[str, Any]] = []
    for _comp in _parsed:
        if not isinstance(_comp, dict):
            continue
        _price = _safe_float(_comp.get("price"))
        if _price is None:
            continue
        _row = dict(_comp)
        _row["price"] = _price
        _rows.append(_row)
    return _rows


def _compact_comp_evidence_row(comp: Dict[str, Any]) -> Optional[Dict[str, Any]]:
    if not isinstance(comp, dict):
        return None
    _price = _safe_float(
        comp.get("price")
        or comp.get("sold_price")
        or comp.get("sale_price")
        or comp.get("amount")
    )
    if _price is None or _price <= 0:
        return None
    _descriptor = str(
        comp.get("descriptor")
        or comp.get("title")
        or comp.get("comp_title")
        or comp.get("card_title")
        or comp.get("summary")
        or ""
    ).strip()
    _grade = str(
        comp.get("grade_label")
        or comp.get("grade")
        or comp.get("grade_state")
        or comp.get("condition")
        or comp.get("raw_grade")
        or ""
    ).strip()
    _sold_date = str(
        comp.get("sold_date")
        or comp.get("date")
        or comp.get("sale_date")
        or comp.get("last_sold_date")
        or ""
    ).strip()
    _source = str(
        comp.get("source")
        or comp.get("marketplace")
        or comp.get("comp_source")
        or ""
    ).strip()
    _entry: Dict[str, Any] = {
        "price": round(float(_price), 2),
        "descriptor": _descriptor[:180],
    }
    _lane = str(comp.get("lane") or comp.get("comp_lane_tier") or "").strip()
    _exactness_tier = str(comp.get("exactness_tier") or "").strip()
    _support_reason = str(comp.get("support_signal_reason") or comp.get("comp_lane_reason") or "").strip()
    if _grade:
        _entry["grade"] = _grade[:48]
    if _sold_date:
        _entry["sold_date"] = _sold_date[:32]
    if _source:
        _entry["source"] = _source[:48]
    if _lane:
        _entry["lane"] = _lane[:48]
    if _exactness_tier:
        _entry["exactness_tier"] = _exactness_tier[:64]
    if _support_reason:
        _entry["support_signal_reason"] = _support_reason[:120]
    return _entry


