def _single_card_support_norm_text(value: Any) -> str:
    return re.sub(r"[^a-z0-9]+", " ", str(value or "").lower()).strip()


def _single_card_support_canonical_player(row: Dict[str, Any]) -> str:
    if not isinstance(row, dict):
        return ""
    for _key in (
        "player",
        "player_name",
        "target_player_name",
        "normalized_entity",
        "identity_player",
        "fingerprint_player",
        "subject_player",
        "comp_player",
    ):
        _value = _single_card_support_norm_text(row.get(_key))
        if _value:
            return _value
    _title = _single_card_support_norm_text(row.get("title") or row.get("source_title") or row.get("descriptor") or row.get("comp_title") or row.get("sold_title"))
    _known = [
        _single_card_support_norm_text(row.get(_key))
        for _key in ("target_entity", "entity", "athlete", "name")
    ]
    for _value in _known:
        if _value:
            return _value
    _stop = {
        "2020", "2021", "2022", "2023", "2024", "2025", "panini", "topps", "bowman",
        "prizm", "draft", "picks", "signing", "day", "saturday", "star", "stars",
        "auto", "autograph", "rc", "rookie", "red", "blue", "green", "psa", "bgs",
        "sgc", "gem", "mint", "pop", "bucs", "card", "chrome",
    }
    _tokens = [t for t in _title.split() if t not in _stop and not t.isdigit()]
    return " ".join(_tokens[:2]).strip()


def _single_card_support_serial_denominator(row: Dict[str, Any]) -> Optional[int]:
    if not isinstance(row, dict):
        return None
    for _key in ("serial_denominator", "_hydrated_serial_denominator", "_canonical_serial_denominator", "fingerprint_serial_denominator", "serial", "serial_bucket"):
        _raw = str(row.get(_key) or "").strip()
        if not _raw:
            continue
        _m = re.search(r"(\d{1,4})", _raw)
        if _m:
            try:
                return int(_m.group(1))
            except Exception:
                pass
    _title = str(row.get("title") or row.get("source_title") or row.get("descriptor") or row.get("comp_title") or row.get("sold_title") or "")
    _m = re.search(r"/\s*(\d{1,4})\b", _title)
    if _m:
        try:
            return int(_m.group(1))
        except Exception:
            return None
    return None


def _single_card_support_insert_family(row: Dict[str, Any]) -> str:
    if not isinstance(row, dict):
        return ""
    _explicit = str(row.get("insert_family") or row.get("_hydrated_insert_family") or row.get("identity_insert_family") or row.get("fingerprint_insert_family") or "").strip().lower()
    _title = _single_card_support_norm_text(row.get("title") or row.get("source_title") or row.get("descriptor") or row.get("comp_title") or row.get("sold_title"))
    _checks = [
        ("home field advantage", "home_field_advantage"),
        ("stained glass", "stained_glass"),
        ("color blast", "color_blast"),
        ("blank slate", "blank_slate"),
        ("micro mosaic", "micro_mosaic"),
        ("ultra violet", "ultra_violet"),
        ("downtown", "downtown"),
        ("kaboom", "kaboom"),
        ("manga", "manga"),
        ("honeycomb", "honeycomb"),
        ("genesis", "genesis"),
        ("patch auto", "patch_auto"),
        ("auto patch", "auto_patch"),
        ("autograph", "auto"),
        ("auto", "auto"),
    ]
    for _needle, _family in _checks:
        if _needle in _title:
            return _family
    return _explicit


def _single_card_support_parallel_family(row: Dict[str, Any]) -> str:
    if not isinstance(row, dict):
        return ""
    _explicit = str(row.get("parallel_family") or row.get("_hydrated_parallel_family") or row.get("identity_parallel_family") or row.get("fingerprint_parallel") or row.get("parallel") or row.get("parallel_name") or "").strip().lower().replace(" ", "_")
    if _explicit:
        return _explicit
    _title = _single_card_support_norm_text(row.get("title") or row.get("source_title") or row.get("descriptor") or row.get("comp_title") or row.get("sold_title"))
    for _parallel in ("gold", "red", "blue", "green", "orange", "purple", "black", "silver", "pink"):
        if _parallel in _title.split():
            return _parallel
    return ""


def _single_card_support_grade_lane(row: Dict[str, Any]) -> str:
    _grade = str((row or {}).get("grade") or (row or {}).get("grade_label") or (row or {}).get("_hydrated_grade") or (row or {}).get("condition") or "").strip().upper()
    _title = str((row or {}).get("title") or (row or {}).get("source_title") or (row or {}).get("descriptor") or (row or {}).get("comp_title") or (row or {}).get("sold_title") or "").upper()
    _blob = f"{_grade} {_title}"
    if "PSA 10" in _blob:
        return "psa10"
    if "PSA" in _blob:
        return "psa"
    if "BGS 10" in _blob or "BGS 9.5" in _blob:
        return "bgs_gem"
    if "SGC 10" in _blob:
        return "sgc10"
    if any(_g in _blob for _g in ("BGS", "SGC", "CGC")):
        return "graded_other"
    return "raw"


def _single_card_support_premium_subject(row: Dict[str, Any]) -> bool:
    if not isinstance(row, dict):
        return False
    _insert = _single_card_support_insert_family(row)
    _serial = _single_card_support_serial_denominator(row)
    _grade = _single_card_support_grade_lane(row)
    _premium_lane = bool(row.get("premium_lane") or row.get("_prep_board") or row.get("prep_comp_mode") == "fresh_single_card")
    return bool(
        _premium_lane
        or _insert in {"auto", "patch_auto", "auto_patch"} | _SINGLE_CARD_CASE_HIT_FAMILIES
        or _serial is not None
        or _grade != "raw"
    )


def _single_card_support_comp_contract(subject_row: Dict[str, Any], comp_row: Dict[str, Any]) -> Tuple[bool, str]:
    """
    Strict support-comp admission for premium single-card valuation.
    """
    try:
        _subject = subject_row if isinstance(subject_row, dict) else {}
        _comp = comp_row if isinstance(comp_row, dict) else {}
        _subject_title = str(_subject.get("title") or _subject.get("source_title") or "")[:160]
        _comp_title = str(_comp.get("title") or _comp.get("comp_title") or _comp.get("descriptor") or _comp.get("sold_title") or "")[:160]
        _subject_player = _single_card_support_canonical_player(_subject)
        _comp_player = _single_card_support_canonical_player(_comp)
        _subject_serial = _single_card_support_serial_denominator(_subject)
        _comp_serial = _single_card_support_serial_denominator(_comp)
        _subject_insert = _single_card_support_insert_family(_subject)
        _comp_insert = _single_card_support_insert_family(_comp)
        _subject_parallel = _single_card_support_parallel_family(_subject)
        _comp_parallel = _single_card_support_parallel_family(_comp)
        _subject_grade = _single_card_support_grade_lane(_subject)
        _comp_grade = _single_card_support_grade_lane(_comp)
        _support_reason = str(_comp.get("support_signal_reason") or _comp.get("comp_lane_reason") or "").strip().lower()
        _source = str(_comp.get("source") or _comp.get("marketplace") or _comp.get("comp_source") or _comp.get("evidence_source") or "").strip().lower()
        _sold_date = str(_comp.get("sold_date") or _comp.get("date") or _comp.get("sale_date") or "").strip()
        _price = _safe_float(_comp.get("price") or _comp.get("sold_price") or _comp.get("sale_price") or _comp.get("amount"))
        _subject_premium = _single_card_support_premium_subject(_subject)
        _reason = "allow"

        if not _subject_premium:
            _allow = True
        elif not _comp_title or _comp_title.lower() in {"comp evidence", "market value", "minimum_renderable_evidence"}:
            _allow, _reason = False, "generic_placeholder_identity"
        elif bool(_subject.get("dual_player") or _subject.get("multi_player")) and not bool(_subject.get("allow_multi_entity_support")):
            _allow, _reason = False, "multi_entity_support_not_allowed"
        elif not _subject_player or not _comp_player or _subject_player != _comp_player:
            _allow, _reason = False, "player_mismatch"
        elif _subject_serial is not None and _comp_serial is not None and _subject_serial != _comp_serial:
            _allow, _reason = False, f"serial_band_mismatch_{_subject_serial}_vs_{_comp_serial}"
        elif _subject_serial is not None and _comp_serial is None:
            _allow, _reason = False, "serial_missing_on_comp"
        elif _subject_insert in {"auto", "patch_auto", "auto_patch"} | _SINGLE_CARD_CASE_HIT_FAMILIES and _subject_insert != _comp_insert:
            _allow, _reason = False, "insert_family_mismatch"
        elif _subject_insert in _SINGLE_CARD_CASE_HIT_FAMILIES and _subject_insert != _comp_insert:
            _allow, _reason = False, "premium_family_mismatch"
        elif _subject_grade != "raw" and (_comp_grade == "raw" or (_subject_grade in {"psa10", "psa"} and _comp_grade not in {"psa10", "psa"})):
            _allow, _reason = False, "grade_lane_mismatch"
        elif _support_reason == "generic_support_identity":
            _allow, _reason = False, "generic_support_identity_blocked"
        elif not _price or _price <= 0 or _source in {"none", "price_anchor_fallback", "minimum_renderable_evidence", "structured_fallback"} or (not _source and not _sold_date):
            _allow, _reason = False, "no_sold_proof"
        else:
            _allow = True

        print(
            f"[SUPPORT_COMP_CONTRACT] "
            f"title={_subject_title} "
            f"comp_title={_comp_title} "
            f"allow={1 if _allow else 0} "
            f"reason={_reason} "
            f"subject_player={_subject_player or 'none'} "
            f"comp_player={_comp_player or 'none'} "
            f"subject_serial={_subject_serial if _subject_serial is not None else ''} "
            f"comp_serial={_comp_serial if _comp_serial is not None else ''} "
            f"subject_insert={_subject_insert or ''} "
            f"comp_insert={_comp_insert or ''} "
            f"subject_parallel={_subject_parallel or ''} "
            f"comp_parallel={_comp_parallel or ''} "
            f"subject_grade={_subject_grade or ''} "
            f"comp_grade={_comp_grade or ''}"
        )
        return bool(_allow), str(_reason)
    except Exception:
        return False, "exception"


def _single_card_support_reject_bucket(reason: str) -> str:
    _reason = str(reason or "").lower()
    if "player" in _reason or "entity" in _reason:
        return "rejected_player"
    if "serial" in _reason:
        return "rejected_serial"
    if "insert" in _reason or "family" in _reason:
        return "rejected_insert"
    if "grade" in _reason or "raw" in _reason:
        return "rejected_grade"
    if "generic" in _reason or "placeholder" in _reason or "sold_proof" in _reason:
        return "rejected_generic"
    return "rejected_generic"


def _published_comp_evidence_payload(
    row: Dict[str, Any],
    comp_rows: List[Dict[str, Any]],
    *,
    limit: int = 5,
) -> Dict[str, List[Dict[str, Any]]]:
    _raw_rows = [dict(_comp) for _comp in list(comp_rows or []) if isinstance(_comp, dict)]
    _strict_single_card_support = bool(
        str((row or {}).get("prep_comp_mode") or "").strip() == "fresh_single_card"
        or bool((row or {}).get("single_card_fresh_run"))
    )
    _support_contract_raw = 0
    _support_contract_accepted = 0
    _support_contract_reject_counts = {
        "rejected_player": 0,
        "rejected_serial": 0,
        "rejected_insert": 0,
        "rejected_grade": 0,
        "rejected_generic": 0,
    }

    def _raw_comp_key(_entry: Dict[str, Any]) -> str:
        return "|".join(
            [
                str(_entry.get("price") or "").strip().lower(),
                str(_entry.get("title") or _entry.get("comp_title") or "").strip().lower(),
                str(_entry.get("date") or _entry.get("sold_date") or "").strip().lower(),
            ]
        )

    def _exact_lane_labeled(_entry: Dict[str, Any]) -> bool:
        _lane = str(_entry.get("lane") or _entry.get("comp_lane_tier") or "").strip().lower()
        _exactness_tier = str(_entry.get("exactness_tier") or "").strip().lower()
        _support_reason = str(_entry.get("support_signal_reason") or _entry.get("comp_lane_reason") or "").strip().lower()
        return bool(
            _lane == "exact_lane"
            or _exactness_tier in {"exact_strict", "exact_lane", "exact"}
            or _support_reason == "exact_lane"
        )

    _candidate_exact_raw = [dict(_comp) for _comp in _raw_rows if _exact_lane_labeled(_comp)]
    if not _candidate_exact_raw:
        _candidate_exact_raw = _filter_exact_same_card_comps(row or {}, _raw_rows) if _raw_rows else []

    _exact_raw: List[Dict[str, Any]] = []
    _blocked_raw_keys: set[str] = set()
    _wrong_parallel_blocked = 0
    for _comp in _candidate_exact_raw:
        _comp_title = str(_comp.get("title") or _comp.get("comp_title") or "").strip()
        _raw_key = _raw_comp_key(_comp)
        if _comp_title:
            _parallel_contract = exact_parallel_identity_contract(
                dict(row or {}),
                _comp_title,
                source_row=dict(row or {}),
                emit_log=False,
            )
            if not bool(_parallel_contract.get("allow")):
                _wrong_parallel_blocked += 1
                if _raw_key:
                    _blocked_raw_keys.add(_raw_key)
                continue
        _exact_raw.append(dict(_comp))

    _exact_keys = {
        _raw_comp_key(_comp)
        for _comp in _exact_raw
    }

    def _row_key(_entry: Dict[str, Any]) -> str:
        return "|".join(
            [
                str(_entry.get("price") or "").strip().lower(),
                str(_entry.get("descriptor") or _entry.get("title") or "").strip().lower(),
                str(_entry.get("sold_date") or _entry.get("date") or "").strip().lower(),
            ]
        )

    _exact_rows: List[Dict[str, Any]] = []
    _support_rows: List[Dict[str, Any]] = []
    _seen_keys: set[str] = set()

    for _raw in _exact_raw:
        _compact = _compact_comp_evidence_row(_raw)
        if not _compact:
            continue
        _key = _row_key(_compact)
        if not _key or _key in _seen_keys:
            continue
        _seen_keys.add(_key)
        _exact_rows.append(_compact)

    for _raw in _raw_rows:
        _raw_key = _raw_comp_key(_raw)
        if _raw_key in _exact_keys or _raw_key in _blocked_raw_keys:
            continue
        if _strict_single_card_support:
            _support_contract_raw += 1
            _allow_support, _support_reason = _single_card_support_comp_contract(dict(row or {}), _raw)
            if not _allow_support:
                _bucket = _single_card_support_reject_bucket(_support_reason)
                _support_contract_reject_counts[_bucket] = int(_support_contract_reject_counts.get(_bucket) or 0) + 1
                print(
                    f"[SINGLE_CARD_SUPPORT_REJECT] "
                    f"title={str((row or {}).get('title') or (row or {}).get('source_title') or '')[:160]} "
                    f"comp_title={str(_raw.get('title') or _raw.get('comp_title') or _raw.get('descriptor') or '')[:160]} "
                    f"reason={_support_reason}"
                )
                continue
        _compact = _compact_comp_evidence_row(_raw)
        if not _compact:
            continue
        _key = _row_key(_compact)
        if not _key or _key in _seen_keys:
            continue
        _seen_keys.add(_key)
        _support_rows.append(_compact)
        if _strict_single_card_support:
            _support_contract_accepted += 1

    _published = list((_exact_rows + _support_rows)[: max(0, int(limit or 0)) or 5])
    if _strict_single_card_support:
        print(
            f"[SINGLE_CARD_SUPPORT_SUMMARY] "
            f"title={str((row or {}).get('title') or (row or {}).get('source_title') or '')[:160]} "
            f"raw_candidates={_support_contract_raw} "
            f"accepted_support={_support_contract_accepted} "
            f"rejected_player={int(_support_contract_reject_counts.get('rejected_player') or 0)} "
            f"rejected_serial={int(_support_contract_reject_counts.get('rejected_serial') or 0)} "
            f"rejected_insert={int(_support_contract_reject_counts.get('rejected_insert') or 0)} "
            f"rejected_grade={int(_support_contract_reject_counts.get('rejected_grade') or 0)} "
            f"rejected_generic={int(_support_contract_reject_counts.get('rejected_generic') or 0)}"
        )
    print(
        f"[PARALLEL_RENDER_PAYLOAD] title={str(row.get('title') or row.get('source_title') or '')[:140]} "
        f"trusted_detail_rows={len(_exact_rows)} exact_comps={len(_exact_rows)} "
        f"wrong_parallel_blocked={_wrong_parallel_blocked}"
    )
    return {
        "exact_rows": _exact_rows,
        "support_rows": _support_rows,
        "published": _published,
    }


def _coerce_comp_detail_rows(value: Any) -> List[Dict[str, Any]]:
    _rows: List[Dict[str, Any]] = []
    if isinstance(value, list):
        for _entry in value:
            if isinstance(_entry, dict):
                _rows.append(dict(_entry))
    return _rows


def _renderable_comp_evidence_rows(value: Any) -> List[Dict[str, Any]]:
    _candidate_rows: List[Dict[str, Any]] = []
    if isinstance(value, list):
        _candidate_rows.extend(dict(_entry) for _entry in value if isinstance(_entry, dict))
    elif isinstance(value, dict):
        for _nested_key in ("used", "rows", "exact", "supporting", "comps", "evidence"):
            _nested_value = value.get(_nested_key)
            if isinstance(_nested_value, list):
                _candidate_rows.extend(dict(_entry) for _entry in _nested_value if isinstance(_entry, dict))
    _renderable_rows: List[Dict[str, Any]] = []
    for _entry in _candidate_rows:
        _price = _safe_float(
            _entry.get("price")
            or _entry.get("sold_price")
            or _entry.get("sale_price")
            or _entry.get("amount")
            or _entry.get("value")
        )
        _descriptor = str(
            _entry.get("descriptor")
            or _entry.get("title")
            or _entry.get("card_title")
            or _entry.get("summary")
            or ""
        ).strip()
        _grade = str(
            _entry.get("grade_label")
            or _entry.get("grade")
            or _entry.get("condition_label")
            or _entry.get("condition")
            or ""
        ).strip()
        _date = str(
            _entry.get("date")
            or _entry.get("sold_date")
            or _entry.get("sale_date")
            or _entry.get("listing_end_iso")
            or ""
        ).strip()
        if _price is not None or _descriptor or _grade or _date:
            _renderable_rows.append(dict(_entry))
    return _renderable_rows


def _build_review_evidence_payload(row: Dict[str, Any]) -> List[Dict[str, Any]]:
    _row = row or {}
    _review = _safe_float(_row.get("review_estimate_value") or _row.get("review_estimate"))
    _target = _safe_float(_row.get("target_bid") or _row.get("target_bid_price") or _row.get("bid_ceiling_value"))
    _anchor = _safe_float(_row.get("final_bid_anchor_value"))
    _current = _safe_float(_row.get("current_price") or _row.get("price") or _row.get("listing_price"))
    _out: List[Dict[str, Any]] = []
    if _review and _review > 0:
        _out.append({
            "kind": "review_estimate",
            "label": "Review estimate",
            "value": round(_review, 2),
            "renderable": True,
        })
    if _target and _target > 0:
        _out.append({
            "kind": "target_bid",
            "label": "Target bid",
            "value": round(_target, 2),
            "renderable": True,
        })
    if _anchor and _anchor > 0:
        _out.append({
            "kind": "bid_anchor",
            "label": "Bid anchor",
            "value": round(_anchor, 2),
            "renderable": True,
        })
    if _current and _current > 0:
        _out.append({
            "kind": "current_price",
            "label": "Current price",
            "value": round(_current, 2),
            "renderable": True,
        })
    if _out and ((_review and _review > 0) or (_target and _target > 0) or (_anchor and _anchor > 0)):
        _title = str(_row.get("title") or _row.get("source_title") or "").strip()
        print(
            f"[REVIEW_EVIDENCE_BUILD] title={_title[:120]} "
            f"review={round(float(_review), 2) if _review and _review > 0 else None} "
            f"target_bid={round(float(_target), 2) if _target and _target > 0 else None} "
            f"payload_count={len(_out)}"
        )
    return _out


def _review_surface_evidence_ok(row: Dict[str, Any]) -> bool:
    _row = row or {}
    _truth_level = str(_row.get("truth_level") or _row.get("valuation_truth_level") or "").strip().upper()
    _truth = str(_row.get("truth") or _row.get("_valuation_truth_tier") or _row.get("valuation_truth_tier") or "").strip().upper()
    return bool(
        (_truth_level == "REVIEW" or _truth == "REVIEW")
        and _safe_float(_row.get("review_estimate_value") or _row.get("review_estimate")) is not None
        and _safe_float(_row.get("target_bid") or _row.get("target_bid_price") or _row.get("bid_ceiling_value")) is not None
        and int(_row.get("evidence_renderable") or 0) == 1
        and _row.get("evidence_render_source") == "review_payload"
    )


def _trusted_premium_lane_authority(row):
    try:
        if not isinstance(row, dict):
            return False, "not_dict"

        _identity_is_clean = bool(row.get("identity_is_clean") or row.get("_hydrated_identity_is_clean"))
        _truth = str(row.get("truth") or row.get("_valuation_truth_tier") or row.get("valuation_truth_tier") or "").strip().upper()
        _trusted_exact = int(row.get("trusted_exact_comp_count") or 0)
        _parallel_family = str(row.get("parallel_family") or row.get("_hydrated_parallel_family") or "").strip().lower()
        _insert_family = str(row.get("insert_family") or row.get("_hydrated_insert_family") or "").strip().lower()
        _serial = row.get("serial_denominator") or row.get("_hydrated_serial_denominator")
        _current_price = row.get("current_price")
        _target_bid = row.get("target_bid")

        _has_premium_signal = bool(
            (_parallel_family not in {"", "base", "none"})
            or _insert_family
            or str(_serial).strip()
        )
        _has_live_price = isinstance(_current_price, (int, float))
        _has_target_bid = isinstance(_target_bid, (int, float))

        _allow = bool(
            _identity_is_clean
            and _truth == "TRUE"
            and _trusted_exact >= 1
            and _has_premium_signal
            and _has_live_price
            and _has_target_bid
        )
        _reason = "trusted_premium_lane_authority" if _allow else "not_trusted_premium_ready"
        print(
            f"[TRUSTED_PREMIUM_LANE] "
            f"title={str((row or {}).get('title') or (row or {}).get('source_title') or '')[:160]} "
            f"allow={_allow} "
            f"reason={_reason} "
            f"truth={row.get('truth') or row.get('_valuation_truth_tier') or row.get('valuation_truth_tier')} "
            f"trusted_exact={row.get('trusted_exact_comp_count')} "
            f"current_price={row.get('current_price')} "
            f"target_bid={row.get('target_bid')} "
            f"parallel_family={row.get('parallel_family') or row.get('_hydrated_parallel_family')} "
            f"insert_family={row.get('insert_family') or row.get('_hydrated_insert_family')} "
            f"serial_denominator={row.get('serial_denominator') or row.get('_hydrated_serial_denominator')}"
        )
        return _allow, _reason
    except Exception:
        return False, "exception"


