def _stamp_collector_heat_signal(row: Dict[str, Any]) -> Dict[str, Any]:
    try:
        if not isinstance(row, dict):
            return row
        _title = str(row.get("source_title") or row.get("title") or "").strip().lower()
        _player = str(row.get("player_name") or row.get("target_player_name") or row.get("_target_player") or "").strip().lower()
        _product = str(row.get("product_family") or row.get("target_product_family") or row.get("lane_product") or "").strip().lower()
        _parallel = str(row.get("parallel_family") or row.get("parallel_bucket") or row.get("parallel_name") or row.get("rare_parallel") or "").strip().lower()
        _insert = str(row.get("insert_family") or row.get("subset_name") or row.get("lane_insert") or "").strip().lower()
        _haystack = " ".join([_title, _product, _parallel, _insert])
        _padded = f" {_haystack} "
        _case_hit_terms = {
            "downtown", "kaboom", "color blast", "stained glass",
            "manga", "national pride", "ultra rare", "case hit",
            "genesis", "honeycomb", "zebra", "tiger", "elephant",
            "peacock", "dragon scale", "gold vinyl", "superfractor",
        }
        _premium_grade_terms = {"psa 10", "bgs 10", "black label", "sgc 10"}
        _rookie_terms = {"rookie", "rc", "1st bowman", "1st chrome"}
        _auto_terms = {"auto", "autograph", "signatures"}
        _premium_product_terms = {
            "topps chrome", "bowman chrome", "topps chrome black", "topps cosmic chrome",
            "sapphire", "finest", "prizm", "select", "optic", "mosaic",
            "national treasures", "immaculate", "flawless", "spectra",
            "dynasty", "transcendent", "museum", "definitive", "sterling",
        }

        def _has_term(_terms: set[str]) -> bool:
            return any(f" {_term} " in _padded or _term in _haystack for _term in _terms)

        _score = 0
        _reasons: List[str] = []
        if _has_term(_case_hit_terms):
            _score += 40
            _reasons.append("CASE HIT")
        if _has_term(_premium_grade_terms):
            _score += 30
            _reasons.append("PSA 10")
        if _has_term(_rookie_terms):
            _score += 25
            _reasons.append("RC")
        if _has_term(_auto_terms):
            _score += 25
            _reasons.append("AUTO")

        _serial_raw = (
            row.get("serial_denominator")
            or row.get("_canonical_serial_denominator")
            or row.get("_lane_serial_denominator")
            or row.get("serial")
            or row.get("print_run")
            or ""
        )
        _serial_den = _safe_float(_serial_raw)
        if _serial_den is None:
            try:
                _serial_match = re.search(r"/\s*(\d{1,4})(?:\D|$)", _title)
                _serial_den = float(_serial_match.group(1)) if _serial_match else None
            except Exception:
                _serial_den = None
        if _serial_den is not None and _serial_den > 0:
            if _serial_den <= 10:
                _score += 60
                _reasons.append("LOW SERIAL")
            elif _serial_den <= 25:
                _score += 40
                _reasons.append("LOW SERIAL")
            elif _serial_den <= 99:
                _score += 25
                _reasons.append("LOW SERIAL")
        if _player and _player_heat_tier(_player) in {1, 2}:
            _score += 20
            _reasons.append("ELITE PLAYER")
        _quality_contract = row.get("_final_quality_contract")
        if not isinstance(_quality_contract, dict):
            try:
                _quality_contract = _build_final_quality_contract(row)
            except Exception:
                _quality_contract = {}
        if bool((_quality_contract or {}).get("final_is_premium_product")) or _has_term(_premium_product_terms):
            _score += 15
            _reasons.append("PREMIUM PRODUCT")

        _deduped_reasons: List[str] = []
        for _reason in _reasons:
            if _reason not in _deduped_reasons:
                _deduped_reasons.append(_reason)
        row["heat_signal_score"] = int(_score)
        row["heat_signal_reasons"] = list(_deduped_reasons)
        row["_collector_heat_surface"] = bool(_score >= 40)
        if row["_collector_heat_surface"]:
            _intent = str(row.get("surface_intent") or "").strip().lower()
            if _intent not in {"watchlist", "sniper", "snipe", "execute_now", "execute now"}:
                row["surface_intent"] = "monitor"
            if not str(row.get("surface_label") or "").strip():
                row["surface_label"] = "HIGH-HEAT RESEARCH"
            if not str(row.get("decision_label") or "").strip():
                row["decision_label"] = "HIGH-HEAT RESEARCH"
            if not str(row.get("action_label") or "").strip():
                row["action_label"] = "HIGH-HEAT RESEARCH"
            row["board_visible"] = True
            row["commercially_visible"] = True
        print(
            f"[COLLECTOR_HEAT_SIGNAL] title={str((row or {}).get('title') or '')[:160]} "
            f"score={row.get('heat_signal_score')} "
            f"reasons={row.get('heat_signal_reasons')} "
            f"surface={1 if row.get('_collector_heat_surface') else 0} "
            f"truth={row.get('truth') or row.get('valuation_truth_tier') or row.get('_valuation_truth_tier')} "
            f"current={row.get('current_price')} "
            f"mv={row.get('true_mv') or row.get('true_market_value') or row.get('market_value_true') or row.get('review_estimate') or row.get('review_estimate_value')} "
            f"surface_intent={row.get('surface_intent')}"
        )
        return row
    except Exception as e:
        print(f"[COLLECTOR_HEAT_SIGNAL_ERROR] error={e}")
        return row


def _stamp_final_surface_tier_contract(row: Dict[str, Any]) -> Dict[str, Any]:
    try:
        if not isinstance(row, dict):
            return row
        _stamp_collector_heat_signal(row)
        _truth_tier = str(
            row.get("truth")
            or row.get("_valuation_truth_tier")
            or row.get("valuation_truth_tier")
            or ""
        ).strip().upper()
        _truth_level = str(row.get("truth_level") or row.get("valuation_truth_level") or "").strip().upper()
        _truth = _truth_tier or _truth_level
        _trusted_exact = int(row.get("trusted_exact_comp_count") or row.get("exact_comp_count") or 0)
        _support = int(row.get("support_comp_count") or 0)
        _current = _safe_float(row.get("current_price") or row.get("current_bid") or row.get("price"))
        _true_mv = _safe_float(row.get("true_mv") or row.get("true_market_value") or row.get("market_value_true"))
        _review = _safe_float(row.get("review_estimate_value") or row.get("review_estimate") or row.get("anchored_estimate_value"))
        try:
            _evidence_renderable = bool(int(row.get("evidence_renderable") or 0))
        except Exception:
            _evidence_renderable = bool(row.get("evidence_renderable"))
        _no_renderable = str(row.get("evidence_render_reason") or row.get("final_surface_reason") or row.get("decision_reason") or "").strip() == "no_renderable_evidence"
        _true_differs = bool(_true_mv is not None and _current is not None and abs(float(_true_mv) - float(_current)) >= 0.01)
        _review_differs = bool(_review is not None and _current is not None and abs(float(_review) - float(_current)) >= 0.01)
        _review_equals_current = bool(_review is not None and _current is not None and abs(float(_review) - float(_current)) < 0.01)
        _edge_value = (
            _safe_float(row.get("edge_dollars"))
            or _safe_float(row.get("edge_value"))
            or _safe_float((row.get("action_summary") or {}).get("expected_profit"))
            or 0.0
        )
        _target_bid = _safe_float(row.get("target_bid") or row.get("target_bid_price") or row.get("bid_ceiling_value"))
        _edge_passes = bool(
            (_edge_value and _edge_value > 0)
            or (_current is not None and _target_bid is not None and _current <= _target_bid)
        )
        _tier = "none"
        _reason = "no_surface_tier"

        if (_truth_tier == "TRUE" or _truth in {"TRUE", "EXACT", "EXACT_RESCUE"}) and _trusted_exact >= 1 and _true_mv is not None and _true_mv > 0 and _true_differs:
            _tier = "watchlist"
            _reason = "true_mv_verified_non_clone"
            row["_surface_tier"] = "verified_watchlist"
            row["surface_intent"] = "watchlist"
            row["surface_label"] = "WATCHLIST"
            row["decision_label"] = "WATCHLIST"
            row["action_label"] = "WATCHLIST"
            row["board_visible"] = True
            row["commercially_visible"] = True
            row["commercial_visibility"] = "watchlist"
            row["execution_admission_bucket"] = "watchlist"
            row["_surface_tier_blocks_sniper"] = not _edge_passes
            row["_surface_tier_allows_mv"] = True
        elif _review is not None and _review > 0 and _review_differs and (_support >= 1 or _evidence_renderable):
            _tier = "watchlist_verify"
            _reason = "review_reference_non_clone_with_evidence"
            row["_surface_tier"] = "review_watchlist_verify"
            row["surface_intent"] = "watchlist"
            row["surface_label"] = "WATCHLIST - VERIFY"
            row["decision_label"] = "WATCHLIST - VERIFY"
            row["action_label"] = "WATCHLIST - VERIFY"
            row["board_visible"] = True
            row["commercially_visible"] = True
            row["commercial_visibility"] = "watchlist"
            row["execution_admission_bucket"] = "watchlist"
            row["_surface_tier_blocks_sniper"] = True
            row["_surface_tier_allows_reference_value"] = True
        _trusted_lane_allow, _trusted_lane_reason = _trusted_premium_lane_authority(row)
        if _trusted_lane_allow:
            row["trusted_premium_lane_authority"] = True
            row["premium_lane"] = 1
            row["premium_lane_reason"] = _trusted_lane_reason
            row["_research_only_price_check"] = False
            row["_research_only_reason"] = ""
            print(
                f"[TRUSTED_PREMIUM_LANE_ASSERT] "
                f"title={str((row or {}).get('title') or '')[:160]} "
                f"premium_lane={row.get('premium_lane')} "
                f"premium_lane_reason={row.get('premium_lane_reason')} "
                f"research_only={row.get('_research_only_price_check')} "
                f"research_reason={row.get('_research_only_reason')}"
            )
        if _tier == "none":
            _late_allow, _late_allow_reason = _late_live_surface_allow_contract(row)
            if _late_allow:
                _late_bucket, _late_bucket_reason = _late_live_surface_bucket(row)
                if _late_bucket:
                    _tier = _late_bucket
                    _reason = _late_bucket_reason
                    row["late_live_surface_rescue"] = True
                    row["late_live_surface_reason"] = _late_bucket_reason
                    row["execution_final_decision"] = "SNIPE" if _late_bucket == "sniper" else "WATCH"
                    row["execution_admission_bucket"] = _late_bucket
                    row["commercial_visibility"] = _late_bucket
                    row["final_bucket"] = _late_bucket
                    row["_final_bucket"] = _late_bucket.upper()
                    row["commercially_visible"] = True
                    row["board_visible"] = True
                    row["_surface_bucket"] = _late_bucket
                    row["surface_intent"] = _late_bucket
                    row["subscription_lane_tier"] = _late_bucket.upper()
                    row["subscription_lane_tier_reason"] = _late_bucket_reason
                    row["_surface_tier"] = "late_live_surface_sniper" if _late_bucket == "sniper" else "late_live_surface_watchlist"
                    row["final_visible_append_reason"] = _late_bucket_reason
                else:
                    _reason = _late_bucket_reason
            elif str(_late_allow_reason or "") and _reason == "no_surface_tier":
                _reason = _late_allow_reason
        if _tier == "none" and (row.get("_research_only_price_check") or row.get("_estimate_equals_current") or _no_renderable or _review_equals_current):
            _tier = "research_only"
            _reason = str(row.get("_research_only_reason") or "mv_clone_or_no_renderable_evidence")
            _stamp_research_only_price_check(row)
            _apply_research_only_presentation(row)
            row["_surface_tier"] = "research_only"
            if row.get("_collector_heat_surface"):
                row["surface_label"] = "HIGH-HEAT RESEARCH"
                row["decision_label"] = "RESEARCH ONLY"
                row["action_label"] = "PRICE CHECK NEEDED"
            else:
                row["surface_label"] = "RESEARCH ONLY"
            row["_surface_tier_blocks_sniper"] = True
        print(
            f"[SURFACE_TIER_DECISION] title={str((row or {}).get('title') or '')[:160]} "
            f"tier={_tier} "
            f"reason={_reason} "
            f"truth={_truth} "
            f"trusted_exact={_trusted_exact} "
            f"support={_support} "
            f"current={_current} "
            f"true_mv={_true_mv} "
            f"review_estimate={_review} "
            f"surface_intent={row.get('surface_intent')}"
        )
        return row
    except Exception as e:
        print(f"[SURFACE_TIER_DECISION_ERROR] error={e}")
        return row


def _is_customer_surface_eligible(row):
    try:
        if not isinstance(row, dict):
            return False

        _truth = str(
            row.get("truth")
            or row.get("truth_level")
            or row.get("valuation_truth_level")
            or row.get("_valuation_truth_tier")
            or row.get("valuation_truth_tier")
            or ""
        ).strip().upper()
        _true_mv = (
            row.get("true_mv")
            if row.get("true_mv") is not None
            else row.get("true_market_value")
            if row.get("true_market_value") is not None
            else row.get("market_value_true")
        )
        _true_mv_numeric = _safe_float(_true_mv)
        _true_mv_present = bool(_true_mv_numeric is not None and _true_mv_numeric > 0)
        _support_count = int(row.get("support_comp_count") or 0)
        _trusted_exact = int(row.get("trusted_exact_comp_count") or row.get("exact_comp_count") or 0)
        try:
            _evidence_renderable = bool(int(row.get("evidence_renderable") or 0))
        except Exception:
            _evidence_renderable = bool(row.get("evidence_renderable"))
        _review_class = str(
            row.get("review_class")
            or row.get("review_truth_class")
            or ""
        ).strip().lower()
        if not _review_class and bool(row.get("anchor_only_review") or row.get("_anchor_only_review")):
            _review_class = "anchor_only_review"
        _target_bid = row.get("target_bid")
        _current = row.get("current_price") or row.get("current") or row.get("price")
        _ = (_target_bid, _current)

        if str(row.get("surface_intent") or "").strip().lower() == "watchlist" and str(row.get("_surface_tier") or "").strip() in {
            "verified_watchlist",
            "review_watchlist_verify",
        }:
            return True

        # true comp-backed rows are always eligible
        if (_truth == "TRUE" or _truth in {"EXACT", "EXACT_RESCUE"}) and _true_mv_present:
            return True

        # support-backed rows with renderable evidence are eligible
        if (_support_count > 0 or _trusted_exact > 0) and _evidence_renderable:
            return True

        # hard block anchor-only review rows
        if _review_class == "anchor_only_review":
            return False

        # hard block review rows with no evidence
        if _truth == "REVIEW" and not _evidence_renderable:
            return False

        return False
    except Exception:
        return False


def _is_research_queue_eligible(row):
    try:
        if not isinstance(row, dict):
            return False
        if (
            row.get("_research_only_price_check")
            or row.get("_collector_heat_surface")
            or str(row.get("_surface_tier") or "").strip() == "research_only"
        ):
            return True
        _truth = str(
            row.get("truth")
            or row.get("truth_level")
            or row.get("valuation_truth_level")
            or row.get("_valuation_truth_tier")
            or row.get("valuation_truth_tier")
            or ""
        ).strip().upper()
        _review_class = str(
            row.get("review_class")
            or row.get("review_truth_class")
            or ""
        ).strip().lower()
        if not _review_class and bool(row.get("anchor_only_review") or row.get("_anchor_only_review")):
            _review_class = "anchor_only_review"
        _premium_lane = bool(
            row.get("premium_lane")
            or row.get("is_premium_lane")
            or row.get("premium")
            or str(row.get("premium_class") or "").strip().upper() in {"ENDGAME_CHASE", "PREMIUM_SECONDARY"}
            or str(row.get("chase_class") or "").strip().upper() in {"ENDGAME_CHASE", "PREMIUM_SECONDARY"}
            or str(row.get("commercial_class") or "").strip().upper() in {"ENDGAME_CHASE", "PREMIUM_SECONDARY"}
            or str(row.get("lane_tier") or "").strip().upper() in {"ENDGAME_CHASE", "PREMIUM_SECONDARY"}
        )
        _target_bid = row.get("target_bid")
        _current_price = row.get("current_price") or row.get("current") or row.get("price")
        return bool(
            _premium_lane
            and _truth == "REVIEW"
            and _review_class == "anchor_only_review"
            and _target_bid is not None
            and _current_price is not None
        )
    except Exception:
        return False


def _stamp_customer_surface_contract(row: Dict[str, Any], *, emit_log: bool = True) -> Dict[str, Any]:
    _row = row if isinstance(row, dict) else {}
    _customer_surface_ok = _is_customer_surface_eligible(_row)
    if _customer_surface_ok:
        _row["_customer_surface_blocked"] = False
        _row["_customer_surface_reason"] = ""
        if emit_log:
            print(
                f"[CUSTOMER_SURFACE_ALLOW] title={str((_row or {}).get('title') or '')[:140]} "
                f"truth={_row.get('truth') or _row.get('truth_level') or _row.get('valuation_truth_level')} "
                f"true_mv={_row.get('true_mv') or _row.get('true_market_value') or _row.get('market_value_true')} "
                f"trusted_exact={_row.get('trusted_exact_comp_count')} "
                f"support_count={_row.get('support_comp_count')}"
            )
        return _row

    _row["_customer_surface_blocked"] = True
    _row["_customer_surface_reason"] = "no_verified_edge"
    _row["commercial_visibility"] = "hidden_research_candidate"
    _row["visible_route"] = "hidden_research_candidate"
    _row["final_bucket"] = "research"
    _row["execution_admission_bucket"] = "research"
    _row["_render_live_watchlist"] = False
    _row["render_live_watchlist"] = False
    if emit_log:
        print(
            f"[CUSTOMER_SURFACE_BLOCK] title={str((_row or {}).get('title') or '')[:140]} "
            f"truth={_row.get('truth') or _row.get('truth_level') or _row.get('valuation_truth_level')} "
            f"true_mv={_row.get('true_mv') or _row.get('true_market_value') or _row.get('market_value_true')} "
            f"trusted_exact={_row.get('trusted_exact_comp_count')} "
            f"support_count={_row.get('support_comp_count')} "
            f"review_class={_row.get('review_class') or _row.get('review_truth_class')} "
            f"reason=no_verified_edge"
        )
    return _row


def _stamp_evidence_render_contract(
    row: Dict[str, Any],
    *,
    emit_log: bool = True,
) -> Dict[str, Any]:
    _row = _stamp_comp_truth_split(dict(row or {}), emit_log=False)
    _truth = str(_row.get("_valuation_truth_tier") or _row.get("valuation_truth_tier") or "").strip().upper() or "NONE"
    _truth_level = str(_row.get("valuation_truth_level") or "").strip().upper() or "NONE"
    _trusted_rows = _renderable_comp_evidence_rows(_row.get("trusted_detail_rows"))
    _support_rows = _renderable_comp_evidence_rows(_row.get("support_detail_rows"))
    _fallback_rows = _renderable_comp_evidence_rows(_row.get("comp_evidence"))
    _renderable_rows: List[Dict[str, Any]] = []
    if _trusted_rows:
        _renderable_rows = list(_trusted_rows)
    elif _support_rows:
        _renderable_rows = list(_support_rows)
    elif _truth_level in {"REVIEW", "NONE"} and _fallback_rows:
        _renderable_rows = list(_fallback_rows)
    _review_payload = _build_review_evidence_payload(_row)
    _review_payload_ready = bool(
        (_truth_level == "REVIEW" or _truth == "REVIEW")
        and _safe_float(_row.get("target_bid") or _row.get("target_bid_price") or _row.get("bid_ceiling_value")) is not None
        and _safe_float(_row.get("review_estimate_value") or _row.get("review_estimate")) is not None
        and _review_payload
    )
    if _review_payload_ready:
        _renderable_rows = list(_review_payload)
        _row["review_evidence_payload"] = list(_review_payload)
        _row["evidence_render_source"] = "review_payload"
        _row["commercial_evidence_mode"] = "review"
        _row["valuation_support_label"] = "REVIEW_EVIDENCE_ONLY"
    _evidence_renderable = 1 if _renderable_rows else 0
    if _truth_level in {"EXACT", "EXACT_RESCUE"}:
        _comp_count_display = int(max(0, _row.get("trusted_exact_comp_count") or len(_trusted_rows) or 0))
    elif _truth_level == "SUPPORT":
        _comp_count_display = int(max(0, _row.get("support_comp_count") or len(_support_rows) or 0))
    elif _review_payload_ready:
        _comp_count_display = 0
    elif _truth_level in {"REVIEW", "NONE"} and _evidence_renderable:
        _comp_count_display = int(len(_renderable_rows))
    else:
        _comp_count_display = 0
    _reason = "renderable_detail_rows"
    if not _evidence_renderable:
        _reason = "no_renderable_evidence"
    elif _review_payload_ready:
        _reason = "review_payload"
    elif _truth_level in {"REVIEW", "NONE"} and _fallback_rows:
        _reason = "renderable_comp_evidence"
    _row["evidence_renderable"] = int(_evidence_renderable)
    _row["comp_count_display"] = int(max(0, _comp_count_display))
    _row["renderable_evidence_rows"] = list(_renderable_rows)
    _row["renderable_evidence_count"] = int(len(_renderable_rows))
    _row["evidence_render_reason"] = _reason
    if _review_payload_ready:
        _title = str(_row.get("title") or _row.get("source_title") or "").strip()
        print(
            f"[REVIEW_EVIDENCE_ALLOW] title={_title[:120]} truth=REVIEW "
            f"target_bid={round(float(_safe_float(_row.get('target_bid') or _row.get('target_bid_price') or _row.get('bid_ceiling_value')) or 0.0), 2)} "
            f"keep=1 source=review_payload"
        )
    if _truth_level in {"REVIEW", "NONE"} and not _evidence_renderable:
        _row["comp_count_display"] = 0
    if emit_log:
        _title = str(_row.get("title") or _row.get("source_title") or "").strip()
        print(
            f"[EVIDENCE_RENDER_CONTRACT] title={_title[:120]} truth={_truth} truth_level={_truth_level} "
            f"comp_count={int(_row.get('comp_count') or 0)} detail_rows={len(_renderable_rows)} "
            f"evidence_renderable={_evidence_renderable} reason={_reason}"
        )
    return _row


def _stamp_final_surface_gate(
    row: Dict[str, Any],
    *,
    emit_log: bool = True,
) -> Dict[str, Any]:
    _row = _stamp_evidence_render_contract(dict(row or {}), emit_log=False)
    _truth = str(_row.get("_valuation_truth_tier") or _row.get("valuation_truth_tier") or "").strip().upper() or "NONE"
    _truth_level = str(_row.get("valuation_truth_level") or "").strip().upper() or "NONE"
    _evidence_renderable = int(_row.get("evidence_renderable") or 0)
    _evidence_source = str(_row.get("evidence_render_source") or "").strip()
    _trusted_exact_comp_count = int(_row.get("trusted_exact_comp_count") or 0)
    _support_comp_count = int(_row.get("support_comp_count") or 0)
    _review_surface_ok = _review_surface_evidence_ok(_row)
    _allow = 1
    _reason = "surface_allowed"
    if _truth in {"REVIEW", "NONE"} or _truth_level in {"REVIEW", "NONE"}:
        if _evidence_renderable <= 0 and _trusted_exact_comp_count <= 0 and _support_comp_count <= 0 and not _review_surface_ok:
            _allow = 0
            _reason = "no_renderable_evidence"
            _stamp_research_only_price_check(_row)
        elif _review_surface_ok:
            _allow = 1
            _reason = "review_payload"
    _customer_surface_ok = _is_customer_surface_eligible(_row)
    if not _customer_surface_ok:
        _allow = 0
        _reason = "no_verified_edge"
        _stamp_customer_surface_contract(_row, emit_log=emit_log)
    else:
        _stamp_customer_surface_contract(_row, emit_log=emit_log)
    _row["final_surface_allowed"] = int(_allow)
    _row["final_surface_reason"] = _reason
    if emit_log:
        _title = str(_row.get("title") or _row.get("source_title") or "").strip()
        print(
            f"[FINAL_SURFACE_GATE] title={_title[:120]} truth={_truth} truth_level={_truth_level} "
            f"evidence_renderable={_evidence_renderable} evidence_source={_evidence_source or 'none'} "
            f"trusted_exact_comp_count={_trusted_exact_comp_count} "
            f"support_comp_count={_support_comp_count} allow={_allow} reason={_reason}"
        )
        if not _allow:
            print(f"[WATCHLIST_SUPPRESS] title={_title[:120]} reason={_reason}")
    return _row


def _comp_truth_split_fields(row: Dict[str, Any]) -> Dict[str, Any]:
    _row = dict(row or {})
    _stamp_review_truth_class(_row, emit_log=False)
    if "identity_clean" not in _row:
        _row["identity_clean"] = bool(_is_clean_bid_identity(_row))
    _existing_exact_truth_rescued = bool(_row.get("exact_truth_rescued"))
    _existing_exact_truth_rescue_reason = str(_row.get("exact_truth_rescue_reason") or "")
    _trusted_detail_rows = _coerce_comp_detail_rows(
        _row.get("trusted_detail_rows")
    )
    _raw_exact_detail_rows = _coerce_comp_detail_rows(
        _row.get("raw_exact_detail_rows") or _row.get("exact_comps")
    )
    _support_detail_rows = _coerce_comp_detail_rows(
        _row.get("support_detail_rows") or _row.get("supporting_comps")
    )
    try:
        _raw_exact_match_count = int(
            _row.get("raw_exact_match_count")
            or _row.get("exact_comp_count")
            or len(_raw_exact_detail_rows)
            or 0
        )
    except (TypeError, ValueError):
        _raw_exact_match_count = len(_raw_exact_detail_rows)
    try:
        _trusted_exact_comp_count = int(
            _row.get("trusted_exact_comp_count")
            or len(_trusted_detail_rows)
            or 0
        )
    except (TypeError, ValueError):
        _trusted_exact_comp_count = len(_trusted_detail_rows)
    try:
        _support_comp_count = int(
            _row.get("support_comp_count")
            or len(_support_detail_rows)
            or 0
        )
    except (TypeError, ValueError):
        _support_comp_count = len(_support_detail_rows)
    _raw_exact_match_count = max(_raw_exact_match_count, len(_raw_exact_detail_rows))
    _trusted_exact_comp_count = max(_trusted_exact_comp_count, len(_trusted_detail_rows))
    _support_comp_count = max(_support_comp_count, len(_support_detail_rows))
    _true_mv = _safe_float(_row.get("true_market_value") or _row.get("market_value_true"))
    _review_estimate = _safe_float(_row.get("review_estimate_value") or _row.get("anchored_estimate_value"))
    _final_truth = str(_row.get("_valuation_truth_tier") or _row.get("valuation_truth_tier") or "").strip().upper()
    _lock_kind = str(_row.get("_mv_truth_lock_kind") or "").strip().lower()
    _review_locked = bool(_row.get("_mv_truth_locked_review")) and _lock_kind == "hard"
    _mv_true_blocked = bool(_row.get("_mv_true_blocked")) or bool(_row.get("_mv_true_block_reason"))
    _stamp_hydrated_identity_snapshot(_row, emit_log=True)
    _locator_ok, _locator_reason = _has_valid_insert_locator(_row)
    print(
        f"[INSERT_LOCATOR_CHECK] title={str((_row or {}).get('title') or '')[:160]} "
        f"ok={_locator_ok} "
        f"reason={_locator_reason} "
        f"insert_family={_row.get('_hydrated_insert_family') or _row.get('insert_family')} "
        f"parallel_family={_row.get('_hydrated_parallel_family') or _row.get('parallel_family')} "
        f"serial_denominator={_row.get('_hydrated_serial_denominator') or _row.get('serial_denominator')} "
        f"serial={_row.get('_hydrated_serial') or _row.get('serial')} "
        f"parsed_serial={_row.get('parsed_serial')} "
        f"card_number={_row.get('_hydrated_card_number') or _row.get('card_number')}"
    )
    if _locator_ok and _locator_reason != "card_number_present":
        _row["_insert_locator_override"] = True
        _row["_insert_locator_override_reason"] = _locator_reason
        print(
            f"[INSERT_LOCATOR_OVERRIDE] title={str((_row or {}).get('title') or '')[:160]} "
            f"reason={_locator_reason}"
        )
    print(
        f"[PRE_ACCELERATOR_ROW] title={str((_row or {}).get('title') or '')[:160]} "
        f"lane_type={_row.get('lane_type')} "
        f"insert_family={_row.get('insert_family')} "
        f"parallel_family={_row.get('parallel_family')} "
        f"card_number={_row.get('card_number')} "
        f"grade={_row.get('grade')} "
        f"tier={_row.get('subscription_lane_tier')} "
        f"identity_is_clean={_row.get('identity_is_clean')}"
    )
    _exact_truth_rescue_ok, _exact_truth_rescue_reason = _exact_truth_accelerator(_row)
    _serial_auto_bridge_allow, _serial_auto_bridge_reason = _premium_serial_auto_truth_bridge(_row)
    if (
        _serial_auto_bridge_allow
        and _exact_truth_rescue_reason in {"insufficient_exact_truth", "missing_subset_or_card_number"}
    ):
        _row["_premium_serial_auto_truth_bridge"] = True
        _row["_premium_serial_auto_truth_reason"] = _serial_auto_bridge_reason
        _row["surface_intent"] = str(_row.get("surface_intent") or "monitor")
        _row["_research_only_price_check"] = True
        _row["_research_only_reason"] = "premium_serial_auto_truth_bridge"
        _exact_truth_rescue_ok = True
        _exact_truth_rescue_reason = _serial_auto_bridge_reason
    _topps_black_survivor_allow, _topps_black_survivor_reason = _premium_topps_black_auto_survivor(_row)
    if _topps_black_survivor_allow and _exact_truth_rescue_reason in {"insufficient_exact_truth", "missing_subset_or_card_number"}:
        _stamp_premium_topps_black_auto_survivor(_row, _topps_black_survivor_reason)
        _exact_truth_rescue_ok = True
        _exact_truth_rescue_reason = _topps_black_survivor_reason
        if _raw_exact_match_count > 0:
            _trusted_exact_comp_count = max(_trusted_exact_comp_count, 1)
            if not _trusted_detail_rows and _raw_exact_detail_rows:
                _trusted_detail_rows = list(_raw_exact_detail_rows[:1])
        _review_locked = False
        _mv_true_blocked = False
    if _apply_identity_not_clean_truth_block(_row, stage="pre_exact_truth_rescue_bridge"):
        _exact_truth_rescue_ok = False
        _exact_truth_rescue_reason = "identity_not_clean_truth_block"
        _exact_truth_rescued = False
        _trusted_exact_comp_count = 0
        _trusted_detail_rows = []
        _final_truth = "NONE"
        _review_locked = True
        _mv_true_blocked = True
    if _apply_weak_base_truth_block(_row):
        _exact_truth_rescue_ok = False
        _exact_truth_rescue_reason = "weak_base_truth_block"
        _trusted_exact_comp_count = 0
        _trusted_detail_rows = []
        _final_truth = "REVIEW"
        _review_locked = True
        _mv_true_blocked = True
        print(
            f"[WEAK_BASE_TRUTH_ASSERT] title={str((_row or {}).get('title') or '')[:160]} "
            f"truth={_row.get('valuation_truth_tier')} "
            f"truth_level={_row.get('valuation_truth_level')} "
            f"reason=weak_base_truth_block"
        )
    if bool(_row.get("exact_rescue_perma_block")):
        _exact_truth_rescue_ok = False
        _exact_truth_rescue_reason = str(_row.get("exact_rescue_perma_block_reason") or "exact_rescue_perma_block")
        _review_locked = True
    _exact_truth_rescued = bool(_existing_exact_truth_rescued)
    if bool(_row.get("exact_rescue_perma_block")):
        _exact_truth_rescued = False
    _true_mv_rescued = None
    _exact_truth_ok = bool(
        _true_mv is not None and _true_mv > 0
        and _final_truth == "TRUE"
        and _trusted_exact_comp_count > 0
        and not _review_locked
        and not _mv_true_blocked
    )
    if _apply_identity_not_clean_truth_block(_row, stage="pre_true_mv_rescue_bridge"):
        _exact_truth_rescue_ok = False
        _exact_truth_rescue_reason = "identity_not_clean_truth_block"
        _exact_truth_rescued = False
        _exact_truth_ok = False
        _final_truth = "NONE"
        _review_locked = True
        _mv_true_blocked = True
    if (
        not _exact_truth_ok
        and _exact_truth_rescue_ok
        and _exact_truth_rescue_reason != "already_trusted"
        and not bool(_row.get("_premium_serial_auto_truth_bridge"))
        and _exact_truth_rescue_reason != "live_premium_actionable_rescue"
    ):
        _exact_truth_rescued = True
        _trusted_exact_comp_count = max(_trusted_exact_comp_count, 1)
        _final_truth = "TRUE"
        _review_locked = False
        _mv_true_blocked = False
        _true_mv_rescued = _safe_float(
            _row.get("review_estimate_value")
            or _row.get("review_estimate")
            or _row.get("market_value")
        )
        print(
            f"[EXACT_DEMOTION_BYPASSED] title={str(_row.get('title') or _row.get('source_title') or '')[:120]} "
            f"reason=exact_truth_rescue"
        )
        if _true_mv is None and _true_mv_rescued is not None and _true_mv_rescued > 0:
            print(
                f"[TRUE_MV_RESCUE_BRIDGE] title={str(_row.get('title') or _row.get('source_title') or '')[:120]} "
                f"rescued_value={round(float(_true_mv_rescued), 2)}"
            )
    _truth_level = str(_row.get("valuation_truth_level") or "").strip().upper()
    if _exact_truth_rescued:
        _truth_level = "EXACT_RESCUE"
    elif _exact_truth_ok:
        _truth_level = "EXACT"
    elif _true_mv is None and _support_comp_count > 0 and _review_estimate and _review_estimate > 0:
        _truth_level = "SUPPORT"
    elif _review_estimate and _review_estimate > 0:
        _truth_level = "REVIEW"
    else:
        _truth_level = "NONE"
    _demotion_reasons: List[str] = []
    if _raw_exact_match_count > 0 and not _exact_truth_ok and not _exact_truth_rescued:
        if _review_locked:
            _demotion_reasons.append("review_lock_hard")
        if _mv_true_blocked:
            _demotion_reasons.append(str(_row.get("_mv_true_block_reason") or "mv_true_block"))
        if _final_truth != "TRUE":
            _demotion_reasons.append(f"final_truth_{_final_truth.lower() or 'none'}")
        if not _true_mv or _true_mv <= 0:
            _demotion_reasons.append("true_mv_missing")
    # ── STRUCTURAL TRUST RESCUE ────────────────────────────────────────────
    # New rule: an exact comp (raw_exact_match_count >= 1) survives as
    # trusted whenever ALL structural keys are matched AND no explicit
    # block disagrees. The premise: if identity_is_clean is true and
    # product/insert/parallel/serial/card/player all hydrated to canonical
    # values, the exact comp is structurally provably-correct — even if
    # true_mv hasn't materialized yet. Bid logic downstream
    # (_finalize_missing_target_bid_for_survivor) handles missing anchors.
    #
    # We do NOT loosen bad comps: if any of these block flags is set, we
    # still demote.
    #   - _review_locked (hard MV truth lock, e.g. exact_rescue_perma_block,
    #     identity_not_clean_truth_block, weak_base_truth_block)
    #   - _mv_true_blocked
    #   - exact_rescue_perma_block on the row
    if (
        _raw_exact_match_count >= 1
        and not _exact_truth_ok
        and not _exact_truth_rescued
        and not _review_locked
        and not _mv_true_blocked
        and not bool(_row.get("exact_rescue_perma_block"))
    ):
        _struct_identity_clean = bool(
            _row.get("identity_is_clean")
            or _row.get("_hydrated_identity_is_clean")
            or _row.get("identity_clean")
        )
        _struct_product = str(
            _row.get("_hydrated_product_family")
            or _row.get("product_family")
            or _row.get("target_product_family")
            or ""
        ).strip().lower()
        _struct_insert = str(
            _row.get("_hydrated_insert_family")
            or _row.get("insert_family")
            or ""
        ).strip().lower()
        _struct_parallel = str(
            _row.get("_hydrated_parallel_family")
            or _row.get("parallel_family")
            or ""
        ).strip().lower()
        _struct_serial = str(
            _row.get("_hydrated_serial_denominator")
            or _row.get("serial_denominator")
            or _row.get("parsed_serial")
            or ""
        ).strip()
        _struct_card = str(
            _row.get("_hydrated_card_number")
            or _row.get("card_number")
            or ""
        ).strip()
        _struct_player = str(
            _row.get("_hydrated_player_name")
            or _row.get("player_name")
            or _row.get("clean_player")
            or _row.get("target_player_name")
            or ""
        ).strip()
        # Insert/parallel must be a real bucket (not generic base/none).
        _insert_meaningful = bool(_struct_insert) and _struct_insert not in {"base", "none", "common", ""}
        _parallel_meaningful = bool(_struct_parallel) and _struct_parallel not in {"base", "none", "common", ""}
        # Card-number is optional for autograph-style rows (often have no #).
        _is_auto_shape = _struct_insert in {"auto", "autograph", "patch_auto", "auto_patch", "patch_autograph", "rookie_auto"}
        _card_present_or_waived = bool(_struct_card) or _is_auto_shape
        _struct_complete = bool(
            _struct_identity_clean
            and _struct_product
            and _insert_meaningful
            and _parallel_meaningful
            and _struct_serial
            and _card_present_or_waived
            and _struct_player
        )
        if _struct_complete:
            _exact_truth_rescued = True
            _trusted_exact_comp_count = max(int(_trusted_exact_comp_count or 0), 1)
            if not _trusted_detail_rows and _raw_exact_detail_rows:
                _trusted_detail_rows = list(_raw_exact_detail_rows[:1])
            _final_truth = "TRUE"
            _truth_level = "EXACT_RESCUE"
            _exact_truth_rescue_reason = (
                _exact_truth_rescue_reason
                if _exact_truth_rescue_reason and _exact_truth_rescue_reason != "insufficient_exact_truth"
                else "structural_trust_rescue"
            )
            _row["_structural_trust_rescue"] = True
            _row["_structural_trust_rescue_reason"] = "all_structural_keys_match"
            _row["valuation_truth_level"] = "EXACT_RESCUE"
            print(
                f"[STRUCTURAL_TRUST_RESCUE] "
                f"title={str((_row or {}).get('title') or (_row or {}).get('source_title') or '')[:160]} "
                f"product_family={_struct_product[:48]} "
                f"insert_family={_struct_insert[:32]} "
                f"parallel_family={_struct_parallel[:32]} "
                f"serial_denominator={_struct_serial[:16]} "
                f"card_number={_struct_card[:24] or ('waived_auto' if _is_auto_shape else '')} "
                f"player={_struct_player[:48]} "
                f"identity_is_clean=1 "
                f"raw_exact_match_count={_raw_exact_match_count} "
                f"trusted_exact_after={_trusted_exact_comp_count} "
                f"prior_truth_level={_truth_level} "
                f"reason=structural_trust_rescue"
            )
            print(
                f"[STRUCTURAL_TRUST_PROMOTE] "
                f"title={str((_row or {}).get('title') or '')[:160]} "
                f"final_truth={_final_truth} "
                f"truth_level=EXACT_RESCUE "
                f"trusted_exact_comp_count={_trusted_exact_comp_count} "
                f"raw_exact_match_count={_raw_exact_match_count} "
                f"demotion_bypassed=1"
            )
        else:
            # Structural completeness audit log — emitted only when we *could*
            # have rescued but a structural key is missing. Lets us see which
            # field is the culprit so we can fix the upstream hydration.
            print(
                f"[STRUCTURAL_TRUST_REJECT] "
                f"title={str((_row or {}).get('title') or '')[:160]} "
                f"identity_is_clean={1 if _struct_identity_clean else 0} "
                f"product_ok={1 if _struct_product else 0} "
                f"insert_ok={1 if _insert_meaningful else 0} "
                f"parallel_ok={1 if _parallel_meaningful else 0} "
                f"serial_ok={1 if _struct_serial else 0} "
                f"card_ok={1 if _card_present_or_waived else 0} "
                f"player_ok={1 if _struct_player else 0} "
                f"raw_exact_match_count={_raw_exact_match_count} "
                f"reason=structural_keys_incomplete"
            )
    if _truth_level not in {"EXACT", "EXACT_RESCUE"}:
        _trusted_exact_comp_count = 0
        _trusted_detail_rows = []
    if bool(_row.get("_premium_serial_auto_truth_bridge")):
        _trusted_exact_comp_count = 0
        _trusted_detail_rows = []
        _exact_truth_rescued = False
        if _final_truth == "TRUE":
            _final_truth = "NONE"
        print(
            f"[PREMIUM_SERIAL_AUTO_TRUTH_ASSERT] "
            f"title={str((_row or {}).get('title') or '')[:160]} "
            f"final_keep=1 "
            f"final_reason={_row.get('_premium_serial_auto_truth_reason')} "
            f"surface_intent={_row.get('surface_intent')} "
            f"research_only={_row.get('_research_only_price_check')} "
            f"research_reason={_row.get('_research_only_reason')} "
            f"truth={_final_truth or _row.get('truth') or _row.get('valuation_truth_tier') or _row.get('_valuation_truth_tier')} "
            f"trusted_exact={_trusted_exact_comp_count}"
        )
    return {
        "raw_exact_match_count": int(max(0, _raw_exact_match_count)),
        "raw_exact_detail_rows": list(_raw_exact_detail_rows),
        "trusted_exact_comp_count": int(max(0, _trusted_exact_comp_count)),
        "trusted_detail_rows": list(_trusted_detail_rows),
        "support_comp_count": int(max(0, _support_comp_count)),
        "support_detail_rows": list(_support_detail_rows),
        "valuation_truth_level": _truth_level,
        "true_mv": _true_mv,
        "true_mv_rescued": _true_mv_rescued,
        "review_estimate": _review_estimate,
        "final_truth": _final_truth or "NONE",
        "exact_truth_rescued": bool(_exact_truth_rescued),
        "exact_truth_rescue_reason": (
            _existing_exact_truth_rescue_reason
            or (_exact_truth_rescue_reason if _exact_truth_rescue_ok else "insufficient_exact_truth")
        ),
        "review_lock_hard": False if _exact_truth_rescued else bool(_review_locked),
        "valid": 1 if (
            (_truth_level == "EXACT" and _exact_truth_ok)
            or (_truth_level == "EXACT_RESCUE" and _exact_truth_rescued)
            or (_truth_level == "SUPPORT" and _true_mv is None and _support_comp_count > 0 and (_review_estimate or 0) > 0)
            or (_truth_level == "REVIEW" and (_review_estimate or 0) > 0 and not _exact_truth_ok and _support_comp_count <= 0)
            or (_truth_level == "NONE")
        ) else 0,
        "reason": "|".join(_demotion_reasons) if _demotion_reasons else "ok",
        "demotion_reasons": list(dict.fromkeys(_demotion_reasons)),
    }


def _premium_active_path_stage_queries(
    row: Dict[str, Any],
    query_contract: Dict[str, Any],
) -> List[Dict[str, str]]:
    _row = dict(row or {})
    _contract = dict(query_contract or {})
    if str(_contract.get("lane_type") or "").strip().lower() != "parallel_serial":
        return []
    _player = str(_contract.get("player") or "").strip()
    _year = str(_contract.get("year") or "").strip()
    _product = str(_contract.get("product_family") or "").strip()
    _parallel = str(_contract.get("parallel_family") or "").strip()
    _serial = str(_contract.get("serial_denominator") or "").strip()
    _card = str(_contract.get("card_number") or "").strip()
    _insert = str(_contract.get("query_insert_family") or _contract.get("insert_family") or "").strip()
    _query_mode = str(_contract.get("query_mode") or "").strip().lower()
    _has_auto = bool(
        _contract.get("has_auto")
        or _row.get("query_contract_has_auto")
        or _row.get("identity_has_auto")
        or _row.get("fingerprint_has_auto")
        or _row.get("is_auto")
        or _row.get("autograph")
    )
    _product_query = _product.replace("_", " ").strip()
    _insert_query = _insert.replace("_", " ").strip()
    _parallel_query = _parallel.replace("_", " ").strip()
    _serial_query = _support_query_serial_display(_serial)
    _auto_query = "auto" if _has_auto else ""
    _grade_token = " ".join(
        [
            str(_contract.get("grade_company") or "").strip(),
            str(_contract.get("grade_value") or "").strip(),
        ]
    ).strip()
    _strict_query = str(
        _row.get("debug_search_query")
        or _row.get("query_text")
        or _row.get("primary_query")
        or ""
    ).strip()
    if not _strict_query:
        _strict_query = _recovery_query_from_parts(
            _year,
            _player,
            _product_query,
            _insert_query if _query_mode == "insert_parallel_serial" else "",
            f"#{_card}" if _card else "",
            _parallel_query,
            _serial_query,
            _auto_query,
            _grade_token,
        )
    if _query_mode == "insert_parallel_serial" and _insert_query:
        return [
            {
                "query_mode": "strict_exact",
                "phase_name": "strict_exact",
                "stage_label": "strict_insert_exact",
                "query": _strict_query,
            },
            {
                "query_mode": "exact_family",
                "phase_name": "parallel_serial_insert_family_support",
                "stage_label": "insert_family_support",
                "query": _recovery_query_from_parts(
                    _player,
                    _product_query,
                    _insert_query,
                    _parallel_query,
                ),
            },
            {
                "query_mode": "support",
                "phase_name": "parallel_serial_support",
                "stage_label": "parallel_serial_support",
                "query": _recovery_query_from_parts(
                    _player,
                    _product_query,
                    _parallel_query,
                    _serial_query,
                    _year,
                    _grade_token,
                ),
            },
        ]
    _variants = _comp_query_family_variants(_product)
    _exact_family_variant = str(_variants[1] if len(_variants) > 1 else "").strip()
    _exact_family_query = _recovery_query_from_parts(
        _year,
        _player,
        _product_query,
        _exact_family_variant,
        _parallel_query,
        _serial_query,
        _grade_token,
    )
    _support_query = _recovery_query_from_parts(
        _player,
        _product_query,
        _parallel_query,
        _serial_query,
        _year,
        _grade_token,
    )
    _stages: List[Dict[str, str]] = [
        {
            "query_mode": "strict_exact",
            "phase_name": "strict_exact",
            "stage_label": "strict_auto_exact" if _has_auto else "strict_exact",
            "query": _strict_query,
        },
    ]
    if _has_auto:
        _stages.append(
            {
                "query_mode": "exact_family",
                "phase_name": "parallel_serial_auto_family",
                "stage_label": "auto_family",
                "query": _recovery_query_from_parts(
                    _year,
                    _player,
                    _product_query,
                    _exact_family_variant,
                    _parallel_query,
                    _serial_query,
                    _auto_query,
                    _grade_token,
                ),
            }
        )
        _stages.append(
            {
                "query_mode": "support",
                "phase_name": "parallel_serial_support_auto",
                "stage_label": "parallel_serial_support",
                "query": _recovery_query_from_parts(
                    _player,
                    _product_query,
                    _parallel_query,
                    _serial_query,
                    _auto_query,
                    _year,
                    _grade_token,
                ),
            }
        )
    _stages.extend(
        [
            {
                "query_mode": "exact_family",
                "phase_name": "parallel_serial_exact_family",
                "stage_label": "exact_family_fallback",
                "query": _exact_family_query,
            },
            {
                "query_mode": "support",
                "phase_name": "parallel_serial_support",
                "stage_label": "support_fallback",
                "query": _support_query,
            },
        ]
    )
    return _stages


def _auto_query_stage_label(
    row: Dict[str, Any],
    query_contract: Optional[Dict[str, Any]] = None,
) -> str:
    _row = dict(row or {})
    _contract = dict(query_contract or {})
    _lane_type = str(
        _contract.get("lane_type")
        or _row.get("query_contract_lane_type")
        or _row.get("query_contract_mode")
        or _row.get("identity_lane_type")
        or _row.get("lane_type")
        or ""
    ).strip().lower()
    _has_auto = bool(
        _contract.get("query_has_auto")
        or _contract.get("has_auto")
        or _row.get("query_contract_has_auto")
        or _row.get("identity_has_auto")
        or _row.get("fingerprint_has_auto")
        or bool((_row.get("_final_quality_contract") or {}).get("final_has_auto"))
        or _row.get("final_has_auto")
    )
    if _lane_type != "parallel_serial" or not _has_auto:
        return ""
    _phase = str(
        _row.get("comp_support_recovery_phase")
        or _row.get("comp_recovery_phase")
        or ""
    ).strip().lower()
    if _phase == "parallel_serial_auto_family":
        return "auto_family"
    if _phase == "parallel_serial_support_auto":
        return "parallel_serial_support"
    if not _phase:
        return "strict_auto_exact"
    return ""


def _insert_query_stage_label(
    row: Dict[str, Any],
    query_contract: Optional[Dict[str, Any]] = None,
) -> str:
    _row = dict(row or {})
    _contract = dict(query_contract or {})
    _lane_type = str(
        _contract.get("lane_type")
        or _row.get("query_contract_lane_type")
        or _row.get("identity_lane_type")
        or _row.get("lane_type")
        or ""
    ).strip().lower()
    _query_mode = str(
        _contract.get("query_mode")
        or _row.get("query_contract_mode")
        or ""
    ).strip().lower()
    _insert = str(
        _contract.get("query_insert_family")
        or _contract.get("insert_family")
        or _row.get("query_contract_query_insert_family")
        or _row.get("query_contract_insert_family")
        or _row.get("identity_insert_family")
        or ""
    ).strip()
    if _lane_type != "parallel_serial" or _query_mode != "insert_parallel_serial" or not _insert:
        return ""
    _phase = str(
        _row.get("comp_support_recovery_phase")
        or _row.get("comp_recovery_phase")
        or ""
    ).strip().lower()
    if _phase == "parallel_serial_insert_family_support":
        return "insert_family_support"
    if _phase == "parallel_serial_support":
        return "parallel_serial_support"
    if not _phase:
        return "strict_insert_exact"
    return ""


def _emit_active_path_premium_comp_observability(row: Dict[str, Any]) -> Dict[str, Any]:
    _row = row if isinstance(row, dict) else dict(row or {})
    if any(
        bool(_row.get(_flag))
        for _flag in (
            "_premium_comp_callsite_active_branch_seen",
            "_premium_comp_callsite_query_emit_seen",
            "_premium_comp_callsite_query_result_seen",
            "_premium_comp_callsite_filter_death_seen",
            "_premium_comp_callsite_filter_summary_seen",
            "_premium_comp_callsite_zero_root_seen",
        )
    ):
        return {
            "emitted_any": True,
            "strict_exact_raw": int(_row.get("debug_fetched_count") or 0),
            "exact_family_raw": 0,
            "support_raw": 0,
            "strict_exact_survivors": int(_row.get("debug_accepted_count") or 0),
            "exact_family_survivors": 0,
            "support_survivors": 0,
        }
    if bool(_row.get("_premium_comp_observability_emitted")):
        return {
            "emitted_any": True,
            "strict_exact_raw": int(_row.get("_premium_comp_strict_exact_raw") or 0),
            "exact_family_raw": int(_row.get("_premium_comp_exact_family_raw") or 0),
            "support_raw": int(_row.get("_premium_comp_support_raw") or 0),
            "strict_exact_survivors": int(_row.get("_premium_comp_strict_exact_survivors") or 0),
            "exact_family_survivors": int(_row.get("_premium_comp_exact_family_survivors") or 0),
            "support_survivors": int(_row.get("_premium_comp_support_survivors") or 0),
        }
    _identity_contract = _build_clean_identity_contract(_row)
    _query_contract = _build_canonical_comp_query_contract(_row)
    if not _premium_comp_observable_row(_row, _query_contract) or not bool(_identity_contract.get("identity_is_clean")):
        return {
            "emitted_any": False,
            "strict_exact_raw": 0,
            "exact_family_raw": 0,
            "support_raw": 0,
            "strict_exact_survivors": 0,
            "exact_family_survivors": 0,
            "support_survivors": 0,
        }
    _title = str(_row.get("title") or _row.get("source_title") or "").strip()
    _trusted_exact = int(_row.get("trusted_exact_comp_count") or _row.get("exact_comp_count") or 0)
    _support = int(_row.get("support_comp_count") or 0)
    _observed_phase = str(_row.get("comp_support_recovery_phase") or _row.get("comp_recovery_phase") or "").strip().lower()
    _observed_query = str(_row.get("comp_recovery_query") or "").strip()
    _query_has_auto = bool(_query_contract.get("query_has_auto") or _query_contract.get("has_auto"))
    _query_has_insert = bool(
        str(_query_contract.get("query_mode") or "").strip().lower() == "insert_parallel_serial"
        and str(_query_contract.get("query_insert_family") or _query_contract.get("insert_family") or "").strip()
    )
    _stage_queries = _premium_active_path_stage_queries(_row, _query_contract)
    _strict_exact_raw = 0
    _exact_family_raw = 0
    _support_raw = 0
    _strict_exact_survivors = 0
    _exact_family_survivors = 0
    _support_survivors = 0
    print(
        f"[PREMIUM_COMP_ACTIVE_BRANCH] title={_title[:140]} "
        f"lane_type={str(_query_contract.get('lane_type') or '')[:24]} "
        f"identity_is_clean={1 if bool(_identity_contract.get('identity_is_clean')) else 0} "
        f"product_family={str(_query_contract.get('product_family') or '')[:64]} "
        f"parallel_family={str(_query_contract.get('parallel_family') or '')[:32]} "
        f"serial_denominator={str(_query_contract.get('serial_denominator') or '')[:12]}"
    )
    _row["_premium_comp_active_branch_seen"] = True
    for _stage in _stage_queries:
        _query_mode = str(_stage.get("query_mode") or "").strip().lower()
        _phase_name = str(_stage.get("phase_name") or "").strip().lower()
        _stage_label = str(_stage.get("stage_label") or _query_mode).strip().lower()
        _query_text = str(_stage.get("query") or "").strip()
        if _phase_name == _observed_phase and _observed_query:
            _query_text = _observed_query
        _emit_premium_comp_query_contract(_title, _query_contract, query_mode=_query_mode)
        _row["_premium_comp_query_contract_seen"] = True
        if _query_text:
            _emit_premium_comp_query_emit(_title, _query_contract, _query_text, query_mode=_query_mode)
            _row["_premium_comp_query_emit_seen"] = True
            if _query_has_auto and _stage_label in {"strict_auto_exact", "auto_family", "parallel_serial_support"}:
                print(
                    f"[AUTO_QUERY_EMIT] title={_title[:140]} stage={_stage_label} "
                    f"player={str(_query_contract.get('player') or '')[:40]} "
                    f"year={str(_query_contract.get('year') or '')} "
                    f"product_family={str(_query_contract.get('product_family') or '')[:64]} "
                    f"parallel_family={str(_query_contract.get('parallel_family') or '')[:32]} "
                    f"serial_denominator={str(_query_contract.get('serial_denominator') or '')[:12]} "
                    f"insert_family={str(_query_contract.get('insert_family') or '')[:24]} "
                    f"query={_query_text[:220]}"
                )
            if _query_has_insert and _stage_label in {"strict_insert_exact", "insert_family_support", "parallel_serial_support"}:
                print(
                    f"[INSERT_QUERY_EMIT] stage={_stage_label} "
                    f"insert_family={str(_query_contract.get('query_insert_family') or _query_contract.get('insert_family') or '')[:32]} "
                    f"query={_query_text[:220]}"
                )
        _raw_hits = 0
        _post_filter_hits = 0
        _survivors = 0
        _reason = "stage_not_observed_on_active_row"
        if _query_mode == "strict_exact":
            _raw_hits = int(_row.get("debug_fetched_count") or 0)
            _post_filter_hits = int(_row.get("debug_accepted_count") or 0)
            _survivors = _trusted_exact + _support
            _reason = str(
                _row.get("valuation_source_clean")
                or _row.get("mv_source")
                or _row.get("market_value_source")
                or _row.get("debug_rejections_top")
                or "no_hits"
            )[:96]
            _strict_exact_raw = _raw_hits
            _strict_exact_survivors = _survivors
        elif _phase_name == _observed_phase:
            _raw_hits = int(_row.get("debug_fetched_count") or 0)
            _post_filter_hits = int(_row.get("debug_accepted_count") or 0)
            _survivors = _trusted_exact + _support
            _reason = str(
                _row.get("comp_support_recovery_phase")
                or _row.get("comp_recovery_phase")
                or _row.get("valuation_source_clean")
                or _row.get("market_value_source")
                or "recovery_stage_observed"
            )[:96]
            if _query_mode == "exact_family":
                _exact_family_raw = _raw_hits
                _exact_family_survivors = _survivors
            elif _query_mode == "support":
                _support_raw = _raw_hits
                _support_survivors = _survivors
        print(
            f"[PREMIUM_COMP_QUERY_RESULT] title={_title[:140]} "
            f"query_mode={_query_mode} raw_hits={_raw_hits} "
            f"post_filter_hits={_post_filter_hits} survivors={_survivors} "
            f"reason={_reason}"
        )
        if _query_has_auto and _stage_label in {"strict_auto_exact", "auto_family", "parallel_serial_support"}:
            print(
                f"[AUTO_QUERY_RESULT] title={_title[:140]} stage={_stage_label} "
                f"raw_hits={_raw_hits} survivors={_survivors} reason={_reason}"
            )
        _row["_premium_comp_query_result_seen"] = True
        if _raw_hits > 0 and _survivors <= 0:
            _emit_premium_comp_filter_deaths(
                title=_title,
                query_mode=_query_mode,
                subject_contract=_query_contract,
                raw_hits=_raw_hits,
                survivors=_survivors,
                debug_trace=_row.get("debug_comp_trace") or _row.get("debug_rejections_top"),
                auto_stage_label=_stage_label if _query_has_auto else "",
            )
            _row["_premium_comp_filter_death_seen"] = True
    if _trusted_exact <= 0 and _support <= 0:
        _reason_blob = " ".join(
            _part
            for _part in (
                str(_row.get("debug_rejections_top") or "").strip(),
                str(_row.get("debug_comp_trace") or "").strip(),
                str(_row.get("mv_blocked_reason") or "").strip(),
                str(_row.get("review_truth_class") or "").strip(),
            )
            if _part
        )
        _zero_root = _premium_comp_zero_root_cause(
            strict_exact_raw=_strict_exact_raw,
            exact_family_raw=_exact_family_raw,
            support_raw=_support_raw,
            strict_exact_survivors=_strict_exact_survivors,
            exact_family_survivors=_exact_family_survivors,
            support_survivors=_support_survivors,
            reason_blob=_reason_blob,
        )
        print(
            f"[PREMIUM_COMP_ZERO_ROOT] title={_title[:140]} "
            f"strict_exact_raw={_strict_exact_raw} exact_family_raw={_exact_family_raw} support_raw={_support_raw} "
            f"strict_exact_survivors={_strict_exact_survivors} exact_family_survivors={_exact_family_survivors} support_survivors={_support_survivors} "
            f"root_cause={_zero_root}"
        )
        _row["_premium_comp_zero_root_seen"] = True
    _row["_premium_comp_observability_emitted"] = True
    _row["_premium_comp_strict_exact_raw"] = int(_strict_exact_raw)
    _row["_premium_comp_exact_family_raw"] = int(_exact_family_raw)
    _row["_premium_comp_support_raw"] = int(_support_raw)
    _row["_premium_comp_strict_exact_survivors"] = int(_strict_exact_survivors)
    _row["_premium_comp_exact_family_survivors"] = int(_exact_family_survivors)
    _row["_premium_comp_support_survivors"] = int(_support_survivors)
    return {
        "emitted_any": True,
        "strict_exact_raw": int(_strict_exact_raw),
        "exact_family_raw": int(_exact_family_raw),
        "support_raw": int(_support_raw),
        "strict_exact_survivors": int(_strict_exact_survivors),
        "exact_family_survivors": int(_exact_family_survivors),
        "support_survivors": int(_support_survivors),
    }


def _stamp_comp_truth_split(
    row: Dict[str, Any],
    *,
    emit_log: bool = True,
) -> Dict[str, Any]:
    _row = row if isinstance(row, dict) else dict(row or {})
    if _apply_fake_serial_base_promo_hard_block(_row, stage="comp_truth_split", final_true_allowed=0):
        return _row
    _active_obs = _emit_active_path_premium_comp_observability(_row)
    _split = _comp_truth_split_fields(_row)
    _row["raw_exact_match_count"] = int(_split["raw_exact_match_count"])
    _row["raw_exact_detail_rows"] = list(_split["raw_exact_detail_rows"])
    _row["trusted_exact_comp_count"] = int(_split["trusted_exact_comp_count"])
    _row["trusted_detail_rows"] = list(_split["trusted_detail_rows"])
    _row["support_comp_count"] = int(_split["support_comp_count"])
    _row["support_detail_rows"] = list(_split["support_detail_rows"])
    _row["valuation_truth_level"] = str(_split["valuation_truth_level"] or "NONE")
    _row["exact_comp_count"] = int(_split["trusted_exact_comp_count"])
    _row["exact_truth_rescued"] = bool(_split.get("exact_truth_rescued"))
    _row["exact_truth_rescue_reason"] = str(_split.get("exact_truth_rescue_reason") or "")
    _row["review_lock_hard"] = bool(_split.get("review_lock_hard"))
    _row["_review_lock_hard"] = bool(_split.get("review_lock_hard"))
    if (
        (bool(_row.get("_parallel_serial_locator_override")) or bool(_row.get("_insert_locator_override")))
        and str(_row.get("exact_rescue_perma_block_reason") or "").strip() == "missing_subset_or_card_number"
    ):
        _row["exact_rescue_perma_block"] = False
        _row["exact_rescue_perma_block_reason"] = ""
        _row["review_lock_hard"] = False
        _row["_review_lock_hard"] = False
        _row["_mv_truth_locked_review"] = False
        _row["_mv_truth_lock_kind"] = ""
        _row["_mv_truth_lock_reason"] = ""
        _override_reason = (
            "parallel_serial_locator_override"
            if bool(_row.get("_parallel_serial_locator_override"))
            else "valid_insert_locator_override"
        )
        print(
            f"[REVIEW_LOCK_OVERRIDE] title={str((_row or {}).get('title') or '')[:160]} "
            f"reason={_override_reason}"
        )
    if bool(_row.get("exact_rescue_perma_block")):
        _row["exact_truth_rescued"] = False
        _row["review_lock_hard"] = True
        _row["_review_lock_hard"] = True
        _row["_mv_truth_locked_review"] = True
        _row["_mv_truth_lock_kind"] = "hard"
        if not str(_row.get("_mv_truth_lock_reason") or "").strip():
            _row["_mv_truth_lock_reason"] = str(_row.get("exact_rescue_perma_block_reason") or "exact_rescue_perma_block")
        _row["valuation_truth_level"] = "REVIEW_LOCKED"
    if bool(_split.get("exact_truth_rescued")) and not bool(_row.get("exact_rescue_perma_block")):
        _row["valuation_truth_tier"] = "TRUE"
        _row["_valuation_truth_tier"] = "TRUE"
        _row["review_lock_hard"] = False
        _row["_review_lock_hard"] = False
        _row["_mv_truth_locked_review"] = False
        if _split.get("true_mv_rescued") is not None and float(_split.get("true_mv_rescued") or 0.0) > 0:
            _row["true_mv_rescued"] = round(float(_split.get("true_mv_rescued") or 0.0), 2)
    _stamp_review_truth_class(_row, emit_log=False)
    if _split["raw_exact_match_count"] > 0:
        print(
            f"[EXACT_TRUST_SPLIT] title={str(_row.get('title') or _row.get('source_title') or '')[:120]} "
            f"raw_exact_match_count={_split['raw_exact_match_count']} "
            f"trusted_exact_comp_count={_split['trusted_exact_comp_count']} "
            f"demoted={max(0, int(_split['raw_exact_match_count']) - int(_split['trusted_exact_comp_count']))} "
            f"reasons={_split.get('demotion_reasons') or []}"
        )
    if emit_log:
        _title = str(_row.get("title") or _row.get("source_title") or "").strip()
        print(
            f"[VALUATION_TRUTH_SPLIT] title={_title[:120]} "
            f"truth_level={_row.get('valuation_truth_level') or 'NONE'} "
            f"true_mv={round(float(_split['true_mv']), 2) if _split['true_mv'] and _split['true_mv'] > 0 else None} "
            f"review_estimate={round(float(_split['review_estimate']), 2) if _split['review_estimate'] and _split['review_estimate'] > 0 else None} "
            f"trusted_exact_comp_count={_row.get('trusted_exact_comp_count') or 0} "
            f"support_comp_count={_row.get('support_comp_count') or 0}"
        )
        print(
            f"[TRUTH_CONTRACT_ASSERT] title={_title[:120]} truth={_split.get('final_truth') or 'NONE'} "
            f"truth_level={_row.get('valuation_truth_level') or 'NONE'} "
            f"true_mv={round(float(_split['true_mv']), 2) if _split['true_mv'] and _split['true_mv'] > 0 else None} "
            f"review_estimate={round(float(_split['review_estimate']), 2) if _split['review_estimate'] and _split['review_estimate'] > 0 else None} "
            f"raw_exact_match_count={_row.get('raw_exact_match_count') or 0} "
            f"trusted_exact_comp_count={_row.get('trusted_exact_comp_count') or 0} "
            f"support_comp_count={_row.get('support_comp_count') or 0} "
            f"valid={_split.get('valid') or 0} reason={_split.get('reason') or 'ok'}"
        )
        _assert_query_contract = _build_canonical_comp_query_contract(_row)
        _assert_identity = _build_clean_identity_contract(_row)
        _should_assert = bool(
            _premium_comp_observable_row(_row, _assert_query_contract)
            and bool(_assert_identity.get("identity_is_clean"))
            and str(_row.get("valuation_truth_level") or "").strip().upper() == "REVIEW"
            and int(_row.get("trusted_exact_comp_count") or 0) <= 0
            and int(_row.get("support_comp_count") or 0) <= 0
        )
        _obs_seen = any(
            bool(_row.get(_flag))
            for _flag in (
                "_premium_comp_active_branch_seen",
                "_premium_comp_query_contract_seen",
                "_premium_comp_query_emit_seen",
                "_premium_comp_query_result_seen",
                "_premium_comp_filter_death_seen",
                "_premium_comp_zero_root_seen",
            )
        ) or bool(_active_obs.get("emitted_any"))
        if _should_assert and not _obs_seen:
            print(
                f"[PREMIUM_COMP_OBSERVABILITY_ASSERT] title={_title[:140]} "
                f"reason=active_path_missing_comp_logs"
            )
    return _row


def _safe_fallback_mv(comps: List[Dict[str, Any]], price: Optional[float]) -> Optional[Dict[str, Any]]:
    if not comps:
        return None

    values = [_safe_float(c.get("price")) for c in comps if isinstance(c, dict)]
    values = sorted(v for v in values if v)
    if not values:
        return None

    n = len(values)
    trim = max(1, int(n * 0.2))
    core = values[trim:-trim] if n > 5 else values
    if not core:
        core = values

    mv = sum(core) / len(core)
    return {
        "market_value": round(mv, 2),
        "confidence": "MEDIUM" if n >= 5 else "LOW",
        "comps_used": len(core),
        "source": "structured_fallback",
    }


# ── Valuation authority stack ─────────────────────────────────────────────────
# Lower number = stronger/more trusted. 9 = unknown/unresolved.
# A weaker source (higher number) must NEVER overwrite a stronger source (lower number).
_VALUATION_SOURCE_RANK: Dict[str, int] = {
    # Tier 1 — exact same-card / exact lane comp engine
    "exact_comp_engine":              1,
    "scarcity_aligned_comp_engine":   1,
    # Tier 2 — hybrid strict / strong exact comp result
    "strong_comp_engine":             2,
    "scarcity_supported_comp_engine": 2,
    # Tier 3 — medium comp engine / scarcity fallback
    "medium_comp_engine":             3,
    "scarcity_fallback":              3,
    # Tier 4 — fallback comp support (hybrid value preserved, weaker lane)
    "fallback_comp_support":          4,
    "single_comp_conservative":       4,
    "hybrid_near_lane":               4,
    "near_family_support":            4,
    "premium_scarcity_bucket_support": 4,
    # Tier 5 — structured fallback / price anchors (weakest real value)
    "structured_fallback":            5,
    "soft_watchlist_estimate":        5,
    "common_card_review_clamp":       5,
    # Tier 6 — pure price anchors (no comp evidence)
    "price_anchor_fallback":          6,
    "price_anchor_emergency":         6,
    "floor_fallback":                 6,
    # Unresolved / error
    "none":                           9,
    "error":                          9,
    "unresolved":                     9,
    "listing_type_excluded":          9,
}


def _valuation_source_rank(source: str) -> int:
    """Lower number = stronger/more trusted. 9 = unknown. Used to block weaker overwrites."""
    return int(_VALUATION_SOURCE_RANK.get(str(source or "").strip().lower(), 9))


def _should_preserve_existing_valuation(existing_source: str, new_source: str) -> bool:
    """Return True if existing_source is at least as strong as new_source (block the overwrite)."""
    return _valuation_source_rank(existing_source) <= _valuation_source_rank(new_source)


_MV_ANCHOR_ONLY_SOURCES: frozenset = frozenset({
    "price_anchor_fallback",
    "price_anchor_emergency",
    "floor_fallback",
})
_MV_NON_TRUE_SOURCES: frozenset = frozenset({
    "none",
    "error",
    "unresolved",
    "listing_type_excluded",
    "legacy_comp_engine",
    "common_card_review_clamp",
    "exact_required_fail",
    "structured_fallback",
    "fallback_comp_support",
})


def _resolve_mv_truth_fields(
    mv_value: Any,
    source: Any,
    comp_count: Any,
) -> Tuple[Optional[float], Optional[float]]:
    _mv = _safe_float(mv_value)
    _source = str(source or "").strip().lower()
    try:
        _comp_count = int(comp_count or 0)
    except (TypeError, ValueError):
        _comp_count = 0
    if not _mv or _mv <= 0:
        return None, None
    if _source in {"structured_fallback", "fallback_comp_support"}:
        return None, round(_mv, 2)
    if _source in {"price_anchor_fallback", "price_anchor_emergency"}:
        return None, round(_mv, 2)
    if _comp_count > 0 and _source not in _MV_NON_TRUE_SOURCES and _source not in _MV_ANCHOR_ONLY_SOURCES:
        return round(_mv, 2), None
    return None, None


def _valuation_source_clean(row: Dict[str, Any]) -> str:
    return str(
        (row or {}).get("mv_source")
        or (row or {}).get("market_value_source")
        or (row or {}).get("valuation_source")
        or (row or {}).get("valuation_basis")
        or ""
    ).strip().lower()


def _has_true_market_value(row: dict) -> bool:
    _row = dict(row or {})
    _true_mv = _safe_float(_row.get("true_market_value"))
    if bool(_row.get("exact_truth_rescued")) and _true_mv is not None and _true_mv > 0:
        return True
    _source = _valuation_source_clean(_row)
    _comp_count = _row.get("usable_comp_count")
    if _comp_count is None:
        _comp_count = _row.get("comp_count")
    try:
        _comp_count = int(_comp_count or 0)
    except Exception:
        _comp_count = 0
    if _source in {"soft_watchlist_estimate", "price_anchor_fallback", "anchor_only", "review_estimate", "structured_fallback", "fallback_comp_support"}:
        return False
    _support_profile = _support_truth_profile(_row)
    if bool(_support_profile.get("is_support_source")) and not bool(_support_profile.get("support_truth_true")):
        return False
    return bool(_true_mv is not None and _true_mv > 0)


def _resolve_review_estimate(row: dict):
    _row = dict(row or {})
    for _key in [
        "review_estimate_value",
        "anchored_estimate_value",
        "market_value",
        "market_value_true",
        "estimated_value",
        "display_value",
        "market_value_raw",
        "mv_value",
    ]:
        _value = _row.get(_key)
        try:
            if _value is not None:
                _num = float(_value)
                if _num > 0:
                    return _num
        except Exception:
            pass
    return None


def _looks_like_current_price_clone(row: dict) -> bool:
    _row = dict(row or {})
    try:
        _cp = float(_row.get("current_price"))
    except Exception:
        return False
    _candidate = _row.get("true_market_value")
    try:
        _mv = float(_candidate) if _candidate is not None else None
    except Exception:
        _mv = None
    if _mv is None:
        return False
    return abs(_cp - _mv) < 0.01 and _valuation_source_clean(_row) in {
        "soft_watchlist_estimate",
        "price_anchor_fallback",
        "anchor_only",
        "review_estimate",
    }


_SUPPORT_TRUTH_SOURCES: frozenset = frozenset({
    "near_family_support",
    "premium_scarcity_bucket_support",
    "hybrid_near_lane",
    "fallback_comp_support",
    "single_comp_conservative",
})


def _support_truth_profile(row: Dict[str, Any]) -> Dict[str, Any]:
    _row = row or {}
    _source = _valuation_source_clean(_row)
    _is_support = _source in _SUPPORT_TRUTH_SOURCES
    try:
        _comp_count = int(_row.get("mv_comp_count") or _row.get("comp_count") or 0)
    except (TypeError, ValueError):
        _comp_count = 0
    try:
        _lane_comp_count = int(_row.get("market_lane_comp_count") or _row.get("lane_comp_count") or 0)
    except (TypeError, ValueError):
        _lane_comp_count = 0
    try:
        _strict_comp_count = int(_row.get("strict_comp_count") or _row.get("operator_exact_kept") or 0)
    except (TypeError, ValueError):
        _strict_comp_count = 0
    try:
        _family_recovery_count = int(_row.get("comp_family_recovery_count") or 0)
    except (TypeError, ValueError):
        _family_recovery_count = 0
    _confidence = _normalize_mv_confidence_label(
        _row.get("mv_confidence_strict")
        or _row.get("valuation_confidence")
        or _row.get("confidence")
        or _row.get("mv_confidence")
        or ""
    )
    _range_low = _safe_float(_row.get("value_range_low"))
    _range_high = _safe_float(_row.get("value_range_high"))
    _dispersion: Optional[float] = None
    if _range_low is not None and _range_high is not None and _range_low > 0 and _range_high > 0:
        _center = (_range_low * 0.55) + (_range_high * 0.45)
        if _center > 0:
            _dispersion = (_range_high - _range_low) / max(_center, 0.01)
    _has_identity = bool(
        str(_row.get("fingerprint_product") or _row.get("product_family") or _row.get("target_product_family") or "").strip()
        and (
            str(_row.get("fingerprint_card_number") or _row.get("card_number") or "").strip()
            or str(_row.get("fingerprint_subset") or _row.get("subset_name") or "").strip()
        )
    )
    _bucket = str(_row.get("parallel_bucket") or _row.get("parallel_name") or _row.get("serial_bucket") or "").strip()
    _subtype = _same_card_subtype_bucket(str(_row.get("title") or _row.get("source_title") or ""))
    _alignment_hits = 0
    _family_alignment_score = 0
    if str(_row.get("fingerprint_product") or _row.get("product_family") or _row.get("target_product_family") or "").strip():
        _family_alignment_score += 1
    if str(_row.get("fingerprint_card_number") or _row.get("card_number") or "").strip():
        _family_alignment_score += 2
        _alignment_hits += 1
    elif str(_row.get("fingerprint_subset") or _row.get("subset_name") or "").strip():
        _family_alignment_score += 2
        _alignment_hits += 1
    if _bucket:
        _family_alignment_score += 1
    if _lane_comp_count >= 2:
        _family_alignment_score += 2
        _alignment_hits += 1
    elif _lane_comp_count >= 1:
        _family_alignment_score += 1
    if _strict_comp_count >= 1:
        _family_alignment_score += 1
        _alignment_hits += 1
    if _family_recovery_count >= 2:
        _family_alignment_score += 1
        _alignment_hits += 1
    if _has_identity:
        _family_alignment_score += 1
    if _subtype != "other":
        _family_alignment_score += 1
    if bool(_row.get("memorabilia_junk")):
        _family_alignment_score -= 4

    _dispersion_band = "na"
    if _dispersion is None:
        _dispersion_band = "na"
    elif _dispersion > 1.35:
        _dispersion_band = "extreme"
    elif _dispersion > 1.10:
        _dispersion_band = "wide"
    else:
        _dispersion_band = "normal"

    _should_true = False
    _should_true_tier = ""  # which branch triggered approval
    if _is_support and _confidence in {"MEDIUM", "HIGH"} and _family_alignment_score >= 4:
        if _comp_count >= 5 and _alignment_hits >= 2 and (_dispersion is None or _dispersion <= 1.35):
            _should_true = True
            _should_true_tier = "tier_a:comps5_hits2"
        elif _comp_count >= 4 and _family_alignment_score >= 4 and _alignment_hits >= 1 and (_dispersion is None or _dispersion <= 1.12):
            # ── GAP FIX: 4-comp pool with positive alignment (≥1 structural hit) ──
            # Covers Caleb-style: score=4, hits=1, comps=4, dispersion normal.
            # Requires at least one structural identity hit (card_number or subset).
            _should_true = True
            _should_true_tier = "tier_b:comps4_hits1"
        elif _comp_count >= 3 and _family_alignment_score >= 5 and _alignment_hits >= 2 and (_dispersion is None or _dispersion <= 1.12):
            _should_true = True
            _should_true_tier = "tier_c:comps3_score5_hits2"
        elif _comp_count == 2 and _family_alignment_score >= 6 and _lane_comp_count >= 2 and _confidence == "HIGH" and (_dispersion is None or _dispersion <= 0.78):
            _should_true = True
            _should_true_tier = "tier_d:comps2_high_conf"

    # ── TIER E: near-family relaxed promotion ────────────────────────────────────
    # Fires when the source is a genuine near-family comp (not a fallback),
    # ≥3 comps exist, confidence is MEDIUM/HIGH, but no exact lane match produced
    # lane_comps. In real card markets near-family comps on MEDIUM/HIGH are actionable.
    # Explicitly blocked: structured_fallback, price_anchor_fallback, fallback_comp_support.
    # A 10% safety haircut is flagged for callers via near_family_haircut=True.
    _NEAR_FAMILY_PROMOTE_SOURCES: frozenset = frozenset({
        "near_family_support", "premium_scarcity_bucket_support", "hybrid_near_lane"
    })
    if (
        not _should_true
        and _is_support
        and _source in _NEAR_FAMILY_PROMOTE_SOURCES
        and _comp_count >= 3
        and _confidence in {"MEDIUM", "HIGH"}
        and _lane_comp_count == 0
        and (_dispersion is None or _dispersion <= 1.35)
    ):
        _should_true = True
        _should_true_tier = "tier_e:near_family_3comps"
        print(
            f"[NEAR_FAMILY_PROMOTE] source={_source} comps={_comp_count} "
            f"conf={_confidence} score={_family_alignment_score} hits={_alignment_hits} "
            f"lane_comps={_lane_comp_count} disp={_dispersion_band} → tier_e promoted"
        )

    # ── PRECISE REASON ASSIGNMENT ──────────────────────────────────────────────
    # Distinguish "score was actually 0/negative" from "score was positive but
    # didn't reach the approval threshold". The old catch-all support_alignment_too_weak
    # covered both, producing contradictions in logs (score=4 + reason=too_weak).
    _reason = "not_support_source"
    if _is_support:
        if _comp_count < 2:
            _reason = f"thin_support_pool:{_comp_count}"
        elif _dispersion is not None and _dispersion > 1.35:
            _reason = f"support_dispersion_extreme:{_dispersion:.2f}"
        elif _comp_count == 2 and _should_true:
            _reason = "two_comp_high_alignment_support"
        elif _comp_count == 2:
            _reason = f"two_comp_review_support:align={_family_alignment_score}"
        elif _comp_count >= 3 and _should_true:
            _reason = f"aligned_premium_support:{_should_true_tier}"
        elif _confidence not in {"MEDIUM", "HIGH"}:
            _reason = f"low_support_conf:{_confidence.lower()}"
        elif _family_alignment_score <= 0:
            # Alignment truly absent — no product/card/lane signal at all
            _reason = "support_alignment_zero"
        elif _alignment_hits == 0 and _family_alignment_score > 0:
            # Score came from product/bucket weak signals only; no structural identity hit
            _reason = f"support_no_structural_hits:score={_family_alignment_score}"
        elif _alignment_hits >= 1 and _family_alignment_score >= 4 and _comp_count >= 3:
            # Has positive alignment score AND a structural hit AND enough comps —
            # only failing because dispersion is wide, not because alignment is absent
            _reason = f"support_review_band:{_dispersion_band}:score={_family_alignment_score}:hits={_alignment_hits}"
        elif _alignment_hits >= 1 and _family_alignment_score >= 4:
            # Score and hits present but comp pool still thin (2-3 comps) for this tier
            _reason = f"support_thin_for_single_hit:comps={_comp_count}:score={_family_alignment_score}"
        elif _alignment_hits < 2 and _family_alignment_score < 5:
            # Both hits and score below the multi-hit threshold — alignment is genuinely weak
            _reason = f"support_alignment_too_weak:score={_family_alignment_score}:hits={_alignment_hits}"
        else:
            _reason = f"support_review_band:{_dispersion_band}"

    # ── STRUCTURED DECISION LOG ────────────────────────────────────────────────
    print(
        f"[SUPPORT_TRUTH_DECISION] source={_is_support} score={_family_alignment_score} "
        f"hits={_alignment_hits} comps={_comp_count} lane_comps={_lane_comp_count} "
        f"conf={_confidence} disp={_dispersion_band} "
        f"should_true={_should_true} tier={_should_true_tier or 'none'} reason={_reason}"
    )
    return {
        "is_support_source": _is_support,
        "support_truth_true": _should_true,
        "support_truth_tier": "STRONG_SUPPORT" if _should_true else ("REVIEW_SUPPORT" if _is_support else "EXACT_OR_NON_SUPPORT"),
        "reason": _reason,
        "should_true_tier": _should_true_tier,
        "comp_count": _comp_count,
        "lane_comp_count": _lane_comp_count,
        "strict_comp_count": _strict_comp_count,
        "family_recovery_count": _family_recovery_count,
        "confidence": _confidence,
        "dispersion": _dispersion,
        "alignment_hits": _alignment_hits,
        "family_alignment_score": _family_alignment_score,
        "dispersion_band": _dispersion_band,
        "near_family_haircut": bool(_should_true_tier and _should_true_tier.startswith("tier_e")),
    }


def _review_lock_kind(row: Dict[str, Any], source: str = "") -> str:
    _row = row or {}
    if not bool(_row.get("_mv_truth_locked_review")):
        return ""
    _kind = str(_row.get("_mv_truth_lock_kind") or "").strip().lower()
    if _kind in {"hard", "soft"}:
        return _kind
    _source = str(source or _valuation_source_clean(_row)).strip().lower()
    if _source in {
        "structured_fallback",
        "fallback",
        "fallback_comp_support",
        "structured_review",
        "fallback_review",
        "price_anchor_fallback",
        "price_anchor_emergency",
        "floor_fallback",
    }:
        return "hard"
    if bool(_row.get("_same_card_downgraded")) or bool(_row.get("memorabilia_junk")):
        return "hard"
    return "soft"


def _support_truth_can_upgrade_locked_review(
    row: Dict[str, Any],
    support_profile: Dict[str, Any],
    source: str = "",
) -> bool:
    _row = row or {}
    _profile = support_profile or {}
    _source = str(source or _valuation_source_clean(_row)).strip().lower()
    if _review_lock_kind(_row, _source) != "soft":
        return False
    if _source in {
        "structured_fallback",
        "fallback",
        "fallback_comp_support",
        "structured_review",
        "fallback_review",
        "price_anchor_fallback",
        "price_anchor_emergency",
        "floor_fallback",
    }:
        return False
    if bool(_row.get("_same_card_downgraded")) or bool(_row.get("memorabilia_junk")):
        return False
    if not bool(_profile.get("is_support_source")) or not bool(_profile.get("support_truth_true")):
        return False
    if str(_profile.get("dispersion_band") or "").strip().lower() == "extreme":
        return False
    _comp_count = int(_profile.get("comp_count") or 0)
    _tier = str(_profile.get("should_true_tier") or "").strip().lower()
    # ── TIER E: near-family relaxed unlock ──────────────────────────────────────
    # Near-family promotion bypasses the alignment score and hits gates — source
    # quality and comp count are the guarantees here, not structural identity.
    if _tier.startswith("tier_e"):
        return _comp_count >= 3 and str(_profile.get("dispersion_band") or "").lower() != "extreme"
    # ── Standard alignment gates (tiers A-D) ───────────────────────────────────
    if int(_profile.get("alignment_hits") or 0) <= 0:
        return False
    if int(_profile.get("family_alignment_score") or 0) < 4:
        return False
    if _comp_count >= 3:
        return True
    return _comp_count == 2 and _tier == "tier_d:comps2_high_conf"


def _should_clear_review_lock(
    row: Dict[str, Any],
    support_profile: Dict[str, Any],
    source: str = "",
) -> bool:
    return _support_truth_can_upgrade_locked_review(row, support_profile, source)


def _get_final_display_anchor(row: Dict[str, Any]) -> Tuple[Optional[float], str]:
    _row = row or {}
    _truth = str(_row.get("_valuation_truth_tier") or _row.get("valuation_truth_tier") or "").strip().upper()
    _true_mv = _safe_float(_row.get("true_market_value") or _row.get("market_value_true"))
    _review_mv = _safe_float(_row.get("review_estimate_value"))
    if _truth == "TRUE" and _true_mv and _true_mv > 0:
        return round(float(_true_mv), 2), "true_market_value"
    if _truth == "REVIEW" and _review_mv and _review_mv > 0:
        return round(float(_review_mv), 2), "review_estimate"
    return None, "none"


def _get_final_bid_anchor(row: Dict[str, Any]) -> Tuple[Optional[float], str]:
    return _get_final_display_anchor(row)


def _compute_final_target_bid_from_anchor(row: Dict[str, Any], anchor_value: Optional[float], anchor_mode: str) -> Tuple[Optional[float], str, str]:
    if anchor_value is None or anchor_value <= 0:
        return None, "none", "none"
    _row = dict(row or {})
    _row["market_value"] = round(float(anchor_value), 2)
    _row["mv_value"] = round(float(anchor_value), 2)
    _row["mv"] = round(float(anchor_value), 2)
    if anchor_mode == "review_estimate":
        _row["valuation_confidence"] = str(_row.get("valuation_confidence") or _row.get("mv_confidence_strict") or "LOW").upper()
        _row["confidence"] = str(_row.get("confidence") or _row.get("valuation_confidence") or "LOW").upper()
        _row["mv_source"] = str(_row.get("valuation_source_clean") or _row.get("mv_source") or _row.get("market_value_source") or "review_estimate")
        _row["market_value_source"] = _row["mv_source"]
    _bid, _mode = _build_provisional_target_bid(_row)
    if _bid is not None and _bid > 0:
        return round(float(_bid), 2), _mode, anchor_mode
    if anchor_mode == "review_estimate":
        return round(float(anchor_value) * 0.64, 2), "review_ceiling", anchor_mode
    _conf = _normalize_mv_confidence_label(
        _row.get("mv_confidence_strict")
        or _row.get("valuation_confidence")
        or _row.get("confidence")
        or ""
    )
    _pct = 0.82 if _conf == "HIGH" else 0.74 if _conf == "MEDIUM" else 0.64
    return round(float(anchor_value) * _pct, 2), ("strict" if _conf == "HIGH" else "median_discount" if _conf == "MEDIUM" else "review_ceiling"), anchor_mode


def _collect_trusted_comp_floor(row: Dict[str, Any]) -> Tuple[Optional[float], int, str]:
    """
    Walk the row's existing trusted-comp evidence and return
    (floor_value, price_count, reason).

    floor_value is the MIN of all positive comp prices found across the
    same evidence keys _exact_comp_value_rescue trusts. The floor is the
    most conservative anchor for a target_bid fallback — bidding off the
    minimum observed sale guarantees we never bid above what the market
    has actually paid for an exact comp.

    Returns (None, 0, reason) when no usable comp price can be found, so
    the caller can decide whether to bail or escalate.
    """
    try:
        if not isinstance(row, dict):
            return None, 0, "not_dict"
        _candidate_prices: List[float] = []

        def _try_add(_value: Any) -> None:
            _pv = _safe_float(_value)
            if isinstance(_pv, (int, float)) and float(_pv) > 0:
                _candidate_prices.append(float(_pv))
                return
            try:
                if _value not in (None, "", "?"):
                    _pv2 = float(str(_value).replace("$", "").replace(",", "").strip())
                    if _pv2 > 0:
                        _candidate_prices.append(float(_pv2))
            except Exception:
                return

        # Same evidence-row keys _exact_comp_value_rescue trusts. Order
        # preserved so logs stay diff-friendly with the existing rescue.
        for _ev_key in (
            "renderable_evidence_rows",
            "evidence_rows",
            "comp_rows",
            "review_evidence_rows",
            "exact_comp_rows",
            "exact_match_rows",
            "support_rows",
        ):
            _ev_rows = row.get(_ev_key)
            if not isinstance(_ev_rows, list):
                continue
            for _ev in _ev_rows:
                if not isinstance(_ev, dict):
                    continue
                for _price_key in ("sold_price", "price", "comp_price", "amount", "sale_price"):
                    _try_add(_ev.get(_price_key))

        # Top-level scalar comp price hints — last resort, since these are
        # often medians/displays rather than raw observed sales.
        for _scalar_key in (
            "exact_comp_price",
            "exact_price",
            "best_exact_price",
            "trusted_exact_price",
            "review_anchor_value",
            "display_value",
            "reference_value",
        ):
            _try_add(row.get(_scalar_key))

        _positive = sorted(float(_p) for _p in _candidate_prices if isinstance(_p, (int, float)) and float(_p) > 0)
        if not _positive:
            return None, 0, "no_trusted_comp_prices"
        _floor = float(_positive[0])  # min = most conservative floor
        return _floor, len(_positive), "min_of_trusted_comps"
    except Exception as _e:
        return None, 0, f"error:{type(_e).__name__}"


def _finalize_missing_target_bid_for_survivor(row):
    """
    If row is premium/clean and has review_estimate or true_mv,
    compute target_bid from final bid anchor logic.
    """
    try:
        if not isinstance(row, dict):
            return False
        _title = str(row.get("title") or row.get("source_title") or "").strip()
        _identity_is_clean = bool(row.get("identity_is_clean") or row.get("_hydrated_identity_is_clean"))
        _old_target_bid = _safe_float(row.get("target_bid") or row.get("target_bid_price") or row.get("bid_ceiling_value"))
        if not _identity_is_clean or _old_target_bid is not None:
            return False
        _premium = bool(
            row.get("premium_lane")
            or row.get("_premium_insert_parallel")
            or row.get("premium_signal")
            or row.get("promoted_live_candidate")
            or _title_has_premium_signal(_title)
            or _is_commercial_listing(row)
        )
        if not _premium:
            return False
        _truth = str(row.get("truth") or row.get("valuation_truth_tier") or row.get("_valuation_truth_tier") or "").strip().upper()
        _true_mv = _safe_float(row.get("true_mv") or row.get("true_market_value") or row.get("market_value_true"))
        _review_estimate = _safe_float(
            row.get("review_estimate")
            or row.get("review_estimate_value")
            or row.get("anchored_estimate_value")
            or row.get("market_value_raw")
        )
        if _true_mv is None and _review_estimate is None:
            # ── PREMIUM EXACT-TRUTH TARGET-BID RECOVERY ─────────────────────
            # Both anchors missing. Before bailing, check whether this row is
            # the premium/exact-truth shape we promised to keep actionable:
            #   trusted_exact >= 1  AND  truth=TRUE  AND  identity_is_clean=1
            #   AND  premium_lane=1
            # If so, derive a fallback target_bid from the trusted-comp floor
            # (the lowest trusted comp price the row already carries) times a
            # configurable discount (env TARGET_BID_TRUSTED_FLOOR_DISCOUNT,
            # default 0.64 — same factor used by review_ceiling).
            try:
                _trusted_exact_recovery = int(row.get("trusted_exact_comp_count") or 0)
            except Exception:
                _trusted_exact_recovery = 0
            _premium_lane_recovery = bool(row.get("premium_lane"))
            _qualifies_recovery = bool(
                _trusted_exact_recovery >= 1
                and _truth == "TRUE"
                and _identity_is_clean
                and _premium_lane_recovery
            )
            print(
                f"[TARGET_BID_FAILURE] "
                f"title={_title[:160]} "
                f"truth={_truth} "
                f"trusted_exact={_trusted_exact_recovery} "
                f"identity_is_clean={1 if _identity_is_clean else 0} "
                f"premium_lane={1 if _premium_lane_recovery else 0} "
                f"true_mv=None review_estimate=None "
                f"qualifies_recovery={1 if _qualifies_recovery else 0} "
                f"reason=both_anchors_missing"
            )
            if not _qualifies_recovery:
                return False
            _floor_value, _floor_count, _floor_reason = _collect_trusted_comp_floor(row)
            try:
                import os as _os_recovery
                _floor_discount = float(_os_recovery.getenv("TARGET_BID_TRUSTED_FLOOR_DISCOUNT", "0.64") or 0.64)
            except (TypeError, ValueError, ImportError):
                _floor_discount = 0.64
            if _floor_discount <= 0.0 or _floor_discount > 1.0:
                _floor_discount = 0.64
            print(
                f"[TARGET_BID_FALLBACK] "
                f"title={_title[:160]} "
                f"trusted_comp_floor={_floor_value} "
                f"price_count={_floor_count} "
                f"discount={_floor_discount} "
                f"floor_reason={_floor_reason}"
            )
            if _floor_value is None or _floor_value <= 0:
                return False
            _recovered_bid = round(float(_floor_value) * float(_floor_discount), 2)
            if _recovered_bid <= 0:
                return False
            row["target_bid"] = _recovered_bid
            row["target_bid_price"] = _recovered_bid
            row["bid_ceiling_value"] = _recovered_bid
            row["adjusted_max_bid"] = _recovered_bid
            row["target_max_bid"] = _recovered_bid
            row["max_bid"] = _recovered_bid
            row["target_bid_mode"] = "trusted_comp_floor"
            row["target_bid_source"] = "trusted_comp_floor_recovery"
            row["target_bid_source_detail"] = f"trusted_comp_floor_recovery:{_floor_reason}"
            row["bid_ceiling_source"] = "TRUSTED_COMP_FLOOR"
            row["target_bid_ready"] = True
            row["bid_ceiling_ready"] = True
            row["bid_mode"] = "trusted_comp_floor"
            row["final_bid_anchor_value"] = round(float(_floor_value), 2)
            row["final_bid_anchor_mode"] = "trusted_comp_floor"
            row["target_bid_confidence"] = "MEDIUM"
            row["bid_ceiling_confidence"] = "MEDIUM"
            row["_trusted_comp_floor_recovery"] = True
            row["_trusted_comp_floor_value"] = round(float(_floor_value), 2)
            row["_trusted_comp_floor_discount"] = float(_floor_discount)
            row["_trusted_comp_floor_price_count"] = int(_floor_count)
            print(
                f"[TARGET_BID_RECOVERY] "
                f"title={_title[:160]} "
                f"trusted_exact={_trusted_exact_recovery} "
                f"trusted_comp_floor={round(float(_floor_value), 2)} "
                f"discount={_floor_discount} "
                f"recovered_target_bid={_recovered_bid} "
                f"price_count={_floor_count} "
                f"reason=premium_exact_truth_floor_recovery"
            )
            return True
        _anchor_mode = "true_market_value" if _truth == "TRUE" and _true_mv is not None and _true_mv > 0 else "review_estimate"
        _anchor_value = _true_mv if _anchor_mode == "true_market_value" else _review_estimate
        if _anchor_value is None or _anchor_value <= 0:
            return False
        if _anchor_mode == "true_market_value":
            row["true_market_value"] = round(float(_anchor_value), 2)
            row["market_value_true"] = round(float(_anchor_value), 2)
            row["has_true_market_value"] = True
            row["valuation_truth_tier"] = row.get("valuation_truth_tier") or "TRUE"
            row["_valuation_truth_tier"] = row.get("_valuation_truth_tier") or row["valuation_truth_tier"]
        else:
            row["review_estimate_value"] = round(float(_anchor_value), 2)
            row["anchored_estimate_value"] = row.get("anchored_estimate_value") or round(float(_anchor_value), 2)
            if str(row.get("valuation_truth_tier") or row.get("_valuation_truth_tier") or "").strip().upper() not in {"TRUE", "REVIEW"}:
                row["valuation_truth_tier"] = "REVIEW"
                row["_valuation_truth_tier"] = "REVIEW"
            row["valuation_truth_level"] = row.get("valuation_truth_level") or "REVIEW"
        _new_target_bid, _target_bid_mode, _computed_anchor_mode = _compute_final_target_bid_from_anchor(row, _anchor_value, _anchor_mode)
        if _new_target_bid is None or _new_target_bid <= 0:
            return False
        _new_target_bid = round(float(_new_target_bid), 2)
        row["target_bid"] = _new_target_bid
        row["target_bid_price"] = _new_target_bid
        row["bid_ceiling_value"] = _new_target_bid
        row["adjusted_max_bid"] = _new_target_bid
        row["target_max_bid"] = _new_target_bid
        row["max_bid"] = _new_target_bid
        row["target_bid_mode"] = str(_target_bid_mode or "review_ceiling")
        row["target_bid_source"] = f"final_survivor_{_computed_anchor_mode or _anchor_mode}"
        row["target_bid_source_detail"] = f"final_survivor_{_computed_anchor_mode or _anchor_mode}"
        row["bid_ceiling_source"] = str(_target_bid_mode or "review_ceiling").upper()
        row["target_bid_ready"] = True
        row["bid_ceiling_ready"] = True
        row["bid_mode"] = _computed_anchor_mode or _anchor_mode
        row["final_bid_anchor_value"] = round(float(_anchor_value), 2)
        row["final_bid_anchor_mode"] = _computed_anchor_mode or _anchor_mode
        row["target_bid_confidence"] = "REVIEW" if (_computed_anchor_mode or _anchor_mode) == "review_estimate" else str(row.get("target_bid_confidence") or row.get("bid_ceiling_confidence") or "MEDIUM").upper()
        row["bid_ceiling_confidence"] = row["target_bid_confidence"]
        print(
            f"[FINAL_TARGET_BID_RESCUE] "
            f"title={_title[:160]} "
            f"truth={row.get('truth') or row.get('valuation_truth_tier') or row.get('_valuation_truth_tier')} "
            f"true_mv={row.get('true_mv') or row.get('true_market_value') or row.get('market_value_true')} "
            f"review_estimate={row.get('review_estimate') or row.get('review_estimate_value') or row.get('anchored_estimate_value')} "
            f"old_target_bid={_old_target_bid} "
            f"new_target_bid={_new_target_bid} "
            f"anchor_mode={_computed_anchor_mode or _anchor_mode}"
        )
        print(
            f"[FINAL_TARGET_BID_ASSERT] "
            f"title={_title[:160]} "
            f"target_bid={row.get('target_bid')} "
            f"true_mv={row.get('true_mv') or row.get('true_market_value') or row.get('market_value_true')} "
            f"review_estimate={row.get('review_estimate') or row.get('review_estimate_value') or row.get('anchored_estimate_value')} "
            f"identity_is_clean={row.get('identity_is_clean') or row.get('_hydrated_identity_is_clean')}"
        )
        return True
    except Exception as _e:
        print(f"[FINAL_TARGET_BID_RESCUE_ERROR] title={str((row or {}).get('title') or '')[:160]} error={_e}")
        return False


# ---------------------------------------------------------------------------
# PART 2 — Patch-family comp contamination guard.
# Prevents broad "Brock Bowers NT patch" clusters from getting truth=TRUE
# when the comp serial spread or subtype mix is too wide to be reliable.
# ---------------------------------------------------------------------------

def _exact_comp_value_rescue(row: Dict[str, Any]) -> Dict[str, Any]:
    """
    If a row already has exact-backed trust but no materialized value,
    derive a conservative usable value from exact comp payload.
    """
    try:
        if not isinstance(row, dict):
            return row

        _truth = str(row.get("truth") or row.get("valuation_truth_tier") or row.get("_valuation_truth_tier") or "").strip().upper()
        try:
            _trusted_exact = int(row.get("trusted_exact_comp_count") or 0)
        except Exception:
            _trusted_exact = 0
        try:
            _raw_exact = int(row.get("raw_exact_match_count") or row.get("raw_exact_comp_count") or 0)
        except Exception:
            _raw_exact = 0
        _old_true_mv = _safe_float(row.get("true_mv") or row.get("true_market_value") or row.get("market_value_true"))
        _old_review = _safe_float(row.get("review_estimate") or row.get("review_estimate_value") or row.get("review"))

        if isinstance(_old_true_mv, (int, float)) or isinstance(_old_review, (int, float)):
            row["_exact_comp_value_rescue"] = False
            return row

        if not (_truth == "TRUE" and (_trusted_exact >= 1 or _raw_exact >= 1)):
            row["_exact_comp_value_rescue"] = False
            return row

        _candidate_prices: List[float] = []

        def _add_price(_value: Any) -> bool:
            _pv = _safe_float(_value)
            if isinstance(_pv, (int, float)) and _pv > 0:
                _candidate_prices.append(float(_pv))
                return True
            try:
                if _value not in (None, "", "?"):
                    _pv = float(str(_value).replace("$", "").replace(",", "").strip())
                    if _pv > 0:
                        _candidate_prices.append(float(_pv))
                        return True
            except Exception:
                pass
            return False

        for _key in (
            "renderable_evidence_rows",
            "evidence_rows",
            "comp_rows",
            "review_evidence_rows",
            "exact_comp_rows",
            "exact_match_rows",
            "support_rows",
        ):
            _rows = row.get(_key)
            if isinstance(_rows, list):
                for _r in _rows:
                    if not isinstance(_r, dict):
                        continue
                    for _pk in ("sold_price", "price", "comp_price", "amount", "sale_price"):
                        if _add_price(_r.get(_pk)):
                            break

        for _pk in (
            "exact_comp_price",
            "exact_price",
            "best_exact_price",
            "trusted_exact_price",
            "review_anchor_value",
            "display_value",
            "reference_value",
        ):
            _add_price(row.get(_pk))

        _candidate_prices = sorted(float(x) for x in _candidate_prices if isinstance(x, (int, float)) and float(x) > 0)

        if not _candidate_prices:
            row["_exact_comp_value_rescue"] = False
            row["_exact_comp_value_rescue_reason"] = "no_exact_prices_found"
            return row

        _rescue_value = round(float(_candidate_prices[len(_candidate_prices) // 2]), 2)
        row["review_estimate"] = _rescue_value
        row["review_estimate_value"] = _rescue_value
        row["review"] = _rescue_value
        row["reference_value"] = _rescue_value
        row["reference_price"] = _rescue_value
        row["display_value"] = _rescue_value
        row["display_mode"] = "review_estimate"
        row["_exact_comp_value_rescue"] = True
        row["_exact_comp_value_rescue_reason"] = "median_exact_comp_price"
        row["_exact_comp_value_rescue_price_count"] = len(_candidate_prices)

        if _trusted_exact >= 1:
            row["true_mv"] = _rescue_value
            row["true_market_value"] = _rescue_value
            row["market_value_true"] = _rescue_value
            row["has_true_market_value"] = True
            row["valuation_truth_tier"] = "TRUE"
            row["_valuation_truth_tier"] = "TRUE"
            row["valuation_truth_level"] = "EXACT_RESCUE_VALUE"

        print(
            f"[EXACT_COMP_VALUE_RESCUE] "
            f"title={str(row.get('title') or row.get('source_title') or '')[:160]} "
            f"truth={_truth} "
            f"trusted_exact={_trusted_exact} "
            f"raw_exact={_raw_exact} "
            f"price_count={len(_candidate_prices)} "
            f"old_true_mv={_old_true_mv} "
            f"old_review={_old_review} "
            f"new_value={_rescue_value} "
            f"reason={row.get('_exact_comp_value_rescue_reason')}"
        )
        print(
            f"[EXACT_COMP_VALUE_ASSERT] "
            f"title={str(row.get('title') or row.get('source_title') or '')[:160]} "
            f"true_mv={row.get('true_mv') or row.get('true_market_value')} "
            f"review_estimate={row.get('review_estimate') or row.get('review_estimate_value')} "
            f"reference_value={row.get('reference_value')} "
            f"target_bid={row.get('target_bid')} "
            f"display_mode={row.get('display_mode')} "
            f"rescue_reason={row.get('_exact_comp_value_rescue_reason')}"
        )
        return row
    except Exception:
        return row


def _exact_comp_value_surface_allow(row: Dict[str, Any]) -> Tuple[bool, str]:
    """
    Promote rescued exact-value rows out of generic PASS if current price and target bid both exist.
    """
    try:
        if not isinstance(row, dict):
            return False, "not_dict"
        if not bool(row.get("_exact_comp_value_rescue")):
            return False, "not_rescued"
        _current = _safe_float(
            row.get("current_price")
            if row.get("current_price") is not None
            else row.get("authoritative_current_price")
            or row.get("_board_current_price")
            or row.get("current_bid")
        )
        _target = _safe_float(row.get("target_bid") or row.get("target_bid_price") or row.get("bid_ceiling_value"))
        _truth = str(row.get("truth") or row.get("valuation_truth_tier") or row.get("_valuation_truth_tier") or "").strip().upper()
        try:
            _trusted_exact = int(row.get("trusted_exact_comp_count") or 0)
        except Exception:
            _trusted_exact = 0
        if (
            _truth == "TRUE"
            and _trusted_exact >= 1
            and isinstance(_current, (int, float))
            and isinstance(_target, (int, float))
        ):
            return True, "exact_comp_value_surface_allow"
        return False, "not_surface_allow"
    except Exception:
        return False, "exception"


def _premium_actionability_bid_rescue(row: Dict[str, Any]) -> Dict[str, Any]:
    """
    Build a late actionable bid contract for premium exact-backed rows
    that survived truth/identity but still have no target bid.
    """
    try:
        if not isinstance(row, dict):
            return row

        _truth = str(row.get("truth") or row.get("valuation_truth_tier") or row.get("_valuation_truth_tier") or "").strip().upper()
        try:
            _trusted_exact = int(row.get("trusted_exact_comp_count") or 0)
        except Exception:
            _trusted_exact = 0
        _identity_is_clean = bool(row.get("identity_is_clean") or row.get("_hydrated_identity_is_clean") or row.get("identity_clean"))
        _premium_lane = bool(row.get("premium_lane"))
        _insert_family = str(row.get("insert_family") or row.get("_hydrated_insert_family") or "").strip().lower()
        _parallel_family = str(row.get("parallel_family") or row.get("_hydrated_parallel_family") or "").strip().lower()
        _serial = str(row.get("serial_denominator") or row.get("_hydrated_serial_denominator") or "").strip()
        _old_target_bid = _safe_float(row.get("target_bid") or row.get("target_bid_price") or row.get("bid_ceiling_value"))
        _true_mv = _safe_float(row.get("true_mv") or row.get("true_market_value") or row.get("market_value_true"))
        _review = _safe_float(row.get("review_estimate") or row.get("review_estimate_value") or row.get("review"))

        _elite_shape = bool(
            _serial
            or _insert_family in {"auto", "autograph", "patch_auto", "auto_patch", "downtown", "kaboom", "stained_glass", "genesis", "manga", "color_blast"}
            or _parallel_family not in {"", "base", "none"}
        )

        if isinstance(_old_target_bid, (int, float)):
            row["_premium_actionability_bid_rescue"] = False
            return row

        if _truth == "TRUE" and _trusted_exact >= 1 and _identity_is_clean and (_premium_lane or _elite_shape):
            _anchor = _true_mv if isinstance(_true_mv, (int, float)) else _review
            _anchor_mode = "premium_actionability_bid_rescue" if isinstance(_true_mv, (int, float)) else "review_estimate"
            if isinstance(_anchor, (int, float)) and _anchor > 0:
                _new_bid, _target_mode, _computed_anchor_mode = _compute_final_target_bid_from_anchor(row, _anchor, _anchor_mode)
                if isinstance(_new_bid, (int, float)) and _new_bid > 0:
                    _new_bid = round(float(_new_bid), 2)
                    row["target_bid"] = _new_bid
                    row["target_bid_price"] = _new_bid
                    row["target_max_bid"] = _new_bid
                    row["adjusted_max_bid"] = _new_bid
                    row["bid_ceiling_value"] = _new_bid
                    row["target_bid_source"] = "premium_actionability_bid_rescue"
                    row["target_bid_source_detail"] = "premium_actionability_bid_rescue"
                    row["bid_ceiling_source"] = str(_target_mode or "premium_actionability_bid_rescue").upper()
                    row["target_bid_confidence"] = "MEDIUM"
                    row["bid_ceiling_confidence"] = "MEDIUM"
                    row["target_bid_ready"] = True
                    row["bid_ceiling_ready"] = True
                    row["_premium_actionability_bid_rescue"] = True
                    row["_premium_actionability_bid_reason"] = "premium_exact_backed_bid_rescue"
                    print(
                        f"[PREMIUM_ACTION_BID_RESCUE] "
                        f"title={str(row.get('title') or row.get('source_title') or '')[:160]} "
                        f"truth={_truth} "
                        f"trusted_exact={_trusted_exact} "
                        f"true_mv={_true_mv} "
                        f"review_estimate={_review} "
                        f"old_target_bid={_old_target_bid} "
                        f"new_target_bid={_new_bid} "
                        f"reason={row.get('_premium_actionability_bid_reason')}"
                    )
        return row
    except Exception:
        return row


def _premium_actionability_surface_allow(row: Dict[str, Any]) -> Tuple[bool, str]:
    """
    Prevent exact-backed premium rows from dying as generic PASS when
    they now have a rescued bid contract and live price.
    """
    try:
        if not isinstance(row, dict):
            return False, "not_dict"

        _truth = str(row.get("truth") or row.get("valuation_truth_tier") or row.get("_valuation_truth_tier") or "").strip().upper()
        try:
            _trusted_exact = int(row.get("trusted_exact_comp_count") or 0)
        except Exception:
            _trusted_exact = 0
        _target_bid = _safe_float(row.get("target_bid") or row.get("target_bid_price") or row.get("bid_ceiling_value"))
        _current = _safe_float(
            row.get("current_price")
            if row.get("current_price") is not None
            else row.get("authoritative_current_price")
            or row.get("_board_current_price")
            or row.get("current_bid")
        )
        _premium_lane = bool(row.get("premium_lane"))

        if (
            _truth == "TRUE"
            and _trusted_exact >= 1
            and isinstance(_target_bid, (int, float))
            and isinstance(_current, (int, float))
            and _premium_lane
        ):
            return True, "premium_actionability_surface_allow"

        if (
            bool(row.get("_premium_actionability_bid_rescue"))
            and isinstance(_target_bid, (int, float))
            and isinstance(_current, (int, float))
        ):
            return True, "premium_bid_rescue_surface_allow"

        return False, "not_actionable_surface_allow"
    except Exception:
        return False, "exception"


_PATCH_GUARD_PRODUCTS: frozenset = frozenset({
    "national treasures", "immaculate", "flawless", "spectra",
})

_PATCH_SUBTYPE_BUCKET_MAP: Dict[str, str] = {
    "colossal": "colossal",
    "sunday treasures": "sunday_treasures",
    "treasure chest": "treasure_chest",
    "jumbo": "jumbo",
    "laundry tag": "laundry_tag",
    "laundry": "laundry_tag",
    "nameplate": "nameplate",
    "tag patch": "tag_patch",
    "prime": "prime",
    "3-color": "multi_color",
    "tri-color": "multi_color",
    "4-color": "multi_color",
    "quad": "multi_color",
}


def _pg_extract_patch_subtype(title: str) -> str:
    """Return canonical patch subtype bucket for a title, or '' for generic."""
    _t = str(title or "").lower()
    for _kw, _bucket in _PATCH_SUBTYPE_BUCKET_MAP.items():
        if _kw in _t:
            return _bucket
    return ""


def _pg_extract_serial(title: str) -> Optional[int]:
    """Extract serial denominator from a title string."""
    _m = re.search(r"/(\d{1,4})\b", str(title or ""))
    if _m:
        try:
            return int(_m.group(1))
        except (TypeError, ValueError):
            pass
    return None


def _pg_serial_tier(serial: Optional[int]) -> str:
    """Map serial denominator to a tier bucket."""
    if serial is None:
        return "unnumbered"
    if serial == 1:
        return "1of1"
    if serial <= 10:
        return "ultra_low"
    if serial <= 25:
        return "very_low"
    if serial <= 50:
        return "low"
    if serial <= 99:
        return "near_low"
    if serial <= 249:
        return "mid"
    return "high"


def _pg_parse_comps_title_only(raw_json: Any) -> List[Dict[str, Any]]:
    """
    Parse comps from debug_accepted_comps_json without requiring a price field.
    _extract_debug_comp_rows filters by price and would drop title-only entries.
    """
    if isinstance(raw_json, list):
        _parsed = raw_json
    elif not raw_json:
        return []
    else:
        try:
            _parsed = json.loads(str(raw_json))
        except (TypeError, ValueError, json.JSONDecodeError):
            return []
    return [_c for _c in _parsed if isinstance(_c, dict)]


def _is_patch_guard_eligible(row: Dict[str, Any]) -> bool:
    """Return True if this row is a patch-family card that needs contamination checking."""
    _title = str(row.get("title") or row.get("source_title") or "").lower()
    _product = str(
        row.get("target_product_family") or row.get("product_family") or
        row.get("lane_product") or ""
    ).lower()
    _combined = f"{_title} {_product}"
    if not any(_key in _combined for _key in _PATCH_GUARD_PRODUCTS):
        return False
    _patch_terms = ("patch", "relic", "materials", "memorabilia", "tag", "swatch")
    return any(_t in _title for _t in _patch_terms)


def _is_patch_family_comp_contaminated(
    row: Dict[str, Any],
    comps: List[Dict[str, Any]],
) -> Tuple[bool, str]:
    """
    Return (contaminated: bool, reason: str).

    Rules (applied only for patch-family cards):
    1. Non-patch comps mixed into a patch card comp cluster.
    2. Serial tiers span >= 3 distinct numbered tiers (e.g., /25+/49+/99 all together).
    3. Row serial is specific but comp range is 4× wider.
    4. Patch subtype mismatch when the row has a specific subtype.
    """
    if not comps:
        return False, "no_comps"

    _title = str(row.get("title") or row.get("source_title") or "").lower()
    _row_serial = _pg_extract_serial(_title)
    _row_subtype = _pg_extract_patch_subtype(_title)
    _row_tier = _pg_serial_tier(_row_serial)

    _comp_serials: List[int] = []
    _comp_tiers: set = set()
    _comp_subtypes: set = set()
    _obvious_non_patch_comps = 0
    # Broad patch-related evidence terms — a comp missing all of these AND carrying
    # clear non-patch signals (auto-only, base, etc.) is definitively not a patch card.
    _patch_evidence_terms = (
        "patch", "relic", "materials", "tag", "swatch",
        "colossal", "sunday treasures", "treasure chest", "jumbo", "nameplate",
    )
    # Signals that clearly indicate a non-patch card type
    _non_patch_signals = ("auto rc", "refractor", "base", "prizm", "silver", "gold vinyl", "superfractor")

    for _comp in list(comps or []):
        _ct = str(_comp.get("title") or _comp.get("comp_title") or "").lower()
        _cs = _pg_extract_serial(_ct)
        _comp_tiers.add(_pg_serial_tier(_cs))
        _comp_subtypes.add(_pg_extract_patch_subtype(_ct))
        if _cs is not None:
            _comp_serials.append(_cs)
        # Only count as "obviously non-patch" if: missing ALL patch evidence AND has a clear
        # non-patch signal. Avoids false-positives on legitimate shortened eBay titles.
        if not any(_t in _ct for _t in _patch_evidence_terms) and any(_s in _ct for _s in _non_patch_signals):
            _obvious_non_patch_comps += 1

    # Rule 1: clearly non-patch card types contaminating a patch card (strict: both absence + presence)
    if _obvious_non_patch_comps >= 2 and len(comps) <= 4:
        return True, f"obvious_non_patch_comps={_obvious_non_patch_comps}_of_{len(comps)}"

    # Rule 2: serial tiers span >= 3 distinct numbered tiers
    _numbered_tiers = {
        _t for _t in _comp_tiers
        if _t in ("ultra_low", "very_low", "low", "near_low", "mid")
    }
    if len(_numbered_tiers) >= 3:
        return True, f"serial_tier_spread={sorted(_numbered_tiers)}"

    # Rule 3: comp serial range > 4× wider than row's serial
    if _row_serial is not None and len(_comp_serials) >= 2:
        _mn = min(_comp_serials)
        _mx = max(_comp_serials)
        if _mn > 0 and (_mx / _mn) > 4.0 and len(_numbered_tiers) >= 2:
            return True, f"serial_range_too_wide: row={_row_serial} comps=[{_mn}..{_mx}]"

    # Rule 4: patch subtype mismatch in small cluster
    if _row_subtype:
        _mismatched = {_s for _s in _comp_subtypes if _s and _s != _row_subtype}
        if _mismatched and len(comps) <= 5:
            return True, f"subtype_mismatch: row={_row_subtype} comps_have={sorted(_mismatched)}"

    return False, f"subtype_match={_row_subtype or 'generic'} serial_tier={_row_tier}"


# ---------------------------------------------------------------------------
# SAME-CARD MARKET SANITY LAYER
# Medium-confidence comp MV must survive a price-distribution reality check
# before truth=TRUE is granted. Prevents inflated small-cluster comp values
# from claiming market certainty against actual live/sold market evidence.
#
# Priority (Part 3 of the patch spec):
#   1. exact same-card sold median    ← what this layer enforces
#   2. value-range sanity             ← Rule 2 below
#   3. strong/exact comp engine       ← already trusted (not in SANITY_GUARD_SOURCES)
#   4. medium_comp_engine             ← gated by this layer
#   5. fallback/review support        ← unchanged
# ---------------------------------------------------------------------------

_SANITY_GUARD_SOURCES: frozenset = frozenset({
    "medium_comp_engine",
    "scarcity_supported_comp_engine",
    "fallback_comp_support",
})


def _percentile(values: List[float], pct: float) -> float:
    """Linear-interpolation percentile from a sorted list."""
    if not values:
        return 0.0
    _v = sorted(v for v in values if v and v > 0)
    if not _v:
        return 0.0
    _idx = (len(_v) - 1) * pct / 100.0
    _lo = int(_idx)
    _hi = min(_lo + 1, len(_v) - 1)
    return _v[_lo] + (_v[_hi] - _v[_lo]) * (_idx - _lo)


def _same_card_subtype_bucket(title: str) -> str:
    _t = str(title or "").lower()
    _has_auto = any(_term in _t for _term in ("auto", "autograph", "signed"))
    _has_patch = any(_term in _t for _term in ("patch", "logo", "shield"))
    _has_relic = any(_term in _t for _term in ("relic", "jersey", "material", "materials", "memorabilia", "swatch"))
    if "rpa" in _t or (_has_auto and _has_patch):
        return "patch_auto"
    if _has_patch:
        return "patch"
    if _has_auto:
        return "auto"
    if _has_relic:
        return "relic"
    return "other"


def _same_card_subject_player_tokens(row: Dict[str, Any]) -> List[str]:
    _player_name = str(
        row.get("player_name")
        or row.get("normalized_entity")
        or row.get("entity_name")
        or row.get("target_player_name")
        or ""
    ).strip()
    _key = _normalize_person_key(_player_name)
    return [tok for tok in _key.split() if len(tok) >= 2]


def _same_card_product_aliases(row: Dict[str, Any]) -> List[str]:
    _product = str(
        row.get("target_product_family")
        or row.get("product_family")
        or row.get("lane_product")
        or row.get("set_name")
        or ""
    ).strip().lower()
    if not _product:
        return []
    _aliases = {_product}
    if "national treasures" in _product or _product == "nt":
        _aliases.update({"national treasures", "nt"})
    if "immaculate" in _product:
        _aliases.add("immaculate")
    if "flawless" in _product:
        _aliases.add("flawless")
    if "spectra" in _product:
        _aliases.add("spectra")
    if "donruss optic" in _product or _product == "optic":
        _aliases.update({"donruss optic", "optic"})
    if "topps chrome black" in _product:
        _aliases.update({"topps chrome black", "chrome black"})
    if "topps chrome" in _product:
        _aliases.add("topps chrome")
    if "bowman chrome" in _product:
        _aliases.add("bowman chrome")
    if "topps finest" in _product or "finest" in _product:
        _aliases.update({"topps finest", "finest"})
    return sorted(_aliases, key=len, reverse=True)


def _subject_serial_for_same_card(row: Dict[str, Any], title: str) -> Optional[int]:
    _serial = _safe_int(
        row.get("serial_denominator")
        or row.get("serial")
        or row.get("serial_to")
        or row.get("print_run")
    )
    if _serial and _serial > 0:
        return int(_serial)
    return _pg_extract_serial(title)


def _filter_exact_same_card_comps(row: Dict[str, Any], comp_rows: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
    _title = str(row.get("title") or row.get("source_title") or "")
    _player_tokens = _same_card_subject_player_tokens(row)
    _product_aliases = _same_card_product_aliases(row)
    _subject_serial = _subject_serial_for_same_card(row, _title)
    _subject_serial_tier = _pg_serial_tier(_subject_serial)
    _subject_subtype = _same_card_subtype_bucket(_title)
    _kept: List[Dict[str, Any]] = []

    for _comp in list(comp_rows or []):
        _comp_title = str(_comp.get("title") or _comp.get("comp_title") or "").strip()
        _comp_lower = _comp_title.lower()
        _price = _safe_float(_comp.get("price"))
        if not _comp_title or not _price or _price <= 0:
            continue
        if _player_tokens:
            _last = _player_tokens[-1]
            _first = _player_tokens[0] if len(_player_tokens) > 1 else ""
            if _last not in _comp_lower or (_first and _first not in _comp_lower):
                print(f"[MV_SANITY_PROXY_REJECT] title={_comp_title[:120]} reason=player_mismatch")
                continue
        if _product_aliases and not any(_alias in _comp_lower for _alias in _product_aliases):
            print(f"[MV_SANITY_PROXY_REJECT] title={_comp_title[:120]} reason=product_mismatch")
            continue
        _comp_subtype = _same_card_subtype_bucket(_comp_title)
        if _subject_subtype != "other" and _comp_subtype != _subject_subtype:
            print(f"[MV_SANITY_PROXY_REJECT] title={_comp_title[:120]} reason=subtype_mismatch")
            continue
        _comp_serial = _pg_extract_serial(_comp_title)
        if _subject_serial is not None:
            if _comp_serial is None:
                print(f"[MV_SANITY_PROXY_REJECT] title={_comp_title[:120]} reason=serial_missing")
                continue
            if _pg_serial_tier(_comp_serial) != _subject_serial_tier:
                print(f"[MV_SANITY_PROXY_REJECT] title={_comp_title[:120]} reason=serial_tier_mismatch")
                continue
        _kept.append(_comp)

    _prices = sorted(
        _safe_float(_comp.get("price")) or 0.0
        for _comp in _kept
        if (_safe_float(_comp.get("price")) or 0.0) > 0
    )
    if len(_prices) >= 3:
        _median = _percentile(_prices, 50)
        _filtered: List[Dict[str, Any]] = []
        for _comp in _kept:
            _price = _safe_float(_comp.get("price")) or 0.0
            if _median > 0 and _price < (_median * 0.35):
                _comp_title = str(_comp.get("title") or _comp.get("comp_title") or "").strip()
                print(f"[MV_SANITY_PROXY_REJECT] title={_comp_title[:120]} reason=low_outlier")
                continue
            _filtered.append(_comp)
        _kept = _filtered
    return _kept


def _build_same_card_market_snapshot(row: Dict[str, Any]) -> Dict[str, Any]:
    """
    Extract comp price distribution from debug_accepted_comps_json.
    Returns snapshot dict with _same_card_* fields.
    The comp prices ARE the best available same-card sold evidence in the current pipeline
    (external live-ask data is not yet available; value_range_low is the best proxy).
    """
    _comp_rows = _filter_exact_same_card_comps(row, _extract_debug_comp_rows(row.get("debug_accepted_comps_json")))
    _prices = sorted(
        p for p in (_safe_float(c.get("price")) for c in _comp_rows)
        if p and p > 0
    )
    _snap: Dict[str, Any] = {
        "_same_card_sold_count": len(_prices),
        "_same_card_sold_floor": round(min(_prices), 2) if _prices else None,
        "_same_card_sold_median": round(_percentile(_prices, 50), 2) if _prices else None,
        "_same_card_sold_p25": round(_percentile(_prices, 25), 2) if _prices else None,
        "_same_card_sold_high": round(max(_prices), 2) if _prices else None,
        "_same_card_live_floor": round(min(_prices), 2) if _prices else None,
        "_same_card_live_median": round(_percentile(_prices, 50), 2) if _prices else None,
        "_same_card_live_count": len(_prices),
    }
    _title = str(row.get("title") or row.get("source_title") or "")[:120]
    if _prices:
        print(
            f"[MV_EXACT_SNAPSHOT] title={_title} exact_comps={len(_prices)} "
            f"sold_median={_snap.get('_same_card_sold_median')} live_floor={_snap.get('_same_card_live_floor')}"
        )
    else:
        print(f"[MV_EXACT_SNAPSHOT_INSUFFICIENT] title={_title} exact_comps=0")
    return _snap


_REVIEW_FALLBACK_SUPPORT_SOURCES: frozenset = frozenset({
    "fallback",
    "near_family_support",
    "premium_scarcity_bucket_support",
    "hybrid_near_lane",
    "fallback_comp_support",
    "single_comp_conservative",
    "scarcity_fallback",
    "structured_fallback",
    "structured_review",
    "fallback_review",
})


def _premium_serial_review_fallback_adjustment(
    row: Dict[str, Any],
    *,
    source: str,
    truth_tier: str,
    review_estimate: Optional[float],
) -> Dict[str, Any]:
    _row = row or {}
    _source = str(source or "").strip().lower()
    _truth = str(truth_tier or "").strip().upper()
    _review = _safe_float(review_estimate)
    _exact_comp_count = _resolved_exact_comp_count(_row)
    _serial_raw = str(
        _row.get("serial")
        or _row.get("serial_denominator")
        or _row.get("serial_bucket")
        or ""
    ).strip()
    _has_serial = bool(re.sub(r"[^0-9]", "", _serial_raw))
    _eligible = bool(
        _truth != "TRUE"
        and _exact_comp_count < 2
        and _source in _REVIEW_FALLBACK_SUPPORT_SOURCES
        and _has_serial
        and _is_premium_card(_row)
    )
    if not _eligible:
        return {
            "applied": False,
            "review_estimate": _review,
            "anchor_value": None,
            "anchor_source": "",
            "serial_haircut": 1.0,
            "uncertainty_haircut": 1.0,
        }

    _same_card_snapshot = _build_same_card_market_snapshot(_row)
    _same_card_floor = _safe_float(_same_card_snapshot.get("_same_card_sold_floor"))
    _same_card_p25 = _safe_float(_same_card_snapshot.get("_same_card_sold_p25"))
    _same_card_median = _safe_float(_same_card_snapshot.get("_same_card_sold_median"))
    _same_card_count = int(_same_card_snapshot.get("_same_card_sold_count") or 0)
    _range_low = _safe_float(_row.get("value_range_low"))
    _raw_mv = _safe_float(_row.get("market_value_raw"))
    _anchor_value = _safe_float(_row.get("_review_fallback_base_anchor"))
    _anchor_source = str(_row.get("_review_fallback_anchor_source") or "").strip()
    if not _anchor_value or _anchor_value <= 0:
        for _label, _candidate in (
            ("same_card_floor", _same_card_floor),
            ("same_card_p25", _same_card_p25),
            ("value_range_low", _range_low),
            ("same_card_median", _same_card_median),
            ("market_value_raw", _raw_mv),
            ("review_estimate", _review),
        ):
            if _candidate and _candidate > 0:
                _anchor_value = round(float(_candidate), 2)
                _anchor_source = _label
                break
    if not _anchor_value or _anchor_value <= 0:
        return {
            "applied": False,
            "review_estimate": _review,
            "anchor_value": None,
            "anchor_source": "",
            "serial_haircut": 1.0,
            "uncertainty_haircut": 1.0,
        }

    _row["_review_fallback_base_anchor"] = _anchor_value
    _row["_review_fallback_anchor_source"] = _anchor_source
    print(
        f"[REVIEW_FALLBACK_ANCHOR] title={str(_row.get('title') or _row.get('source_title') or '')[:120]} "
        f"source={_source or 'none'} exact_comp_count={_exact_comp_count} "
        f"anchor_source={_anchor_source or 'none'} anchor_value={_anchor_value}"
    )

    if _exact_comp_count >= 1:
        _serial_haircut = 1.00
        _serial_reason = "single_exact_comp_only"
    elif _same_card_count > 0:
        _serial_haircut = 0.84
        _serial_reason = "cross_serial_same_tier_only"
    else:
        _serial_haircut = 0.76
        _serial_reason = "family_support_only"
    print(
        f"[SERIAL_SUPPORT_HAIRCUT] title={str(_row.get('title') or _row.get('source_title') or '')[:120]} "
        f"source={_source or 'none'} exact_comp_count={_exact_comp_count} "
        f"same_card_count={_same_card_count} reason={_serial_reason} haircut={_serial_haircut:.2f}"
    )

    if _source in {"near_family_support", "premium_scarcity_bucket_support", "hybrid_near_lane", "fallback"}:
        _uncertainty_haircut = 0.95
        _uncertainty_reason = "support_lane_uncertainty"
    elif _source in {"fallback_comp_support", "single_comp_conservative", "scarcity_fallback"}:
        _uncertainty_haircut = 0.92
        _uncertainty_reason = "fallback_support_uncertainty"
    else:
        _uncertainty_haircut = 0.88
        _uncertainty_reason = "structured_fallback_uncertainty"
    if _exact_comp_count == 0 and _same_card_count <= 1:
        _uncertainty_haircut *= 0.94
    elif _exact_comp_count == 0 and _same_card_count == 0:
        _uncertainty_haircut *= 0.90
    _uncertainty_haircut = max(0.70, min(round(float(_uncertainty_haircut), 4), 0.98))
    print(
        f"[REVIEW_FALLBACK_DISCOUNT] title={str(_row.get('title') or _row.get('source_title') or '')[:120]} "
        f"source={_source or 'none'} reason={_uncertainty_reason} "
        f"serial_haircut={_serial_haircut:.2f} uncertainty_haircut={_uncertainty_haircut:.2f}"
    )

    _final_review = round(float(_anchor_value) * float(_serial_haircut) * float(_uncertainty_haircut), 2)
    if _review and _review > 0:
        _final_review = min(_final_review, round(float(_review), 2))
    if _raw_mv and _raw_mv > 0:
        _final_review = min(_final_review, round(float(_raw_mv), 2))
    print(
        f"[REVIEW_FALLBACK_FINAL] title={str(_row.get('title') or _row.get('source_title') or '')[:120]} "
        f"source={_source or 'none'} exact_comp_count={_exact_comp_count} "
        f"review_estimate={_final_review}"
    )
    return {
        "applied": True,
        "review_estimate": _final_review,
        "anchor_value": _anchor_value,
        "anchor_source": _anchor_source,
        "serial_haircut": _serial_haircut,
        "uncertainty_haircut": _uncertainty_haircut,
    }


def _apply_same_card_market_sanity(
    row: Dict[str, Any],
    proposed_mv: float,
) -> Optional[float]:
    """
    Same-card market sanity guard.
    Returns saner_mv (float) if MV should be downgraded to REVIEW, or None if MV passes.

    Does NOT modify the row — caller (inside _stamp_mv_truth_fields) handles state changes
    so local variables stay in sync.

    Three rules (any single one triggers downgrade):
      1. Comp floor is far below proposed MV in a small cluster (comp data is unreliable)
      2. Hybrid engine's own value_range_low is very far below proposed MV (wide uncertainty)
      3. Comp median is materially below proposed MV (outlier pulling MV up)
    """
    _source = _valuation_source_clean(row)
    if _source not in _SANITY_GUARD_SOURCES:
        return None
    if not proposed_mv or proposed_mv <= 0:
        return None

    _snap = _build_same_card_market_snapshot(row)
    _sold_count = int(_snap.get("_same_card_sold_count") or 0)
    _sold_floor = _snap.get("_same_card_sold_floor")
    _sold_median = _snap.get("_same_card_sold_median")
    _live_floor = _snap.get("_same_card_live_floor")  # value_range_low proxy
    _title = str(row.get("title") or row.get("source_title") or "")[:120]

    # Stamp snapshot fields into row for downstream inspection
    row.update({k: v for k, v in _snap.items() if k not in row or row[k] is None})

    print(
        f"[MV_SAME_CARD_SNAPSHOT] title={_title} proposed_mv={round(proposed_mv, 2)} "
        f"source={_source} sold_count={_sold_count} "
        f"floor={_sold_floor} median={_sold_median} range_low={_live_floor}"
    )

    _downgrade = False
    _reason = ""
    _saner_mv: Optional[float] = None

    # Rule 1: comp floor far below proposed MV in small cluster
    # Fires when: cheapest accepted comp < 55% of proposed MV, cluster ≤ 5 comps
    if _sold_floor is not None and 1 <= _sold_count <= 5:
        if _sold_floor < proposed_mv * 0.55:
            _downgrade = True
            _reason = (
                f"comp_floor_far_below_mv: floor={_sold_floor} mv={round(proposed_mv, 2)} "
                f"ratio={round(_sold_floor/proposed_mv, 2)}"
            )
            _saner_mv = _sold_median if (_sold_median and _sold_median > 0) else _sold_floor

    # Rule 2: hybrid engine's own value_range_low very far below proposed MV
    # Fires when: MV > range_low × 1.65 — the comp distribution is too wide for certainty
    if not _downgrade and _live_floor is not None and _live_floor > 0:
        if proposed_mv > _live_floor * 1.65:
            _downgrade = True
            _reason = (
                f"value_range_too_wide: range_low={_live_floor} mv={round(proposed_mv, 2)} "
                f"ratio={round(proposed_mv/_live_floor, 2)}"
            )
            # Conservative anchor: geometric mean of range_low and proposed_mv
            import math as _math
            _saner_mv = round(_math.sqrt(_live_floor * proposed_mv), 2)

    # Rule 3: comp median materially below proposed MV (outlier pulling value up)
    # Fires when: median < 78% of proposed MV, at least 2 comps
    if not _downgrade and _sold_median is not None and _sold_count >= 2:
        if _sold_median < proposed_mv * 0.78:
            _downgrade = True
            _reason = (
                f"comp_median_below_mv: median={_sold_median} mv={round(proposed_mv, 2)} "
                f"ratio={round(_sold_median/proposed_mv, 2)}"
            )
            _saner_mv = _sold_median

    if not _downgrade:
        print(
            f"[MV_SAME_CARD_GUARD] title={_title} mv={round(proposed_mv, 2)} "
            f"source={_source} passed=True"
        )
        return None

    # Guard fired — compute final saner anchor
    if not _saner_mv or _saner_mv <= 0:
        _saner_mv = round(proposed_mv * 0.68, 2)
    _saner_mv = round(float(_saner_mv), 2)

    print(
        f"[MV_SAME_CARD_DOWNGRADE] title={_title} old_mv={round(proposed_mv, 2)} "
        f"saner_mv={_saner_mv} reason={_reason}"
    )
    print(
        f"[TARGET_BID_RECOMPUTE] title={_title} basis=same_card_sanity "
        f"saner_anchor={_saner_mv} old_truth=TRUE new_truth=REVIEW"
    )

    row["_same_card_downgraded"] = True
    row["_same_card_downgrade_reason"] = _reason
    row["_same_card_saner_mv"] = _saner_mv
    return _saner_mv


def _apply_same_card_market_sanity(
    row: Dict[str, Any],
    proposed_mv: float,
) -> Optional[float]:
    _source = _valuation_source_clean(row)
    if _source not in _SANITY_GUARD_SOURCES:
        return None
    if not proposed_mv or proposed_mv <= 0:
        return None

    _snap = _build_same_card_market_snapshot(row)
    _sold_count = int(_snap.get("_same_card_sold_count") or 0)
    _sold_median = _snap.get("_same_card_sold_median")
    _live_floor = _snap.get("_same_card_live_floor")
    _title = str(row.get("title") or row.get("source_title") or "")[:120]

    row.update({k: v for k, v in _snap.items() if k not in row or row[k] is None})

    if _sold_count <= 0 or _sold_median is None:
        print(f"[MV_EXACT_SNAPSHOT_INSUFFICIENT] title={_title} exact_comps={_sold_count} source={_source}")
        return None

    _downgrade = False
    _reason = ""
    _saner_mv: Optional[float] = None

    if proposed_mv > float(_sold_median) * 1.25:
        _downgrade = True
        _reason = f"same_card_override median={_sold_median} mv={round(proposed_mv, 2)}"
        _saner_mv = float(_sold_median)
    elif _live_floor is not None and _live_floor > 0 and proposed_mv > float(_live_floor) * 1.65:
        _downgrade = True
        _reason = f"same_card_floor_cap live_floor={_live_floor} mv={round(proposed_mv, 2)}"
        _saner_mv = float(_sold_median)

    if not _downgrade:
        return None

    if not _saner_mv or _saner_mv <= 0:
        _saner_mv = round(float(_sold_median), 2)
    _saner_mv = round(float(_saner_mv), 2)

    print(
        f"[MV_SAME_CARD_OVERRIDE] title={_title} old_mv={round(proposed_mv, 2)} "
        f"anchor={_saner_mv} reason={_reason}"
    )
    print(
        f"[TARGET_BID_RECOMPUTE] title={_title} basis=same_card_sanity "
        f"saner_anchor={_saner_mv} old_truth=TRUE new_truth=REVIEW"
    )

    row["_same_card_downgraded"] = True
    row["_same_card_downgrade_reason"] = _reason
    row["_same_card_saner_mv"] = _saner_mv
    row["_mv_truth_locked_review"] = True
    return _saner_mv


def _mv_true_premium_lane_guard(row: Dict[str, Any]) -> Dict[str, Any]:
    _r = dict(row or {})
    _title = str(_r.get("title") or _r.get("source_title") or "").strip()
    _title_lower = f" {_title.lower()} "
    _player_name = str(
        _r.get("player_name")
        or _r.get("target_player_name")
        or _r.get("normalized_entity")
        or ""
    ).strip()
    _product_raw = str(
        _r.get("product_family")
        or _r.get("target_product_family")
        or _r.get("lane_product")
        or _r.get("product")
        or _r.get("product_name")
        or ""
    ).strip()
    _product_norm = _normalize_exact_product_family(_product_raw)
    _subset_raw = str(_r.get("subset_name") or _r.get("lane_subset") or _r.get("subset") or "").strip()
    try:
        _subset_norm = _normalize_subset_name(_subset_raw)
    except Exception:
        _subset_norm = str(_subset_raw or "").strip().lower().replace("-", "_").replace(" ", "_")
    _parallel_raw = str(
        _r.get("parallel_name")
        or _r.get("parallel")
        or _r.get("parallel_bucket")
        or _r.get("parallel_family")
        or ""
    ).strip().lower().replace("_", " ")
    _serial_raw = str(
        _r.get("serial")
        or _r.get("serial_bucket")
        or _r.get("serial_denominator")
        or ""
    ).strip()
    _serial_cap = _extract_serial_ceiling(f"{_serial_raw} {_parallel_raw} {_title_lower}")
    _has_serial = bool(_serial_raw and _serial_raw.lower() not in {"0", "none", "n/a", ""}) or _serial_cap > 0
    _has_auto = bool(_r.get("is_auto")) or any(
        _tok in _title_lower
        for _tok in (" auto ", " autograph ", " signed ", " signature ", " patch auto ", " auto patch ", " rpa ", " auto rpa ")
    )
    _has_mem = bool(_r.get("is_memorabilia")) or any(
        _tok in _title_lower
        for _tok in (" patch ", " relic ", " jersey ", " memorabilia ", " material ", " materials ", " swatch ", " gear ", " mem ", " fabric ")
    )
    _mem_junk, _ = _is_memorabilia_junk(_r)
    _lane_type = str(_r.get("target_lane_type") or _r.get("spec_lane_class") or "").strip().lower()
    _product_tier = str(_r.get("product_tier") or _classify_product_tier(_r) or "").strip().upper()
    _endgame_tier = str(_r.get("endgame_tier") or "").strip().lower()
    if not _endgame_tier:
        try:
            _endgame_tier = str(_compute_endgame_tier(_r)[0] or "").strip().lower()
        except Exception:
            _endgame_tier = ""
    _chase_class = str(_r.get("chase_class") or "").strip().upper()
    if not _chase_class:
        try:
            _chase_class = str(_classify_true_chase_class(_r)[0] or "").strip().upper()
        except Exception:
            _chase_class = ""
    _commodity_reason = str(_r.get("commodity_reason") or "").strip().lower()
    _common_rookie = bool(_r.get("common_rookie_commodity")) or _is_common_rookie_commodity(_r)
    _rookie_signal = _infer_rookie_truth(_player_name, _r) or bool(re.search(r"\b(rc|rookie|prospect|debut)\b", _title_lower))
    _grade_state = "raw"
    try:
        _grade_state = str(_extract_grade_bucket(_title) or "RAW").strip().lower()
    except Exception:
        _grade_state = "raw"
    _card_no = str(
        _r.get("card_number")
        or _r.get("fingerprint_card_number")
        or _r.get("target_card_number")
        or ""
    ).strip()
    if not _card_no:
        _card_match = re.search(r"#\s*([a-z0-9\-]+)", _title_lower)
        if _card_match:
            _card_no = str(_card_match.group(1) or "").strip()
    _year_num = 0
    try:
        _year_num = int(_r.get("year") or _r.get("card_year") or 0)
    except (TypeError, ValueError):
        _year_num = 0
    if not _year_num:
        _year_match = re.search(r"\b(19|20)\d{2}\b", _title)
        if _year_match:
            try:
                _year_num = int(_year_match.group(0))
            except (TypeError, ValueError):
                _year_num = 0
    _common_modern_commodity = False
    _common_modern_reason = ""
    try:
        _common_modern_commodity, _common_modern_reason = _classify_common_modern_row(
            product=_product_norm or _product_raw,
            year_num=_year_num,
            card_no=_card_no,
            subset=_subset_norm or _subset_raw,
            parallel=_parallel_raw,
            serial_bucket="serial" if _has_serial else "",
            grade_state=_grade_state or "raw",
            is_auto=_has_auto,
            is_mem=_has_mem,
            title=_title,
        )
    except Exception:
        _common_modern_commodity = False
        _common_modern_reason = ""
    _plain_parallel_block, _plain_parallel_reason = _is_plain_parallel_without_endgame_support(_r)
    _listing_signal_ok, _listing_signal_reason = _listing_has_strong_chase_signal(_r)
    _premium_classifier = premium_lane_classifier_signals(_r)
    _trusted_lane_allow, _trusted_lane_reason = _trusted_premium_lane_authority(_r)
    if _trusted_lane_allow:
        _r["trusted_premium_lane_authority"] = True
        _r["premium_lane"] = 1
        _r["premium_lane_reason"] = _trusted_lane_reason
        _premium_classifier = dict(_premium_classifier or {})
        _classifier_reasons_override = list(_premium_classifier.get("reasons") or [])
        if _trusted_lane_reason not in _classifier_reasons_override:
            _classifier_reasons_override.append(_trusted_lane_reason)
        _premium_classifier["premium_lane"] = True
        _premium_classifier["reasons"] = _classifier_reasons_override
    _true_premium_subset = bool(
        _lane_type == "premium_subset"
        or (_subset_norm and bool((_ENDGAME_SUBSET_REGISTRY.get(_subset_norm) or {}).get("endgame")))
        or (_listing_signal_ok and _listing_signal_reason in {"endgame_subset", "premium_subset_aura", "field_level_premium_color"})
        or bool(_premium_classifier.get("premium_lane"))
    )
    _endgame_product_support = bool(
        _product_tier == "ENDGAME"
        or _endgame_tier == "endgame"
        or _chase_class == "ENDGAME_CHASE"
    )
    _premium_mem_support = bool(
        _has_auto
        or (
            _has_mem
            and not _mem_junk
            and (_product_tier in {"PREMIUM", "ENDGAME"} or _endgame_tier in {"endgame", "premium_secondary"})
        )
    )
    _explicit_premium_lane_approval = bool(
        bool(_r.get("lane_approved"))
        and bool(_r.get("spec_premium_lane"))
        and _lane_type in {"auto", "patch", "serial_parallel", "premium_subset", "ssp_case_hit"}
    )
    _base_parallel_family = bool(
        _common_modern_commodity
        or _plain_parallel_block
        or (not _has_serial and _parallel_raw in _COMMON_MODERN_COMMODITY_PARALLELS)
    )
    _commodity_lane = bool(
        bool(_r.get("commodity_suppressed"))
        or bool(_r.get("commercially_suppressed"))
        or _commodity_reason in {"common_rookie_non_endgame", "commodity_lane"}
        or _common_rookie
        or _common_modern_commodity
        or _chase_class == "COMMODITY"
    )
    _non_endgame_rookie = bool(
        _common_rookie
        or (
            _rookie_signal
            and not _has_serial
            and not _has_auto
            and not _true_premium_subset
            and not _endgame_product_support
        )
    )
    _premium_lane_pass = bool(
        _true_premium_subset
        or _has_serial
        or _premium_mem_support
        or _endgame_product_support
        or _explicit_premium_lane_approval
        or bool(_premium_classifier.get("premium_lane"))
    )
    _blocked = bool(
        _base_parallel_family
        and _commodity_lane
        and _non_endgame_rookie
        and not _premium_lane_pass
    )
    _reasons: List[str] = []
    if _blocked:
        if _commodity_lane:
            _reasons.append("commodity_lane")
        if _base_parallel_family:
            _reasons.append("base_parallel_family")
        if _non_endgame_rookie:
            _reasons.append("non_endgame_rookie")
        if not _has_serial and not _has_auto and not _true_premium_subset and not _premium_mem_support:
            _reasons.append("no_serial_no_auto_no_premium_subset")
    _classifier_reasons = list(_premium_classifier.get("reasons") or [])
    if bool(_premium_classifier.get("premium_lane")):
        _reasons = [r for r in _reasons if r not in {"commodity_lane", "base_parallel_family", "non_endgame_rookie", "no_serial_no_auto_no_premium_subset"}]
        _blocked = False
    print(
        f"[TRUSTED_PREMIUM_LANE_ASSERT] "
        f"title={_title[:160]} "
        f"premium_lane={1 if bool(_premium_classifier.get('premium_lane')) else 0} "
        f"premium_lane_reason={_r.get('premium_lane_reason')} "
        f"research_only={_r.get('_research_only_price_check')} "
        f"research_reason={_r.get('_research_only_reason')}"
    )
    print(
        f"[PREMIUM_LANE_CLASSIFIER] title={_title[:120]} product={str(_premium_classifier.get('product') or _product_norm or _product_raw)[:48]} "
        f"subset={str(_premium_classifier.get('subset') or _subset_norm or _subset_raw)[:40]} "
        f"parallel={str(_premium_classifier.get('parallel') or _parallel_raw)[:48]} "
        f"serial={str(_premium_classifier.get('serial') or _serial_raw)[:24]} "
        f"grade={str(_premium_classifier.get('grade') or _grade_state)[:24]} "
        f"premium_lane={1 if bool(_premium_classifier.get('premium_lane')) else 0} reasons={_classifier_reasons}"
    )
    return {
        "blocked": _blocked,
        "reasons": _reasons,
        "lane_type": _lane_type,
        "parallel": _parallel_raw,
        "subset": _subset_norm or _subset_raw,
        "common_modern_reason": _common_modern_reason,
        "plain_parallel_reason": _plain_parallel_reason,
        "premium_lane": bool(_premium_classifier.get("premium_lane")),
        "premium_lane_reasons": _classifier_reasons,
    }


def _stamp_valuation_provenance(row: Dict[str, Any]) -> Dict[str, Any]:
    _row = row or {}
    _row["_valuation_contract_version"] = str(
        _row.get("_valuation_contract_version") or TRUE_MV_CONTRACT_VERSION
    )
    _row["_valuation_source_module"] = str(
        _row.get("_valuation_source_module") or VALUATION_SOURCE_MODULE
    )
    _row["_valuation_publish_stage"] = str(
        _row.get("_valuation_publish_stage") or VALUATION_PUBLISH_STAGE
    )
    _row["_valuation_apply_guard"] = str(
        _row.get("_valuation_apply_guard") or VALUATION_APPLY_GUARD
    )
    return _row


def _resolved_exact_comp_count(row: Dict[str, Any]) -> int:
    _row = row or {}
    _count = 0
    try:
        _count = max(_count, int(float(_row.get("trusted_exact_comp_count") or 0)))
    except (TypeError, ValueError):
        _count = max(_count, 0)
    try:
        _count = max(_count, int(float(_row.get("exact_comp_count") or 0)))
    except (TypeError, ValueError):
        _count = max(_count, 0)
    _trusted_rows = _row.get("trusted_detail_rows")
    if isinstance(_trusted_rows, list):
        _count = max(_count, len(_trusted_rows))
    return max(0, int(_count or 0))


def _final_board_true_contract_reasons(row: Dict[str, Any]) -> List[str]:
    _row = _stamp_valuation_provenance(row)
    if _identity_not_clean_truth_hard_block(_row):
        return ["identity_not_clean_truth_block"]
    if bool(_row.get("_weak_base_truth_block")) or _is_weak_base_truth_block_case(_row):
        return ["weak_base_truth_block"]
    _truth = str(_row.get("_valuation_truth_tier") or _row.get("valuation_truth_tier") or "").strip().upper()
    _truth_level = str(_row.get("valuation_truth_level") or "").strip().upper()
    _exact_comp_count = _resolved_exact_comp_count(_row)
    _trusted_exact = int(_row.get("trusted_exact_comp_count") or 0)
    _exact_truth_rescued = bool(_row.get("exact_truth_rescued"))
    _allow_exact_truth = bool(
        _exact_comp_count >= 1
        and (
            _exact_truth_rescued
            or _truth_level in {"EXACT", "EXACT_RESCUE"}
            or _trusted_exact >= 1
        )
    )
    if _allow_exact_truth:
        return []
    if _truth != "TRUE":
        return []
    _source = _valuation_source_clean(_row)
    _true_mv = _safe_float(_row.get("true_market_value") or _row.get("market_value_true"))
    _reasons: List[str] = []
    if _source != "exact_comp_engine":
        _reasons.append("source_not_exact_comp_engine")
    if _exact_comp_count < 2:
        _reasons.append("exact_comp_count_lt_2")
    if not _true_mv or _true_mv <= 0:
        _reasons.append("true_mv_missing")
    return _reasons


def _apply_final_board_true_guard(row: Dict[str, Any], *, trace_tag: str = "") -> Dict[str, Any]:
    _row = _stamp_valuation_provenance(row or {})
    _carry_canonical_serial_identity(_row)
    _title = str(_row.get("title") or _row.get("source_title") or "").strip()
    if _apply_fake_serial_base_promo_hard_block(_row, stage="final_true_contract", final_true_allowed=0):
        _log_final_truth_assert(_row, title=_title)
        return _row
    if _apply_identity_not_clean_truth_block(_row, stage="final_true_contract"):
        _row["true_market_value"] = None
        _row["market_value_true"] = None
        _row["has_true_market_value"] = False
        _log_final_truth_assert(_row, title=_title)
        return _row
    _truth = str(_row.get("_valuation_truth_tier") or _row.get("valuation_truth_tier") or "").strip().upper() or "NONE"
    _truth_level = str(_row.get("valuation_truth_level") or "").strip().upper() or "NONE"
    _source = _valuation_source_clean(_row) or "none"
    _true_mv = _safe_float(_row.get("true_market_value") or _row.get("market_value_true"))
    _review_estimate = (
        _safe_float(_row.get("review_estimate_value"))
        or _safe_float(_row.get("anchored_estimate_value"))
        or _safe_float(_row.get("market_value_raw"))
    )
    _exact_comp_count = _resolved_exact_comp_count(_row)
    _trusted_exact = int(_row.get("trusted_exact_comp_count") or 0)
    _exact_truth_rescued = bool(_row.get("exact_truth_rescued"))
    _row["exact_comp_count"] = int(_exact_comp_count or 0)
    _row["source"] = _source
    _row["valuation_source_clean"] = _source
    _fallback_locked = bool(
        _row.get("_mv_truth_locked_review")
        and (
            str(_row.get("_mv_truth_lock_reason") or "").strip().lower().startswith("fallback")
            or _source in {"fallback", "structured_fallback", "fallback_comp_support", "fallback_review", "structured_review", "price_anchor_fallback"}
        )
    )
    _weak_identity_downgrade = bool(
        str(_row.get("commercial_risk_flag") or "").strip().upper() == "WEAK_IDENTITY"
        or (
            str(_row.get("identity_confidence") or "").strip().upper() == "LOW"
            and str(_row.get("exact_truth_rescue_reason") or "").strip() == "missing_subset_or_card_number"
        )
    )
    if not bool(_row.get("_parallel_serial_locator_override")):
        _parallel_locator_ok, _parallel_locator_reason = _has_valid_parallel_serial_locator(_row)
        if _parallel_locator_ok:
            _row["_parallel_serial_locator_override"] = True
            _row["_parallel_serial_locator_override_reason"] = _parallel_locator_reason
    if _weak_identity_downgrade and bool(_row.get("_parallel_serial_locator_override")):
        _weak_identity_downgrade = False
        _row["identity_confidence"] = "HIGH"
        _row["commercial_risk_flag"] = ""
        print(
            f"[FINAL_TRUE_CONTRACT_OVERRIDE] title={str((_row or {}).get('title') or '')[:160]} "
            f"reason=parallel_serial_locator_override"
        )
    if _weak_identity_downgrade:
        _premium_insert_survivor_allow, _premium_insert_survivor_reason = _premium_insert_identity_survivor(_row)
        if _premium_insert_survivor_allow:
            _stamp_premium_insert_identity_survivor(_row, _premium_insert_survivor_reason)
            _weak_identity_downgrade = False
            print(
                f"[FINAL_TRUE_CONTRACT_OVERRIDE] title={str((_row or {}).get('title') or '')[:160]} "
                f"reason={_premium_insert_survivor_reason}"
            )
    if _apply_weak_base_truth_block(_row):
        print(
            f"[WEAK_BASE_TRUTH_ASSERT] title={_title[:160]} "
            f"truth={_row.get('valuation_truth_tier')} "
            f"truth_level={_row.get('valuation_truth_level')} "
            f"reason=final_true_contract_block"
        )
        _log_final_truth_assert(_row, title=_title)
        return _row
    if _fallback_locked and not bool(_row.get("exact_rescue_perma_block")):
        _stamp_exact_rescue_permablock(_row, "fallback_locked", title=_title)
    if _weak_identity_downgrade and not bool(_row.get("exact_rescue_perma_block")):
        _stamp_exact_rescue_permablock(_row, "missing_subset_or_card_number", title=_title)
    if (
        bool(_row.get("_parallel_serial_locator_override"))
        and bool(_row.get("exact_rescue_perma_block"))
        and str(_row.get("exact_rescue_perma_block_reason") or "").strip() == "missing_subset_or_card_number"
    ):
        _row["exact_rescue_perma_block"] = False
        _row["exact_rescue_perma_block_reason"] = ""
        _row["_mv_truth_locked_review"] = False
        _row["_mv_truth_lock_kind"] = ""
        _row["_mv_truth_lock_reason"] = ""
        print(
            f"[FINAL_TRUE_CONTRACT_OVERRIDE] title={str((_row or {}).get('title') or '')[:160]} "
            f"reason=parallel_serial_locator_override"
        )
    _perma_block = bool(_row.get("exact_rescue_perma_block"))
    if _perma_block:
        _premium_insert_survivor_allow, _premium_insert_survivor_reason = _premium_insert_identity_survivor(_row)
        if _premium_insert_survivor_allow:
            _stamp_premium_insert_identity_survivor(_row, _premium_insert_survivor_reason)
            _perma_block = False
    if trace_tag:
        print(
            f"[{trace_tag}] title={_title[:140]} truth={_truth} source={_source} "
            f"true_mv={round(float(_true_mv), 2) if _true_mv and _true_mv > 0 else None} "
            f"review_estimate={round(float(_review_estimate), 2) if _review_estimate and _review_estimate > 0 else None} "
            f"exact_comp_count={_exact_comp_count} "
            f"valuation_contract_version={_row.get('_valuation_contract_version') or TRUE_MV_CONTRACT_VERSION}"
        )
    _allow_exact_truth = bool(
        not _perma_block
        and not _fallback_locked
        and not _weak_identity_downgrade
        and _trusted_exact >= 1
        and _exact_comp_count >= 1
        and (
            _exact_truth_rescued
            or _truth_level in {"EXACT", "EXACT_RESCUE"}
            or _trusted_exact >= 1
        )
    )
    if _perma_block:
        print(
            f"[FINAL_TRUE_CONTRACT_DENY] title={_title[:140]} "
            f"reason={_row.get('exact_rescue_perma_block_reason')}"
        )
        _review_out = (
            _review_estimate
            or _safe_float(_row.get("review_estimate_value"))
            or _safe_float(_row.get("anchored_estimate_value"))
            or _safe_float(_row.get("market_value_raw"))
            or _safe_float(_row.get("current_price") or _row.get("current_bid") or _row.get("price"))
        )
        _review_out = round(float(_review_out), 2) if _review_out and _review_out > 0 else None
        _row["true_market_value"] = None
        _row["market_value_true"] = None
        _row["market_value"] = None
        _row["mv_value"] = None
        _row["mv_mid"] = None
        _row["review_estimate_value"] = _review_out
        _row["_valuation_truth_tier"] = "REVIEW"
        _row["valuation_truth_tier"] = "REVIEW"
        _row["valuation_truth_level"] = "REVIEW_LOCKED"
        _row["exact_truth_rescued"] = False
        _row["_mv_truth_locked_review"] = True
        _row["_mv_truth_lock_kind"] = "hard"
        if not str(_row.get("_mv_truth_lock_reason") or "").strip():
            _row["_mv_truth_lock_reason"] = str(_row.get("exact_rescue_perma_block_reason") or "exact_rescue_perma_block")
        _stamp_review_truth_class(_row)
        _log_final_truth_assert(_row, title=_title)
        return _row
    if _allow_exact_truth:
        _bridge_true_mv = (
            _true_mv
            or _safe_float(_row.get("true_mv_rescued"))
            or _safe_float(_row.get("review_estimate_value"))
            or _safe_float(_row.get("review_estimate"))
            or _safe_float(_row.get("market_value_raw"))
            or _safe_float(_row.get("market_value"))
            or _safe_float(_row.get("mv_value"))
        )
        if _bridge_true_mv is not None and _bridge_true_mv > 0:
            _bridge_true_mv = round(float(_bridge_true_mv), 2)
            _row["true_market_value"] = _bridge_true_mv
            _row["market_value_true"] = _bridge_true_mv
            _row["has_true_market_value"] = True
        _row["_valuation_truth_tier"] = "TRUE"
        _row["valuation_truth_tier"] = "TRUE"
        if _truth_level not in {"EXACT", "EXACT_RESCUE"}:
            _row["valuation_truth_level"] = "EXACT_RESCUE" if _exact_truth_rescued else "EXACT"
        print(
            f"[FINAL_TRUE_CONTRACT_ALLOW] title={_title[:140]} "
            f"exact_truth_rescued={1 if _exact_truth_rescued else 0} "
            f"trusted_exact={_trusted_exact} truth={_row.get('valuation_truth_tier') or 'NONE'} "
            f"truth_level={_row.get('valuation_truth_level') or 'NONE'} "
            f"true_mv={round(float(_bridge_true_mv), 2) if _bridge_true_mv and _bridge_true_mv > 0 else None}"
        )
        _log_final_truth_assert(_row, title=_title)
        return _row
    _reasons = _final_board_true_contract_reasons(_row)
    if not _reasons:
        _log_final_truth_assert(_row, title=_title)
        return _row
    print(
        f"[FINAL_TRUE_CONTRACT_BLOCK] title={_title[:140]} reason={'|'.join(_reasons)}"
    )
    for _reason in _reasons:
        print(
            f"[FINAL_BOARD_TRUE_REASON] title={_title[:140]} truth={_truth} source={_source} "
            f"true_mv={round(float(_true_mv), 2) if _true_mv and _true_mv > 0 else None} "
            f"review_estimate={round(float(_review_estimate), 2) if _review_estimate and _review_estimate > 0 else None} "
            f"exact_comp_count={_exact_comp_count} reason={_reason} "
            f"valuation_contract_version={_row.get('_valuation_contract_version') or TRUE_MV_CONTRACT_VERSION}"
        )
    if _review_estimate is None or _review_estimate <= 0:
        _review_estimate = _safe_float(_row.get("current_price") or _row.get("current_bid") or _row.get("price"))
    _review_out = round(float(_review_estimate), 2) if _review_estimate and _review_estimate > 0 else None
    _row["true_market_value"] = None
    _row["market_value_true"] = None
    _row["market_value"] = None
    _row["mv_value"] = None
    _row["mv_mid"] = None
    _row["review_estimate_value"] = _review_out
    _row["_valuation_truth_tier"] = "REVIEW" if _review_out else "NONE"
    _row["valuation_truth_tier"] = _row["_valuation_truth_tier"]
    _stamp_review_truth_class(_row)
    _row["has_true_market_value"] = False
    _row["market_value_mode"] = "review_estimate" if _review_out else "none"
    _row["valuation_mode"] = _row["market_value_mode"]
    _row["mode"] = _row["market_value_mode"]
    _row["bid_mode"] = _row["market_value_mode"]
    print(
        f"[FINAL_BOARD_TRUE_BLOCK] title={_title[:140]} source={_source} "
        f"exact_comp_count={_exact_comp_count} true_mv={round(float(_true_mv), 2) if _true_mv and _true_mv > 0 else None} "
        f"review_estimate={_review_out} final_truth={_row.get('valuation_truth_tier') or 'NONE'} "
        f"valuation_contract_version={_row.get('_valuation_contract_version') or TRUE_MV_CONTRACT_VERSION}"
    )
    _stamp_review_truth_class(_row)
    _log_final_truth_assert(_row, title=_title)
    return _row


def _stamp_mv_truth_fields(row: Dict[str, Any]) -> Dict[str, Any]:
    _row = row or {}
    _stamp_valuation_provenance(_row)
    _source = _valuation_source_clean(_row)
    _truth_locked_review = bool(_row.get("_mv_truth_locked_review"))
    _review_lock_kind_value = _review_lock_kind(_row, _source)

    # ── VALUATION AUTHORITY LOCK ──────────────────────────────────────────────
    # If this row was already stamped with a stronger source's value, block any
    # weaker source from overwriting it on a subsequent stamp call.
    # Only fires when: (a) a prior value exists, (b) prior source is stronger,
    # (c) the incoming source is different and weaker.
    _lock_true_mv   = _safe_float(_row.get("market_value_true")) or _safe_float(_row.get("true_market_value"))
    _lock_review_mv = _safe_float(_row.get("review_estimate_value"))
    _lock_source    = str(_row.get("mv_source") or _row.get("market_value_source") or "").strip().lower()
    _lock_truth     = str(_row.get("_valuation_truth_tier") or _row.get("valuation_truth_tier") or "").strip().upper()
    _lock_has_value = bool(
        (_lock_true_mv and _lock_true_mv > 0) or (_lock_review_mv and _lock_review_mv > 0)
    )
    if (
        _lock_has_value
        and _lock_truth in {"TRUE", "REVIEW"}
        and _lock_source
        and _source != _lock_source                          # different source
        and not _truth_locked_review                         # not already REVIEW-locked (let guard run)
        and _valuation_source_rank(_lock_source) < _valuation_source_rank(_source)  # existing stronger
    ):
        _lock_mv_display = _lock_true_mv or _lock_review_mv
        _lock_title = str(_row.get("title") or _row.get("source_title") or "")[:100]
        print(
            f"[MV_AUTHORITY_LOCK] title={_lock_title} "
            f"locked_source={_lock_source} rank={_valuation_source_rank(_lock_source)} "
            f"blocked_source={_source} rank={_valuation_source_rank(_source)}"
        )
        print(
            f"[MV_OVERWRITE_BLOCK] title={_lock_title} "
            f"keeping source={_lock_source} mv={_lock_mv_display} truth={_lock_truth} "
            f"blocked_source={_source} reason=authority_lock"
        )
        return _row   # preserve stronger stamped value — do not overwrite
    # Allowed overwrite — log when a stronger source is replacing an existing weaker one
    if (
        _lock_has_value
        and _lock_truth in {"TRUE", "REVIEW"}
        and _lock_source
        and _source != _lock_source
        and _valuation_source_rank(_source) < _valuation_source_rank(_lock_source)  # NEW is stronger
    ):
        _lock_mv_display = _lock_true_mv or _lock_review_mv
        _lock_title = str(_row.get("title") or _row.get("source_title") or "")[:100]
        print(
            f"[MV_AUTHORITY_REPLACE] title={_lock_title} "
            f"old_source={_lock_source} old_mv={_lock_mv_display} "
            f"new_source={_source} reason=stronger_source_takes_over"
        )
    # ── end authority lock ────────────────────────────────────────────────────
    _counts: List[int] = []
    for _field_name in (
        "mv_comp_count",
        "comp_count",
        "comps_count",
        "dominant_comp_count",
        "market_lane_comp_count",
        "market_lane_recent_count",
    ):
        try:
            _val = int(_row.get(_field_name) or 0)
        except (TypeError, ValueError):
            _val = 0
        if _val > 0:
            _counts.append(_val)
    _comp_count = max(_counts) if _counts else 0
    _row = _stamp_comp_truth_split(_row, emit_log=False)
    _trusted_exact_comp_count = int(_row.get("trusted_exact_comp_count") or 0)
    _support_comp_count = int(_row.get("support_comp_count") or 0)
    _raw_mv = (
        _safe_float(_row.get("market_value_raw"))
        or _safe_float(_row.get("raw_market_value"))
        or _safe_float(_row.get("market_value"))
        or _safe_float(_row.get("mv_value"))
    )
    _explicit_true_mv = _safe_float(_row.get("true_market_value"))
    _explicit_review_mv = _safe_float(_row.get("review_estimate_value"))
    _true_mv = _safe_float(_row.get("market_value_true"))
    _anchor_estimate = _safe_float(_row.get("anchored_estimate_value"))
    _truth_tier = str(_row.get("_valuation_truth_tier") or _row.get("valuation_truth_tier") or "").strip().upper()
    _confidence = _normalize_mv_confidence_label(
        _row.get("mv_confidence_strict")
        or _row.get("valuation_confidence")
        or _row.get("confidence")
        or _row.get("mv_confidence")
        or ""
    )
    _title = str(_row.get("title") or _row.get("source_title") or "").strip()
    _high_end_premium = _is_premium_card(_row) and any(
        _token in _title.lower()
        for _token in ("national treasures", "immaculate", "flawless", "spectra")
    )
    _support_profile = _support_truth_profile(_row)
    _stamp_hydrated_identity_snapshot(_row, emit_log=True)
    _identity_truth_blocked = _apply_identity_not_clean_truth_block(_row, stage="mv_truth_pre_accelerator")
    _locator_ok, _locator_reason = _has_valid_insert_locator(_row)
    print(
        f"[INSERT_LOCATOR_CHECK] title={str((_row or {}).get('title') or '')[:160]} "
        f"ok={_locator_ok} "
        f"reason={_locator_reason} "
        f"insert_family={_row.get('_hydrated_insert_family') or _row.get('insert_family')} "
        f"parallel_family={_row.get('_hydrated_parallel_family') or _row.get('parallel_family')} "
        f"serial_denominator={_row.get('_hydrated_serial_denominator') or _row.get('serial_denominator')} "
        f"serial={_row.get('_hydrated_serial') or _row.get('serial')} "
        f"parsed_serial={_row.get('parsed_serial')} "
        f"card_number={_row.get('_hydrated_card_number') or _row.get('card_number')}"
    )
    if _locator_ok and _locator_reason != "card_number_present":
        _row["_insert_locator_override"] = True
        _row["_insert_locator_override_reason"] = _locator_reason
        print(
            f"[INSERT_LOCATOR_OVERRIDE] title={str((_row or {}).get('title') or '')[:160]} "
            f"reason={_locator_reason}"
        )
    print(
        f"[PRE_ACCELERATOR_ROW] title={str((_row or {}).get('title') or '')[:160]} "
        f"lane_type={_row.get('lane_type')} "
        f"insert_family={_row.get('insert_family')} "
        f"parallel_family={_row.get('parallel_family')} "
        f"card_number={_row.get('card_number')} "
        f"grade={_row.get('grade')} "
        f"tier={_row.get('subscription_lane_tier')} "
        f"identity_is_clean={_row.get('identity_is_clean')}"
    )
    _exact_truth_rescue_ok, _exact_truth_rescue_reason = _exact_truth_accelerator(_row)
    if _identity_truth_blocked or _apply_identity_not_clean_truth_block(_row, stage="mv_truth_pre_exact_rescue"):
        _identity_truth_blocked = True
        _exact_truth_rescue_ok = False
        _exact_truth_rescue_reason = "identity_not_clean_truth_block"
        _trusted_exact_comp_count = 0
        _row["trusted_exact_comp_count"] = 0
        _row["exact_comp_count"] = 0
        _truth_tier = "NONE"
    if _apply_weak_base_truth_block(_row):
        _exact_truth_rescue_ok = False
        _exact_truth_rescue_reason = "weak_base_truth_block"
        _trusted_exact_comp_count = 0
        _row["trusted_exact_comp_count"] = 0
        _row["exact_comp_count"] = 0
        _truth_tier = "REVIEW"
        print(
            f"[WEAK_BASE_TRUTH_ASSERT] title={str((_row or {}).get('title') or '')[:160]} "
            f"truth={_row.get('valuation_truth_tier')} "
            f"truth_level={_row.get('valuation_truth_level')} "
            f"reason=weak_base_truth_block"
        )
    if bool(_row.get("exact_rescue_perma_block")):
        _exact_truth_rescue_ok = False
        _exact_truth_rescue_reason = str(_row.get("exact_rescue_perma_block_reason") or "exact_rescue_perma_block")
    if _apply_fake_serial_base_promo_hard_block(_row, stage="exact_rescue_authority", final_true_allowed=0):
        _exact_truth_rescue_ok = False
        _exact_truth_rescue_reason = "fake_serial_base_promo"
        _trusted_exact_comp_count = 0
        _row["trusted_exact_comp_count"] = 0
        _row["exact_comp_count"] = 0
        _truth_tier = "NONE"
    _exact_truth_rescue_authority = bool(_exact_truth_rescue_ok)
    _exact_identity_contract = _exact_rescue_identity_contract(_row)
    _weak_exact_identity = bool(
        not bool(_exact_identity_contract.get("valid_identity"))
        and int(_row.get("raw_exact_match_count") or 0) >= 3
    )
    if _identity_truth_blocked or _apply_identity_not_clean_truth_block(_row, stage="pre_exact_rescue_authority"):
        _identity_truth_blocked = True
        _exact_truth_rescue_authority = False
        _exact_truth_rescue_ok = False
        _exact_truth_rescue_reason = "identity_not_clean_truth_block"
        _truth_tier = "NONE"
    if _exact_truth_rescue_authority:
        _row["exact_truth_rescued"] = True
        _row["exact_truth_rescue_reason"] = str(_exact_truth_rescue_reason or "already_trusted")
        _truth_tier = "TRUE"
        _row["valuation_truth_tier"] = "TRUE"
        _row["_valuation_truth_tier"] = "TRUE"
        _row["valuation_truth_level"] = "EXACT_RESCUE"
        _row["identity_confidence"] = "HIGH"
        _row["commercial_risk_flag"] = ""
        _trusted_exact_comp_count = max(_trusted_exact_comp_count, 1)
        _row["trusted_exact_comp_count"] = _trusted_exact_comp_count
        _row["exact_comp_count"] = _trusted_exact_comp_count
        if not list(_row.get("trusted_detail_rows") or []) and list(_row.get("raw_exact_detail_rows") or []):
            _row["trusted_detail_rows"] = list(_row.get("raw_exact_detail_rows") or [])
            print(
                f"[EXACT_RESCUE_TRUST_ROWS] title={_title[:120]} "
                f"raw_rows={len(_row.get('raw_exact_detail_rows') or [])} "
                f"trusted_rows={len(_row.get('trusted_detail_rows') or [])}"
            )
        _row["_mv_truth_locked_review"] = False
        _row["_mv_truth_lock_kind"] = ""
        _row["_mv_truth_lock_reason"] = "exact_truth_rescue"
        _row["review_lock_hard"] = False
        _row["_review_lock_hard"] = False
        _row["_mv_true_blocked"] = False
        _row["_mv_true_block_reason"] = ""
        _row["_mv_true_block_reasons"] = []
        print(
            f"[EXACT_RESCUE_AUTHORITY] title={_title[:120]} "
            f"raw_exact={int(_row.get('raw_exact_match_count') or 0)} "
            f"support={int(_row.get('support_comp_count') or 0)} "
            f"trusted_exact={_trusted_exact_comp_count} "
            f"reason={_exact_truth_rescue_reason}"
        )
        if (_true_mv is None or _true_mv <= 0):
            _exact_true_mv_bridge = _safe_float(
                _row.get("review_estimate_value")
                or _row.get("review_estimate")
                or _row.get("market_value")
                or _row.get("market_value_raw")
                or _raw_mv
            )
            if _exact_true_mv_bridge is not None and _exact_true_mv_bridge > 0:
                _true_mv = round(float(_exact_true_mv_bridge), 2)
                _explicit_true_mv = _true_mv
                _row["true_mv_rescued"] = _true_mv
                _row["market_value_true"] = _true_mv
                _row["true_market_value"] = _true_mv
                print(
                    f"[EXACT_RESCUE_TRUE_MV] title={_title[:120]} true_mv={_true_mv}"
                )
        _truth_locked_review = False
        _review_lock_kind_value = ""
    _strong_one_comp = bool(
        _comp_count == 1
        and _source in {"near_family_support", "premium_scarcity_bucket_support", "hybrid_near_lane"}
        and _high_end_premium
        and _confidence in {"MEDIUM", "HIGH"}
    )
    _review_estimate_override: Optional[float] = None  # set by patch-family contamination guard
    if _source in {"structured_fallback", "fallback", "fallback_comp_support", "structured_review", "fallback_review"} and not _exact_truth_rescue_authority:
        _true_mv = None
        _truth_tier = "REVIEW"
        _derived_anchor = round(_raw_mv, 2) if _raw_mv and _raw_mv > 0 else None
        _truth_locked_review = True
        _row["_mv_truth_locked_review"] = True
        _row["_mv_truth_lock_kind"] = "hard"
        _row["_mv_truth_lock_reason"] = f"fallback_source:{_source}"
        _review_lock_kind_value = "hard"
        print(
            f"[REVIEW_LOCK_HARD] title={_title[:120]} source={_source} reason=fallback_source"
        )
        _stamp_exact_rescue_permablock(_row, "fallback_locked", title=_title)
        if not str(_row.get("exact_rescue_perma_block_reason") or "").strip():
            _row["exact_rescue_perma_block_reason"] = "fallback_truth_blocked"
        print(
            f"[MV_FALLBACK_BLOCK] title={_title[:120]} source={_source} "
            f"truth=REVIEW true_mv=None"
        )
    elif _explicit_true_mv is not None and _explicit_true_mv > 0:
        _true_mv = round(_explicit_true_mv, 2)
        _derived_anchor = None
        _truth_tier = "TRUE"
    elif _true_mv is not None and _true_mv > 0:
        _true_mv = round(_true_mv, 2)
        _derived_anchor = None
        _truth_tier = "TRUE"
    else:
        _derived_anchor = None
        if _raw_mv and _raw_mv > 0:
            if _comp_count >= 2 and _source not in _MV_NON_TRUE_SOURCES and _source not in _MV_ANCHOR_ONLY_SOURCES:
                # ── SAME-CARD SANITY LAYER 1: medium sources on patch cards need ≥4 comps
                # medium_comp_engine is in _REVIEW_ONLY_MV_SOURCES (defined but previously unwired).
                # For patch-family cards, 2 comps from a medium source is not sufficient certainty.
                _medium_patch_insufficient = (
                    _source in _REVIEW_ONLY_MV_SOURCES
                    and _is_patch_guard_eligible(_row)
                    and _comp_count < 4
                )
                if _medium_patch_insufficient:
                    # Demote: REVIEW with conservative anchor off value_range_low
                    _true_mv = None
                    _truth_tier = "REVIEW"
                    _range_low_anchor = _safe_float(_row.get("value_range_low"))
                    _derived_anchor = (
                        round(_range_low_anchor * 1.15, 2)
                        if _range_low_anchor and _range_low_anchor > 0
                        else round(_raw_mv * 0.68, 2)
                    )
                    print(
                        f"[MV_SAME_CARD_ANCHOR] title={_title[:100]} source={_source} "
                        f"comp_count={_comp_count} reason=insufficient_comps_medium_patch "
                        f"anchor={_derived_anchor}"
                    )
                else:
                    _true_mv = round(_raw_mv, 2)
                    _truth_tier = "TRUE"
                    # ── TIER E safety haircut: near-family comps → 10% conservative discount ──
                    if bool(_support_profile.get("near_family_haircut")) and _true_mv > 0:
                        _true_mv = round(_true_mv * 0.90, 2)
                        _row["_near_family_haircut_applied"] = True
                        print(
                            f"[NEAR_FAMILY_HAIRCUT] title={_title[:100]} source={_source} "
                            f"raw={_raw_mv} haircut_mv={_true_mv}"
                        )
            elif _strong_one_comp:
                _true_mv = round(_raw_mv, 2)
                _truth_tier = "TRUE"
            else:
                _true_mv, _derived_anchor = _resolve_mv_truth_fields(_raw_mv, _source, _comp_count)
                if _true_mv:
                    _truth_tier = "TRUE"
        else:
            _true_mv = None

    # ── ENFORCE PART 1: Patch-family contamination guard — FINAL ENFORCEMENT ──
    # Runs AFTER all truth branches so it catches explicit_true_mv, true_mv, and raw_mv paths.
    # Requires title in the row (injected into payload before _stamp_mv_truth_fields is called).
    if (
        _truth_tier == "TRUE"
        and _weak_exact_identity
        and (
            bool(_row.get("_parallel_serial_locator_override"))
            or bool(_row.get("_insert_locator_override"))
        )
    ):
        _weak_exact_identity = False
        if bool(_row.get("_parallel_serial_locator_override")):
            print(
                f"[FINAL_TRUE_CONTRACT_OVERRIDE] title={str((_row or {}).get('title') or '')[:160]} "
                f"reason=parallel_serial_locator_override"
            )
        else:
            print(
                f"[REVIEW_LOCK_OVERRIDE] title={str((_row or {}).get('title') or '')[:160]} "
                f"reason=valid_insert_locator_override"
            )
    _premium_insert_survivor_allow, _premium_insert_survivor_reason = _premium_insert_identity_survivor(_row)
    _topps_black_survivor_allow, _topps_black_survivor_reason = _premium_topps_black_auto_survivor(_row)
    if _truth_tier == "TRUE" and _weak_exact_identity and _topps_black_survivor_allow:
        _stamp_premium_topps_black_auto_survivor(_row, _topps_black_survivor_reason)
        _weak_exact_identity = False
        print(
            f"[FINAL_TRUE_CONTRACT_OVERRIDE] title={str((_row or {}).get('title') or '')[:160]} "
            f"reason={_topps_black_survivor_reason}"
        )
    if _truth_tier == "TRUE" and _weak_exact_identity and _premium_insert_survivor_allow:
        _stamp_premium_insert_identity_survivor(_row, _premium_insert_survivor_reason)
        _weak_exact_identity = False
        print(
            f"[FINAL_TRUE_CONTRACT_OVERRIDE] title={str((_row or {}).get('title') or '')[:160]} "
            f"reason={_premium_insert_survivor_reason}"
        )
    if _truth_tier == "TRUE" and _weak_exact_identity:
        _raw_for_review = _true_mv or _raw_mv or _explicit_true_mv or _explicit_review_mv
        _true_mv = None
        _truth_tier = "REVIEW"
        _row["exact_truth_rescued"] = False
        _row["exact_truth_rescue_reason"] = "missing_subset_or_card_number"
        _row["trusted_exact_comp_count"] = 0
        _row["exact_comp_count"] = 0
        _row["trusted_detail_rows"] = []
        _row["identity_confidence"] = "LOW"
        _row["commercial_risk_flag"] = "WEAK_IDENTITY"
        _row["valuation_truth_tier"] = "REVIEW"
        _row["_valuation_truth_tier"] = "REVIEW"
        _row["valuation_truth_level"] = "SUPPORT" if _support_comp_count > 0 else "REVIEW"
        if _review_estimate_override is None and _raw_for_review and _raw_for_review > 0:
            _review_estimate_override = round(float(_raw_for_review), 2)
        _stamp_exact_rescue_permablock(_row, "missing_subset_or_card_number", title=_title)
        print(
            f"[EXACT_DOWNGRADE_WEAK_IDENTITY] title={_title[:120]} "
            f"raw_exact={int(_row.get('raw_exact_match_count') or 0)} reason=missing_subset_or_card_number"
        )

    if _truth_tier == "TRUE" and _is_patch_guard_eligible(_row):
        # Use price-agnostic parser — _extract_debug_comp_rows requires price field
        _pg_comps = _pg_parse_comps_title_only(_row.get("debug_accepted_comps_json"))
        _pg_contaminated, _pg_reason = _is_patch_family_comp_contaminated(_row, _pg_comps)
        print(
            f"[MV_PATCH_GUARD_ENFORCED] title={_title[:100]} source={_source} "
            f"comps={len(_pg_comps)} contaminated={1 if _pg_contaminated else 0} reason={_pg_reason}"
        )
        if _pg_contaminated:
            _raw_for_review = _true_mv or _raw_mv
            _true_mv = None
            _truth_tier = "REVIEW"
            _truth_locked_review = True
            _row["_mv_truth_locked_review"] = True
            _row["_mv_truth_lock_kind"] = "hard"
            _row["_mv_truth_lock_reason"] = f"patch_guard:{_pg_reason}"
            _review_lock_kind_value = "hard"
            print(
                f"[REVIEW_LOCK_HARD] title={_title[:120]} source={_source} reason=patch_guard:{_pg_reason}"
            )
            _review_estimate_override = round(float(_raw_for_review), 2) if _raw_for_review else None
            print(
                f"[MV_TRUTH_FORCED_REVIEW] title={_title[:100]} "
                f"old_truth=TRUE new_truth=REVIEW reason={_pg_reason}"
            )
    # ── end final patch guard ─────────────────────────────────────────────────

    # ── ENFORCE SAME-CARD SANITY LAYER 2: distribution-level MV reality check ──
    # Runs AFTER the patch contamination guard. Catches cases where the comp cluster
    # passes the contamination check but the price distribution signals the MV is inflated
    # (wide range, low floor, or median pulled up by outliers).
    if _truth_tier == "TRUE" and _raw_mv and _raw_mv > 0:
        _sc_saner_mv = _apply_same_card_market_sanity(_row, float(_true_mv or _raw_mv))
        if _sc_saner_mv is not None:
            _true_mv = None
            _truth_tier = "REVIEW"
            _truth_locked_review = True
            _row["_mv_truth_locked_review"] = True
            _row["_mv_truth_lock_kind"] = "hard"
            _row["_mv_truth_lock_reason"] = str(_row.get("_same_card_downgrade_reason") or "same_card_sanity")
            _review_lock_kind_value = "hard"
            print(
                f"[REVIEW_LOCK_HARD] title={_title[:120]} source={_source} "
                f"reason={_row.get('_mv_truth_lock_reason')}"
            )
            if _review_estimate_override is None or _review_estimate_override <= 0:
                _review_estimate_override = _sc_saner_mv
    # ── end same-card sanity layer 2 ─────────────────────────────────────────

    if _truth_tier == "TRUE":
        _mv_true_guard = _mv_true_premium_lane_guard(_row)
        if bool(_mv_true_guard.get("blocked")):
            _block_reasons = list(_mv_true_guard.get("reasons") or []) or ["commodity_lane"]
            if _exact_truth_rescue_authority:
                _ignored_exact_rescue_reasons = {
                    "commodity_lane",
                    "base_parallel_family",
                    "non_endgame_rookie",
                    "no_serial_no_auto_no_premium_subset",
                }
                _remaining_block_reasons = [
                    _reason for _reason in _block_reasons
                    if _reason not in _ignored_exact_rescue_reasons
                ]
                print(
                    f"[EXACT_RESCUE_BYPASS] title={_title[:120]} "
                    f"blocked_reasons={_block_reasons} bypassed="
                    f"{[_reason for _reason in _block_reasons if _reason in _ignored_exact_rescue_reasons]}"
                )
                if not _remaining_block_reasons:
                    _row["_mv_true_blocked"] = False
                    _row["_mv_true_block_reason"] = ""
                    _row["_mv_true_block_reasons"] = []
                    _block_reasons = []
                else:
                    _block_reasons = list(_remaining_block_reasons)
            if _block_reasons:
                _raw_for_review = _true_mv or _raw_mv
                _conservative_review = (
                    _safe_float(_row.get("review_estimate_value"))
                    or _safe_float(_row.get("anchored_estimate_value"))
                    or _safe_float(_row.get("_same_card_saner_mv"))
                    or _safe_float(_row.get("value_range_low"))
                    or _safe_float(_row.get("current_price") or _row.get("current_bid") or _row.get("price"))
                )
                if _conservative_review and _raw_for_review and _conservative_review > _raw_for_review:
                    _conservative_review = _raw_for_review
                _row["_mv_true_blocked"] = True
                _row["_mv_true_block_reason"] = "|".join(_block_reasons)
                _row["_mv_true_block_reasons"] = list(_block_reasons)
                _true_mv = None
                _truth_tier = "REVIEW"
                _truth_locked_review = True
                _row["_mv_truth_locked_review"] = True
                _row["_mv_truth_lock_kind"] = "hard"
                _row["_mv_truth_lock_reason"] = f"mv_true_block:{'|'.join(_block_reasons)}"
                _review_lock_kind_value = "hard"
                print(
                    f"[MV_TRUE_BLOCK] title={_title[:120]} source={_source} "
                    f"lane_type={str(_mv_true_guard.get('lane_type') or 'none')} "
                    f"parallel={str(_mv_true_guard.get('parallel') or '')[:40]} "
                    f"subset={str(_mv_true_guard.get('subset') or '')[:40]}"
                )
                for _reason in _block_reasons:
                    print(
                        f"[MV_TRUE_BLOCK_REASON] title={_title[:120]} source={_source} reason={_reason}"
                    )
                print(
                    f"[REVIEW_LOCK_HARD] title={_title[:120]} source={_source} "
                    f"reason={_row.get('_mv_truth_lock_reason')}"
                )
                if _review_estimate_override is None and _conservative_review and _conservative_review > 0:
                    _review_estimate_override = round(float(_conservative_review), 2)
                print(
                    f"[MV_TRUE_DOWNGRADE] title={_title[:120]} source={_source} "
                    f"old_truth=TRUE new_truth=REVIEW review={_review_estimate_override}"
                )

    if _truth_locked_review and _truth_tier == "TRUE":
        print(
            f"[REPROMOTION_RECHECK] title={_title[:120]} source={_source} "
            f"lock_kind={_review_lock_kind_value or 'soft'} support_true={bool(_support_profile.get('support_truth_true'))}"
        )
        if _should_clear_review_lock(_row, _support_profile, _source):
            _truth_locked_review = False
            _row["_mv_truth_locked_review"] = False
            _row["_mv_truth_lock_kind"] = ""
            _row["_mv_truth_lock_reason"] = "cleared_by_support_truth"
            _row["_true_upgrade_allowed"] = True
            _review_lock_kind_value = ""
            print(
                f"[REVIEW_LOCK_CLEARED] title={_title[:120]} source={_source} "
                f"reason={str(_support_profile.get('reason') or 'support_truth_true')}"
            )
            print(
                f"[REPROMOTION_ALLOW] title={_title[:120]} source={_source} "
                f"tier={str(_support_profile.get('should_true_tier') or 'none')}"
            )
            print(
                f"[TRUE_UPGRADE_FINAL] title={_title[:120]} source={_source} "
                f"tier={str(_support_profile.get('should_true_tier') or 'none')}"
            )
        else:
            _preserve_reason = str(_row.get("_mv_truth_lock_reason") or _support_profile.get("reason") or "locked_review")
            if _review_lock_kind_value == "hard":
                print(
                    f"[REVIEW_LOCK_HARD] title={_title[:120]} source={_source} reason={_preserve_reason}"
                )
            else:
                print(
                    f"[REVIEW_LOCK_SOFT] title={_title[:120]} source={_source} reason={_preserve_reason}"
                )
            print(
                f"[REVIEW_LOCK_PRESERVED] title={_title[:120]} source={_source} "
                f"kind={_review_lock_kind_value or 'soft'} reason={_preserve_reason}"
            )
            print(
                f"[REPROMOTION_DENY] title={_title[:120]} source={_source} "
                f"kind={_review_lock_kind_value or 'soft'} reason={_preserve_reason}"
            )
            print(
                f"[MV_REPROMOTION_BLOCK] title={_title[:120]} source={_source} "
                f"blocked_truth=TRUE"
            )
            _truth_tier = "REVIEW"
            if _review_estimate_override is None and _true_mv and _true_mv > 0:
                _review_estimate_override = round(float(_true_mv), 2)
            _true_mv = None
            _row["_mv_truth_locked_review"] = True

    if bool(_support_profile.get("is_support_source")):
        _support_disp = _support_profile.get("dispersion")
        _support_disp_text = f"{float(_support_disp):.2f}" if isinstance(_support_disp, (int, float)) and _support_disp is not None else "na"
        _support_decision = "true" if (_truth_tier == "TRUE" and bool(_support_profile.get("support_truth_true"))) else "review"
        print(
            f"[FAMILY_ALIGNMENT_SCORE] title={_title[:120]} source={_source} "
            f"score={int(_support_profile.get('family_alignment_score') or 0)} "
            f"hits={int(_support_profile.get('alignment_hits') or 0)}"
        )
        if str(_support_profile.get("dispersion_band") or "") == "extreme":
            print(
                f"[SUPPORT_DISPERSION_EXTREME] title={_title[:120]} source={_source} "
                f"dispersion={_support_disp_text}"
            )
        else:
            print(
                f"[SUPPORT_DISPERSION_NORMAL] title={_title[:120]} source={_source} "
                f"dispersion={_support_disp_text} band={str(_support_profile.get('dispersion_band') or 'na')}"
            )
        print(
            f"[SUPPORT_TRUTH_CALIBRATE] title={_title[:120]} source={_source} "
            f"comps={int(_support_profile.get('comp_count') or 0)} "
            f"align={int(_support_profile.get('family_alignment_score') or 0)} "
            f"conf={str(_support_profile.get('confidence') or '')} decision={_support_decision}"
        )
        print(
            f"[SUPPORT_TRUTH_EVAL] title={_title[:120]} source={_source} comps={int(_support_profile.get('comp_count') or 0)} "
            f"lane={int(_support_profile.get('lane_comp_count') or 0)} strict={int(_support_profile.get('strict_comp_count') or 0)} "
            f"conf={str(_support_profile.get('confidence') or '')} dispersion={_support_disp_text} decision={_support_decision}"
        )
        # ── SUPPORT-TRUTH DISPATCH: bind decision logs to alignment profile ──────
        _sp_align_score = int(_support_profile.get("family_alignment_score") or 0)
        _sp_align_hits = int(_support_profile.get("alignment_hits") or 0)
        _sp_reason = str(_support_profile.get("reason") or "support_review_only")
        _sp_tier = str(_support_profile.get("should_true_tier") or "none")
        _sp_support_true = bool(_support_profile.get("support_truth_true"))
        _sp_comp_count = int(_support_profile.get("comp_count") or 0)
        print(
            f"[SUPPORT_TRUTH_DECISION] title={_title[:120]} source={_source} "
            f"truth_tier={_truth_tier} support_true={_sp_support_true} "
            f"score={_sp_align_score} hits={_sp_align_hits} comps={_sp_comp_count} "
            f"tier={_sp_tier} reason={_sp_reason}"
        )
        if _truth_tier == "TRUE" and not _sp_support_true:
            print(
                f"[SUPPORT_TRUE_BLOCK] title={_title[:120]} source={_source} "
                f"reason={_sp_reason}"
            )
            # When alignment is genuinely positive (score > 0), log override reason
            # so the log reader can see WHY a non-zero-alignment row still goes REVIEW
            if _sp_align_score > 0:
                print(
                    f"[SUPPORT_TRUTH_OVERRIDE_REASON] title={_title[:120]} source={_source} "
                    f"score={_sp_align_score} hits={_sp_align_hits} comps={_sp_comp_count} "
                    f"override_reason={_sp_reason} "
                    f"note=positive_alignment_but_below_threshold_see_reason"
                )
            if _review_estimate_override is None and (_true_mv or _raw_mv):
                _review_estimate_override = round(float(_true_mv or _raw_mv), 2)
            _true_mv = None
            _truth_tier = "REVIEW"
            _truth_locked_review = True
            _row["_mv_truth_locked_review"] = True
            if _review_lock_kind(_row, _source) != "hard":
                _row["_mv_truth_lock_kind"] = "soft"
                _row["_mv_truth_lock_reason"] = f"support_review:{_sp_reason}"
                _review_lock_kind_value = "soft"
                print(
                    f"[REVIEW_LOCK_SOFT] title={_title[:120]} source={_source} reason={_sp_reason}"
                )
            print(
                f"[SUPPORT_TRUTH_REVIEW] title={_title[:120]} source={_source} "
                f"reason={_sp_reason} score={_sp_align_score} hits={_sp_align_hits}"
            )
        elif _truth_tier == "TRUE":
            print(
                f"[FAMILY_ALIGNMENT_TRUE_BOOST] title={_title[:120]} source={_source} "
                f"score={_sp_align_score}"
            )
            print(
                f"[SUPPORT_TRUE_ALLOW] title={_title[:120]} source={_source} "
                f"reason={_sp_reason}"
            )
            print(
                f"[SUPPORT_TRUTH_ALLOW] title={_title[:120]} source={_source} "
                f"reason={_sp_reason} tier={_sp_tier}"
            )
            print(
                f"[SUPPORT_TRUTH_TRUE] title={_title[:120]} source={_source} "
                f"reason={_sp_reason}"
            )
        else:
            print(
                f"[SUPPORT_TRUTH_REVIEW] title={_title[:120]} source={_source} "
                f"reason={_sp_reason} score={_sp_align_score} hits={_sp_align_hits}"
            )

    _review_estimate = _explicit_review_mv if _explicit_review_mv and _explicit_review_mv > 0 else None
    # Apply patch-family contamination override (set when truth demoted TRUE→REVIEW)
    if _review_estimate is None and _review_estimate_override is not None and _review_estimate_override > 0:
        _review_estimate = float(_review_estimate_override)
    if _review_estimate is None and _anchor_estimate is not None and _anchor_estimate > 0:
        _review_estimate = round(_anchor_estimate, 2)
    if _review_estimate is None and _derived_anchor is not None:
        _review_estimate = _derived_anchor
        # Emit anchor-preserved log when source is from a real comp engine (not pure price anchor)
        if _valuation_source_rank(_source) <= 5 and _raw_mv and _raw_mv > 0:
            print(
                f"[MV_STRONG_ANCHOR_PRESERVED] title={_title[:100]} "
                f"source={_source} anchor={_derived_anchor} raw_mv={round(_raw_mv,2)} "
                f"reason=hybrid_comp_value_kept_as_review_anchor"
            )
    if _review_estimate is None and _raw_mv and _raw_mv > 0 and _source in {
        "price_anchor_fallback",
        "price_anchor_emergency",
        "near_family_support",
        "premium_scarcity_bucket_support",
        "hybrid_near_lane",
        "single_comp_conservative",
        "structured_fallback",
        "soft_watchlist_estimate",
    }:
        _review_estimate = round(_raw_mv, 2)
    _review_fallback_adjustment = _premium_serial_review_fallback_adjustment(
        _row,
        source=_source,
        truth_tier=_truth_tier,
        review_estimate=_review_estimate,
    )
    if bool(_review_fallback_adjustment.get("applied")):
        _review_estimate = _safe_float(_review_fallback_adjustment.get("review_estimate"))
    if (_truth_tier != "TRUE") and _review_estimate and _review_estimate > 0:
        _truth_tier = "REVIEW"
    _anchor_estimate = round(_anchor_estimate, 2) if _anchor_estimate is not None and _anchor_estimate > 0 else None

    if _truth_tier == "TRUE" and _trusted_exact_comp_count <= 0 and not _exact_truth_rescue_authority:
        _support_reason = "support_quality_fail" if _support_comp_count <= 0 else "support_only_no_true_mv"
        if _review_estimate_override is None and (_raw_mv or _true_mv):
            _review_estimate_override = round(float(_raw_mv or _true_mv), 2)
        _true_mv = None
        _truth_tier = "REVIEW" if (_review_estimate_override and _review_estimate_override > 0) else "NONE"
        _row["_mv_truth_locked_review"] = True
        if _review_lock_kind(_row, _source) != "hard":
            _row["_mv_truth_lock_kind"] = "soft"
            _row["_mv_truth_lock_reason"] = _support_reason
        print(
            f"[PREMIUM_LANE_DEATH] player={str(_row.get('player_name') or _row.get('target_player_name') or '')[:48]} "
            f"product={str(_row.get('target_product_family') or _row.get('product_family') or _row.get('lane_product') or '')[:48]} "
            f"lane={str(_source or 'none')[:48]} raw_exact={int(_row.get('raw_exact_match_count') or 0)} "
            f"trusted_exact={_trusted_exact_comp_count} support={_support_comp_count} "
            f"final_truth_level={_truth_tier} reason={_support_reason}"
        )

    if _raw_mv is not None and _raw_mv > 0:
        _row["market_value_raw"] = round(_raw_mv, 2)
    _row["market_value_true"] = round(_true_mv, 2) if _true_mv is not None and _true_mv > 0 else None
    _row["true_market_value"] = _row["market_value_true"]
    if not _has_true_market_value(_row):
        if _exact_truth_rescue_authority:
            _late_true_mv_bridge = _safe_float(
                _row.get("true_market_value")
                or _row.get("review_estimate_value")
                or _review_estimate
                or _explicit_review_mv
                or _row.get("market_value")
                or _row.get("market_value_raw")
                or _raw_mv
            )
            if _late_true_mv_bridge is not None and _late_true_mv_bridge > 0:
                _true_mv = round(float(_late_true_mv_bridge), 2)
                _row["true_mv_rescued"] = _true_mv
                _row["market_value_true"] = _true_mv
                _row["true_market_value"] = _true_mv
                print(
                    f"[EXACT_RESCUE_TRUE_MV] title={_title[:120]} true_mv={_true_mv}"
                )
        if not _has_true_market_value(_row):
            _row["market_value_true"] = None
            _row["true_market_value"] = None
            _truth_tier = "REVIEW" if _review_estimate and _review_estimate > 0 else "NONE"
    _row["review_estimate_value"] = round(_review_estimate, 2) if _review_estimate is not None and _review_estimate > 0 else None
    _row["anchored_estimate_value"] = _anchor_estimate
    _row["valuation_source_clean"] = _source or "none"
    if _source in {"structured_fallback", "fallback", "fallback_comp_support", "structured_review", "fallback_review"} and not _exact_truth_rescue_authority:
        if not bool(_row.get("exact_rescue_perma_block")):
            _stamp_exact_rescue_permablock(_row, "fallback_truth_blocked", title=_title)
        _row["true_market_value"] = None
        _row["market_value_true"] = None
        _row["has_true_market_value"] = False
        _row["_valuation_truth_tier"] = "REVIEW" if _row.get("review_estimate_value") else "NONE"
        _row["valuation_truth_tier"] = _row["_valuation_truth_tier"]
        _stamp_review_truth_class(_row)
        _row["market_value"] = None
        _row["mv_value"] = None
        _row["market_value_mode"] = "review_estimate"
        _row["valuation_mode"] = "review_estimate"
        _row["mode"] = "review_estimate"
        _row["bid_mode"] = "review_estimate"
        _row["target_bid_mode"] = "review_estimate" if _row.get("review_estimate_value") else str(_row.get("target_bid_mode") or "none")
        print(
            f"[MV_MODE_FORCE_REVIEW] title={str(_row.get('title') or _row.get('source_title') or '')[:120]} "
            f"source={_source} review={_row.get('review_estimate_value')}"
        )
    _trusted_lane_allow, _trusted_lane_reason = _trusted_premium_lane_authority(_row)
    if _trusted_lane_allow:
        _row["trusted_premium_lane_authority"] = True
        _row["premium_lane"] = 1
        _row["premium_lane_reason"] = _trusted_lane_reason
        _row["_research_only_price_check"] = False
        _row["_research_only_reason"] = ""
        print(
            f"[TRUSTED_PREMIUM_LANE_ASSERT] "
            f"title={str((_row or {}).get('title') or (_row or {}).get('source_title') or '')[:160]} "
            f"premium_lane={_row.get('premium_lane')} "
            f"premium_lane_reason={_row.get('premium_lane_reason')} "
            f"research_only={_row.get('_research_only_price_check')} "
            f"research_reason={_row.get('_research_only_reason')}"
        )
    if (
        not _trusted_lane_allow
        and _row["true_market_value"] is not None
        and _looks_like_current_price_clone({
        **_row,
        "true_market_value": _row["true_market_value"],
        "valuation_source": _row["valuation_source_clean"],
        })
    ):
        _clone_mv = _row["true_market_value"]
        _row["true_market_value"] = None
        _row["market_value_true"] = None
        _row["review_estimate_value"] = round(float(_clone_mv), 2)
        _row["_estimate_equals_current"] = True
        _truth_tier = "REVIEW"
        print(
            f"[MV_CLONE_BLOCK] title={str(_row.get('title') or _row.get('source_title') or '')[:120]} "
            f"current={_row.get('current_price')} review={_row.get('review_estimate_value')}"
        )
        _stamp_research_only_price_check(_row)
    elif (
        _row.get("review_estimate_value") is not None
        and _safe_float(_row.get("current_price")) is not None
        and abs(float(_row.get("review_estimate_value")) - float(_row.get("current_price"))) < 0.01
        and _source in {"soft_watchlist_estimate", "price_anchor_fallback", "anchor_only", "review_estimate", "near_family_support"}
    ):
        _row["_estimate_equals_current"] = True
    if _apply_identity_not_clean_truth_block(_row, stage="pre_mv_truth_stamp"):
        _identity_truth_blocked = True
        _truth_tier = "NONE"
        _row["true_market_value"] = None
        _row["market_value_true"] = None
        _row["has_true_market_value"] = False
        _row["exact_truth_rescued"] = False
        _row["trusted_exact_comp_count"] = 0
        _row["exact_comp_count"] = 0
    _row["exact_comp_count"] = int(_resolved_exact_comp_count(_row) or 0)
    _apply_final_board_true_guard(_row)
    _stamp_comp_truth_split(_row)
    _truth_tier = str(_row.get("_valuation_truth_tier") or _row.get("valuation_truth_tier") or _truth_tier).strip().upper()
    _true_mv = _safe_float(_row.get("market_value_true") or _row.get("true_market_value"))
    _review_estimate = _safe_float(_row.get("review_estimate_value"))
    if _apply_identity_not_clean_truth_block(_row, stage="post_final_true_guard_pre_mv_truth"):
        _identity_truth_blocked = True
        _truth_tier = "NONE"
        _true_mv = None
        _review_estimate = _safe_float(_row.get("review_estimate_value"))
    _row["has_true_market_value"] = bool(_row["market_value_true"]) and not _identity_truth_blocked
    _row["_valuation_truth_tier"] = _truth_tier if _truth_tier in {"TRUE", "REVIEW"} else "NONE"
    _row["valuation_truth_tier"] = _row["_valuation_truth_tier"]
    _row["support_truth_tier"] = str(_support_profile.get("support_truth_tier") or ("EXACT_OR_NON_SUPPORT" if not bool(_support_profile.get("is_support_source")) else "REVIEW_SUPPORT"))
    _row["support_truth_reason"] = str(_support_profile.get("reason") or "")
    _row["market_value"] = _row["market_value_true"]
    _row["mv_value"] = _row["market_value_true"]
    _display_anchor_value, _display_anchor_mode = _get_final_display_anchor(_row)
    _bid_anchor_value, _bid_anchor_mode = _get_final_bid_anchor(_row)
    _existing_target_bid = _safe_float(_row.get("target_bid") or _row.get("target_bid_price") or _row.get("bid_ceiling_value"))
    _existing_bid_mode = str(_row.get("target_bid_mode") or "none").strip().lower()
    _existing_bid_source = str(_row.get("target_bid_source_detail") or _row.get("target_bid_source") or _row.get("bid_ceiling_source") or "none").strip().lower()
    _row["final_display_anchor_value"] = _display_anchor_value
    _row["final_display_anchor_mode"] = _display_anchor_mode
    _row["final_bid_anchor_value"] = _bid_anchor_value
    _row["final_bid_anchor_mode"] = _bid_anchor_mode
    print(
        f"[FINAL_BID_ANCHOR] title={str(_row.get('title') or _row.get('source_title') or '')[:120]} "
        f"display_mode={_display_anchor_mode} display_value={_display_anchor_value} "
        f"bid_mode={_bid_anchor_mode} bid_anchor={_bid_anchor_value}"
    )
    _needs_bid_override = False
    _bid_override_reason = ""
    if bool(_row.get("_true_upgrade_allowed")):
        _needs_bid_override = True
        _bid_override_reason = "true_upgrade_final"
    elif _bid_anchor_value is None or _bid_anchor_value <= 0:
        if _existing_target_bid is not None and _existing_target_bid > 0:
            _needs_bid_override = True
            _bid_override_reason = "no_final_anchor"
    else:
        if _existing_target_bid is None or _existing_target_bid <= 0:
            _needs_bid_override = True
            _bid_override_reason = "missing_target_bid"
        elif _existing_target_bid > (_bid_anchor_value * 1.05):
            _needs_bid_override = True
            _bid_override_reason = "target_above_final_anchor"
        elif _bid_anchor_mode == "review_estimate" and _existing_bid_mode in {"strict", "median_discount"}:
            _needs_bid_override = True
            _bid_override_reason = "review_truth_with_strict_bid"
        elif _bid_anchor_mode == "review_estimate" and _existing_bid_source in {"adjusted_max_bid", "target_max_bid", "target_bid", "target_bid_price", "max_bid"}:
            _needs_bid_override = True
            _bid_override_reason = "review_truth_with_stale_explicit_bid"
    if _needs_bid_override:
        print(
            f"[FINAL_BID_ANCHOR_MISMATCH] title={str(_row.get('title') or _row.get('source_title') or '')[:120]} "
            f"truth={_row.get('valuation_truth_tier')} review={_row.get('review_estimate_value')} "
            f"true_mv={_row.get('true_market_value')} existing_bid={_existing_target_bid} reason={_bid_override_reason}"
        )
        if _bid_anchor_value is not None and _bid_anchor_value > 0:
            _recomputed_bid, _recomputed_mode, _recomputed_anchor_mode = _compute_final_target_bid_from_anchor(_row, _bid_anchor_value, _bid_anchor_mode)
            if _recomputed_bid is not None and _recomputed_bid > 0:
                _row["target_bid"] = round(float(_recomputed_bid), 2)
                _row["target_bid_price"] = round(float(_recomputed_bid), 2)
                _row["bid_ceiling_value"] = round(float(_recomputed_bid), 2)
                _row["adjusted_max_bid"] = round(float(_recomputed_bid), 2)
                _row["target_bid_mode"] = str(_recomputed_mode or "review_ceiling")
                _row["target_bid_source"] = f"final_{_recomputed_anchor_mode}"
                _row["target_bid_source_detail"] = f"final_{_recomputed_anchor_mode}"
                _row["bid_ceiling_source"] = f"final_{_recomputed_anchor_mode}".upper()
                _row["target_bid_ready"] = True
                _row["bid_ceiling_ready"] = True
                _row["bid_mode"] = _bid_anchor_mode
                _row["target_bid_confidence"] = "REVIEW" if _bid_anchor_mode == "review_estimate" else str(_row.get("target_bid_confidence") or _row.get("bid_ceiling_confidence") or _confidence or "MEDIUM").upper()
                _row["bid_ceiling_confidence"] = _row["target_bid_confidence"]
                print(
                    f"[FINAL_BID_ANCHOR_OVERRIDE] title={str(_row.get('title') or _row.get('source_title') or '')[:120]} "
                    f"anchor_mode={_bid_anchor_mode} anchor={_bid_anchor_value} target_bid={_row.get('target_bid')}"
                )
                print(
                    f"[TARGET_BID_RECOMPUTE_FINAL] title={str(_row.get('title') or _row.get('source_title') or '')[:120]} "
                    f"anchor_mode={_bid_anchor_mode} anchor={_bid_anchor_value} bid={_row.get('target_bid')}"
                )
                if bool(_row.get("_true_upgrade_allowed")):
                    print(
                        f"[TRUE_UPGRADE_BID_RECOMPUTE] title={str(_row.get('title') or _row.get('source_title') or '')[:120]} "
                        f"anchor_mode={_bid_anchor_mode} bid={_row.get('target_bid')}"
                    )
            else:
                for _clear_field in ("target_bid", "target_bid_price", "bid_ceiling_value", "adjusted_max_bid", "target_max_bid"):
                    _row[_clear_field] = None
                _row["target_bid_mode"] = "none"
                _row["target_bid_source"] = "final_anchor_none"
                _row["target_bid_source_detail"] = "final_anchor_none"
                _row["bid_ceiling_source"] = "NONE"
                _row["target_bid_confidence"] = "NONE"
                _row["bid_ceiling_confidence"] = "NONE"
                _row["target_bid_ready"] = False
                _row["bid_ceiling_ready"] = False
                _row["bid_mode"] = "none"
                print(
                    f"[TARGET_BID_CLEAR_STALE] title={str(_row.get('title') or _row.get('source_title') or '')[:120]} "
                    f"reason={_bid_override_reason}"
                )
        else:
            for _clear_field in ("target_bid", "target_bid_price", "bid_ceiling_value", "adjusted_max_bid", "target_max_bid"):
                _row[_clear_field] = None
            _row["target_bid_mode"] = "none"
            _row["target_bid_source"] = "final_anchor_none"
            _row["target_bid_source_detail"] = "final_anchor_none"
            _row["bid_ceiling_source"] = "NONE"
            _row["target_bid_confidence"] = "NONE"
            _row["bid_ceiling_confidence"] = "NONE"
            _row["target_bid_ready"] = False
            _row["bid_ceiling_ready"] = False
            _row["bid_mode"] = "none"
            print(
                f"[TARGET_BID_CLEAR_STALE] title={str(_row.get('title') or _row.get('source_title') or '')[:120]} "
                f"reason={_bid_override_reason}"
            )
    _final_target_bid = _safe_float(_row.get("target_bid") or _row.get("target_bid_price") or _row.get("bid_ceiling_value"))
    if _bid_anchor_value is not None and _bid_anchor_value > 0 and _final_target_bid is not None and _final_target_bid > (_bid_anchor_value * 1.05):
        print(
            f"[BID_SANITY_BLOCK] title={str(_row.get('title') or _row.get('source_title') or '')[:120]} "
            f"anchor={_bid_anchor_value} target_bid={_final_target_bid}"
        )
        _repair_bid, _repair_mode, _repair_anchor_mode = _compute_final_target_bid_from_anchor(_row, _bid_anchor_value, _bid_anchor_mode)
        if _repair_bid is not None and _repair_bid > 0:
            _row["target_bid"] = round(float(_repair_bid), 2)
            _row["target_bid_price"] = round(float(_repair_bid), 2)
            _row["bid_ceiling_value"] = round(float(_repair_bid), 2)
            _row["adjusted_max_bid"] = round(float(_repair_bid), 2)
            _row["target_bid_mode"] = str(_repair_mode or "review_ceiling")
            _row["target_bid_source"] = f"final_{_repair_anchor_mode}"
            _row["target_bid_source_detail"] = f"final_{_repair_anchor_mode}"
            _row["bid_ceiling_source"] = f"final_{_repair_anchor_mode}".upper()
            _row["target_bid_ready"] = True
            _row["bid_ceiling_ready"] = True
            _row["bid_mode"] = _bid_anchor_mode
            print(
                f"[BID_SANITY_REPAIR] title={str(_row.get('title') or _row.get('source_title') or '')[:120]} "
                f"anchor={_bid_anchor_value} repaired_bid={_row.get('target_bid')}"
            )
        else:
            for _clear_field in ("target_bid", "target_bid_price", "bid_ceiling_value", "adjusted_max_bid", "target_max_bid"):
                _row[_clear_field] = None
            _row["target_bid_mode"] = "none"
            _row["target_bid_source"] = "final_anchor_none"
            _row["target_bid_source_detail"] = "final_anchor_none"
            _row["bid_ceiling_source"] = "NONE"
            _row["target_bid_confidence"] = "NONE"
            _row["bid_ceiling_confidence"] = "NONE"
            _row["target_bid_ready"] = False
            _row["bid_ceiling_ready"] = False
            _row["bid_mode"] = "none"
    if not _row["has_true_market_value"]:
        _row["mv_resolved"] = False
        if _source in _MV_ANCHOR_ONLY_SOURCES or _comp_count <= 0:
            _row["mv_valid"] = False
            _row["mv_blocked_reason"] = str(_row.get("mv_blocked_reason") or "anchor_only_no_real_mv")
    print(
        f"[MV_TRUTH] title={str(_row.get('title') or _row.get('source_title') or '')[:120]} "
        f"truth={_row.get('valuation_truth_tier')} true_mv={_row.get('true_market_value')} "
        f"review={_row.get('review_estimate_value')} source={_row.get('valuation_source_clean')}"
    )
    _stamp_review_truth_class(_row)
    _log_final_truth_assert(_row)
    return _row


def _mv_truth_gate(row: Dict[str, Any], *, emit_log: bool = False) -> Dict[str, Any]:
    _r = _stamp_mv_truth_fields(row)
    _source = str(_r.get("mv_source") or _r.get("market_value_source") or "").strip().lower()
    try:
        _comp_count = int(_r.get("comp_count") or _r.get("mv_comp_count") or 0)
    except (TypeError, ValueError):
        _comp_count = 0
    _true_mv = _safe_float(_r.get("market_value_true")) or 0.0
    _anchor_estimate = _safe_float(_r.get("anchored_estimate_value")) or 0.0
    _conf = _normalize_mv_confidence_label(
        _r.get("mv_confidence_strict")
        or _r.get("valuation_confidence")
        or _r.get("confidence")
        or _r.get("mv_confidence")
        or ""
    )
    try:
        _price = float(_r.get("price") or _r.get("current_price") or _r.get("current_bid") or 0.0)
    except (TypeError, ValueError):
        _price = 0.0
    try:
        _edge_dollars = float(
            _r.get("edge_dollars")
            or (_r.get("action_summary") or {}).get("expected_profit")
            or max(0.0, _true_mv - _price)
        )
    except (TypeError, ValueError):
        _edge_dollars = max(0.0, _true_mv - _price)
    _chase_class = str(_r.get("chase_class") or "").strip().upper()
    _endgame_tier = str(_r.get("endgame_tier") or "").strip().lower()
    _endgame_watch_ok = bool(
        _chase_class in {"ENDGAME_CHASE", "PREMIUM_SECONDARY"}
        or _endgame_tier in {"endgame", "premium_secondary"}
    )
    _mem_junk = bool(_r.get("memorabilia_junk"))
    _vet_non_chase = bool(_r.get("veteran_non_chase"))
    _target_bid_ready = bool(_r.get("bid_ceiling_ready")) or bool(_r.get("target_bid_ready")) or _row_target_bid_ready(_r)

    _decision = "visible"
    _reason = "trusted_comp_mv"
    _allow_watch = True
    _allow_execute = True
    _allow_sniper = True

    if _source in _MV_ANCHOR_ONLY_SOURCES or _true_mv <= 0 or _comp_count <= 0:
        _decision = "hidden"
        _reason = "anchor_only_no_real_mv"
        _allow_watch = False
        _allow_execute = False
        _allow_sniper = False
        _r["hidden_reason"] = _reason
        _r["mv_truth_decision"] = _decision
        if emit_log:
            print(
                f"[MV_TRUTH_GATE] item={str(_r.get('item_id') or _r.get('source_item_id') or '')[:24] or '?'} "
                f"source={_source or 'none'} comp_count={_comp_count} true_mv={round(_true_mv, 2) if _true_mv else 'None'} "
                f"anchor_estimate={round(_anchor_estimate, 2) if _anchor_estimate else 'None'} decision=hidden"
            )
            print(f"[ANCHOR_BLOCK] item={str(_r.get('item_id') or _r.get('source_item_id') or '')[:24] or '?'} reason=anchor_only_no_real_mv")
        return {
            "decision": _decision,
            "reason": _reason,
            "allow_watch": _allow_watch,
            "allow_execute": _allow_execute,
            "allow_sniper": _allow_sniper,
        }

    if _source == "structured_fallback":
        _allow_sniper = False
        _allow_execute = False
        _allow_watch = bool(
            _comp_count >= 2
            and _conf in {"MEDIUM", "HIGH"}
            and _endgame_watch_ok
            and _target_bid_ready
            and not _mem_junk
            and not _vet_non_chase
        )
        _decision = "watch" if _allow_watch else "hidden"
        _reason = "structured_fallback_watch_only" if _allow_watch else "structured_fallback_low_support"
        if not _allow_watch:
            _r["hidden_reason"] = _reason
        if emit_log:
            print(
                f"[STRUCTURED_FALLBACK_GATE] item={str(_r.get('item_id') or _r.get('source_item_id') or '')[:24] or '?'} "
                f"comps={_comp_count} conf={_conf or 'LOW'} decision={'watch' if _allow_watch else 'hidden'}"
            )
            print(
                f"[MV_TRUTH_GATE] item={str(_r.get('item_id') or _r.get('source_item_id') or '')[:24] or '?'} "
                f"source={_source or 'none'} comp_count={_comp_count} true_mv={round(_true_mv, 2) if _true_mv else 'None'} "
                f"anchor_estimate={round(_anchor_estimate, 2) if _anchor_estimate else 'None'} decision={_decision}"
            )
        _r["mv_truth_decision"] = _decision
        return {
            "decision": _decision,
            "reason": _reason,
            "allow_watch": _allow_watch,
            "allow_execute": _allow_execute,
            "allow_sniper": _allow_sniper,
        }

    _r["mv_truth_decision"] = _decision
    if emit_log:
        print(
            f"[MV_TRUTH_GATE] item={str(_r.get('item_id') or _r.get('source_item_id') or '')[:24] or '?'} "
            f"source={_source or 'none'} comp_count={_comp_count} true_mv={round(_true_mv, 2) if _true_mv else 'None'} "
            f"anchor_estimate={round(_anchor_estimate, 2) if _anchor_estimate else 'None'} decision=visible"
        )
    return {
        "decision": _decision,
        "reason": _reason,
        "allow_watch": _allow_watch,
        "allow_execute": _allow_execute,
        "allow_sniper": _allow_sniper,
    }


def _unresolved_board_reasons(row: Dict[str, Any]) -> List[str]:
    _r = row if isinstance(row, dict) else dict(row or {})
    _r = _stamp_mv_truth_fields(_r)
    _reasons: List[str] = []
    _true_mv = _safe_float(_r.get("market_value_true")) or 0.0
    try:
        _comp_count = int(_r.get("comp_count") or _r.get("mv_comp_count") or 0)
    except (TypeError, ValueError):
        _comp_count = 0
    _target_bid_ready = bool(_r.get("bid_ceiling_ready")) or bool(_r.get("target_bid_ready")) or _row_target_bid_ready(_r)
    _source = str(_r.get("mv_source") or _r.get("market_value_source") or "").strip().lower()
    if _true_mv <= 0:
        _reasons.append("no_true_mv")
    if _comp_count <= 0:
        _reasons.append("no_comps")
    if not _target_bid_ready:
        _reasons.append("no_target_bid")
    if _source == "price_anchor_fallback":
        _reasons.append("anchor_source")
    if _reasons and _is_premium_card(_r):
        _override_ok = _weak_mv_override_allowed(_r, emit_log=True)
        if _override_ok:
            if isinstance(_r, dict):
                _r["_mv_untrusted_but_allowed"] = True
            print(f"[MV_OVERRIDE] Allowing premium despite weak MV: {_r.get('title')}")
            return []
        if isinstance(_r, dict):
            _r["_mv_untrusted_but_allowed"] = False
    # Fallback-promoted rows: soft_watchlist zeroes market_value_true and sets
    # review_estimate_value instead. They are NOT unresolved — the estimate and
    # target_bid exist, just under different fields. Treat as resolved.
    if _reasons and bool((row or {}).get("_fallback_promoted")):
        if isinstance(row, dict):
            row["_mv_untrusted_but_allowed"] = True
        print(f"[FALLBACK_PROMO_OVERRIDE] Allowing fallback-promoted despite no true_mv: {(row or {}).get('title', '')[:80]}")
        return []
    # Soft-watchlist rows similarly have review_estimate_value as their anchor.
    if _reasons and bool((row or {}).get("_soft_watchlist")) or bool((row or {}).get("_rescued_watchlist")):
        _review_est = _safe_float((row or {}).get("review_estimate_value") or (row or {}).get("anchored_estimate_value"))
        _bid_ready = bool((row or {}).get("bid_ceiling_ready")) or bool((row or {}).get("target_bid_ready"))
        if _review_est and _review_est > 0 and _bid_ready:
            if isinstance(row, dict):
                row["_mv_untrusted_but_allowed"] = True
            return []
    return _reasons


def _is_unresolved_no_trusted_mv(row: Dict[str, Any]) -> bool:
    return bool(_unresolved_board_reasons(row))


def _append_comp_query_exclusions(query_text: str) -> str:
    _query = str(query_text or "").strip()
    if not _query:
        return ""
    if "-lot" not in _query.lower():
        _query = f"{_query} {_COMP_JUNK_EXCLUSIONS}".strip()
    return _query


def _finalize_mv_payload(
    item: Dict[str, Any],
    payload: Optional[Dict[str, Any]],
    comps: Optional[List[Dict[str, Any]]] = None,
) -> Dict[str, Any]:
    _payload = dict(payload or {})
    _price = _mv_price_anchor(item)
    _comp_rows = list(comps or [])
    if not _comp_rows:
        _comp_rows = _extract_debug_comp_rows(_payload.get("debug_accepted_comps_json"))

    mv = _safe_float(_payload.get("market_value"))
    conf = str(_payload.get("confidence") or "LOW").strip().upper() or "LOW"
    mv_source = str(_payload.get("market_value_source") or "none").strip() or "none"
    _used_fallback = False

    if mv is None:
        fallback_mv = _safe_fallback_mv(_comp_rows, _price)
        if fallback_mv:
            mv = float(fallback_mv["market_value"])
            conf = str(fallback_mv["confidence"] or "LOW").strip().upper() or "LOW"
            mv_source = str(fallback_mv["source"] or "structured_fallback").strip() or "structured_fallback"
        else:
            mv = _price if _price else None
            conf = "LOW"
            mv_source = "price_anchor_fallback"
        _used_fallback = True

    if mv is None:
        if _price:
            mv = round(_price * 1.15, 2)
            conf = "LOW"
            mv_source = "price_anchor_emergency"
        else:
            mv = 1.0
            conf = "LOW"
            mv_source = "floor_fallback"
        _used_fallback = True

    _raw_mv = round(float(mv), 2)
    _payload["market_value_raw"] = _raw_mv
    _payload["market_value"] = _raw_mv
    _payload["confidence"] = conf
    _payload["low_confidence"] = conf == "LOW"
    _payload["insufficient_data"] = False
    _payload["market_value_source"] = mv_source
    _payload["comp_source_label"] = mv_source
    if _comp_rows:
        try:
            _payload["comp_count"] = max(int(_payload.get("comp_count") or 0), len(_comp_rows))
        except (TypeError, ValueError):
            _payload["comp_count"] = len(_comp_rows)
    _comp_publish = _published_comp_evidence_payload(item or {}, _comp_rows, limit=5)
    _payload["comp_evidence"] = list(_comp_publish.get("published") or [])
    _payload["exact_comps"] = list(_comp_publish.get("exact_rows") or [])
    _payload["supporting_comps"] = list(_comp_publish.get("support_rows") or [])
    if _used_fallback:
        _payload["mv_valid"] = True
        _payload["mv_confidence_strict"] = conf
        _payload["mv_blocked_reason"] = ""
        _payload["mv_medium_eligible"] = False
        _payload["mv_medium_resolved"] = conf == "MEDIUM"
        _payload["mv_medium_blocked_reason"] = ""
        _payload["mv_fallback_used"] = True
        _payload["mv_fallback_tier_label"] = mv_source
        _payload["mv_type"] = "estimated"
    elif "mv_type" not in _payload:
        _payload["mv_type"] = "exact" if bool(_payload.get("mv_valid")) else "estimated"

    _stamp_mv_truth_fields(_payload)
    if not bool(_payload.get("market_value_true")):
        _payload["mv_valid"] = False
        _payload["mv_resolved"] = False
        _payload["mv_blocked_reason"] = str(_payload.get("mv_blocked_reason") or "anchor_only_no_real_mv")
        if _payload.get("market_value_source") in _MV_ANCHOR_ONLY_SOURCES:
            _payload["insufficient_data"] = True
            _payload["mv_type"] = "anchor_estimate"
        elif not int(_payload.get("comp_count") or 0):
            _payload["insufficient_data"] = True
            _payload["mv_type"] = "none"
    else:
        _payload["mv_resolved"] = True
        if str(_payload.get("mv_type") or "") == "anchor_estimate":
            _payload["mv_type"] = "estimated"

    print(
        f"[MV][FINAL] mv={_payload.get('market_value_true')} "
        f"conf={conf} source={mv_source}"
    )
    return _payload


def _summarize_exact_comp_rejects(
    *,
    rejection_summary: str,
    lookup_contract: Dict[str, Any],
    strict_comp_count: int,
    lane_comp_count: int,
    exact_grade_count: int,
    comp_count: int,
) -> Dict[str, int]:
    _raw = _parse_comp_rejection_summary(rejection_summary)
    _counts = {
        "wrong_card_number": 0,
        "wrong_parallel": 0,
        "wrong_subset": 0,
        "graded_raw_mismatch": 0,
        "broad_product_only_reject": 0,
        "exact_required_fail": 0,
    }
    for _reason, _count in _raw.items():
        _r = str(_reason or "").strip().lower()
        if "exact_required_fail" in _r:
            _counts["exact_required_fail"] += _count
        elif "card_number_mismatch" in _r or "card_number_family_mixed" in _r:
            _counts["wrong_card_number"] += _count
        elif "subset" in _r:
            _counts["wrong_subset"] += _count
        elif "parallel" in _r or "lane" in _r:
            _counts["wrong_parallel"] += _count
        elif "grade:" in _r or "cross_grade" in _r or "graded_other" in _r or "raw" in _r:
            _counts["graded_raw_mismatch"] += _count
        elif "set_mismatch" in _r:
            _counts["broad_product_only_reject"] += _count
    if bool(lookup_contract.get("common_modern_exact_required")) and comp_count > 0:
        if strict_comp_count < 2:
            _counts["exact_required_fail"] += max(1, comp_count - strict_comp_count)
            _counts["wrong_card_number"] += max(1, comp_count - strict_comp_count)
        if bool(lookup_contract.get("exact_parallel_required")) and lane_comp_count < 1:
            _counts["wrong_parallel"] += max(1, comp_count - lane_comp_count)
        if bool(lookup_contract.get("exact_subset_required")) and lane_comp_count < 1:
            _counts["wrong_subset"] += max(1, comp_count - lane_comp_count)
        if str(lookup_contract.get("exact_grade_state") or "").strip().lower() == "graded" and exact_grade_count < 1:
            _counts["graded_raw_mismatch"] += max(1, comp_count)
        if strict_comp_count < 2 and lane_comp_count < 1:
            _counts["broad_product_only_reject"] += max(1, comp_count)
    return {k: int(v) for k, v in _counts.items() if int(v) > 0}


def _common_card_realism_clamp(
    *,
    item: Dict[str, Any],
    lookup_contract: Dict[str, Any],
    strict_comp_count: int,
    lane_comp_count: int,
    comp_count: int,
    value_range_low: Optional[float],
    value_range_high: Optional[float],
    mv: Optional[float],
) -> Dict[str, Any]:
    _eligible = bool(
        lookup_contract.get("common_modern_exact_required")
        and str(lookup_contract.get("exact_grade_state") or "").strip().lower() == "raw"
    )
    _price = _row_price_anchor(item)
    if not _eligible:
        return {
            "eligible": False,
            "passed": False,
            "clamped": False,
            "downgraded_to_review": False,
            "mv": float(mv) if mv and float(mv) > 0 else None,
            "reason": "",
        }
    if not mv or float(mv) <= 0:
        return {
            "eligible": True,
            "passed": False,
            "clamped": False,
            "downgraded_to_review": True,
            "mv": None,
            "reason": "exact_required_fail",
            "current_price": round(_price, 2) if _price > 0 else 0.0,
            "unclamped_mv": 0.0,
        }

    _variance_ratio = 9.99
    if value_range_low is not None and value_range_high is not None and float(mv or 0.0) > 0:
        _low = float(value_range_low or 0.0)
        _high = float(value_range_high or 0.0)
        if _low > 0 and _high >= _low:
            _variance_ratio = (_high - _low) / max(float(mv), 0.01)

    _parallel_needed = bool(lookup_contract.get("exact_parallel_required"))
    _subset_needed = bool(lookup_contract.get("exact_subset_required"))
    _lane_exact_ok = True
    if (_parallel_needed or _subset_needed) and lane_comp_count < 2:
        _lane_exact_ok = False

    _strong_exact_support = bool(
        strict_comp_count >= 4
        and comp_count >= 5
        and _variance_ratio <= 0.45
        and _lane_exact_ok
    )
    if _strong_exact_support:
        return {
            "eligible": True,
            "passed": True,
            "clamped": False,
            "downgraded_to_review": False,
            "mv": round(float(mv), 2),
            "reason": "strong_exact_support",
        }

    _anchors: List[float] = []
    if value_range_low is not None:
        try:
            _vlo = float(value_range_low or 0.0)
        except (TypeError, ValueError):
            _vlo = 0.0
        if _vlo > 0:
            _anchors.append(_vlo)
    if _price > 0:
        if strict_comp_count >= 3 and comp_count >= 4:
            _price_cap = _price * (5.0 if _price <= 2.5 else 3.5 if _price <= 6.0 else 2.6)
        else:
            _price_cap = _price * (3.75 if _price <= 2.5 else 2.75 if _price <= 6.0 else 2.0)
        _anchors.append(_price_cap)
    _anchors = [float(_a) for _a in _anchors if float(_a or 0.0) > 0]
    _clamped_mv = min([float(mv)] + _anchors) if _anchors else float(mv)
    _reason = "common_modern_thin_exact_support"
    if _variance_ratio > 0.60:
        _reason = "common_modern_high_variance"
    elif strict_comp_count < 3:
        _reason = "common_modern_low_exact_count"
    elif not _lane_exact_ok:
        _reason = "common_modern_parallel_subset_mismatch"
    return {
        "eligible": True,
        "passed": False,
        "clamped": True,
        "downgraded_to_review": True,
        "mv": round(max(0.0, _clamped_mv), 2) if _clamped_mv > 0 else None,
        "reason": _reason,
        "current_price": round(_price, 2) if _price > 0 else 0.0,
        "unclamped_mv": round(float(mv), 2),
    }


def _mv_strict_post_validate(
    *,
    source: str,
    lookup_contract: Dict[str, Any],
    strict_comp_count: int,
    lane_comp_count: int,
    exact_grade_count: int,
    comp_count: int,
    value_range_low: Optional[float],
    value_range_high: Optional[float],
    mv: Optional[float],
) -> Tuple[bool, str, str]:
    """
    Post-validate hybrid valuation output against strict comp matching rules.

    Returns (mv_valid, blocked_reason, strict_confidence).
      mv_valid=True  → MV is trusted; edge + target_bid may be computed
      mv_valid=False → MV is blocked; show for review only, never produce edge/bid

    Rules (all must pass for mv_valid=True):
      R1. Source must be strong_comp_engine (only).
      R2. Graded listing → exact_grade_comp_count >= 1 (no cross-grade comps).
      R3. Parallel listing → lane_comp_count >= 1, or total comps >= 5.
      R4. Minimum comps: strict >= 2, or total >= 3.
      R5. Variance: if value range span > 70% of MV, require strict >= 3.
    """
    _src = str(source or "").strip().lower()

    # R1 — only strong_comp_engine earns trusted MV
    if _src not in _STRONG_MV_SOURCES:
        return False, f"weak_source:{_src}", "LOW"

    # R2 — grade match
    _grade_company = str(lookup_contract.get("grade_company") or "").strip().upper()
    _grade_value = str(lookup_contract.get("grade_value") or "").strip()
    _is_graded = bool(_grade_company and _grade_value)
    if _is_graded and exact_grade_count < 1:
        _grade_block = "graded_raw_mismatch" if bool(lookup_contract.get("common_modern_exact_required")) else "no_exact_grade_comps"
        return False, f"{_grade_block}:{_grade_company}_{_grade_value}", "LOW"

    # R3 — parallel match
    _title = str(lookup_contract.get("title") or "").strip()
    _scarcity_lane_required = bool(
        str(lookup_contract.get("subset_name") or "").strip()
        or str(lookup_contract.get("rare_parallel") or "").strip()
        or str(lookup_contract.get("serial_bucket") or "").strip()
    )
    _parallel_bucket = str(
        lookup_contract.get("parallel_bucket") or lookup_contract.get("parallel_name") or ""
    ).strip().lower()
    _parallel_in_title = _detect_parallel_in_title(_title)
    _has_parallel = bool(_parallel_bucket) or bool(_parallel_in_title)
    _exact_required = bool(lookup_contract.get("common_modern_exact_required"))
    _exact_subset_required = bool(lookup_contract.get("exact_subset_required"))
    _exact_parallel_required = bool(lookup_contract.get("exact_parallel_required"))
    if _exact_required and not str(lookup_contract.get("card_number") or "").strip():
        return False, "exact_required_fail:no_card_number", "LOW"
    if _exact_required and strict_comp_count < 2:
        return False, f"exact_required_fail:strict={strict_comp_count}", "LOW"
    if _exact_subset_required and lane_comp_count < 1:
        return False, f"exact_required_fail:wrong_subset:{str(lookup_contract.get('exact_subset_name') or '')}", "LOW"
    if _scarcity_lane_required and lane_comp_count < 2:
        return False, f"generic_lane_reject:lane_comps={lane_comp_count}", "LOW"
    if _has_parallel:
        if _exact_required and _exact_parallel_required and lane_comp_count < 1:
            _par_tag = _parallel_bucket or _parallel_in_title
            return False, f"exact_required_fail:wrong_parallel:{_par_tag}", "LOW"
        if lane_comp_count < 1 and comp_count < 5:
            _par_tag = _parallel_bucket or _parallel_in_title
            return False, f"parallel_no_lane_comps:{_par_tag}", "LOW"

    # R4 — minimum comp count
    if strict_comp_count < 2 and comp_count < 3:
        return False, f"insufficient_comps:strict={strict_comp_count} total={comp_count}", "LOW"
    if _exact_required and strict_comp_count < 2:
        return False, f"exact_required_fail:broad_product_only_reject:strict={strict_comp_count}_total={comp_count}", "LOW"

    # R5 — variance / outlier proxy
    if mv and mv > 0 and value_range_low is not None and value_range_high is not None:
        _span = (value_range_high - value_range_low)
        _variance_ratio = _span / mv
        if _variance_ratio > 0.70 and strict_comp_count < 3:
            return False, f"high_variance:{_variance_ratio:.0%}_strict={strict_comp_count}", "LOW"

    # Confidence tier
    if strict_comp_count >= 3 or lane_comp_count >= 3:
        return True, "", "HIGH"
    if strict_comp_count >= 2 or lane_comp_count >= 2:
        if _scarcity_lane_required and lane_comp_count < 2:
            return False, "generic_lane_reject:weak_scarcity_lane", "LOW"
        # Tight variance check for 2-comp HIGH
        if mv and mv > 0 and value_range_low is not None and value_range_high is not None:
            _var2 = (value_range_high - value_range_low) / mv
            if _var2 < 0.15:
                return True, "", "HIGH"
        return True, "", "MEDIUM"
    # comp_count >= 3 but strict_comp_count < 2 — usable but not tight
    if _exact_required:
        return False, "exact_required_fail:common_modern_exact", "LOW"
    return True, "", "MEDIUM"


def _mv_medium_post_validate(
    *,
    source: str,
    lookup_contract: Dict[str, Any],
    strict_comp_count: int,
    lane_comp_count: int,
    exact_grade_count: int,
    comp_count: int,
    value_range_low: Optional[float],
    value_range_high: Optional[float],
    mv: Optional[float],
) -> Tuple[bool, Optional[float], str]:
    _src = str(source or "").strip().lower()
    _premium_support_ok = _is_premium_support_resolution_contract(lookup_contract)
    _support_mode_ok, _support_mode_reason, _support_mode_profile = _premium_family_support_allowed(lookup_contract)
    _item_id = str(lookup_contract.get("itemId") or lookup_contract.get("item_id") or "")[:24] or "?"
    _mem_support_mode = bool(
        _support_mode_ok
        and _is_memorabilia_support_subtype(str(_support_mode_profile.get("subtype") or ""))
    )
    if not mv or float(mv) <= 0:
        return False, None, "blocked_low_score:no_mv"
    if _src in {"listing_type_excluded", "error", "none", "unresolved", "structured_fallback"}:
        return False, None, f"blocked_low_score:{_src}"
    if comp_count < 4 and lane_comp_count < 2 and not (_premium_support_ok and _support_mode_ok):
        return False, None, f"blocked_thin_pool:total={comp_count}"
    if comp_count < 4 and lane_comp_count < 2 and _support_mode_ok:
        print(
            f"[PREMIUM_FAMILY_SUPPORT] item={_item_id} reason=thin_pool_override "
            f"bucket={str(_support_mode_profile.get('bucket') or '')} total={comp_count} lane={lane_comp_count}"
        )

    _grade_company = str(lookup_contract.get("grade_company") or "").strip().upper()
    _grade_value = str(lookup_contract.get("grade_value") or "").strip()
    _is_graded = bool(_grade_company and _grade_value)
    if _is_graded and exact_grade_count < 1:
        _grade_reason = "graded_raw_mismatch" if bool(lookup_contract.get("common_modern_exact_required")) else f"grade={_grade_company}_{_grade_value}"
        return False, None, f"blocked_mismatch:{_grade_reason}"

    _title = str(lookup_contract.get("title") or "").strip()
    _scarcity_lane_required = bool(
        str(lookup_contract.get("subset_name") or "").strip()
        or str(lookup_contract.get("rare_parallel") or "").strip()
        or str(lookup_contract.get("serial_bucket") or "").strip()
    )
    _parallel_bucket = str(
        lookup_contract.get("parallel_bucket") or lookup_contract.get("parallel_name") or ""
    ).strip().lower()
    _parallel_in_title = _detect_parallel_in_title(_title)
    _has_parallel = bool(_parallel_bucket) or bool(_parallel_in_title)
    _exact_required = bool(lookup_contract.get("common_modern_exact_required"))
    _exact_subset_required = bool(lookup_contract.get("exact_subset_required"))
    _exact_parallel_required = bool(lookup_contract.get("exact_parallel_required"))
    if _exact_required and not str(lookup_contract.get("card_number") or "").strip():
        return False, None, "blocked_mismatch:exact_required_fail:no_card_number"
    if _exact_required and strict_comp_count < 2:
        return False, None, f"blocked_mismatch:exact_required_fail:strict={strict_comp_count}"
    _lane_type = "generic"
    if str(lookup_contract.get("subset_name") or "").strip():
        _lane_type = "subset"
    elif str(lookup_contract.get("serial_bucket") or "").strip():
        _lane_type = "serial"
    elif _has_parallel:
        _lane_type = "parallel"
    if _exact_required and _exact_subset_required and lane_comp_count < 1:
        if _support_mode_ok:
            print(
                f"[PREMIUM_FAMILY_SUPPORT] item={_item_id} reason=wrong_subset_support "
                f"bucket={str(_support_mode_profile.get('bucket') or '')}"
            )
        else:
            print(
                f"[PREMIUM_FAMILY_REJECT] item={_item_id} reason=wrong_subset "
                f"subset={str(lookup_contract.get('exact_subset_name') or '')[:32]}"
            )
            return False, None, f"blocked_mismatch:exact_required_fail:wrong_subset:{str(lookup_contract.get('exact_subset_name') or '')}"
    if _exact_required and _exact_parallel_required and lane_comp_count < 1:
        if _mem_support_mode and comp_count >= 2:
            print(
                f"[MEM_PARALLEL_SUPPORT_ACCEPT] item={_item_id} "
                f"reason=parallel_band_support distance={str(_support_mode_profile.get('support_serial_distance') or 'near')} "
                f"weight={float(_support_mode_profile.get('support_weight') or 0.0):.2f}"
            )
        elif _support_mode_ok:
            print(
                f"[SUPPORT_MODE_PARALLEL_ACCEPT] item={_item_id} parallel={(_parallel_bucket or _parallel_in_title)[:32]} "
                f"reason={_support_mode_reason}"
            )
        else:
            if _is_memorabilia_support_subtype(_same_card_subtype_bucket(_title)):
                print(
                    f"[MEM_PARALLEL_SUPPORT_REJECT] item={_item_id} "
                    f"reason=parallel_band_mismatch parallel={(_parallel_bucket or _parallel_in_title)[:32]}"
                )
            print(
                f"[SUPPORT_MODE_PARALLEL_REJECT] item={_item_id} parallel={(_parallel_bucket or _parallel_in_title)[:32]} "
                f"reason=wrong_parallel"
            )
            return False, None, f"blocked_mismatch:exact_required_fail:wrong_parallel:{_parallel_bucket or _parallel_in_title}"
    if _scarcity_lane_required and lane_comp_count < 2:
        if _mem_support_mode and comp_count >= 2:
            print(
                f"[MEM_PARALLEL_SUPPORT_ACCEPT] item={_item_id} reason=scarcity_lane_mem_support "
                f"distance={str(_support_mode_profile.get('support_serial_distance') or 'near')} "
                f"weight={float(_support_mode_profile.get('support_weight') or 0.0):.2f}"
            )
        elif _support_mode_ok and comp_count >= 2:
            print(
                f"[PREMIUM_FAMILY_SUPPORT] item={_item_id} reason=scarcity_lane_support "
                f"bucket={str(_support_mode_profile.get('bucket') or '')} lane={lane_comp_count} total={comp_count}"
            )
        else:
            return False, None, f"blocked_mismatch:generic_lane_reject:lane_comps={lane_comp_count}"
    if _lane_type in {"subset", "serial", "parallel"} and lane_comp_count < 1 and comp_count < 6:
        if _mem_support_mode and comp_count >= 2:
            print(
                f"[MEM_PARALLEL_SUPPORT_ACCEPT] item={_item_id} reason=memorabilia_family_only "
                f"lane={_lane_type} distance={str(_support_mode_profile.get('support_serial_distance') or 'near')}"
            )
        elif _support_mode_ok and comp_count >= 2:
            print(
                f"[IDENTITY_SUPPORT_ACCEPT] item={_item_id} reason=support_mode_lane "
                f"lane={_lane_type} bucket={str(_support_mode_profile.get('bucket') or '')}"
            )
        else:
            print(
                f"[IDENTITY_SUPPORT_REJECT] item={_item_id} reason=weak_card_identity_match "
                f"lane={_lane_type} total={comp_count}"
            )
            return False, None, f"blocked_mismatch:lane={_lane_type}"

    _resolved_mv = float(mv)
    if value_range_low is not None and value_range_high is not None and value_range_low > 0 and value_range_high > 0:
        _low = float(value_range_low)
        _high = float(value_range_high)
        if _high < _low:
            return False, None, "blocked_low_score:bad_range"
        _center = (_low * 0.55) + (_high * 0.45)
        _variance_ratio = ((_high - _low) / max(_center, 0.01)) if _center > 0 else 9.99
        if _variance_ratio > 0.65 and comp_count < 6:
            return False, None, f"blocked_low_score:variance={_variance_ratio:.2f}"
        _resolved_mv = _center
    elif comp_count < 5 and strict_comp_count < 1 and lane_comp_count < 1:
        return False, None, "blocked_thin_pool:no_range"
    if _scarcity_lane_required and (comp_count < 3 or strict_comp_count < 1) and not (
        (_premium_support_ok and comp_count >= 3 and lane_comp_count >= 2)
        or (_support_mode_ok and comp_count >= 2)
    ):
        return False, None, f"blocked_thin_pool:scarcity_exact={strict_comp_count}_total={comp_count}"
    if _scarcity_lane_required and _support_mode_ok and (comp_count >= 2) and (strict_comp_count < 1 or lane_comp_count < 2):
        print(
            f"[PREMIUM_FAMILY_SUPPORT] item={_item_id} reason=scarcity_exact_override "
            f"bucket={str(_support_mode_profile.get('bucket') or '')} strict={strict_comp_count} lane={lane_comp_count} total={comp_count}"
        )
    if _exact_required and strict_comp_count < 2:
        return False, None, "blocked_mismatch:exact_required_fail:common_modern_exact"

    if _resolved_mv <= 0:
        return False, None, "blocked_low_score:resolved_zero"
    return True, round(_resolved_mv, 2), "resolved_medium_comp"


def _normalize_mv_comp_count(item: Dict[str, Any]) -> int:
    _row = item or {}
    _counts: List[int] = []
    for _field_name in ("comp_count", "comps_count", "dominant_comp_count", "market_lane_comp_count", "market_lane_recent_count"):
        try:
            _val = int(_row.get(_field_name) or 0)
        except (TypeError, ValueError):
            _val = 0
        if _val > 0:
            _counts.append(_val)
    return max(_counts) if _counts else 0


def _strengthen_row_valuation_support(item: Dict[str, Any]) -> Dict[str, Any]:
    _row = dict(item or {})
    _stamp_mv_truth_fields(_row)
    _mv = _safe_float(_row.get("market_value_true"))
    if _mv is not None and _mv > 0:
        _mv = round(_mv, 2)
    else:
        _mv = None
    _bid_anchor_value, _bid_anchor_mode = _get_final_bid_anchor(_row)
    _bid_basis = _mv
    if (_bid_basis is None or _bid_basis <= 0) and _bid_anchor_value is not None and _bid_anchor_value > 0:
        _bid_basis = round(float(_bid_anchor_value), 2)
    _source = str(_row.get("mv_source") or _row.get("market_value_source") or _row.get("valuation_basis") or "").strip() or "none"
    _conf = _normalize_mv_confidence(_row)
    _comp_count = _normalize_mv_comp_count(_row)
    _insufficient = bool(_row.get("insufficient_data", False))
    _mv_valid = bool(_row.get("mv_valid", False))
    _mv_conf_strict = str(_row.get("mv_confidence_strict") or "").strip().lower()
    _mv_action_gate = _mv_valid and _mv_conf_strict in {"high", "medium"}
    if _mv and _mv > 0 and not _insufficient:
        _mv_status_norm = "ready"
    elif _mv and _mv > 0:
        _mv_status_norm = "thin_support"
    elif _insufficient:
        _mv_status_norm = "insufficient_data"
    else:
        _mv_status_norm = "no_mv"
    _target_bid = None
    _target_source = "unavailable"
    _target_bid_mode = "none"
    _bid_ceiling = None
    _bid_source = "NONE"
    _bid_conf = "NONE"
    if _bid_basis is not None and _bid_basis > 0:
        for _field_name, _source_name in (
            ("adjusted_max_bid", "adjusted_max_bid"),
            ("target_max_bid", "target_max_bid"),
            ("target_bid", "target_bid"),
            ("target_bid_price", "target_bid_price"),
            ("max_bid", "max_bid"),
        ):
            try:
                _candidate = float(_row.get(_field_name) or 0.0)
            except (TypeError, ValueError):
                _candidate = 0.0
            if _candidate > 0:
                _target_bid = round(_candidate, 2)
                _target_source = _source_name
                _target_bid_mode = "review_ceiling" if _bid_anchor_mode == "review_estimate" else "strict"
                _bid_ceiling = _target_bid
                _bid_source = "REVIEW_CEILING" if _bid_anchor_mode == "review_estimate" else "STRICT"
                _bid_conf = "REVIEW" if _bid_anchor_mode == "review_estimate" else "HIGH"
                break
    try:
        _current_price = float(_row.get("current_price") or _row.get("current_bid") or 0.0)
    except (TypeError, ValueError):
        _current_price = 0.0
    _clean_bid_identity = _is_clean_bid_identity(_row)
    _strict_identity = _clean_bid_identity and str(_row.get("target_fit_tier") or "").strip().lower() in {"exact", "strong_family", "exact_match", "strong_match"}
    # Path A: Strict target bid — clean identity, mv valid, medium/high confidence, 3+ comps
    if (
        _target_bid is None
        and _mv and _mv > 0
        and _mv_valid
        and _clean_bid_identity
        and _comp_count >= 3
        and _conf in {"high", "medium"}
    ):
        _strict_pct = 0.75 if _conf == "high" else 0.72
        _strict_bid = round(_mv * _strict_pct, 2)
        if _strict_bid > 0 and (_current_price <= 0 or _strict_bid >= (_current_price * 0.92)):
            _target_bid = _strict_bid
            _target_source = "market_value_default_75pct"
            _target_bid_mode = "strict"
            _bid_ceiling = _strict_bid
            _bid_source = "STRICT"
            _bid_conf = "HIGH" if _conf == "high" else "MEDIUM"
    try:
        _edge_pct = float(_row.get("edge_pct") or _row.get("edge_percent") or 0.0)
    except (TypeError, ValueError):
        _edge_pct = 0.0
    if (_edge_pct == 0.0) and _mv and _mv > 0 and _current_price > 0 and (_mv_action_gate or _bid_source == "STRICT"):
        _edge_pct = max(0.0, (_mv - _current_price) / _mv * 100.0)

    # ── Bid Ladder: conservative paths for clean exact rows ───────────────────
    # Only runs when Path A produced no bid.
    # Hard gates: clean identity, no rescue. Never applied to weak-family or rescue rows.
    _tb_conf = _bid_conf
    if _target_bid is not None:
        # Path A was used — derive confidence from strict gate or conf field
        if _bid_anchor_mode == "review_estimate":
            _tb_conf = "REVIEW"
            _bid_source = "REVIEW_CEILING"
            _bid_conf = "REVIEW"
        elif _target_source in {"adjusted_max_bid", "target_max_bid", "target_bid", "target_bid_price", "max_bid"}:
            _tb_conf = "HIGH"
            _bid_source = "STRICT"
            _bid_conf = "HIGH"
        elif (_mv_action_gate or _bid_source == "STRICT") and _conf == "high":
            _tb_conf = "HIGH"
            _bid_source = "STRICT"
            _bid_conf = "HIGH"
        elif _mv_action_gate or _bid_source == "STRICT":
            _tb_conf = "MEDIUM"
            _bid_source = "STRICT"
            _bid_conf = "MEDIUM"
        else:
            _tb_conf = "MEDIUM"
            _bid_conf = "MEDIUM"
    else:
        # Paths B and C — clean exact rows only
        _ladder_entity = str(_row.get("entity_match_status") or "").upper()
        _ladder_rescue = str(_row.get("rescue_trust_tier") or "none").lower()
        _ladder_fit = str(_row.get("target_fit_tier") or "").lower()
        _clean_exact = (
            _ladder_entity in {"EXACT", "STRONG_FAMILY", "EXACT_MATCH"}
            or _ladder_fit in {"exact", "strong_family", "exact_match", "strong_match"}
        ) and _ladder_rescue == "none"

        if _clean_exact:
            try:
                _vrl = float(_row.get("value_range_low") or 0.0) or None
                _vrh = float(_row.get("value_range_high") or 0.0) or None
            except (TypeError, ValueError):
                _vrl = _vrh = None

            # Path B: Conservative median discount — clean identity, 3+ comps, acceptable variance.
            if _target_bid is None and _mv and _mv > 0 and _conf in {"high", "medium"} and _comp_count >= 3 and _strict_identity:
                _var_b = (_vrh - _vrl) / _mv if (_vrl and _vrh and _mv > 0 and _vrh > _vrl) else 0.3
                if _var_b < 0.60:
                    _median_anchor = _mv
                    if _vrl and _vrh and _vrl > 0 and _vrh > 0:
                        _median_anchor = (_vrl + _vrh) / 2.0
                    _cand_b = round(_median_anchor * (0.70 if _conf == "high" else 0.67), 2)
                    if _cand_b > 0:
                        _target_bid = _cand_b
                        _target_source = "discount_median"
                        _target_bid_mode = "median_discount"
                        _tb_conf = "MEDIUM"
                        _bid_ceiling = _cand_b
                        _bid_source = "MEDIAN_DISCOUNT"
                        _bid_conf = "MEDIUM"

            # Path C: Review bid ceiling — exact/strong family, 2+ comps, low anchor + strong haircut.
            if _target_bid is None and _comp_count >= 2 and _strict_identity:
                _anchor_c = None
                if _vrl and _vrl > 0:
                    _anchor_c = _vrl
                elif _mv and _mv > 0:
                    _anchor_c = _mv
                if _anchor_c and _anchor_c > 0 and float(_row.get("commercial_signal_score") or 0.0) >= 12.0:
                    _var_c = (_vrh - _vrl) / _anchor_c if (_vrl and _vrh and _anchor_c > 0 and _vrh > _vrl) else 0.4
                    if _var_c < 0.75:
                        _cand_c = round(_anchor_c * 0.58, 2)
                        if _cand_c > 0:
                            _target_bid = _cand_c
                            _target_source = "review_ceiling"
                            _target_bid_mode = "review_ceiling"
                            _tb_conf = "REVIEW"
                            _bid_ceiling = _cand_c
                            _bid_source = "REVIEW_CEILING"
                            _bid_conf = "REVIEW"

        if _target_bid is None and _mv and _mv > 0 and _row_exact_surface_candidate(_row) and _clean_bid_identity:
            _provisional_bid, _provisional_mode = _build_provisional_target_bid(_row)
            if _provisional_bid is not None and _provisional_bid > 0:
                _target_bid = _provisional_bid
                _target_source = _provisional_mode
                _target_bid_mode = _provisional_mode
                _tb_conf = (
                    "HIGH" if _provisional_mode == "strict"
                    else "MEDIUM" if _provisional_mode == "median_discount"
                    else "REVIEW"
                )
                _bid_ceiling = _provisional_bid
                _bid_source = (
                    "STRICT" if _provisional_mode == "strict"
                    else "MEDIAN_DISCOUNT" if _provisional_mode == "median_discount"
                    else "REVIEW_CEILING"
                )
                _bid_conf = _tb_conf
        if (
            _target_bid is None
            and _bid_basis is not None
            and _bid_basis > 0
            and _bid_anchor_mode == "review_estimate"
            and _row_exact_surface_candidate(_row)
            and _clean_bid_identity
        ):
            _review_bid, _review_mode, _review_anchor_mode = _compute_final_target_bid_from_anchor(
                _row,
                _bid_basis,
                _bid_anchor_mode,
            )
            if _review_bid is not None and _review_bid > 0:
                _target_bid = _review_bid
                _target_source = f"final_{_review_anchor_mode}"
                _target_bid_mode = _review_mode
                _tb_conf = "REVIEW"
                _bid_ceiling = _review_bid
                _bid_source = "REVIEW_CEILING"
                _bid_conf = "REVIEW"

    if _bid_ceiling is None and _target_bid is not None and _target_bid > 0:
        _bid_ceiling = _target_bid
    if _target_bid is None:
        _bid_source = "NONE"
        _bid_conf = "NONE"
        _target_bid_mode = "none"

    _row["mv_value"] = _mv
    _row["market_value"] = _mv
    _row["market_value_true"] = _mv
    _row["final_bid_anchor_value"] = _bid_anchor_value
    _row["final_bid_anchor_mode"] = _bid_anchor_mode
    _row["anchored_estimate_value"] = _safe_float(_row.get("anchored_estimate_value"))
    _row["mv_source"] = _source
    _row["mv_confidence"] = str(_row.get("mv_confidence") or _conf).upper()
    _row["confidence"] = str(_row.get("confidence") or _row.get("mv_confidence") or _conf).upper()
    _row["valuation_confidence"] = _conf
    _row["mv_comp_count"] = _comp_count
    _row["comp_count"] = _comp_count
    _row["mv_status_norm"] = _mv_status_norm
    _row["target_bid"] = _target_bid
    _row["target_bid_price"] = _target_bid
    _row["target_bid_mode"] = _target_bid_mode
    _row["target_bid_source"] = _target_source
    _row["target_bid_source_detail"] = _target_source
    _row["target_bid_confidence"] = _tb_conf
    _row["target_bid_pct_used"] = (
        0.75 if _target_source == "market_value_default_75pct" else
        0.82 if _target_bid_mode == "strict" and _target_source == "strict" else
        0.74 if _target_bid_mode == "median_discount" else
        0.64 if _target_bid_mode == "review_ceiling" else
        0.68 if _target_source == "discount_median" else
        0.62 if _target_source == "review_ceiling" else
        (0.75 if _target_bid is not None else None)
    )
    _row["target_bid_ready"] = bool(_target_bid is not None and _target_bid > 0 and _bid_basis is not None and _bid_basis > 0)
    _row["bid_ceiling_value"] = round(_bid_ceiling, 2) if _bid_ceiling is not None and _bid_ceiling > 0 else None
    _row["bid_ceiling_confidence"] = _bid_conf
    _row["bid_ceiling_source"] = _bid_source
    _row["bid_ceiling_ready"] = bool(_bid_ceiling is not None and _bid_ceiling > 0 and _bid_basis is not None and _bid_basis > 0)
    _review_payload = _build_review_evidence_payload(_row)
    if _review_payload:
        _row["review_evidence_payload"] = list(_review_payload)
    if (
        (
            str(_row.get("truth_level") or _row.get("valuation_truth_level") or "").strip().upper() == "REVIEW"
            or str(_row.get("truth") or _row.get("_valuation_truth_tier") or _row.get("valuation_truth_tier") or "").strip().upper() == "REVIEW"
        )
        and _safe_float(_row.get("target_bid")) not in (None, 0)
        and _safe_float(_row.get("review_estimate_value") or _row.get("review_estimate")) not in (None, 0)
        and _review_payload
    ):
        _row["evidence_renderable"] = 1
        _row["evidence_render_source"] = "review_payload"
        _row["commercial_evidence_mode"] = "review"
        _row["renderable_evidence_count"] = len(_review_payload)
        _row["renderable_evidence_rows"] = list(_review_payload)
        _row["valuation_support_label"] = "REVIEW_EVIDENCE_ONLY"
        print(
            f"[REVIEW_EVIDENCE_ALLOW] title={str(_row.get('title') or _row.get('source_title') or '')[:120]} "
            f"truth=REVIEW target_bid={round(float(_safe_float(_row.get('target_bid')) or 0.0), 2)} "
            f"keep=1 source=review_payload"
        )
    _row["edge_pct"] = _edge_pct
    if str(_row.get("route_stage") or "").strip().lower() == "promoted_live_candidate":
        _row["promoted_live_candidate"] = True
        _row["comp_attempted"] = True
        _row["mv_attempted"] = True
        _row["mv_resolved"] = bool(_mv and _mv > 0)
        _row["target_bid_attempted"] = True
        _fail_reasons = _valuation_failure_reasons(_row)
        _failure_map = {
            "no_comps": "No clean comps found.",
            "no_mv": "No usable market value resolved.",
            "weak_source": "Comps found but too inconsistent.",
            "low_conf": "Valuation confidence below threshold.",
            "no_target_bid": "No bid recommendation because confidence is too thin.",
            "weak_edge": "Current edge is too weak for a bid recommendation.",
        }
        _review_failure_reason = next((_failure_map.get(_r) for _r in _fail_reasons if _failure_map.get(_r)), None)
        if bool(_row["mv_resolved"]) and bool(_row["target_bid_ready"]) and (_comp_count > 0 or _conf in {"high", "medium"}):
            _status = "resolved"
            _reason = f"Promoted for premium review — MV resolved from {max(1, int(_comp_count or 0))} usable comp{'s' if int(_comp_count or 0) != 1 else ''}."
            _review_failure_reason = None
        elif bool(_row["mv_resolved"]) or _comp_count > 0 or _conf in {"high", "medium"}:
            _status = "partial"
            _reason = f"Premium review partial — {_review_failure_reason or 'valuation support is still thin.'}"
        else:
            _status = "failed"
            _reason = f"Premium review failed — {_review_failure_reason or 'no clean comps found.'}"
        _row["premium_review_status"] = _status
        _row["premium_review_reason"] = _reason
        _row["review_failed"] = _status == "failed"
        _row["review_failure_reason"] = _review_failure_reason
    else:
        _row["promoted_live_candidate"] = bool(_row.get("promoted_live_candidate"))
        _row["premium_review_status"] = str(_row.get("premium_review_status") or "")
        _row["premium_review_reason"] = str(_row.get("premium_review_reason") or "")
        _row["review_failed"] = bool(_row.get("review_failed"))
        _row["review_failure_reason"] = str(_row.get("review_failure_reason") or "")
    return _row


def _valuation_failure_reasons(item: Dict[str, Any]) -> List[str]:
    _row = _stamp_mv_truth_fields(dict(item or {}))
    _reasons: List[str] = []
    try:
        _mv = float(_row.get("market_value_true") or 0.0)
    except (TypeError, ValueError):
        _mv = 0.0
    _comp_count = int(_row.get("mv_comp_count") or _row.get("comp_count") or 0)
    _conf = _normalize_mv_confidence(_row)
    try:
        _edge = float(_row.get("edge_pct") or _row.get("edge_percent") or 0.0)
    except (TypeError, ValueError):
        _edge = 0.0
    _source = str(_row.get("mv_source") or _row.get("market_value_source") or "none").strip().lower()
    if _mv <= 0:
        _reasons.append("no_mv")
    if _comp_count <= 0:
        _reasons.append("no_comps")
    if _conf in {"low", "unknown"}:
        _reasons.append("low_conf")
    if not _row_target_bid_ready(_row):
        _reasons.append("no_target_bid")
    if _mv > 0 and _edge < 0:
        _reasons.append("weak_edge")
    if _source in {"structured_fallback", "none", "error", "listing_type_excluded"}:
        _reasons.append("weak_source")
    if not bool(_row.get("market_value_true")):
        _reasons.append("anchor_only_no_real_mv")
    return _reasons


def _log_mv_failure_sample(item: Dict[str, Any], *, reasons: List[str]) -> None:
    _title = str((item or {}).get("title") or "")[:88]
    print(
        f"[ES][MV_FAIL_SAMPLE] title=\"{_title}\" mv={str((item or {}).get('mv_value') or (item or {}).get('market_value') or '')} "
        f"comps={int((item or {}).get('mv_comp_count') or (item or {}).get('comp_count') or 0)} "
        f"confidence={str((item or {}).get('valuation_confidence') or (item or {}).get('mv_confidence') or (item or {}).get('confidence') or '')} "
        f"source={str((item or {}).get('mv_source') or (item or {}).get('market_value_source') or '')} "
        f"reason={','.join(list(reasons or [])[:3])}"
    )


def _valuation_bucket_for_row(item: Dict[str, Any]) -> str:
    _row = _stamp_mv_truth_fields(dict(item or {}))
    try:
        _mv = float(_row.get("market_value_true") or 0.0)
    except (TypeError, ValueError):
        _mv = 0.0
    try:
        _edge = float(_row.get("edge_pct") or 0.0)
    except (TypeError, ValueError):
        _edge = 0.0
    _comp_count = int(_row.get("mv_comp_count") or _row.get("comp_count") or 0)
    _quality = str(_row_quality_state(_row) or "").strip().lower()
    _conf = _normalize_mv_confidence(_row)
    _has_conf_support = _conf in {"high", "medium"}
    _target_bid_ready = bool(_row.get("target_bid_ready")) or _row_target_bid_ready(_row)
    if _mv > 0 and _target_bid_ready and ((_comp_count >= 1 and _has_conf_support) or _comp_count >= 2 or _quality == "execution_ready" or (_has_conf_support and str(_row.get("mv_source") or _row.get("market_value_source") or "").strip().lower() not in {"structured_fallback", "none", "error", "listing_type_excluded"})) and (_edge >= 0 or _quality == "execution_ready"):
        return "action_ready"
    if _mv > 0 or _target_bid_ready or _comp_count > 0 or _has_conf_support or _quality in {"execution_ready", "monitor_only"}:
        return "monitor"
    return "suppressed"


def _ending_soon_exclusion_reason(item: Dict[str, Any]) -> str:
    """Hard pre-render exclusion for obvious non-single-card listings."""
    title = str((item or {}).get("title") or "").strip()
    lower = title.lower()
    listing_type = str((item or {}).get("single_card_listing_type") or classify_listing_type(item)).strip().upper()
    if listing_type in {
        "MULTI_CARD_LOT",
        "BREAK_OR_SPOT",
        "SEALED_WAX_OR_BOX",
        "TEAM_SET_OR_COLLECTION",
        "AMBIGUOUS_MULTI",
    }:
        return f"classified_{listing_type.lower()}"
    if re.search(r"\b(lot|lots|bundle|mixed\s+lot|collection|team\s+lot|set\s+of|complete\s+set|break|break\s+spot|case\s+break|hobby\s+box|blaster|mega|hanger)\b", lower):
        return "obvious_non_single_keyword"
    if re.search(r"\b(rookies|patches|parallels)\b", lower) and re.search(r"\b(lot|bundle|mixed|group|multi)\b", lower):
        return "grouped_rookie_patch_parallel_lot"
    if re.search(r"\b(etc|and\s+more|plus\s+more|plus\s+extras|with\s+extras)\b", lower):
        return "open_ended_multi_listing"
    if re.search(r"\b\d+\s*(card|cards)\b", lower) or re.search(r"\blot\s+of\s+\d+\b", lower):
        return "explicit_multi_card_count"
    comma_count = title.count(",")
    sep_hits = 0
    for tok in (" / ", " & ", " and ", "+"):
        if tok in lower:
            sep_hits += 1
    if comma_count >= 2 and re.search(r"\b(rookie|rc|patch|prizm|optic|mosaic|select|bowman|chrome)\b", lower):
        return "multi_subject_title"
    if sep_hits >= 2 and re.search(r"\b(rookie|rc|patch|parallel|auto|prizm|optic|mosaic|select|bowman|chrome)\b", lower):
        return "multi_subject_title"
    return ""


def _hard_shape_reject_reason(title: str) -> str:
    _lower = str(title or "").strip().lower()
    if not _lower:
        return ""
    # Oversized Downtown variants — also catch "giant" / "giant-size" / "giant size"
    # which are how Panini sometimes labels the oversized boxtopper version.
    # Only the size-descriptor forms; bare "giant" would false-positive on
    # NY Giants / SF Giants team names.
    if re.search(
        r"\b(oversized|oversize|jumbo|large[\s-]?format|giant[\s-]?size)\s+(downtown|dt)\b",
        _lower,
    ):
        return "oversized_downtown"
    if re.search(
        r"\b(downtown|dt)\s+(oversized|oversize|jumbo|large[\s-]?format|giant[\s-]?size)\b",
        _lower,
    ):
        return "oversized_downtown"
    return ""


def _is_nonstandard_subset_variant(title: str) -> Tuple[bool, str]:
    _t = str(title or "").lower()
    _bad_terms = {
        "oversized card": "oversized",
        "oversized": "oversized",
        "oversize": "oversized",
        "jumbo": "jumbo",
        "box topper": "box_topper",
        "display": "display_variant",
    }
    for _term, _reason in _bad_terms.items():
        if _term in _t:
            return True, _reason

    # Image/photo variations are structurally ambiguous without a card-number anchor.
    # A "VARIATION" title may refer to a base refractor or an SSP/photo variation
    # worth dramatically more. If there is no explicit card number in the raw title,
    # treat it as nonstandard/unsafe for exact-lane trust.
    if re.search(r"\bvariation(?:s)?\b", _t):
        if not re.search(r"#\s*[A-Za-z]{0,4}-?\d+\b", str(title or "")):
            return True, "ambiguous_variation_no_card_number"

    return False, ""


_SUBSET_NONSTANDARD_VARIANT_ALLOWLIST: Dict[str, frozenset] = {}


def _subset_lane_requires_standard_variant(spec: Dict[str, Any]) -> bool:
    _spec = spec or {}
    _lane_type = str(_spec.get("target_lane_type") or "").strip().lower()
    _query_kind = str(_spec.get("query_kind") or "").strip().lower()
    return bool(_lane_type in {"lane_subset", "premium_subset", "subset"} or "lane_subset" in _query_kind)


def _allowed_subset_variant_reasons(spec: Dict[str, Any]) -> set:
    _spec = spec or {}
    _subset = str(
        _spec.get("subset_name")
        or (_spec.get("target_meta") or {}).get("subset_name")
        or _spec.get("lane_subset")
        or ""
    ).strip().lower()
    _allowed = set(_SUBSET_NONSTANDARD_VARIANT_ALLOWLIST.get(_subset, frozenset()))
    for _raw in (
        _spec.get("subset_variant_allowlist"),
        (_spec.get("target_meta") or {}).get("subset_variant_allowlist"),
        (_spec.get("tracked_target") or {}).get("subset_variant_allowlist"),
    ):
        if isinstance(_raw, (list, tuple, set, frozenset)):
            _allowed.update(str(_v).strip().lower() for _v in _raw if str(_v).strip())
    return _allowed

# ---------------------------------------------------------------------------
# API rate throttle — minimum 0.5s between eBay Browse API calls
# Used by both _fetch_auctions_for_spec and _fetch_bin_for_spec so that
# parallel workers don't hammer the API simultaneously.
# ---------------------------------------------------------------------------

_API_THROTTLE_LOCK = threading.Lock()
_API_LAST_CALL_TS  = 0.0
_API_MIN_SPACING   = 1.2   # seconds — raised from 0.5; circuit breaker may widen further

def _api_throttle() -> None:
    """Acquire the right to make one eBay API call.
    Spacing is adaptive: reads current circuit-breaker mode to slow down in
    slow/cooldown state.  Thread-safe.
    """
    global _API_LAST_CALL_TS
    spacing = _circuit_current_spacing()   # may be larger than _API_MIN_SPACING
    with _API_THROTTLE_LOCK:
        now  = time.monotonic()
        wait = spacing - (now - _API_LAST_CALL_TS)
        if wait > 0:
            time.sleep(wait)
        _API_LAST_CALL_TS = time.monotonic()


# ---------------------------------------------------------------------------
# Rate-aware circuit breaker — tracks 429 events and escalates executor mode
# ---------------------------------------------------------------------------

# Mode ladder:  "normal"  →(2+ 429s in window)→  "slow"
#               "slow"    →(3+ 429s in window)→  "cooldown"
#               "cooldown"→(cooldown expires)→   "slow"

_CB_LOCK:           threading.Lock = threading.Lock()
_CB_RL_TIMESTAMPS:  List[float]    = []   # monotonic() stamps of 429 events
_CB_COOLDOWN_UNTIL: float          = 0.0  # monotonic() — hard-pause until here
_CB_MODE:           str            = "normal"  # "normal" | "slow" | "cooldown"

_CB_RL_WINDOW     = 30.0  # seconds — rolling window for counting 429 events
_CB_RL_SLOW_AT    = 2     # escalate to "slow" when this many 429s in window
_CB_RL_COOL_AT    = 3     # escalate to "cooldown" when this many 429s in window
_CB_COOLDOWN_SECS = 45.0  # how long to pause before resuming in slow mode

_CB_SPACING_NORMAL = _API_MIN_SPACING   # 1.2 s
_CB_SPACING_SLOW   = 2.8               # wider gap in slow mode

_CB_JITTER_NORMAL  = (0.1, 0.9)   # (min, max) random sleep before each API call
_CB_JITTER_SLOW    = (0.5, 2.2)   # wider jitter in slow/cooldown mode


def _circuit_record_rl() -> None:
    """Record one 429 event and escalate mode if threshold crossed."""
    global _CB_RL_TIMESTAMPS, _CB_COOLDOWN_UNTIL, _CB_MODE
    now = time.monotonic()
    with _CB_LOCK:
        cutoff = now - _CB_RL_WINDOW
        _CB_RL_TIMESTAMPS = [t for t in _CB_RL_TIMESTAMPS if t > cutoff]
        _CB_RL_TIMESTAMPS.append(now)
        count = len(_CB_RL_TIMESTAMPS)

        if count >= _CB_RL_COOL_AT and _CB_MODE != "cooldown":
            _CB_MODE = "cooldown"
            _CB_COOLDOWN_UNTIL = now + _CB_COOLDOWN_SECS
            print(
                f"[RADAR][RECOVERY] circuit_breaker entered cooldown={_CB_COOLDOWN_SECS:.0f}s "
                f"due_to=rate_limit_spike rl_events={count}"
            )
        elif count >= _CB_RL_SLOW_AT and _CB_MODE == "normal":
            _CB_MODE = "slow"
            print(
                f"[RADAR][RECOVERY] circuit_breaker mode=slow "
                f"spacing={_CB_SPACING_SLOW}s jitter=wider rl_events={count}"
            )


def _circuit_pre_request() -> bool:
    """
    Must be called before every API attempt.
    Returns True if the call is permitted (possibly after sleeping out cooldown).
    Returns False if the circuit is in hard cooldown and the call should be skipped.
    """
    global _CB_MODE, _CB_COOLDOWN_UNTIL
    now = time.monotonic()
    with _CB_LOCK:
        if _CB_MODE == "cooldown":
            remaining = _CB_COOLDOWN_UNTIL - now
            if remaining > 0:
                # Hard block — tell caller to defer this family
                return False
            else:
                # Cooldown expired — step down to slow
                _CB_MODE = "slow"
                print("[RADAR][RECOVERY] circuit_breaker cooldown expired, resuming mode=slow")
    return True


def _circuit_current_spacing() -> float:
    """Return the current per-call minimum spacing based on circuit mode."""
    with _CB_LOCK:
        if _CB_MODE in ("slow", "cooldown"):
            return _CB_SPACING_SLOW
    return _CB_SPACING_NORMAL


def _circuit_jitter() -> None:
    """Sleep a randomized amount to break up request burst patterns."""
    with _CB_LOCK:
        mode = _CB_MODE
    lo, hi = _CB_JITTER_SLOW if mode in ("slow", "cooldown") else _CB_JITTER_NORMAL
    time.sleep(_random.uniform(lo, hi))


def get_circuit_mode() -> str:
    """Public accessor for current circuit-breaker mode (for logging / UI)."""
    with _CB_LOCK:
        return _CB_MODE


# ---------------------------------------------------------------------------
# POL helper timers
# ---------------------------------------------------------------------------

def _pol_family_sleep() -> None:
    """Inter-family sleep for proof-of-life mode (2.5–4.0 s)."""
    secs  = _random.uniform(*_POL_FAMILY_SPACING)
    until = time.time() + secs
    print(
        f"[RADAR][POL] inter_family_sleep={secs:.1f}s "
        f"next_allowed={time.strftime('%H:%M:%S', time.localtime(until))}"
    )
    time.sleep(secs)


def _pol_rl_pause() -> None:
    """Extra pause after a 429 event in proof-of-life mode (5–10 s)."""
    secs  = _random.uniform(*_POL_RL_PAUSE_RANGE)
    until = time.time() + secs
    print(
        f"[RADAR][POL] rate_limit_pause={secs:.1f}s "
        f"cooldown_until={time.strftime('%H:%M:%S', time.localtime(until))}"
    )
    time.sleep(secs)


# ---------------------------------------------------------------------------
# Progress tracking — read by scan_scheduler for the "scanning X of Y" display
# ---------------------------------------------------------------------------

_PROGRESS_LOCK     = threading.Lock()
_PROGRESS_DONE     = 0
_PROGRESS_TOTAL    = 0
_PROGRESS_PLAYER   = ""
_PROGRESS_CALLBACK: Optional[Callable[[str, int, int], None]] = None
_SCAN_ACTIVE       = False
_SCAN_PHASE        = "idle"
_SCAN_STARTED_AT   = 0.0
_SCAN_COMPLETED_AT = 0.0
_SCAN_LAST_HEARTBEAT_AT = 0.0
_SCAN_PROGRESS_CURRENT = 0
_SCAN_PROGRESS_TOTAL_UNITS = 0
_SCAN_PROGRESS_LABEL = ""
_LAST_COMPLETED_ACTION = ""
_SCAN_FAILED       = False
_SCAN_ERROR_MESSAGE = ""
_LATEST_COMPLETED_SCAN: Dict[str, Any] = {}
_LATEST_ACTIVE_SCAN_PARTIAL: Dict[str, Any] = {}


def _progress_tick(player_name: str) -> None:
    """Called from each fetch worker when it completes. Thread-safe."""
    global _PROGRESS_DONE, _PROGRESS_PLAYER
    with _PROGRESS_LOCK:
        _PROGRESS_DONE  += 1
        _PROGRESS_PLAYER = player_name
        done  = _PROGRESS_DONE
        total = _PROGRESS_TOTAL
        cb    = _PROGRESS_CALLBACK
    if cb:
        try:
            cb(player_name, done, total)
        except Exception:
            pass


def _clear_active_scan_partial_snapshot() -> None:
    global _LATEST_ACTIVE_SCAN_PARTIAL
    _LATEST_ACTIVE_SCAN_PARTIAL = {}


def _set_active_scan_partial_snapshot(
    *,
    deals: List[Dict[str, Any]],
    meta: Dict[str, Any],
    cache_key: str,
    sport_filter: Optional[str],
    time_window_hours: float,
) -> None:
    global _LATEST_ACTIVE_SCAN_PARTIAL
    _meta = dict(meta or {})
    _rows = [dict(r or {}) for r in list(deals or [])]
    _LATEST_ACTIVE_SCAN_PARTIAL = {
        "cache_key": str(cache_key or ""),
        "sport_filter": sport_filter,
        "time_window_hours": float(time_window_hours or 0.0),
        "scan_started_at": float(_meta.get("scan_started_at") or 0.0),
        "scan_last_heartbeat_ts": float(_meta.get("scan_last_heartbeat_ts") or time.time()),
        "scan_phase": str(_meta.get("scan_phase") or "idle"),
        "latest_result_rows": _rows,
        "meta": _meta,
    }


def get_active_scan_partial_snapshot(
    *,
    sport_filter: Optional[str] = None,
    time_window_hours: Optional[float] = None,
) -> Dict[str, Any]:
    _snap = dict(_LATEST_ACTIVE_SCAN_PARTIAL or {})
    if not _snap:
        return {}
    if sport_filter is not None and _snap.get("sport_filter") != sport_filter:
        return {}
    if time_window_hours is not None:
        try:
            if abs(float(_snap.get("time_window_hours") or 0.0) - float(time_window_hours or 0.0)) > 1e-6:
                return {}
        except (TypeError, ValueError):
            return {}
    _snap["meta"] = dict(_snap.get("meta") or {})
    _snap["latest_result_rows"] = [dict(r or {}) for r in list(_snap.get("latest_result_rows") or [])]
    return _snap


def get_scan_progress() -> Tuple[int, int, str]:
    """Return (queries_done, queries_total, current_player). Thread-safe."""
    with _PROGRESS_LOCK:
        return _PROGRESS_DONE, _PROGRESS_TOTAL, _PROGRESS_PLAYER


def _scan_heartbeat(
    phase: str,
    detail: str = "",
    *,
    progress_current: Optional[int] = None,
    progress_total: Optional[int] = None,
    progress_label: Optional[str] = None,
) -> float:
    global _SCAN_PHASE, _LAST_COMPLETED_ACTION, _SCAN_FAILED, _SCAN_ERROR_MESSAGE
    global _SCAN_LAST_HEARTBEAT_AT, _SCAN_PROGRESS_CURRENT, _SCAN_PROGRESS_TOTAL_UNITS, _SCAN_PROGRESS_LABEL
    _now = time.time()
    with _PROGRESS_LOCK:
        _SCAN_PHASE = str(phase or "").strip() or "idle"
        _SCAN_FAILED = False
        _SCAN_ERROR_MESSAGE = ""
        _SCAN_LAST_HEARTBEAT_AT = _now
        if progress_current is not None:
            _SCAN_PROGRESS_CURRENT = int(progress_current or 0)
        if progress_total is not None:
            _SCAN_PROGRESS_TOTAL_UNITS = int(progress_total or 0)
        if progress_label is not None:
            _SCAN_PROGRESS_LABEL = str(progress_label or "")
        if detail:
            _LAST_COMPLETED_ACTION = str(detail or "").strip()
    print(f"[SCAN_HEARTBEAT] phase={str(phase or 'idle').strip() or 'idle'} ts={_now:.3f}")
    return _now


def set_scan_phase(phase: str, detail: str = "") -> None:
    _scan_heartbeat(phase, detail)


def set_scan_failure(error_message: str) -> None:
    global _SCAN_ACTIVE, _SCAN_PHASE, _SCAN_COMPLETED_AT, _LAST_COMPLETED_ACTION, _SCAN_FAILED, _SCAN_ERROR_MESSAGE
    global _SCAN_LAST_HEARTBEAT_AT
    _now = time.time()
    with _PROGRESS_LOCK:
        _SCAN_ACTIVE = False
        _SCAN_PHASE = "failed"
        _SCAN_COMPLETED_AT = _now
        _SCAN_LAST_HEARTBEAT_AT = _now
        _SCAN_FAILED = True
        _SCAN_ERROR_MESSAGE = str(error_message or "")[:240]
        _LAST_COMPLETED_ACTION = "Scan failed"


def get_scan_state() -> Dict[str, Any]:
    with _PROGRESS_LOCK:
        return {
            "scan_active": bool(_SCAN_ACTIVE),
            "scan_phase": str(_SCAN_PHASE or "idle"),
            "scan_started_at": float(_SCAN_STARTED_AT or 0.0),
            "scan_completed_at": float(_SCAN_COMPLETED_AT or 0.0),
            "scan_last_heartbeat_ts": float(_SCAN_LAST_HEARTBEAT_AT or 0.0),
            "scan_progress_current": int(_SCAN_PROGRESS_CURRENT or 0),
            "scan_progress_total": int(_SCAN_PROGRESS_TOTAL_UNITS or 0),
            "scan_progress_label": str(_SCAN_PROGRESS_LABEL or ""),
            "last_completed_action": str(_LAST_COMPLETED_ACTION or ""),
            "scan_failed": bool(_SCAN_FAILED),
            "scan_error_message": str(_SCAN_ERROR_MESSAGE or ""),
            "progress_done": int(_PROGRESS_DONE or 0),
            "progress_total": int(_PROGRESS_TOTAL or 0),
            "progress_player": str(_PROGRESS_PLAYER or ""),
        }


def _set_latest_completed_scan_snapshot(
    *,
    deals: List[Dict[str, Any]],
    meta: Dict[str, Any],
    cache_key: str,
    sport_filter: Optional[str],
    time_window_hours: float,
) -> None:
    global _LATEST_COMPLETED_SCAN
    _meta = dict(meta or {})
    _rows = [dict(r or {}) for r in list(deals or [])]
    _execution_rows = sum(1 for r in _rows if str((r or {}).get("row_quality_state") or "").strip() == "execution_ready")
    _monitor_rows = sum(1 for r in _rows if str((r or {}).get("row_quality_state") or "").strip() == "monitor_only")
    _elite_rows = sum(1 for r in _rows if str((r or {}).get("deal_class") or "").strip().upper() == "ELITE")
    _rendered_rows = len(_rows)
    _admitted_rows = int(_meta.get("rows_admitted", _rendered_rows) or _rendered_rows)
    _snapshot = {
        "cache_key": str(cache_key or ""),
        "sport_filter": sport_filter,
        "time_window_hours": float(time_window_hours or 0.0),
        "scan_completed_at": float(_meta.get("scan_completed_at") or time.time()),
        "scan_started_at": float(_meta.get("scan_started_at") or 0.0),
        "listings_found": int(_meta.get("raw_auction_count", _rendered_rows) or _rendered_rows),
        "elite_count": int(_elite_rows),
        "admitted_rows": int(_admitted_rows),
        "execution_rows": int(_execution_rows),
        "monitor_rows": int(_monitor_rows),
        "rendered_rows": int(_rendered_rows),
        "latest_result_rows": _rows,
        "telemetry_summary": {
            "configured_target_lanes": int(_meta.get("configured_target_lanes", 0) or 0),
            "lanes_scanned": int(_meta.get("lanes_scanned", 0) or 0),
            "rows_passed_to_valuation": int(_meta.get("rows_passed_to_valuation", 0) or 0),
            "rows_scored": int(_meta.get("rows_scored", 0) or 0),
            "rows_execution_ready": int(_meta.get("rows_execution_ready", 0) or 0),
            "rows_monitor_only": int(_meta.get("rows_monitor_only", 0) or 0),
            "rows_quarantined": int(_meta.get("rows_quarantined", 0) or 0),
        },
        "meta": _meta,
    }
    _meta["latest_scan_snapshot"] = {
        "scan_completed_at": _snapshot["scan_completed_at"],
        "listings_found": _snapshot["listings_found"],
        "elite_count": _snapshot["elite_count"],
        "admitted_rows": _snapshot["admitted_rows"],
        "execution_rows": _snapshot["execution_rows"],
        "monitor_rows": _snapshot["monitor_rows"],
        "rendered_rows": _snapshot["rendered_rows"],
    }
    _LATEST_COMPLETED_SCAN = _snapshot


def get_latest_completed_scan_snapshot(
    *,
    sport_filter: Optional[str] = None,
    time_window_hours: Optional[float] = None,
) -> Dict[str, Any]:
    _snap = dict(_LATEST_COMPLETED_SCAN or {})
    if not _snap:
        return {}
    if sport_filter is not None and _snap.get("sport_filter") != sport_filter:
        return {}
    if time_window_hours is not None:
        try:
            if abs(float(_snap.get("time_window_hours") or 0.0) - float(time_window_hours or 0.0)) > 1e-6:
                return {}
        except (TypeError, ValueError):
            return {}
    _snap["meta"] = dict(_snap.get("meta") or {})
    _snap["latest_result_rows"] = [dict(r or {}) for r in list(_snap.get("latest_result_rows") or [])]
    return _snap


def store_latest_completed_scan_snapshot(
    deals: List[Dict[str, Any]],
    meta: Dict[str, Any],
    *,
    sport_filter: Optional[str] = None,
    time_window_hours: Optional[float] = None,
) -> None:
    _set_latest_completed_scan_snapshot(
        deals=deals,
        meta=meta,
        cache_key=str((meta or {}).get("cache_key") or ""),
        sport_filter=sport_filter,
        time_window_hours=float((meta or {}).get("time_window_hours") or time_window_hours or 0.0),
    )


def _budget_day_key(now_ts: Optional[float] = None) -> str:
    _ts = float(now_ts or time.time())
    return datetime.fromtimestamp(_ts, tz=timezone.utc).astimezone().strftime("%Y-%m-%d")


def _ensure_budget_state(now_ts: Optional[float] = None) -> None:
    _day_key = _budget_day_key(now_ts)
    with _BUDGET_LOCK:
        if str(_BUDGET_STATE.get("day_key") or "") == _day_key:
            return
        _BUDGET_STATE.update(
            {
                "day_key": _day_key,
                "daily_budget_total": _DAILY_BROWSE_BUDGET_TOTAL,
                "daily_budget_used": 0,
                "ending_soon_used": 0,
                "buying_radar_used": 0,
                "valuation_used": 0,
            }
        )


def get_budget_snapshot(now_ts: Optional[float] = None) -> Dict[str, Any]:
    _ensure_budget_state(now_ts)
    with _BUDGET_LOCK:
        _used = int(_BUDGET_STATE.get("daily_budget_used") or 0)
        _ending_used = int(_BUDGET_STATE.get("ending_soon_used") or 0)
        _radar_used = int(_BUDGET_STATE.get("buying_radar_used") or 0)
        _valuation_used = int(_BUDGET_STATE.get("valuation_used") or 0)
    _remaining = max(0, _DAILY_BROWSE_BUDGET_TOTAL - _used)
    return {
        "day_key": _budget_day_key(now_ts),
        "daily_budget_total": _DAILY_BROWSE_BUDGET_TOTAL,
        "daily_budget_used": _used,
        "daily_budget_remaining": _remaining,
        "ending_soon_budget": _ENDING_SOON_DAILY_BUDGET,
        "ending_soon_budget_used": _ending_used,
        "ending_soon_budget_remaining": max(0, _ENDING_SOON_DAILY_BUDGET - _ending_used),
        "buying_radar_budget": _BUYING_RADAR_DAILY_BUDGET,
        "buying_radar_budget_used": _radar_used,
        "buying_radar_budget_remaining": max(0, _BUYING_RADAR_DAILY_BUDGET - _radar_used),
        "valuation_budget": _VALUATION_DAILY_BUDGET,
        "valuation_budget_used": _valuation_used,
        "valuation_budget_remaining": max(0, _VALUATION_DAILY_BUDGET - _valuation_used),
        "reserve_budget": _RESERVE_DAILY_BUDGET,
    }


def _record_budget_usage(*, feed_type: str, browse_calls: int = 0, valuation_rows: int = 0) -> None:
    _ensure_budget_state()
    with _BUDGET_LOCK:
        if browse_calls > 0:
            _BUDGET_STATE["daily_budget_used"] = int(_BUDGET_STATE.get("daily_budget_used") or 0) + int(browse_calls)
            if str(feed_type).strip().lower() == "ending_soon":
                _BUDGET_STATE["ending_soon_used"] = int(_BUDGET_STATE.get("ending_soon_used") or 0) + int(browse_calls)
            elif str(feed_type).strip().lower() == "buying_radar":
                _BUDGET_STATE["buying_radar_used"] = int(_BUDGET_STATE.get("buying_radar_used") or 0) + int(browse_calls)
        if valuation_rows > 0:
            _BUDGET_STATE["valuation_used"] = int(_BUDGET_STATE.get("valuation_used") or 0) + int(valuation_rows)


def _allocate_cycle_budget(*, feed_type: str, now_ts: Optional[float] = None) -> Dict[str, Any]:
    _snap = get_budget_snapshot(now_ts)
    _feed = str(feed_type or "ending_soon").strip().lower()
    _feed_remaining = int(
        _snap.get("ending_soon_budget_remaining" if _feed == "ending_soon" else "buying_radar_budget_remaining") or 0
    )
    _daily_remaining = int(_snap.get("daily_budget_remaining") or 0)
    _reserve = int(_snap.get("reserve_budget") or 0)
    _usable_daily = max(0, _daily_remaining - _reserve)
    # [LANE_BUDGET_EXPANSION_2026_04_30] — bumped from 48 to 100 calls per
    # cycle for ending_soon (and 36 → 72 for buying_radar). With
    # _MAX_LANES_PER_CYCLE now 50 and lane_cap = scan_budget // 2, this lets
    # the cycle actually use 50 lanes when budget is available (previously
    # capped at 24 lanes due to the 48-call ceiling). User accepts higher
    # per-scan call cost in exchange for ~3x coverage of the 1,790 target
    # universe per scan.
    _scan_budget = max(0, min(_feed_remaining, _usable_daily, 100 if _feed == "ending_soon" else 72))
    _lane_cap = max(0, min(_MAX_LANES_PER_CYCLE, _scan_budget // 2))
    # [BUDGET_PASS_AUDIT] — primary_lane_cap fix.
    # Old formula:
    #     min(_PRIMARY_LANE_SCAN_TARGET, max(0, _lane_cap if _lane_cap <= 12 else 12))
    # The `else 12` branch hard-clamped primary lanes to 12 whenever
    # _lane_cap exceeded 12, even though _PRIMARY_LANE_SCAN_TARGET = 16
    # is the documented intent. With _lane_cap=20 the old formula
    # produced primary=12, secondary=8, total=20 lanes selected — but
    # the budget_pass cliff in [PREFETCH_STAGE] logs showed only 12
    # lanes actually executing. Removing the clamp restores the
    # intended 16 primary + 4 secondary = 20 lane allocation, lifting
    # per-scan volume by ~33%.
    _primary_lane_cap = max(0, min(_PRIMARY_LANE_SCAN_TARGET, _lane_cap))
    _secondary_lane_cap = min(_SECONDARY_LANE_SCAN_TARGET, max(0, _lane_cap - _primary_lane_cap))
    _valuation_remaining = int(_snap.get("valuation_budget_remaining") or 0)
    _valuation_cycle_cap = max(0, min(_MAX_ROWS_TO_VALUATION_PER_CYCLE, _valuation_remaining, 12 if _feed == "ending_soon" else 8))
    print(
        f"[BUDGET_PASS_AUDIT] feed={_feed} scan_budget={_scan_budget} "
        f"lane_cap={_lane_cap} primary_cap={_primary_lane_cap} "
        f"secondary_cap={_secondary_lane_cap} "
        f"primary_target={_PRIMARY_LANE_SCAN_TARGET} "
        f"secondary_target={_SECONDARY_LANE_SCAN_TARGET} "
        f"max_lanes_per_cycle={_MAX_LANES_PER_CYCLE}"
    )
    return {
        **_snap,
        "feed_type": _feed,
        "scan_budget_cycle": _scan_budget,
        "lane_scan_cap": _lane_cap,
        "primary_lane_cap": _primary_lane_cap,
        "secondary_lane_cap": _secondary_lane_cap,
        "candidate_admit_cap": _MAX_ROWS_ADMITTED_PER_CYCLE,
        "valuation_cycle_cap": _valuation_cycle_cap,
        "comp_lookups_cycle_cap": min(_MAX_COMP_LOOKUPS_PER_CYCLE, _valuation_cycle_cap),
        "budget_cap_reached": _scan_budget <= 0,
    }


# ---------------------------------------------------------------------------
# Inline deal-scoring — replaces market_value_engine dependency
# ---------------------------------------------------------------------------

_TIER_MULT = {1: 1.2, 2: 1.1, 3: 1.0}


def _deal_score(price: float, mv: float, tier: int) -> int:
    """0-100 deal score: discount vs MV with tier velocity multiplier."""
    if mv <= 0:
        return 0
    edge = (mv - price) / mv
    base = int(max(0, min(100, edge * 120)))
    mult = _TIER_MULT.get(tier, 1.0)
    return int(max(0, min(100, base * mult)))


def _classify_deal(score: int) -> str:
    if score >= 80:
        return "ELITE"
    if score >= 60:
        return "STRONG"
    if score >= 40:
        return "GOOD"
    if score >= 20:
        return "WEAK"
    return "PASS"

