_SERIAL_PATTERN_RE = re.compile(r"(?:^|[^\d])(?:1/1|/\d{1,3}|\d{1,3}/\d{1,3})(?:$|[^\d])", re.IGNORECASE)
_CARD_NUMBER_RE = re.compile(r"#\s?[A-Za-z0-9]{1,6}\b", re.IGNORECASE)
_TOPPS_INSERT_CARD_NUMBER_RE = re.compile(r"#\s?([A-Za-z0-9]{1,6}(?:-[A-Za-z0-9]{1,3})?)\b", re.IGNORECASE)

# ---------------------------------------------------------------------------
# Grade filtering
# ---------------------------------------------------------------------------

_GRADE_PARSE_RE = re.compile(
    r"\b(psa|bgs|sgc|cgc|hga|gma|ags)\s*(\d{1,2}(?:\.\d)?)\b", re.IGNORECASE
)
_SGC_DETECT_RE = re.compile(r"\bsgc\b", re.IGNORECASE)


def _passes_grade_filter(title: str) -> bool:
    """
    Allow: raw (no grader), PSA 9/10, BGS 9.5/10, CGC any.
    Reject: SGC (all grades), PSA 8 and below, BGS 9.0 and below.
    """
    if _SGC_DETECT_RE.search(title):
        return False  # SGC — always exclude
    m = _GRADE_PARSE_RE.search(title)
    if not m:
        return True   # raw / no grader
    company = m.group(1).upper()
    try:
        grade = float(m.group(2))
    except ValueError:
        return True   # can't parse grade — allow
    if company == "PSA":
        return grade >= 9    # PSA 9 and PSA 10 only
    if company == "BGS":
        return grade >= 9.5  # BGS 9.5 and BGS 10 only
    return True  # CGC, HGA, GMA — allow all


def classify_lane_quality(title: str) -> str:
    t = f" {str(title or '').lower()} "
    _hard_block_patterns = (
        r"\bx-fractor\b",
        r"\blogofractor\b",
    )
    for _pattern in _hard_block_patterns:
        if re.search(_pattern, t):
            return "BLOCK"

    if any(x in t for x in [
        " refractor psa 10 ",
        " prizm psa 10 ",
        " select psa 10 ",
    ]):
        return "CONDITIONAL"

    _has_low_serial = any(x in t for x in [
        "/25", "/10", "/5", "/1", " one of one ", " 1/1 ",
    ])
    _has_case_hit = any(x in t for x in [
        " kaboom ", " downtown ", " color blast ",
    ])
    _has_endgame = any(x in t for x in [
        " national treasures ", " immaculate ", " flawless ", " spectra ",
    ]) or bool(re.search(r"\bnt\b", t))
    _has_auto = any(x in t for x in [
        " auto ", " autograph ",
    ])
    _has_color = any(re.search(_pattern, t) for _pattern in (
        r"\bgold\b",
        r"\bblack\b",
        r"\bred\b",
    ))
    _has_modern_chrome = any(x in t for x in [
        " chrome ", " refractor ", " prizm ", " optic ", " select ", " mosaic ",
    ])

    if (
        _has_modern_chrome
        and _has_color
        and not (_has_low_serial or _has_case_hit or _has_endgame or _has_auto)
    ):
        return "BLOCK"

    if any(x in t for x in [
        " auto ", " autograph ",
        "/25", "/10", "/5", "/1",
        " kaboom ", " downtown ", " color blast ",
        " national treasures ", " immaculate ", " flawless ", " spectra ",
        " one of one ", " 1/1 ",
    ]) or bool(re.search(r"\bnt\b", t)) or _has_color:
        return "PREMIUM"

    if any(re.search(_pattern, t) for _pattern in (
        r"\bbase\b",
        r"\binsert\b",
        r"\blot\b",
        r"\bbulk\b",
    )):
        return "BLOCK"

    return "BLOCK"


def _title_filter_profile(title: str, tier: int = 0) -> Dict[str, bool]:
    _title = str(title or "")
    _t = _title.lower()
    _padded = f" {_t} "
    _lot_reject = any(_tok in _t for _tok in _LOT_REJECT) or bool(_ending_soon_exclusion_reason({"title": _title}))
    _premium_keyword = any(_kw in _t for _kw in _CARD_TYPE_KEYWORDS)
    _product_family = any(_kw in _t for _kw in _PRODUCT_FAMILY_TOKENS)
    _parallel = any(_kw in _t for _kw in _PARALLEL_SIGNAL_TOKENS)
    _auto = any(_kw in _t for _kw in _AUTO_SIGNAL_TOKENS)
    _memorabilia = any(_kw in _t for _kw in _MEMORABILIA_TOKENS)
    _serial = bool(_SERIAL_PATTERN_RE.search(_title))
    _card_number = bool(_CARD_NUMBER_RE.search(_title))
    _base_rookie = any(_tok in _padded for _tok in [f" {_tok} " for _tok in _BASE_ROOKIE_TOKENS])
    _raw_single = (
        not _lot_reject
        and _product_family
        and (
            _base_rookie
            or _card_number
            or _parallel
            or _auto
            or _memorabilia
            or _serial
            or any(_tok in _padded for _tok in [f" {_tok} " for _tok in _RAW_SINGLE_TOKENS])
        )
    )
    _keep = False
    _reason = "grade_or_card_type"
    if _lot_reject:
        _keep = False
        _reason = "junk_or_multi"
    elif _premium_keyword or _parallel or _auto or _memorabilia or _serial:
        _keep = True
        if _auto:
            _reason = "auto"
        elif _memorabilia:
            _reason = "memorabilia"
        elif _parallel:
            _reason = "parallel"
        elif _serial:
            _reason = "serial_numbered"
        else:
            _reason = "premium_keyword"
    elif _raw_single:
        _keep = True
        _reason = "raw_single"
    elif _base_rookie:
        _keep = tier in (1, 2)
        _reason = "base_rookie" if _keep else "tier3_base_rookie"
    return {
        "keep": bool(_keep),
        "reason": _reason,
        "raw_single": bool(_raw_single and _keep),
        "memorabilia": bool(_memorabilia and _keep),
        "parallel": bool((_parallel or _serial) and _keep),
        "auto": bool(_auto and _keep),
        "product_family": bool(_product_family),
    }


def _passes_card_type_filter(title: str, tier: int = 0) -> bool:
    """
    Returns True if the card type is worth targeting.
    tier: 1/2 = Tier 1 or 2 player (base rookies OK); 3 = Tier 3 (base rookies excluded).
    """
    return bool(_title_filter_profile(title, tier).get("keep"))


# ---------------------------------------------------------------------------
# Case-hit detection
# ---------------------------------------------------------------------------

_CASE_HIT_PHRASES: List[str] = [
    "rookie patch autograph", "rpa", "superfractor", "shimmer autograph", "shimmer auto",
    "rated rookie autograph", "rated rookie auto", "gold vinyl", "black finite",
    "printing plates", "printing plate", "prizmatrix signatures", "sensational signatures",
    "dual autograph", "dual auto", "triple autograph", "triple auto",
    "lava lamp refractor", "atomic refractor", "color blast", "gold die-cut", "black die-cut",
    "cherry blossom", "tiger stripe", "flashback signatures", "prizmania", "nebula",
    "all-etch rookie rush", "radiating rookies", "topps chrome authentics",
    "manga", "downtown", "uptown", "fireworks", "groovy", "kaleidoscopic", "talismen",
]


def detect_case_hit(title: str) -> Optional[str]:
    t = title.lower()
    for phrase in _CASE_HIT_PHRASES:
        if phrase in t:
            return phrase.title()
    return None


