_PLAYER_MASTER_TIER_MAP: Dict[str, int] = {
    str(_pm.get("name") or "").strip().lower(): int(_pm.get("tier") or 3)
    for _pm in _PLAYER_MASTER
    if _pm.get("name")
}


def _player_commercial_tier(player_name: str) -> int:
    """Return 1/2/3 from _PLAYER_MASTER; default 3 if unknown."""
    _key = str(player_name or "").strip().lower()
    return int(_PLAYER_MASTER_TIER_MAP.get(_key, 3))


# ── Player-Product-Year Compatibility Scoring ──────────────────────────────
# Module-level lookups for the new tier_label / rookie_year fields. Used by
# `_player_product_year_compatibility()` to score row desirability based on
# WHEN the card was printed relative to the player's career arc.
#
# Core insight (April 30 2026 user-articulated): "Marvin Harrison Jr Downtown
# is OK to buy, Josh Allen rookie Prizm is OK to buy, Marvin Harrison Jr base
# Prizm is NOT desirable enough." The system, not the user, should know which
# (player × product × year) combinations are worth surfacing.
_PLAYER_MASTER_TIER_LABEL_MAP: Dict[str, str] = {
    str(_pm.get("name") or "").strip().lower(): str(_pm.get("tier_label") or "3")
    for _pm in _PLAYER_MASTER
    if _pm.get("name")
}
_PLAYER_MASTER_ROOKIE_YEAR_MAP: Dict[str, int] = {
    str(_pm.get("name") or "").strip().lower(): int(_pm.get("rookie_year") or 0)
    for _pm in _PLAYER_MASTER
    if _pm.get("name") and _pm.get("rookie_year")
}


def _player_tier_label(player_name: str) -> str:
    """Return granular tier ('0'/'1A'/'1B'/'2'/'3'); default '3' if unknown."""
    _key = str(player_name or "").strip().lower()
    return str(_PLAYER_MASTER_TIER_LABEL_MAP.get(_key, "3"))


def _player_rookie_year(player_name: str) -> int:
    """Return player's rookie year from master; 0 if unknown."""
    _key = str(player_name or "").strip().lower()
    return int(_PLAYER_MASTER_ROOKIE_YEAR_MAP.get(_key, 0))


def _player_product_year_compatibility(
    player_name: str,
    card_year: Optional[int],
    has_premium_structure: bool = False,
    is_case_hit: bool = False,
) -> Tuple[int, str]:
    """
    Score how desirable a (player × card_year × structure) combination is.
    Returns (score 0-100, reason_string). Higher = more desirable to surface.

    Scoring logic (April 30 2026 audit-validated):
      • Tier 0 (vintage legend) — anything from their rookie era is HOT;
        modern reprints/parallels still OK if premium-structured.
      • Tier 1A (generational face) — rookie year cards are MAX score;
        off-year base cards drop dramatically; off-year case-hit/premium
        retains strong score (because Mahomes Tecmo Super Bowl 2025 ≠
        Mahomes 2025 Prizm base).
      • Tier 1B (franchise anchor) — same shape, slightly less peak.
      • Tier 2 (elite active) — rookie year still desirable, off-year
        REQUIRES premium structure to be worth surfacing.
      • Tier 3 (speculation) — only desirable when paired with premium
        structure (numbered serial, auto, premium parallel, case hit).

    A single off-year base of any active player is almost always SKIP.
    """
    _label = _player_tier_label(player_name)
    _rookie_yr = _player_rookie_year(player_name)
    if not _rookie_yr or not card_year:
        # No year data — fallback to tier-only scoring.
        _fallback = {"0": 80, "1A": 75, "1B": 60, "2": 40, "3": 20}.get(_label, 20)
        if has_premium_structure:
            _fallback = min(100, _fallback + 20)
        if is_case_hit:
            _fallback = min(100, _fallback + 30)
        return _fallback, f"no_year_data:tier={_label}"
    _years_since_rookie = max(0, int(card_year) - int(_rookie_yr))
    _is_rookie_year = _years_since_rookie == 0
    _is_rookie_window = _years_since_rookie <= 1  # rookie + sophomore year
    # Base score by tier_label
    _base = {"0": 70, "1A": 70, "1B": 55, "2": 35, "3": 15}.get(_label, 15)
    # Rookie-year boost — biggest single multiplier.
    # Calibration tuned April 30 2026 against user's stated philosophy:
    #   "MHJr off-year Prizm = not desirable enough" → Tier 2 sophomore base
    #     drops to skip-tier (~25) instead of getting a sophomore boost.
    #   "Tier 3 speculation needs structure" → Tier 3 rookies without
    #     premium / case_hit signals get only a tiny boost (essentially skip).
    if _is_rookie_year:
        if _label == "3" and not has_premium_structure and not is_case_hit:
            # Speculation tier rookie WITHOUT structure = stay near skip floor.
            _base += 5
        else:
            _base += {"0": 30, "1A": 30, "1B": 30, "2": 35, "3": 30}.get(_label, 25)
    elif _is_rookie_window:
        # Sophomore year — only Tier 0/1A/1B get meaningful credit.
        # Tier 2/3 sophomores get nothing here (handled by hard cap below).
        _base += {"0": 20, "1A": 20, "1B": 18}.get(_label, 0)
    # Hard cap on off-year base cards (NOT rookie year, no premium, no case
    # hit). User's articulated philosophy: "off-year base of any active star
    # is essentially skip." This applies uniformly to Tier 1A/1B/2/3 — even
    # Mahomes 2025 Prizm base ($1 retail) shouldn't score above MHJr 2025
    # Prizm base. Tier 0 vintage legends are the exception (their modern
    # reprints/parallels still carry historic premium).
    if not _is_rookie_year and not has_premium_structure and not is_case_hit:
        if _label == "1A":
            _base = min(_base, 25)  # off-year 1A base = skip (philosophy)
        elif _label == "1B":
            _base = min(_base, 25)  # off-year 1B base = skip
        elif _label == "2":
            _base = min(_base, 25)  # MHJr off-year = skip
        elif _label == "3":
            _base = min(_base, 10)  # speculation off-year base = skip hard
        elif _label == "0":
            _base = min(_base, 50)  # vintage modern reprint stays interesting
    # Premium structure (auto / numbered / premium parallel / PSA grade) boost
    if has_premium_structure:
        _base += {"0": 20, "1A": 25, "1B": 22, "2": 25, "3": 25}.get(_label, 15)
    # Case hit override — even off-year of any tier scores well if case hit
    if is_case_hit:
        _base += {"0": 25, "1A": 30, "1B": 30, "2": 30, "3": 25}.get(_label, 20)
    # Cap at 100
    _score = max(0, min(100, _base))
    _reason_parts = [f"tier={_label}", f"yrs_since_rookie={_years_since_rookie}"]
    if _is_rookie_year:
        _reason_parts.append("rookie_year")
    if has_premium_structure:
        _reason_parts.append("premium_structure")
    if is_case_hit:
        _reason_parts.append("case_hit")
    return _score, ":".join(_reason_parts)


