def _endgame_subset_terms() -> list[str]:
    return [
        "auto", "autograph", "patch", "rpa", "relic",
        "gold", "black", "zebra", "shimmer", "vinyl",
        "kaboom", "downtown", "color blast", "genesis", "stained glass", "aura",
        "/25", "/10", "/5", "1/1",
    ]


def _allowed_subset_terms_for_product(product: str, is_rookie: bool) -> list[str]:
    _product = str(product or "").strip().lower()
    if "topps chrome black" in _product:
        return ["auto", "gold", "/10"] if is_rookie else ["auto", "gold"]
    if "topps chrome" in _product:
        return ["auto", "gold", "/25", "/10"]
    if "bowman chrome" in _product:
        return ["auto", "gold", "/25", "/10"]
    if "topps finest" in _product or "finest" in _product:
        return ["auto", "gold", "/25", "/10"]
    if "prizm" in _product or "select" in _product or "optic" in _product:
        return ["auto", "gold", "black", "zebra", "vinyl", "/25", "/10"]
    if "spectra" in _product:
        _terms = ["auto", "patch", "relic", "gold", "/25", "/10", "/5"]
        if is_rookie:
            _terms.insert(3, "rpa")
        return _terms
    if "national treasures" in _product or "immaculate" in _product or "flawless" in _product:
        # ── ENFORCE PART 3: add patch-specific subtypes so specificity-ranked fallback
        # can generate commercial queries like "Brock Bowers NT colossal patch /49"
        # instead of only generic "NT patch". These sit in the "patch" bucket and
        # will beat generic "patch" in _query_specificity_rank.
        _terms = [
            "colossal patch", "sunday treasures patch", "jumbo patch",
            "nameplate patch", "laundry tag",
            "auto", "patch", "relic", "gold", "/25", "/10", "/5",
        ]
        if is_rookie:
            _terms.append("rpa")
        return _terms
    if "contenders optic" in _product or "contenders" in _product:
        return ["auto", "gold", "/25", "/10"]
    if "chrome" in _product or "finest" in _product:
        return ["auto", "gold", "black", "/25", "/10"]
    return []


def _normalize_person_key(value: str) -> str:
    return re.sub(r"[^a-z0-9]+", " ", str(value or "").strip().lower()).strip()


def _clean_query_tokens(tokens: list[str]) -> list[str]:
    _cleaned: list[str] = []
    _seen: set[str] = set()
    _normalized = [str(_token).strip() for _token in list(tokens or []) if str(_token).strip()]
    _joined_lower = " ".join(_token.lower() for _token in _normalized)
    for _token in _normalized:
        _tl = _token.lower()
        _skip = False
        if _tl in _seen:
            _skip = True
        if "chrome black" in _joined_lower and _tl == "black":
            _skip = True
        if not _skip:
            _cleaned.append(_token)
            _seen.add(_tl)
    return _cleaned


def _normalized_query_text(query_text: str) -> str:
    return " ".join(str(query_text or "").split()).strip().lower()


