def _infer_rookie_truth(player_name: str, row_or_profile: dict | None = None) -> bool:
    _row = dict(row_or_profile or {})
    if _row.get("is_rookie") is True:
        _result = True
    else:
        _result = False
    _rookie_year = _row.get("rookie_year")
    _current_year = _row.get("year") or _row.get("season_year")
    if not _result:
        try:
            if _rookie_year and _current_year and abs(int(_current_year) - int(_rookie_year)) <= 1:
                _result = True
            elif _rookie_year and abs(int(datetime.now().year) - int(_rookie_year)) <= 2:
                _result = True
        except Exception:
            pass
    _name = _normalize_person_key(player_name)
    _sport = str(_row.get("sport") or _row.get("league") or "").strip().upper()
    if not _result and _name in _CURATED_ROOKIE_SENSITIVE_NAMES:
        _result = True
    if not _result and _sport in {"MLB", "BASEBALL"} and _name in _CURATED_MLB_ROOKIE_SENSITIVE_NAMES:
        _result = True
    # Note: "gunnar henderson", "elly de la cruz", "evan carter" are now in
    # both curated sets above — the year-gated Henderson branch is superseded.
    if _sport in {"MLB", "BASEBALL"}:
        if _result and _name in {"gunnar henderson", "elly de la cruz", "evan carter"}:
            print(f"[MLB_ROOKIE_TRUTH_ENFORCED] player={player_name} reason=curated_override")
        print(f"[MLB_ROOKIE_TRUTH] player={player_name} inferred={int(bool(_result))}")
    return _result


def _spec_rookie_context(spec: Dict[str, Any]) -> bool:
    _spec = dict(spec or {})
    _player_name = str(_spec.get("player_name") or "").strip()
    _is_rookie = _infer_rookie_truth(_player_name, _spec)
    if _is_rookie or bool(_spec.get("rookie")):
        return True
    _text = " ".join(
        str(_spec.get(_field) or "")
        for _field in (
            "query",
            "seed_text",
            "target_label",
            "lane_subset",
            "subset_name",
            "target_id",
            "player_name",
        )
    ).lower()
    if re.search(r"\b(rc|rookie|prospect|debut)\b", _text):
        return True
    return bool(_player_name and _player_heat_tier(_player_name) >= 4 and re.search(r"\b(20(2[3-6]))\b", _text))


def _default_product_families_for_sport(sport: str) -> list[str]:
    return list(_endgame_product_families_by_sport(sport))


def _auto_seed_product_family_allowed(product_family: str) -> bool:
    _family_key = _normalize_family_probe(product_family)
    if not _family_key:
        return False
    return not any(_blocked in _family_key for _blocked in _AUTO_SEEDED_PRODUCT_BLOCKLIST)


def _endgame_lane_score(query_text: str) -> int:
    _query = str(query_text or "").lower()
    _score = 0

    _premium_products = [
        "prizm", "select", "optic", "spectra",
        "national treasures", "immaculate", "flawless",
        "chrome", "finest", "dynasty", "definitive", "museum collection",
    ]
    for _token in _premium_products:
        if _token in _query:
            _score += 2

    _premium_terms = [
        "auto", "patch", "rpa", "relic",
        "kaboom", "downtown", "color blast",
        "/25", "/10", "/5", "1/1",
        "gold", "black", "zebra", "vinyl", "shimmer",
    ]
    for _token in _premium_terms:
        if _token in _query:
            _score += 2

    return int(_score)


def _spec_has_endgame_subset_attachment(spec: Dict[str, Any]) -> bool:
    _text_parts = [
        str((spec or {}).get("query") or ""),
        str((spec or {}).get("seed_text") or ""),
        str((spec or {}).get("lane_subset") or ""),
        str((spec or {}).get("subset_name") or ""),
        str((spec or {}).get("lane_parallel") or ""),
        str((spec or {}).get("parallel_name") or ""),
    ]
    _text = " ".join(_text_parts).lower()
    return any(_term in _text for _term in _endgame_subset_terms())


def _scan_family_hard_blocked(spec: Dict[str, Any]) -> bool:
    _product = _normalize_family_probe(_lane_product_family_value(spec))
    if not _product:
        return False
    if "donruss optic" in _product or "contenders optic" in _product:
        return False
    if "absolute" in _product and _spec_has_endgame_subset_attachment(spec):
        return False
    if any(_blocked in _product for _blocked in _ENDGAME_SCAN_DENYLIST):
        return not _spec_has_endgame_subset_attachment(spec)
    return False


def _build_endgame_seeded_product_lane(base_spec: Dict[str, Any], product_family: str, subset_term: str = "") -> Dict[str, Any]:
    _seed_product = " ".join(str(product_family or "").split()).strip()
    _subset_term = " ".join(str(subset_term or "").split()).strip()
    _spec = dict(base_spec or {})
    _player_name = _sanitize_query_player_name(" ".join(
        str(_spec.get("player_name") or (_spec.get("tracked_target") or {}).get("player_name") or "").split()
    ).strip())
    _sport = str(_spec.get("sport") or "").strip().upper()
    if not _player_name or not _seed_product:
        return {}

    _query_parts = [_player_name, _seed_product]
    if _subset_term:
        _query_parts.append(_subset_term)
    _raw_query_text = " ".join(_query_parts).strip()
    _query_text = " ".join(_clean_query_tokens(_query_parts)).strip()
    if not _query_text:
        return {}
    if _raw_query_text != _query_text:
        print(f"[QUERY_CLEAN] raw={_raw_query_text} clean={_query_text}")

    _target_meta = dict(_spec.get("target_meta") or {})
    _target_meta["set_name"] = _seed_product
    _target_meta["brand"] = str(_target_meta.get("brand") or _seed_product)
    _target_meta["product_family"] = _seed_product
    if _subset_term:
        _target_meta["subset_name"] = _subset_term

    _tracked_target = dict(_spec.get("tracked_target") or {})
    _tracked_target["player_name"] = _player_name
    _tracked_target["product_family"] = _seed_product
    _tracked_target["product_keywords"] = [_seed_product]
    _tracked_target["card_keywords"] = [_subset_term] if _subset_term else []
    _tracked_target["subset_name"] = _subset_term
    _tracked_target["parallel_name"] = ""
    _tracked_target["subset_product_family"] = ""
    _tracked_target["target_meta"] = dict(_target_meta)

    _spec["query"] = _query_text
    _spec["seed_text"] = _query_text
    _spec["player_name"] = _player_name
    _spec["sport"] = _sport
    _spec["tracked_target"] = _tracked_target
    _spec["target_meta"] = dict(_target_meta)
    _spec["target_label"] = f"{_player_name} | {_seed_product} | {_subset_term or 'product'}"
    _spec["lane_product"] = _seed_product
    _spec["target_product_family"] = _seed_product
    _spec["product_family"] = _seed_product
    _spec["product"] = _seed_product
    _spec["lane_subset"] = _subset_term
    _spec["subset_name"] = _subset_term
    _spec["lane_parallel"] = ""
    _spec["parallel_name"] = ""
    _spec["parallel_bucket"] = ""
    _spec["subset_binding_override"] = False
    _spec["subset_product_family"] = ""
    _spec["query_kind"] = "lane_subset" if _subset_term else "lane_product_only"
    _spec["target_lane_type"] = "lane_subset" if _subset_term else "lane_product_only"
    _spec["query_contract_type"] = "subset_seed" if _subset_term else "product_base"
    _spec["lane_tier"] = "primary"
    _spec["lane_augmented"] = True
    _spec["premium_lane_allowed"] = True
    _spec["spec_premium_lane"] = True
    _spec["spec_lane_class"] = "endgame_seed"
    _spec["_endgame_seeded_lane"] = True
    _spec["premium_lane_priority"] = 30.0 + float(_endgame_lane_score(_query_text))
    _spec["query_variants"] = _build_auction_query_variants_for_spec(_spec)
    for _variant in (_spec.get("query_variants") or []):
        _variant["query"] = _apply_junk_exclusions(str(_variant.get("query") or ""))
    _spec["lane_priority"] = _lane_priority_score(_spec, latest_run=None) + float(_endgame_lane_score(_query_text))
    return _spec


def _final_monitor_eligible(row: dict) -> bool:
    if not row:
        return False

    _truth = str((row or {}).get("valuation_truth_tier") or "").strip().upper()
    _true_mv = (row or {}).get("true_market_value")
    _target_bid = (row or {}).get("target_bid")
    _comp_count = (row or {}).get("usable_comp_count", (row or {}).get("comp_count", 0))
    _title = str((row or {}).get("title") or "").lower()

    try:
        _comp_count = int(_comp_count or 0)
    except Exception:
        _comp_count = 0

    try:
        _true_mv = float(_true_mv) if _true_mv is not None else None
    except Exception:
        _true_mv = None

    try:
        _target_bid = float(_target_bid) if _target_bid is not None else None
    except Exception:
        _target_bid = None

    _premium_hit = any(_term in _title for _term in [
        "national treasures", "immaculate", "flawless", "spectra",
        "patch", "auto", "rpa", "gold", "holo", "/10", "/25", "/49",
    ])

    return bool(_truth == "TRUE" and _true_mv is not None and _target_bid is not None and _comp_count >= 1 and _premium_hit)


_PATCH_SUBTYPE_QUERY_TERMS: Tuple[str, ...] = (
    "colossal patch", "sunday treasures patch", "jumbo patch",
    "nameplate patch", "laundry tag",
)


def _query_contract_bucket(spec: Dict[str, Any]) -> str:
    _query = str((spec or {}).get("query") or "").lower()
    _player_name = str((spec or {}).get("player_name") or "")
    _rookie_sensitive = _infer_rookie_truth(_player_name, spec)
    if "rpa" in _query:
        return "rpa" if _rookie_sensitive else "skip"
    # ── ENFORCE PART 3: patch-subtype queries land in the "patch" bucket ──────
    # This ensures "colossal patch" and "sunday treasures patch" compete against
    # (and beat, via _query_specificity_rank) the generic "patch" query.
    if any(_sub in _query for _sub in _PATCH_SUBTYPE_QUERY_TERMS):
        return "patch"
    if any(_term in _query for _term in ("patch auto", "patch", "relic", "materials", "jersey")):
        return "patch"
    if "auto" in _query or "autograph" in _query:
        return "auto"
    # Expand serial detection to cover all meaningful serial caps, not just /10 and /25.
    # /49, /50, /75, /99 are premium numbered parallels — give them the serial budget slot
    # instead of burning the base slot, which unlocks dedicated budget for these lanes.
    if any(_term in _query for _term in ("/10", "/25", "/49", "/50", "/75", "/99")):
        return "serial"
    return "base"


