_DISCOVERY_URGENCY_TIER_ORDER: Dict[str, int] = {
    "tier_0_1h": 0,
    "tier_1_3h": 1,
    "tier_3_6h": 2,
    "tier_6_24h": 3,
    "tier_over_24h": 4,
}


def _discovery_urgency_tier(seconds_remaining: Any) -> str:
    _seconds = _safe_float(seconds_remaining)
    if _seconds is None:
        return "tier_over_24h"
    if _seconds <= 3600.0:
        return "tier_0_1h"
    if _seconds <= 10800.0:
        return "tier_1_3h"
    if _seconds <= 21600.0:
        return "tier_3_6h"
    if _seconds <= 86400.0:
        return "tier_6_24h"
    return "tier_over_24h"


def _discovery_urgency_rank(tier: str) -> int:
    return int(_DISCOVERY_URGENCY_TIER_ORDER.get(str(tier or "").strip(), 5))


def _discovery_live_scan_gate(entry: Dict[str, Any]) -> Tuple[bool, str]:
    _entry = dict(entry or {})
    _spec = dict(_entry.get("spec") or {})
    _meta = dict(_entry.get("lane_meta") or {})
    _premium_score = float(_entry.get("premium_score") or 0.0)
    _is_premium = bool(
        _spec.get("spec_premium_lane")
        or _spec.get("premium_lane_allowed")
        or _spec.get("collector_heat_lane_allowed")
        or _premium_score >= 48.0
    )
    if not _is_premium:
        return True, "non_premium_lane"
    _window_viability_score = float(_entry.get("window_viability_score") or _meta.get("window_viability_score") or 0.0)
    if _window_viability_score > 0.0:
        return True, "positive_window_viability"
    if int(_entry.get("recent_in_window_hits") or _meta.get("recent_in_window_hits") or _meta.get("lane_in_window_hits") or _meta.get("window_in_window_count") or 0) > 0:
        return True, "recent_in_window_auction"
    if int(_meta.get("live_strict_within") or _meta.get("live_edge_rescued") or _meta.get("live_rows_returned") or _meta.get("window_rows_returned") or 0) > 0:
        return True, "live_ending_sample"
    _remaining = _safe_float(_meta.get("live_nearest_remaining") or _meta.get("window_nearest_remaining_seconds"))
    _window_seconds = _safe_float(_meta.get("live_strict_window_seconds") or _meta.get("strict_window_seconds"))
    if _remaining is not None and _window_seconds is not None and _window_seconds > 0.0 and 0.0 <= _remaining <= _window_seconds:
        return True, "remaining_within_selected_window"
    if bool(
        _spec.get("_fallback_window_used")
        or _spec.get("fallback_window")
        or _spec.get("fallback_window_lane")
        or _spec.get("fallback_window_allowed")
    ):
        return True, "fallback_window_lane"
    return False, "zero_live_window_viability"


def _discovery_recent_live_hits(meta: Optional[Dict[str, Any]]) -> int:
    _meta = dict(meta or {})
    return max(
        0,
        int(_meta.get("live_strict_within") or 0) + int(_meta.get("live_edge_rescued") or 0),
    )


def _discovery_has_current_urgency_signal(meta: Optional[Dict[str, Any]]) -> bool:
    _meta = dict(meta or {})
    _nearest = _safe_float(_meta.get("live_nearest_remaining"))
    _rows = int(_meta.get("live_rows_returned") or 0)
    return bool(
        _rows > 0
        and _nearest is not None
        and float(_nearest) <= 21600.0
    )


def _discovery_is_generic_lane(spec: Dict[str, Any], lane_meta: Optional[Dict[str, Any]] = None) -> bool:
    _spec = dict(spec or {})
    _lane_meta = dict(lane_meta or {})
    _lane_type = str(
        _spec.get("target_lane_type")
        or _spec.get("spec_lane_class")
        or _lane_meta.get("target_lane_type")
        or ""
    ).strip().lower()
    _query_kind = str(_spec.get("query_kind") or _lane_meta.get("query_kind") or "").strip().lower()
    _intake_type = str(_spec.get("_intake_type") or "").strip().lower()
    return bool(
        not _spec_is_premium_intent(_spec)
        and (
            _intake_type == "broad"
            or _lane_type in {"product_base", "broad_fallback"}
            or _query_kind in {"broad_intake", "broad_intake_template", "broad_fallback"}
        )
    )


def _discovery_premium_priority_score(
    spec: Dict[str, Any],
    lane_meta: Optional[Dict[str, Any]] = None,
) -> float:
    _spec = dict(spec or {})
    _lane_meta = dict(lane_meta or {})
    _query_quality = _query_lane_quality_profile(_spec)
    _product = " ".join(
        part
        for part in (
            str(_spec.get("lane_product") or _lane_meta.get("lane_product") or _spec.get("target_product_family") or ""),
            str(_spec.get("lane_subset") or _lane_meta.get("lane_subset") or ""),
            str(_spec.get("lane_parallel") or _lane_meta.get("lane_parallel") or ""),
        )
        if str(part or "").strip()
    ).lower()
    _query = " ".join(
        part
        for part in (
            str(_spec.get("query") or ""),
            str(_spec.get("target_label") or ""),
        )
        if str(part or "").strip()
    ).lower()
    _signal_blob = f" {_product} {_query} "
    _lane_type = str(_spec.get("target_lane_type") or _spec.get("spec_lane_class") or "").strip().lower()
    _score = 0.0
    _score += min(36.0, float(_spec.get("premium_lane_priority") or _lane_meta.get("premium_lane_priority") or 0.0) * 0.35)
    if bool(_query_quality.get("premium_keep")):
        _score += 18.0
    if bool(_spec.get("spec_premium_lane")):
        _score += 14.0
    if any(_prod in _signal_blob for _prod in ("topps chrome", "bowman chrome", "prizm", "optic", "select", "mosaic")):
        _score += 14.0
    if _lane_type == "auto" or any(_term in _signal_blob for _term in (" auto ", " autograph ", " signature ", " on card ")):
        _score += 18.0
    if any(_term in _signal_blob for _term in (" rpa ", " patch auto ", " rookie patch autograph ")):
        _score += 14.0
    elif any(_term in _signal_blob for _term in (" patch ", " relic ", " jersey ", " swatch ")):
        _score += 8.0
    if _lane_type in {"serial_parallel"} or any(_term in _signal_blob for _term in ("1/1", "/5", "/10", "/15", "/25", "superfractor", "gold vinyl")):
        _score += 16.0
    elif any(_term in _signal_blob for _term in ("/49", "/50", "/75", "/99")):
        _score += 8.0
    if _lane_type in {"premium_subset", "ssp_case_hit"} or any(_term in _signal_blob for _term in ("kaboom", "downtown", "color blast", "stained glass", "manga", "genesis", "honeycomb", "peacock", "zebra", "elephant", "tiger", "checkerboard", "case hit", "ssp")):
        _score += 16.0
    if _spec_rookie_context(_spec) or any(_term in _signal_blob for _term in (" rookie ", " rc ", " rookie card ")):
        _score += 10.0
    if any(_term in _signal_blob for _term in (" psa ", " bgs ", " sgc ", " black label ", " gem mint ", " gem mt ", " mint 10 ")):
        _score += 10.0
    if _discovery_is_generic_lane(_spec, _lane_meta):
        _score -= 22.0
    return round(max(0.0, _score), 2)


def _discovery_lane_budget_sort_key(spec: Dict[str, Any]) -> Tuple[float, ...]:
    _spec = dict(spec or {})
    _lane_meta = _lane_yield_meta_for_spec(_spec)
    _urgency_tier = _discovery_urgency_tier(_lane_meta.get("live_nearest_remaining"))
    _premium_score = _discovery_premium_priority_score(_spec, _lane_meta)
    _recent_live_hits = _discovery_recent_live_hits(_lane_meta)
    _cold_generic = bool(
        _discovery_is_generic_lane(_spec, _lane_meta)
        and _recent_live_hits <= 0
        and not _discovery_has_current_urgency_signal(_lane_meta)
    )
    return (
        1 if _cold_generic else 0,
        _discovery_urgency_rank(_urgency_tier),
        0 if (_spec_is_premium_intent(_spec) or bool(_spec.get("spec_premium_lane"))) else 1,
        -float(_premium_score),
        -float(_recent_live_hits),
        -float(_lane_yield_score(_lane_meta)),
        -float(_spec.get("premium_lane_priority") or 0.0),
        -float(_spec.get("lane_priority") or 0.0),
        str(_spec.get("query") or ""),
    )


def _discovery_row_premium_score(item: Dict[str, Any]) -> float:
    _row = dict(item or {})
    _title = str(_row.get("title") or _row.get("source_title") or "").lower()
    _product = " ".join(
        part
        for part in (
            str(_row.get("lane_product") or _row.get("target_product_family") or _row.get("product_family") or ""),
            str(_row.get("lane_subset") or _row.get("subset_name") or ""),
            str(_row.get("lane_parallel") or ""),
        )
        if str(part or "").strip()
    ).lower()
    _signal_blob = f" {_title} {_product} "
    _lane_type = str(_row.get("target_lane_type") or _row.get("spec_lane_class") or "").strip().lower()
    _score = 0.0
    if bool(_row.get("spec_premium_lane")):
        _score += 16.0
    if any(_prod in _signal_blob for _prod in ("topps chrome", "bowman chrome", "prizm", "optic", "select", "mosaic")):
        _score += 14.0
    if _lane_type == "auto" or any(_term in _signal_blob for _term in (" auto ", " autograph ", " signature ", " on card ")):
        _score += 18.0
    if any(_term in _signal_blob for _term in (" rpa ", " patch auto ", " rookie patch autograph ")):
        _score += 14.0
    elif any(_term in _signal_blob for _term in (" patch ", " relic ", " jersey ", " swatch ")):
        _score += 8.0
    if any(_term in _signal_blob for _term in ("1/1", "/5", "/10", "/15", "/25", "superfractor", "gold vinyl")):
        _score += 16.0
    elif any(_term in _signal_blob for _term in ("/49", "/50", "/75", "/99")):
        _score += 8.0
    if _lane_type in {"premium_subset", "ssp_case_hit"} or any(_term in _signal_blob for _term in ("kaboom", "downtown", "color blast", "stained glass", "manga", "genesis", "honeycomb", "peacock", "zebra", "elephant", "tiger", "checkerboard", "case hit", "ssp")):
        _score += 16.0
    if any(_term in _signal_blob for _term in (" rookie ", " rc ", " rookie card ")):
        _score += 10.0
    if any(_term in _signal_blob for _term in (" psa ", " bgs ", " sgc ", " black label ", " gem mint ", " gem mt ", " mint 10 ")):
        _score += 10.0
    if str(_row.get("_intake_type") or "").strip().lower() == "broad" and not bool(_row.get("spec_premium_lane")):
        _score -= 20.0
    return round(max(0.0, _score), 2)


def _lane_yield_meta_for_spec(spec: Optional[Dict[str, Any]]) -> Dict[str, Any]:
    _base = _lane_yield_meta_defaults(spec)
    _lane_key = str(_base.get("lane_key") or "")
    if not _lane_key:
        return _base
    with _LANE_YIELD_LOCK:
        _existing = dict(_LANE_YIELD_STATE.get(_lane_key) or {})
    _merged = dict(_base)
    _merged.update(_existing)
    _merged["lane_key"] = _lane_key
    if not str(_merged.get("lane_label") or "").strip():
        _merged["lane_label"] = _lane_metric_label(spec)
    return _merged


def _lane_live_dead_threshold_seconds(strict_window_seconds: Any) -> float:
    try:
        _strict_window = float(strict_window_seconds or 0.0)
    except (TypeError, ValueError):
        _strict_window = 0.0
    if _strict_window <= 0.0:
        return 0.0
    return float(_strict_window) * 2.0


def _premium_live_yield_override_contract(row, *, strict_window_seconds):
    """
    Allow premium PSA/auto/serial/case-hit rows slightly outside the strict live window
    to count as live-yield candidates, so premium lanes do not die too early.
    """
    try:
        if not isinstance(row, dict):
            return False, "not_dict"

        _remaining = _safe_float(
            row.get("remaining_seconds")
            if row.get("remaining_seconds") is not None
            else row.get("seconds_remaining")
            or row.get("source_time_remaining_seconds")
        )
        if _remaining is None:
            _remaining = _safe_float(_row_remaining_seconds(row))
        _title = str(row.get("title") or row.get("source_title") or "").strip()
        _title_l = _title.lower()
        _grade = str(row.get("grade") or row.get("grade_label") or "").strip().upper()
        if not _grade:
            if "psa 10" in _title_l:
                _grade = "PSA 10"
            elif "psa " in _title_l:
                _grade = "PSA"
        _insert = str(row.get("insert_family") or row.get("_hydrated_insert_family") or "").strip().lower()
        _parallel = str(row.get("parallel_family") or row.get("_hydrated_parallel_family") or "").strip().lower()
        _serial = str(row.get("serial_denominator") or row.get("_hydrated_serial_denominator") or row.get("serial") or "").strip()
        _classifier = premium_lane_classifier_signals(row)
        _premium_lane = bool(
            row.get("premium_lane")
            or row.get("spec_premium_lane")
            or row.get("premium_lane_allowed")
            or _classifier.get("premium_lane")
        )
        _identity_is_clean = bool(row.get("identity_is_clean") or row.get("_hydrated_identity_is_clean") or row.get("identity_clean") or _title)

        if not isinstance(_remaining, (int, float)):
            return False, "no_remaining"

        _psa10 = "PSA 10" in _grade
        _psa = "PSA" in _grade
        _title_case_hit = any(
            _term in _title_l
            for _term in ("downtown", "home field advantage", "kaboom", "stained glass", "stained_glass", "genesis", "manga", "color blast", "color_blast", "blank slate", "honeycomb", "micro mosaic", "ultra violet", "uv all stars")
        )
        _case_hit_allow, _case_hit_reason = _premium_case_hit_contract(row)
        _title_auto = bool(" auto" in f" {_title_l}" or "autograph" in _title_l)
        _title_parallel = any(
            _term in _title_l
            for _term in ("refractor", "prizm", "wave", "mojo", "gold", "black", "silver", "sapphire", "negative", "shock")
        )
        _elite_shape = bool(
            _serial
            or _insert in {"auto", "autograph", "patch_auto", "auto_patch", "downtown", "kaboom", "stained_glass", "genesis", "manga", "color_blast"}
            or _parallel not in {"", "base", "none"}
            or _title_case_hit
            or _case_hit_allow
            or _title_auto
            or _title_parallel
        )

        _strict_window = _safe_float(strict_window_seconds) or 0.0
        _extended_live_cap = float(_strict_window) + 6 * 3600.0

        if (
            _identity_is_clean
            and _premium_lane
            and _elite_shape
            and (_psa10 or _psa or _case_hit_allow)
            and float(_remaining) <= _extended_live_cap
        ):
            if _case_hit_allow:
                _stamp_premium_case_hit_survivor(row, _case_hit_reason)
                return True, f"premium_case_hit_live_yield:{_case_hit_reason}"
            return True, "premium_live_yield_override"

        return False, "not_premium_live_yield_override"
    except Exception:
        return False, "exception"


def compute_window_viability(
    rows_returned: Any,
    in_window_count: Any,
    nearest_remaining_seconds: Any,
    response_scope_valid: Any,
) -> float:
    _rows_returned = max(0, int(rows_returned or 0))
    _in_window_count = max(0, int(in_window_count or 0))
    _nearest_remaining = _safe_float(nearest_remaining_seconds)
    _response_scope_valid = bool(response_scope_valid)
    _score = 0.0
    if _rows_returned <= 0:
        return 0.0
    if _in_window_count > 0:
        _score += 1.0
    if _response_scope_valid:
        _score += 1.0
    if _nearest_remaining is not None:
        if float(_nearest_remaining) <= 43200.0:
            _score += 1.0
        elif float(_nearest_remaining) <= 86400.0:
            _score += 0.4
        else:
            _score -= 1.0
    return round(_score, 3)


def _rolling_lane_history(values: Any, new_value: Any, *, limit: int = 6) -> List[int]:
    _limit = max(1, int(limit or 6))
    _history: List[int] = []
    for _value in list(values or []):
        try:
            _history.append(int(_value or 0))
        except (TypeError, ValueError):
            continue
    try:
        _history.append(int(new_value or 0))
    except (TypeError, ValueError):
        _history.append(0)
    if len(_history) > _limit:
        _history = _history[-_limit:]
    return _history


def _lane_window_memory_summary(meta: Optional[Dict[str, Any]]) -> Dict[str, Any]:
    _meta = dict(meta or {})
    _recent_in_window_hits = int(_meta.get("recent_in_window_hits") or 0)
    _recent_scope_invalid = int(_meta.get("recent_scope_invalid_count") or 0)
    _recent_dead = int(_meta.get("recent_dead_lane_count") or 0)
    _action = "keep"
    _penalty = 0.0
    if _recent_dead >= 2:
        _action = "downrank"
        _penalty += min(42.0, float(_recent_dead) * 10.0)
    if _recent_scope_invalid >= 2 and _recent_in_window_hits <= 0:
        _action = "downrank"
        _penalty += min(24.0, float(_recent_scope_invalid) * 5.0)
    return {
        "recent_in_window_hits": _recent_in_window_hits,
        "recent_scope_invalid": _recent_scope_invalid,
        "recent_dead": _recent_dead,
        "action": _action,
        "penalty": round(_penalty, 2),
    }


def _lane_live_priority_score(spec: Dict[str, Any], lane_meta: Optional[Dict[str, Any]] = None) -> float:
    _lane_meta = dict(lane_meta or _lane_yield_meta_for_spec(spec))
    _premium_score = float(_discovery_premium_priority_score(spec, _lane_meta) or 0.0)
    _window_viability_score = float(_lane_meta.get("window_viability_score") or 0.0)
    _memory_penalty = float((_lane_window_memory_summary(_lane_meta) or {}).get("penalty") or 0.0)
    _score = (_premium_score * 0.65) + (_window_viability_score * 0.35) - _memory_penalty
    return round(_score, 3)


def _lane_has_positive_window_viability(meta: Optional[Dict[str, Any]]) -> bool:
    _meta = dict(meta or {})
    return bool(
        float(_meta.get("window_viability_score") or 0.0) > 0.0
        or int(_meta.get("recent_in_window_hits") or 0) > 0
        or int(_meta.get("live_strict_within") or 0) > 0
        or int(_meta.get("live_edge_rescued") or 0) > 0
        or _discovery_has_current_urgency_signal(_meta)
    )


def _lane_live_yield_snapshot(
    *,
    rows_returned: int,
    strict_within: int,
    edge_rescued: int,
    nearest_remaining: Any,
    strict_window_seconds: Any,
) -> Dict[str, Any]:
    _rows = max(0, int(rows_returned or 0))
    _strict = max(0, int(strict_within or 0))
    _rescued = max(0, int(edge_rescued or 0))
    _nearest = _safe_float(nearest_remaining)
    _strict_window = max(0.0, float(_safe_float(strict_window_seconds) or 0.0))
    _rescue_band = float(_strict_window) + float(_WINDOW_EDGE_RESCUE_GRACE_SECONDS) if _strict_window > 0.0 else 0.0
    _dead_threshold = _lane_live_dead_threshold_seconds(_strict_window)
    _urgency_tier = _discovery_urgency_tier(_nearest)
    _dead = bool(
        _strict <= 0
        and _rescued <= 0
        and _nearest is not None
        and _dead_threshold > 0.0
        and float(_nearest) > float(_dead_threshold)
    )
    _score = 0.0
    _score += min(18.0, float(_rows) * 1.5)
    _score += min(84.0, float(_strict) * 32.0)
    _score += min(54.0, float(_rescued) * 24.0)
    if _nearest is not None and _rows > 0:
        _score += {
            "tier_0_1h": 22.0,
            "tier_1_3h": 16.0,
            "tier_3_6h": 10.0,
            "tier_6_24h": 4.0,
            "tier_over_24h": -14.0,
        }.get(_urgency_tier, 0.0)
    if _nearest is not None and _strict_window > 0.0:
        if float(_nearest) <= _strict_window:
            _score += 18.0
        elif float(_nearest) <= _rescue_band:
            _score += 10.0
        else:
            _hours_past_rescue = max(0.0, (float(_nearest) - _rescue_band) / 3600.0)
            _score -= min(36.0, _hours_past_rescue * 8.0)
    if _dead:
        _score -= 40.0
    return {
        "rows_returned": _rows,
        "strict_within": _strict,
        "edge_rescued": _rescued,
        "nearest_remaining": _nearest,
        "strict_window_seconds": _strict_window,
        "dead_window_threshold_seconds": _dead_threshold,
        "dead_for_live_window": bool(_dead),
        "live_yield_score": round(_score, 2),
    }


def _lane_live_budget_penalty(meta: Optional[Dict[str, Any]]) -> float:
    _meta = dict(meta or {})
    _cooldown_cycles = max(0, int(_meta.get("live_cooldown_cycles") or 0))
    _dead = bool(_meta.get("dead_for_live_window"))
    _nearest = _safe_float(_meta.get("live_nearest_remaining"))
    _dead_threshold = _safe_float(_meta.get("live_dead_window_threshold_seconds"))
    _penalty = 0.0
    if _cooldown_cycles > 0:
        _penalty += 32.0 + float(_cooldown_cycles * 18.0)
    if _dead:
        _penalty += 48.0
    if _nearest is not None and _dead_threshold is not None and _dead_threshold > 0.0 and float(_nearest) > float(_dead_threshold):
        _penalty += min(28.0, max(0.0, (float(_nearest) - float(_dead_threshold)) / 3600.0) * 6.0)
    return round(_penalty, 2)


def _live_fetch_spec_key(spec: Optional[Dict[str, Any]]) -> str:
    _spec = dict(spec or {})
    _lane_key = str(_lane_metric_key(_spec) or "").strip()
    if _lane_key:
        return f"lane:{_lane_key}"
    _query = _normalized_query_text(str(_spec.get("query") or ""))
    if _query:
        return f"query:{_query}"
    return f"id:{id(spec)}"


def _live_fetch_restore_priority(spec: Optional[Dict[str, Any]]) -> Tuple[float, ...]:
    _spec = dict(spec or {})
    _meta = _lane_yield_meta_for_spec(_spec)
    _live_priority = _lane_live_priority_score(_spec, _meta)
    _strict_within = max(0, int(_meta.get("live_strict_within") or 0))
    _edge_rescued = max(0, int(_meta.get("live_edge_rescued") or 0))
    _nearest_remaining = _safe_float(_meta.get("live_nearest_remaining"))
    _rows_returned = max(0, int(_meta.get("live_rows_returned") or 0))
    _dead_penalized = bool(_meta.get("dead_for_live_window")) or int(_meta.get("live_cooldown_cycles") or 0) > 0
    _lane_priority = float(_spec.get("premium_lane_priority") or _spec.get("lane_priority") or 0.0)
    return (
        -float(_live_priority),
        -float(_strict_within),
        -float(_edge_rescued),
        float(_nearest_remaining) if _nearest_remaining is not None else 999999999.0,
        -float(1 if _rows_returned > 0 else 0),
        -float(_rows_returned),
        float(1 if _dead_penalized else 0),
        -float(_lane_priority),
        str(_meta.get("lane_label") or _meta.get("lane_key") or ""),
    )


def _ensure_live_fetch_floor(
    selected_specs: List[Dict[str, Any]],
    available_specs: List[Dict[str, Any]],
    requested_floor: Optional[int] = None,
) -> Tuple[List[Dict[str, Any]], Dict[str, Any]]:
    _requested_floor = max(0, int(_MIN_LIVE_FETCH_LANES if requested_floor is None else requested_floor or 0))
    _selected = list(selected_specs or [])
    _available_by_key: Dict[str, Dict[str, Any]] = {}
    _dead_penalized = 0
    for _spec in list(available_specs or []):
        _key = _live_fetch_spec_key(_spec)
        if not _key or _key in _available_by_key:
            continue
        _available_by_key[_key] = _spec
        _meta = _lane_yield_meta_for_spec(_spec)
        if bool(_meta.get("dead_for_live_window")) or int(_meta.get("live_cooldown_cycles") or 0) > 0:
            _dead_penalized += 1
    _selected_keys = {_live_fetch_spec_key(_spec) for _spec in list(_selected or []) if _live_fetch_spec_key(_spec)}
    _actual_pre_floor = len(_selected)
    _restore_target = min(_requested_floor, len(_available_by_key))
    _restored_count = 0
    if len(_selected) < _restore_target:
        _restore_pool = sorted(
            [
                _spec
                for _key, _spec in _available_by_key.items()
                if _key not in _selected_keys
            ],
            key=_live_fetch_restore_priority,
        )
        for _spec in _restore_pool:
            if len(_selected) >= _restore_target:
                break
            _key = _live_fetch_spec_key(_spec)
            if not _key or _key in _selected_keys:
                continue
            _selected.append(_spec)
            _selected_keys.add(_key)
            _restored_count += 1
            _meta = _lane_yield_meta_for_spec(_spec)
            _nearest_remaining = _safe_float(_meta.get("live_nearest_remaining"))
            print(
                f"[LIVE_FETCH_RESTORE] lane={str(_meta.get('lane_label') or _meta.get('lane_key') or _key)[:96]} "
                f"reason=floor_restore strict_within={int(_meta.get('live_strict_within') or 0)} "
                f"edge_rescued={int(_meta.get('live_edge_rescued') or 0)} "
                f"nearest_remaining={_nearest_remaining if _nearest_remaining is not None else 'None'} "
                f"rows_returned={int(_meta.get('live_rows_returned') or 0)}"
            )
    _actual_post_floor = len(_selected)
    print(
        f"[LIVE_FETCH_FLOOR] requested_floor={_requested_floor} "
        f"actual_pre_floor={_actual_pre_floor} actual_post_floor={_actual_post_floor}"
    )
    print(
        f"[LIVE_BUDGET_ANTISTARVATION] pre_budget={_actual_pre_floor} "
        f"post_budget={_actual_post_floor} dead_penalized={_dead_penalized} restored={_restored_count}"
    )
    return _selected, {
        "requested_floor": _requested_floor,
        "actual_pre_floor": _actual_pre_floor,
        "actual_post_floor": _actual_post_floor,
        "dead_penalized": _dead_penalized,
        "restored": _restored_count,
    }


def _runtime_replacement_sort_key(spec: Dict[str, Any]) -> Tuple[float, ...]:
    _meta = _lane_yield_meta_for_spec(spec)
    _live_priority = _lane_live_priority_score(spec, _meta)
    _premium_score = float(_discovery_premium_priority_score(spec, _meta) or 0.0)
    _window_viability_score = float(_meta.get("window_viability_score") or 0.0)
    _nearest_remaining = _safe_float(_meta.get("live_nearest_remaining"))
    return (
        -float(_live_priority),
        -float(_premium_score),
        -float(_window_viability_score),
        float(_nearest_remaining) if _nearest_remaining is not None else 999999999.0,
        str(_meta.get("lane_label") or _meta.get("lane_key") or ""),
    )


def _build_runtime_replacement_pool(
    selected_specs: List[Dict[str, Any]],
    candidate_specs: List[Dict[str, Any]],
    *,
    ignore_cold_penalties: bool = False,
) -> List[Dict[str, Any]]:
    _selected_keys = {
        str(_lane_metric_key(_spec) or _live_fetch_spec_key(_spec))
        for _spec in list(selected_specs or [])
        if str(_lane_metric_key(_spec) or _live_fetch_spec_key(_spec))
    }
    _seen_keys: set[str] = set()
    _pool: List[Dict[str, Any]] = []
    for _spec in list(candidate_specs or []):
        _lane_key = str(_lane_metric_key(_spec) or _live_fetch_spec_key(_spec))
        if not _lane_key or _lane_key in _selected_keys or _lane_key in _seen_keys:
            continue
        _seen_keys.add(_lane_key)
        _meta = _lane_yield_meta_for_spec(_spec)
        if not ignore_cold_penalties and (bool(_meta.get("dead_for_live_window")) or int(_meta.get("live_cooldown_cycles") or 0) > 0):
            continue
        if not ignore_cold_penalties and not _lane_has_positive_window_viability(_meta):
            continue
        _pool.append(_spec)
    return sorted(_pool, key=_runtime_replacement_sort_key)


def _pop_runtime_replacement_spec(
    replacement_pool: List[Dict[str, Any]],
    *,
    active_lane_keys: set[str],
    dead_lane_keys: set[str],
) -> Optional[Dict[str, Any]]:
    while replacement_pool:
        _replacement = replacement_pool.pop(0)
        _lane_key = str(_lane_metric_key(_replacement) or _live_fetch_spec_key(_replacement))
        if not _lane_key or _lane_key in active_lane_keys or _lane_key in dead_lane_keys:
            continue
        return _replacement
    return None


def _spec_has_dead_window_diags(diags: List[Dict[str, Any]]) -> bool:
    return any(bool((_diag or {}).get("dead_live_lane")) for _diag in list(diags or []))


def _summarize_live_lane_outcome(spec: Dict[str, Any], diags: List[Dict[str, Any]]) -> Dict[str, Any]:
    _auction_diags = [
        dict(_diag or {})
        for _diag in list(diags or [])
        if str((_diag or {}).get("scan_type") or "").strip().upper() == "AUCTION"
    ]
    _lane_key = str(_lane_metric_key(spec) or _live_fetch_spec_key(spec) or "")
    _rows_returned = 0
    _parsed_rows = 0
    _in_window = 0
    _window_rows_forwarded = 0
    _nearest_remaining = None
    _scope_valid = False
    for _diag in _auction_diags:
        _rows_returned = max(_rows_returned, int(_diag.get("rows_returned") or _diag.get("raw_rows_count") or 0))
        _parsed_rows = max(_parsed_rows, int(_diag.get("parsed_rows_count") or 0))
        _in_window = max(_in_window, int(_diag.get("in_window_count") or _diag.get("within_window_count") or 0))
        _window_rows_forwarded = max(_window_rows_forwarded, int(_diag.get("window_rows_forwarded") or 0))
        _scope_valid = bool(_scope_valid or _diag.get("response_scope_valid"))
        _nearest = _safe_float(_diag.get("nearest_remaining") or _diag.get("nearest_remaining_seconds"))
        if _nearest is not None:
            _nearest_remaining = _nearest if _nearest_remaining is None else min(float(_nearest_remaining), float(_nearest))
    if _in_window > 0 or _window_rows_forwarded > 0:
        _outcome = "window_success"
    elif _rows_returned <= 0:
        _outcome = "fetched_zero"
    elif _parsed_rows <= 0:
        _outcome = "parse_zero"
    elif not _scope_valid:
        _outcome = "fetched_but_scope_invalid"
    else:
        _outcome = "fetched_but_out_of_window"
    return {
        "lane": _lane_key,
        "rows_returned": int(_rows_returned),
        "parsed_rows": int(_parsed_rows),
        "in_window": int(_in_window),
        "window_rows_forwarded": int(_window_rows_forwarded),
        "nearest_remaining": _nearest_remaining,
        "outcome": _outcome,
    }


def _ensure_probe_lane_budget(
    selected_specs: List[Dict[str, Any]],
    candidate_specs: List[Dict[str, Any]],
    *,
    min_probe_lanes: Optional[int] = None,
    ignore_cold_penalties: bool = False,
) -> List[Dict[str, Any]]:
    global _DISCOVERY_PROBE_CONFIG_LOGGED
    _selected = list(selected_specs or [])
    _probe_symbol_present = "MIN_PROBE_LANES" in globals()
    _probe_floor = int(globals().get("MIN_PROBE_LANES", 8) or 8)
    _requested_probe_lanes = _probe_floor if min_probe_lanes is None else int(min_probe_lanes or _probe_floor)
    if not _DISCOVERY_PROBE_CONFIG_LOGGED:
        print(
            f"[DISCOVERY_PROBE_CONFIG] min_probe_lanes={_probe_floor} "
            f"source={'module_constant' if _probe_symbol_present else 'fallback_default'}"
        )
        _DISCOVERY_PROBE_CONFIG_LOGGED = True
    _selected_keys = {
        str(_lane_metric_key(_spec) or _live_fetch_spec_key(_spec))
        for _spec in list(_selected or [])
        if str(_lane_metric_key(_spec) or _live_fetch_spec_key(_spec))
    }
    _probe_pool = _build_runtime_replacement_pool(
        _selected,
        candidate_specs,
        ignore_cold_penalties=ignore_cold_penalties,
    )
    for _spec in _probe_pool:
        if len(_selected) >= max(0, _requested_probe_lanes):
            break
        _lane_key = str(_lane_metric_key(_spec) or _live_fetch_spec_key(_spec))
        if not _lane_key or _lane_key in _selected_keys:
            continue
        _selected.append(_spec)
        _selected_keys.add(_lane_key)
        print(
            f"[DISCOVERY_PROBE] lane={_lane_key[:96]} "
            f"reason=forced_probe"
        )
    return _selected


def _lane_yield_score(meta: Dict[str, Any]) -> float:
    _queries = max(1, int(meta.get("lane_queries") or 0))
    _raw_hits = float(meta.get("lane_raw_hits") or 0.0)
    _in_window_hits = float(meta.get("lane_in_window_hits") or 0.0)
    _candidate_hits = float(meta.get("lane_candidate_hits") or 0.0)
    _visible_hits = float(meta.get("lane_visible_hits") or 0.0)
    _sniper_hits = float(meta.get("lane_sniper_hits") or 0.0)
    _zero_rows = float(meta.get("lane_zero_rows") or 0.0)
    _dead_window_queries = float(meta.get("lane_dead_window_queries") or 0.0)
    _zero_streak = float(meta.get("lane_zero_streak") or 0.0)
    _dead_window_streak = float(meta.get("lane_dead_window_streak") or 0.0)
    _live_yield_score = float(meta.get("live_yield_score") or 0.0)
    _live_penalty = float(_lane_live_budget_penalty(meta) or 0.0)
    _score = 0.0
    _score += min(18.0, _raw_hits * 0.25)
    _score += min(28.0, _in_window_hits * 1.5)
    _score += min(70.0, _candidate_hits * 7.0)
    _score += min(80.0, _visible_hits * 14.0)
    _score += min(90.0, _sniper_hits * 24.0)
    _score += min(24.0, (_candidate_hits / _queries) * 18.0)
    _score += min(28.0, (_visible_hits / _queries) * 26.0)
    _score += min(34.0, (_sniper_hits / _queries) * 34.0)
    _score -= min(42.0, _zero_rows * 5.0)
    _score -= min(38.0, _dead_window_queries * 4.0)
    _score -= min(26.0, _zero_streak * 4.0)
    _score -= min(20.0, _dead_window_streak * 4.0)
    _score += _live_yield_score
    _score -= min(160.0, _live_penalty)
    return round(_score, 2)


def _winner_lane_score(meta: dict) -> float:
    _meta = dict(meta or {})
    _score = 0.0
    _score += float(_meta.get("usable_comp_rows") or 0) * 6.0
    _score += float(_meta.get("displayable_rows") or 0) * 5.0
    _score += float(_meta.get("watchlist_rows") or 0) * 7.0
    _score += float(_meta.get("sniper_rows") or 0) * 12.0
    _score += float(_meta.get("actionable_rows") or 0) * 8.0
    if str(_meta.get("product_family") or _meta.get("lane_product") or "").strip() in {
        "National Treasures", "Immaculate", "Flawless", "Spectra", "Prizm", "Select", "Optic", "Topps Chrome", "Bowman Chrome",
    }:
        _score += 5.0
    if int(_meta.get("zero_scan_streak") or _meta.get("lane_zero_streak") or 0) >= 3:
        _score -= 12.0
    return round(_score, 2)


def _lane_player_key(meta: Optional[Dict[str, Any]]) -> str:
    _src = dict(meta or {})
    return _normalize_person_key(str(_src.get("player_name") or _src.get("player_id") or ""))


# PATCH 3 — Supply-Aware Lane Scoring
def _lane_meta_product_tier(meta: Dict[str, Any]) -> str:
    """Classify a lane meta dict into ENDGAME / PREMIUM / MID / LOW."""
    _lane_product = str(meta.get("lane_product") or "").lower()
    _lane_type = str(meta.get("target_lane_type") or "").lower()
    _lane_subset = str(meta.get("lane_subset") or "").lower()
    if _lane_subset in _PRODUCT_TIER_ENDGAME_KEYWORDS:
        return "ENDGAME"
    if _lane_type in {"premium_subset", "ssp_case_hit"}:
        return "ENDGAME"
    if _lane_type == "auto":
        for _pk in _PRODUCT_TIER_PREMIUM_PRODUCTS:
            if _pk in _lane_product:
                return "PREMIUM"
        return "PREMIUM"
    for _pk in _PRODUCT_TIER_PREMIUM_PRODUCTS:
        if _pk in _lane_product:
            if _lane_type in {"premium_parallel", "serial_parallel"}:
                return "PREMIUM"
            return "MID"
    for _mk in _PRODUCT_TIER_MID_PRODUCTS:
        if _mk in _lane_product:
            return "MID"
    if _lane_type in {"product_base", "broad_fallback"}:
        return "LOW"
    return "LOW"


def _lane_supply_score(meta: Dict[str, Any]) -> float:
    """
    Supply-aware lane score: activity hit counts + product tier modifier
    + PATCH 7 chase class prior for cold-start ranking.
    """
    _candidate_hits = float(meta.get("lane_candidate_hits") or 0.0)
    _visible_hits = float(meta.get("lane_visible_hits") or 0.0)
    _sniper_hits = float(meta.get("lane_sniper_hits") or 0.0)
    _zero_rows = float(meta.get("lane_zero_rows") or 0.0)

    _score = 0.0
    _score += _candidate_hits * 5
    _score += _visible_hits * 10
    _score += _sniper_hits * 20
    _score -= _zero_rows * 5

    # Product tier modifier
    _pt = _lane_meta_product_tier(meta)
    if _pt == "ENDGAME":
        _score += 15
    elif _pt == "LOW":
        _score -= 20

    # PATCH 7: cold-start chase class prior — biases initial ranking before yield history
    _prior = _lane_chase_prior(meta)
    _score += _prior

    # PATCH 8: [LANE_PRIOR] log — emitted only when prior is non-zero to avoid noise
    if _prior != 0.0:
        _lane_id = str(meta.get("lane_id") or meta.get("target_id") or meta.get("lane_product") or "?")[:30]
        _lane_type = str(meta.get("target_lane_type") or "")[:20]
        print(f"[LANE_PRIOR] lane={_lane_id} type={_lane_type} prior={_prior:+.1f} supply_score={round(_score, 2)}")

    return round(_score, 2)


def _lane_allocator_bucket(spec: Dict[str, Any], lane_meta: Dict[str, Any]) -> str:
    _queries = int(lane_meta.get("lane_queries") or 0)
    _raw_hits = int(lane_meta.get("lane_raw_hits") or 0)
    _in_window_hits = int(lane_meta.get("lane_in_window_hits") or 0)
    _candidate_hits = int(lane_meta.get("lane_candidate_hits") or 0)
    _visible_hits = int(lane_meta.get("lane_visible_hits") or 0)
    _sniper_hits = int(lane_meta.get("lane_sniper_hits") or 0)
    _live_strict_within = int(lane_meta.get("live_strict_within") or 0)
    _live_edge_rescued = int(lane_meta.get("live_edge_rescued") or 0)
    _live_nearest_remaining = _safe_float(lane_meta.get("live_nearest_remaining"))
    _live_strict_window_seconds = _safe_float(lane_meta.get("live_strict_window_seconds")) or 0.0
    _live_cooldown_cycles = int(lane_meta.get("live_cooldown_cycles") or 0)
    _dead_for_live_window = bool(lane_meta.get("dead_for_live_window"))
    _yield_score = _lane_yield_score(lane_meta)
    _winner_score = _winner_lane_score(lane_meta)
    _premium_priority = float(spec.get("premium_lane_priority") or spec.get("lane_priority") or 0.0)
    _lane_tier = str(spec.get("lane_tier") or "").strip().lower()
    _sport = str(spec.get("sport") or "").strip().upper()
    _heat_state = get_recent_board_heat_state()
    _heat_mode = str(_heat_state.get("mode") or "normal")
    _is_target_broad = _sport in _TARGET_SPORT_BROAD_INTAKE_PRODUCTS and str(spec.get("_intake_type") or "").strip().lower() == "broad"
    _live_rescue_band = (
        float(_live_strict_window_seconds) + float(_WINDOW_EDGE_RESCUE_GRACE_SECONDS)
        if _live_strict_window_seconds > 0.0
        else 0.0
    )
    _live_near_rescue_band = bool(
        _live_nearest_remaining is not None
        and _live_rescue_band > 0.0
        and float(_live_nearest_remaining) <= float(_live_rescue_band)
    )
    if _is_target_broad and (_heat_mode == "broad_bias" or bool(spec.get("_broad_force_keep"))):
        return "promising"
    if _dead_for_live_window and _live_cooldown_cycles > 0 and _live_strict_within <= 0 and _live_edge_rescued <= 0:
        return "explore"
    if _live_strict_within > 0 or _live_edge_rescued > 0 or _live_near_rescue_band:
        return "promising"
    _has_history = bool(_queries > 0 or _raw_hits > 0 or _in_window_hits > 0 or _candidate_hits > 0 or _visible_hits > 0 or _sniper_hits > 0)
    if _yield_score <= 0.0 and _winner_score <= 0.0 and not _has_history:
        _lane_for_live_floor = {**dict(lane_meta or {}), **dict(spec or {})}
        _lane_name = str((lane_meta or {}).get("lane_label") or (lane_meta or {}).get("lane_key") or _lane_metric_label(spec) or "")[:64]
        _live_floor_matched = bool(_has_collector_heat_live_floor(_lane_for_live_floor))
        print(
            f"[LIVE_FLOOR_MATCH_DEBUG] lane={_lane_name} "
            f"collector_heat_lane_allowed={_lane_for_live_floor.get('collector_heat_lane_allowed')} "
            f"variant={_lane_for_live_floor.get('variant') or _lane_for_live_floor.get('query_variant') or _lane_for_live_floor.get('lane_variant')} "
            f"product_family={_lane_for_live_floor.get('product_family')} "
            f"player={_lane_for_live_floor.get('player')} "
            f"is_elite={_lane_for_live_floor.get('is_elite_player')} "
            f"is_curated={_lane_for_live_floor.get('is_curated_player')} "
            f"matched={_live_floor_matched}"
        )
        if _live_floor_matched:
            spec["yield_bucket"] = "live_floor"
            spec["yield_reason"] = "collector_heat_live_floor"
            spec["live_budget_floor"] = True
            print(
                f"[COLLECTOR_HEAT_LIVE_FLOOR] lane={_lane_name} "
                f"player={str(_lane_for_live_floor.get('player') or _lane_for_live_floor.get('player_name') or _lane_for_live_floor.get('target_player_name') or '')[:48]} "
                f"product={str(_lane_for_live_floor.get('product_family') or _lane_for_live_floor.get('lane_product') or _lane_for_live_floor.get('target_product_family') or '')[:48]} "
                f"reason=collector_heat_live_floor"
            )
            return "promising"
        print(
            f"[LANE_YIELD_RECLASS] lane={str((lane_meta or {}).get('lane_label') or (lane_meta or {}).get('lane_key') or '')[:64]} "
            f"yield={_yield_score} winner={_winner_score} bucket=explore reason=no_history_zero_signal"
        )
        return "explore"
    if _sniper_hits > 0 or _visible_hits >= 2 or _candidate_hits >= 3 or _yield_score >= 38.0:
        return "proven"
    if (
        (_candidate_hits > 0 and _yield_score > 0.0)
        or _visible_hits > 0
        or _in_window_hits >= 2
        or (_queries == 0 and (_premium_priority >= 88.0 or _lane_tier == "primary") and (_yield_score > 0.0 or _winner_score > 0.0))
        or (_raw_hits > 0 and _queries <= 2)
    ):
        return "promising"
    return "explore"


def _has_collector_heat_live_floor(lane: Dict[str, Any]) -> bool:
    _lane = dict(lane or {})
    _target_meta = _lane.get("target_meta") if isinstance(_lane.get("target_meta"), dict) else {}
    _variant = str(
        _lane.get("variant")
        or _lane.get("query_variant")
        or _lane.get("lane_variant")
        or _lane.get("surface_variant")
        or ""
    ).strip().lower()
    _query = str(_lane.get("query") or "").strip().lower()
    _lane_name = str(
        _lane.get("lane_name")
        or _lane.get("lane_label")
        or _lane.get("target_label")
        or _lane.get("lane_key")
        or ""
    ).strip().lower()
    _product_family = str(
        _lane.get("product_family")
        or _lane.get("lane_product")
        or _lane.get("target_product_family")
        or _target_meta.get("set_name") if isinstance(_target_meta, dict) else ""
    ).strip().lower().replace(" ", "_")
    _player_name = str(
        _lane.get("player")
        or _lane.get("player_name")
        or _lane.get("target_player_name")
        or _elite_player_name(_lane)
        or ""
    ).strip()
    _signal = " ".join(
        str(_part or "").strip().lower()
        for _part in [
            _variant,
            _query,
            _lane_name,
            _lane.get("query"),
            _lane.get("target_label"),
            _lane.get("lane_name"),
            _lane.get("query_kind"),
            _lane.get("target_lane_type"),
            _lane.get("query_contract_type"),
            _lane.get("lane_subset"),
            _lane.get("subset_name"),
            _lane.get("lane_parallel"),
            _lane.get("parallel_name"),
            _lane.get("lane_product"),
            _lane.get("product_family"),
            _lane.get("target_product_family"),
            _target_meta.get("set_name") if isinstance(_target_meta, dict) else "",
            _target_meta.get("parallel") if isinstance(_target_meta, dict) else "",
        ]
        if str(_part or "").strip()
    )
    _heat_tokens = (
        "collector_heat",
        "auto",
        "autograph",
        "/10",
        "/25",
        "/50",
        "/99",
        "psa 10",
        "bgs 10",
        "sgc 10",
        "gold",
        "black",
        "superfractor",
        "stained glass",
        "downtown",
        "kaboom",
        "genesis",
        "zebra",
        "tiger",
        "honeycomb",
        "manga",
        "color blast",
        "peacock",
        "elephant",
    )
    _auto_serial_case_hit_signal = any(_tok in _signal for _tok in _heat_tokens)
    _elite = bool(_lane.get("is_elite_player"))
    _curated = bool(_lane.get("is_curated_player"))
    if not _elite and _player_name:
        _elite = bool(_player_heat_tier(_player_name) in {1, 2})
    if not _curated:
        try:
            _curated = int(_lane.get("whatnot_tier") or _lane.get("player_tier") or 99) <= 2
        except Exception:
            _curated = False
    if bool(_lane.get("collector_heat_lane_allowed")):
        return bool(_elite or _curated or _player_name)
    if bool(_lane.get("live_budget_floor")) and _auto_serial_case_hit_signal:
        return bool(_elite or _curated or _player_name)
    if any(_tok in _variant for _tok in _heat_tokens):
        return bool(_elite or _curated or _player_name)
    if any(_tok in _query for _tok in _heat_tokens):
        return bool(_elite or _curated or _player_name)
    if (
        "topps chrome black" in _lane_name
        and any(_tok in _lane_name for _tok in ("auto", "autograph", "/10", "/25", "/50", "/99", "gold", "superfractor"))
        and (_elite or _curated or _player_name)
    ):
        return True
    _premium_live_floor_products = {
        "topps_chrome_black",
        "topps_chrome",
        "national_treasures",
        "immaculate",
        "flawless",
        "prizm",
        "select",
        "optic",
    }
    if (_elite or _curated) and _product_family in _premium_live_floor_products and _auto_serial_case_hit_signal:
        return True
    _has_heat_signal = bool(
        _lane.get("collector_heat_lane_allowed")
        or _lane.get("_collector_heat_query")
        or str(_lane.get("target_lane_type") or "").strip().lower() == "collector_heat"
        or str(_lane.get("query_kind") or "").strip().lower().startswith("collector_heat")
        or _collector_heat_lane_signal(_lane)
        or _auto_serial_case_hit_signal
    )
    if not _has_heat_signal:
        return False
    return bool(_elite or _curated)


def _lane_allocator_profile(spec: Dict[str, Any], diversity_memory: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    _lane_meta = _lane_yield_meta_for_spec(spec)
    _base_score = _target_priority_score(spec)
    _yield_score = _lane_yield_score(_lane_meta)
    _supply_score = _lane_supply_score(_lane_meta)
    _diversity_penalty = _spec_diversity_penalty(spec, diversity_memory)
    _rank_score = _base_score + _yield_score + _supply_score * 0.5 - _diversity_penalty
    _urgency_tier = _discovery_urgency_tier(_lane_meta.get("live_nearest_remaining"))
    _premium_score = _discovery_premium_priority_score(spec, _lane_meta)
    _window_viability_score = float(_lane_meta.get("window_viability_score") or 0.0)
    _window_memory = _lane_window_memory_summary(_lane_meta)
    _live_priority = _lane_live_priority_score(spec, _lane_meta)
    _recent_live_hits = _discovery_recent_live_hits(_lane_meta)
    _recent_in_window_hits = int(_lane_meta.get("recent_in_window_hits") or 0)
    _last_good_boost = min(
        24.0,
        (float(_recent_in_window_hits) * 4.0)
        + (float(_recent_live_hits) * 2.5)
        + (float(int(_lane_meta.get("live_strict_within") or 0)) * 6.0),
    )
    if _last_good_boost > 0.0:
        print(
            f"[LAST_GOOD_LANE] lane={str(_lane_meta.get('lane_label') or _lane_meta.get('lane_key') or _lane_metric_label(spec))[:96]} "
            f"recent_within_window={_recent_in_window_hits} boost={round(_last_good_boost, 2)}"
        )
    _current_urgency_signal = _discovery_has_current_urgency_signal(_lane_meta)
    _cold_generic_lane = bool(
        _discovery_is_generic_lane(spec, _lane_meta)
        and _recent_live_hits <= 0
        and not _current_urgency_signal
    )
    _quality = _query_lane_quality_profile(spec)
    _sport = str(spec.get("sport") or "").strip().upper()
    _heat_state = get_recent_board_heat_state()
    _heat_mode = str(_heat_state.get("mode") or "normal")
    _is_target_broad = _sport in _TARGET_SPORT_BROAD_INTAKE_PRODUCTS and str(spec.get("_intake_type") or "").strip().lower() == "broad"
    _product_tier = _lane_meta_product_tier(_lane_meta)
    _product_desirability = {
        "ENDGAME": 3.0,
        "PREMIUM": 2.0,
        "MID": 1.0,
        "LOW": 0.0,
    }.get(_product_tier, 0.0)
    _rank_score += {
        "tier_0_1h": 34.0,
        "tier_1_3h": 24.0,
        "tier_3_6h": 14.0,
        "tier_6_24h": 6.0,
        "tier_over_24h": -18.0,
    }.get(_urgency_tier, 0.0)
    _rank_score += float(_live_priority)
    _rank_score += float(_last_good_boost)
    if bool(_quality.get("premium_keep")):
        _rank_score += 12.0
    elif _is_target_broad and _heat_mode == "broad_bias":
        _rank_score += 8.0
    elif bool(spec.get("_broad_force_keep")) and _is_target_broad:
        _rank_score += 3.0
    elif bool(_quality.get("weak_explore")):
        _rank_score -= 26.0
    elif not bool(spec.get("spec_premium_lane")):
        _rank_score -= 18.0
    if _cold_generic_lane:
        _rank_score -= 120.0
    return {
        "spec": spec,
        "lane_meta": _lane_meta,
        "base_score": _base_score,
        "yield_score": _yield_score,
        "supply_score": _supply_score,
        "diversity_penalty": _diversity_penalty,
        "rank_score": _rank_score,
        "bucket": _lane_allocator_bucket(spec, _lane_meta),
        "urgency_tier": _urgency_tier,
        "premium_score": _premium_score,
        "window_viability_score": _window_viability_score,
        "window_memory": _window_memory,
        "live_priority": _live_priority,
        "recent_live_hits": _recent_live_hits,
        "recent_in_window_hits": _recent_in_window_hits,
        "last_good_boost": _last_good_boost,
        "product_tier": _product_tier,
        "product_desirability": _product_desirability,
        "cold_lane_blocked": bool(_cold_generic_lane),
    }


def _runtime_bucket_for_spec(spec: Dict[str, Any], lane_meta: Optional[Dict[str, Any]] = None) -> str:
    _lane_meta = dict(lane_meta or _lane_yield_meta_for_spec(spec))
    _premium_score = float(_discovery_premium_priority_score(spec, _lane_meta) or 0.0)
    _recent_in_window_hits = int(_lane_meta.get("recent_in_window_hits") or 0)
    _recent_live_hits = _discovery_recent_live_hits(_lane_meta)
    _product_tier = _lane_meta_product_tier(_lane_meta)
    _dead = bool(_lane_meta.get("dead_for_live_window")) or int(_lane_meta.get("live_cooldown_cycles") or 0) > 0
    _cold_generic = bool(
        _discovery_is_generic_lane(spec, _lane_meta)
        and _recent_live_hits <= 0
        and not _discovery_has_current_urgency_signal(_lane_meta)
    )
    if _dead or _cold_generic:
        return "probe_pool"
    # [TIER1_PROTECTED_CORE_BOOST] — auto-promote Tier 1 player lanes to
    # protected_core regardless of other criteria. Tier 1 = mega-liquid
    # players (Mahomes, Ohtani, Skenes, Wembanyama, Curry, LeBron, Brock
    # Bowers, Justin Jefferson, etc.) whose base rookie cards have hundreds
    # of sold comps. Their lanes are exactly the ones most likely to surface
    # SNIPE-NOW-eligible inventory (verified MV + occasional auction price
    # below target). Earlier scans showed `core 0 + rotating 18` in the UI
    # header — meaning zero Tier 1 lanes were getting protected status. This
    # boost ensures the cohort always reserves slots for them.
    # Tier resolution chain — first available wins:
    #   1. spec["whatnot_tier"] (legacy generator)
    #   2. spec["player_demand_tier"] (player_hub generator)
    #   3. lane_meta["player_demand_tier"]
    #   4. _player_heat_tier(spec.player_name) — _PLAYER_MASTER lookup
    _spec_tier = 0
    try:
        for _tier_field, _tier_source in (
            (spec.get("whatnot_tier"), "spec.whatnot_tier"),
            (spec.get("player_demand_tier"), "spec.player_demand_tier"),
            (_lane_meta.get("player_demand_tier"), "lane_meta.player_demand_tier"),
            (_lane_meta.get("whatnot_tier"), "lane_meta.whatnot_tier"),
        ):
            try:
                _v = int(_tier_field or 0)
            except (TypeError, ValueError):
                _v = 0
            if _v in (1, 2, 3):
                _spec_tier = _v
                break
        if _spec_tier == 0:
            # Last resort: resolve from player name via _PLAYER_MASTER table.
            _player_for_lookup = str(
                spec.get("player_name")
                or spec.get("target_label")
                or _lane_meta.get("player_name")
                or _lane_meta.get("target_player_name")
                or ""
            ).strip()
            if _player_for_lookup:
                try:
                    _resolved = int(_player_heat_tier(_player_for_lookup) or 0)
                    if _resolved in (1, 2, 3):
                        _spec_tier = _resolved
                except Exception:
                    pass
    except Exception:
        _spec_tier = 0
    if _spec_tier == 1:
        try:
            print(
                f"[TIER1_PROTECTED_BOOST] "
                f"player={str(spec.get('player_name') or '')[:48]} "
                f"product={str(spec.get('lane_product') or spec.get('target_product_family') or '')[:48]} "
                f"tier={_spec_tier} action=force_protected_core"
            )
        except Exception:
            pass
        return "protected_core"
    if (
        bool(spec.get("spec_premium_lane"))
        or _recent_in_window_hits > 0
        or _product_tier in {"ENDGAME", "PREMIUM"}
        or _premium_score >= 48.0
        or _lane_has_positive_window_viability(_lane_meta)
    ):
        return "protected_core"
    # Tier 2 players (Joe Burrow, Bobby Witt Jr, Anthony Richardson, Luka,
    # etc.) get protected_core only when paired with PREMIUM/ENDGAME products
    # — that's already covered by the conditions above, but we add an
    # explicit Tier 2 + premium product elevation here for visibility.
    if _spec_tier == 2 and _product_tier in {"ENDGAME", "PREMIUM"}:
        try:
            print(
                f"[TIER2_PREMIUM_BOOST] "
                f"player={str(spec.get('player_name') or '')[:48]} "
                f"product={str(spec.get('lane_product') or spec.get('target_product_family') or '')[:48]} "
                f"tier={_spec_tier} product_tier={_product_tier} action=force_protected_core"
            )
        except Exception:
            pass
        return "protected_core"
    return "probe_pool"


def _protected_core_profile_sort_key(profile: Dict[str, Any]) -> Tuple[float, ...]:
    _spec = dict(profile.get("spec") or {})
    _lane_meta = dict(profile.get("lane_meta") or {})
    return (
        -float(profile.get("last_good_boost") or 0.0),
        -float(profile.get("recent_in_window_hits") or 0),
        -float(profile.get("live_priority") or 0.0),
        -float(profile.get("premium_score") or 0.0),
        -float(profile.get("product_desirability") or 0.0),
        -float(profile.get("window_viability_score") or 0.0),
        _discovery_urgency_rank(str(profile.get("urgency_tier") or "")),
        -float(profile.get("rank_score") or 0.0),
        str(_lane_meta.get("lane_label") or _lane_metric_label(_spec)),
    )


def _annotate_query_slot_signature(spec: Dict[str, Any]) -> Dict[str, Any]:
    _spec = dict(spec or {})
    try:
        _sig = player_hub.build_query_slot_signature(_spec)
    except Exception:
        _sig = {}
    _spec["query_slot_signature"] = str(_sig.get("signature") or "")
    _spec["query_slot_player_key"] = str(_sig.get("player_key") or "")
    _spec["query_slot_product_ecosystem"] = str(_sig.get("product_ecosystem") or "")
    _spec["query_slot_intent_type"] = str(_sig.get("intent_type") or "")
    _spec["query_slot_intent_label"] = str(_sig.get("intent_label") or "")
    _spec["query_slot_intent_key"] = str(_sig.get("intent_key") or "")
    _spec["query_slot_exposure_key"] = str(_sig.get("exposure_key") or "")
    _spec["query_slot_rarity_class"] = str(_sig.get("rarity_class") or "")
    return _spec


def _query_slot_priority_tuple(spec: Dict[str, Any]) -> Tuple[float, ...]:
    _quality = _query_lane_quality_profile(spec)
    return (
        float(_query_lane_quality_rank(spec)),
        1.0 if bool(spec.get("_broad_force_keep")) else 0.0,
        0.0 if bool(_quality.get("weak_explore")) else 1.0,
        1.0 if bool(spec.get("spec_premium_lane")) else 0.0,
        1.0 if str(spec.get("lane_tier") or "").strip().lower() == "primary" else 0.0,
        float(spec.get("premium_lane_priority") or 0.0),
        float(spec.get("lane_priority") or 0.0),
        {
            "lane_subset_parallel": 4.0,
            "lane_subset": 3.0,
            "lane_parallel": 2.0,
            "lane_product_only": 1.0,
            "product_base": 0.0,
            "broad_fallback": -1.0,
        }.get(str(spec.get("query_kind") or spec.get("target_lane_type") or "").strip().lower(), 0.0),
        float(len(list(spec.get("query_variants") or []))),
    )


def _collapse_duplicate_live_query_specs(specs: List[Dict[str, Any]]) -> Tuple[List[Dict[str, Any]], Dict[str, Any]]:
    _annotated = [_annotate_query_slot_signature(_spec) for _spec in list(specs or [])]
    _best_by_sig: Dict[str, Dict[str, Any]] = {}
    _duplicates: Dict[str, List[Dict[str, Any]]] = {}
    for _idx, _spec in enumerate(_annotated):
        _sig = str(_spec.get("query_slot_signature") or "")
        if not _sig:
            _sig = f"unsig|{_idx}"
            _spec["query_slot_signature"] = _sig
        _spec["_query_slot_idx"] = _idx
        _current = _best_by_sig.get(_sig)
        if _current is None or _query_slot_priority_tuple(_spec) > _query_slot_priority_tuple(_current):
            if _current is not None:
                _duplicates.setdefault(_sig, []).append(_current)
            _best_by_sig[_sig] = _spec
        else:
            _duplicates.setdefault(_sig, []).append(_spec)

    _kept = sorted(_best_by_sig.values(), key=lambda _spec: int(_spec.get("_query_slot_idx") or 0))
    _collapsed = sum(len(_vals) for _vals in _duplicates.values())
    for _spec in _kept:
        _sig = str(_spec.get("query_slot_signature") or "")
        _spec["query_slot_duplicate_count"] = len(_duplicates.get(_sig) or [])
        _spec["query_slot_collapsed"] = bool(_spec.get("query_slot_duplicate_count"))
        _spec.pop("_query_slot_idx", None)
    for _dup_list in _duplicates.values():
        for _dup in _dup_list:
            _dup["query_slot_deferred"] = True
            _dup.pop("_query_slot_idx", None)

    _sample = []
    for _sig, _dups in list(_duplicates.items())[:8]:
        _keep = _best_by_sig.get(_sig) or {}
        _sample.append((
            str((_keep.get("player_name") or _keep.get("player_id") or ""))[:18],
            str(_keep.get("query_slot_intent_label") or _keep.get("query_slot_intent_type") or ""),
            len(_dups),
            str(_keep.get("query") or "")[:54],
        ))
    print(f"[QUERY_DEDUPE] collapsed={_collapsed} sample={_sample}")
    print(
        f"[QUERY_SLOT_EFFICIENCY] unique_live_intents={len(_kept)} "
        f"duplicates_removed={_collapsed}"
    )
    return _kept, {
        "duplicates_removed": _collapsed,
        "unique_live_intents": len(_kept),
        "sample": _sample,
    }


def _select_query_slot_efficient_entries(
    entries: List[Dict[str, Any]],
    *,
    limit: int,
    recent_players: Optional[set] = None,
    recent_products: Optional[set] = None,
) -> Tuple[List[Dict[str, Any]], int]:
    _selected: List[Dict[str, Any]] = []
    _seen_players: set = set()
    _seen_products: set = set()
    _seen_intents: set = set()
    _seen_exposures: set = set()
    _fresh = 0
    for _entry in list(entries or []):
        if len(_selected) >= int(limit or 0):
            break
        _spec = dict(_entry.get("spec") or {})
        _player, _product, _sport = _spec_diversity_keys(_spec)
        _intent = str(_spec.get("query_slot_intent_key") or "").strip().lower()
        _exposure = str(_spec.get("query_slot_exposure_key") or "").strip().lower()
        _prefer = (
            (_player and _player not in _seen_players and _player not in (recent_players or set()))
            or (_product and _product not in _seen_products and _product not in (recent_products or set()))
            or (_intent and _intent not in _seen_intents)
            or (_exposure and _exposure not in _seen_exposures)
        )
        if _prefer or len(_selected) < max(3, int(limit or 0) // 2):
            _selected.append(_spec)
            if _player:
                _seen_players.add(_player)
            if _product:
                _seen_products.add(_product)
            if _intent:
                _seen_intents.add(_intent)
            if _exposure:
                _seen_exposures.add(_exposure)
            if _prefer:
                _fresh += 1
    for _entry in list(entries or []):
        if len(_selected) >= int(limit or 0):
            break
        _spec = dict(_entry.get("spec") or {})
        if _spec in _selected:
            continue
        _selected.append(_spec)
    return _selected[: int(limit or 0)], _fresh


def _normalize_diversity_memory(diversity_memory: Optional[Dict[str, Any]]) -> Dict[str, set]:
    _raw = dict(diversity_memory or {})
    def _norm_list(_vals: Any) -> set:
        _out: set = set()
        for _v in list(_vals or []):
            _txt = str(_v or "").strip().lower()
            if _txt:
                _out.add(_txt)
        return _out
    return {
        "recent_players": _norm_list(_raw.get("recent_players")),
        "recent_products": _norm_list(_raw.get("recent_products")),
        "recent_item_ids": _norm_list(_raw.get("recent_item_ids")),
    }


def _spec_diversity_keys(spec: Dict[str, Any]) -> Tuple[str, str, str]:
    _player = str(spec.get("player_name") or spec.get("player_id") or "").strip().lower()
    _product = str(spec.get("target_product_family") or spec.get("product_family") or spec.get("target_id") or "").strip().lower()
    _sport = str(spec.get("sport") or "").strip().upper()
    return _player, _product, _sport


def _spec_diversity_penalty(spec: Dict[str, Any], diversity_memory: Optional[Dict[str, Any]]) -> float:
    _mem = _normalize_diversity_memory(diversity_memory)
    _player, _product, _sport = _spec_diversity_keys(spec)
    _penalty = 0.0
    if _player and _player in _mem["recent_players"]:
        _penalty += _ES_DIVERSITY_RECENT_PLAYER_PENALTY
    if _product and _product in _mem["recent_products"]:
        _penalty += _ES_DIVERSITY_RECENT_PRODUCT_PENALTY
    if _player and _product and f"{_player}|{_product}" in _mem["recent_item_ids"]:
        _penalty += _ES_DIVERSITY_RECENT_ITEM_BONUS_BLOCK
    if _sport in {"MLB", "NBA"}:
        _penalty *= 0.9
    return _penalty


def _select_diverse_specs(
    scored_specs: List[Tuple[Dict[str, Any], float]],
    *,
    limit: int,
    recent_players: Optional[set] = None,
    recent_products: Optional[set] = None,
) -> Tuple[List[Dict[str, Any]], int]:
    _selected: List[Dict[str, Any]] = []
    _seen_players = set()
    _seen_products = set()
    _fresh_injected = 0
    for _spec, _score in list(scored_specs or []):
        if len(_selected) >= int(limit or 0):
            break
        _player, _product, _sport = _spec_diversity_keys(_spec)
        _prefer = (
            (_player and _player not in _seen_players and _player not in (recent_players or set()))
            or (_product and _product not in _seen_products and _product not in (recent_products or set()))
        )
        if _prefer or len(_selected) < max(3, int(limit or 0) // 2):
            _selected.append(_spec)
            if _player:
                _seen_players.add(_player)
            if _product:
                _seen_products.add(_product)
            if _prefer:
                _fresh_injected += 1
    for _spec, _score in list(scored_specs or []):
        if len(_selected) >= int(limit or 0):
            break
        if _spec in _selected:
            continue
        _selected.append(_spec)
    return _selected[: int(limit or 0)], _fresh_injected


def _inject_diversity_floor(
    cohort: List[Dict[str, Any]],
    candidates: List[Tuple[Dict[str, Any], float]],
    *,
    min_players: int,
    min_products: int,
    max_total: int,
) -> Tuple[List[Dict[str, Any]], int]:
    _out = list(cohort or [])
    _fresh = 0
    _player_set = {str(s.get("player_name") or s.get("player_id") or "").strip().lower() for s in _out if str(s.get("player_name") or s.get("player_id") or "").strip()}
    _product_set = {str(s.get("target_product_family") or s.get("product_family") or s.get("target_id") or "").strip().lower() for s in _out if str(s.get("target_product_family") or s.get("product_family") or s.get("target_id") or "").strip()}
    for _spec, _score in list(candidates or []):
        if len(_out) >= max_total:
            break
        if _spec in _out:
            continue
        _player, _product, _sport = _spec_diversity_keys(_spec)
        _need_player = len(_player_set) < min_players and _player and _player not in _player_set
        _need_product = len(_product_set) < min_products and _product and _product not in _product_set
        if not (_need_player or _need_product):
            continue
        _out.append(_spec)
        if _player:
            _player_set.add(_player)
        if _product:
            _product_set.add(_product)
        _fresh += 1
    return _out[:max_total], _fresh


def _build_es_scan_cohort(
    specs: List[Dict[str, Any]],
    cycle_id: int,
    cross_sport: bool = False,
    diversity_memory: Optional[Dict[str, Any]] = None,
) -> Tuple[List[Dict[str, Any]], Dict[str, Any]]:
    """
    Select a focused scan cohort from the full spec list.

    Single-sport mode (cross_sport=False):
      Core = top _ES_COHORT_CORE_SIZE by priority + rotating slice, capped at _ES_MAX_COHORT_SIZE.

    Cross-sport mode (cross_sport=True):
      Per-sport allocation: NFL 18+10, MLB 10+5, NBA 6+4 = 53 total, capped at _ES_MAX_COHORT_SIZE.
      Within each sport, core slots are always filled; rotating slots use cycle_id slicing.

    Returns (cohort_specs, diagnostics_dict).
    """
    if not specs:
        return [], {"core": 0, "rotating_pool": 0, "rotating_kept": 0, "total": 0, "cycle_id": cycle_id}
    _heat_state = get_recent_board_heat_state()
    print(
        f"[QUERY_HEAT_MODE] mode={str(_heat_state.get('mode') or 'normal')} "
        f"last_board_rows={int(_heat_state.get('last_total_rows') or 0)} "
        f"threshold={_BOARD_HEAT_BROAD_THRESHOLD} source={str(_heat_state.get('source') or '')}"
    )

    _incoming_total = len(list(specs or []))
    _elite_specs: List[Dict[str, Any]] = []
    _blocked_non_elite = 0
    _soft_premium_lanes = 0
    for _spec in list(specs or []):
        _gate = _elite_lane_gate(_spec)
        _spec["elite_whitelist_tier"] = str(_gate.get("tier") or "BLOCKED")
        _spec["elite_whitelist_reason"] = str(_gate.get("reason") or "")
        _spec["premium_product_soft_allowed"] = bool(_gate.get("premium_product_soft_allowed"))
        _spec["requires_strong_listing_chase_signal"] = bool(_gate.get("requires_strong_listing_chase_signal"))
        _spec["lane_seed_chase_missing"] = bool(_gate.get("lane_seed_chase_missing"))
        if bool(_gate.get("collector_heat_lane_allowed")):
            _spec["collector_heat_lane_allowed"] = True
        if bool(_gate.get("authoritative_chase_signal")):
            _spec["authoritative_chase_signal"] = True
            _spec["parallel_signal_reason"] = _spec.get("parallel_signal_reason") or "authoritative_lane_label"
        print(f"[WHITELIST_TIER] lane={_elite_lane_label(_spec)} tier={_spec['elite_whitelist_tier']}")
        print(
            f"[CHASE_SIGNAL_GATE] lane={_elite_lane_label(_spec)} "
            f"allowed={1 if _gate.get('allowed') else 0} reason={_spec['elite_whitelist_reason'] or 'none'}"
        )
        if bool(_spec.get("premium_product_soft_allowed")):
            _soft_premium_lanes += 1
            print(
                f"[SOFT_PREMIUM_LANE] lane={_elite_lane_label(_spec)} "
                f"product={str(_spec.get('lane_product') or _spec.get('target_product_family') or _spec.get('product_family') or '')[:48]} "
                f"allowed=1 requires_listing_signal=1"
            )
        if not _gate.get("allowed"):
            _blocked_non_elite += 1
            print(f"[LANE_WHITELIST_BLOCK] lane={_elite_lane_label(_spec)} reason={_spec['elite_whitelist_reason'] or 'non_elite'}")
            continue
        print(f"[ELITE_LANE] lane={_elite_lane_label(_spec)} accepted")
        _elite_specs.append(_spec)
    specs = _elite_specs
    print(f"[ELITE_DENSITY] elite_scanned={len(specs)} total_scanned={_incoming_total}")
    print(f"[INTAKE_STAGE] stage=post_elite_lane_gate count={len(specs)}")
    if not specs:
        return [], {
            "core": 0,
            "rotating_pool": 0,
            "rotating_kept": 0,
            "total": 0,
            "cycle_id": cycle_id,
            "blocked_non_elite": _blocked_non_elite,
            "elite_scanned": 0,
            "total_scanned": _incoming_total,
            "soft_premium_lanes": _soft_premium_lanes,
        }

    _mem = _normalize_diversity_memory(diversity_memory)
    _recent_players = set(_mem.get("recent_players") or set())
    _recent_products = set(_mem.get("recent_products") or set())
    _max_total = min(_ES_MAX_COHORT_SIZE, len(specs))
    _premium_specs: List[Dict[str, Any]] = []
    _fallback_specs: List[Dict[str, Any]] = []
    _cooled_skip_count = 0
    _seen_lane_keys: set = set()
    _quality_counts = {"premium_keep": 0, "weak_explore": 0, "neutral": 0}

    # PATCH 4: filter cooled lanes; PATCH 6: separate by product tier for density enforcement
    _endgame_specs: List[Dict[str, Any]] = []
    _premium_tier_specs: List[Dict[str, Any]] = []
    _other_tier_specs: List[Dict[str, Any]] = []

    for _spec in list(specs or []):
        _lane_key = _lane_metric_key(_spec)
        if _lane_key and _lane_key in _seen_lane_keys:
            continue
        if _lane_key:
            _seen_lane_keys.add(_lane_key)
        # PATCH 4: skip cooled lanes
        _spec_meta = _lane_yield_meta_for_spec(_spec)
        _live_cooldown_cycles = max(0, int(_spec_meta.get("live_cooldown_cycles") or 0))
        if bool(_spec_meta.get("dead_for_live_window")) or _live_cooldown_cycles > 0:
            _baseline_meta = dict(_spec_meta)
            _baseline_meta["dead_for_live_window"] = False
            _baseline_meta["live_cooldown_cycles"] = 0
            _old_rank = round(_lane_yield_score(_baseline_meta), 2)
            _new_rank = round(_lane_yield_score(_spec_meta), 2)
            _spec["dead_for_live_window"] = bool(_spec_meta.get("dead_for_live_window"))
            _spec["live_cooldown_cycles"] = _live_cooldown_cycles
            print(
                f"[LANE_BUDGET_DOWNRANK] lane={str(_spec_meta.get('lane_label') or _lane_key)[:96]} "
                f"old_rank={_old_rank} new_rank={_new_rank} cooldown_cycles={_live_cooldown_cycles}"
            )
        if bool(_spec_meta.get("lane_cooled")) and int(_spec_meta.get("lane_cooldown_cycles_remaining") or 0) > 0:
            _cooled_skip_count += 1
            continue
        _qprof = _query_lane_quality_profile(_spec)
        _quality_bucket = str(_qprof.get("quality_bucket") or "neutral")
        _quality_counts[_quality_bucket] = int(_quality_counts.get(_quality_bucket, 0) or 0) + 1
        if bool(_qprof.get("premium_keep")):
            _premium_specs.append(_spec)
        else:
            _fallback_specs.append(_spec)
        # PATCH 6: classify by product tier for density enforcement
        _pt = _lane_spec_product_tier(_spec)
        if _pt == "ENDGAME":
            _endgame_specs.append(_spec)
        elif _pt == "PREMIUM":
            _premium_tier_specs.append(_spec)
        else:
            _other_tier_specs.append(_spec)

    if _cooled_skip_count > 0:
        print(f"[LANE_COOLDOWN_FILTER] cooled_skipped={_cooled_skip_count} remaining_specs={len(_premium_specs) + len(_fallback_specs)}")

    # ── PREMIUM-FIRST BUDGET CLASSIFICATION ──────────────────────────────────
    # Separate fallback specs into query-intent premium vs base-only, so
    # base-intent queries can be capped in the explore slot rather than
    # competing freely with premium lanes for winner/active budget.
    _fallback_premium_intent: List[Dict[str, Any]] = []  # non-weak fallback support
    _fallback_base_intent: List[Dict[str, Any]] = []      # purely base/generic queries
    for _fs in list(_fallback_specs or []):
        if not _spec_is_weak_exploration_query(_fs):
            _fallback_premium_intent.append(_fs)
        else:
            _fallback_base_intent.append(_fs)

    # COMMON_MODERN containment: mark base-intent + LOW-tier specs for explore-only
    _cm_contained_count = 0
    _cm_escaped_count = 0
    for _fs in list(_fallback_base_intent):
        _fs_pt = _lane_spec_product_tier(_fs)
        _fs_cm = bool(_fs.get("common_modern_exact_required")) or bool(_fs.get("_base_query_intent_only"))
        if _fs_cm or _fs_pt == "LOW":
            _fs["_cm_containment_target"] = True
            _cm_contained_count += 1
            print(
                f"[COMMON_MODERN_CONTAIN] player={str(_fs.get('player_name') or '')[:24]} "
                f"query={str(_fs.get('query') or '')[:60]} "
                f"tier={_fs_pt} reason=base_intent_no_premium_signal"
            )
        else:
            # Premium-tier product with base query — eligible for mid-priority budget
            _cm_escaped_count += 1
            print(
                f"[COMMON_MODERN_ESCAPE] player={str(_fs.get('player_name') or '')[:24]} "
                f"query={str(_fs.get('query') or '')[:60]} "
                f"tier={_fs_pt} reason=premium_product_family_salvage"
            )

    _scan_budget_premium_count = len(_premium_specs) + len(_fallback_premium_intent)
    _scan_budget_explore_count = len(_fallback_base_intent)
    print(
        f"[LANE_QUALITY_SUMMARY] total={len(specs)} premium_keep={int(_quality_counts.get('premium_keep', 0))} "
        f"weak_explore={int(_quality_counts.get('weak_explore', 0))} neutral={int(_quality_counts.get('neutral', 0))}"
    )
    print(
        f"[SCAN_BUDGET_PREMIUM] premium_lane_specs={len(_premium_specs)} "
        f"premium_intent_fallback={len(_fallback_premium_intent)} "
        f"total_premium_budget={_scan_budget_premium_count}"
    )
    print(
        f"[SCAN_BUDGET_EXPLORE] base_intent_specs={_scan_budget_explore_count} "
        f"cm_contained={_cm_contained_count} cm_escaped={_cm_escaped_count}"
    )
    # ─────────────────────────────────────────────────────────────────────────

    _explore_target = 0 if _max_total <= 3 else max(1, min(4, int(round(_max_total * 0.10)) or 1))
    _premium_budget_target = max(1, _max_total - _explore_target)
    _winner_target = max(1, min(_premium_budget_target, int(round(_premium_budget_target * 0.60)) or 1))
    _active_target = max(0, _premium_budget_target - _winner_target)

    # Ensure base-intent-only specs (flagged _cm_containment_target) cannot claim
    # more than half the explore slots, preventing them from displacing premium lanes.
    _base_intent_explore_cap = 0 if _explore_target <= 0 else max(1, min(_explore_target, 4))
    _base_intent_in_explore = 0

    _all_source_specs = _premium_specs + _fallback_premium_intent + _fallback_base_intent
    _profiles_all = [_lane_allocator_profile(_s, diversity_memory=diversity_memory) for _s in _all_source_specs]
    _profiles_filtered: List[Dict[str, Any]] = []
    for _profile in list(_profiles_all):
        _spec = dict(_profile.get("spec") or {})
        _lane_meta = dict(_profile.get("lane_meta") or {})
        _lane = str(_lane_meta.get("lane_label") or _lane_meta.get("lane_key") or _lane_metric_label(_spec))[:96]
        _player = str(_lane_meta.get("player_name") or _spec.get("player_name") or "")[:48]
        _product = str(_lane_meta.get("lane_product") or _spec.get("lane_product") or _spec.get("target_product_family") or "")[:48]
        _urgency_tier = str(_profile.get("urgency_tier") or _discovery_urgency_tier(_lane_meta.get("live_nearest_remaining")))
        _nearest_remaining = _safe_float(_lane_meta.get("live_nearest_remaining"))
        print(
            f"[DISCOVERY_URGENCY_TIER] lane={_lane} "
            f"player={_player} product={_product} tier={_urgency_tier} "
            f"nearest_remaining={_nearest_remaining if _nearest_remaining is not None else 'None'}"
        )
        _window_memory = dict(_profile.get("window_memory") or {})
        print(
            f"[WINDOW_LANE_MEMORY] lane={_lane} "
            f"recent_in_window_hits={int(_window_memory.get('recent_in_window_hits') or 0)} "
            f"recent_scope_invalid={int(_window_memory.get('recent_scope_invalid') or 0)} "
            f"recent_dead={int(_window_memory.get('recent_dead') or 0)} "
            f"action={str(_window_memory.get('action') or 'keep')}"
        )
        if bool(_profile.get("cold_lane_blocked")):
            print(
                f"[DISCOVERY_COLD_LANE_BLOCK] lane={_lane} "
                f"reason=low_yield_generic_lane_penalized_only "
                f"recent_live_hits={int(_profile.get('recent_live_hits') or 0)} selected=1"
            )
        _profiles_filtered.append(_profile)
    _profiles_all = _profiles_filtered
    _profiles = _profiles_all
    with _PLAYER_WINNER_LOCK:
        _player_state_snapshot = {str(_k): dict(_v) for _k, _v in _PLAYER_WINNER_STATE.items()}

    _player_best_score: Dict[str, float] = {}
    _player_best_name: Dict[str, str] = {}
    _player_best_sport: Dict[str, str] = {}
    for _prof in _profiles_all:
        _lane_meta = dict(_prof.get("lane_meta") or {})
        _player_key = str(_lane_meta.get("player_key") or _lane_player_key(_lane_meta))
        if not _player_key:
            continue
        _winner_score = _winner_lane_score(_lane_meta)
        _recent_active = int((_player_state_snapshot.get(_player_key) or {}).get("recently_active_cycles") or 0)
        _player_score = float(_prof.get("rank_score") or 0.0) + _winner_score + min(8.0, _recent_active * 1.5)
        if _player_score > float(_player_best_score.get(_player_key, -9999.0)):
            _player_best_score[_player_key] = _player_score
            _player_best_name[_player_key] = str(_lane_meta.get("player_name") or _player_key)
            _player_best_sport[_player_key] = str(_lane_meta.get("sport") or "").strip().upper()

    _active_players_by_sport: Dict[str, List[str]] = {}
    for _sport_key in {str((_prof.get("lane_meta") or {}).get("sport") or "").strip().upper() for _prof in _profiles_all}:
        if not _sport_key:
            continue
        for _player_key, _state in _player_state_snapshot.items():
            if str((_state or {}).get("sport") or "").strip().upper() != _sport_key:
                continue
            _cooldown_cycles = int((_state or {}).get("cooldown_cycles_remaining") or 0)
            if _cooldown_cycles > 0:
                print(f"[LANE_COOLDOWN] player={str((_state or {}).get('player_name') or _player_key)} product=ALL cooldown={_cooldown_cycles}")
        _sport_players = [
            _pk for _pk, _sp in _player_best_sport.items()
            if _sp == _sport_key and int((_player_state_snapshot.get(_pk) or {}).get("cooldown_cycles_remaining") or 0) <= 0
        ]
        _sport_players.sort(key=lambda _pk: (-float(_player_best_score.get(_pk, 0.0)), _player_best_name.get(_pk, _pk)))
        _winner_players = list(_sport_players[:6])
        _explore_players = list(_sport_players[6:8])
        _active_players_by_sport[_sport_key] = _winner_players + _explore_players
        print(f"[ACTIVE_PLAYER_SET] sport={_sport_key} count={len(_active_players_by_sport[_sport_key])} players={_active_players_by_sport[_sport_key][:12]}")
        print(f"[ACTIVE_PREMIUM_PLAYERS] sport={_sport_key} players={_active_players_by_sport[_sport_key]}")

    _allowed_player_keys = {
        _player_key
        for _players in _active_players_by_sport.values()
        for _player_key in _players
    }
    _filtered_profiles: List[Dict[str, Any]] = []
    _player_products_logged: set[tuple[str, str]] = set()
    _product_rank_by_player: Dict[str, Dict[str, float]] = {}
    for _prof in _profiles_all:
        _lane_meta = dict(_prof.get("lane_meta") or {})
        _player_key = str(_lane_meta.get("player_key") or _lane_player_key(_lane_meta))
        if _allowed_player_keys and _player_key not in _allowed_player_keys:
            continue
        _product = str(_lane_meta.get("product_family") or _lane_meta.get("lane_product") or "").strip() or "unknown"
        _product_rank_by_player.setdefault(_player_key, {})
        _product_rank_by_player[_player_key][_product] = max(
            float(_product_rank_by_player[_player_key].get(_product, -9999.0)),
            float(_prof.get("rank_score") or 0.0) + _winner_lane_score(_lane_meta),
        )
        _filtered_profiles.append(_prof)
    _profiles_all = _filtered_profiles

    _allowed_products_by_player: Dict[str, set[str]] = {}
    for _player_key, _product_scores in _product_rank_by_player.items():
        _chosen_products = [
            _product for _product, _score in sorted(_product_scores.items(), key=lambda _entry: (-float(_entry[1]), _entry[0]))[:2]
        ]
        _allowed_products_by_player[_player_key] = set(_chosen_products)
        print(f"[PLAYER_PRODUCT_CAP] player={_player_best_name.get(_player_key, _player_key)} chosen_products={_chosen_products}")
        print(f"[ACTIVE_PLAYER_PRODUCTS] player={_player_best_name.get(_player_key, _player_key)} products={_chosen_products}")

    _filtered_profiles = []
    for _prof in _profiles_all:
        _lane_meta = dict(_prof.get("lane_meta") or {})
        _player_key = str(_lane_meta.get("player_key") or _lane_player_key(_lane_meta))
        _product = str(_lane_meta.get("product_family") or _lane_meta.get("lane_product") or "").strip() or "unknown"
        if _allowed_products_by_player.get(_player_key) and _product not in _allowed_products_by_player[_player_key]:
            continue
        _filtered_profiles.append(_prof)
    _profiles_all = _filtered_profiles
    _profiles = _profiles_all
    _proving_profiles = [_p for _p in _profiles_all if str(_p.get("bucket") or "") == "proven"]
    _promising_profiles = [_p for _p in _profiles_all if str(_p.get("bucket") or "") == "promising"]
    _explore_profiles = [_p for _p in _profiles_all if str(_p.get("bucket") or "") == "explore"]
    _reclassified_promising: List[Dict[str, Any]] = []
    _reclassified_explore: List[Dict[str, Any]] = []
    for _profile in list(_promising_profiles):
        _lane_meta = dict(_profile.get("lane_meta") or {})
        _yield_score = float(_profile.get("yield_score") or 0.0)
        _winner_score = _winner_lane_score(_lane_meta)
        _queries = int(_lane_meta.get("lane_queries") or 0)
        _raw_hits = int(_lane_meta.get("lane_raw_hits") or 0)
        _in_window_hits = int(_lane_meta.get("lane_in_window_hits") or 0)
        _candidate_hits = int(_lane_meta.get("lane_candidate_hits") or 0)
        _visible_hits = int(_lane_meta.get("lane_visible_hits") or 0)
        _sniper_hits = int(_lane_meta.get("lane_sniper_hits") or 0)
        _has_success = bool(_candidate_hits > 0 or _visible_hits > 0 or _sniper_hits > 0)
        if _yield_score <= 0.0 and _winner_score <= 0.0 and not _has_success and _queries <= 0 and _raw_hits <= 0 and _in_window_hits <= 0:
            _profile_live_floor_lane = {**dict(_lane_meta or {}), **dict(_profile.get("spec") or {})}
            if _has_collector_heat_live_floor(_profile_live_floor_lane):
                _profile["bucket"] = "promising"
                (_profile.get("spec") or {})["yield_bucket"] = "live_floor"
                (_profile.get("spec") or {})["yield_reason"] = "collector_heat_live_floor"
                (_profile.get("spec") or {})["live_budget_floor"] = True
                print(
                    f"[COLLECTOR_HEAT_LIVE_FLOOR] lane={str(_lane_meta.get('lane_label') or _lane_meta.get('lane_key') or '')[:64]} "
                    f"player={str(_profile_live_floor_lane.get('player') or _profile_live_floor_lane.get('player_name') or '')[:48]} "
                    f"product={str(_profile_live_floor_lane.get('product_family') or _profile_live_floor_lane.get('lane_product') or _profile_live_floor_lane.get('target_product_family') or '')[:48]} "
                    f"reason=collector_heat_live_floor"
                )
                continue
            _profile["bucket"] = "explore"
            _reclassified_promising.append(_profile)
            print(
                f"[COHORT_ACTIVE_BLOCK] lane={str(_lane_meta.get('lane_label') or _lane_meta.get('lane_key') or '')[:64]} "
                f"yield={_yield_score} winner={_winner_score} reason=zero_signal_no_history"
            )
    if _reclassified_promising:
        _promising_profiles = [_p for _p in _promising_profiles if _p not in _reclassified_promising]
        _explore_profiles.extend(_reclassified_promising)
    for _profile in _explore_profiles:
        _lane_meta = dict(_profile.get("lane_meta") or {})
        _yield_score = float(_profile.get("yield_score") or 0.0)
        _winner_score = _winner_lane_score(_lane_meta)
        if _yield_score <= 0.0 and _winner_score <= 0.0:
            print(
                f"[COHORT_EXPLORE_ASSIGN] lane={str(_lane_meta.get('lane_label') or _lane_meta.get('lane_key') or '')[:64]} "
                f"yield={_yield_score} winner={_winner_score}"
            )

    def _sorted_bucket(_entries: List[Dict[str, Any]], *, _explore: bool = False) -> List[Dict[str, Any]]:
        _sorted = sorted(
            list(_entries or []),
            key=lambda _entry: (
                _discovery_urgency_rank(str(_entry.get("urgency_tier") or "")),
                -float(_entry.get("live_priority") or 0.0),
                -float(_entry.get("premium_score") or 0.0),
                -float(_entry.get("window_viability_score") or 0.0),
                int((_entry.get("lane_meta") or {}).get("lane_queries") or 0) if _explore else 0,
                -int(bool(((_entry.get("spec") or _entry) or {}).get("_broad_force_keep"))),
                -_winner_lane_score(_entry.get("lane_meta") or {}),
                -float(_entry.get("rank_score") or 0.0),
                -float(_entry.get("supply_score") or 0.0),
                -float(_entry.get("yield_score") or 0.0),
                -float(_entry.get("base_score") or 0.0),
            ),
        )
        if _explore and _sorted:
            _offset = cycle_id % len(_sorted)
            _sorted = _sorted[_offset:] + _sorted[:_offset]
        return _sorted

    def _take_entries(_entries: List[Dict[str, Any]], _limit: int) -> Tuple[List[Dict[str, Any]], int]:
        if _limit <= 0 or not _entries:
            return [], 0
        _selected, _fresh = _select_query_slot_efficient_entries(
            list(_entries or []),
            limit=_limit,
            recent_players=_recent_players,
            recent_products=_recent_products,
        )
        return _selected, _fresh

    _selected: List[Dict[str, Any]] = []
    _fresh_total = 0

    _winner_sorted = _sorted_bucket(_proving_profiles)
    _active_sorted = _sorted_bucket(_promising_profiles)
    _explore_sorted = _sorted_bucket(_explore_profiles, _explore=True)

    _winner_taken, _fr_winner = _take_entries(_winner_sorted, _winner_target)
    _selected.extend(_winner_taken)
    _fresh_total += _fr_winner

    _active_pool = [_e for _e in _active_sorted if (_e.get("spec") or _e) not in _selected]
    _active_taken, _fr_active = _take_entries(_active_pool, _active_target)
    _selected.extend(_active_taken)
    _fresh_total += _fr_active

    # ── EXPLORE POOL: enforce base-intent cap so common queries don't dominate ──
    _live_floor_eligible = [
        _e for _e in _profiles_all
        if _has_collector_heat_live_floor({**dict(_e.get("lane_meta") or {}), **dict(_e.get("spec") or _e)})
    ]
    _live_floor_already_selected = [
        _e for _e in _live_floor_eligible
        if (_e.get("spec") or _e) in _selected
    ]
    _live_floor_pool = [
        _e for _e in _sorted_bucket(_live_floor_eligible)
        if (_e.get("spec") or _e) not in _selected
    ]
    _live_floor_quota = max(
        0,
        min(4 - len(_live_floor_already_selected), _max_total - len(_selected)),
    )
    _live_floor_taken, _fr_live_floor = _take_entries(_live_floor_pool, _live_floor_quota)
    _selected.extend(_live_floor_taken)
    _fresh_total += _fr_live_floor
    _live_floor_selected = list(_live_floor_already_selected) + list(_live_floor_taken)
    _live_floor_lane_names = [
        str(((_entry.get("lane_meta") or {}).get("lane_label")) or _lane_metric_label(_entry.get("spec") or _entry) or "")[:64]
        for _entry in _live_floor_selected[:4]
    ]
    _live_floor_replaced_explore = min(len(_live_floor_taken), _explore_target)
    print(
        f"[COLLECTOR_HEAT_LIVE_BUDGET] eligible={len(_live_floor_eligible)} "
        f"selected={len(_live_floor_selected)} "
        f"replaced_explore={_live_floor_replaced_explore} "
        f"lane_names={_live_floor_lane_names}"
    )

    _explore_pool_raw = [_e for _e in _explore_sorted if (_e.get("spec") or _e) not in _selected]
    _explore_pool = []
    _base_intent_dropped_from_explore = 0
    for _ep in _explore_pool_raw:
        _ep_spec = _ep.get("spec") or _ep
        _ep_is_base = bool(_ep_spec.get("_cm_containment_target")) or bool(_query_lane_quality_profile(_ep_spec).get("weak_explore"))
        if _ep_is_base and _base_intent_in_explore >= _base_intent_explore_cap:
            _base_intent_dropped_from_explore += 1
            print(
                f"[QUERY_PREMIUM_DROP] player={str(_ep_spec.get('player_name') or '')[:24]} "
                f"query={str(_ep_spec.get('query') or '')[:60]} "
                f"bucket={_query_contract_bucket(_ep_spec)} reason=explore_budget_cap "
                f"reasons={list((_query_lane_quality_profile(_ep_spec) or {}).get('drop_reasons') or [])}"
            )
            continue
        if _ep_is_base:
            _base_intent_in_explore += 1
        _explore_pool.append(_ep)
    _explore_target_after_live_floor = max(0, _explore_target - _live_floor_replaced_explore)
    _explore_taken, _fr_explore = _take_entries(_explore_pool, _explore_target_after_live_floor)
    _selected.extend(_explore_taken)
    _fresh_total += _fr_explore
    if _base_intent_dropped_from_explore > 0:
        print(f"[SCAN_BUDGET_EXPLORE] base_intent_dropped={_base_intent_dropped_from_explore} cap={_base_intent_explore_cap}")

    _fr_back = 0
    if len(_selected) < _max_total:
        _backfill_pool_all = [
            _e for _e in _sorted_bucket(_profiles_all)
            if (_e.get("spec") or _e) not in _selected
        ]
        _backfill_pool = [
            _e for _e in _backfill_pool_all
            if not bool(_query_lane_quality_profile(_e.get("spec") or _e).get("weak_explore"))
        ]
        _backfill_taken, _fr_back = _take_entries(_backfill_pool, _max_total - len(_selected))
        _selected.extend(_backfill_taken)
        _fresh_total += _fr_back

    _proven_specs = list(_winner_taken[:_winner_target])
    _promising_specs = list(_active_taken[:_active_target])
    _explore_specs = list(_explore_taken[:_explore_target])
    _proven_target = _winner_target
    _promising_target = _active_target
    _explore_target = _explore_target
    _fresh_proven = _fr_winner
    _fresh_promising = _fr_active
    _fresh_explore = _fr_explore
    _fresh_backfill = _fr_back if len(_selected) > len(_proven_specs) + len(_promising_specs) + len(_explore_specs) else 0
    _fresh_fallback = 0
    _fallback_count = 0

    print(
        f"[COHORT_ALLOC] winners={len(_winner_taken)} active={len(_active_taken)} explore={len(_explore_taken)}"
    )
    print(
        f"[PREMIUM_DENSITY] winners_target={_winner_target} active_target={_active_target} "
        f"explore_target={_explore_target} winners_taken={len(_winner_taken)} "
        f"active_taken={len(_active_taken)} explore_taken={len(_explore_taken)} "
        f"total_cohort={len(_selected)} cooled_skipped={_cooled_skip_count}"
    )

    cohort = _selected[:_max_total]
    _sport_mix: Dict[str, int] = {}
    _diag_by_sport: Dict[str, Any] = {}
    for _spec in cohort:
        _sp = str(_spec.get("sport") or "").upper() or "?"
        _sport_mix[_sp] = int(_sport_mix.get(_sp, 0) or 0) + 1
        _diag_by_sport.setdefault(_sp, {"selected": 0})
        _diag_by_sport[_sp]["selected"] = int(_diag_by_sport[_sp].get("selected", 0) or 0) + 1

    _lane_yield_top = [
        (
            str((_entry.get("lane_meta") or {}).get("lane_label") or ""),
            round(float(_entry.get("yield_score") or 0.0), 1),
            round(float(_entry.get("supply_score") or 0.0), 1),
            str(_entry.get("bucket") or ""),
            int(((_entry.get("lane_meta") or {}).get("lane_queries")) or 0),
            int(((_entry.get("lane_meta") or {}).get("lane_visible_hits")) or 0),
            int(((_entry.get("lane_meta") or {}).get("lane_sniper_hits")) or 0),
        )
        for _entry in sorted(_profiles, key=lambda _entry: (-float(_entry.get("supply_score") or 0.0), -float(_entry.get("yield_score") or 0.0), -float(_entry.get("rank_score") or 0.0)))[:8]
    ]
    print(f"[LANE_YIELD] top={_lane_yield_top}")
    _selected_premium_queries = sum(1 for _spec in cohort if _spec_is_premium_intent(_spec))
    _selected_weak_queries = sum(1 for _spec in cohort if _spec_is_weak_exploration_query(_spec))
    print(
        f"[QUERY_BUDGET_SUMMARY] total_selected={len(cohort)} premium_selected={_selected_premium_queries} "
        f"weak_selected={_selected_weak_queries} winners={len(_winner_taken)}/{_winner_target} "
        f"active={len(_active_taken)}/{_active_target} explore={len(_explore_taken)}/{_explore_target}"
    )
    print(
        f"[LANE_QUALITY_SUMMARY] selected_premium={_selected_premium_queries} "
        f"selected_weak={_selected_weak_queries} premium_pool={len(_premium_specs) + len(_fallback_premium_intent)} "
        f"explore_pool={len(_fallback_base_intent)}"
    )
    print(
        f"[LANE_BUDGET] winners={len(_winner_taken)}/{_winner_target} "
        f"active={len(_active_taken)}/{_active_target} "
        f"explore={len(_explore_taken)}/{_explore_target}"
    )
    _protected_core_target = int(globals().get("PROTECTED_CORE_LANES", 8) or 8)
    _probe_cap = int(globals().get("MAX_PROBE_LANES", 4) or 4)
    _protected_profiles = [
        _profile
        for _profile in list(_profiles or [])
        if str(_runtime_bucket_for_spec(_profile.get("spec") or {}, _profile.get("lane_meta") or {})) == "protected_core"
    ]
    _protected_profiles = sorted(_protected_profiles, key=_protected_core_profile_sort_key)
    _protected_core_keys = {
        str(((_profile.get("lane_meta") or {}).get("lane_key")) or _lane_metric_key(_profile.get("spec") or {})).strip()
        for _profile in _protected_profiles[:max(0, _protected_core_target)]
        if str(((_profile.get("lane_meta") or {}).get("lane_key")) or _lane_metric_key(_profile.get("spec") or {})).strip()
    }
    _probe_selected = 0
    _protected_core_selected = 0
    for _spec in cohort:
        _lane_key = str(_lane_metric_key(_spec) or _live_fetch_spec_key(_spec)).strip()
        _bucket = "protected_core" if _lane_key in _protected_core_keys else _runtime_bucket_for_spec(_spec)
        _spec["_runtime_lane_bucket"] = _bucket
        if _bucket == "protected_core":
            _protected_core_selected += 1
        else:
            _probe_selected += 1
    print(
        f"[CORE_PROBE_BUDGET] protected_core_target={_protected_core_target} "
        f"protected_core_selected={_protected_core_selected} "
        f"probe_cap={_probe_cap} probe_selected={_probe_selected}"
    )
    # Per-lane supply score diagnostics (top 5)
    _supply_top = sorted(_profiles, key=lambda _e: -float(_e.get("supply_score") or 0.0))[:5]
    for _se in _supply_top:
        _sm = _se.get("lane_meta") or {}
        print(
            f"[LANE_SUPPLY_SCORE] lane={str(_sm.get('lane_label') or _sm.get('lane_key') or '')[:40]} "
            f"score={round(float(_se.get('supply_score') or 0.0), 1)} "
            f"tier={_lane_meta_product_tier(_sm)}"
        )

    diags = {
        "core": len(_proven_specs),
        "rotating_pool": len(_promising_profiles) + len(_explore_profiles),
        "rotating_kept": len(_promising_specs) + len(_explore_specs),
        "total": len(cohort),
        "cycle_id": cycle_id,
        "slice_idx": cycle_id % max(1, len(_explore_profiles)) if _explore_profiles else 0,
        "n_slices": max(1, len(_explore_profiles)),
        "cross_sport": bool(cross_sport),
        "by_sport": _diag_by_sport,
        "sport_mix": _sport_mix,
        "fresh_injected": int(_fresh_total),
        "repeated_players": sum(1 for _spec in cohort if _spec_diversity_keys(_spec)[0] in _recent_players),
        "repeated_products": sum(1 for _spec in cohort if _spec_diversity_keys(_spec)[1] in _recent_products),
        "lane_budget": {
            "winners": len(_winner_taken),
            "active": len(_active_taken),
            "explore": len(_explore_taken),
            "backfill": _fallback_count,
        },
        "lane_budget_targets": {
            "winners": _winner_target,
            "active": _active_target,
            "explore": _explore_target,
        },
        "protected_core_target": _protected_core_target,
        "protected_core_selected": _protected_core_selected,
        "probe_cap": _probe_cap,
        "probe_selected": _probe_selected,
        "lane_yield_top": _lane_yield_top,
        "elite_scanned": len(specs),
        "total_scanned": _incoming_total,
        "blocked_non_elite": _blocked_non_elite,
        "soft_premium_lanes": _soft_premium_lanes,
    }
    return cohort, diags


_QUALITY_HARD_MIN        = 20   # absolute floor — rows below this are always rejected
# [QUALITY_GATE_RECALIBRATION] Apr 2026: ACTIONABLE_MIN 45→35, REVIEW_MIN 28→22.
# Diag showed 24 rows dying at quality_reject — the second-biggest cliff after
# time_filter. Old thresholds were set before SYNTHETIC_MV_BLOCK / DISPLAY_
# PRICE_FLOOR / HIDE_PASS_OVERPRICED existed; those downstream gates now
# catch the garbage that this gate was conservatively over-rejecting.
# HARD_MIN=20 remains as the absolute trust floor.
_QUALITY_ACTIONABLE_MIN  = 35   # actionable rows must reach this (was 45)
_QUALITY_REVIEW_MIN      = 22   # review-only rows must reach this (was 28)
_QUALITY_THIN_FLOOR      = 18   # relaxed floor when inventory is thin (< 4 quality rows total)
_QUALITY_ROWS_THRESHOLD  = 4    # "enough inventory" — if >= this many rows reach 55+, filter strictly

_STRONG_PRODUCT_TOKENS = {
    "national treasures", "flawless", "immaculate", "one of one", "1/1",
    "prizm", "optic", "select", "mosaic", "chronicles",
    "topps chrome", "bowman chrome", "bowman draft",
    "contenders", "downtown", "kaboom", "status",
    "absolute", "certified", "spectra", "luminance",
}
_NOISY_TOKENS = {
    " lot ", " lots ", " bundle ", " break ", " repack ", " case break ",
    " box break ", "mystery", " and more", " rc lot", " card lot",
}

# ---------------------------------------------------------------------------
# Whatnot heat scoring — commercial appeal / resellability priors
# ---------------------------------------------------------------------------

# Built lazily from _PLAYER_MASTER on first call
_PLAYER_HEAT_TIER_CACHE: Dict[str, int] = {}


def _player_heat_tier(player_name: str) -> int:
    """Return demand tier (1=elite, 2=strong, 3=good, 0=untracked) from _PLAYER_MASTER."""
    global _PLAYER_HEAT_TIER_CACHE
    if not _PLAYER_HEAT_TIER_CACHE:
        for _p in _PLAYER_MASTER:
            _n = str(_p.get("name") or "").strip().lower()
            if _n:
                _PLAYER_HEAT_TIER_CACHE[_n] = int(_p.get("tier") or 3)
    _ln = str(player_name or "").strip().lower()
    if not _ln:
        return 0
    if _ln in _PLAYER_HEAT_TIER_CACHE:
        return _PLAYER_HEAT_TIER_CACHE[_ln]
    for _tracked, _tier in _PLAYER_HEAT_TIER_CACHE.items():
        # substring match — "mahomes" in "patrick mahomes" etc.
        if _tracked in _ln or _ln in _tracked:
            return _tier
    return 0


_AUTO_TOKENS: frozenset = frozenset({
    "auto ", "autograph", " /a ", "auto#", "auto/", "auto:",
    " auto\n", " rpa ", " rpa\n", " pa ", "patch auto",
})
_SSP_TOKENS: frozenset = frozenset({
    "kaboom", "downtown", "color blast", "stained glass", "manga",
    "prize", "nebula", "genesis", "superfractor", "all aces",
    "field level", "premier level", "field of vision", "cracked ice",
    "gold vinyl", "logoman", "laundry tag",
})
_PREMIUM_PARALLEL_TOKENS: frozenset = frozenset({
    "refractor", "chrome", "holo", "prizm", "silver",
    "optic", "cracked ice",
})
_COLOR_PARALLEL_TOKENS: frozenset = frozenset({
    "blue", "gold", "red", "orange", "green", "pink", "purple",
    "aqua", "neon", "arctic", "camo", "wave", "reactive",
    "zebra", "tiger", "mojo",
})
_ULTRA_PREMIUM_PRODUCTS: frozenset = frozenset({
    "national treasures", "flawless", "immaculate", "spectra",
    "panini black", "topps black", "definitive",
})
_STRONG_LIQUID_PRODUCTS: frozenset = frozenset({
    "prizm", "optic", "select", "mosaic", "chronicles",
    "topps chrome", "bowman chrome", "bowman draft", "contenders",
    "absolute", "certified", "status",
})


def _whatnot_heat_score(row: Dict[str, Any]) -> float:
    """
    0–100 Whatnot commercial appeal score.
    Higher = more likely to generate buyer excitement and quick resale.
    Uses only parsed title signals and existing row fields — no external calls.
    """
    _r = row or {}
    _title = str(_r.get("source_title") or _r.get("title") or "").strip().lower()
    _player = str(_r.get("player_name") or _r.get("target_player_name") or "").strip().lower()
    _product = str(_r.get("product_family") or _r.get("target_product_family") or "").strip().lower()
    _parallel_bucket = str(_r.get("parallel_bucket") or _r.get("parallel_name") or "").strip().lower()
    _rare_parallel = str(_r.get("rare_parallel") or "").strip().lower()
    _serial_bucket = str(_r.get("serial_bucket") or "").strip().lower()
    _serial_den_raw = str(_r.get("serial_denominator") or "").strip()
    _subset_name = str(_r.get("subset_name") or "").strip().lower()
    _padded = f" {_title} "

    _score = 28.0  # neutral baseline

    # ── Auto / autograph — highest-liquidity category on Whatnot ──────────────
    _is_auto = any(_tok in _padded for _tok in _AUTO_TOKENS)
    if _is_auto and "redemption" not in _title:
        _score += 22.0
    elif _is_auto:
        _score += 8.0   # redemption autos — less liquid

    # ── SSP / case-hit visual appeal ──────────────────────────────────────────
    if any(_tok in _title for _tok in _SSP_TOKENS) or any(_tok in _subset_name for _tok in _SSP_TOKENS):
        _score += 18.0

    # ── Numbered card ─────────────────────────────────────────────────────────
    try:
        _den = int(_serial_den_raw) if _serial_den_raw else 0
    except (ValueError, TypeError):
        _den = 0
    if _serial_bucket == "1_of_1" or "/1 " in _padded or " 1/1" in _padded:
        _score += 16.0
    elif _den > 0 and _den <= 10:
        _score += 14.0
    elif _den > 0 and _den <= 25:
        _score += 12.0
    elif _den > 0 and _den <= 99:
        _score += 10.0
    elif _den > 0 and _den <= 299:
        _score += 7.0
    elif any(f"/{n} " in _padded for n in ("10", "25", "49", "50", "75", "99")):
        _score += 9.0   # serial in title but unparsed

    # ── Premium parallel — refractor / chrome / holo / prizm ─────────────────
    _has_premium_par = (
        any(_tok in _parallel_bucket for _tok in _PREMIUM_PARALLEL_TOKENS)
        or any(_tok in _title for _tok in _PREMIUM_PARALLEL_TOKENS)
    )
    if _has_premium_par:
        _score += 12.0

    # ── Color parallel ────────────────────────────────────────────────────────
    _has_color_par = (
        any(_tok in _parallel_bucket for _tok in _COLOR_PARALLEL_TOKENS)
        or any(_tok in _rare_parallel for _tok in _COLOR_PARALLEL_TOKENS)
    )
    if _has_color_par:
        _score += 8.0
    elif any(_tok in _title for _tok in _COLOR_PARALLEL_TOKENS):
        _score += 3.0   # weaker title-only signal

    # ── Rookie / RC ───────────────────────────────────────────────────────────
    if any(_tok in _padded for _tok in (" rookie ", " rc ", " /rc ", "(rc)")):
        _score += 8.0

    # ── Product lines ─────────────────────────────────────────────────────────
    if any(_tok in _product for _tok in _ULTRA_PREMIUM_PRODUCTS) or \
       any(_tok in _title for _tok in _ULTRA_PREMIUM_PRODUCTS):
        _score += 10.0
    elif any(_tok in _product for _tok in _STRONG_LIQUID_PRODUCTS) or \
         any(_tok in _title for _tok in _STRONG_LIQUID_PRODUCTS):
        _score += 6.0

    # ── Player demand tier ────────────────────────────────────────────────────
    # tier 1 = instant sellers (Mahomes, Skenes, Wemby, Ohtani, Caleb, JD…)
    # tier 2 = fast movers / breakout-young assets (Brian Thomas Jr, CJ Stroud,
    #          Drake Maye, Ant Edwards, James Wood, Bobby Witt Jr, etc.)
    # tier 3 = steady mainstream
    # tier 0 = untracked
    # Bumped from {1:12,2:8,3:4} → {1:14,2:12,3:6}. The biggest jump is tier 2
    # so breakout-young players whose card carries any premium structure clear
    # the 50/65 thresholds the rest of the system uses.
    _tier = _player_heat_tier(_player)
    _score += {1: 14.0, 2: 12.0, 3: 6.0}.get(_tier, 0.0)

    # ── PSA 10 on an already-hot card ─────────────────────────────────────────
    _grade_ctx = _extract_grade_context(_title)
    if _grade_ctx.get("grade_company") == "PSA" and _grade_ctx.get("grade_value") == "10":
        if _score >= 40.0:   # only net positive when the underlying card has appeal
            _score += 6.0

    # ── Negative signals ─────────────────────────────────────────────────────
    if any(_tok in _padded for _tok in _NOISY_TOKENS):
        _score -= 22.0

    # Plain base with nothing notable — penalise
    _has_any_hook = (
        _is_auto or bool(_serial_den_raw) or bool(_subset_name)
        or _has_premium_par or _has_color_par
        or any(_tok in _title for _tok in ("rookie", " rc ", "refractor", "prizm", "chrome", "auto"))
    )
    if not _has_any_hook:
        _score -= 14.0

    # Unidentified product (no family and no known product token in title) → weak appeal
    if not _product and not any(_tok in _title for _tok in _STRONG_LIQUID_PRODUCTS | _ULTRA_PREMIUM_PRODUCTS):
        _score -= 6.0

    # Very short / low-identity title
    if len(_title) < 18:
        _score -= 8.0

    return float(max(0.0, min(100.0, _score)))


