    " psa ", " bgs ", " sgc ", " cgc ", " gma ", " hga ",
    "gem mt", "gem-mt", "mint 10", "mint 9",
    "psa 10", "psa 9", "psa 8", "psa 7",
    "bgs 9.5", "bgs 10", "sgc 10",
    " graded ", " slabbed ", " slab ",
