def _is_clone_risk_presentation_case(row: Dict[str, Any]) -> bool:
    try:
        if not isinstance(row, dict):
            return False
        _clone_block = _surface_truthy_flag(row.get("single_comp_clone_block"))
        _trusted_exact = int(row.get("trusted_exact_comp_count") or 0)
        _current = row.get("current_price") or row.get("current") or row.get("current_bid") or row.get("price")
        _true_mv = row.get("true_mv") or row.get("true_market_value") or row.get("market_value_true")
        _source = str(
            row.get("valuation_source")
            or row.get("mv_source")
            or row.get("market_value_source")
            or row.get("source")
            or ""
        ).strip().lower()

        if _clone_block:
            return True

        if _trusted_exact == 1 and _current is not None and _true_mv is not None:
            try:
                _delta = abs(float(_true_mv) - float(_current)) / max(float(_current), 1.0)
                if _delta <= 0.03:
                    # [SYNTHETIC_COUNT_GUARD_PRESENTATION] — symmetric guard.
                    # Same fix as in _is_single_comp_clone_surface_case: when
                    # trusted_exact_comp_count = 1 but the row carries no
                    # priced comp evidence, the count is synthetic (stamped
                    # by a survivor function in this file) and the mv ≈
                    # current pattern is fallback-MV-from-current artifact,
                    # not real contamination. Suppress the presentation-
                    # risk-block flag so the UI doesn't paint the misleading
                    # "Single-comp or fallback-based pricing" subtitle.
                    _has_real_comp_evidence = False
                    for _ev_key in (
                        "renderable_evidence_rows",
                        "evidence_rows",
                        "trusted_exact_comps",
                        "comp_evidence",
                        "review_evidence_rows",
                    ):
                        _ev_val = row.get(_ev_key)
                        if not isinstance(_ev_val, list):
                            continue
                        for _c in _ev_val:
                            if not isinstance(_c, dict):
                                continue
                            try:
                                _c_price_raw = (
                                    _c.get("price")
                                    or _c.get("sold_price")
                                    or _c.get("sale_price")
                                )
                                _c_price = float(_c_price_raw or 0.0)
                            except (TypeError, ValueError):
                                _c_price = 0.0
                            if _c_price > 0:
                                _has_real_comp_evidence = True
                                break
                        if _has_real_comp_evidence:
                            break
                    if not _has_real_comp_evidence:
                        # [SYNTHETIC_MV_SCRUB] — comprehensive scrub of every
                        # MV-carrying field the UI / view-model builders read
                        # from. The earlier minimal scrub only covered five
                        # row-dict keys, but the watchlist card UI also reads
                        # `view.value_numeric`, `view.market_value_display`,
                        # `view.mv_valid`, and `row.mv_valid` — so contaminated
                        # MV survived through the view stamp despite the row
                        # scrub. This expanded list nukes every MV path AND
                        # sets `mv_valid=False` so the view-model treats the
                        # row as "no MV" downstream.
                        try:
                            _pre_mv = row.get("true_mv") or row.get("true_market_value") or row.get("market_value_true")
                            _MV_NULL_KEYS = (
                                "true_mv",
                                "true_market_value",
                                "market_value_true",
                                "mv_value",
                                "market_value",
                                "value_numeric",
                                "market_value_display",
                                "_market_value_display",
                                "mv_display_value",
                                "mv_resolved_value",
                                "review_estimate",
                                "review_estimate_value",
                                "review_estimate_display",
                            )
                            for _mv_key in _MV_NULL_KEYS:
                                if _mv_key in row:
                                    row[_mv_key] = None
                            _MV_FALSE_KEYS = (
                                "mv_valid",
                                "mv_resolved",
                            )
                            for _mv_flag in _MV_FALSE_KEYS:
                                if _mv_flag in row:
                                    row[_mv_flag] = False
                            row["_synthetic_trusted_exact"] = True
                            row["_synthetic_no_mv"] = True
                            row["mv_blocked_reason_display"] = "Unconfirmed"
                            print(
                                f"[SYNTHETIC_MV_SCRUB] "
                                f"title={str(row.get('title') or row.get('source_title') or '')[:140]} "
                                f"prior_mv={_pre_mv} "
                                f"current={_current} "
                                f"trusted_exact={_trusted_exact} "
                                f"reason=count_1_mv_echoes_current_no_real_evidence "
                                f"keys_nulled={len(_MV_NULL_KEYS)} flags_falsed={len(_MV_FALSE_KEYS)}"
                            )
                        except Exception as _mv_scrub_exc:
                            print(f"[SYNTHETIC_MV_SCRUB] error_type={type(_mv_scrub_exc).__name__} msg={str(_mv_scrub_exc)[:120]}")
                        try:
                            print(
                                f"[SYNTHETIC_COUNT_GUARD_PRESENTATION] "
                                f"title={str(row.get('title') or row.get('source_title') or '')[:140]} "
                                f"trusted_exact={_trusted_exact} "
                                f"reason=no_priced_comp_evidence_on_row "
                                f"action=skip_presentation_risk_block"
                            )
                        except Exception:
                            pass
                        return False
                    return True
            except Exception:
                pass

        if "price_anchor_fallback" in _source:
            return True

        return False
    except Exception:
        return False


def _stamp_presentation_risk_block(row: Dict[str, Any]) -> bool:
    if not isinstance(row, dict) or not _is_clone_risk_presentation_case(row):
        return False
    row["_presentation_risk_block"] = True
    row["_presentation_bucket"] = "monitor"
    row["presentation_bucket"] = "monitor"
    row["_presentation_headline"] = "Unconfirmed valuation"
    row["_presentation_subhead"] = "Single-comp or fallback-based pricing"
    row["_presentation_badges_override"] = [
        "MONITOR",
        "UNCONFIRMED VALUE",
        "DO NOT CHASE",
    ]
    row["_presentation_cta_mode"] = "monitor_only"
    if not _surface_truthy_flag(row.get("_presentation_risk_logged")):
        print(
            f"[PRESENTATION_RISK_BLOCK] title={str((row or {}).get('title') or '')[:140]} "
            f"trusted_exact={row.get('trusted_exact_comp_count')} "
            f"true_mv={row.get('true_mv') or row.get('true_market_value') or row.get('market_value_true')} "
            f"current={row.get('current_price') or row.get('current')} "
            f"single_comp_clone_block={row.get('single_comp_clone_block')}"
        )
        row["_presentation_risk_logged"] = True
    return True


def _endgame_sniper_gate(row: Dict[str, Any], *, emit_log: bool = False) -> Dict[str, Any]:
    _r = row or {}
    _tier = str(_r.get("endgame_tier") or "").strip().lower()
    try:
        _comps = int(_r.get("comp_count") or _r.get("mv_comp_count") or _r.get("comps") or 0)
    except (TypeError, ValueError):
        _comps = 0
    _conf = _normalize_mv_confidence_label(
        _r.get("mv_confidence_strict")
        or _r.get("valuation_confidence")
        or _r.get("confidence")
        or _r.get("mv_confidence")
        or ""
    )
    _mv_source = str(_r.get("mv_source") or _r.get("market_value_source") or "").strip().lower()
    _confidence_gate = _premium_confidence_gate(_r)
    try:
        _edge_dollars = float(
            _r.get("edge_dollars")
            or (_r.get("action_summary") or {}).get("expected_profit")
            or 0.0
        )
    except (TypeError, ValueError):
        _edge_dollars = 0.0
    try:
        _edge_pct = float(_r.get("edge_pct") or _r.get("edge_percent") or 0.0)
    except (TypeError, ValueError):
        _edge_pct = 0.0
    _commodity_suppressed = bool(_r.get("commodity_suppressed"))
    _title = str(_r.get("source_title") or _r.get("title") or "")
    _item = str(_r.get("item_id") or _r.get("source_item_id") or _r.get("itemId") or "")[:24] or "?"
    _window_contract = _resolve_window_contract(_r, caller="sniper_eligibility")
    _secs = _safe_float(_window_contract.get("remaining_seconds"))
    _window_seconds = _safe_float(_window_contract.get("threshold_seconds")) or _safe_float(_window_contract.get("window_seconds"))
    _window_source = str(_window_contract.get("source") or _window_contract.get("_source") or "window_contract")
    _legacy_window_check = bool(_secs is not None and 5.0 <= _secs <= 300.0)
    _auction_window_ok = _within_sniper_window(
        _secs,
        window_seconds=_window_seconds,
    )
    _r["_within_scan_window"] = bool(_auction_window_ok)
    _r["within_window"] = bool(_auction_window_ok)
    _r["_within_window"] = bool(_auction_window_ok)
    _r["_window_source"] = _window_source
    if _window_seconds is not None:
        _r["_window_threshold_seconds"] = _window_seconds
    if _secs is not None:
        _r["_window_remaining_seconds"] = _secs
        _r["remaining_seconds"] = _secs
        _r["seconds_remaining"] = _secs
    print(
        f"[STRICT_WINDOW_CONTRACT] title={_title[:120]} item={_item} "
        f"remaining_seconds={round(float(_secs), 2) if _secs is not None else 'na'} "
        f"window_seconds={round(float(_window_seconds), 2) if _window_seconds is not None else 'na'} "
        f"in_window={1 if _auction_window_ok else 0}"
    )
    _nonstandard, _variant_reason = _is_nonstandard_subset_variant(_title)
    _target_bid_ready = bool(_r.get("bid_ceiling_ready")) or bool(_r.get("target_bid_ready")) or _row_target_bid_ready(_r)
    try:
        _target_bid = float(_r.get("bid_ceiling_value") or _r.get("target_bid_price") or _r.get("target_bid") or 0.0)
    except (TypeError, ValueError):
        _target_bid = 0.0
    try:
        _price = float(_r.get("current_price") or _r.get("current_bid") or _r.get("price") or 0.0)
    except (TypeError, ValueError):
        _price = 0.0
    _bid_gap_pct = ((_target_bid - _price) / _target_bid * 100.0) if (_target_bid > 0 and _price > 0) else 999.0
    _premium_family = any(
        _token in str(_r.get("title") or _r.get("source_title") or _r.get("lane_product") or _r.get("product_family") or "").lower()
        for _token in ("national treasures", "immaculate", "flawless", "spectra", "prizm", "select", "optic", "topps chrome", "bowman chrome")
    )
    _displayable = str(_r.get("execution_admission_bucket") or _r.get("commercial_visibility") or "").strip().lower() in {"sniper", "watchlist"}
    _force_true_actionable = _decision_true_target_bid_actionable(_r)
    _truth = str(_r.get("valuation_truth_tier") or _r.get("_valuation_truth_tier") or "").strip().upper()
    try:
        _trusted_exact = int(_r.get("trusted_exact_comp_count") or _r.get("exact_comp_count") or 0)
    except (TypeError, ValueError):
        _trusted_exact = 0
    _single_comp_clone_block = _stamp_single_comp_clone_hero_block(_r)
    _final_review_keep = bool(_confidence_gate.get("review_keep_visible"))
    _execution_final = str(_confidence_gate.get("review_execution_final") or "PASS").strip().upper() or "PASS"
    try:
        _legacy_comp_count = int(_r.get("usable_comp_count", _r.get("comp_count", 0)) or 0)
    except (TypeError, ValueError):
        _legacy_comp_count = 0
    _legacy_allow_sniper = bool(_confidence_gate.get("allow_sniper"))
    if _target_bid > 0 and not _target_bid_ready and _force_true_actionable:
        _target_bid_ready = True
        _r["target_bid_ready"] = True
        _r["bid_ceiling_ready"] = True
        print(
            f"[TARGET_BID_FORCE_READY] title={str(_r.get('title') or _r.get('source_title') or '')[:120]} "
            f"target_bid={round(_target_bid, 2)}"
        )
    _edge_override = _decision_premium_edge_override(_r, _edge_dollars, _edge_pct)
    if _edge_override:
        print(
            f"[EDGE_OVERRIDE_PREMIUM] title={str(_r.get('title') or _r.get('source_title') or '')[:120]} "
            f"edge_dollars={round(_edge_dollars, 2)} edge_pct={round(_edge_pct, 2)}"
        )
    if _legacy_window_check != _auction_window_ok:
        print(
            f"[SNIPER_GATE_LEGACY_BLOCK] title={_title[:120]} item={_item} "
            f"legacy_field=window_check legacy_value={1 if _legacy_window_check else 0} "
            f"canonical_in_window={1 if _auction_window_ok else 0} ignored=1"
        )
    if _auction_window_ok and _trusted_exact > 0 and _legacy_comp_count <= 0:
        print(
            f"[SNIPER_GATE_LEGACY_BLOCK] title={_title[:120]} item={_item} "
            f"legacy_field=comp_count legacy_value={_legacy_comp_count} "
            f"canonical_in_window={1 if _auction_window_ok else 0} ignored=1"
        )

    _sniper_candidate = bool(
        _tier == "endgame"
        and _auction_window_ok
        and _comps >= 3
        and _conf in {"MEDIUM", "HIGH"}
        and _mv_source not in {"price_anchor_fallback"}
        and (_edge_dollars >= 75.0 or _edge_pct >= 18.0)
        and not _commodity_suppressed
        and not _nonstandard
        and _target_bid_ready
        and bool(_confidence_gate.get("allow_sniper"))
        and not _single_comp_clone_block
    )
    if (
        not _sniper_candidate
        and not _single_comp_clone_block
        and _force_true_actionable
        and _auction_window_ok
        and not _commodity_suppressed
        and not _nonstandard
        and (_edge_dollars > 0.0 or _edge_pct > 0.0 or _edge_override)
    ):
        _sniper_candidate = True
        print(
            f"[SNIPER_PROMOTE_TRUE] title={str(_r.get('title') or _r.get('source_title') or '')[:120]} "
            f"edge_dollars={round(_edge_dollars, 2)} edge_pct={round(_edge_pct, 2)}"
        )
    if (
        not _sniper_candidate
        and not _single_comp_clone_block
        and _tier == "endgame"
        and _premium_family
        and _auction_window_ok
        and _displayable
        and _comps >= 2
        and _conf in {"MEDIUM", "HIGH"}
        and _edge_pct >= 25.0
        and _mv_source not in {"price_anchor_fallback"}
        and not _commodity_suppressed
        and not _nonstandard
        and _target_bid_ready
        and bool(_confidence_gate.get("allow_sniper"))
    ):
        _sniper_candidate = True
    _canonical_exact_backed_sniper = bool(
        _auction_window_ok
        and _truth == "TRUE"
        and _trusted_exact > 0
        and _final_review_keep
        and _execution_final in {"PREPARE", "EXECUTE_NOW"}
        and _target_bid_ready
        and not _commodity_suppressed
        and not _nonstandard
        and not _single_comp_clone_block
    )
    _sniper_reason = "legacy_gate_blocked"
    if _sniper_candidate:
        _sniper_reason = (
            "canonical_force_true_actionable"
            if _force_true_actionable and not (_tier == "endgame" and _legacy_allow_sniper)
            else "endgame_window_candidate"
        )
    elif _canonical_exact_backed_sniper:
        if not _legacy_allow_sniper:
            print(
                f"[SNIPER_GATE_LEGACY_BLOCK] title={_title[:120]} item={_item} "
                f"legacy_field=allow_sniper legacy_value={1 if _legacy_allow_sniper else 0} "
                f"canonical_in_window={1 if _auction_window_ok else 0} ignored=1"
            )
        _sniper_candidate = True
        _sniper_reason = "canonical_exact_backed_in_window"
    if _sniper_candidate:
        if _execution_final == "EXECUTE_NOW" or (_target_bid > 0 and _price > 0 and _bid_gap_pct <= 12.0 and bool(_r.get("is_actionable_bid"))):
            _execution_decision = "EXECUTE_NOW"
        else:
            _execution_decision = "PREPARE"
        _admission = "sniper"
    elif (
        _tier == "endgame"
        and _mv_source not in {"price_anchor_fallback"}
        and not _commodity_suppressed
        and not _nonstandard
        and _comps >= 2
        and (_edge_dollars >= 25.0 or _edge_pct >= 8.0)
        and bool(_confidence_gate.get("allow_watch"))
    ):
        _execution_decision = "WATCH"
        _admission = "watch"
        _sniper_reason = "endgame_watch_candidate"
    else:
        _execution_decision = "PASS"
        _admission = "drop"
        _sniper_reason = (
            "canonical_window_false"
            if not _auction_window_ok
            else "exact_backed_contract_not_met"
            if _truth == "TRUE" and _trusted_exact > 0
            else "insufficient_sniper_signal"
        )
    if _single_comp_clone_block and _sniper_candidate:
        _sniper_candidate = False
        _execution_decision = "WATCH"
        _admission = "watch"
        _sniper_reason = "single_comp_clone_no_edge"
    if _single_comp_clone_block:
        _log_hero_assert(_r)
    print(
        f"[SNIPER_GATE_CANONICAL] title={_title[:120]} item={_item} "
        f"remaining_seconds={round(float(_secs), 2) if _secs is not None else 'na'} "
        f"window_seconds={round(float(_window_seconds), 2) if _window_seconds is not None else 'na'} "
        f"in_window={1 if _auction_window_ok else 0} truth={_truth or 'NONE'} "
        f"trusted_exact={_trusted_exact} final_review_keep={1 if _final_review_keep else 0} "
        f"execution_final={_execution_final} eligible={1 if _sniper_candidate else 0}"
    )

    print(
        f"[SNIPER_ELIGIBILITY] title={str(_r.get('title') or _r.get('source_title') or '')[:120]} "
        f"comps={_comps} edge={round(_edge_pct, 2)} conf={_conf or 'NONE'} eligible={1 if _sniper_candidate else 0}"
    )
    print(
        f"[SNIPER_WINDOW_BIND] title={_title[:120]} item={_item} "
        f"window_source={_window_source[:48]} in_window={1 if _auction_window_ok else 0} "
        f"eligible={1 if _sniper_candidate else 0}"
    )
    if _admission in {"sniper", "watch"}:
        _surface = "sniper" if _admission == "sniper" else "watchlist"
        _surface_reason = (
            "endgame_sniper_execute_now"
            if _admission == "sniper" and _execution_decision == "EXECUTE_NOW"
            else _sniper_reason
            if _admission == "sniper"
            else "endgame_watch_candidate"
        )
        print(
            f"[SNIPER_SURFACE_FINAL] title={_title[:120]} item={_item} "
            f"surface={_surface} reason={_surface_reason}"
        )
    print(
        f"[SNIPER_GATE_FINAL] title={_title[:120]} item={_item} eligible={1 if _sniper_candidate else 0} "
        f"surface={'sniper' if _admission == 'sniper' else 'watchlist' if _admission == 'watch' else 'pass'} "
        f"reason={_sniper_reason}"
    )

    if emit_log and _tier == "endgame":
        print(
            f"[ENDGAME_SNIPER_GATE] item={str(_r.get('item_id') or _r.get('source_item_id') or '')[:24] or '?'} "
            f"tier={_tier} comps={_comps} conf={_conf or 'NONE'} edge_dollars={round(_edge_dollars, 2)} "
            f"decision={_admission}"
        )

    return {
        "sniper_candidate": _sniper_candidate,
        "execution_decision": _execution_decision,
        "admission_decision": _admission,
        "bid_gap_pct": round(_bid_gap_pct, 2) if _bid_gap_pct != 999.0 else None,
        "nonstandard_subset_variant": bool(_nonstandard),
        "variant_reason": _variant_reason,
    }


def _compute_execution_decision(row: Dict[str, Any]) -> Dict[str, Any]:
    """
    Compute execution decision tier, score, and urgency pressure for a board row.

    Decision tiers (exclusive, in priority order):
      EXECUTE_NOW — high-confidence edge, comps, bid ready, MV valid
      SNIPE       — edge + bid + <10 min remaining
      WATCH       — edge >= 10%, insufficient comps/confidence for action yet
      SKIP        — no meaningful edge

    execution_score (0–100) drives board sort order within each tier.
    execution_pressure (URGENT/HIGH/MEDIUM/LOW) reflects time-to-close urgency.
    """
    _r = row or {}
    try:
        _edge_pct = float(_r.get("edge_pct") or 0.0)
    except (TypeError, ValueError):
        _edge_pct = 0.0

    # Prefer strict confidence from _mv_strict_post_validate over legacy confidence
    _mv_conf_strict = str(_r.get("mv_confidence_strict") or "").strip().upper()
    _mv_conf_legacy = str(
        _r.get("mv_confidence") or _r.get("valuation_confidence") or _r.get("confidence") or ""
    ).strip().upper()
    # Normalise legacy values → HIGH/MEDIUM/LOW
    _legacy_map = {
        "RESOLVED": "HIGH", "STRONG": "HIGH", "STRONG_MARKET_VALUE": "HIGH",
        "USABLE": "MEDIUM", "MED": "MEDIUM",
        "ESTIMATE_ONLY": "LOW", "MANUAL_CONTEXT": "LOW", "UNKNOWN": "LOW",
        "EXCLUDED": "LOW", "LOW_CONFIDENCE": "LOW",
    }
    _mv_conf_legacy = _legacy_map.get(_mv_conf_legacy, _mv_conf_legacy)
    _mv_conf = _mv_conf_strict if _mv_conf_strict in {"HIGH", "MEDIUM", "LOW"} else _mv_conf_legacy
    if _mv_conf not in {"HIGH", "MEDIUM", "LOW"}:
        _mv_conf = "LOW"

    try:
        _comps = int(_r.get("comp_count") or _r.get("mv_comp_count") or 0)
    except (TypeError, ValueError):
        _comps = 0

    _secs = float(_row_remaining_seconds(_r) or float("inf"))
    _target_bid_ready = _row_target_bid_ready(_r)
    _exact_surface = _row_exact_surface_candidate(_r)
    _mv_source = str(_r.get("mv_source") or _r.get("market_value_source") or "").strip().lower()
    _fallback_lane = "fallback" in _mv_source
    _commercial_bucket = str(_r.get("commercial_bucket") or "WEAK").strip().upper()
    _commercially_suppressed = bool(_r.get("commercially_suppressed"))
    _commodity_suppressed = bool(_r.get("commodity_suppressed"))
    _premium_secondary_floor = _passes_non_endgame_watchlist_floor(_r)
    _watch_salvage = _is_watchlist_salvage_candidate(_r)
    _endgame_gate = _endgame_sniper_gate(_r)
    _confidence_gate = _premium_confidence_gate(_r)
    _mv_truth_decision = str(_confidence_gate.get("mv_truth_decision") or "visible")
    try:
        _edge_dollars = float(
            _r.get("edge_dollars")
            or (_r.get("action_summary") or {}).get("expected_profit")
            or max(0.0, float(_r.get("market_value_true") or _r.get("market_value") or _r.get("mv_value") or 0.0) - float(_r.get("current_price") or _r.get("current_bid") or 0.0))
        )
    except (TypeError, ValueError):
        _edge_dollars = 0.0

    _force_true_actionable = _decision_true_target_bid_actionable(_r)
    _edge_override = _decision_premium_edge_override(_r, _edge_dollars, _edge_pct)
    # ── Decision gate ───────────────────────────────────────────────────────────
    if _endgame_gate["sniper_candidate"]:
        _decision = str(_endgame_gate.get("execution_decision") or "PREPARE")
        _decision_reason = (
            "endgame_sniper_execute_now"
            if _decision == "EXECUTE_NOW"
            else "endgame_sniper_prepare"
        )
    elif bool(_confidence_gate.get("force_drop")):
        _decision = "PASS"
        _decision_reason = str(_confidence_gate.get("reason") or "premium_confidence_drop")
    elif (
        _exact_surface
        and _target_bid_ready
        and not _commercially_suppressed
        and not _commodity_suppressed  # commodity cards never reach EXECUTE_NOW
        and _edge_dollars >= 12.0
        and _commercial_bucket in {"ELITE", "STRONG"}
        and _comps >= 3
        and _mv_conf in {"HIGH", "MEDIUM"}
        and bool(_confidence_gate.get("allow_execute"))
    ):
        _decision = "EXECUTE_NOW"
        _decision_reason = "commercial_elite_actionable"
    elif (
        _exact_surface
        and _target_bid_ready
        and not _commercially_suppressed
        and not _commodity_suppressed  # commodity cards never reach PREPARE
        and _edge_dollars >= 8.0
        and _commercial_bucket in {"MID", "STRONG"}
        and _comps >= 2
        and _premium_secondary_floor
        and bool(_confidence_gate.get("allow_execute"))
    ):
        _decision = "PREPARE"
        _decision_reason = "commercial_prepare_candidate"
    elif bool(_confidence_gate.get("allow_watch")) and (_watch_salvage or str(_endgame_gate.get("admission_decision") or "") == "watch"):
        _decision = "WATCH"
        _decision_reason = (
            "endgame_watch_candidate"
            if str(_endgame_gate.get("admission_decision") or "") == "watch"
            else "watchlist_salvage_candidate"
        )
    elif _mv_truth_decision == "watch":
        _decision = "WATCH"
        _decision_reason = str(_confidence_gate.get("reason") or "structured_fallback_watch_only")
    elif str(_confidence_gate.get("decision") or "") == "watch_only" and _target_bid_ready and _edge_dollars >= 8.0 and _comps >= 2:
        _decision = "WATCH"
        _decision_reason = str(_confidence_gate.get("reason") or "premium_confidence_watch_only")
    elif _force_true_actionable and not bool(_confidence_gate.get("force_drop")):
        _decision = "PREPARE" if (_endgame_gate.get("sniper_candidate") or _edge_dollars > 0.0 or _edge_pct > 0.0 or _edge_override) else "WATCH"
        _decision_reason = "force_actionable_true_contract"
    elif bool(_review_contract.get("keep_visible")):
        _decision = "PREPARE" if str(_review_contract.get("bucket") or "") == "prepare" else "WATCH"
        _decision_reason = str(_review_contract.get("reason") or "review_contract_visible")
    else:
        _decision = "PASS"
        _decision_reason = (
            str(_review_contract.get("reason") or "")
            or (str(_confidence_gate.get("reason") or "commercial_quality_below_floor") if str(_confidence_gate.get("decision") or "") != "allow" else "commercial_quality_below_floor")
        )

    # ── Execution score (0–100) ─────────────────────────────────────────────────
    _conf_weight = {"HIGH": 1.0, "MEDIUM": 0.5, "LOW": 0.2}.get(_mv_conf, 0.2)
    _urgency_bonus = 20.0 if _secs < 300.0 else (10.0 if _secs < 900.0 else 0.0)
    _exec_score = (
        _edge_pct * 0.5
        + min(_comps, 20) * 0.2
        + _conf_weight * 20.0
        + _urgency_bonus
    )
    if _decision == "PREPARE":
        _exec_score += 6.0
    elif _decision == "WATCH":
        _exec_score += 3.0
    if _fallback_lane and _target_bid_ready:
        _exec_score += 4.0
    if _commercial_bucket == "ELITE":
        _exec_score += 10.0
    elif _commercial_bucket == "STRONG":
        _exec_score += 6.0
    elif _commercial_bucket == "WEAK":
        _exec_score -= 12.0
    if _commercially_suppressed:
        _exec_score -= 25.0
    elif _commodity_suppressed:
        _exec_score -= 20.0
    _exec_score = float(max(0.0, min(100.0, _exec_score)))

    # ── Urgency pressure label ──────────────────────────────────────────────────
    if _secs < 300.0:
        _pressure = "URGENT"
    elif _secs < 900.0:
        _pressure = "HIGH"
    elif _secs < 3600.0:
        _pressure = "MEDIUM"
    else:
        _pressure = "LOW"

    return {
        "execution_decision": _decision,
        "decision": _decision.replace("_", " "),
        "decision_reason": _decision_reason,
        "execution_score": round(_exec_score, 1),
        "execution_pressure": _pressure,
        "sniper_candidate": bool(_endgame_gate.get("sniper_candidate")),
        "endgame_sniper_admission": str(_endgame_gate.get("admission_decision") or ""),
        "endgame_bid_gap_pct": _endgame_gate.get("bid_gap_pct"),
    }


def _auction_quality_score(row: Dict[str, Any]) -> float:
    """
    Compact 0–100 auction quality score derived entirely from existing row signals.
    Higher = higher-confidence, better-identity, better-economics auction.
    """
    _r = row or {}
    _score = 50.0

    # ── Identity quality ──────────────────────────────────────────────────────
    _entity_status = str(_r.get("entity_match_status") or (
        "EXACT_MATCH" if bool(_r.get("exact_entity_match")) else "NO_MATCH"
    )).strip().upper()
    _entity_score = float(_r.get("entity_match_score") or 0.0)
    _score += {"EXACT_MATCH": 20.0, "STRONG_MATCH": 10.0, "WEAK_MATCH": -20.0, "NO_MATCH": -30.0}.get(_entity_status, -10.0)
    if _entity_score >= 0.90:
        _score += 5.0
    elif _entity_score >= 0.75:
        _score += 2.0
    if bool(_r.get("entity_loose_match")):
        _score -= 6.0   # passed only via relaxed 0.65 threshold, not exact/strong
    if bool(_r.get("lane_approved")):
        _score += 8.0
    else:
        _score -= 12.0

    # Route/recovery stage penalties — exact routes are most trustworthy
    _route = str(_r.get("route_stage") or "tracked_exact").strip().lower()
    _recovery = str(_r.get("recovery_stage") or "primary").strip().lower()
    _score += {"tracked_exact": 5.0, "family_valid_premium": 2.0, "premium_soft_valid": 2.5, "family_valid_fallback": -5.0,
               "promoted_live_candidate": -2.0, "route_rejected": -15.0}.get(_route, -5.0)
    _score += {"primary": 0.0, "tracked_expand": -8.0, "window_expand": -12.0, "discovery_fallback": -18.0}.get(_recovery, -8.0)

    # Query recall stage
    _recall = str(_r.get("query_recall_stage") or "precise").strip().lower()
    _score += {"precise": 3.0, "fallback_relaxed": -3.0, "fallback_recovery": -8.0}.get(_recall, 0.0)

    # ── Title specificity ─────────────────────────────────────────────────────
    _title = str(_r.get("source_title") or _r.get("title") or "").strip().lower()
    _clean = _title_cleanliness_score(_title)
    _score += min(8.0, max(-8.0, _clean - 7.0))   # cleanliness_score 7 = neutral

    # Card number present (#NNN)
    if re.search(r"#\s*\d+", _title):
        _score += 5.0
    # Year present
    if re.search(r"\b(20\d{2}|19\d{2})\b", _title):
        _score += 3.0
    # Known premium product keyword
    if any(tok in _title for tok in _STRONG_PRODUCT_TOKENS):
        _score += 4.0
    # Rookie / RC indicators (positive)
    if any(tok in _title for tok in (" rookie ", " rc ", "/rc", "(rc)")):
        _score += 2.0
    # Noisy/non-single-card language → hard penalty
    if any(tok in f" {_title} " for tok in _NOISY_TOKENS):
        _score -= 18.0
    # Very short title = low identity
    if len(_title) < 18:
        _score -= 10.0

    # ── MV / comps quality ────────────────────────────────────────────────────
    _mv_source = str(_r.get("market_value_source") or _r.get("mv_source") or "").strip().lower()
    _mv_conf = str(_r.get("mv_confidence") or _r.get("valuation_confidence") or "").strip().lower()
    _comp_count = int(float(_r.get("comp_count") or _r.get("mv_comp_count") or 0))
    _score += {
        "strong_comp_engine": 12.0,
        "exact_comp_engine": 10.0,
        "hybrid_exact_lane": 12.0,
        "hybrid_near_lane": 8.0,
        "near_family_support": 7.0,          # Tier E near-family — real comp evidence
        "premium_scarcity_bucket_support": 7.0,
        "scarcity_supported_comp_engine": 7.0,
        "medium_comp_engine": 5.0,
        "legacy_comp_engine": 4.0,
        "fallback_comp_support": 1.0,
        "structured_fallback": -10.0,
        "none": -10.0,
        "error": -10.0,
        "listing_type_excluded": -12.0,
    }.get(_mv_source, 0.0)
    # TRUE-tier rescue: rows that reached TRUE with a real MV should never be quality-gated
    # out by missing edge/actionable flags (which may not be recomputed after promotion).
    _truth_tier_q = str(_r.get("valuation_truth_tier") or "").strip().upper()
    _true_mv_q = _safe_float(_r.get("market_value_true") or _r.get("true_market_value"))
    if _truth_tier_q == "TRUE" and _true_mv_q and _true_mv_q > 0:
        _score += 15.0   # Genuine TRUE + MV overrides missing edge/actionable bonuses
    _score += {"high": 8.0, "medium": 4.0, "low": -5.0, "resolved": 8.0, "strong": 8.0}.get(_mv_conf, 0.0)
    if _comp_count >= 5:
        _score += 8.0
    elif _comp_count >= 3:
        _score += 5.0
    elif _comp_count >= 1:
        _score += 2.0
    else:
        _score -= 5.0   # zero comps = thin support

    # ── Economics ─────────────────────────────────────────────────────────────
    _has_positive_edge = bool(_r.get("has_positive_edge"))
    _is_actionable = bool(_r.get("is_actionable_bid"))
    _edge_pct = float(_r.get("edge_pct") or _r.get("edge_percent") or 0.0)
    if _is_actionable:
        _score += 8.0
    if bool(_r.get("target_bid_ready")):
        _score += 5.0
    if _has_positive_edge:
        _score += 10.0
        if _edge_pct >= 15.0:
            _score += 5.0
        elif _edge_pct >= 5.0:
            _score += 2.0
    else:
        _score -= 12.0   # over-MV / negative edge

    # ── Deal class bonus ──────────────────────────────────────────────────────
    _deal_class = str(_r.get("deal_class") or "UNKNOWN").strip().upper()
    _score += {"ELITE": 10.0, "STRONG": 6.0, "GOOD": 3.0, "UNKNOWN": -5.0, "FILTERED": -15.0}.get(_deal_class, 0.0)

    return float(max(0.0, min(100.0, _score)))


def _title_cleanliness_score(title: str) -> float:
    _t = str(title or "").strip().lower()
    if not _t:
        return 0.0
    _score = 12.0
    if len(_t) > 120:
        _score -= 2.0
    if _t.count(",") >= 2:
        _score -= 2.5
    if any(tok in _t for tok in [" lot ", " bundle ", " and more", " etc", " / ", " & "]):
        _score -= 4.0
    if any(tok in _t for tok in [" psa ", " bgs ", " sgc ", " auto", " rookie", "#"]):
        _score += 1.5
    return max(0.0, _score)


def _comp_quality_label(row: Dict[str, Any]) -> str:
    _source = str((row or {}).get("market_value_source") or "").strip().lower()
    _conf = str((row or {}).get("mv_confidence") or (row or {}).get("confidence") or "").strip().lower()
    _cc = int((row or {}).get("comp_count") or 0)
    if _source in {"structured_fallback", "none", "error", "listing_type_excluded"}:
        return "weak"
    if _conf in {"high", "medium"} and _cc >= 3:
        return "strong"
    if _conf not in {"low", "estimate_only", "excluded", ""} and _cc >= 1:
        return "usable"
    return "weak"


def _row_quality_state(row: Dict[str, Any]) -> str:
    _row = row or {}
    _entity_status = str(_row.get("entity_match_status") or ("EXACT_MATCH" if bool(_row.get("exact_entity_match")) else "NO_MATCH")).strip().upper()
    _supply_provisional = bool(_row.get("_supply_provisional_admit")) or bool(_row.get("_supply_provisional_entry"))
    if _entity_status == "NO_MATCH" or not bool(_row.get("lane_approved")):
        if _supply_provisional and _entity_status != "NO_MATCH":
            return "monitor_only"
        return "quarantined"
    if _valuation_status_for_row(_row) != "valued":
        if _supply_provisional:
            return "monitor_only"
        return "quarantined"
    if _entity_status == "WEAK_MATCH":
        return "quarantined"
    if _entity_status == "STRONG_MATCH":
        return "monitor_only"
    if _comp_quality_label(_row) == "weak":
        return "monitor_only"
    if str(_row.get("deal_class") or "").strip().upper() not in {"ELITE", "STRONG", "GOOD", "BIN_DEAL"}:
        return "monitor_only"
    return "execution_ready"


def _ranking_reasons(row: Dict[str, Any]) -> Tuple[str, str]:
    _quality = _row_quality_state(row)
    _comp = _comp_quality_label(row)
    _edge = float((row or {}).get("edge_pct") or 0.0)
    _secs = float(_row_remaining_seconds(row) or 999999.0)
    _entity_status = str((row or {}).get("entity_match_status") or "").strip().upper()
    if _quality == "execution_ready":
        _primary = "Exact entity + approved product"
        _secondary = "Strong comps + disciplined edge" if _comp == "strong" else "Usable comps + live urgency"
    elif _quality == "monitor_only":
        _primary = "Strong entity match - trust-adjusted"
        _secondary = "Monitor until cleaner comps/edge" if _comp == "weak" else "Strong match only - confirm before acting"
    else:
        _primary = "Quarantined by premium quality gate"
        _secondary = "Weak entity/product/trust issue blocks prominence"
    if _entity_status == "WEAK_MATCH":
        _secondary = "Weak entity signal - manual verification required"
    if _secs < 1800 and _quality != "quarantined":
        _secondary = f"{_secondary} · ends soon"
    elif _edge >= 12.0 and _quality == "execution_ready":
        _secondary = f"{_secondary} · {round(_edge, 1)}% edge"
    return _primary, _secondary


def _premium_rank_score(row: Dict[str, Any]) -> float:
    _row = row or {}
    _score = 0.0
    _quality = _row_quality_state(_row)
    _entity_status = str(_row.get("entity_match_status") or ("EXACT_MATCH" if bool(_row.get("exact_entity_match")) else "NO_MATCH")).strip().upper()
    _score += {"execution_ready": 120.0, "monitor_only": 55.0, "quarantined": 5.0}.get(_quality, 0.0)
    _score += {"EXACT_MATCH": 25.0, "STRONG_MATCH": 10.0, "WEAK_MATCH": -18.0, "NO_MATCH": -40.0}.get(_entity_status, -25.0)
    _score += 18.0 if bool(_row.get("lane_approved")) else -25.0
    _score += {"strong": 18.0, "usable": 8.0, "weak": -10.0}.get(_comp_quality_label(_row), 0.0)
    _score += min(25.0, max(0.0, float(_row.get("edge_pct") or 0.0)))
    _score += min(10.0, int(_row.get("comp_count") or 0) * 2.0)
    _score += _title_cleanliness_score(str(_row.get("title") or ""))
    _score += min(8.0, max(0.0, float(_row.get("entity_match_score") or 0.0) * 8.0))
    _truth = str(_row.get("valuation_truth_tier") or "").strip().upper()
    _support_profile = _support_truth_profile(_row)
    _truth_weight = 0.0
    if _truth == "TRUE" and not bool(_support_profile.get("is_support_source")):
        _truth_weight = 18.0
    elif _truth == "TRUE" and bool(_support_profile.get("support_truth_true")):
        _truth_weight = 7.0
    elif bool(_support_profile.get("is_support_source")):
        _truth_weight = -7.0
    elif _truth == "REVIEW":
        _truth_weight = -4.0
    _score += _truth_weight
    _secs = float(_row_remaining_seconds(_row) or 999999.0)
    if _secs < 900:
        _score += 10.0
    elif _secs < 3600:
        _score += 5.0
    if bool(_support_profile.get("is_support_source")):
        print(
            f"[RANK_TRUTH_WEIGHT] title={str(_row.get('title') or '')[:120]} "
            f"source={_valuation_source_clean(_row)} truth={_truth or 'NONE'} "
            f"support_tier={str(_support_profile.get('support_truth_tier') or '')} weight={_truth_weight:+.1f}"
        )
        if _truth_weight < 0:
            print(
                f"[RANK_SUPPORT_DEMOTE] title={str(_row.get('title') or '')[:120]} "
                f"reason={str(_support_profile.get('reason') or 'support_review_only')}"
            )
    return _score


def _commercial_card_signal_score(row: Dict[str, Any]) -> float:
    _r = row or {}
    _title = str(_r.get("source_title") or _r.get("title") or "").strip().lower()
    _product = str(_r.get("product_family") or _r.get("target_product_family") or "").strip().lower()
    _parallel = str(_r.get("parallel_name") or _r.get("parallel_bucket") or "").strip().lower()
    _subset = str(_r.get("subset_name") or "").strip().lower()
    _serial = int(_r.get("serial_denominator") or 0)
    _score = 0.0

    if _subset:
        _score += 16.0
    if _serial > 0:
        _score += 12.0 if _serial <= 25 else (9.0 if _serial <= 99 else 5.0)
    if any(_tok in _parallel for _tok in {"silver", "refractor", "holo", "chrome", "x-fractor"}):
        _score += 8.0
    if any(_tok in _title for _tok in [" silver ", " refractor ", " holo ", " chrome ", " x-fractor "]):
        _score += 5.0
    if any(_tok in _title for _tok in [" auto", " autograph", " /auto", " on-card auto"]):
        _score += 12.0
    if any(_tok in _title for _tok in [" zebra", " gold", " black", " nebula", " manga", " downtown", " kaboom", " genesis", " color blast"]):
        _score += 14.0
    if any(_tok in _title for _tok in [" rookie ", " rc ", "(rc)", " rookie card"]):
        _score += 6.0
        if any(_tok in (_product or _title) for _tok in _STRONG_PRODUCT_TOKENS):
            _score += 6.0
    if any(_tok in (_product or _title) for _tok in _STRONG_PRODUCT_TOKENS):
        _score += 5.0
    if not _subset and _serial <= 0 and not _parallel and not any(_tok in _title for _tok in [" silver ", " refractor ", " holo ", " chrome ", " auto", " rookie ", " rc "]):
        _score -= 8.0
    return float(max(0.0, min(40.0, _score)))


_COMMON_INSERT_TERMS: Tuple[str, ...] = (
    "fireworks", "visionary", "emergent", "deca", "global reach",
    "touchdown masters", "notoriety", "epic performers", "prizmatic",
)
_PREMIUM_SCARCITY_CLASSES: frozenset = frozenset({"ssp", "ssp_insert", "case_hit", "rare_parallel"})


def _compute_endgame_tier(row: Dict[str, Any]) -> Tuple[str, str]:
    """
    Classify a matched row into endgame / premium_secondary / commodity.

    Returns (endgame_tier, endgame_reason).

    ENDGAME   — iconic SSP/case-hit subset, serial ≤/99, patch auto,
                ultra-premium product, or rare parallel + strong product
    PREMIUM_SECONDARY — auto (no rare serial), silver/chrome/prizm parallel,
                        numbered /100–/499, strong-product RC
    COMMODITY — common insert, base with zero premium signal
    """
    _r = row or {}
    _title = " " + str(_r.get("source_title") or _r.get("title") or "").lower() + " "
    _subset = str(_r.get("subset_name") or _r.get("subset") or "").lower().replace("_", " ")
    _serial_raw = str(_r.get("serial") or _r.get("serial_bucket") or _r.get("serial_denominator") or "").strip()
    _scarcity = str(_r.get("scarcity_class") or "").lower()
    _parallel = str(_r.get("parallel_name") or _r.get("parallel") or _r.get("parallel_bucket") or "").lower()
    _product = str(_r.get("product") or _r.get("product_name") or _r.get("product_family") or "").lower()
    _common_insert = any(_t in _title for _t in _COMMON_INSERT_TERMS)

    _has_serial = bool(_serial_raw and _serial_raw not in {"0", "none", "n/a", ""})
    _has_auto = any(_tok in _title for _tok in _AUTO_TOKENS) or " auto " in _title
    _is_ultra_premium = any(_t in _product for _t in _ULTRA_PREMIUM_PRODUCTS) or any(_t in _title for _t in _ULTRA_PREMIUM_PRODUCTS)
    _is_ssp = _scarcity in {"ssp", "ssp_insert", "case_hit"}

    # Serial denominator
    _serial_den = 9999
    if _has_serial:
        _m = re.search(r"[/\\](\d+)", _serial_raw)
        if _m:
            _serial_den = int(_m.group(1))
        else:
            _m2 = re.search(r"(\d+)", _serial_raw)
            if _m2:
                _serial_den = int(_m2.group(1))

    # Subset in endgame registry and marked endgame=True?
    _subset_endgame = bool(
        _subset and _ENDGAME_SUBSET_REGISTRY.get(_subset, {}).get("endgame")
    )
    # Also check scarcity signal from subset detection
    _subset_endgame = _subset_endgame or (
        _is_ssp and _scarcity in {"ssp_insert"}
        and _subset not in _COMMODITY_SUBSET_EXCLUSIONS
    )

    # ── ENDGAME ───────────────────────────────────────────────────────────────
    if _subset_endgame:
        return "endgame", f"ssp_subset:{_subset or 'ssp_class'}"
    if _is_ultra_premium and (_has_auto or _has_serial):
        return "endgame", "ultra_premium_pedigree"
    if _has_auto and _has_serial and _serial_den <= 25:
        return "endgame", "patch_auto_rare_serial"
    if _has_serial and _serial_den <= 99:
        return "endgame", "serial_rare"

    # ── COMMODITY ─────────────────────────────────────────────────────────────
    if _common_insert:
        return "commodity", "common_insert"
    _has_premium_parallel = (
        any(_t in _parallel for _t in _PREMIUM_PARALLEL_TOKENS)
        or any(_t in _title for _t in {"refractor", "chrome", "holo"})
    )
    _is_base = not _parallel or _parallel in {"base", "na", ""} or "base" in _parallel
    if (not _has_serial and not _has_auto and not _is_ssp
            and not _has_premium_parallel and _is_base and not _subset):
        return "commodity", "base_no_premium"

    # ── PREMIUM_SECONDARY ─────────────────────────────────────────────────────
    if _has_auto:
        reason = "auto_serial" if _has_serial else "auto"
        return "premium_secondary", reason
    if _has_serial and _serial_den <= 499:
        return "premium_secondary", "serial_color" if _serial_den <= 199 else "serial_common"
    if _has_premium_parallel:
        return "premium_secondary", "premium_parallel"
    return "premium_secondary", "named_subset_or_rc"


def _stamp_endgame_tier(row: Dict[str, Any]) -> Dict[str, Any]:
    """Compute and stamp endgame_tier + endgame_reason onto the row (mutates in place)."""
    _tier, _reason = _compute_endgame_tier(row)
    row["endgame_tier"] = _tier
    row["endgame_reason"] = _reason
    return row


def _build_premium_sniper_lane_profile(row: Dict[str, Any]) -> Dict[str, Any]:
    """
    Classify a card row into one of four premium sniper lane tiers.

    Tiers (evaluated top-down, first match wins):
      elite      — SSP/case_hit, ultra-premium product + auto/serial, auto+serial ≤/99
      strong     — auto, serial ≤/99, strong-product + premium parallel
      speculative — serial /100–/499, color parallel, named subset, premium parallel
      commodity  — common insert, OR base card with zero premium signal

    Returns dict with keys:
      lane_tier          : "elite" | "strong" | "speculative" | "commodity"
      lane_reason        : short reason string for logging
      premium_lane_allowed : bool (False only for commodity)
      commodity_suppressed : bool (True only for commodity)
    """
    _r = row or {}
    _title = " " + str(_r.get("source_title") or _r.get("title") or "").lower() + " "
    _serial_raw = str(_r.get("serial") or _r.get("serial_bucket") or _r.get("serial_denominator") or "").strip()
    _scarcity = str(_r.get("scarcity_class") or "").lower()
    _parallel = str(_r.get("parallel_name") or _r.get("parallel") or _r.get("parallel_bucket") or "").lower()
    _subset = str(_r.get("subset_name") or _r.get("subset") or "").lower()
    _product = str(_r.get("product") or _r.get("product_name") or "").lower()

    _has_serial = bool(_serial_raw and _serial_raw not in {"0", "none", "n/a", ""})
    _has_auto = any(_tok in _title for _tok in _AUTO_TOKENS) or " auto " in _title
    _scarce = _scarcity in _PREMIUM_SCARCITY_CLASSES
    _common_insert = any(_t in _title for _t in _COMMON_INSERT_TERMS) or _subset in _COMMON_INSERT_TERMS
    _ultra_premium = (
        any(_t in _product for _t in _ULTRA_PREMIUM_PRODUCTS)
        or any(_t in _title for _t in _ULTRA_PREMIUM_PRODUCTS)
    )
    _strong_product = (
        any(_t in _product for _t in _STRONG_LIQUID_PRODUCTS)
        or any(_t in _title for _t in _STRONG_LIQUID_PRODUCTS)
    )
    # Premium parallel: prefer the structured _parallel field.
    # For title fallback, exclude tokens that are already the product name itself
    # so that "2023 Prizm CJ Stroud" (base) doesn't fire because "prizm" is in the title.
    if _parallel:
        _premium_parallel = any(_t in _parallel for _t in _PREMIUM_PARALLEL_TOKENS)
        if not _premium_parallel:
            # Parallel field is set but no token match — also check title
            _premium_parallel = any(_t in _title for _t in _PREMIUM_PARALLEL_TOKENS)
    else:
        # No parallel field: check title but exclude tokens already present in the product name
        _product_parallel_exclusions = {_t for _t in _PREMIUM_PARALLEL_TOKENS if _t in _product}
        _premium_parallel = any(
            _t in _title for _t in _PREMIUM_PARALLEL_TOKENS
            if _t not in _product_parallel_exclusions
        )
    _color_parallel = (
        any(_t in _parallel for _t in _COLOR_PARALLEL_TOKENS)
        or any(_t in _title for _t in _COLOR_PARALLEL_TOKENS)
    )
    _is_base = not _parallel or _parallel in {"base", "na", ""} or "base" in _parallel

    # Parse serial denominator from strings like "/249", "249/249", "to_249"
    _serial_den = 9999
    if _has_serial:
        _m = re.search(r"[/\\](\d+)", _serial_raw)
        if _m:
            _serial_den = int(_m.group(1))
        else:
            _m2 = re.search(r"(\d+)", _serial_raw)
            if _m2:
                _serial_den = int(_m2.group(1))

    # ── ELITE ─────────────────────────────────────────────────────────────────
    if _scarce:
        return {"lane_tier": "elite", "lane_reason": "ssp_casehit",
                "premium_lane_allowed": True, "commodity_suppressed": False}
    if _ultra_premium and (_has_auto or _has_serial):
        return {"lane_tier": "elite", "lane_reason": "ultra_premium_pedigree",
                "premium_lane_allowed": True, "commodity_suppressed": False}
    if _has_auto and _has_serial and _serial_den <= 99:
        return {"lane_tier": "elite", "lane_reason": "auto_serial_rare",
                "premium_lane_allowed": True, "commodity_suppressed": False}

    # ── STRONG ────────────────────────────────────────────────────────────────
    if _has_auto:
        return {"lane_tier": "strong", "lane_reason": "auto",
                "premium_lane_allowed": True, "commodity_suppressed": False}
    if _has_serial and _serial_den <= 99:
        return {"lane_tier": "strong", "lane_reason": "serial_rare",
                "premium_lane_allowed": True, "commodity_suppressed": False}
    if _strong_product and _premium_parallel:
        return {"lane_tier": "strong", "lane_reason": "strong_product_premium_parallel",
                "premium_lane_allowed": True, "commodity_suppressed": False}

    # ── COMMODITY ─────────────────────────────────────────────────────────────
    if _common_insert:
        return {"lane_tier": "commodity", "lane_reason": "common_insert",
                "premium_lane_allowed": False, "commodity_suppressed": True}
    if (
        not _has_serial and not _has_auto and not _scarce
        and not _premium_parallel and not _color_parallel
        and _is_base and not _subset
    ):
        return {"lane_tier": "commodity", "lane_reason": "base_no_premium",
                "premium_lane_allowed": False, "commodity_suppressed": True}

    # ── SPECULATIVE ───────────────────────────────────────────────────────────
    if _has_serial and _serial_den <= 199:
        _reason = "serial_color"
    elif _has_serial and _serial_den <= 499:
        _reason = "serial_common"
    elif _color_parallel:
        _reason = "color_parallel"
    elif _premium_parallel:
        _reason = "premium_parallel"
    elif _subset:
        _reason = "named_subset"
    else:
        _reason = "base_product_rc"
    return {"lane_tier": "speculative", "lane_reason": _reason,
            "premium_lane_allowed": True, "commodity_suppressed": False}


def _commercial_desirability_score(row: Dict[str, Any]) -> Tuple[int, List[str]]:
    score = 0
    reasons: List[str] = []

    _row = row or {}
    title = str(_row.get("source_title") or _row.get("title") or "").lower()
    try:
        price = float(_row.get("price") or _row.get("current_price") or _row.get("current_bid") or 0.0)
    except (TypeError, ValueError):
        price = 0.0
    try:
        mv = float(_row.get("market_value") or _row.get("mv_value") or _row.get("mv") or 0.0)
    except (TypeError, ValueError):
        mv = 0.0
    try:
        edge_dollars = float(
            _row.get("edge_dollars")
            or _row.get("edge_$")
            or (_row.get("action_summary") or {}).get("expected_profit")
            or max(0.0, mv - price)
        )
    except (TypeError, ValueError):
        edge_dollars = max(0.0, mv - price)
    comps = int(_row.get("comps") or _row.get("comp_count") or _row.get("mv_comp_count") or 0)
    conf = str(
        _row.get("valuation_confidence")
        or _row.get("mv_confidence_strict")
        or _row.get("confidence")
        or _row.get("mv_confidence")
        or ""
    ).upper()
    source = str(_row.get("mv_source") or _row.get("market_value_source") or "").lower()
    serial = str(_row.get("serial") or _row.get("serial_bucket") or _row.get("serial_denominator") or "").strip()
    subset = str(_row.get("subset_name") or _row.get("subset") or "").lower()
    parallel = str(_row.get("parallel_name") or _row.get("parallel") or _row.get("parallel_bucket") or "").lower()
    scarcity = str(_row.get("scarcity_class") or "").lower()

    has_serial = bool(serial)
    has_auto = "auto" in title
    scarce = scarcity in _PREMIUM_SCARCITY_CLASSES
    common_insert = any(t in title for t in _COMMON_INSERT_TERMS) or subset in _COMMON_INSERT_TERMS

    if has_serial:
        score += 30
        reasons.append("serialed")
    if has_auto:
        score += 28
        reasons.append("auto")
    if scarce:
        score += 24
        reasons.append("ssp_casehit")
    if comps >= 5:
        score += 10
        reasons.append("comp_depth")
    if conf == "HIGH":
        score += 12
        reasons.append("high_conf")
    elif conf == "MEDIUM":
        score += 6
        reasons.append("med_conf")
    if edge_dollars >= 20:
        score += 14
        reasons.append("real_profit")
    elif edge_dollars >= 10:
        score += 8
        reasons.append("usable_profit")

    if common_insert:
        score -= 24
        reasons.append("common_insert")

    if (not has_serial and not has_auto and not scarce) and ("base" in parallel or parallel in {"base", "na", ""}):
        score -= 18
        reasons.append("base_parallel")

    if price <= 5 and edge_dollars < 8:
        score -= 18
        reasons.append("tiny_ticket")

    if source == "structured_fallback":
        score -= 10
        reasons.append("fallback_mv")

    if source == "price_anchor_fallback":
        score -= 28
        reasons.append("anchor_mv")

    return score, reasons


def _is_common_rookie_commodity(row: Dict[str, Any]) -> bool:
    _row = row or {}
    title = str(_row.get("source_title") or _row.get("title") or "").lower()
    subset = str(_row.get("subset_name") or "").lower()
    product = str(
        _row.get("product_family")
        or _row.get("target_product_family")
        or _row.get("set_name")
        or (_row.get("target_meta") or {}).get("set_name")
        or ""
    ).lower()
    parallel = str(
        _row.get("parallel_name")
        or _row.get("parallel")
        or _row.get("parallel_bucket")
        or ""
    ).lower()
    serial = str(_row.get("serial") or _row.get("serial_bucket") or _row.get("serial_denominator") or "")
    auto = "auto" in title
    patch = "patch" in title
    try:
        price = float(_row.get("price") or _row.get("current_price") or _row.get("current_bid") or 0.0)
    except (TypeError, ValueError):
        price = 0.0
    try:
        mv = float(_row.get("market_value") or _row.get("mv_value") or _row.get("mv") or 0.0)
    except (TypeError, ValueError):
        mv = 0.0
    try:
        edge_dollars = float(
            _row.get("edge_dollars")
            or (_row.get("action_summary") or {}).get("expected_profit")
            or max(0.0, mv - price)
        )
    except (TypeError, ValueError):
        edge_dollars = max(0.0, mv - price)

    common_products = {
        "stadium club", "base topps chrome", "paper", "donruss", "score",
        "prestige", "chronicles", "mosaic base", "prizm base",
    }
    common_insert_terms = {
        "future stars", "1989 topps", "1990 topps", "strokes", "power players",
        "fortune 15", "scouts top 100", "prizmatic", "fireworks", "visionary",
        "emergent", "deca", "notoriety",
    }

    if serial or auto or patch:
        return False
    if subset in common_insert_terms:
        return True
    if any(t in title for t in common_insert_terms):
        return True
    if any(p in product for p in common_products) and edge_dollars < 40.0:
        return True
    if (
        price < 150.0
        and edge_dollars < 40.0
        and parallel in {"", "base", "refractor", "silver", "sepia", "pink", "raywave"}
    ):
        return True
    return False


def _passes_non_endgame_watchlist_floor(row: Dict[str, Any]) -> bool:
    _row = row or {}
    _endgame_tier = str(_row.get("endgame_tier") or "").strip().lower()
    _lane_tier = str(_row.get("lane_tier") or "").strip().lower()
    _commercial_bucket = str(_row.get("commercial_bucket") or "").strip().upper()
    try:
        _price = float(_row.get("price") or _row.get("current_price") or _row.get("current_bid") or 0.0)
    except (TypeError, ValueError):
        _price = 0.0
    try:
        _mv = float(_row.get("market_value") or _row.get("mv_value") or _row.get("mv") or 0.0)
    except (TypeError, ValueError):
        _mv = 0.0
    try:
        _edge_dollars = float(
            _row.get("edge_dollars")
            or (_row.get("action_summary") or {}).get("expected_profit")
            or max(0.0, _mv - _price)
        )
    except (TypeError, ValueError):
        _edge_dollars = max(0.0, _mv - _price)
    if _endgame_tier == "endgame" or _lane_tier == "elite" or _commercial_bucket == "ELITE":
        return True
    return bool(_price >= 150.0 or _edge_dollars >= 50.0)


def _stamp_commercial_profile(row: Dict[str, Any]) -> Dict[str, Any]:
    _r = row or {}

    # ================================
    # IDENTITY → COMMERCIAL NORMALIZATION
    # ================================

    # --- PARALLEL NORMALIZATION ---
    if not (_r.get("parallel_name") or _r.get("parallel") or _r.get("parallel_bucket")):
        _resolved_parallel = str(
            _r.get("identity_parallel_family") or _r.get("parallel_family") or ""
        ).strip()

        if _resolved_parallel and _resolved_parallel.lower() not in {"", "base"}:
            _r["parallel"] = _resolved_parallel

            print(
                f"[IDENTITY_PARALLEL_NORMALIZE] title={str(_r.get('title') or '')[:120]} "
                f"parallel={_resolved_parallel}"
            )

    # --- SERIAL NORMALIZATION ---
    if not (_r.get("serial") or _r.get("serial_denominator") or _r.get("serial_bucket")):
        _resolved_serial = str(
            _r.get("serial_number") or ""
        ).strip()

        if _resolved_serial and _resolved_serial not in {"0", "none", "n/a", ""}:
            _r["serial_denominator"] = _resolved_serial

            print(
                f"[IDENTITY_SERIAL_NORMALIZE] title={str(_r.get('title') or '')[:120]} "
                f"serial_denominator={_resolved_serial}"
            )

    # ================================
    score, reasons = _commercial_desirability_score(_r)
    bucket = "ELITE" if score >= 30 else "STRONG" if score >= 18 else "MID" if score >= 8 else "WEAK"
    title = str(_r.get("source_title") or _r.get("title") or "").lower()
    source = str(_r.get("mv_source") or _r.get("market_value_source") or "").lower()
    serial = str(_r.get("serial") or _r.get("serial_bucket") or _r.get("serial_denominator") or "").strip()
    scarcity = str(_r.get("scarcity_class") or "").lower()
    has_auto = "auto" in title
    try:
        mv = float(_r.get("market_value") or _r.get("mv_value") or 0.0)
    except (TypeError, ValueError):
        mv = 0.0
    try:
        price = float(_r.get("price") or _r.get("current_price") or _r.get("current_bid") or 0.0)
    except (TypeError, ValueError):
        price = 0.0
    try:
        edge_dollars = float(
            _r.get("edge_dollars")
            or (_r.get("action_summary") or {}).get("expected_profit")
            or max(0.0, mv - price)
        )
    except (TypeError, ValueError):
        edge_dollars = max(0.0, mv - price)

    common_insert = "common_insert" in reasons
    scarce_support = scarcity in _PREMIUM_SCARCITY_CLASSES
    common_rookie_commodity = _is_common_rookie_commodity(_r)
    _plain_parallel_block, _plain_parallel_reason = _is_plain_parallel_without_endgame_support(_r)
    common_modern_kill = bool(
        common_insert
        and not serial
        and not has_auto
        and not scarce_support
        and edge_dollars < 10.0
        and source in {"structured_fallback", "price_anchor_fallback"}
    )

    # ── Premium sniper lane classification ────────────────────────────────────
    _lane_profile = _build_premium_sniper_lane_profile(_r)
    _lane_tier = _lane_profile["lane_tier"]
    _premium_lane_allowed = _lane_profile["premium_lane_allowed"]
    _raw_commodity = _lane_profile["commodity_suppressed"]
    _lane_reason = _lane_profile["lane_reason"]

    # Market quality floor for commodity rows:
    #   edge_dollars >= 15 → commodity_quality_floor_met=True → watchlist allowed, hero blocked
    #   edge_dollars < 15  → full suppression (no board presence)
    _commodity_floor_met = bool(_raw_commodity and edge_dollars >= 15.0 and not common_rookie_commodity)
    _commodity_hard_suppressed = bool(_raw_commodity and not _commodity_floor_met)

    # Merge suppression: original common_modern_kill OR commodity below floor
    _commercially_suppressed = (
        common_modern_kill
        or _commodity_hard_suppressed
        or common_rookie_commodity
        or _plain_parallel_block
    )
    _suppression_reason = (
        "common_rookie_non_endgame" if common_rookie_commodity
        else _plain_parallel_reason if _plain_parallel_block
        else "common_modern_low_signal" if common_modern_kill
        else "commodity_below_quality_floor" if _commodity_hard_suppressed
        else ""
    )
    _floor_reason = (
        "commodity_quality_floor_exception" if _commodity_floor_met
        else ""
    )

    if _commercially_suppressed:
        _item_id = str(_r.get("source_item_id") or _r.get("item_id") or "")[:20]
        print(
            f"[PREMIUM_LANE_GATE] suppress item={_item_id} lane_tier={_lane_tier} "
            f"reason={_suppression_reason} lane_reason={_lane_reason} edge=${edge_dollars:.1f}"
        )
    elif _raw_commodity and _commodity_floor_met:
        _item_id = str(_r.get("source_item_id") or _r.get("item_id") or "")[:20]
        print(
            f"[PREMIUM_LANE_GATE] watchlist_only item={_item_id} lane_tier={_lane_tier} "
            f"reason=commodity_floor_exception edge=${edge_dollars:.1f}"
        )
    if common_rookie_commodity:
        _item_id = str(_r.get("source_item_id") or _r.get("item_id") or "")[:20]
        _kill_title = str(_r.get("source_title") or _r.get("title") or "")[:96]
        print(
            f"[COMMODITY_KILL] item={_item_id or '?'} reason=common_rookie_non_endgame "
            f"title=\"{_kill_title}\""
        )

    # PATCH 1: classify product tier for hard board block
    _product_tier = _classify_product_tier(_r)
    # TRUE CHASE CLASS GATE — classify card quality above product brand
    _chase_class, _chase_reasons = _classify_true_chase_class(_r)
    _mem_junk, _mem_junk_reason = _is_memorabilia_junk(_r)
    _vet_non_chase, _vet_reason = _is_veteran_non_chase(_r)
    _veteran_parallel_block = bool(_vet_non_chase and not _plain_parallel_block)
    if _veteran_parallel_block:
        _commercially_suppressed = True
        _suppression_reason = "veteran_parallel_non_endgame"

    _r["edge_dollars"] = round(edge_dollars, 2)
    _r["commercial_score"] = int(score)
    _r["commercial_reasons"] = list(reasons)
    _r["commercial_bucket"] = bucket
    _r["commercial_common_insert"] = common_insert
    _r["commercial_support_flags"] = {
        "serial": bool(serial),
        "auto": bool(has_auto),
        "scarcity": bool(scarce_support),
    }
    _r["commercially_suppressed"] = _commercially_suppressed
    _r["commercial_suppression_reason"] = _suppression_reason
    # Premium lane fields
    _r["lane_tier"] = _lane_tier
    _r["lane_reason"] = _lane_reason
    _r["premium_lane_allowed"] = _premium_lane_allowed
    _r["commodity_suppressed"] = bool(
        _raw_commodity or common_rookie_commodity or _plain_parallel_block or _veteran_parallel_block
    )
    _r["commodity_reason"] = (
        "common_rookie_non_endgame" if common_rookie_commodity
        else _plain_parallel_reason if _plain_parallel_block
        else "veteran_parallel_non_endgame" if _veteran_parallel_block
        else ("commodity_lane" if _raw_commodity else "")
    )
    _r["common_rookie_commodity"] = bool(common_rookie_commodity)
    _r["commodity_quality_floor_met"] = _commodity_floor_met
    _r["market_quality_floor_reason"] = _floor_reason
    # PATCH 1: stamp product tier
    _r["product_tier"] = _product_tier
    # TRUE CHASE CLASS GATE stamps
    _r["chase_class"] = _chase_class
    _r["chase_reasons"] = _chase_reasons
    _r["memorabilia_junk"] = bool(_mem_junk)
    _r["memorabilia_junk_reason"] = _mem_junk_reason
    _r["veteran_non_chase"] = bool(_vet_non_chase)
    _r["veteran_non_chase_reason"] = _vet_reason
    _r["plain_parallel_blocked"] = bool(_plain_parallel_block)
    _r["plain_parallel_block_reason"] = _plain_parallel_reason
    _r["veteran_parallel_blocked"] = bool(_veteran_parallel_block)
    # Logging
    if _mem_junk:
        _item_id_cc = str(_r.get("source_item_id") or _r.get("item_id") or "")[:20]
        _kill_title_cc = str(_r.get("source_title") or _r.get("title") or "")[:100]
        print(f"[MEM_JUNK_BLOCK] item={_item_id_cc} title=\"{_kill_title_cc}\" reason={_mem_junk_reason or 'generic_mem_junk'}")
    if _plain_parallel_block:
        _item_id_cc = str(_r.get("source_item_id") or _r.get("item_id") or "")[:20]
        print(f"[REFRACTOR_SILVER_BLOCK] item={_item_id_cc} reason=plain_parallel_without_endgame_support")
    if _vet_non_chase:
        _item_id_cc = str(_r.get("source_item_id") or _r.get("item_id") or "")[:20]
        _kill_title_cc = str(_r.get("source_title") or _r.get("title") or "")[:80]
        print(f"[VETERAN_NON_CHASE] item={_item_id_cc} title=\"{_kill_title_cc}\"")
    if _veteran_parallel_block:
        _item_id_cc = str(_r.get("source_item_id") or _r.get("item_id") or "")[:20]
        _kill_title_cc = str(_r.get("source_title") or _r.get("title") or "")[:80]
        print(f"[VETERAN_PARALLEL_BLOCK] item={_item_id_cc} title=\"{_kill_title_cc}\"")
    if _chase_class in {"GENERIC_PREMIUM_JUNK", "COMMODITY"}:
        _item_id_cc = str(_r.get("source_item_id") or _r.get("item_id") or "")[:20]
        print(f"[CHASE_CLASS] item={_item_id_cc} class={_chase_class} reasons={_chase_reasons}")
    return _r


def _is_commercial_listing(row: Dict[str, Any]) -> bool:
    _title = str((row or {}).get("title") or (row or {}).get("source_title") or "").lower()
    _bad_terms = [
        "lot", "lots", "bundle", "break", "case break", "team break",
        "sealed", "blaster", "mega box", "fat pack", "hobby box",
        "mystery", "blind", "reprint",
    ]
    if any(_term in _title for _term in _bad_terms):
        return False

    _good_terms = [
        "auto", "autograph", "patch", "relic", "jersey", "rpa",
        "/99", "/75", "/50", "/49", "/35", "/25", "/20", "/15", "/10", "/5", "1/1",
        "kaboom", "downtown", "color blast", "genesis", "stained glass", "aura",
        "gold", "black", "zebra", "scope", "shimmer", "vinyl",
        "prizm", "select", "optic", "spectra", "national treasures",
        "immaculate", "flawless", "contenders", "chrome", "finest",
    ]
    return any(_term in _title for _term in _good_terms)


def _commercial_listing_signal_count(row: Dict[str, Any]) -> int:
    _title = str((row or {}).get("title") or (row or {}).get("source_title") or "").lower()
    _good_terms = [
        "auto", "autograph", "patch", "relic", "jersey", "rpa",
        "/99", "/75", "/50", "/49", "/35", "/25", "/20", "/15", "/10", "/5", "1/1",
        "kaboom", "downtown", "color blast", "genesis", "stained glass", "aura",
        "gold", "black", "zebra", "scope", "shimmer", "vinyl",
        "prizm", "select", "optic", "spectra", "national treasures",
        "immaculate", "flawless", "contenders", "chrome", "finest",
    ]
    return sum(1 for _term in _good_terms if _term in _title)


def _is_late_hydrated_tier_b_survivor(row):
    try:
        if not isinstance(row, dict):
            return False, "not_dict"

        tier = str(row.get("_hydrated_subscription_lane_tier") or row.get("subscription_lane_tier") or "").strip().upper()
        identity_is_clean = bool(row.get("_hydrated_identity_is_clean") or row.get("identity_is_clean"))
        lane_type = str(row.get("_hydrated_lane_type") or row.get("lane_type") or "").strip().lower()
        insert_family = str(row.get("_hydrated_insert_family") or row.get("insert_family") or "").strip().lower()
        parallel_family = str(row.get("_hydrated_parallel_family") or row.get("parallel_family") or "").strip().lower()
        card_number = str(row.get("_hydrated_card_number") or row.get("card_number") or "").strip()
        grade = str(row.get("_hydrated_grade") or row.get("grade") or "").strip().lower()

        graded = any(x in grade for x in ["psa", "bgs", "sgc", "graded"])

        if not identity_is_clean:
            return False, "identity_not_clean"

        if tier == "TIER_B":
            return True, "tier_b"

        if lane_type == "insert" and insert_family in {"image_variation", "variation"} and card_number:
            return True, "graded_variation_insert"

        if graded and lane_type in {"insert", "parallel", "parallel_serial", "insert_parallel"} and card_number:
            return True, "graded_liquid_lane"

        if parallel_family in {"refractor", "purple", "blue", "green", "pink", "sepia", "silver"} and card_number:
            return True, "liquid_parallel"

        return False, "not_tier_b_survivor"
    except Exception as e:
        return False, f"error:{e}"


def _board_recovery_eligible(row: Dict[str, Any]) -> bool:
    _row = row or {}
    if not _row:
        return False
    if not _apply_domestic_board_gate(_row, caller="board_recovery_eligible"):
        return False
    if _review_fallback_commercial_floor_applies(_row):
        _floor_ok, _floor_reason = _passes_commercial_review_floor(_row)
        if not _floor_ok:
            _stamp_commercial_review_floor_fail(_row, _floor_reason, caller="board_recovery")
            return False

    _entity_reason = str(_row.get("entity_gate_reason") or _row.get("match_reason") or "").strip().lower()
    if bool(_row.get("player_mismatch")) or bool(_row.get("wrong_player")):
        return False
    if _entity_reason in {
        "wrong_entity", "player_mismatch", "other_player_in_title",
        "conflicting_seed_player", "negative_alias_conflict",
    }:
        return False
    if str(_row.get("entity_match_status") or "").strip().upper() == "NO_MATCH":
        return False

    _entity_ok = bool(
        _row.get("entity_exact_match")
        or _row.get("exact_entity_match")
        or _row.get("tracked_anchor")
        or _row.get("normalized_entity")
        or _row.get("_target_match_relaxed")
    )

    _remaining = _row.get("seconds_remaining")
    if _remaining is None:
        _remaining = _row_remaining_seconds(_row)
    _window_ok = bool(
        _row.get("within_window")
        or _row.get("_within_window")
        or _remaining is not None
    )

    _commercial_ok = _is_commercial_listing(_row)
    return bool(_entity_ok and _window_ok and _commercial_ok)


def _endgame_signal_score(row: Dict[str, Any]) -> int:
    _row = row or {}
    _title = str(_row.get("title") or _row.get("source_title") or "").lower()
    _score = 0

    _strong_terms = [
        "auto", "autograph", "patch", "rpa", "relic",
        "kaboom", "downtown", "color blast", "genesis", "stained glass", "aura",
        "gold", "black", "zebra", "shimmer", "vinyl",
        "national treasures", "immaculate", "flawless", "spectra",
        "prizm", "select", "optic", "finest", "chrome",
    ]
    for _term in _strong_terms:
        if _term in _title:
            _score += 1

    _serial_terms = ["/99", "/75", "/50", "/49", "/35", "/25", "/20", "/15", "/10", "/5", "1/1"]
    for _term in _serial_terms:
        if _term in _title:
            _score += 2

    if _row.get("exact_entity_match") or _row.get("entity_exact_match") or _row.get("tracked_anchor"):
        _score += 2

    if _row.get("_target_match_relaxed"):
        _score += 1

    if _row.get("_mv_untrusted_but_allowed"):
        _score -= 1

    return int(_score)


def _is_bad_recovery_row(row: Dict[str, Any]) -> bool:
    _title = str((row or {}).get("title") or (row or {}).get("source_title") or "").lower()

    _bad_terms = [
        "autographden", "read free ship", "custom", "reprint",
        "lot", "bundle", "break", "case break", "team break",
        "sealed", "blaster", "mega box", "hobby box",
    ]
    if any(_term in _title for _term in _bad_terms):
        return True

    _current_price = (row or {}).get("current_price")
    # TRUE rows with comp-backed MV are never "bad" regardless of current bid level.
    # A low current_price on a TRUE row is an opportunity, not a quality signal.
    _truth = str((row or {}).get("valuation_truth_tier") or "").strip().upper()
    _true_mv = _safe_float((row or {}).get("true_market_value") or (row or {}).get("market_value_true"))
    _target_bid = _safe_float((row or {}).get("target_bid"))
    _comp_ct = int((row or {}).get("comp_count") or (row or {}).get("usable_comp_count") or 0)
    if _truth == "TRUE" and _true_mv and _true_mv > 0 and _target_bid and _target_bid > 0 and _comp_ct >= 1:
        return False  # low current_price = opportunity, not bad quality
    try:
        if _current_price is not None and float(_current_price) < 5:
            return True
    except Exception:
        pass

    return False


def _is_watchlist_worthy(row: Dict[str, Any]) -> bool:
    _title = str((row or {}).get("title") or (row or {}).get("source_title") or "").lower()

    _junk_terms = [
        "lot", "bundle", "break", "case break", "team break",
        "sealed", "blaster", "mega box", "fat pack", "hobby box",
        "custom", "reprint",
    ]
    if any(_term in _title for _term in _junk_terms):
        return False

    _good_terms = [
        "auto", "autograph", "patch", "rpa", "relic",
        "kaboom", "downtown", "color blast", "genesis", "stained glass", "aura",
        "gold", "black", "zebra", "shimmer", "vinyl",
        "prizm", "select", "optic", "spectra", "contenders",
        "national treasures", "immaculate", "flawless", "chrome", "finest",
    ]
    _signal_hits = sum(1 for _term in _good_terms if _term in _title)

    if (
        bool((row or {}).get("exact_entity_match"))
        or bool((row or {}).get("entity_exact_match"))
        or bool((row or {}).get("tracked_anchor"))
    ):
        _signal_hits += 1

    try:
        _price = float((row or {}).get("current_price") or (row or {}).get("current_bid") or 0)
    except Exception:
        _price = 0.0

    return bool(_signal_hits >= 1 and _price >= 5.0)


# ── Commercial watchlist floor constants ──────────────────────────────────────
_COMMERCIAL_WATCH_DOLLAR_FLOOR: float = 15.0   # min review_estimate / true_mv
_COMMERCIAL_WATCH_PRICE_FLOOR: float  = 10.0   # min current_price (alt path)
_COMMERCIAL_WATCH_BID_FLOOR: float    = 10.0   # min target_bid (with comp support)
_WATCHLIST_LOW_REVIEW_VALUE_FLOOR: float = 8.0
_WATCHLIST_LOW_TARGET_BID_FLOOR: float = 5.0
_WATCHLIST_LOW_VALUE_SOURCES: frozenset = frozenset({
    "fallback",
    "structured_fallback",
    "fallback_review",
    "review_estimate",
    "soft_watchlist_estimate",
    "price_anchor_fallback",
    "anchor_only",
})


def _build_final_quality_contract(row: Dict[str, Any]) -> Dict[str, Any]:
    _row = row if isinstance(row, dict) else dict(row or {})
    _title = str(_row.get("title") or _row.get("source_title") or "").strip()
    _title_lower = f" {_title.lower()} "
    _identity_contract = _build_clean_identity_contract(_row)
    _product_family = _normalize_exact_product_family(
        str(
            _identity_contract.get("identity_product_family")
            or _row.get("query_contract_product_family")
            or _row.get("fingerprint_product_family")
            or _row.get("product_family")
            or _row.get("target_product_family")
            or _row.get("lane_product")
            or _row.get("product")
            or _row.get("product_name")
            or _title
        )
    )
    _insert_family = _normalize_subset_name(
        str(
            _identity_contract.get("identity_insert_family")
            or _row.get("query_contract_insert_family")
            or _row.get("fingerprint_insert_family")
            or _row.get("subset_name")
            or _row.get("subset_family")
            or _row.get("lane_subset")
            or _row.get("subset")
            or ""
        )
    )
    if _looks_like_serial_only_token(_insert_family):
        _insert_family = ""
    _immutable_insert_family = _first_premium_insert_family(
        _row.get("_hydrated_insert_family"),
        _row.get("insert_family"),
        _row.get("identity_insert_family"),
        _row.get("fingerprint_insert_family"),
        _row.get("query_contract_insert_family"),
        _identity_contract.get("insert_family"),
        _identity_contract.get("identity_insert_family"),
    )
    if _immutable_insert_family:
        _insert_family = _immutable_insert_family
        if isinstance(_row, dict):
            _row["_premium_insert_immutable"] = True
            _row["_premium_insert_immutable_reason"] = "preserve_detected_premium_insert"
            _row["_hydrated_insert_family"] = _immutable_insert_family
            _row["insert_family"] = _immutable_insert_family
    _parallel_seed = str(
        _identity_contract.get("identity_parallel_family")
        or _row.get("query_contract_parallel_family")
        or _row.get("fingerprint_parallel")
        or _row.get("parallel_family")
        or _row.get("parallel_name")
        or _row.get("parallel")
        or _row.get("parallel_bucket")
        or ""
    ).strip().lower().replace("_", " ")
    _parallel_ctx = _normalize_parallel_family(_title, _product_family, _parallel_seed)
    _parallel_family = str(
        _parallel_ctx.get("parallel_family") or _parallel_seed or ""
    ).strip().lower().replace(" ", "_")
    _auto_ctx = _resolve_autograph_lane_signals(_title, _product_family, _insert_family, _parallel_family)
    if str(_auto_ctx.get("insert_family") or "").strip() and (not _insert_family or _insert_family in {"auto", "autograph", "autographs"}):
        _insert_family = str(_auto_ctx.get("insert_family") or "").strip()
    _serial_denominator = str(
        _row.get("serial_denominator")
        or _row.get("query_contract_serial_denominator")
        or _row.get("fingerprint_serial_denominator")
        or _row.get("serial_bucket")
        or _extract_serial_denominator(_title)
        or ""
    ).strip()
    _serial_cap = _extract_serial_ceiling(f"{_serial_denominator} {_title}")
    _has_serial = bool(
        (_serial_denominator and _serial_denominator.lower() not in {"0", "none", "n/a", ""})
        or _serial_cap > 0
    )
    _has_auto = bool(
        _identity_contract.get("identity_has_auto")
        or _row.get("identity_has_auto")
        or _row.get("query_contract_has_auto")
        or _row.get("fingerprint_has_auto")
        or _row.get("is_auto")
        or _row.get("has_auto")
        or _row.get("autograph")
        or _row.get("is_autograph")
        or _auto_ctx.get("has_auto")
        or _insert_family in {"auto", "autograph", "autographs"}
        or any(
            _tok in _title_lower
            for _tok in (
                " auto ",
                " autograph ",
                " autographs ",
                " signed ",
                " signature ",
                " patch auto ",
                " auto patch ",
                " rpa ",
                " auto rpa ",
            )
        )
    )
    _merged_row = {
        **dict(_row),
        **dict(_identity_contract),
        "title": _title,
        "product_family": _product_family,
        "target_product_family": _product_family,
        "parallel_name": _parallel_family.replace("_", " "),
        "parallel_family": _parallel_family,
        "parallel": _parallel_family.replace("_", " "),
        "parallel_bucket": _parallel_family.replace("_", " "),
        "subset_name": _insert_family,
        "subset_family": _insert_family,
        "lane_subset": _insert_family,
        "serial_denominator": _serial_denominator,
        "serial_bucket": _serial_denominator,
    }
    _lane_type = str(
        _identity_contract.get("identity_lane_type")
        or _row.get("query_contract_lane_type")
        or _row.get("target_lane_type")
        or _row.get("spec_lane_class")
        or _row.get("lane_type")
        or ""
    ).strip().lower()
    if not _lane_type:
        if _has_serial or (_parallel_family and _parallel_family not in {"", "base"}):
            _lane_type = "parallel_serial"
        elif _insert_family:
            _lane_type = "insert"
        else:
            _lane_type = "base"
    if _immutable_insert_family:
        _old_lane_type = _lane_type
        _lane_type = "insert"
        if isinstance(_row, dict):
            _row["_hydrated_lane_type"] = "insert"
            _row["lane_type"] = "insert"
        print(
            f"[PREMIUM_INSERT_IMMUTABLE] title={_title[:160]} "
            f"insert_family={_immutable_insert_family} "
            f"old_lane={_old_lane_type} "
            f"new_lane=insert "
            f"reason=preserve_detected_premium_insert"
        )
    _product_tier = str(_row.get("product_tier") or _classify_product_tier(_merged_row) or "").strip().upper()
    _endgame_tier = str(_row.get("endgame_tier") or "").strip().lower()
    if not _endgame_tier:
        try:
            _endgame_tier = str(_compute_endgame_tier(_merged_row)[0] or "").strip().lower()
        except Exception:
            _endgame_tier = ""
    _chase_class = str(_row.get("chase_class") or "").strip().upper()
    if not _chase_class:
        try:
            _chase_class = str(_classify_true_chase_class(_merged_row)[0] or "").strip().upper()
        except Exception:
            _chase_class = ""
    _premium_classifier = premium_lane_classifier_signals(_merged_row)
    _premium_subset = bool(
        _lane_type == "premium_subset"
        or (_insert_family and bool((_ENDGAME_SUBSET_REGISTRY.get(_insert_family) or {}).get("endgame")))
        or bool(_premium_support_lane_meta(_insert_family))
    )
    _premium_product_tokens = any(
        _token in _product_family.replace("_", " ")
        for _token in (
            "topps cosmic chrome",
            "topps cosmic chrome black",
            "topps chrome black",
            "topps transcendent icons",
            "topps chrome logofractor",
            "topps chrome sapphire",
            "topps finest",
            "dynasty",
            "luminaries",
            "pristine",
        )
    )
    _is_premium_product = bool(
        bool(_premium_classifier.get("premium_lane"))
        or _premium_product_tokens
        or _product_tier in {"PREMIUM", "ENDGAME"}
        or _endgame_tier in {"premium_secondary", "endgame"}
        or _chase_class in {"PREMIUM_SECONDARY", "ENDGAME_CHASE"}
        or _premium_subset
    )
    _is_endgame_supported = bool(
        _product_tier == "ENDGAME"
        or _endgame_tier in {"premium_secondary", "endgame"}
        or _chase_class in {"PREMIUM_SECONDARY", "ENDGAME_CHASE"}
        or _premium_subset
        or _is_premium_product
    )
    _truth_level = str(
        _row.get("valuation_truth_level")
        or _row.get("valuation_truth_tier")
        or _row.get("_valuation_truth_tier")
        or ""
    ).strip().upper() or "NONE"
    _review_probe = dict(_merged_row)
    if not str(_review_probe.get("review_truth_class") or "").strip():
        _stamp_review_truth_class(_review_probe, emit_log=False)
    _review_class = str(
        _review_probe.get("review_truth_class")
        or _review_probe.get("review_class")
        or "none"
    ).strip().lower() or "none"
    _contract = {
        "final_lane_type": _lane_type,
        "final_product_family": _product_family,
        "final_parallel_family": _parallel_family,
        "final_insert_family": _insert_family,
        "final_serial_denominator": _serial_denominator,
        "final_has_serial": bool(_has_serial),
        "final_has_auto": bool(_has_auto),
        "final_is_premium_product": bool(_is_premium_product),
        "final_is_endgame_supported": bool(_is_endgame_supported),
        "final_truth_level": _truth_level,
        "final_review_class": _review_class,
        "final_identity_is_clean": bool(_identity_contract.get("identity_is_clean")),
    }
    if isinstance(_row, dict):
        _row["_final_quality_contract"] = dict(_contract)
    return _contract


def _watchlist_quality_floor_decision(
    row: Dict[str, Any],
    *,
    emit_log: bool = False,
) -> Dict[str, Any]:
    _row = row or {}
    _title = str(_row.get("title") or _row.get("source_title") or "").strip()
    _quality_contract = _build_final_quality_contract(_row)
    _cached = _row.get("_watchlist_quality_decision")
    if isinstance(_cached, dict) and not emit_log:
        _decision = dict(_cached)
    else:
        _truth = str(
            _quality_contract.get("final_truth_level")
            or _row.get("valuation_truth_tier")
            or _row.get("_valuation_truth_tier")
            or ""
        ).strip().upper()
        _source = _valuation_source_clean(_row)
        _source_fallback_like = bool(_source in _WATCHLIST_LOW_VALUE_SOURCES or "fallback" in _source)
        _review_est = _safe_float(_row.get("review_estimate_value") or _row.get("anchored_estimate_value")) or 0.0
        _target_bid = _safe_float(_row.get("target_bid") or _row.get("target_bid_price") or _row.get("bid_ceiling_value")) or 0.0
        _title_lower = f" {_title.lower()} "
        _product_raw = str(
            _quality_contract.get("final_product_family")
            or _row.get("query_contract_product_family")
            or _row.get("identity_product_family")
            or _row.get("fingerprint_product_family")
            or _row.get("product_family")
            or _row.get("target_product_family")
            or _row.get("lane_product")
            or _row.get("product")
            or _row.get("product_name")
            or ""
        ).strip()
        _product_norm = _normalize_exact_product_family(_product_raw)
        _subset_raw = str(
            _quality_contract.get("final_insert_family")
            or _row.get("query_contract_insert_family")
            or _row.get("identity_insert_family")
            or _row.get("fingerprint_insert_family")
            or _row.get("subset_name")
            or _row.get("lane_subset")
            or _row.get("subset")
            or ""
        ).strip()
        try:
            _subset_norm = _normalize_subset_name(_subset_raw)
        except Exception:
            _subset_norm = str(_subset_raw or "").strip().lower().replace("-", "_").replace(" ", "_")
        _parallel_raw = str(
            _quality_contract.get("final_parallel_family")
            or _row.get("query_contract_parallel_family")
            or _row.get("identity_parallel_family")
            or _row.get("fingerprint_parallel")
            or _row.get("parallel_name")
            or _row.get("parallel")
            or _row.get("parallel_bucket")
            or _row.get("parallel_family")
            or ""
        ).strip().lower().replace("_", " ")
        _serial_raw = str(
            _row.get("serial")
            or _row.get("serial_bucket")
            or _row.get("serial_denominator")
            or ""
        ).strip()
        _serial_cap = _extract_serial_ceiling(
            f"{_quality_contract.get('final_serial_denominator') or _serial_raw} {_parallel_raw} {_title_lower}"
        )
        _legacy_has_serial = bool(_serial_raw and _serial_raw.lower() not in {"0", "none", "n/a", ""}) or _serial_cap > 0
        _has_serial = bool(_quality_contract.get("final_has_serial"))
        _legacy_has_auto = bool(_row.get("is_auto")) or any(
            _tok in _title_lower
            for _tok in (" auto ", " autograph ", " signed ", " signature ", " patch auto ", " auto patch ", " rpa ", " auto rpa ")
        )
        _has_auto = bool(_quality_contract.get("final_has_auto"))
        _has_mem = bool(_row.get("is_memorabilia")) or any(
            _tok in _title_lower
            for _tok in (" patch ", " relic ", " jersey ", " memorabilia ", " material ", " materials ", " swatch ", " gear ", " mem ", " fabric ")
        )
        _mem_junk, _ = _is_memorabilia_junk(_row)
        _lane_type = str(
            _quality_contract.get("final_lane_type")
            or _row.get("target_lane_type")
            or _row.get("spec_lane_class")
            or ""
        ).strip().lower()
        _product_tier = str(_row.get("product_tier") or _classify_product_tier(_row) or "").strip().upper()
        _endgame_tier = str(_row.get("endgame_tier") or "").strip().lower()
        if not _endgame_tier:
            try:
                _endgame_tier = str(_compute_endgame_tier(_row)[0] or "").strip().lower()
            except Exception:
                _endgame_tier = ""
        _chase_class = str(_row.get("chase_class") or "").strip().upper()
        if not _chase_class:
            try:
                _chase_class = str(_classify_true_chase_class(_row)[0] or "").strip().upper()
            except Exception:
                _chase_class = ""
        _commodity_reason = str(_row.get("commodity_reason") or "").strip().lower()
        _grade_state = "raw"
        try:
            _grade_state = str(_extract_grade_bucket(_title) or "RAW").strip().lower()
        except Exception:
            _grade_state = "raw"
        _card_no = str(
            _row.get("card_number")
            or _row.get("fingerprint_card_number")
            or _row.get("target_card_number")
            or ""
        ).strip()
        if not _card_no:
            _card_match = re.search(r"#\s*([a-z0-9\-]+)", _title_lower)
            if _card_match:
                _card_no = str(_card_match.group(1) or "").strip()
        _year_num = 0
        try:
            _year_num = int(_row.get("year") or _row.get("card_year") or 0)
        except (TypeError, ValueError):
            _year_num = 0
        if not _year_num:
            _year_match = re.search(r"\b(19|20)\d{2}\b", _title)
            if _year_match:
                try:
                    _year_num = int(_year_match.group(0))
                except (TypeError, ValueError):
                    _year_num = 0
        _common_modern_commodity = False
        try:
            _common_modern_commodity, _ = _classify_common_modern_row(
                product=_product_norm or _product_raw,
                year_num=_year_num,
                card_no=_card_no,
                subset=_subset_norm or _subset_raw,
                parallel=_parallel_raw,
                serial_bucket="serial" if _has_serial else "",
                grade_state=_grade_state or "raw",
                is_auto=_has_auto,
                is_mem=_has_mem,
                title=_title,
            )
        except Exception:
            _common_modern_commodity = False
        _plain_parallel_probe = {
            **dict(_row),
            "product_family": _product_raw,
            "target_product_family": _product_raw,
            "parallel_name": _parallel_raw,
            "parallel_family": _parallel_raw,
            "parallel": _parallel_raw,
            "parallel_bucket": _parallel_raw,
            "subset_name": _subset_raw,
            "subset_family": _subset_raw,
            "lane_subset": _subset_raw,
            "serial_denominator": _quality_contract.get("final_serial_denominator") or _serial_raw,
            "serial": _quality_contract.get("final_serial_denominator") or _serial_raw,
        }
        _plain_parallel_block, _plain_parallel_reason = _is_plain_parallel_without_endgame_support(_plain_parallel_probe)
        _premium_classifier = premium_lane_classifier_signals(
            {
                **dict(_row),
                "product_family": _product_raw,
                "target_product_family": _product_raw,
                "parallel_name": _parallel_raw,
                "parallel_family": _parallel_raw,
                "parallel": _parallel_raw,
                "parallel_bucket": _parallel_raw,
                "subset_name": _subset_raw,
                "subset_family": _subset_raw,
                "lane_subset": _subset_raw,
                "serial_denominator": _quality_contract.get("final_serial_denominator") or _serial_raw,
            }
        )
        _premium_subset = bool(
            _lane_type == "premium_subset"
            or (_subset_norm and bool((_ENDGAME_SUBSET_REGISTRY.get(_subset_norm) or {}).get("endgame")))
            or bool(_premium_support_lane_meta(_subset_raw or _subset_norm))
        )
        _is_premium_product = bool(_quality_contract.get("final_is_premium_product"))
        _legacy_endgame_product_support = bool(
            _product_tier == "ENDGAME"
            or _endgame_tier == "endgame"
            or _chase_class == "ENDGAME_CHASE"
        )
        _endgame_product_support = bool(_quality_contract.get("final_is_endgame_supported"))
        _premium_patch_support = bool(
            _has_mem
            and not _mem_junk
            and (
                _product_tier in {"PREMIUM", "ENDGAME"}
                or _endgame_tier in {"endgame", "premium_secondary"}
                or _is_premium_product
            )
        )
        _legacy_commodity_shape = bool(
            bool(_row.get("commodity_suppressed"))
            or bool(_row.get("commercially_suppressed"))
            or _commodity_reason in {"commodity_lane", "common_rookie_non_endgame"}
            or _common_modern_commodity
            or _plain_parallel_block
            or _chase_class == "COMMODITY"
        )
        _commodity_shape = bool(
            _legacy_commodity_shape
            and not (_is_premium_product or _has_serial or _has_auto or _premium_subset or _endgame_product_support)
        )
        _legacy_base_parallel_family = bool(
            _common_modern_commodity
            or _plain_parallel_block
            or (not _has_serial and _parallel_raw in _COMMON_MODERN_COMMODITY_PARALLELS)
        )
        _base_parallel_family = bool(
            _legacy_base_parallel_family
            and not (_is_premium_product or _has_serial or _has_auto or _premium_subset or _endgame_product_support)
        )
        _low_review = bool(_review_est > 0 and _review_est < _WATCHLIST_LOW_REVIEW_VALUE_FLOOR)
        _low_bid = bool(_target_bid > 0 and _target_bid < _WATCHLIST_LOW_TARGET_BID_FLOOR)
        _applies = bool(_truth != "TRUE" and _source_fallback_like)
        _commercial_review_floor_ok = True
        _commercial_review_floor_reason = "not_applicable"
        if _review_fallback_commercial_floor_applies(_row):
            _commercial_review_floor_ok, _commercial_review_floor_reason = _passes_commercial_review_floor(_row)
        _blocked = bool(
            _applies
            and not _has_serial
            and not _has_auto
            and not _premium_subset
            and not _premium_patch_support
            and not _endgame_product_support
            and _commodity_shape
            and _base_parallel_family
            and (_low_review or _low_bid)
        )
        if not _commercial_review_floor_ok:
            _blocked = True
            _stamp_commercial_review_floor_fail(_row, _commercial_review_floor_reason, caller="watchlist_quality")
        if (
            (bool(_premium_classifier.get("premium_lane")) or _is_premium_product)
            and _commercial_review_floor_ok
            and (_has_serial or _has_auto or _premium_subset or _endgame_product_support)
        ):
            _blocked = False
        _contract_snapshot = (
            f"lane_type={str(_quality_contract.get('final_lane_type') or '')[:24]}|"
            f"product_family={str(_quality_contract.get('final_product_family') or '')[:48]}|"
            f"insert_family={str(_quality_contract.get('final_insert_family') or '')[:24]}|"
            f"parallel_family={str(_quality_contract.get('final_parallel_family') or '')[:24]}|"
            f"has_serial={1 if _has_serial else 0}|has_auto={1 if _has_auto else 0}|"
            f"is_premium_product={1 if _is_premium_product else 0}|"
            f"is_endgame_supported={1 if _endgame_product_support else 0}|"
            f"truth_level={_truth}|review_class={str(_quality_contract.get('final_review_class') or 'none')[:24]}"
        )
        if emit_log and isinstance(_row, dict) and not bool(_row.get("_final_quality_contract_logged")):
            print(
                f"[FINAL_QUALITY_CONTRACT] title={_title[:120]} "
                f"lane_type={str(_quality_contract.get('final_lane_type') or '')[:24]} "
                f"product_family={str(_quality_contract.get('final_product_family') or '')[:48]} "
                f"insert_family={str(_quality_contract.get('final_insert_family') or '')[:24]} "
                f"parallel_family={str(_quality_contract.get('final_parallel_family') or '')[:24]} "
                f"has_serial={1 if _has_serial else 0} has_auto={1 if _has_auto else 0} "
                f"is_premium_product={1 if _is_premium_product else 0} "
                f"is_endgame_supported={1 if _endgame_product_support else 0} "
                f"truth_level={_truth} review_class={str(_quality_contract.get('final_review_class') or 'none')[:24]}"
            )
            _row["_final_quality_contract_logged"] = True
        if emit_log and _has_auto:
            print(
                f"[AUTO_QUALITY_CONTRACT] title={_title[:140]} "
                f"has_auto={1 if _has_auto else 0} "
                f"is_premium_product={1 if _is_premium_product else 0} "
                f"commodity_lane={1 if _commodity_shape else 0} "
                f"review_class={str(_quality_contract.get('final_review_class') or 'none')[:24]}"
            )
        for _reason_name, _mismatch, _why in (
            (
                "commodity_lane",
                bool(_legacy_commodity_shape and not _commodity_shape),
                f"legacy_commodity_shape={1 if _legacy_commodity_shape else 0} contract_allowed={1 if _commodity_shape else 0}",
            ),
            (
                "base_parallel_family",
                bool(_legacy_base_parallel_family and not _base_parallel_family),
                f"legacy_base_parallel_family={1 if _legacy_base_parallel_family else 0} contract_allowed={1 if _base_parallel_family else 0}",
            ),
            (
                "no_serial",
                bool((not _legacy_has_serial) and _has_serial),
                f"legacy_has_serial={1 if _legacy_has_serial else 0} final_has_serial={1 if _has_serial else 0}",
            ),
            (
                "no_auto",
                bool((not _legacy_has_auto) and _has_auto),
                f"legacy_has_auto={1 if _legacy_has_auto else 0} final_has_auto={1 if _has_auto else 0}",
            ),
            (
                "no_endgame_product_support",
                bool((not _legacy_endgame_product_support) and _endgame_product_support),
                f"legacy_endgame_supported={1 if _legacy_endgame_product_support else 0} final_endgame_supported={1 if _endgame_product_support else 0}",
            ),
        ):
            if emit_log and _mismatch:
                print(
                    f"[FINAL_QUALITY_ASSERT] title={_title[:120]} reason={_reason_name} "
                    f"contract_snapshot={_contract_snapshot} why={_why}"
                )
        _reasons: List[str] = []
        if _blocked:
            for _reason_name, _allowed, _why in (
                ("fallback_review_source", _source_fallback_like, f"source={_source or 'none'}"),
                (
                    "commodity_lane",
                    _commodity_shape,
                    f"legacy_commodity_shape={1 if _legacy_commodity_shape else 0} final_commodity_shape={1 if _commodity_shape else 0} premium={1 if _is_premium_product else 0} serial={1 if _has_serial else 0} auto={1 if _has_auto else 0}",
                ),
                (
                    "base_parallel_family",
                    _base_parallel_family,
                    f"legacy_base_parallel_family={1 if _legacy_base_parallel_family else 0} final_base_parallel_family={1 if _base_parallel_family else 0} parallel={_parallel_raw[:32]}",
                ),
                ("no_serial", not _has_serial, f"has_serial={1 if _has_serial else 0} serial_denominator={str(_quality_contract.get('final_serial_denominator') or '')[:12]}"),
                ("no_auto", not _has_auto, f"has_auto={1 if _has_auto else 0} insert_family={_subset_raw[:24]}"),
                ("no_premium_subset", not _premium_subset, f"premium_subset={1 if _premium_subset else 0} insert_family={_subset_raw[:24]}"),
                (
                    "no_endgame_product_support",
                    not _endgame_product_support,
                    f"is_endgame_supported={1 if _endgame_product_support else 0} is_premium_product={1 if _is_premium_product else 0}",
                ),
            ):
                if emit_log:
                    print(
                        f"[FINAL_QUALITY_REASON_CHECK] title={_title[:120]} reason={_reason_name} "
                        f"allowed={1 if _allowed else 0} why={_why[:180]}"
                    )
                if _allowed:
                    _reasons.append(_reason_name)
            if _low_review:
                if emit_log:
                    print(
                        f"[FINAL_QUALITY_REASON_CHECK] title={_title[:120]} reason=review_below_floor "
                        f"allowed=1 why=review_estimate={_review_est}"
                    )
                _reasons.append("review_below_floor")
            if _low_bid:
                if emit_log:
                    print(
                        f"[FINAL_QUALITY_REASON_CHECK] title={_title[:120]} reason=target_bid_below_floor "
                        f"allowed=1 why=target_bid={_target_bid}"
                    )
                _reasons.append("target_bid_below_floor")
            if not _commercial_review_floor_ok:
                if emit_log:
                    print(
                        f"[FINAL_QUALITY_REASON_CHECK] title={_title[:120]} reason={str(_commercial_review_floor_reason)} "
                        f"allowed=1 why=commercial_review_floor_failed"
                    )
                _reasons.append(str(_commercial_review_floor_reason))
        _pass_reason = "not_applicable"
        if _applies:
            if _has_serial:
                _pass_reason = "serial_support"
            elif _has_auto:
                _pass_reason = "auto_support"
            elif _premium_subset:
                _pass_reason = "premium_subset_support"
            elif _premium_patch_support:
                _pass_reason = "patch_premium_support"
            elif _endgame_product_support:
                _pass_reason = "endgame_product_support"
            elif not _commodity_shape or not _base_parallel_family:
                _pass_reason = "non_commodity_shape"
            elif not _commercial_review_floor_ok:
                _pass_reason = str(_commercial_review_floor_reason)
            else:
                _pass_reason = "value_floor_cleared"
        _decision = {
            "allow": not _blocked,
            "blocked": _blocked,
            "applies": _applies,
            "reason": "|".join(_reasons) if _reasons else _pass_reason,
            "reasons": list(_reasons),
            "pass_reason": _pass_reason,
            "source": _source,
            "truth": _truth,
            "review_estimate": _review_est,
            "target_bid": _target_bid,
            "plain_parallel_reason": _plain_parallel_reason,
            "quality_contract": dict(_quality_contract),
        }
        if isinstance(_row, dict):
            _row["_watchlist_quality_decision"] = dict(_decision)
    if emit_log and isinstance(_row, dict) and not bool(_row.get("_watchlist_quality_logged")):
        if bool(_decision.get("blocked")):
            print(
                f"[WATCHLIST_QUALITY_BLOCK] title={str(_row.get('title') or _row.get('source_title') or '')[:120]} "
                f"source={str(_decision.get('source') or 'none')} truth={str(_decision.get('truth') or 'NONE')} "
                f"review={_decision.get('review_estimate')} bid={_decision.get('target_bid')}"
            )
            for _reason in list(_decision.get("reasons") or []):
                print(
                    f"[WATCHLIST_QUALITY_REASON] title={str(_row.get('title') or _row.get('source_title') or '')[:120]} "
                    f"reason={_reason}"
                )
            _row["_watchlist_quality_logged"] = True
        elif bool(_decision.get("applies")):
            print(
                f"[WATCHLIST_QUALITY_PASS] title={str(_row.get('title') or _row.get('source_title') or '')[:120]} "
                f"source={str(_decision.get('source') or 'none')} "
                f"reason={str(_decision.get('pass_reason') or 'value_floor_cleared')}"
            )
            _row["_watchlist_quality_logged"] = True
    return dict(_decision)


def _is_commercial_watchlist_row(row: Dict[str, Any]) -> Tuple[bool, str]:
    """
    Commercial quality gate for main watchlist admission.
    Returns (eligible: bool, reason: str).

    Fast-passes: endgame/elite commercial bucket, ultra-low serial (/1–/49).
    Hard dollar floor: review_estimate>=15 OR price>=10 OR (bid>=10 AND comps>=1).
    Commodity/base noise below $30 with no premium signals → demoted.
    """
    _premium_secondary = _premium_secondary_watchlist_contract(
        row if isinstance(row, dict) else dict(row or {}),
        emit_log=True,
    )
    _row = _premium_secondary.get("row") if isinstance(_premium_secondary.get("row"), dict) else _stamp_evidence_render_contract(dict(row or {}), emit_log=False)
    if not bool(_premium_secondary.get("allow")):
        return False, str(_premium_secondary.get("reason") or "dead_review_only_no_evidence_no_bid")
    _truth_level = str(_row.get("valuation_truth_level") or "").strip().upper() or "NONE"
    if _truth_level in {"REVIEW", "NONE"} and int(_row.get("evidence_renderable") or 0) <= 0:
        return False, "no_renderable_evidence"
    if _review_fallback_commercial_floor_applies(_row):
        _floor_ok, _floor_reason = _passes_commercial_review_floor(row if isinstance(row, dict) else _row)
        if not _floor_ok:
            if isinstance(row, dict):
                _stamp_commercial_review_floor_fail(row, _floor_reason, caller="commercial_watch_gate")
            return False, _floor_reason
    _quality_contract = dict(_row.get("_final_quality_contract") or _build_final_quality_contract(_row))

    # ── Fast-pass: endgame/elite always surface ──────────────────────────
    _chase    = str(_row.get("chase_class") or "").strip().upper()
    _bucket   = str(_row.get("commercial_bucket") or "WEAK").strip().upper()
    _endgame  = str(_row.get("endgame_tier") or "").strip().lower()
    if _chase == "ENDGAME_CHASE" or _bucket == "ELITE" or _endgame == "endgame":
        return True, "fast_pass_endgame_elite"

    _title = str(_row.get("title") or _row.get("source_title") or "").lower()

    # Ultra-low serial in title (/1, /5, /10, /25, /49)
    if any(_s in _title for _s in ("/1 ", "/5 ", "/10 ", "/25 ", "/49 ")):
        return True, "fast_pass_ultra_serial_title"

    # Serial field: ≤49 = premium regardless of dollar
    _serial_str = str(
        _quality_contract.get("final_serial_denominator")
        or _row.get("serial")
        or _row.get("serial_denominator")
        or ""
    ).strip()
    if _serial_str:
        try:
            if int(_serial_str.replace("/", "").strip()) <= 49:
                return True, "fast_pass_serial_lte_49"
        except Exception:
            pass

    # High-prestige product family fast-pass
    _high_prestige = ("national treasures" in _title or "immaculate" in _title
                      or "flawless" in _title or "spectra" in _title)
    if _high_prestige:
        return True, "fast_pass_high_prestige_product"

    # ── Dollar floor ─────────────────────────────────────────────────────
    _review_est = _safe_float(_row.get("review_estimate_value")) or 0.0
    _true_mv    = (_safe_float(_row.get("true_market_value"))
                   or _safe_float(_row.get("market_value_true")) or 0.0)
    _best_mv    = max(_review_est, _true_mv)
    _price      = (_safe_float(_row.get("current_price"))
                   or _safe_float(_row.get("current_bid")) or 0.0)
    _target_bid = _safe_float(_row.get("target_bid")) or 0.0
    _comp_count = int(_row.get("comp_count_display") or _row.get("comp_count") or _row.get("mv_comp_count") or 0)

    _watchlist_quality = _watchlist_quality_floor_decision(_row, emit_log=True)
    if not bool(_watchlist_quality.get("allow")):
        return False, str(_watchlist_quality.get("reason") or "watchlist_quality_floor")

    _clears_dollar = (
        _best_mv >= _COMMERCIAL_WATCH_DOLLAR_FLOOR
        or _price >= _COMMERCIAL_WATCH_PRICE_FLOOR
        or (_target_bid >= _COMMERCIAL_WATCH_BID_FLOOR and _comp_count >= 1)
    )
    if not _clears_dollar:
        return False, f"low_commercial_value:est={_best_mv:.2f} price={_price:.2f} bid={_target_bid:.2f}"

    # ── Commodity / base noise filter ─────────────────────────────────────
    # Even above the dollar floor, commodity base rows without premium signals
    # below $30 are noise — they are not worth prime watchlist space.
    if bool(_row.get("memorabilia_junk")):
        return False, "memorabilia_junk"

    _is_commodity  = (
        _chase in {"COMMODITY", ""}
        and _bucket in {"WEAK", ""}
        and not bool(_quality_contract.get("final_is_premium_product"))
    )
    _has_premium   = bool(
        _quality_contract.get("final_is_premium_product")
        or _quality_contract.get("final_has_auto")
        or _quality_contract.get("final_has_serial")
        or str(_quality_contract.get("final_parallel_family") or "").strip() not in {"", "base"}
        or any(_t in _title for _t in (
            "patch", "auto", "rpa", "relic", "refractor",
            "prizm", "optic", "select", "chrome", "finest",
            "bowman chrome", "topps chrome", "kaboom", "stained glass",
        ))
    )
    if _is_commodity and not _has_premium and _best_mv < 30.0 and _price < 25.0:
        return False, f"base_noise:chase={_chase} bucket={_bucket} est={_best_mv:.2f}"

    return True, "commercial_floor_cleared"


def _review_watchlist_eligible(row: Dict[str, Any]) -> bool:
    _title = str((row or {}).get("title") or (row or {}).get("source_title") or "").lower()

    _junk_terms = [
        "lot", "bundle", "break", "case break", "team break",
        "sealed", "blaster", "mega box", "fat pack", "hobby box",
        "custom", "reprint",
    ]
    if any(_term in _title for _term in _junk_terms):
        return False

    if str((row or {}).get("valuation_truth_tier") or "").strip().upper() != "REVIEW":
        return False

    try:
        _review_est = float((row or {}).get("review_estimate_value")) if (row or {}).get("review_estimate_value") is not None else None
    except Exception:
        _review_est = None

    try:
        _target_bid = float((row or {}).get("target_bid")) if (row or {}).get("target_bid") is not None else None
    except Exception:
        _target_bid = None

    _premium_terms = [
        "national treasures", "immaculate", "flawless", "spectra",
        "patch", "auto", "rpa", "relic", "gold", "holo", "/10", "/25", "/49", "/99",
    ]
    _premium_hit = any(_term in _title for _term in _premium_terms)

    if not (_premium_hit and _review_est is not None and _target_bid is not None):
        return False

    # ── Commercial quality gate ───────────────────────────────────────────
    _commercial_ok, _commercial_reason = _is_commercial_watchlist_row(row)
    if not _commercial_ok:
        print(
            f"[COMMERCIAL_WATCH_DEMOTE] title={_title[:120]} reason={_commercial_reason} "
            f"est={_review_est} bid={_target_bid}"
        )
        return False

    print(f"[COMMERCIAL_WATCH_GATE] title={_title[:120]} reason={_commercial_reason}")
    return True


def _build_soft_target_bid(row: Dict[str, Any]) -> Optional[float]:
    _current_price = (row or {}).get("current_price")
    if _current_price in (None, "", 0):
        _current_price = (row or {}).get("current_bid")
    _mv = (
        (row or {}).get("review_estimate_value")
        or (row or {}).get("true_market_value")
        or
        (row or {}).get("market_value_true")
        or (row or {}).get("market_value")
        or (row or {}).get("anchored_estimate_value")
        or (row or {}).get("estimated_value")
    )

    try:
        _cp = float(_current_price) if _current_price is not None else None
    except Exception:
        _cp = None

    try:
        _mvf = float(_mv) if _mv is not None else None
    except Exception:
        _mvf = None

    if _mvf and _mvf > 0:
        return round(_mvf * 0.72, 2)

    if _cp and _cp > 0:
        return round(_cp * 1.18, 2)

    return None


def _final_sniper_eligible(row: Dict[str, Any]) -> bool:
    if not row:
        return False
    if not _apply_domestic_board_gate(row, caller="final_sniper_eligible"):
        return False

    _truth = str((row or {}).get("valuation_truth_tier") or "").strip().upper()
    _true_mv = (row or {}).get("true_market_value")
    _target_bid = (row or {}).get("target_bid")
    _comp_count = (row or {}).get("usable_comp_count", (row or {}).get("comp_count", 0))

    try:
        _comp_count = int(_comp_count or 0)
    except Exception:
        _comp_count = 0

    try:
        _true_mv = float(_true_mv) if _true_mv is not None else None
    except Exception:
        _true_mv = None

    try:
        _target_bid = float(_target_bid) if _target_bid is not None else None
    except Exception:
        _target_bid = None

    return bool(
        _truth == "TRUE"
        and _true_mv is not None
        and _target_bid is not None
        and _comp_count >= 1
    )


def _final_watchlist_eligible(row: Dict[str, Any]) -> bool:
    if not row:
        return False
    if not _apply_domestic_board_gate(row, caller="final_watchlist_eligible"):
        return False
    if _review_fallback_commercial_floor_applies(row):
        _floor_ok, _floor_reason = _passes_commercial_review_floor(row)
        if not _floor_ok:
            _stamp_commercial_review_floor_fail(row, _floor_reason, caller="final_watchlist_eligible")
            return False

    _watchlist_quality = _watchlist_quality_floor_decision(row, emit_log=True)
    if not bool(_watchlist_quality.get("allow")):
        return False
    _premium_secondary = _premium_secondary_watchlist_contract(row, emit_log=True)
    if not bool(_premium_secondary.get("allow")):
        return False

    _truth = str((row or {}).get("valuation_truth_tier") or "").strip().upper()
    _target_bid = (row or {}).get("target_bid")
    _review_est = _safe_float((row or {}).get("review_estimate_value"))
    _title = str((row or {}).get("title") or (row or {}).get("source_title") or "").lower()
    _reason_blob = " ".join(
        str((row or {}).get(_field) or "")
        for _field in (
            "target_match_reason",
            "product_match_reason",
            "reject_reason",
            "hidden_reason",
        )
    ).lower()
    _entity_valid = bool(
        (row or {}).get("entity_exact_match")
        or (row or {}).get("exact_entity_match")
        or (row or {}).get("tracked_anchor")
        or (row or {}).get("_target_match_relaxed")
    )
    _product_valid = not any(_term in _reason_blob for _term in ("product_mismatch", "family_exact_miss", "no_match", "conflicting"))
    _non_junk = not any(_term in _title for _term in ("lot", "bundle", "break", "case break", "team break", "sealed", "blaster", "mega box", "fat pack", "hobby box", "custom", "reprint"))

    try:
        _target_bid = float(_target_bid) if _target_bid is not None else None
    except Exception:
        _target_bid = None

    if _target_bid is None and not (_review_est and _review_est > 0):
        return False

    if _truth == "TRUE":
        return True

    if (
        _truth == "REVIEW"
        and (_review_est and _review_est > 0)
        and _entity_valid
        and _product_valid
        and _non_junk
        and (
            bool((row or {}).get("_review_watchlist"))
            or bool((row or {}).get("_visible_survival"))
            or bool((row or {}).get("_minimum_visible_watchlist"))
        )
    ):
        return True

    return False


def _compute_sniper_board_profile(row: Dict[str, Any]) -> Dict[str, Any]:
    _r = row or {}
    _fit = str(_r.get("target_fit_tier") or "forced_review").strip().lower()
    _heat = float(_r.get("whatnot_heat_score") or 0.0)
    _desirability = float(_r.get("desirability_score") or 0.0)
    _exec_score = float(_r.get("execution_score") or 0.0)
    _auction_quality = float(_r.get("auction_quality_score") or 0.0)
    _comp_count = int(_r.get("comp_count") or _r.get("mv_comp_count") or 0)
    _mv_conf = str(_r.get("mv_confidence_strict") or _r.get("mv_confidence") or _r.get("valuation_confidence") or "").strip().upper()
    if _mv_conf not in {"HIGH", "MEDIUM", "LOW"}:
        _mv_conf = "LOW"
    _tb_conf = str(_r.get("target_bid_confidence") or "NONE").strip().upper()
    _bid_conf = str(_r.get("bid_ceiling_confidence") or _tb_conf or "NONE").strip().upper()
    _target_bid_ready = bool(_r.get("bid_ceiling_ready")) or bool(_r.get("target_bid_ready")) or _row_target_bid_ready(_r)
    _mv_value = float(_r.get("mv_value") or _r.get("market_value") or 0.0)
    _mv_resolved = bool(_r.get("mv_resolved")) or _mv_value > 0
    _mv_valid = bool(_r.get("mv_valid"))
    _edge_pct = float(_r.get("edge_pct") or _r.get("edge_percent") or 0.0)
    _is_actionable = bool(_r.get("is_actionable_bid"))
    _review_candidate = bool(_r.get("is_review_candidate"))
    _rescue = str(_r.get("rescue_trust_tier") or "none").strip().lower()
    _route_stage = str(_r.get("route_stage") or "tracked_exact").strip().lower()
    _recovery = str(_r.get("recovery_stage") or "primary").strip().lower()
    _remaining = float(_row_remaining_seconds(_r) or 999999.0)
    _commercial = _commercial_card_signal_score(_r)
    _commercial_score = int(_r.get("commercial_score") or 0)
    _commercial_bucket = str(_r.get("commercial_bucket") or "WEAK").strip().upper()
    _commercial_reasons = list(_r.get("commercial_reasons") or [])
    _commercially_suppressed = bool(_r.get("commercially_suppressed"))
    _commodity_suppressed = bool(_r.get("commodity_suppressed"))
    _commodity_floor_met = bool(_r.get("commodity_quality_floor_met"))
    _lane_tier = str(_r.get("lane_tier") or "").strip().lower()
    _endgame_gate = _endgame_sniper_gate(_r)
    _single_comp_clone_block = _stamp_single_comp_clone_hero_block(_r)
    _common_modern_exact = bool(_r.get("common_modern_exact_required"))
    _realism_downgraded = bool(_r.get("realism_downgraded_to_review"))
    _realism_reason = str(_r.get("realism_clamp_reason") or "").strip()
    _mv_source = str(_r.get("mv_source") or _r.get("market_value_source") or "").strip().lower()
    _has_serial = bool(str(_r.get("serial") or _r.get("serial_bucket") or _r.get("serial_denominator") or "").strip())
    _has_auto = "auto" in str(_r.get("source_title") or _r.get("title") or "").strip().lower()
    _scarcity = str(_r.get("scarcity_class") or "").strip().lower()
    _scarce_support = _scarcity in _PREMIUM_SCARCITY_CLASSES
    try:
        _edge_dollars = float(
            _r.get("edge_dollars")
            or (_r.get("action_summary") or {}).get("expected_profit")
            or max(0.0, _mv_value - float(_r.get("current_price") or _r.get("current_bid") or 0.0))
        )
    except (TypeError, ValueError):
        _edge_dollars = 0.0

    _score = 0.0
    _score += {"exact": 18.0, "strong_family": 12.0, "weak_family": 4.0, "forced_review": -8.0}.get(_fit, 0.0)
    _score += min(22.0, _heat * 0.22)
    _score += min(18.0, _desirability * 0.18)
    _score += min(16.0, _exec_score * 0.16)
    _score += min(10.0, _auction_quality * 0.12)
    _score += {"HIGH": 16.0, "MEDIUM": 10.0, "LOW": 0.0}.get(_mv_conf, 0.0)
    _score += {"HIGH": 20.0, "MEDIUM": 14.0, "REVIEW": 7.0, "NONE": 0.0}.get(_bid_conf, 0.0)
    _score += min(12.0, _comp_count * 1.8)
    _score += _commercial
    _score += min(18.0, max(-18.0, _commercial_score * 0.45))
    if _is_actionable:
        _score += 18.0
    elif _review_candidate:
        _score += 6.0
    if _target_bid_ready:
        _score += 8.0
    else:
        _score -= 22.0 if _commercial < 20.0 else 10.0
    if not _mv_resolved:
        _score -= 16.0
    if _mv_conf == "LOW":
        _score -= 12.0
    if _edge_pct <= 0:
        _score -= 10.0
    elif _edge_pct >= 12.0:
        _score += 6.0
    if _remaining <= 900:
        _score += 8.0
    elif _remaining <= 3600:
        _score += 4.0
    if _route_stage in {"family_valid_premium", "premium_soft_valid"}:
        _score += 4.0
    elif _route_stage == "promoted_live_candidate":
        _score += 2.0
    if _recovery in {"tracked_expand", "window_expand"}:
        _score -= 6.0
    elif _recovery == "discovery_fallback":
        _score -= 16.0
    if _rescue != "none":
        _score -= 18.0
    if _common_modern_exact and (_realism_downgraded or _mv_conf == "LOW"):
        _score -= 24.0
    if _commercial_bucket == "WEAK":
        _score -= 26.0
    elif _commercial_bucket == "MID":
        _score -= 4.0
    if _commercially_suppressed:
        _score -= 40.0
    elif _commodity_suppressed and not _commodity_floor_met:
        # Commodity below floor that wasn't caught by commercially_suppressed yet
        _score -= 40.0
    elif _commodity_suppressed and _commodity_floor_met:
        # Commodity at floor: visible on watchlist but penalised from hero
        _score -= 18.0
    if bool(_endgame_gate.get("sniper_candidate")) and not _single_comp_clone_block:
        _score += 16.0

    _score = float(max(0.0, min(100.0, _score)))

    # ── VALUATION-DRIVEN LABEL OVERRIDE ──────────────────────────────────────
    # Before the eligibility decision tree runs, check if this row has been
    # marked by the valuation override pass. If so, clear any classification
    # suppression flags that may have survived and boost the score so the
    # tree reaches the right positive gate rather than the commodity path.
    if bool(_r.get("_valuation_override")):
        _commercial_bucket = "STRONG"
        _commercially_suppressed = False
        _commodity_suppressed = False
        _commodity_floor_met = True
        _score = max(_score, 65.0)

    _eligible = False
    _hero_tier = ""
    _hero_reason = ""
    _hero_rejected = False
    _hero_reject_reason = ""
    if _single_comp_clone_block:
        _eligible = False
        _hero_tier = ""
        _hero_reason = "Single exact comp matches current price; no verified edge for hero board"
        _hero_rejected = True
        _hero_reject_reason = "single_comp_clone_no_edge"
    elif _commercially_suppressed:
        _eligible = False
        _hero_tier = ""
        _hero_reason = str(_r.get("commercial_suppression_reason") or "Commercially suppressed")
    elif _commodity_suppressed and not _commodity_floor_met:
        # Commodity below $15 edge: full rejection even if not commercially_suppressed
        _eligible = False
        _hero_tier = ""
        _hero_reason = "Commodity card below market quality floor ($15 edge required)"
    elif _common_modern_exact and (_realism_downgraded or _mv_conf == "LOW" or not _mv_valid):
        _eligible = False
        _hero_tier = ""
        _hero_reason = "Common modern card lacks trusted exact-card pricing support"
        print(
            f"[SNIPER_REJECT] item={str(_r.get('source_item_id') or _r.get('item_id') or '')[:24]} "
            f"reason=common_modern_untrusted_mv"
        )
    elif bool(_endgame_gate.get("sniper_candidate")):
        _eligible = True
        _hero_tier = "ACTIONABLE_HERO" if str(_endgame_gate.get("execution_decision") or "") == "EXECUTE_NOW" else "SNIPER_CANDIDATE_HERO"
        _hero_reason = "Trusted endgame row cleared sniper gate"
    elif (
        _is_actionable
        and _target_bid_ready
        and _mv_resolved
        and _edge_dollars >= 8.0
        and _commercial_bucket in {"ELITE", "STRONG"}
        and _mv_source != "price_anchor_fallback"
        and not _commodity_suppressed  # commodity rows never reach hero board
    ):
        _eligible = True
        _hero_tier = "ACTIONABLE_HERO"
        _hero_reason = "Commercially strong actionable hero"
    elif (
        _rescue == "none"
        and _target_bid_ready
        and _mv_resolved
        and _edge_dollars >= 4.0
        and _comp_count >= 2
        and _commercial_bucket in {"MID", "STRONG"}
        and _mv_source != "price_anchor_fallback"
        and not _commodity_suppressed  # commodity rows never reach hero board
    ):
        _eligible = True
        _hero_tier = "WATCHLIST_HERO"
        _hero_reason = "Commercially desirable watch candidate"
    else:
        if (
            not _commercially_suppressed
            and _mv_source != "price_anchor_fallback"
            and _target_bid_ready
            and _mv_resolved
            and _comp_count >= 2
            and (
                _commercial_bucket == "MID"
                or _edge_dollars < 8.0
                or (_common_modern_exact and _comp_count >= 2)
            )
        ):
            _hero_rejected = True
            _hero_reject_reason = "not_hero_quality"
        if _commodity_suppressed:
            _hero_reason = "Commodity card: no premium signal — hero board excluded"
        elif _commercial_bucket == "WEAK":
            _hero_reason = "Commercial desirability too weak for hero board"
        elif not _target_bid_ready and _mv_conf == "LOW":
            _hero_reason = "No valid bid lane and low pricing confidence"
        elif not _mv_resolved:
            _hero_reason = "No usable market value yet"
        elif _edge_dollars < 8.0 and not (_has_serial or _has_auto or _scarce_support):
            _hero_reason = "Dollar profit too thin for commodity card"
        elif _commercial < 10.0:
            _hero_reason = "Commercial appeal too generic for hero board"
        elif _common_modern_exact:
            _hero_reason = "Common modern card belongs in review until exact support strengthens"
        else:
            _hero_reason = "Better suited to watchlist than hero board"

    return {
        "sniper_board_score": round(_score, 1),
        "hero_board_eligible": bool(_eligible),
        "hero_tier": _hero_tier,
        "hero_reason": _hero_reason,
        "hero_rejected": bool(_hero_rejected),
        "hero_reject_reason": _hero_reject_reason,
        "sniper_candidate": bool(_endgame_gate.get("sniper_candidate")) and not _single_comp_clone_block,
        "commercial_signal_score": round(_commercial, 1),
        "commercial_score": _commercial_score,
        "commercial_bucket": _commercial_bucket,
        "commercial_reasons": _commercial_reasons,
    }


def _compute_commercial_visibility(row: Dict[str, Any]) -> Dict[str, Any]:
    _r = row or {}
    _current_price = 0.0
    try:
        _current_price = float(_r.get("current_price") or _r.get("current_bid") or 0.0)
    except (TypeError, ValueError):
        _current_price = 0.0
    _expected_profit = 0.0
    try:
        _expected_profit = float(
            _r.get("edge_dollars")
            or (_r.get("action_summary") or {}).get("expected_profit")
            or 0.0
        )
    except (TypeError, ValueError):
        _expected_profit = 0.0
    _commercial = float(_r.get("commercial_signal_score") or 0.0)
    _actionable = bool(_r.get("is_actionable_bid"))
    _target_bid_ready = bool(_r.get("bid_ceiling_ready")) or bool(_r.get("target_bid_ready"))
    _identity_clean = _is_clean_bid_identity(_r)
    _exact_surface = _row_exact_surface_candidate(_r)
    _suppressed = str(_r.get("row_quality_state") or "").strip().lower() == "suppressed"
    _not_junk = not any(_tok in f" {str(_r.get('source_title') or _r.get('title') or '').strip().lower()} " for _tok in _NOISY_TOKENS)
    try:
        _mv = float(_r.get("market_value") or _r.get("mv_value") or 0.0)
    except (TypeError, ValueError):
        _mv = 0.0
    try:
        _edge_pct = float(_r.get("edge_pct") or _r.get("edge_percent") or 0.0)
    except (TypeError, ValueError):
        _edge_pct = 0.0
    _commercial_bucket = str(_r.get("commercial_bucket") or "WEAK").strip().upper()
    _commercially_suppressed = bool(_r.get("commercially_suppressed"))
    _commodity_suppressed = bool(_r.get("commodity_suppressed"))
    _commodity_reason = str(_r.get("commodity_reason") or "").strip()
    _endgame_tier = str(_r.get("endgame_tier") or "").strip().lower()
    _lane_tier = str(_r.get("lane_tier") or "").strip().lower()
    _common_insert = bool(_r.get("commercial_common_insert"))
    _source = str(_r.get("mv_source") or _r.get("market_value_source") or "").strip().lower()
    _support_flags = dict(_r.get("commercial_support_flags") or {})
    _scarce_support = bool(_support_flags.get("serial") or _support_flags.get("auto") or _support_flags.get("scarcity"))
    _premium_secondary_floor = _passes_non_endgame_watchlist_floor(_r)
    _confidence_gate = _premium_confidence_gate(_r)
    _commodity_watch_block = bool(
        _commodity_suppressed
        and _endgame_tier != "endgame"
        and _lane_tier != "elite"
        and _commercial_bucket != "ELITE"
    )

    _price_floor_pass = _current_price >= 10.0
    _profit_floor_pass = _expected_profit >= 8.0
    _floor_exception = False
    _floor_exception_reason = ""
    if (
        not _price_floor_pass
        and _actionable
        and _target_bid_ready
        and _commercial >= 26.0
        and _expected_profit >= 15.0
        and _identity_clean
    ):
        _price_floor_pass = True
        _floor_exception = True
        _floor_exception_reason = "Elite low-dollar exception — exceptional edge after friction"

    _commercially_visible = bool(
        not _commercially_suppressed
        and not _commodity_watch_block
        and bool(_confidence_gate.get("allow_watch"))
        and _commercial_bucket in {"MID", "STRONG", "ELITE"}
        and _target_bid_ready
        and _mv > 0
        and _expected_profit >= 4.0
        and _premium_secondary_floor
        and _identity_clean
        and _not_junk
        and not _suppressed
    )
    _watch_override = bool(
        _is_watchlist_salvage_candidate(_r)
        and not _commodity_watch_block
        and bool(_confidence_gate.get("allow_watch"))
        and _premium_secondary_floor
        and _exact_surface
        and _identity_clean
        and _target_bid_ready
        and _not_junk
        and not _suppressed
    )
    if _watch_override:
        _commercially_visible = True
    if _commercially_suppressed:
        _reason = str(_r.get("commercial_suppression_reason") or "Commercially suppressed")
    elif _commodity_watch_block:
        _reason = _commodity_reason or "Commodity row blocked from premium-secondary visibility"
    elif bool(_confidence_gate.get("force_drop")):
        _reason = str(_confidence_gate.get("reason") or "Premium confidence gate blocked visibility")
    elif _commercial_bucket == "WEAK":
        _reason = "Commercial bucket too weak for board visibility"
    elif not _premium_secondary_floor:
        _reason = "Non-endgame row below $150 price / $50 edge floor"
    elif _price_floor_pass is False and _current_price <= 3.0 and _expected_profit < 8.0:
        _reason = "Tiny-ticket card below sniper floor"
    elif _common_insert and _source in {"structured_fallback", "price_anchor_fallback"} and not _scarce_support:
        _reason = "Common insert fallback without scarcity support"
    elif _commercially_visible:
        _reason = "Exact fallback watch override" if _watch_override else "Commercial floor passed"
    elif not _price_floor_pass:
        _reason = "Below commercial price floor"
    elif not _profit_floor_pass and _commercial < 24.0:
        _reason = "Expected profit too thin after friction"
    elif not _identity_clean:
        _reason = "Identity not clean enough for commercial surfacing"
    else:
        _reason = "Commercial review only"

    return {
        "commercial_price_floor_pass": bool(_price_floor_pass),
        "commercial_profit_floor_pass": bool(_profit_floor_pass),
        "commercially_visible": bool(_commercially_visible),
        "commercial_visibility_reason": _reason,
        "floor_exception": bool(_floor_exception),
        "floor_exception_reason": _floor_exception_reason,
    }


def _final_execution_admission_score(row: Dict[str, Any]) -> float:
    _r = row or {}
    _sniper = float(_r.get("sniper_board_score") or 0.0)
    _exec = float(_r.get("execution_score") or 0.0)
    _commercial = float(_r.get("commercial_signal_score") or 0.0)
    _edge_pct = float(_r.get("edge_pct") or _r.get("edge_percent") or 0.0)
    try:
        _edge_dollars = float(
            _r.get("edge_dollars")
            or (_r.get("action_summary") or {}).get("expected_profit")
            or 0.0
        )
    except (TypeError, ValueError):
        _edge_dollars = 0.0
    _comp_count = int(_r.get("comp_count") or _r.get("mv_comp_count") or 0)
    _price = float(_r.get("current_price") or _r.get("current_bid") or 0.0)
    _mv_conf = str(_r.get("mv_confidence_strict") or _r.get("mv_confidence") or "LOW").strip().upper()
    _bid_conf = str(_r.get("bid_ceiling_confidence") or _r.get("target_bid_confidence") or "NONE").strip().upper()
    _secs = float(_row_remaining_seconds(_r) or 999999.0)
    _score = 0.0
    _score += min(26.0, _sniper * 0.28)
    _score += min(20.0, _exec * 0.18)
    _score += min(16.0, max(0.0, _edge_pct) * 0.65)
    _score += min(18.0, max(0.0, _edge_dollars) * 0.9)
    _score += min(12.0, _comp_count * 1.8)
    _score += min(12.0, _commercial * 0.35)
    _score += {"HIGH": 12.0, "MEDIUM": 8.0, "LOW": 0.0}.get(_mv_conf, 0.0)
    _score += {"HIGH": 14.0, "MEDIUM": 10.0, "REVIEW": 5.0, "NONE": -14.0}.get(_bid_conf, -14.0)
    if _price >= 40.0:
        _score += 10.0
    elif _price >= 25.0:
        _score += 8.0
    elif _price >= 15.0:
        _score += 5.0
    elif _price >= 10.0:
        _score += 2.0
    elif _price >= 8.0:
        _score -= 2.0
    else:
        _score -= 10.0
    if _secs <= 900:
        _score += 6.0
    elif _secs <= 3600:
        _score += 3.0
    if not bool(_r.get("bid_ceiling_ready")) and not bool(_r.get("target_bid_ready")):
        _score -= 22.0
    if not (bool(_r.get("mv_resolved")) or bool(_r.get("mv_valid"))):
        _score -= 18.0
    _truth = str(_r.get("valuation_truth_tier") or "").strip().upper()
    _support_profile = _support_truth_profile(_r)
    if _truth == "TRUE" and not bool(_support_profile.get("is_support_source")):
        _score += 12.0
    elif _truth == "TRUE" and bool(_support_profile.get("support_truth_true")):
        _score += 3.0
    elif bool(_support_profile.get("is_support_source")):
        _score -= 8.0
    if str(_r.get("rescue_trust_tier") or "none").strip().lower() != "none":
        _score -= 30.0
    if not _is_clean_bid_identity(_r):
        _score -= 30.0
    return float(max(0.0, min(100.0, _score)))


def _lookup_player_id_by_name(player_name: str) -> str:
    _needle = str(player_name or "").strip().lower()
    if not _needle:
        return ""
    for _pid, _row in (player_hub.players_by_id() or {}).items():
        if str((_row or {}).get("player_name") or "").strip().lower() == _needle:
            return str(_pid)
    return ""


