def _truth_case_target_spec(case: Dict[str, Any], state: Dict[str, Any]) -> Dict[str, Any]:
    _target_id = str(case.get("target_id") or "").strip()
    _target_meta = player_hub.get_product_target(state, _target_id) or {}
    _player_name = str(case.get("target_entity") or "").strip()
    _player_id = str(case.get("target_entity_id") or _lookup_player_id_by_name(_player_name))
    return {
        "target_id": _target_id,
        "target_label": str((_target_meta or {}).get("label") or _target_id),
        "target_meta": player_hub.resolve_effective_product_target_meta(_target_meta),
        "player_id": _player_id,
        "player_name": _player_name,
        "feed_type": str(case.get("expected_feed_type") or "auction").strip().lower(),
    }


def _truth_case_seed_row(case: Dict[str, Any], spec: Dict[str, Any]) -> Dict[str, Any]:
    _feed_type = str(case.get("expected_feed_type") or spec.get("feed_type") or "auction").strip().lower()
    _row = {
        "title": str(case.get("title") or ""),
        "item_id": str(case.get("case_id") or ""),
        "url": str(case.get("url") or ""),
        "feed_type": _feed_type,
        "scan_source": "ending_soon" if _feed_type == "auction" else "buying_radar",
        "target_entity_id": str(spec.get("player_id") or ""),
        "target_id": str(spec.get("target_id") or ""),
        "target_label": str(spec.get("target_label") or ""),
        "target_product_family": str((spec.get("target_meta") or {}).get("set_name") or ""),
        "player_name": str(spec.get("player_name") or ""),
        "current_price": float(case.get("current_price") or 50.0),
        "market_value": float(case.get("market_value") or 0.0) if case.get("market_value") is not None else None,
        "market_value_source": str(case.get("market_value_source") or ("none" if case.get("expected_outcome") == "reject_prevaluation" else "hybrid_exact_lane")),
        "mv_confidence": str(case.get("mv_confidence") or "LOW"),
        "confidence": str(case.get("mv_confidence") or "LOW"),
        "comp_count": int(case.get("comp_count") or 0),
        "deal_class": str(case.get("deal_class") or ("UNKNOWN" if case.get("expected_outcome") == "reject_prevaluation" else "GOOD")),
        "edge_pct": float(case.get("edge_pct") or 0.0),
        "seconds_remaining": case.get("seconds_remaining"),
        "insufficient_data": bool(case.get("insufficient_data", False if case.get("market_value") else True)),
        "lane_approved": bool(case.get("lane_approved", True)),
        "exact_entity_match": bool(case.get("exact_entity_match", True)),
        "entity_match_status": str(case.get("entity_match_status") or ("EXACT_MATCH" if bool(case.get("exact_entity_match", True)) else "NO_MATCH")).strip().upper(),
        "entity_match_score": float(case.get("entity_match_score") or (1.0 if bool(case.get("exact_entity_match", True)) else 0.0)),
    }
    return _row


def _outcome_from_row(row: Dict[str, Any]) -> str:
    _quality = str((row or {}).get("row_quality_state") or "")
    if _quality == "quarantined":
        return "quarantine"
    if bool((row or {}).get("alert_eligible")):
        return "admit_and_alert"
    return "admit_monitor_only"


def evaluate_ground_truth_case(case: Dict[str, Any], *, state: Optional[Dict[str, Any]] = None) -> Dict[str, Any]:
    _state = state or player_hub.load_player_hub_state()
    _spec = _truth_case_target_spec(case, _state)
    _title = str(case.get("title") or "")
    _ok, _reason, _entity_status, _entity_score, _alias_soft_match = _validate_spec_listing(_title, _spec)
    _result: Dict[str, Any] = {
        "case_id": str(case.get("case_id") or ""),
        "title": _title,
        "expected_outcome": str(case.get("expected_outcome") or ""),
        "expected_quality_state": str(case.get("expected_quality_state") or ""),
        "expected_alert_eligible": bool(case.get("expected_alert_eligible")),
        "expected_rejection_bucket": str(case.get("expected_rejection_bucket") or ""),
    }
    if not _ok:
        _bucket = _target_gate_bucket(_reason)
        _actual = {
            "entity_match_status": _entity_status,
            "entity_match_score": _entity_score,
            "product_match_status": "rejected_prevaluation",
            "lane_match_status": "rejected_prevaluation",
            "valuation_basis": "not_run",
            "comp_quality": "none",
            "alert_eligibility_reason": "prevaluation_reject",
            "ranking_reason_primary": f"Rejected before valuation ({_bucket})",
            "ranking_reason_secondary": _reason,
            "row_quality_state": "quarantined",
            "alert_eligible": False,
            "actual_outcome": "reject_prevaluation",
            "actual_rejection_bucket": _bucket,
        }
        _result.update(_actual)
    else:
        _row = _truth_case_seed_row(case, _spec)
        _row["entity_match_status"] = _entity_status
        _row["entity_match_score"] = _entity_score
        _row["exact_entity_match"] = _entity_status == "EXACT_MATCH"
        _row["alias_soft_match"] = bool(_alias_soft_match)
        _row = _stamp_alert_contract(_row, expected_feed=str(_row.get("feed_type") or ""), expected_scan_source=str(_row.get("scan_source") or ""))
        _row["actual_outcome"] = _outcome_from_row(_row)
        _result.update({
            "entity_match_status": _row.get("entity_match_status"),
            "product_match_status": _row.get("product_match_status"),
            "lane_match_status": _row.get("lane_match_status"),
            "valuation_basis": _row.get("valuation_basis"),
            "comp_quality": _row.get("comp_quality"),
            "alert_eligibility_reason": _row.get("alert_eligibility_reason"),
            "ranking_reason_primary": _row.get("ranking_reason_primary"),
            "ranking_reason_secondary": _row.get("ranking_reason_secondary"),
            "row_quality_state": _row.get("row_quality_state"),
            "alert_eligible": bool(_row.get("alert_eligible")),
            "actual_outcome": _row.get("actual_outcome"),
            "actual_rejection_bucket": "",
        })
    _result["matched"] = bool(
        _result.get("expected_outcome") == _result.get("actual_outcome")
        and str(_result.get("expected_quality_state") or "") == str(_result.get("row_quality_state") or "")
        and bool(_result.get("expected_alert_eligible")) == bool(_result.get("alert_eligible"))
    )
    return _result


def run_ground_truth_evaluation(cases: Optional[List[Dict[str, Any]]] = None) -> Dict[str, Any]:
    _cases = cases or _default_truth_set_cases()
    _state = player_hub.load_player_hub_state()
    _results = [evaluate_ground_truth_case(_case, state=_state) for _case in _cases]
    _mismatches = [r for r in _results if not bool(r.get("matched"))]

    def _precision(expected_predicate, actual_predicate) -> float:
        _pred = [r for r in _results if actual_predicate(r)]
        if not _pred:
            return 1.0
        _tp = sum(1 for r in _pred if expected_predicate(r))
        return round(_tp / max(1, len(_pred)), 3)

    _wrong_entity_cases = [r for r in _results if str(r.get("expected_rejection_bucket") or "") == "wrong_entity"]
    _wrong_product_cases = [r for r in _results if str(r.get("expected_rejection_bucket") or "") == "wrong_product_family"]
    _scorecard = {
        "cases_total": len(_results),
        "matched_total": sum(1 for r in _results if bool(r.get("matched"))),
        "mismatches_total": len(_mismatches),
        "admission_precision": _precision(
            lambda r: str(r.get("expected_outcome") or "") != "reject_prevaluation",
            lambda r: str(r.get("actual_outcome") or "") != "reject_prevaluation",
        ),
        "wrong_entity_rejection_rate": round(
            sum(1 for r in _wrong_entity_cases if str(r.get("actual_rejection_bucket") or "") == "wrong_entity") / max(1, len(_wrong_entity_cases)),
            3,
        ),
        "wrong_product_rejection_rate": round(
            sum(1 for r in _wrong_product_cases if str(r.get("actual_rejection_bucket") or "") == "wrong_product_family") / max(1, len(_wrong_product_cases)),
            3,
        ),
        "execution_ready_precision": _precision(
            lambda r: str(r.get("expected_quality_state") or "") == "execution_ready",
            lambda r: str(r.get("row_quality_state") or "") == "execution_ready",
        ),
        "monitor_only_precision": _precision(
            lambda r: str(r.get("expected_quality_state") or "") == "monitor_only",
            lambda r: str(r.get("row_quality_state") or "") == "monitor_only",
        ),
        "quarantine_accuracy": round(
            sum(1 for r in _results if (str(r.get("expected_quality_state") or "") == "quarantined") == (str(r.get("row_quality_state") or "") == "quarantined")) / max(1, len(_results)),
            3,
        ),
        "alert_precision": _precision(
            lambda r: bool(r.get("expected_alert_eligible")),
            lambda r: bool(r.get("alert_eligible")),
        ),
    }
    return {
        "scorecard": _scorecard,
        "results": _results,
        "mismatches": [
            {
                "case_id": r.get("case_id"),
                "title": r.get("title"),
                "expected_outcome": r.get("expected_outcome"),
                "actual_outcome": r.get("actual_outcome"),
                "expected_quality_state": r.get("expected_quality_state"),
                "actual_quality_state": r.get("row_quality_state"),
                "expected_alert_eligible": r.get("expected_alert_eligible"),
                "actual_alert_eligible": r.get("alert_eligible"),
                "entity_match_status": r.get("entity_match_status"),
                "product_match_status": r.get("product_match_status"),
                "lane_match_status": r.get("lane_match_status"),
                "valuation_basis": r.get("valuation_basis"),
                "comp_quality": r.get("comp_quality"),
                "alert_eligibility_reason": r.get("alert_eligibility_reason"),
                "ranking_reason_primary": r.get("ranking_reason_primary"),
                "ranking_reason_secondary": r.get("ranking_reason_secondary"),
                "actual_rejection_bucket": r.get("actual_rejection_bucket"),
            }
            for r in _mismatches
        ],
    }


# ---------------------------------------------------------------------------
# eBay helpers
# ---------------------------------------------------------------------------

def _parse_end_dt(iso_str: str) -> Optional[datetime]:
    if not iso_str:
        return None
    try:
        s = re.sub(r"\.\d+", "", str(iso_str).strip().replace("Z", "+00:00"))
        dt = datetime.fromisoformat(s)
        return dt.replace(tzinfo=timezone.utc) if dt.tzinfo is None else dt
    except Exception:
        return None


def _extract_auction_end_dt(item: Dict[str, Any]) -> Optional[datetime]:
    _row = item or {}
    _direct_dt = _row.get("end_dt")
    if isinstance(_direct_dt, datetime):
        return _direct_dt.replace(tzinfo=timezone.utc) if _direct_dt.tzinfo is None else _direct_dt.astimezone(timezone.utc)
    for _field in ("itemEndDate", "end_iso", "end_time", "endDate"):
        _parsed = _parse_end_dt(str(_row.get(_field) or "").strip())
        if _parsed is not None:
            return _parsed.astimezone(timezone.utc)
    return None


def seconds_left(end_dt: Optional[datetime], now_dt: Optional[datetime] = None) -> Optional[float]:
    if end_dt is None:
        return None
    _now = now_dt
    if not isinstance(_now, datetime):
        _now = datetime.now(tz=timezone.utc)
    elif _now.tzinfo is None:
        _now = _now.replace(tzinfo=timezone.utc)
    else:
        _now = _now.astimezone(timezone.utc)
    diff = (end_dt.astimezone(timezone.utc) - _now).total_seconds()
    return diff


def _authoritative_time_contract(row: Dict[str, Any]) -> Dict[str, Any]:
    try:
        if not isinstance(row, dict):
            return {"ok": False, "reason": "not_dict"}
        _remaining = row.get("remaining_seconds")
        if _remaining is None:
            _remaining = row.get("seconds_remaining")
        _end_time = row.get("end_time") or row.get("itemEndDate") or row.get("endDate")
        _listing_type = str(row.get("listing_type") or "").strip().lower()
        _has_remaining = _remaining is not None
        _has_end_time = bool(_end_time)
        return {
            "ok": bool((_listing_type in {"auction", "auction_with_bin", ""}) and (_has_remaining or _has_end_time)),
            "reason": "authoritative_remaining_or_end_time" if (_has_remaining or _has_end_time) else "missing_remaining_and_end_time",
            "remaining_seconds": _remaining,
            "end_time": _end_time,
        }
    except Exception as e:
        return {"ok": False, "reason": f"error:{e}"}


def _window_bucket_label(seconds_remaining: Optional[float]) -> str:
    if seconds_remaining is None:
        return "missing"
    if seconds_remaining < 0:
        return "expired"
    if seconds_remaining <= 900:
        return "<15m"
    if seconds_remaining <= 3600:
        return "<1h"
    if seconds_remaining <= 10800:
        return "<3h"
    if seconds_remaining <= 21600:
        return "<6h"
    return ">6h"


def _ebay_auth_headers() -> Dict[str, str]:
    # ── ENV CHECK (once per process; no secrets printed) ─────────────────────
    # Reports presence/absence of the OAuth credentials and marketplace var.
    # Values themselves are NEVER printed — only "present" / "missing".
    if not getattr(_ebay_auth_headers, "_env_check_emitted", False):
        try:
            import os as _os
            _cid_present  = bool((_os.getenv("EBAY_CLIENT_ID")     or "").strip())
            _csec_present = bool((_os.getenv("EBAY_CLIENT_SECRET") or "").strip())
            _mkt_raw      = (_os.getenv("EBAY_MARKETPLACE_ID")     or "").strip()
            _cid_status   = "present" if _cid_present  else "missing"
            _csec_status  = "present" if _csec_present else "missing"
            _mkt_status   = "present" if _mkt_raw      else "default(EBAY_US)"
        except Exception as _env_exc:
            _cid_status = _csec_status = _mkt_status = (
                f"check_error_{type(_env_exc).__name__}"
            )
        print(
            f"[EBAY_AUTH_ENV_CHECK] EBAY_CLIENT_ID={_cid_status} "
            f"EBAY_CLIENT_SECRET={_csec_status} "
            f"EBAY_MARKETPLACE_ID={_mkt_status}"
        )
        try:
            _ebay_auth_headers._env_check_emitted = True  # type: ignore[attr-defined]
        except Exception:
            pass

    # ── ATTEMPT ──────────────────────────────────────────────────────────────
    print("[EBAY_AUTH_ATTEMPT] source=ebay_search._get_application_access_token_str")

    # ── TOKEN FETCH (catches every exception class; surfaces error_type only) ─
    try:
        token = ebay_search._get_application_access_token_str()
    except Exception as _auth_exc:
        print(
            f"[EBAY_AUTH_FAIL] stage=token_fetch "
            f"error_type={type(_auth_exc).__name__}"
        )
        raise

    # ── EMPTY-TOKEN GUARD ────────────────────────────────────────────────────
    # The OAuth call can succeed at HTTP layer but return an empty/whitespace
    # token (sandbox quirks, malformed JSON).  Treat that as a hard auth fail
    # rather than letting a Bearer="" header reach the Browse API and cascade
    # into 401s that are easy to misclassify.
    if not token or not str(token).strip():
        print("[EBAY_AUTH_FAIL] stage=token_validation error_type=EmptyToken")
        raise RuntimeError("eBay auth returned empty token")

    # ── SUCCESS ──────────────────────────────────────────────────────────────
    # No secrets in this log — only that a token was obtained.
    print("[EBAY_AUTH_SUCCESS] token=present")

    return {
        "Authorization":           f"Bearer {token}",
        "X-EBAY-C-MARKETPLACE-ID": ebay_search.EBAY_MARKETPLACE_ID,
    }


def _parse_price(item: Dict[str, Any]) -> float:
    price_obj = item.get("price") or {}
    try:
        return float(str(price_obj.get("value") or 0).replace(",", ""))
    except (ValueError, TypeError):
        return 0.0


def _parse_auction_current_price(item: Dict[str, Any]) -> float:
    """
    For auction rows: return the CURRENT BID price, not BIN/fixed price.
    eBay Browse API puts BIN price in 'price.value' for AUCTION+FIXED_PRICE listings.
    The actual current bid is in 'currentBidPrice.value'.
    """
    _item = item or {}
    _bid_obj = _item.get("currentBidPrice") or {}
    try:
        _bid = float(str(_bid_obj.get("value") or 0).replace(",", ""))
    except (ValueError, TypeError):
        _bid = 0.0
    if _bid > 0:
        return _bid
    return _parse_price(_item)


def _parse_buy_now_price(item: Dict[str, Any]) -> Optional[float]:
    """Return BIN price for AUCTION+BIN listings, else None."""
    _mode = _parse_browse_listing_mode(item or {})
    if _mode != "auction_or_bin":
        return None
    try:
        _bin = float(str(((item or {}).get("price") or {}).get("value") or 0).replace(",", ""))
    except (ValueError, TypeError):
        _bin = 0.0
    return _bin if _bin > 0 else None


def _stamp_source_listing_truth(row: Dict[str, Any]) -> Dict[str, Any]:
    """
    Derive and stamp canonical source truth fields onto a row.
    For AUCTION rows: source_display_price and current_price are the auction bid,
    never the BIN price. source_buy_now_price stores the BIN price separately.
    source_time_remaining_seconds is recomputed live from source_end_time.
    """
    _r = row
    _contract = _authoritative_auction_contract(_r)
    if _contract.get("item_id"):
        _r["item_id"] = str(_contract.get("item_id") or "")
    if _contract.get("title"):
        _r["title"] = str(_contract.get("title") or "")
    if _contract.get("url"):
        _r["url"] = str(_contract.get("url") or "")
    if _contract.get("thumbnail"):
        _r["thumbnail"] = str(_contract.get("thumbnail") or "")
    if _contract.get("end_dt") is not None and not isinstance(_r.get("end_dt"), datetime):
        _r["end_dt"] = _contract.get("end_dt")
    if _contract.get("end_iso"):
        _r["end_iso"] = str(_contract.get("end_iso") or "")
    if _contract.get("buyingOptions") and not _r.get("buyingOptions"):
        _r["buyingOptions"] = list(_contract.get("buyingOptions") or [])
    if _contract.get("currentBidPrice") and not _r.get("currentBidPrice"):
        _r["currentBidPrice"] = dict(_contract.get("currentBidPrice") or {})
    if _contract.get("normalized_entity") and not str(_r.get("normalized_entity") or "").strip():
        _r["normalized_entity"] = str(_contract.get("normalized_entity") or "")
    if _contract.get("_source_contract") and not isinstance(_r.get("_source_contract"), dict):
        _r["_source_contract"] = dict(_contract.get("_source_contract") or {})
    _stamp_normalized_entity(_r)
    _mode = _parse_browse_listing_mode(_r)
    _is_auction = _mode in {"auction", "auction_or_bin"}
    _r["source_item_id"] = str(_r.get("source_item_id") or _contract.get("item_id") or _r.get("item_id") or "")
    _r["source_listing_type"] = _mode
    _r["source_title"] = str(_r.get("source_title") or _contract.get("title") or _r.get("title") or "")
    _r["source_image_url"] = str(_r.get("source_image_url") or _contract.get("thumbnail") or _r.get("thumbnail") or _r.get("image_url") or "")
    _r["source_view_url"] = str(_r.get("source_view_url") or _contract.get("url") or _r.get("url") or "")
    _r["source_end_time"] = str(_r.get("source_end_time") or _contract.get("end_iso") or _r.get("end_iso") or "")
    # Recompute remaining seconds live from source_end_time (accurate at render time)
    _end_dt = _parse_end_dt(_r["source_end_time"])
    if _end_dt is None and isinstance(_contract.get("end_dt"), datetime):
        _end_dt = _contract.get("end_dt")
        _r["source_end_time"] = _end_dt.astimezone(timezone.utc).isoformat().replace("+00:00", "Z")
    if _end_dt is not None:
        _now_utc = datetime.now(tz=timezone.utc)
        _secs = (_end_dt - _now_utc).total_seconds()
        if _secs > 86400 * 30:
            _secs = _secs / 1000.0  # milliseconds guard
        _r["source_time_remaining_seconds"] = max(0.0, _secs)
        # Keep remaining_seconds in sync so existing display helpers pick it up
        _r["remaining_seconds"] = _r["source_time_remaining_seconds"]
        _r["seconds_remaining"] = _r["source_time_remaining_seconds"]
    else:
        _r["source_time_remaining_seconds"] = _contract.get("remaining_seconds", _r.get("remaining_seconds"))
    # Price truth
    if _is_auction:
        # For auction rows: current_price must be the auction bid, not BIN price
        _auction_bid = 0.0
        _cbp = (_r.get("currentBidPrice") or {})
        try:
            _auction_bid = float(str(_cbp.get("value") or 0).replace(",", ""))
        except (ValueError, TypeError):
            _auction_bid = 0.0
        if _auction_bid <= 0:
            # already-lifted field: current_price was set at row-build time
            # if it was set from _parse_auction_current_price, it's already correct
            _auction_bid = float(_r.get("current_bid") or _r.get("current_price") or 0.0)
        # BIN price: original price field if AUCTION+BIN
        _bin_price: Optional[float] = None
        if _mode == "auction_or_bin":
            _bp = (_r.get("buy_now_price"))
            if _bp is not None:
                try:
                    _bin_price = float(_bp)
                except (TypeError, ValueError):
                    _bin_price = None
        _r["source_current_bid"] = _auction_bid
        _r["source_buy_now_price"] = _bin_price
        _r["source_display_price"] = _auction_bid
        _r["source_price_kind"] = "auction_bid"
        # Overwrite current_price so all downstream helpers see the correct value
        if _auction_bid > 0:
            _r["current_price"] = _auction_bid
            _r["current_bid"] = _auction_bid
    else:
        _fixed = float(_r.get("current_price") or 0.0)
        _r["source_current_bid"] = 0.0
        _r["source_buy_now_price"] = _fixed if _fixed > 0 else None
        _r["source_display_price"] = _fixed
        _r["source_price_kind"] = "fixed_price"
    return _r


def _fetch_auctions_for_spec(
    spec: Dict[str, Any],
    time_window_hours: float,
) -> Tuple[List[Dict[str, Any]], bool, int]:
    """
    Fetch auction listings ending within time_window_hours for one player spec.
    Returns (items_passed_filter, rate_limited, pre_filter_count).
    """
    _api_throttle()   # rate-limit: 0.5s minimum between eBay calls
    try:
        headers = _ebay_auth_headers()
    except Exception as e:
        print(f"[ES] Auth error: {e}")
        _progress_tick(spec.get("player_name", ""))
        return [], False, 0

    params = {
        "q":      spec["query"],
        "filter": (
            f"buyingOptions:{{AUCTION}},"
            f"price:[{MIN_PRICE:.0f}..{MAX_PRICE:.0f}],"
            f"priceCurrency:USD"
        ),
        "sort":  "endingSoonest",
        # eBay Browse API max is 200. Bumped to 100 (2x baseline 50) — gives
        # popular lanes more room without the brutal scan-time amplification
        # we saw at 200 (more raw rows = more parse + filter + valuation work
        # downstream).
        "limit": 100,
    }

    print(
        f"[PRICE_RANGE_APPLIED] min={MIN_PRICE:.0f} max={MAX_PRICE:.0f}"
    )
    try:
        resp = requests.get(
            "https://api.ebay.com/buy/browse/v1/item_summary/search",
            headers=headers, params=params, timeout=20,
        )
    except requests.RequestException as e:
        print(f"[ES] Request error ({spec['player_name']}): {e}")
        return [], False, 0

    if resp.status_code == 429:
        print(f"[ES] Rate limited on {spec['player_name']}")
        return [], True, 0
    if resp.status_code != 200:
        print(f"[ES] HTTP {resp.status_code} for {spec['player_name']}: {resp.text[:200]}")
        return [], False, 0

    try:
        items = resp.json().get("itemSummaries", []) or []
    except Exception:
        return [], False, 0

    cutoff = datetime.now(tz=timezone.utc) + timedelta(hours=time_window_hours)
    now    = datetime.now(tz=timezone.utc)
    tier   = spec.get("whatnot_tier", 3)

    out: List[Dict[str, Any]] = []
    pre_filter_count = 0
    for item in items:
        if not isinstance(item, dict):
            continue
        end_dt = _parse_end_dt(item.get("itemEndDate") or "")
        if end_dt is None or end_dt <= now or end_dt > cutoff:
            continue
        price = _parse_price(item)
        if not (MIN_PRICE <= price <= MAX_PRICE):
            continue
        title = str(item.get("title") or "")
        pre_filter_count += 1
        if not _passes_grade_filter(title):
            continue
        if not _passes_card_type_filter(title, tier):
            continue
        out.append({
            "item_id":       str(item.get("itemId") or ""),
            "title":         title,
            "current_price": price,
            "end_dt":        end_dt,
            "end_iso":       item.get("itemEndDate") or "",
            "url":           str(item.get("itemWebUrl") or ""),
            "thumbnail":     (item.get("image") or {}).get("imageUrl") or "",
            "player_name":   spec["player_name"],
            "sport":         spec["sport"],
            "whatnot_tier":  spec.get("whatnot_tier"),
            "listing_type":  "AUCTION",
        })
    _progress_tick(spec.get("player_name", ""))
    return out, False, pre_filter_count


def _fetch_bin_for_spec(spec: Dict[str, Any]) -> Tuple[List[Dict[str, Any]], bool, int]:
    """
    Fetch BIN (Fixed Price) listings for one player spec, newest first.
    Returns (items_passed_filter, rate_limited, pre_filter_count).
    """
    _api_throttle()   # rate-limit: 0.5s minimum between eBay calls
    try:
        headers = _ebay_auth_headers()
    except Exception:
        _progress_tick(spec.get("player_name", ""))
        return [], False, 0

    params = {
        "q":      spec["query"],
        "filter": (
            f"buyingOptions:{{FIXED_PRICE}},"
            f"price:[{MIN_PRICE:.0f}..{MAX_PRICE:.0f}],"
            f"priceCurrency:USD"
        ),
        "sort":  "newlyListed",
        # 20 → 50 (2.5x baseline). 100 was too aggressive given each lane
        # also runs comp search on hits. Balance fetch breadth vs scan time.
        "limit": 50,
    }

    try:
        resp = requests.get(
            "https://api.ebay.com/buy/browse/v1/item_summary/search",
            headers=headers, params=params, timeout=20,
        )
    except requests.RequestException:
        return [], False, 0

    if resp.status_code == 429:
        return [], True, 0
    if resp.status_code != 200:
        return [], False, 0

    try:
        items = resp.json().get("itemSummaries", []) or []
    except Exception:
        return [], False, 0

    tier = spec.get("whatnot_tier", 3)
    out: List[Dict[str, Any]] = []
    pre_filter_count = 0
    for item in items:
        if not isinstance(item, dict):
            continue
        price = _parse_price(item)
        if not (MIN_PRICE <= price <= MAX_PRICE):
            continue
        title = str(item.get("title") or "")
        pre_filter_count += 1
        if not _passes_grade_filter(title):
            continue
        if not _passes_card_type_filter(title, tier):
            continue
        out.append({
            "item_id":       str(item.get("itemId") or ""),
            "title":         title,
            "current_price": price,
            "end_dt":        None,
            "end_iso":       "",
            "url":           str(item.get("itemWebUrl") or ""),
            "thumbnail":     (item.get("image") or {}).get("imageUrl") or "",
            "player_name":   spec.get("player_name") or (spec.get("tracked_target") or {}).get("player_name") or "",
            "sport":         spec.get("sport") or (spec.get("tracked_target") or {}).get("sport") or "",
            "whatnot_tier":  spec.get("whatnot_tier"),
            "listing_type":  "BIN",
        })
    _progress_tick(spec.get("player_name", ""))
    return out, False, pre_filter_count


# ---------------------------------------------------------------------------
# Family-level retrieval recovery ladder — fallback variants + diagnostics
# ---------------------------------------------------------------------------

BIN_CANDIDATE_THRESHOLD = 1  # early-stop when >= this many viable candidates found
_AUCTION_VARIANT_CANDIDATE_THRESHOLD = 4

_DIAG_LOCK:       threading.Lock       = threading.Lock()
_LAST_SCAN_DIAGS: List[Dict[str, Any]] = []  # replaced after each scan
_LANE_YIELD_LOCK: threading.Lock       = threading.Lock()
_LANE_YIELD_STATE: Dict[str, Dict[str, Any]] = {}
_PLAYER_WINNER_LOCK: threading.Lock = threading.Lock()
_PLAYER_WINNER_STATE: Dict[str, Dict[str, Any]] = {}
_LANE_ZERO_COOLDOWN_STREAK = 3
_LANE_DEAD_WINDOW_COOLDOWN_STREAK = 2
# PATCH 4 — Zero-Return Kill Switch: after cooldown triggers, block for this many cycles
_LANE_COOLDOWN_CYCLES = 10
_LANE_LIVE_DEAD_BUFFER_SECONDS = 3600.0
_LANE_LIVE_COOLDOWN_CYCLES = 2
_MIN_LIVE_FETCH_LANES = 6
_DISCOVERY_PROBE_CONFIG_LOGGED = False
_PLAYER_ZERO_COOLDOWN_STREAK = 3
_PLAYER_COOLDOWN_CYCLES = 5


def get_last_scan_diags() -> List[Dict[str, Any]]:
    """Return a snapshot of per-family diagnostic records from the most recent scan."""
    with _DIAG_LOCK:
        return list(_LAST_SCAN_DIAGS)


def _run_bin_variant(
    spec: Dict[str, Any],
    variant: Dict[str, str],
) -> Dict[str, Any]:
    """
    Execute one BIN query variant and return a fully populated diag dict.
    items_out key holds candidate items on success; None if the variant failed.
    """
    tier = spec.get("whatnot_tier", 3)
    diag: Dict[str, Any] = {
        "family_id":             spec["player_name"],
        "family_key":            f"{spec.get('sport', '')}_{spec['player_name']}",
        "lane_key":              _lane_metric_key(spec),
        "target_id":             str(spec.get("target_id") or ""),
        "target_label":          str(spec.get("target_label") or spec.get("player_name") or ""),
        "player_id":             str(spec.get("player_id") or ""),
        "lane_tier":             str(spec.get("lane_tier") or "primary"),
        "lane_priority":         float(spec.get("lane_priority") or 0.0),
        "query_kind":            str(spec.get("query_kind") or ""),
        "target_lane_type":      str(spec.get("target_lane_type") or ""),
        "lane_subset":           str(spec.get("lane_subset") or ""),
        "lane_parallel":         str(spec.get("lane_parallel") or ""),
        "lane_product":          str(spec.get("lane_product") or spec.get("target_product_family") or ""),
        "spec_premium_lane":     bool(spec.get("spec_premium_lane")),
        "spec_lane_class":       str(spec.get("spec_lane_class") or ""),
        "scan_type":             "BIN",
        "query_variant_name":    variant["variant_name"],
        "query_text":            variant["query"],
        "raw_rows_count":        0,
        "bin_rows_count":        0,
        "title_pass_count":      0,
        "off_target_reject_count": 0,
        "shape_reject_count":      0,
        "rejection_reason_counts": {},
        "deduped_count":         0,
        "final_candidate_count": 0,
        "failure_stage":         None,
        "failure_reason":        None,
        "winning_variant":       False,
        "_items_out":            None,   # internal: List[Dict] on success
        "_rate_limited":         False,
        "_stop_ladder":          False,  # True when caller should not try more variants
    }

    # Jitter: randomized pre-call sleep breaks up burst patterns
    _circuit_jitter()
    # Circuit breaker: if in hard cooldown, defer this family instead of hammering eBay
    if not _circuit_pre_request():
        diag["failure_stage"]  = "rate_limit_deferred"
        diag["failure_reason"] = "circuit_breaker in cooldown — family queued for retry"
        diag["_rate_limited"]  = True
        diag["_stop_ladder"]   = True
        return diag

    _api_throttle()
    try:
        headers = _ebay_auth_headers()
    except Exception as exc:
        diag["failure_stage"] = "auth"
        diag["failure_reason"] = str(exc)[:160]
        diag["_stop_ladder"] = True   # auth failure is global
        return diag

    params = {
        "q":      variant["query"],
        "filter": (
            f"buyingOptions:{{FIXED_PRICE}},"
            f"price:[{MIN_PRICE:.0f}..{MAX_PRICE:.0f}],"
            f"priceCurrency:USD"
        ),
        "sort":  "newlyListed",
        "limit": 20,
    }

    try:
        resp = requests.get(
            "https://api.ebay.com/buy/browse/v1/item_summary/search",
            headers=headers, params=params, timeout=20,
        )
    except requests.RequestException as exc:
        diag["failure_stage"]  = "fetch"
        diag["failure_reason"] = str(exc)[:160]
        return diag   # network error — try next variant

    if resp.status_code == 429:
        _circuit_record_rl()   # update circuit breaker state
        diag["failure_stage"]  = "rate_limit_deferred"
        diag["failure_reason"] = "HTTP 429 — family deferred, not dead"
        diag["_rate_limited"]  = True
        diag["_stop_ladder"]   = True
        return diag

    if resp.status_code != 200:
        diag["failure_stage"]  = "http_error"
        diag["failure_reason"] = f"HTTP {resp.status_code}"
        return diag

    try:
        raw_items = resp.json().get("itemSummaries", []) or []
    except Exception as exc:
        diag["failure_stage"]  = "json_decode"
        diag["failure_reason"] = str(exc)[:120]
        return diag

    diag["raw_rows_count"] = len(raw_items)

    if not raw_items:
        diag["failure_stage"]  = "browse_zero_rows"
        diag["failure_reason"] = "eBay returned 0 items for this query"
        return diag

    in_price = [
        it for it in raw_items
        if isinstance(it, dict) and MIN_PRICE <= _parse_price(it) <= MAX_PRICE
    ]
    diag["bin_rows_count"] = len(in_price)

    if not in_price:
        diag["failure_stage"]  = "price_filter"
        diag["failure_reason"] = f"All {diag['raw_rows_count']} items outside price range"
        return diag

    title_passed: List[Dict[str, Any]] = []
    for it in in_price:
        t = str(it.get("title") or "")
        if _passes_grade_filter(t) and _passes_card_type_filter(t, tier):
            title_passed.append(it)

    diag["title_pass_count"] = len(title_passed)

    if not title_passed:
        diag["failure_stage"]  = "title_filter"
        diag["failure_reason"] = (
            f"{diag['bin_rows_count']} items in range but all failed grade/card-type filter"
        )
        return diag   # try next variant — different query may pull better matches

    candidates: List[Dict[str, Any]] = []
    for it in title_passed:
        _title = str(it.get("title") or "")
        _spec_for_item = dict(spec)
        _spec_for_item["_candidate_item_id"] = str(it.get("itemId") or "")
        _ok_target, _reason, _entity_status, _entity_score, _alias_soft_match = _validate_spec_listing(_title, _spec_for_item)
        _log_subset_product_match(_spec_for_item, str(it.get("itemId") or ""), decision=("pass" if _ok_target else "reject"), reason=str(_reason or "ok"))
        if not _ok_target:
            diag["off_target_reject_count"] = int(diag.get("off_target_reject_count") or 0) + 1
            _bucket = _target_gate_bucket(_reason)
            _rr = diag.setdefault("rejection_reason_counts", {})
            _rr[_bucket] = int(_rr.get(_bucket, 0) or 0) + 1
            if _bucket in {"oversized_downtown", "nonstandard_subset_variant"}:
                diag["shape_reject_count"] = int(diag.get("shape_reject_count") or 0) + 1
            continue
        candidates.append({
            "item_id":        str(it.get("itemId") or ""),
            "title":          _title,
            "current_price":  _parse_price(it),
            "end_dt":         None,
            "end_iso":        "",
            "url":            str(it.get("itemWebUrl") or ""),
            "thumbnail":      (it.get("image") or {}).get("imageUrl") or "",
            "player_name":    spec["player_name"],
            "player_id":      str(spec.get("player_id") or ""),
            "sport":          spec["sport"],
            "whatnot_tier":   spec.get("whatnot_tier"),
            "listing_type":   "BIN",
            "_query_variant": variant["variant_name"],
            "target_id":      str(spec.get("target_id") or ""),
            "target_label":   str(spec.get("target_label") or ""),
            "target_meta":    dict(spec.get("target_meta") or {}),
            "target_entity_id": str(spec.get("player_id") or ""),
            "exact_entity_match": _entity_status == "EXACT_MATCH",
            "entity_match_status": _entity_status,
            "entity_match_score": _entity_score,
            "alias_soft_match": bool(_alias_soft_match),
            "subset_name": str(spec.get("subset_name") or (spec.get("target_meta") or {}).get("subset_name") or spec.get("lane_subset") or ""),
            "subset_product_family": str(spec.get("subset_product_family") or (spec.get("target_meta") or {}).get("subset_product_family") or ""),
            "subset_binding_override": bool(spec.get("subset_binding_override") or (spec.get("target_meta") or {}).get("subset_binding_override")),
            "entity_gate_reason": "ok",
            "lane_approved": True,
            "query_kind":     str(spec.get("query_kind") or variant["variant_name"]),
            "lane_tier":      str(spec.get("lane_tier") or "primary"),
            "lane_priority":  float(spec.get("lane_priority") or 0.0),
            "target_lane_type": str(spec.get("target_lane_type") or ""),
            "lane_subset": str(spec.get("lane_subset") or ""),
            "lane_parallel": str(spec.get("lane_parallel") or ""),
            "lane_product": str(spec.get("lane_product") or spec.get("target_product_family") or ""),
            "spec_premium_lane": bool(spec.get("spec_premium_lane")),
            "spec_lane_class": str(spec.get("spec_lane_class") or ""),
            "lane_key": _lane_metric_key(spec),
        })

    diag["deduped_count"]         = len(candidates)
    diag["final_candidate_count"] = len(candidates)
    if title_passed and not candidates:
        diag["failure_stage"] = "target_lane_filter"
        diag["failure_reason"] = "all title-passing rows rejected by approved target-lane gate"
    diag["winning_variant"]       = True
    diag["_items_out"]            = candidates
    return diag


def _fetch_bin_with_fallback(
    spec: Dict[str, Any],
) -> Tuple[List[Dict[str, Any]], bool, int, List[Dict[str, Any]]]:
    """
    BIN retrieval with up to 3 query variants (primary → relaxed → recovery).
    Stops early once _AUCTION_VARIANT_CANDIDATE_THRESHOLD viable candidates are found.
    Returns (items, rate_limited, pre_filter_count, diags).
    """
    variants     = spec.get("query_variants") or [{"variant_name": "primary", "query": spec["query"]}]
    diags:       List[Dict[str, Any]] = []
    all_items:   List[Dict[str, Any]] = []
    rate_limited = False

    for variant in variants[:3]:
        diag = _run_bin_variant(spec, variant)
        # Strip internal keys before storing
        public_diag = {k: v for k, v in diag.items() if not k.startswith("_")}
        diags.append(public_diag)

        if diag.get("_rate_limited"):
            rate_limited = True
        if diag.get("_stop_ladder"):
            break

        items_out = diag.get("_items_out")
        if items_out is not None:
            all_items.extend(items_out)
            print(
                f"[RADAR] {spec['player_name']} BIN/{variant['variant_name']}: "
                f"raw={diag['raw_rows_count']} price={diag['bin_rows_count']} "
                f"pass={diag['title_pass_count']} candidates={diag['final_candidate_count']}"
            )
            if diag["final_candidate_count"] >= BIN_CANDIDATE_THRESHOLD:
                break   # early stop — threshold met

    winning = [d for d in diags if d.get("winning_variant")]
    if winning:
        pre_filter_count = winning[-1]["bin_rows_count"]
    elif diags:
        pre_filter_count = max(d.get("bin_rows_count", 0) for d in diags)
    else:
        pre_filter_count = 0

    _progress_tick(spec.get("player_name", ""))
    return all_items, rate_limited, pre_filter_count, diags


def _run_auction_variant(
    spec: Dict[str, Any],
    variant: Dict[str, Any],
    cutoff: datetime,
    now: datetime,
    time_window_hours: float,
) -> Dict[str, Any]:
    """Execute one auction query variant and return a fully populated diag dict."""
    _lane_key = _lane_metric_key(spec)
    print(
        f"[FETCH_PATH_ENTER] function=_run_auction_variant "
        f"lane={_lane_key[:96]} query={str((variant or {}).get('query') or '')[:180]} "
        f"variant={str((variant or {}).get('variant_name') or '')[:48]}"
    )
    tier = spec.get("whatnot_tier", 3)
    diag: Dict[str, Any] = {
        "family_id":             spec["player_name"],
        "family_key":            f"{spec.get('sport', '')}_{spec['player_name']}",
        "lane_key":              _lane_metric_key(spec),
        "target_id":             str(spec.get("target_id") or ""),
        "target_label":          str(spec.get("target_label") or spec.get("player_name") or ""),
        "player_id":             str(spec.get("player_id") or ""),
        "lane_tier":             str(spec.get("lane_tier") or "primary"),
        "lane_priority":         float(spec.get("lane_priority") or 0.0),
        "query_kind":            str(spec.get("query_kind") or ""),
        "target_lane_type":      str(spec.get("target_lane_type") or ""),
        "lane_subset":           str(spec.get("lane_subset") or ""),
        "lane_parallel":         str(spec.get("lane_parallel") or ""),
        "lane_product":          str(spec.get("lane_product") or spec.get("target_product_family") or ""),
        "spec_premium_lane":     bool(spec.get("spec_premium_lane")),
        "spec_lane_class":       str(spec.get("spec_lane_class") or ""),
        "scan_type":             "AUCTION",
        "query_variant_name":    variant["variant_name"],
        "query_text":            variant["query"],
        "raw_rows_count":        0,
        "bin_rows_count":        0,   # = in_window_count for auctions
        "with_end_time_count":   0,
        "missing_end_time_count": 0,
        "within_window_count":   0,
        "window_edge_rescue_count": 0,
        "outside_window_count":  0,
        "nearest_remaining":     None,
        "strict_window_seconds": None,
        "rows_returned":         0,
        "parsed_rows_count":     0,
        "in_window_count":       0,
        "out_of_window_count":   0,
        "nearest_remaining_seconds": None,
        "window_rows_forwarded": 0,
        "response_scope_valid":  False,
        "api_ignored_window":    False,
        "window_viability_score": 0.0,
        "dead_live_lane":        False,
        "min_seconds_remaining": None,
        "max_seconds_remaining": None,
        "window_bucket_counts":  {},
        "time_filter_reject_count": 0,
        "time_filter_override_count": 0,
        "price_filter_reject_count": 0,
        "total_listings_seen": 0,
        "total_listings_blocked": 0,
        "total_listings_admitted": 0,
        "discovery_premium_admitted": 0,
        "discovery_conditional_admitted": 0,
        "title_pass_count":      0,
        "off_target_reject_count": 0,
        "relaxed_target_passes": 0,
        "target_relax_rejects": 0,
        "shape_reject_count": 0,
        "fake_serial_dropped_count": 0,
        "player_reject_count":    0,
        "product_reject_count":   0,
        "parallel_reject_count":  0,
        "rejection_reason_counts": {},
        "deduped_count":         0,
        "final_candidate_count": 0,
        "failure_stage":         None,
        "failure_reason":        None,
        "winning_variant":       False,
        "_items_out":            None,
        "_title_rows_out":       None,
        "_expanded_items_out":   None,
        "_rate_limited":         False,
        "_stop_ladder":          False,
        "_runtime_branch":       "",
    }

    # ── ZERO-RESULT RELAXED RETRY STATE ───────────────────────────────────────
    # _relaxed_attempted_state is mutable across the closure boundary so the
    # helper can flip it once the relaxed query has actually been executed.
    _relaxed_attempted_state = {"value": False}
    _strict_items_seen_state = {"value": 0}
    _relaxed_items_seen_state = {"value": 0}
    _relaxed_query_text_state = {"value": ""}
    _auth_headers_state: Dict[str, Any] = {}

    def _force_relaxed_retry(reason: str) -> List[Dict[str, Any]]:
        """Idempotent relaxed-query retry. Always logs RELAXED_RESULT + RECOVERY."""
        if _relaxed_attempted_state["value"]:
            return []
        _relaxed_attempted_state["value"] = True
        _relaxed_items_local: List[Dict[str, Any]] = []
        _relaxed_q_text = ""
        try:
            _relaxed_variant = _build_zero_result_relaxed_auction_variant(spec, variant)
            _relaxed_params = _build_auction_fetch_params(
                _relaxed_variant,
                window_start=_request_start_utc_state.get("value"),
                window_end=_request_end_utc_state.get("value"),
                scoped=bool(_request_scoped_state.get("value", True)),
            )
            _relaxed_q_text = str(_relaxed_params.get("q") or "")
            _relaxed_query_text_state["value"] = _relaxed_q_text
            _hdrs = _auth_headers_state.get("headers")
            if not _hdrs:
                try:
                    _hdrs = _ebay_auth_headers()
                    _auth_headers_state["headers"] = _hdrs
                except Exception as _hx:
                    diag["relaxed_auth_error"] = str(_hx)[:120]
                    _hdrs = None
            if _hdrs is not None:
                _api_throttle()
                try:
                    _relaxed_resp_local = requests.get(
                        "https://api.ebay.com/buy/browse/v1/item_summary/search",
                        headers=_hdrs, params=_relaxed_params, timeout=20,
                    )
                    if _relaxed_resp_local.status_code == 429:
                        _circuit_record_rl()
                        diag["_rate_limited"] = True
                    elif _relaxed_resp_local.status_code == 200:
                        try:
                            _relaxed_items_local = _relaxed_resp_local.json().get("itemSummaries", []) or []
                        except Exception:
                            _relaxed_items_local = []
                    else:
                        diag["relaxed_http_status"] = int(_relaxed_resp_local.status_code)
                except requests.RequestException as _rx:
                    diag["relaxed_fetch_error"] = type(_rx).__name__
                    _relaxed_items_local = []
        except Exception as _bx:
            diag["relaxed_build_error"] = type(_bx).__name__
        _relaxed_items_seen_state["value"] = len(_relaxed_items_local)
        print(
            f"[EBAY_QUERY_RELAXED_RESULT] lane={_lane_key[:96]} "
            f"query={_relaxed_q_text[:180]} "
            f"items={len(_relaxed_items_local)} "
            f"trigger={reason}"
        )
        print(
            f"[EBAY_QUERY_RECOVERY] lane={_lane_key[:96]} "
            f"strict_items={_strict_items_seen_state['value']} "
            f"relaxed_items={len(_relaxed_items_local)} "
            f"recovered={1 if len(_relaxed_items_local) > 0 else 0} "
            f"trigger={reason}"
        )
        if _relaxed_items_local:
            diag["zero_result_relaxed_query"] = _relaxed_q_text
            diag["zero_result_relaxed_items"] = len(_relaxed_items_local)
        return _relaxed_items_local

    def _fetch_path_exit() -> None:
        _raw_count = int(diag.get('raw_rows_count') or 0)
        _listing_count = int(diag.get('parsed_rows_count') or 0)
        _auction_count = int(diag.get('bin_rows_count') or diag.get('within_window_count') or 0)
        if _raw_count == 0 and not _relaxed_attempted_state["value"]:
            print(
                f"[EBAY_ZERO_EXIT_WITHOUT_RELAXED] lane={_lane_key[:96]} "
                f"failure_stage={diag.get('failure_stage')} "
                f"failure_reason={str(diag.get('failure_reason') or '')[:120]} "
                f"strict_items={_strict_items_seen_state['value']}"
            )
        print(
            f"[FETCH_PATH_EXIT] function=_run_auction_variant "
            f"raw_count={_raw_count} "
            f"listing_count={_listing_count} "
            f"auction_count={_auction_count} "
            f"relaxed_attempted={1 if _relaxed_attempted_state['value'] else 0} "
            f"strict_items={_strict_items_seen_state['value']} "
            f"relaxed_items={_relaxed_items_seen_state['value']}"
        )

    # Mutable holders so the relaxed helper can read request window/scope state
    # set later in the function body.
    _request_start_utc_state: Dict[str, Any] = {"value": None}
    _request_end_utc_state: Dict[str, Any] = {"value": None}
    _request_scoped_state: Dict[str, Any] = {"value": True}

    raw_window_rows: List[Dict[str, Any]] = []
    title_passed: List[Dict[str, Any]] = []
    _expanded_rows: List[Dict[str, Any]] = []

    # Jitter: randomized pre-call sleep breaks up burst patterns
    _circuit_jitter()
    # Circuit breaker: if in hard cooldown, defer this family instead of hammering eBay
    if not _circuit_pre_request():
        diag["failure_stage"]  = "rate_limit_deferred"
        diag["failure_reason"] = "circuit_breaker in cooldown — family queued for retry"
        diag["_rate_limited"]  = True
        diag["_stop_ladder"]   = True
        # Circuit-breaker: do NOT issue a relaxed retry (we are intentionally
        # silent toward eBay), but stamp the strict-result log so the audit
        # trail shows we touched this lane.
        print(
            f"[EBAY_QUERY_STRICT_RESULT] lane={_lane_key[:96]} "
            f"query={str((variant or {}).get('query') or '')[:180]} "
            f"items=0 stage=circuit_breaker"
        )
        _fetch_path_exit()
        return diag

    _api_throttle()
    try:
        headers = _ebay_auth_headers()
        _auth_headers_state["headers"] = headers
    except Exception as exc:
        diag["failure_stage"]  = "auth"
        diag["failure_reason"] = str(exc)[:160]
        diag["_stop_ladder"]   = True
        # Auth failed — relaxed retry cannot run without headers, but we still
        # must stamp the strict result log + the zero-exit guard.
        print(
            f"[EBAY_QUERY_STRICT_RESULT] lane={_lane_key[:96]} "
            f"query={str((variant or {}).get('query') or '')[:180]} "
            f"items=0 stage=auth_fail"
        )
        _fetch_path_exit()
        return diag

    _request_start_utc = datetime.now(tz=timezone.utc)
    _request_end_utc = _request_start_utc + timedelta(hours=float(time_window_hours or 0.0))
    _request_start_utc_state["value"] = _request_start_utc
    _request_end_utc_state["value"] = _request_end_utc
    _request_scoped_state["value"] = True
    params = _build_auction_fetch_params(
        variant,
        window_start=_request_start_utc,
        window_end=_request_end_utc,
        scoped=True,
    )
    _request_scoped = True
    _log_auction_fetch_contract(
        lane_key=_lane_key,
        variant=variant,
        params=params,
        window_hours=time_window_hours,
        window_start=_request_start_utc,
        window_end=_request_end_utc,
        request_scoped=_request_scoped,
    )
    # [EBAY_QUERY_PARAMS] — full request contract sent to Browse API.
    print(
        f"[EBAY_QUERY_PARAMS] lane={_lane_key[:96]} "
        f"q={str(params.get('q') or '')[:180]!r} "
        f"filter={str(params.get('filter') or '')!r} "
        f"sort={str(params.get('sort') or '')!r} "
        f"limit={params.get('limit')} "
        f"window_start={_browse_utc_iso(_request_start_utc)} "
        f"window_end={_browse_utc_iso(_request_end_utc)} "
        f"window_hours={float(time_window_hours or 0.0):.2f} "
        f"scoped={1 if _request_scoped else 0}"
    )
    # [EBAY_SORT_MODE] — surfaces the sort strategy alone for quick grep.
    print(
        f"[EBAY_SORT_MODE] lane={_lane_key[:96]} "
        f"sort={str(params.get('sort') or '')!r} "
        f"expected=endingSoonest "
        f"sort_ok={1 if str(params.get('sort') or '') == 'endingSoonest' else 0}"
    )

    try:
        resp = requests.get(
            "https://api.ebay.com/buy/browse/v1/item_summary/search",
            headers=headers, params=params, timeout=20,
        )
    except requests.RequestException as exc:
        print(
            f"[AUCTION_REQUEST_DEGRADED] lane={_lane_key[:64]} "
            f"reason={type(exc).__name__} used_broad_auction_fallback=1"
        )
        _request_scoped = False
        _request_scoped_state["value"] = False
        params = _build_auction_fetch_params(variant, scoped=False)
        _log_auction_fetch_contract(
            lane_key=_lane_key,
            variant=variant,
            params=params,
            window_hours=time_window_hours,
            window_start=_request_start_utc,
            window_end=_request_end_utc,
            request_scoped=_request_scoped,
        )
        try:
            resp = requests.get(
                "https://api.ebay.com/buy/browse/v1/item_summary/search",
                headers=headers, params=params, timeout=20,
            )
        except requests.RequestException as exc2:
            diag["failure_stage"] = "fetch"
            diag["failure_reason"] = str(exc2)[:160]
            print(
                f"[EBAY_QUERY_STRICT_RESULT] lane={_lane_key[:96]} "
                f"query={str(params.get('q') or '')[:180]} "
                f"items=0 stage=fetch_exception"
            )
            _force_relaxed_retry("fetch_exception")
            _fetch_path_exit()
            return diag

    if resp.status_code == 429:
        _circuit_record_rl()   # update circuit breaker state
        diag["failure_stage"]  = "rate_limit_deferred"
        diag["failure_reason"] = "HTTP 429 — family deferred, not dead"
        diag["_rate_limited"]  = True
        diag["_stop_ladder"]   = True
        print(
            f"[EBAY_QUERY_STRICT_RESULT] lane={_lane_key[:96]} "
            f"query={str(params.get('q') or '')[:180]} "
            f"items=0 stage=http_429"
        )
        _fetch_path_exit()
        return diag

    if resp.status_code != 200:
        if _request_scoped:
            print(
                f"[AUCTION_REQUEST_DEGRADED] lane={_lane_key[:64]} "
                f"reason=HTTP_{resp.status_code} used_broad_auction_fallback=1"
            )
            _request_scoped = False
            _request_scoped_state["value"] = False
            params = _build_auction_fetch_params(variant, scoped=False)
            _log_auction_fetch_contract(
                lane_key=_lane_key,
                variant=variant,
                params=params,
                window_hours=time_window_hours,
                window_start=_request_start_utc,
                window_end=_request_end_utc,
                request_scoped=_request_scoped,
            )
            try:
                resp = requests.get(
                    "https://api.ebay.com/buy/browse/v1/item_summary/search",
                    headers=headers, params=params, timeout=20,
                )
            except requests.RequestException as exc:
                diag["failure_stage"] = "fetch"
                diag["failure_reason"] = str(exc)[:160]
                print(
                    f"[EBAY_QUERY_STRICT_RESULT] lane={_lane_key[:96]} "
                    f"query={str(params.get('q') or '')[:180]} "
                    f"items=0 stage=fetch_exception_2"
                )
                _force_relaxed_retry("fetch_exception_2")
                _fetch_path_exit()
                return diag
    if resp.status_code == 429:
        _circuit_record_rl()   # update circuit breaker state
        diag["failure_stage"]  = "rate_limit_deferred"
        diag["failure_reason"] = "HTTP 429 â€” family deferred, not dead"
        diag["_rate_limited"]  = True
        diag["_stop_ladder"]   = True
        print(
            f"[EBAY_QUERY_STRICT_RESULT] lane={_lane_key[:96]} "
            f"query={str(params.get('q') or '')[:180]} "
            f"items=0 stage=http_429_post_fallback"
        )
        _fetch_path_exit()
        return diag

    if resp.status_code != 200:
        diag["failure_stage"] = "http_error"
        diag["failure_reason"] = f"HTTP {resp.status_code}"
        print(
            f"[EBAY_QUERY_STRICT_RESULT] lane={_lane_key[:96]} "
            f"query={str(params.get('q') or '')[:180]} "
            f"items=0 stage=http_{resp.status_code}"
        )
        _force_relaxed_retry(f"http_{resp.status_code}")
        _fetch_path_exit()
        return diag

    try:
        raw_items = resp.json().get("itemSummaries", []) or []
    except Exception as exc:
        diag["failure_stage"]  = "json_decode"
        diag["failure_reason"] = str(exc)[:120]
        print(
            f"[EBAY_QUERY_STRICT_RESULT] lane={_lane_key[:96]} "
            f"query={str(params.get('q') or '')[:180]} "
            f"items=0 stage=json_decode"
        )
        _force_relaxed_retry("json_decode")
        _fetch_path_exit()
        return diag
    _strict_items_count = len(raw_items)
    _strict_items_seen_state["value"] = _strict_items_count
    print(
        f"[EBAY_QUERY_STRICT_RESULT] lane={_lane_key[:96]} "
        f"query={str(params.get('q') or '')[:180]} "
        f"items={_strict_items_count}"
    )

    if not raw_items:
        _relaxed_items_forced = _force_relaxed_retry("strict_zero_items")
        if _relaxed_items_forced:
            raw_items = list(_relaxed_items_forced)

    diag["request_scoped"] = bool(_request_scoped)
    diag["request_filter"] = str(params.get("filter") or "")
    diag["request_sort"] = str(params.get("sort") or "")
    diag["raw_rows_count"] = len(raw_items)
    print(f"[ES][AUCTION_FETCH] rows_returned={diag['raw_rows_count']}")
    # [EBAY_RAW_ENDTIME_DISTRIBUTION] — distribution of itemEndDate offsets
    # (in seconds-from-now) for the raw rows the API just returned. Lets us
    # see at a glance whether eBay honored the itemEndDate scope filter or
    # returned auctions days out. Bucketed; first 5 raw end times included.
    _now_for_dist = datetime.now(tz=timezone.utc)
    _dist_buckets = {"<=1h": 0, "1-3h": 0, "3-12h": 0, "12-24h": 0, "1-3d": 0, ">3d": 0, "expired": 0, "missing": 0}
    _dist_samples: List[str] = []
    _dist_min: Optional[float] = None
    _dist_max: Optional[float] = None
    for _ri in list(raw_items or []):
        if not isinstance(_ri, dict):
            continue
        _raw_end = str(_ri.get("itemEndDate") or "").strip()
        if len(_dist_samples) < 5:
            _dist_samples.append(_raw_end[:32] if _raw_end else "missing")
        if not _raw_end:
            _dist_buckets["missing"] += 1
            continue
        _parsed_end = _parse_end_dt(_raw_end)
        if _parsed_end is None:
            _dist_buckets["missing"] += 1
            continue
        _delta = (_parsed_end - _now_for_dist).total_seconds()
        _dist_min = _delta if _dist_min is None else min(_dist_min, _delta)
        _dist_max = _delta if _dist_max is None else max(_dist_max, _delta)
        if _delta < 0:
            _dist_buckets["expired"] += 1
        elif _delta <= 3600:
            _dist_buckets["<=1h"] += 1
        elif _delta <= 10800:
            _dist_buckets["1-3h"] += 1
        elif _delta <= 43200:
            _dist_buckets["3-12h"] += 1
        elif _delta <= 86400:
            _dist_buckets["12-24h"] += 1
        elif _delta <= 259200:
            _dist_buckets["1-3d"] += 1
        else:
            _dist_buckets[">3d"] += 1
    _dist_in_window = sum(
        _dist_buckets[_b]
        for _b, _max_s in (("<=1h", 3600), ("1-3h", 10800), ("3-12h", 43200), ("12-24h", 86400), ("1-3d", 259200), (">3d", float("inf")))
        if _max_s <= float(_window_threshold_seconds_for_dist := max(300.0, float(time_window_hours or 0.0) * 3600.0))
    )
    print(
        f"[EBAY_RAW_ENDTIME_DISTRIBUTION] lane={_lane_key[:96]} "
        f"raw_rows={len(raw_items)} "
        f"window_hours={float(time_window_hours or 0.0):.2f} "
        f"window_seconds={int(round(_window_threshold_seconds_for_dist))} "
        f"buckets={_dist_buckets} "
        f"min_seconds={round(float(_dist_min), 2) if _dist_min is not None else 'na'} "
        f"max_seconds={round(float(_dist_max), 2) if _dist_max is not None else 'na'} "
        f"in_window_estimate={_dist_in_window} "
        f"first5_raw_endTimes={_dist_samples} "
        f"request_scoped={1 if _request_scoped else 0} "
        f"sort={str(params.get('sort') or '')!r}"
    )
    print(
        f"[AUCTION_REQUEST_RESULT] lane={_lane_key[:64]} "
        f"rows_returned={diag['raw_rows_count']} "
        f"window_hours={float(time_window_hours or 0.0):.2f} "
        f"request_scoped={1 if _request_scoped else 0}"
    )

    if not raw_items:
        diag["failure_stage"]  = "browse_zero_rows"
        diag["failure_reason"] = "eBay returned 0 items for this query"
        _fetch_path_exit()
        return diag

    _auction_shaped_rows, _raw_listing_type_counts = _extract_browse_auction_rows(raw_items)
    print(f"[ES][AUCTION_PARSE] raw_listing_type_counts={_raw_listing_type_counts}")
    print(f"[ES][AUCTION_PARSE] parsed_auction={sum(int(_raw_listing_type_counts.get(k, 0) or 0) for k in ('auction', 'auction_or_bin'))}")
    print(f"[ES][AUCTION_PARSE] parsed_bin={int(_raw_listing_type_counts.get('fixed_price', 0) or 0)}")
    print(f"[ES][AUCTION_PARSE] parsed_unknown={int(_raw_listing_type_counts.get('unknown', 0) or 0)}")

    if not _auction_shaped_rows:
        diag["failure_stage"] = "listing_type_gate"
        diag["failure_reason"] = "browse rows returned but none parsed as auction-shaped"
        _fetch_path_exit()
        return diag

    # Refresh now immediately before the window gate — avoids using a timestamp
    # that was set before the eBay API call (potentially seconds or minutes stale).
    now = datetime.now(tz=timezone.utc)
    _expanded_cutoff = now + timedelta(hours=_expanded_window_hours(time_window_hours))
    _normalized_auction_rows: List[Dict[str, Any]] = []
    window_rows: List[Dict[str, Any]] = []
    edge_window_rows: List[Dict[str, Any]] = []
    premium_live_rescue_rows: List[Dict[str, Any]] = []
    case_hit_live_rescue_rows: List[Dict[str, Any]] = []
    expanded_window: List[Dict[str, Any]] = []
    _time_check_samples: List[float] = []
    _kept_time_check_samples: List[float] = []
    # Derive thresholds from time_window_hours — never hardcode 300s for Ending Soon.
    # The caller sets time_window_hours (default 3h); the expanded window doubles it.
    _window_threshold_seconds = max(300.0, float(time_window_hours or 3.0) * 3600.0)
    _expanded_window_threshold_seconds = max(300.0, _expanded_window_hours(time_window_hours) * 3600.0)
    _premium_window_meta = _premium_window_meta_for_spec(spec)
    _premium_window_extension_hours = float(_premium_window_meta.get("extension_hours") or 0.0)
    _premium_window_threshold_seconds = _window_threshold_seconds
    _response_scope_valid = False
    _time_filter_overrides = 0
    _scope_validation: Dict[str, Any] = {}
    if _request_scoped:
        _scope_validation = _validate_scoped_auction_response(
            _auction_shaped_rows,
            now_dt=now,
            window_seconds=_window_threshold_seconds,
        )
        _response_scope_valid = bool(_scope_validation.get("response_scope_valid"))
        print(
            f"[AUCTION_SCOPE_VALIDATE] lane={_lane_key[:64]} "
            f"request_scoped={1 if _request_scoped else 0} "
            f"rows={int(_scope_validation.get('rows') or 0)} "
            f"in_window={int(_scope_validation.get('in_window') or 0)} "
            f"out_of_window={int(_scope_validation.get('out_of_window') or 0)} "
            f"response_scope_valid={1 if _response_scope_valid else 0}"
        )
        if not _response_scope_valid:
            print(
                f"[AUCTION_SCOPE_INVALID] lane={_lane_key[:64]} "
                f"reason=api_ignored_itemEndDate rows={int(_scope_validation.get('rows') or 0)} "
                f"nearest_remaining={round(float(_scope_validation.get('nearest_remaining')), 2) if _scope_validation.get('nearest_remaining') is not None else 'na'} "
                f"furthest_remaining={round(float(_scope_validation.get('furthest_remaining')), 2) if _scope_validation.get('furthest_remaining') is not None else 'na'}"
            )
            _fallback_rows = list(_auction_shaped_rows)
            _broad_params = _build_auction_fetch_params(variant, scoped=False)
            try:
                _broad_resp = requests.get(
                    "https://api.ebay.com/buy/browse/v1/item_summary/search",
                    headers=headers, params=_broad_params, timeout=20,
                )
                if _broad_resp.status_code == 200:
                    _broad_raw_items = _broad_resp.json().get("itemSummaries", []) or []
                    _fallback_rows, _broad_listing_type_counts = _extract_browse_auction_rows(_broad_raw_items)
                    if _fallback_rows:
                        _raw_listing_type_counts = dict(_broad_listing_type_counts)
                else:
                    print(
                        f"[AUCTION_REQUEST_DEGRADED] lane={_lane_key[:64]} "
                        f"reason=scope_invalid_broad_HTTP_{_broad_resp.status_code} used_broad_auction_fallback=1"
                    )
            except Exception as exc:
                print(
                    f"[AUCTION_REQUEST_DEGRADED] lane={_lane_key[:64]} "
                    f"reason=scope_invalid_broad_{type(exc).__name__} used_broad_auction_fallback=1"
                )
            _fallback_rows_before = len(_fallback_rows)
            _auction_shaped_rows = _nearest_ending_auction_slice(
                _fallback_rows,
                now_dt=now,
                slice_size=20,
            )
            # ── FALLBACK CONTAINMENT ─────────────────────────────────────────
            # Strict scope failed; we just took the nearest 20. Clip anything
            # whose itemEndDate is more than 2× the user-selected window away,
            # so we don't surface auctions ending days from now (they'd just
            # die at time_filter downstream and pollute the candidate pool).
            #   3h window → max 6h ;  6h window → max 12h ;  12h window → max 24h
            _fallback_clip_before = len(_auction_shaped_rows)
            _max_allowed_seconds_fallback = float(_window_threshold_seconds or 0.0) * 2.0
            _clipped_fallback_rows: List[Dict[str, Any]] = []
            for _fb_row in list(_auction_shaped_rows or []):
                if not isinstance(_fb_row, dict):
                    continue
                _fb_end_dt = _extract_auction_end_dt(_fb_row)
                _fb_remaining = seconds_left(_fb_end_dt, now) if _fb_end_dt is not None else None
                # Keep rows whose remaining is unknown (downstream gate handles those),
                # rows already expired or inside grace, and rows within 2× window.
                if (
                    _fb_remaining is None
                    or _fb_remaining < 0.0
                    or _fb_remaining <= _max_allowed_seconds_fallback
                ):
                    _clipped_fallback_rows.append(_fb_row)
            _auction_shaped_rows = _clipped_fallback_rows
            print(
                f"[FALLBACK_WINDOW_CLIP] lane={_lane_key[:64]} "
                f"before={_fallback_clip_before} "
                f"after={len(_auction_shaped_rows)} "
                f"window_hours={float(time_window_hours or 0.0):.2f} "
                f"max_allowed_hours={float(_max_allowed_seconds_fallback) / 3600.0:.2f} "
                f"window_seconds={int(round(_window_threshold_seconds))} "
                f"max_allowed_seconds={int(round(_max_allowed_seconds_fallback))}"
            )
            print(
                f"[AUCTION_SCOPE_FALLBACK] lane={_lane_key[:64]} "
                f"fallback_mode=nearest_end_local_crop "
                f"rows_before={_fallback_rows_before} rows_after={len(_auction_shaped_rows)}"
            )
    else:
        print(
            f"[AUCTION_SCOPE_VALIDATE] lane={_lane_key[:64]} "
            f"request_scoped=0 rows={len(_auction_shaped_rows)} in_window=0 "
            f"out_of_window={len(_auction_shaped_rows)} response_scope_valid=0"
        )
    diag["response_scope_valid"] = bool(_response_scope_valid)
    diag["api_ignored_window"] = bool(_request_scoped and not _response_scope_valid)
    print(
        f"[AUCTION_SCOPE_FINAL] lane={_lane_key[:64]} "
        f"request_scoped={1 if _request_scoped else 0} "
        f"response_scope_valid={1 if _response_scope_valid else 0} "
        f"rows_forwarded={len(_auction_shaped_rows)}"
    )
    _window_reason_counts: Dict[str, int] = {
        "within_window": 0,
        "missed_window": 0,
        "premium_extended_window": 0,
        "missing_end_time": 0,
        "invalid_remaining": 0,
    }
    _window_edge_rescued = 0
    _window_missed_far = 0
    _premium_live_yield_overrides = 0
    _premium_live_yield_nearest: Optional[float] = None
    print(
        f"[ES][WINDOW_GATE] time_window_hours={time_window_hours} "
        f"window_threshold_seconds={_window_threshold_seconds:.0f} "
        f"now_utc={now.isoformat()} "
        f"candidate_rows={len(_auction_shaped_rows)}"
    )
    for it in _auction_shaped_rows:
        if not isinstance(it, dict):
            continue
        # [TIME_FILTER_INPUT] — raw eBay endTime fields BEFORE any parsing,
        # so we can prove what the API actually returned vs. what we parsed.
        _raw_item_end_date = (it or {}).get("itemEndDate")
        _raw_end_iso       = (it or {}).get("end_iso")
        _raw_end_time      = (it or {}).get("end_time")
        _raw_end_date      = (it or {}).get("endDate")
        _raw_listing_type  = (it or {}).get("listing_type")
        _raw_item_id       = (it or {}).get("itemId") or (it or {}).get("item_id") or (it or {}).get("source_item_id")
        print(
            f"[TIME_FILTER_INPUT] item={str(_raw_item_id or '')[:32]} "
            f"itemEndDate={str(_raw_item_end_date or '')[:64]!r} "
            f"end_iso={str(_raw_end_iso or '')[:64]!r} "
            f"end_time={str(_raw_end_time or '')[:64]!r} "
            f"endDate={str(_raw_end_date or '')[:64]!r} "
            f"listing_type={str(_raw_listing_type or '')[:32]!r} "
            f"window_hours={float(time_window_hours or 0.0):.2f} "
            f"window_seconds={int(round(_window_threshold_seconds))} "
            f"now_utc={now.isoformat()}"
        )
        _time_contract = _authoritative_time_contract(it)
        _window_decision = _window_filter_decision(
            it,
            now_dt=now,
            window_seconds=_window_threshold_seconds,
        )
        end_dt_it = _window_decision.get("end_dt")
        _secs_remaining = _window_decision.get("remaining_seconds")
        _keep_row = bool(_window_decision.get("keep"))
        _drop_reason = str(_window_decision.get("reason") or "invalid_remaining")
        # [TIME_PARSE_RESULT] — what _window_filter_decision actually produced
        # from the raw eBay payload (parsed end_dt + computed remaining seconds).
        print(
            f"[TIME_PARSE_RESULT] item={str(_raw_item_id or '')[:32]} "
            f"parsed_end_dt={end_dt_it.isoformat() if isinstance(end_dt_it, datetime) else 'na'} "
            f"remaining_seconds={round(float(_secs_remaining), 2) if _secs_remaining is not None else 'na'} "
            f"window_seconds={int(round(_window_threshold_seconds))} "
            f"parse_source={str(_window_decision.get('_source') or '?')} "
            f"keep_initial={1 if _keep_row else 0} "
            f"reason_initial={_drop_reason}"
        )
        _premium_window_kept = False
        _effective_fetch_threshold_seconds = max(
            float(_expanded_window_threshold_seconds or 0.0),
            float(_premium_window_threshold_seconds or 0.0),
            float(_window_threshold_seconds or 0.0),
        )
        if not _keep_row:
            _auth_remaining = _safe_float(_time_contract.get("remaining_seconds"))
            _auth_end_dt = _extract_auction_end_dt(it)
            if _auth_remaining is None and _auth_end_dt is not None:
                _auth_remaining = seconds_left(_auth_end_dt, now)
            _authoritative_outside_fetch = bool(
                _auth_remaining is not None
                and _effective_fetch_threshold_seconds > 0.0
                and _auth_remaining > _effective_fetch_threshold_seconds
            )
            print(
                f"[TIME_FILTER_GATE] title={str((it or {}).get('title') or (it or {}).get('source_title') or '')[:160]} "
                f"item={str((it or {}).get('itemId') or (it or {}).get('item_id') or (it or {}).get('source_item_id') or '')[:32]} "
                f"remaining_seconds={round(float(_auth_remaining), 2) if _auth_remaining is not None else 'na'} "
                f"end_time={str(_time_contract.get('end_time') or '')[:64]} "
                f"listing_type={str((it or {}).get('listing_type') or '')[:32]} "
                f"authoritative_ok={1 if _time_contract.get('ok') else 0} "
                f"reason={_time_contract.get('reason') or _drop_reason} "
                f"drop={1 if (not _time_contract.get('ok') or _authoritative_outside_fetch) else 0}"
            )
            if bool(_time_contract.get("ok")) and not _authoritative_outside_fetch:
                _keep_row = True
                _drop_reason = "authoritative_time_contract"
                _secs_remaining = _auth_remaining
                end_dt_it = _auth_end_dt or end_dt_it
                _time_filter_overrides += 1
                diag["time_filter_override_count"] = int(diag.get("time_filter_override_count") or 0) + 1
                print(
                    f"[TIME_FILTER_OVERRIDE] title={str((it or {}).get('title') or (it or {}).get('source_title') or '')[:160]} "
                    f"item={str((it or {}).get('itemId') or (it or {}).get('item_id') or (it or {}).get('source_item_id') or '')[:32]} "
                    f"remaining_seconds={round(float(_secs_remaining), 2) if _secs_remaining is not None else 'na'} "
                    f"end_time={str(_time_contract.get('end_time') or '')[:64]} "
                    f"reason=authoritative_time_contract"
                )
        if (
            not _keep_row
            and bool(_premium_window_meta.get("allowed"))
            and _drop_reason == "missed_window"
        ):
            _premium_window_decision = _window_filter_decision(
                it,
                now_dt=now,
                window_seconds=_premium_window_threshold_seconds,
            )
            if bool(_premium_window_decision.get("keep")):
                _keep_row = True
                _premium_window_kept = True
                _drop_reason = "premium_extended_window"
        _window_reason_counts[_drop_reason] = int(_window_reason_counts.get(_drop_reason, 0) or 0) + 1
        if end_dt_it is None:
            diag["missing_end_time_count"] = int(diag.get("missing_end_time_count") or 0) + 1
        else:
            diag["with_end_time_count"] = int(diag.get("with_end_time_count") or 0) + 1
        _row_with_time = dict(it)
        _row_with_time["end_dt"] = end_dt_it
        _row_with_time["remaining_seconds"] = _secs_remaining
        _row_with_time["seconds_remaining"] = _secs_remaining
        _row_with_time["scan_time_window_hours"] = float(time_window_hours or 0.0)
        _row_with_time["premium_window_allowed"] = bool(_premium_window_meta.get("allowed"))
        _row_with_time["premium_window_extension_hours"] = _premium_window_extension_hours
        _row_with_time["premium_window_kept"] = bool(_premium_window_kept)
        _row_with_time["premium_window_reason"] = str(_drop_reason or "")
        if bool(spec.get("collector_heat_lane_allowed")) or str(spec.get("target_lane_type") or "").strip().lower() == "collector_heat":
            _row_with_time["collector_heat_lane_allowed"] = True
            _row_with_time["target_lane_type"] = str(spec.get("target_lane_type") or _row_with_time.get("target_lane_type") or "")
            _row_with_time["query_kind"] = str(spec.get("query_kind") or _row_with_time.get("query_kind") or "")
        _authoritative_window_threshold = (
            _premium_window_threshold_seconds if _premium_window_kept else _window_threshold_seconds
        )
        _authoritative_window_source = (
            f"{_drop_reason}:{str(_window_decision.get('_source') or 'unknown')}"
            if _premium_window_kept
            else f"{str(_window_decision.get('reason') or _drop_reason or 'unknown')}:{str(_window_decision.get('_source') or 'unknown')}"
        )
        _row_with_time = _stamp_window_contract_fields(
            _row_with_time,
            keep=_keep_row,
            threshold_seconds=_authoritative_window_threshold,
            remaining_seconds=_secs_remaining,
            source=_authoritative_window_source,
            checked_at=now,
        )
        if bool(spec.get("premium_lane_allowed") or spec.get("spec_premium_lane")):
            _row_with_time["premium_lane_allowed"] = True
            _row_with_time["spec_premium_lane"] = True
            _row_with_time["premium_lane"] = _row_with_time.get("premium_lane") or 1
        if spec.get("target_lane_type") and not _row_with_time.get("target_lane_type"):
            _row_with_time["target_lane_type"] = spec.get("target_lane_type")
        if spec.get("query_kind") and not _row_with_time.get("query_kind"):
            _row_with_time["query_kind"] = spec.get("query_kind")
        _fake_serial_block, _fake_serial_reason = _is_fake_serial_base_promo_row(_row_with_time)
        print(
            f"[INGEST_FAKE_SERIAL_CHECK] title={str((_row_with_time or {}).get('title') or '')[:160]} "
            f"block={_fake_serial_block} reason={_fake_serial_reason}"
        )
        if _fake_serial_block:
            diag["fake_serial_dropped_count"] = int(diag.get("fake_serial_dropped_count") or 0) + 1
            print(
                f"[INGEST_FAKE_SERIAL_DROP] title={str((_row_with_time or {}).get('title') or '')[:160]} "
                f"reason={_fake_serial_reason}"
            )
            continue
        _inventory_reject, _inventory_reason = _is_non_single_inventory_title(
            _row_with_time.get("title") or _row_with_time.get("source_title") or "",
            _row_with_time,
        )
        if _inventory_reject:
            _row_with_time["commercially_visible"] = False
            _row_with_time["board_visible"] = False
            _row_with_time["blocked_reason"] = _inventory_reason or "non_single_inventory"
            _row_with_time["hidden_reason"] = _inventory_reason or "non_single_inventory"
            _row_with_time["excluded_from_valuation"] = True
            _row_with_time["exclusion_reason"] = _inventory_reason or "non_single_inventory"
            if _inventory_reason == "generic_break_insert":
                print(
                    f"[GENERIC_BREAK_REJECT] title={str(_row_with_time.get('title') or _row_with_time.get('source_title') or '')[:140]} "
                    f"reason=break_insert_generic"
                )
                print(
                    f"[INTAKE_REJECT] title={str(_row_with_time.get('title') or _row_with_time.get('source_title') or '')[:140]} "
                    f"reason=generic_break_insert"
                )
            else:
                print(
                    f"[NON_SINGLE_INVENTORY_REJECT] title={str(_row_with_time.get('title') or _row_with_time.get('source_title') or '')[:140]} "
                    f"reason=packaging_inventory"
                )
                print(
                    f"[INTAKE_REJECT] title={str(_row_with_time.get('title') or _row_with_time.get('source_title') or '')[:140]} "
                    f"reason=non_single_inventory"
                )
            continue
        _low_value_insert_reject, _low_value_insert_reason = _is_low_value_insert_row(_row_with_time)
        if _low_value_insert_reject:
            _insert_family = _normalize_subset_name(
                str(
                    _row_with_time.get("insert_family")
                    or _row_with_time.get("identity_insert_family")
                    or _row_with_time.get("fingerprint_insert_family")
                    or _row_with_time.get("subset_name")
                    or _row_with_time.get("subset_family")
                    or ""
                ).strip()
            )
            _row_with_time["commercially_visible"] = False
            _row_with_time["board_visible"] = False
            _row_with_time["blocked_reason"] = _low_value_insert_reason or "low_value_insert"
            _row_with_time["hidden_reason"] = _low_value_insert_reason or "low_value_insert"
            _row_with_time["excluded_from_valuation"] = True
            _row_with_time["exclusion_reason"] = _low_value_insert_reason or "low_value_insert"
            print(
                f"[LOW_VALUE_INSERT_REJECT] title={str(_row_with_time.get('title') or _row_with_time.get('source_title') or '')[:140]} "
                f"insert_family={_insert_family[:32]} parallel_family={str(_row_with_time.get('parallel_family') or _row_with_time.get('parallel_name') or _row_with_time.get('parallel') or '')[:24]} reason=low_value_insert_parallel"
            )
            continue
        _normalized_auction_rows.append(_row_with_time)
        _bucket_label = _window_bucket_label(_secs_remaining)
        _bucket_counts = diag.setdefault("window_bucket_counts", {})
        _bucket_counts[_bucket_label] = int(_bucket_counts.get(_bucket_label, 0) or 0) + 1
        if _secs_remaining is not None:
            _cur_min = diag.get("min_seconds_remaining")
            _cur_max = diag.get("max_seconds_remaining")
            diag["min_seconds_remaining"] = _secs_remaining if _cur_min is None else min(float(_cur_min), _secs_remaining)
            diag["max_seconds_remaining"] = _secs_remaining if _cur_max is None else max(float(_cur_max), _secs_remaining)
            if len(_time_check_samples) < 5:
                _time_check_samples.append(round(float(_secs_remaining), 2))
        print(
            f"[ES][WINDOW_DEBUG] "
            f"window_hours={time_window_hours} "
            f"window_sec={int(round(_window_threshold_seconds))} "
            f"remaining={round(float(_secs_remaining), 2) if _secs_remaining is not None else 'na'} "
            f"keep={1 if _keep_row else 0} reason={_drop_reason} "
            f"src={str(_window_decision.get('_source') or '?')} "
            f"title={str(_row_with_time.get('title') or '')[:60]!r} "
            f"end_time={end_dt_it.isoformat() if isinstance(end_dt_it, datetime) else 'na'} "
            f"now_ts={now.isoformat()}"
        )
        if bool(_premium_window_meta.get("allowed")):
            print(
                f"[PREMIUM_WINDOW] item={str(it.get('itemId') or '')[:18] or '?'} "
                f"original_window={float(time_window_hours or 0.0):.2f} "
                f"extended_window={float(time_window_hours or 0.0) + _premium_window_extension_hours:.2f} "
                f"kept={1 if _keep_row else 0}"
            )
        if not _keep_row:
            _premium_yield_allow, _premium_yield_reason = _premium_live_yield_override_contract(
                _row_with_time,
                strict_window_seconds=_window_threshold_seconds,
            )
            print(
                f"[PREMIUM_LIVE_YIELD_OVERRIDE] "
                f"title={str(_row_with_time.get('title') or _row_with_time.get('source_title') or '')[:160]} "
                f"allow={int(bool(_premium_yield_allow))} "
                f"reason={_premium_yield_reason} "
                f"remaining_seconds={_secs_remaining} "
                f"strict_window={_window_threshold_seconds} "
                f"grade={_row_with_time.get('grade') or _row_with_time.get('grade_label')} "
                f"insert_family={_row_with_time.get('insert_family') or _row_with_time.get('_hydrated_insert_family')} "
                f"parallel_family={_row_with_time.get('parallel_family') or _row_with_time.get('_hydrated_parallel_family')} "
                f"serial_denominator={_row_with_time.get('serial_denominator') or _row_with_time.get('_hydrated_serial_denominator') or _row_with_time.get('serial')} "
                f"premium_lane={_row_with_time.get('premium_lane')} "
                f"identity_is_clean={_row_with_time.get('identity_is_clean') or _row_with_time.get('_hydrated_identity_is_clean') or 1}"
            )
            if _premium_yield_allow:
                if bool(_row_with_time.get("_premium_case_hit_survivor")):
                    print(
                        f"[PREMIUM_CASE_HIT_ASSERT] "
                        f"title={str(_row_with_time.get('title') or _row_with_time.get('source_title') or '')[:160]} "
                        f"final_keep=1 "
                        f"final_reason={_premium_yield_reason} "
                        f"surface_intent={_row_with_time.get('surface_intent')} "
                        f"premium_lane={_row_with_time.get('premium_lane')} "
                        f"board_visible={_row_with_time.get('board_visible')} "
                        f"commercially_visible={_row_with_time.get('commercially_visible')}"
                    )
                _row_with_time["_premium_live_yield_override"] = True
                _row_with_time["_premium_live_yield_reason"] = _premium_yield_reason
                _row_with_time["_strict_window_eligible"] = False
                _row_with_time["_window_edge_rescue"] = True
                _row_with_time["window_edge_rescue"] = True
                _row_with_time["window_edge_bucket"] = "premium_live_yield"
                _row_with_time["window_edge_label"] = "PREPARE"
                _row_with_time["window_edge_display_state"] = "PREPARE"
                _row_with_time["surface_intent"] = str(_row_with_time.get("surface_intent") or "watchlist")
                edge_window_rows.append(_row_with_time)
                premium_live_rescue_rows.append(_row_with_time)
                _window_edge_rescued += 1
                _premium_live_yield_overrides += 1
                if _secs_remaining is not None:
                    _premium_live_yield_nearest = (
                        float(_secs_remaining)
                        if _premium_live_yield_nearest is None
                        else min(float(_premium_live_yield_nearest), float(_secs_remaining))
                    )
                diag["premium_live_yield_override_count"] = int(diag.get("premium_live_yield_override_count") or 0) + 1
                if bool(_row_with_time.get("_premium_case_hit_survivor")):
                    case_hit_live_rescue_rows.append(_row_with_time)
                    diag["premium_case_hit_live_yield_count"] = int(diag.get("premium_case_hit_live_yield_count") or 0) + 1
                diag["time_filter_override_count"] = int(diag.get("time_filter_override_count") or 0) + 1
                print(
                    f"[PREMIUM_LIVE_YIELD_OVERRIDE_KEEP] "
                    f"title={str(_row_with_time.get('title') or _row_with_time.get('source_title') or '')[:160]} "
                    f"remaining_seconds={_secs_remaining} strict_window={_window_threshold_seconds} "
                    f"reason={_premium_yield_reason}"
                )
                print(
                    f"[TIME_WINDOW_BRANCH] "
                    f"remaining_seconds={round(float(_secs_remaining), 2) if _secs_remaining is not None else 'na'} "
                    f"window_seconds={int(round(_window_threshold_seconds))} "
                    f"grace_seconds=0 "
                    f"decision=premium_yield_override_keep "
                    f"reason={_premium_yield_reason}"
                )
                continue
            _edge_rescue = _window_edge_rescue_decision(
                remaining_seconds=_secs_remaining,
                threshold_seconds=_window_threshold_seconds,
                grace_seconds=_WINDOW_EDGE_RESCUE_GRACE_SECONDS,
            )
            if (
                _drop_reason == "missed_window"
                and end_dt_it is not None
                and bool(_edge_rescue.get("rescued"))
            ):
                _row_with_time["window_edge_rescue"] = True
                _row_with_time["window_edge_threshold_seconds"] = float(_edge_rescue.get("threshold_seconds") or 0.0)
                _row_with_time["window_edge_grace_seconds"] = float(_edge_rescue.get("grace_seconds") or 0.0)
                _row_with_time["window_edge_bucket"] = "prepare_watchlist"
                _row_with_time["window_edge_label"] = "PREPARE"
                _row_with_time["window_edge_display_state"] = "PREPARE"
                _row_with_time["_strict_window_eligible"] = False
                _row_with_time["_window_edge_rescue"] = True
                edge_window_rows.append(_row_with_time)
                _window_edge_rescued += 1
                print(
                    f"[WINDOW_EDGE_RESCUE] title={str(_row_with_time.get('title') or '')[:120]} "
                    f"item={str(_row_with_time.get('itemId') or _row_with_time.get('item_id') or '')[:18] or '?'} "
                    f"remaining={round(float(_secs_remaining), 2) if _secs_remaining is not None else 'na'} "
                    f"threshold={round(float(_window_threshold_seconds), 2)} "
                    f"grace={round(float(_WINDOW_EDGE_RESCUE_GRACE_SECONDS), 2)} rescued=1"
                )
                print(
                    f"[TIME_WINDOW_BRANCH] "
                    f"remaining_seconds={round(float(_secs_remaining), 2) if _secs_remaining is not None else 'na'} "
                    f"window_seconds={int(round(_window_threshold_seconds))} "
                    f"grace_seconds={round(float(_WINDOW_EDGE_RESCUE_GRACE_SECONDS), 2)} "
                    f"decision=window_edge_rescue "
                    f"reason={_drop_reason}"
                )
                if (
                    _secs_remaining is not None
                    and _secs_remaining <= _expanded_window_threshold_seconds
                    and (MIN_PRICE <= _parse_price(_row_with_time) <= MAX_PRICE)
                ):
                    expanded_window.append(_row_with_time)
                continue
            if _drop_reason == "missing_end_time":
                _bucket_counts = diag.setdefault("window_bucket_counts", {})
                _bucket_counts["missing"] = int(_bucket_counts.get("missing", 0) or 0) + 1
            else:
                diag["outside_window_count"] = int(diag.get("outside_window_count") or 0) + 1
                if _drop_reason == "missed_window":
                    _window_missed_far += 1
            diag["time_filter_reject_count"] = int(diag.get("time_filter_reject_count") or 0) + 1
            print(
                f"[TIME_WINDOW_BRANCH] "
                f"remaining_seconds={round(float(_secs_remaining), 2) if _secs_remaining is not None else 'na'} "
                f"window_seconds={int(round(_window_threshold_seconds))} "
                f"grace_seconds={round(float(_WINDOW_EDGE_RESCUE_GRACE_SECONDS), 2)} "
                f"decision=time_filter_reject "
                f"reason={_drop_reason}"
            )
            # [TIME_FILTER_REJECT] — terminal rejection by time/window filter.
            print(
                f"[TIME_FILTER_REJECT] "
                f"item={str((it or {}).get('itemId') or (it or {}).get('item_id') or (it or {}).get('source_item_id') or '')[:32]} "
                f"title={str((_row_with_time or {}).get('title') or (_row_with_time or {}).get('source_title') or '')[:120]} "
                f"raw_itemEndDate={str((it or {}).get('itemEndDate') or '')[:64]!r} "
                f"parsed_end_dt={end_dt_it.isoformat() if isinstance(end_dt_it, datetime) else 'na'} "
                f"remaining_seconds={round(float(_secs_remaining), 2) if _secs_remaining is not None else 'na'} "
                f"window_seconds={int(round(_window_threshold_seconds))} "
                f"window_hours={float(time_window_hours or 0.0):.2f} "
                f"reason={_drop_reason} "
                f"parse_source={str(_window_decision.get('_source') or '?')}"
            )
            if (
                _secs_remaining is not None
                and _secs_remaining <= _expanded_window_threshold_seconds
                and (MIN_PRICE <= _parse_price(_row_with_time) <= MAX_PRICE)
            ):
                expanded_window.append(_row_with_time)
            continue
        # [TIME_FILTER_ACCEPT] — row passed the time/window gate (strict or override).
        print(
            f"[TIME_FILTER_ACCEPT] "
            f"item={str((it or {}).get('itemId') or (it or {}).get('item_id') or (it or {}).get('source_item_id') or '')[:32]} "
            f"title={str((_row_with_time or {}).get('title') or (_row_with_time or {}).get('source_title') or '')[:120]} "
            f"raw_itemEndDate={str((it or {}).get('itemEndDate') or '')[:64]!r} "
            f"parsed_end_dt={end_dt_it.isoformat() if isinstance(end_dt_it, datetime) else 'na'} "
            f"remaining_seconds={round(float(_secs_remaining), 2) if _secs_remaining is not None else 'na'} "
            f"window_seconds={int(round(_window_threshold_seconds))} "
            f"window_hours={float(time_window_hours or 0.0):.2f} "
            f"reason={_drop_reason} "
            f"premium_window_kept={1 if _premium_window_kept else 0} "
            f"parse_source={str(_window_decision.get('_source') or '?')}"
        )
        window_rows.append(_row_with_time)
        diag["within_window_count"] = int(diag.get("within_window_count") or 0) + 1
        print(
            f"[TIME_WINDOW_BRANCH] "
            f"remaining_seconds={round(float(_secs_remaining), 2) if _secs_remaining is not None else 'na'} "
            f"window_seconds={int(round(_window_threshold_seconds))} "
            f"grace_seconds=0 "
            f"decision=within_window_accept "
            f"reason={_drop_reason}"
        )

    _fallback_6h_count = 0
    _fallback_12h_count = 0
    if len(window_rows) < 3 and _normalized_auction_rows:
        print(
            f"[WINDOW_FALLBACK_TRIGGER] selected_hours={float(time_window_hours or 0.0):.2f} "
            f"inside_selected={len(window_rows)} "
            f"normalized_rows={len(_normalized_auction_rows)} "
            f"missed_window={int(_window_reason_counts.get('missed_window') or 0)}"
        )
        _seen_window_items = {
            str((_row or {}).get("itemId") or (_row or {}).get("item_id") or (_row or {}).get("source_item_id") or "")
            for _row in list(window_rows) + list(edge_window_rows)
        }
        _fallback_rows: List[Dict[str, Any]] = []
        for _fallback_hours in (6.0, 12.0):
            if len(window_rows) + len(edge_window_rows) + len(_fallback_rows) >= 3:
                break
            _fallback_threshold_seconds = max(300.0, float(_fallback_hours) * 3600.0)
            for _src_row in _normalized_auction_rows:
                _item_key = str((_src_row or {}).get("itemId") or (_src_row or {}).get("item_id") or (_src_row or {}).get("source_item_id") or "")
                if _item_key and (_item_key in _seen_window_items):
                    continue
                _fallback_decision = _window_filter_decision(
                    _src_row,
                    now_dt=now,
                    window_seconds=_fallback_threshold_seconds,
                )
                if not bool(_fallback_decision.get("keep")):
                    continue
                _allowed, _collector_heat, _identity_is_clean = _window_fallback_candidate_allowed(_src_row)
                if not _allowed:
                    continue
                _fallback_row = dict(_src_row)
                _remaining_seconds = _safe_float(_fallback_decision.get("remaining_seconds"))
                _fallback_row["remaining_seconds"] = _remaining_seconds
                _fallback_row["seconds_remaining"] = _remaining_seconds
                _fallback_row["_fallback_window_used"] = int(_fallback_hours)
                _fallback_row["_fallback_window_reason"] = "thin_selected_window"
                _fallback_row["surface_intent"] = str(_fallback_row.get("surface_intent") or "monitor")
                _fallback_row["_research_only_price_check"] = True
                _fallback_row["_research_only_reason"] = str(_fallback_row.get("_research_only_reason") or "thin_selected_window")
                _fallback_row = _stamp_window_contract_fields(
                    _fallback_row,
                    keep=True,
                    threshold_seconds=_fallback_threshold_seconds,
                    remaining_seconds=_remaining_seconds,
                    source=f"fallback_{int(_fallback_hours)}h:thin_selected_window",
                    checked_at=now,
                )
                _fallback_rows.append(_fallback_row)
                if _item_key:
                    _seen_window_items.add(_item_key)
                if int(_fallback_hours) == 6:
                    _fallback_6h_count += 1
                else:
                    _fallback_12h_count += 1
                print(
                    f"[WINDOW_FALLBACK_ROW] title={str(_fallback_row.get('title') or _fallback_row.get('source_title') or '')[:160]} "
                    f"fallback_hours={int(_fallback_hours)} "
                    f"remaining_seconds={round(float(_remaining_seconds), 2) if _remaining_seconds is not None else 'na'} "
                    f"collector_heat={1 if _collector_heat else 0} "
                    f"identity_is_clean={1 if _identity_is_clean else 0}"
                )
                print(
                    f"[TIME_WINDOW_BRANCH] "
                    f"remaining_seconds={round(float(_remaining_seconds), 2) if _remaining_seconds is not None else 'na'} "
                    f"window_seconds={int(round(_fallback_threshold_seconds))} "
                    f"grace_seconds=0 "
                    f"decision=window_fallback_keep "
                    f"reason=thin_selected_window_{int(_fallback_hours)}h"
                )
                if len(window_rows) + len(edge_window_rows) + len(_fallback_rows) >= 3:
                    break
        if _fallback_rows:
            edge_window_rows.extend(_fallback_rows)
    print(
        f"[WINDOW_FALLBACK_SUMMARY] selected_inside={len(window_rows)} "
        f"fallback_6h={_fallback_6h_count} "
        f"fallback_12h={_fallback_12h_count} "
        f"final_candidates={len(window_rows) + len(edge_window_rows)}"
    )
    print(
        f"[EDGE_WINDOW_ROWS_ASSERT] "
        f"strict_live_rows={len(window_rows)} "
        f"edge_window_rows={len(edge_window_rows)} "
        f"premium_live_rescue_rows={len(premium_live_rescue_rows)} "
        f"case_hit_live_rescue_rows={len(case_hit_live_rescue_rows)}"
    )

    _window_handoff_rows = list(window_rows) + list(edge_window_rows)
    diag["parsed_rows_count"] = int(len(_normalized_auction_rows))
    diag["time_check_threshold_seconds"] = _window_threshold_seconds
    diag["strict_window_seconds"] = _window_threshold_seconds
    diag["time_check_remaining_seconds"] = _time_check_samples
    diag["window_drop_reason_counts"] = dict(_window_reason_counts)
    diag["window_edge_rescue_count"] = int(_window_edge_rescued)
    diag["nearest_remaining"] = diag.get("min_seconds_remaining")
    diag["rows_returned"] = int(diag.get("raw_rows_count") or 0)
    diag["in_window_count"] = int(len(window_rows))
    diag["out_of_window_count"] = int(diag.get("outside_window_count") or 0)
    diag["nearest_remaining_seconds"] = diag.get("nearest_remaining")
    _kept_time_check_samples = [
        round(float(_row.get("remaining_seconds")), 2)
        for _row in window_rows[:5]
        if _row.get("remaining_seconds") is not None
    ]
    diag["time_check_kept_remaining_seconds"] = _kept_time_check_samples
    diag["within_window_count"] = len(window_rows)
    diag["bin_rows_count"] = len(window_rows)
    diag["window_rows_forwarded"] = int(len(_window_handoff_rows))
    diag["window_viability_score"] = compute_window_viability(
        diag.get("rows_returned"),
        diag.get("in_window_count"),
        diag.get("nearest_remaining_seconds"),
        diag.get("response_scope_valid"),
    )
    _nearest_remaining_seconds = _safe_float(diag.get("nearest_remaining_seconds"))
    _window_dead_lane = bool(
        int(diag.get("rows_returned") or 0) > 0
        and int(diag.get("in_window_count") or 0) == 0
        and int(diag.get("premium_live_yield_override_count") or 0) == 0
        and _nearest_remaining_seconds is not None
        and float(_window_threshold_seconds) > 0.0
        and float(_nearest_remaining_seconds) > float(_window_threshold_seconds) * 2.0
    )
    diag["dead_live_lane"] = bool(_window_dead_lane)
    if _premium_live_yield_overrides > 0:
        diag["premium_live_yield_nearest_remaining"] = _premium_live_yield_nearest
        diag["dead_live_lane"] = False
    diag["_window_rows_out"] = [dict(_row) for _row in _window_handoff_rows]
    print(f"[ES][WINDOW_ASSIGN] kept_count={len(window_rows)} window_rows={len(window_rows)}")
    print(f"[ES][WINDOW_HANDOFF] kept_count={len(window_rows)} window_rows={len(window_rows)}")
    print(
        f"[WINDOW_VIABILITY] lane={_lane_key[:64]} "
        f"rows_returned={int(diag.get('rows_returned') or 0)} "
        f"in_window={int(diag.get('in_window_count') or 0)} "
        f"out_of_window={int(diag.get('out_of_window_count') or 0)} "
        f"nearest_remaining={round(float(_nearest_remaining_seconds), 2) if _nearest_remaining_seconds is not None else 'na'} "
        f"response_scope_valid={1 if diag.get('response_scope_valid') else 0} "
        f"score={float(diag.get('window_viability_score') or 0.0):.3f}"
    )
    if _window_dead_lane:
        print(
            f"[WINDOW_DEAD_LANE] lane={_lane_key[:64]} "
            f"reason=no_near_term_supply "
            f"nearest_remaining={round(float(_nearest_remaining_seconds), 2) if _nearest_remaining_seconds is not None else 'na'} "
            f"window_seconds={round(float(_window_threshold_seconds), 2)}"
        )
    print(
        f"[WINDOW_EDGE_SUMMARY] strict_within={len(window_rows)} "
        f"edge_rescued={len(edge_window_rows)} missed_far={_window_missed_far}"
    )
    if _time_check_samples and not window_rows:
        print("[ES][WINDOW_ASSIGN_ERROR] kept rows identified but window_rows empty")

    for _row in _normalized_auction_rows[:25]:
        _remaining = _row_remaining_seconds(_row)
        _decision = _window_filter_decision(
            _row,
            now_dt=now,
            window_seconds=_window_threshold_seconds,
        )
        _should_keep = bool(_decision.get("keep"))
        _is_kept = any(str((_k or {}).get("itemId") or (_k or {}).get("item_id") or "") == str(_row.get("itemId") or _row.get("item_id") or "") for _k in window_rows)
        if _should_keep and not _is_kept:
            print(
                f"[ES][WINDOW_ERROR] row dropped incorrectly "
                f"remaining={round(float(_remaining), 2) if _remaining is not None else 'na'} "
                f"window_sec={int(round(_window_threshold_seconds))} "
                f"reason={str(_decision.get('reason') or '')} "
                f"title={str(_row.get('title') or '')[:60]!r}"
            )

    print(
        f"[ES][WINDOW_SUMMARY] "
        f"parsed={len(_normalized_auction_rows)} kept={len(window_rows)} "
        f"window_hours={time_window_hours} window_sec={int(round(_window_threshold_seconds))} "
        f"within={int(_window_reason_counts.get('within_window') or 0)} "
        f"missed={int(_window_reason_counts.get('missed_window') or 0)} "
        f"missing_end={int(_window_reason_counts.get('missing_end_time') or 0)} "
        f"invalid={int(_window_reason_counts.get('invalid_remaining') or 0)}"
    )
    print(
        f"[TIME_FILTER_SUMMARY] fetched={int(diag.get('raw_rows_count') or 0)} "
        f"normalized={len(_window_handoff_rows) if '_window_handoff_rows' in locals() else len(window_rows) + len(edge_window_rows)} "
        f"time_filter_rejects={int(diag.get('time_filter_reject_count') or 0)} "
        f"time_filter_overrides={int(diag.get('time_filter_override_count') or _time_filter_overrides or 0)} "
        f"within_window={len(window_rows)}"
    )
    print(
        f"[WINDOW_SURVIVORS] lane={_lane_key[:64]} variant={str(variant.get('variant_name') or 'primary')[:32]} "
        f"within={int(_window_reason_counts.get('within_window') or 0)} "
        f"missed={int(_window_reason_counts.get('missed_window') or 0)} "
        f"missing_end={int(_window_reason_counts.get('missing_end_time') or 0)} "
        f"invalid={int(_window_reason_counts.get('invalid_remaining') or 0)}"
    )
    if len(_normalized_auction_rows) > 0 and len(window_rows) == 0 and not edge_window_rows:
        print(
            f"[ES][WINDOW_EMPTY] ALERT: {len(_normalized_auction_rows)} parsed rows but 0 kept. "
            f"window_hours={time_window_hours} window_sec={int(round(_window_threshold_seconds))} "
            f"drop_reasons={dict(_window_reason_counts)} "
            f"sample_remaining={_time_check_samples[:4]}"
        )

    if not _window_handoff_rows:
        diag["failure_stage"]  = "time_filter"
        diag["failure_reason"] = (
            f"{diag['raw_rows_count']} raw items but none within "
            f"{time_window_hours}h window"
        )
        diag["_runtime_branch"] = "zero_rows"
        try:
            _tff_samples: List[Dict[str, Any]] = []
            for _tff_it in list(_normalized_auction_rows or [])[:5]:
                _tff_raw_end = (_tff_it or {}).get("itemEndDate") or (_tff_it or {}).get("item_end_date") or (_tff_it or {}).get("endDate") or ""
                _tff_parsed = (_tff_it or {}).get("_parsed_end_dt") or (_tff_it or {}).get("end_dt")
                _tff_parsed_iso = _tff_parsed.isoformat() if isinstance(_tff_parsed, datetime) else "na"
                _tff_remaining = (_tff_it or {}).get("_remaining_seconds")
                if _tff_remaining is None:
                    _tff_remaining = (_tff_it or {}).get("remaining_seconds")
                _tff_samples.append({
                    "raw": str(_tff_raw_end)[:48],
                    "parsed": _tff_parsed_iso,
                    "rem_s": (round(float(_tff_remaining), 2) if _tff_remaining is not None else None),
                    "raw_type": type(_tff_raw_end).__name__,
                })
            print(
                f"[TIME_FILTER_FAILURE_SAMPLE] "
                f"raw_rows={int(diag.get('raw_rows_count') or 0)} "
                f"window_hours={float(time_window_hours or 0.0):.2f} "
                f"window_seconds={int(round(_window_threshold_seconds))} "
                f"sample_remaining={list(_time_check_samples or [])[:5]} "
                f"drop_reasons={dict(_window_reason_counts or {})} "
                f"item_samples={_tff_samples}"
            )
        except Exception as _tff_exc:
            print(f"[TIME_FILTER_FAILURE_SAMPLE] error={type(_tff_exc).__name__} msg={str(_tff_exc)[:120]}")
        diag["_items_out"] = []
        diag["_title_rows_out"] = []
        diag["_expanded_items_out"] = [dict(_row) for _row in expanded_window]
        print(
            f"[FETCH_COUNT] lane={_lane_key[:64]} variant={str(variant.get('variant_name') or 'primary')[:32]} "
                f"raw={int(diag.get('raw_rows_count') or 0)} parsed_auction={len(_auction_shaped_rows)} "
                f"within_window=0 title_pass=0 target_pass=0 keep=0 stop=0 reason=time_filter"
            )
        print(
            f"[RUNTIME_PATH] family={spec['player_name']} "
            f"raw_window_rows={len(raw_window_rows)} window_rows={len(window_rows)} "
            f"title_rows={len(title_passed)} built_rows={len(raw_window_rows)}"
        )
        print(
            f"[VARIANT_EXPANDED_OUT] query={str(variant.get('query') or '')!r} "
            f"strict_window_rows={len(window_rows)} expanded_window_rows={len(expanded_window)} "
            f"preserved_out={len(diag.get('_expanded_items_out') or [])}"
        )
        print(f"[RUNTIME_SAFE] family={spec['player_name']} branch=zero_rows")
        print(
            f"[LIVE_YIELD_RUNTIME_SUMMARY] "
            f"strict_live_rows={len(window_rows)} "
            f"edge_window_rows={len(edge_window_rows)} "
            f"premium_live_rescue_rows={len(premium_live_rescue_rows)} "
            f"dead_live_lanes={1 if diag.get('dead_live_lane') else 0} "
            f"error_free=1"
        )
        return diag

    _title_pass_counts: Dict[str, int] = {
        "raw_single": 0,
        "memorabilia": 0,
        "parallel": 0,
        "auto": 0,
    }
    _discovery_title_input = 0
    _discovery_title_blocked = 0
    _discovery_title_rows: List[Dict[str, Any]] = []
    _discovery_quality_reason_counts: Dict[str, int] = {}
    for it in _window_handoff_rows:
        t = str(it.get("title") or "")
        _lane_quality = classify_lane_quality(t)
        diag["total_listings_seen"] = int(diag.get("total_listings_seen") or 0) + 1
        if _lane_quality == "BLOCK":
            diag["total_listings_blocked"] = int(diag.get("total_listings_blocked") or 0) + 1
            _discovery_title_blocked += 1
            print(f"[DISCOVERY_BLOCK] title={t[:140]} reason=low_quality_lane")
            # ── DISCOVERY_QUALITY_DROP per-row observability ────────────────────
            _dqd_reason = "low_quality_lane"
            _discovery_quality_reason_counts[_dqd_reason] = int(_discovery_quality_reason_counts.get(_dqd_reason, 0) or 0) + 1
            try:
                _dqd_current_price: Any = it.get("current_price")
                if _dqd_current_price is None:
                    _dqd_cbp = it.get("currentBidPrice") or {}
                    if isinstance(_dqd_cbp, dict):
                        _dqd_current_price = _dqd_cbp.get("value") or _dqd_cbp.get("amount") or _dqd_cbp.get("convertedFromValue")
                if _dqd_current_price is None:
                    _dqd_price_field = it.get("price") or {}
                    if isinstance(_dqd_price_field, dict):
                        _dqd_current_price = _dqd_price_field.get("value") or _dqd_price_field.get("amount")
            except Exception:
                _dqd_current_price = None
            _dqd_remaining = it.get("remaining_seconds")
            if _dqd_remaining is None:
                _dqd_remaining = it.get("seconds_remaining") or it.get("_window_remaining_seconds")
            try:
                _dqd_remaining_str = (
                    f"{float(_dqd_remaining):.0f}" if _dqd_remaining is not None else "na"
                )
            except Exception:
                _dqd_remaining_str = str(_dqd_remaining or "na")[:32]
            print(
                f"[DISCOVERY_QUALITY_DROP] "
                f"item_id={str(it.get('itemId') or it.get('item_id') or it.get('source_item_id') or '')[:32]} "
                f"title={t[:120]} "
                f"player={str(spec.get('player_name') or it.get('player_name') or '')[:48]} "
                f"product={str(spec.get('lane_product') or spec.get('target_product_family') or it.get('lane_product') or '')[:48]} "
                f"current_price={_dqd_current_price if _dqd_current_price is not None else 'na'} "
                f"serial={str(it.get('serial_denominator') or it.get('serial') or it.get('_hydrated_serial_denominator') or '')[:24]} "
                f"grade={str(it.get('grade') or it.get('grade_label') or '')[:24]} "
                f"reason={_dqd_reason} "
                f"remaining_seconds={_dqd_remaining_str}"
            )
            # ────────────────────────────────────────────────────────────────────
            continue
        diag["total_listings_admitted"] = int(diag.get("total_listings_admitted") or 0) + 1
        _discovery_title_input += 1
        _discovery_title_rows.append(it)
        if _lane_quality == "PREMIUM":
            diag["discovery_premium_admitted"] = int(diag.get("discovery_premium_admitted") or 0) + 1
        elif _lane_quality == "CONDITIONAL":
            diag["discovery_conditional_admitted"] = int(diag.get("discovery_conditional_admitted") or 0) + 1
        _profile = _title_filter_profile(t, tier)
        if _passes_grade_filter(t) and bool(_profile.get("keep")):
            title_passed.append(it)
            for _k in list(_title_pass_counts.keys()):
                if bool(_profile.get(_k)):
                    _title_pass_counts[_k] = int(_title_pass_counts.get(_k, 0) or 0) + 1

    if _discovery_title_blocked > 0 or _discovery_quality_reason_counts:
        print(
            f"[DISCOVERY_QUALITY_SUMMARY] "
            f"total_rejected={_discovery_title_blocked} "
            f"reason_counts={dict(_discovery_quality_reason_counts or {})}"
        )
    diag["title_pass_count"] = len(title_passed)
    diag["title_filter_reject_count"] = max(0, _discovery_title_input - len(title_passed))
    diag["title_filter_pass_counts"] = dict(_title_pass_counts)
    _title_filter_samples = _sample_titles_for_rows([_row for _row in _discovery_title_rows if _row not in title_passed])
    print(
        f"[ES][TITLE_FILTER] in={_discovery_title_input} out={len(title_passed)} "
        f"rejects={max(0, _discovery_title_input - len(title_passed))} reasons={{'grade_or_card_type': {max(0, _discovery_title_input - len(title_passed))}}}"
    )
    print(
        f"[ES][TITLE_FILTER_PASS] raw_single={int(_title_pass_counts.get('raw_single') or 0)} "
        f"memorabilia={int(_title_pass_counts.get('memorabilia') or 0)} "
        f"parallel={int(_title_pass_counts.get('parallel') or 0)} "
        f"auto={int(_title_pass_counts.get('auto') or 0)}"
    )
    print(f"[ES][WINDOW_HANDOFF] title_rows={len(title_passed)} title_rejects={max(0, _discovery_title_input - len(title_passed))}")
    if _title_filter_samples:
        print(f"[ES][FUNNEL][SAMPLE] title_filter grade_or_card_type -> {_title_filter_samples}")

    if not title_passed:
        if _discovery_title_input <= 0 and _discovery_title_blocked > 0:
            diag["failure_stage"] = "discovery_lane_quality"
            diag["failure_reason"] = (
                f"{_discovery_title_blocked} items in strict_or_edge_window blocked by discovery lane quality gate"
            )
        else:
            diag["failure_stage"]  = "title_filter"
            diag["failure_reason"] = (
                f"{_discovery_title_input} discovery-admitted items in strict_or_edge_window but all failed grade/card-type filter"
            )
        diag["_runtime_branch"] = "zero_rows"
        diag["_items_out"] = []
        diag["_title_rows_out"] = []
        diag["_expanded_items_out"] = [dict(_row) for _row in expanded_window]
        print(
            f"[FETCH_COUNT] lane={_lane_key[:64]} variant={str(variant.get('variant_name') or 'primary')[:32]} "
            f"raw={int(diag.get('raw_rows_count') or 0)} parsed_auction={len(_auction_shaped_rows)} "
                f"within_window={len(window_rows)} title_pass=0 target_pass=0 keep=0 stop=0 reason={str(diag.get('failure_stage') or 'title_filter')}"
            )
        print(
            f"[RUNTIME_PATH] family={spec['player_name']} "
            f"raw_window_rows={len(raw_window_rows)} window_rows={len(window_rows)} "
            f"title_rows={len(title_passed)} built_rows={len(raw_window_rows)}"
        )
        print(
            f"[VARIANT_EXPANDED_OUT] query={str(variant.get('query') or '')!r} "
            f"strict_window_rows={len(window_rows)} expanded_window_rows={len(expanded_window)} "
            f"preserved_out={len(diag.get('_expanded_items_out') or [])}"
        )
        print(f"[RUNTIME_SAFE] family={spec['player_name']} branch=zero_rows")
        print(
            f"[LIVE_YIELD_RUNTIME_SUMMARY] "
            f"strict_live_rows={len(window_rows)} "
            f"edge_window_rows={len(edge_window_rows)} "
            f"premium_live_rescue_rows={len(premium_live_rescue_rows)} "
            f"dead_live_lanes={1 if diag.get('dead_live_lane') else 0} "
            f"error_free=1"
        )
        return diag

    def _build_window_row(_it: Dict[str, Any], *, _recovery_window_bucket: str) -> Dict[str, Any]:
        end_dt_it = _extract_auction_end_dt(_it)
        _remaining_seconds = _row_remaining_seconds(_it)
        _title = str(_it.get("title") or "")
        _variant_spec = dict(spec or {})
        _variant_spec["_allow_parallel_miss"] = bool(variant.get("relax_parallel"))
        _variant_spec["_candidate_item_id"] = str(_it.get("itemId") or "")
        _ok_target, _reason, _entity_status, _entity_score, _alias_soft_match = _validate_spec_listing(_title, _variant_spec)
        _log_subset_product_match(_variant_spec, str(_it.get("itemId") or ""), decision=("pass" if _ok_target else "reject"), reason=str(_reason or "ok"))
        _relaxed_target = bool(_variant_spec.get("_target_match_relaxed"))
        _relaxed_target_reason = str(_variant_spec.get("_target_match_reason") or "")
        _auction_bid = _parse_auction_current_price(_it)
        _bin_price = _parse_buy_now_price(_it)
        _row = {
            "item_id":        str(_it.get("itemId") or ""),
            "title":          _title,
            "current_price":  _auction_bid,   # auction bid, not BIN price
            "current_bid":    _auction_bid,
            "buy_now_price":  _bin_price,
            "end_dt":         end_dt_it,
            "end_iso":        _it.get("itemEndDate") or "",
            "url":            str(_it.get("itemWebUrl") or ""),
            "thumbnail":      (_it.get("image") or {}).get("imageUrl") or "",
            "player_name":    spec["player_name"],
            "player_id":      str(spec.get("player_id") or ""),
            "sport":          spec["sport"],
            "whatnot_tier":   spec.get("whatnot_tier"),
            "listing_type":   "AUCTION",
            "_query_variant": variant["variant_name"],
            "target_id":      str(spec.get("target_id") or ""),
            "target_label":   str(spec.get("target_label") or ""),
            "target_meta":    dict(spec.get("target_meta") or {}),
            "target_entity_id": str(spec.get("player_id") or ""),
            "exact_entity_match": _entity_status == "EXACT_MATCH",
            "entity_match_status": _entity_status,
            "entity_match_score": _entity_score,
            "alias_soft_match": bool(_alias_soft_match),
            "subset_name": str(spec.get("subset_name") or (spec.get("target_meta") or {}).get("subset_name") or spec.get("lane_subset") or ""),
            "subset_product_family": str(spec.get("subset_product_family") or (spec.get("target_meta") or {}).get("subset_product_family") or ""),
            "subset_binding_override": bool(spec.get("subset_binding_override") or (spec.get("target_meta") or {}).get("subset_binding_override")),
            "entity_gate_reason": str(_reason or "ok"),
            "lane_approved": bool(_ok_target),
            "route_stage": (
                "premium_soft_valid"
                if _relaxed_target
                else "family_valid_fallback"
                if str(_reason or "") == "family_valid_fallback"
                else "tracked_exact"
            ),
            "route_reason": (
                "Premium near-match accepted under relaxed target routing"
                if _relaxed_target
                else
                "Family-valid live fallback accepted under thin exact route coverage"
                if str(_reason or "") == "family_valid_fallback"
                else "Exact tracked lane match"
            ),
            "query_kind":     str(spec.get("query_kind") or variant["variant_name"]),
            "_intake_type":   str(spec.get("_intake_type") or ""),
            "query_recall_stage": str(variant.get("recall_stage") or "precise"),
            "lane_tier":      str(spec.get("lane_tier") or "primary"),
            "lane_priority":  float(spec.get("lane_priority") or 0.0),
            "target_lane_type": str(spec.get("target_lane_type") or ""),
            "lane_subset": str(spec.get("lane_subset") or ""),
            "lane_parallel": str(spec.get("lane_parallel") or ""),
            "lane_product": str(spec.get("lane_product") or spec.get("target_product_family") or ""),
            "spec_premium_lane": bool(spec.get("spec_premium_lane")),
            "spec_lane_class": str(spec.get("spec_lane_class") or ""),
            "lane_key": _lane_metric_key(spec),
            "elite_whitelist_tier": str(spec.get("elite_whitelist_tier") or ""),
            "elite_whitelist_reason": str(spec.get("elite_whitelist_reason") or ""),
            "premium_product_soft_allowed": bool(spec.get("premium_product_soft_allowed")),
            "requires_strong_listing_chase_signal": bool(spec.get("requires_strong_listing_chase_signal")),
            "lane_seed_chase_missing": bool(spec.get("lane_seed_chase_missing")),
            "scan_time_window_hours": float(_it.get("scan_time_window_hours") or 0.0),
            "premium_window_allowed": bool(_it.get("premium_window_allowed")),
            "premium_window_extension_hours": float(_it.get("premium_window_extension_hours") or 0.0),
            "premium_window_kept": bool(_it.get("premium_window_kept")),
            "premium_window_reason": str(_it.get("premium_window_reason") or ""),
            "target_match_status": "premium_soft_valid" if _relaxed_target else "exact_valid" if bool(_ok_target) else "route_pending",
            "_target_match_relaxed": _relaxed_target,
            "_target_match_reason": _relaxed_target_reason,
            "_target_relax_rejected": bool(_variant_spec.get("_target_relax_rejected")),
            "remaining_seconds": _remaining_seconds,
            "seconds_remaining": _remaining_seconds,
            "buyingOptions":  list(_it.get("buyingOptions") or []),
            "currentBidPrice": dict(_it.get("currentBidPrice") or {}),
            "recovery_window_bucket": _recovery_window_bucket,
            "window_edge_rescue": bool(_it.get("window_edge_rescue")),
            "_window_edge_rescue": bool(_it.get("_window_edge_rescue") or _it.get("window_edge_rescue")),
            "window_edge_threshold_seconds": _safe_float(_it.get("window_edge_threshold_seconds")),
            "window_edge_grace_seconds": _safe_float(_it.get("window_edge_grace_seconds")),
            "window_edge_bucket": str(_it.get("window_edge_bucket") or ""),
            "window_edge_label": str(_it.get("window_edge_label") or ""),
            "window_edge_display_state": str(_it.get("window_edge_display_state") or ""),
            "_strict_window_eligible": bool(_it.get("_strict_window_eligible", True)),
        }
        _row["normalized_entity"] = str(
            spec.get("player_id")
            or spec.get("target_entity_id")
            or player_hub.resolve_hub_player_id_from_display_name(str(spec.get("player_name") or ""))
            or ""
        ).strip()
        _row["_source_contract"] = {
            "item_id": str(_row.get("item_id") or ""),
            "title": str(_row.get("title") or ""),
            "listing_type": str(_row.get("listing_type") or ""),
            "end_iso": str(_row.get("end_iso") or ""),
            "url": str(_row.get("url") or ""),
            "thumbnail": str(_row.get("thumbnail") or ""),
            "remaining_seconds": _row.get("remaining_seconds"),
            "normalized_entity": str(_row.get("normalized_entity") or ""),
            "buyingOptions": list(_row.get("buyingOptions") or []),
            "currentBidPrice": dict(_row.get("currentBidPrice") or {}),
        }
        # ── Frozen target contract bind ────────────────────────────────────────
        # Propagate the originating spec's frozen contract to the row so that
        # downstream routing can prefer the originating contract over any rebuilt
        # aggregate target universe.  Preserved through normalization + routing.
        _row["_target_contract_id"] = str(spec.get("_target_contract_id") or "")
        _row["_target_player"] = str(spec.get("_target_player") or spec.get("player_name") or "")
        _row["_target_sport"] = str(spec.get("_target_sport") or spec.get("sport") or "")
        _row["_target_product_canonical"] = str(spec.get("_target_product_canonical") or spec.get("lane_product") or "")
        _row["_target_subset_family"] = str(spec.get("_target_subset_family") or spec.get("lane_subset") or "")
        _row["_target_source_query"] = str(spec.get("_target_source_query") or "")
        _row["_target_match_scope"] = str(spec.get("_target_match_scope") or spec.get("query_contract_type") or "product_bound")
        print(
            f"[TARGET_CONTRACT_ROW_BIND] item={str(_it.get('itemId') or '')[:18]} "
            f"player={str(spec.get('player_name') or '')[:24]} "
            f"sport={_row['_target_sport']} "
            f"product={_row['_target_product_canonical'][:28] or 'none'} "
            f"scope={_row['_target_match_scope']} "
            f"lane_ok={int(bool(_ok_target))}"
        )
        _stamp_normalized_entity(_row)
        _stamp_source_listing_truth(_row)
        _listing_has_signal, _listing_reason = _listing_has_strong_chase_signal(_row)
        _row["listing_has_strong_chase_signal"] = bool(_listing_has_signal)
        _row["listing_chase_reason"] = str(_listing_reason or "")
        _row["rejected_for_listing_chase"] = False
        if bool(_row.get("requires_strong_listing_chase_signal")):
            print(
                f"[LISTING_CHASE_GATE] item={str(_row.get('item_id') or '')[:18]} "
                f"product={str(_row.get('target_product_family') or _row.get('lane_product') or '')[:40]} "
                f"allowed={1 if _listing_has_signal else 0} reason={str(_listing_reason or 'listing_missing_chase_signal')[:48]}"
            )
            _entity_reason = str(_row.get("entity_gate_reason") or "").strip().lower()
            _entity_status_norm = str(_row.get("entity_match_status") or "").strip().upper()
            if (not _listing_has_signal) and _entity_reason not in _HARD_ENTITY_REJECT_REASONS and _entity_status_norm != "NO_MATCH":
                _row["rejected_for_listing_chase"] = True
                _row["lane_approved"] = False
                _row["entity_gate_reason"] = "listing_missing_chase_signal"
                _row["route_stage"] = "route_rejected"
                _row["route_reason"] = "Soft premium lane listing lacked a true chase signal"
        if _relaxed_target:
            print(f"[TARGET_RELAX_PASS] title={_row.get('title','')[:140]} reason={_row.get('_target_match_reason')}")
        print(
            f"[PRICE_CHAIN_TRACE] stage=build_window_row "
            f"item_id={str(_row.get('item_id') or _row.get('itemId') or '')} "
            f"title={str(_row.get('title') or '')[:80]} "
            f"current_price={_row.get('current_price')} "
            f"current_price_type={type(_row.get('current_price')).__name__ if _row.get('current_price') is not None else 'None'} "
            f"current_bid={_row.get('current_bid')} "
            f"_board_current_price={_row.get('_board_current_price')} "
            f"authoritative_current_price={_row.get('authoritative_current_price')}"
        )
        return _row

    candidates: List[Dict[str, Any]] = []
    _contaminated_title_checked = 0
    _contaminated_title_blocked = 0
    for it in title_passed:
        _row_base = _build_window_row(it, _recovery_window_bucket="original")
        _contaminated_title_checked += 1
        _contam_reason = _contaminated_multi_card_title_reason(_row_base)
        if _contam_reason:
            _contaminated_title_blocked += 1
            _row_base["_contaminated_title_blocked"] = True
            _row_base["_contaminated_title_reason"] = "multi_card_or_cross_product_title"
            _log_contaminated_title_block(_row_base, _contam_reason)
            continue
        raw_window_rows.append(_row_base)
        if not bool(_row_base.get("lane_approved")):
            diag["off_target_reject_count"] = int(diag.get("off_target_reject_count") or 0) + 1
            _bucket = _target_gate_bucket(str(_row_base.get("entity_gate_reason") or ""))
            _rr = diag.setdefault("rejection_reason_counts", {})
            _rr[_bucket] = int(_rr.get(_bucket, 0) or 0) + 1
            if _bucket in {"oversized_downtown", "nonstandard_subset_variant"}:
                diag["shape_reject_count"] = int(diag.get("shape_reject_count") or 0) + 1
            elif _bucket == "wrong_entity":
                diag["player_reject_count"] = int(diag.get("player_reject_count") or 0) + 1
            elif _bucket == "wrong_product_family":
                diag["product_reject_count"] = int(diag.get("product_reject_count") or 0) + 1
            elif _bucket == "parallel_mismatch":
                diag["parallel_reject_count"] = int(diag.get("parallel_reject_count") or 0) + 1
            continue
        candidates.append(dict(_row_base))

    _expanded_title_passed: List[Dict[str, Any]] = []
    for it in expanded_window:
        t = str(it.get("title") or "")
        _lane_quality = classify_lane_quality(t)
        diag["total_listings_seen"] = int(diag.get("total_listings_seen") or 0) + 1
        if _lane_quality == "BLOCK":
            diag["total_listings_blocked"] = int(diag.get("total_listings_blocked") or 0) + 1
            print(f"[DISCOVERY_BLOCK] title={t[:140]} reason=low_quality_lane")
            continue
        diag["total_listings_admitted"] = int(diag.get("total_listings_admitted") or 0) + 1
        if _lane_quality == "PREMIUM":
            diag["discovery_premium_admitted"] = int(diag.get("discovery_premium_admitted") or 0) + 1
        elif _lane_quality == "CONDITIONAL":
            diag["discovery_conditional_admitted"] = int(diag.get("discovery_conditional_admitted") or 0) + 1
        if _passes_grade_filter(t) and _passes_card_type_filter(t, tier):
            _expanded_title_passed.append(it)
    for it in _expanded_title_passed:
        _row_base = _build_window_row(it, _recovery_window_bucket="expanded")
        _contaminated_title_checked += 1
        _contam_reason = _contaminated_multi_card_title_reason(_row_base)
        if _contam_reason:
            _contaminated_title_blocked += 1
            _row_base["_contaminated_title_blocked"] = True
            _row_base["_contaminated_title_reason"] = "multi_card_or_cross_product_title"
            _log_contaminated_title_block(_row_base, _contam_reason)
            continue
        if bool(_row_base.get("lane_approved")):
            _expanded_rows.append(_row_base)

    diag["deduped_count"]         = len(raw_window_rows)
    diag["final_candidate_count"] = len(candidates)
    diag["relaxed_target_passes"] = sum(1 for _row in raw_window_rows if bool((_row or {}).get("_target_match_relaxed")))
    diag["target_relax_rejects"] = sum(1 for _row in raw_window_rows if bool((_row or {}).get("_target_relax_rejected")))
    diag["contaminated_title_checked"] = int(_contaminated_title_checked)
    diag["contaminated_title_blocked"] = int(_contaminated_title_blocked)
    diag["_title_rows_out"]       = [dict(_row) for _row in raw_window_rows]
    _log_entity_contract("auction_row", raw_window_rows)
    _log_anchor_contract("auction_row", raw_window_rows)
    print(f"[LISTING_TRUTH_DROP] stage=player_guard count={int(diag.get('player_reject_count') or 0)}")
    print(f"[LISTING_TRUTH_DROP] stage=product_guard count={int(diag.get('product_reject_count') or 0)}")
    print(f"[LISTING_TRUTH_DROP] stage=parallel_guard count={int(diag.get('parallel_reject_count') or 0)}")
    print(f"[LISTING_TRUTH_DROP] stage=target_route count={int(diag.get('off_target_reject_count') or 0)}")
    print(
        f"[CONTAMINATED_TITLE_SUMMARY] checked={_contaminated_title_checked} "
        f"blocked={_contaminated_title_blocked} "
        f"tracked_targets_after_block={len(candidates) + len(_expanded_rows)}"
    )
    if title_passed and not candidates:
        diag["failure_stage"] = "target_lane_filter"
        diag["failure_reason"] = "all title-passing rows rejected by approved target-lane gate"
    diag["winning_variant"]       = True
    diag["_items_out"]            = raw_window_rows
    diag["_expanded_items_out"]   = _expanded_rows
    diag["_runtime_branch"]       = "recovery_clean" if str(variant.get("variant_name") or "").strip().lower() == "recovery" else "normal"
    print(
        f"[FETCH_COUNT] lane={_lane_key[:64]} variant={str(variant.get('variant_name') or 'primary')[:32]} "
        f"raw={int(diag.get('raw_rows_count') or 0)} parsed_auction={len(_auction_shaped_rows)} "
        f"within_window={len(window_rows)} title_pass={len(title_passed)} "
        f"target_pass={len(raw_window_rows)} keep={1 if len(raw_window_rows) > 0 else 0} "
        f"stop={1 if len(raw_window_rows) >= _AUCTION_VARIANT_CANDIDATE_THRESHOLD else 0} "
        f"reason={str(diag.get('failure_stage') or 'ok')}"
    )
    print(
        f"[RUNTIME_PATH] family={spec['player_name']} "
        f"raw_window_rows={len(raw_window_rows)} window_rows={len(window_rows)} "
        f"title_rows={len(title_passed)} built_rows={len(raw_window_rows)}"
    )
    print(
        f"[VARIANT_EXPANDED_OUT] query={str(variant.get('query') or '')!r} "
        f"strict_window_rows={len(window_rows)} expanded_window_rows={len(expanded_window)} "
        f"preserved_out={len(diag.get('_expanded_items_out') or [])}"
    )
    print(f"[RUNTIME_SAFE] family={spec['player_name']} branch={diag['_runtime_branch']}")
    print(
        f"[LIVE_YIELD_RUNTIME_SUMMARY] "
        f"strict_live_rows={len(window_rows)} "
        f"edge_window_rows={len(edge_window_rows)} "
        f"premium_live_rescue_rows={len(premium_live_rescue_rows)} "
        f"dead_live_lanes={1 if diag.get('dead_live_lane') else 0} "
        f"error_free=1"
    )
    _fetch_path_exit()
    return diag


def _fetch_auctions_with_fallback(
    spec: Dict[str, Any],
    time_window_hours: float,
) -> Tuple[List[Dict[str, Any]], bool, int, List[Dict[str, Any]]]:
    """
    Auction retrieval with up to 3 query variants (primary → relaxed → recovery).
    Stops early once BIN_CANDIDATE_THRESHOLD viable candidates are found.
    Returns (items, rate_limited, pre_filter_count, diags).
    """
    variants     = spec.get("query_variants") or [{"variant_name": "primary", "query": spec["query"]}]
    diags:       List[Dict[str, Any]] = []
    all_items:   List[Dict[str, Any]] = []
    rate_limited = False
    _first_variant = dict(variants[0] or {}) if variants else {}
    print(
        f"[FETCH_PATH_ENTER] function=_fetch_auctions_with_fallback "
        f"lane={str(_lane_metric_key(spec))[:96]} "
        f"query={str(_first_variant.get('query') or spec.get('query') or '')[:180]} "
        f"variant={str(_first_variant.get('variant_name') or 'primary')[:48]}"
    )

    cutoff = datetime.now(tz=timezone.utc) + timedelta(hours=time_window_hours)
    now    = datetime.now(tz=timezone.utc)

    for variant in variants[:3]:
        diag = _run_auction_variant(spec, variant, cutoff, now, time_window_hours)
        diags.append(diag)

        if diag.get("_rate_limited"):
            rate_limited = True
        if diag.get("_stop_ladder"):
            break

        items_out = diag.get("_items_out")
        if items_out is not None:
            all_items.extend(items_out)
            print(
                f"[RADAR] {spec['player_name']} AUC/{variant['variant_name']}: "
                f"raw={diag['raw_rows_count']} in_window={diag['bin_rows_count']} "
                f"time_reject={diag.get('time_filter_reject_count', 0)} "
                f"player_reject={diag.get('player_reject_count', 0)} "
                f"product_reject={diag.get('product_reject_count', 0)} "
                f"parallel_reject={diag.get('parallel_reject_count', 0)} "
                f"pass={diag['title_pass_count']} candidates={diag['final_candidate_count']}"
            )
            if bool(diag.get("dead_live_lane")):
                break
            if diag["final_candidate_count"] >= _AUCTION_VARIANT_CANDIDATE_THRESHOLD:
                break
        print(
            f"[FETCH_COUNT] lane={str(diag.get('lane_key') or _lane_metric_key(spec))[:64]} "
            f"variant={str(variant.get('variant_name') or 'primary')[:32]} "
            f"raw={int(diag.get('raw_rows_count') or 0)} "
            f"parsed_auction={int(diag.get('raw_rows_count') or 0)} "
            f"within_window={int(diag.get('within_window_count') or diag.get('bin_rows_count') or 0)} "
            f"title_pass={int(diag.get('title_pass_count') or 0)} "
            f"target_pass={int(diag.get('final_candidate_count') or 0)} "
            f"keep={1 if int(diag.get('final_candidate_count') or 0) > 0 else 0} "
            f"stop={1 if int(diag.get('final_candidate_count') or 0) >= _AUCTION_VARIANT_CANDIDATE_THRESHOLD else 0} "
            f"reason={str(diag.get('failure_stage') or 'ok')}"
        )

    winning = [d for d in diags if d.get("winning_variant")]
    if winning:
        pre_filter_count = winning[-1]["bin_rows_count"]
    elif diags:
        pre_filter_count = max(d.get("bin_rows_count", 0) for d in diags)
    else:
        pre_filter_count = 0

    _progress_tick(spec.get("player_name", ""))
    print(
        f"[FETCH_PATH_EXIT] function=_fetch_auctions_with_fallback "
        f"raw_count={sum(int((_diag or {}).get('raw_rows_count') or 0) for _diag in diags)} "
        f"listing_count={sum(int((_diag or {}).get('parsed_rows_count') or 0) for _diag in diags)} "
        f"auction_count={len(all_items)}"
    )
    return all_items, rate_limited, pre_filter_count, diags


def _is_lane_comp_backed_candidate(row: Dict[str, Any]) -> bool:
    _row = _stamp_evidence_render_contract(dict(row or {}), emit_log=False)
    try:
        _mv = float(_row.get("market_value") or _row.get("mv_value") or 0.0)
    except (TypeError, ValueError):
        _mv = 0.0
    _truth_level = str(_row.get("valuation_truth_level") or "").strip().upper() or "NONE"
    _review_estimate = _safe_float(_row.get("review_estimate_value") or _row.get("anchored_estimate_value")) or 0.0
    if _truth_level in {"REVIEW", "NONE"} and int(_row.get("evidence_renderable") or 0) <= 0:
        return False
    if _mv <= 0 and _review_estimate <= 0:
        return False
    _source = str(_row.get("mv_source") or _row.get("market_value_source") or "").strip().lower()
    if _source in {"price_anchor_fallback", "price_anchor_emergency", "floor_fallback"}:
        return False
    _comp_count = int(_row.get("comp_count_display") or _row.get("comp_count") or _row.get("mv_comp_count") or 0)
    _conf = str(
        _row.get("valuation_confidence")
        or _row.get("mv_confidence_strict")
        or _row.get("mv_confidence")
        or _row.get("confidence")
        or ""
    ).strip().upper()
    return bool(
        _comp_count >= 2
        or _conf in {"MEDIUM", "HIGH"}
        or "comp" in _source
        or _source in {"structured_fallback", "fallback_comp_support", "scarcity_fallback"}
    )


def _aggregate_lane_attempt_rollup(
    specs: List[Dict[str, Any]],
    family_diags: List[Dict[str, Any]],
) -> Dict[str, Dict[str, Any]]:
    _rollup: Dict[str, Dict[str, Any]] = {}
    _seen_spec_keys: set = set()
    for _spec in list(specs or []):
        _lane_key = _lane_metric_key(_spec)
        if not _lane_key or _lane_key in _seen_spec_keys:
            continue
        _seen_spec_keys.add(_lane_key)
        _rollup.setdefault(
            _lane_key,
            {
                "meta": _lane_yield_meta_defaults(_spec),
                "raw_hits": 0,
                "in_window_hits": 0,
                "candidate_hits": 0,
                "rows_returned": 0,
                "out_of_window_count": 0,
                "strict_within": 0,
                "edge_rescued": 0,
                "premium_live_yield_override_count": 0,
                "premium_case_hit_live_yield_count": 0,
                "nearest_remaining": None,
                "strict_window_seconds": 0.0,
                "response_scope_valid": False,
                "api_ignored_window": False,
                "dead_live_lane": False,
                "window_viability_score": 0.0,
            },
        )
    for _diag in list(family_diags or []):
        if str((_diag or {}).get("scan_type") or "").strip().upper() != "AUCTION":
            continue
        _lane_key = str((_diag or {}).get("lane_key") or "") or _lane_metric_key(_diag)
        if not _lane_key:
            continue
        _entry = _rollup.setdefault(
            _lane_key,
            {
                "meta": _lane_yield_meta_defaults(_diag),
                "raw_hits": 0,
                "in_window_hits": 0,
                "candidate_hits": 0,
                "rows_returned": 0,
                "out_of_window_count": 0,
                "strict_within": 0,
                "edge_rescued": 0,
                "premium_live_yield_override_count": 0,
                "premium_case_hit_live_yield_count": 0,
                "nearest_remaining": None,
                "strict_window_seconds": 0.0,
                "response_scope_valid": False,
                "api_ignored_window": False,
                "dead_live_lane": False,
                "window_viability_score": 0.0,
            },
        )
        _rows_returned = int((_diag or {}).get("raw_rows_count") or 0)
        _strict_within = int((_diag or {}).get("within_window_count") or (_diag or {}).get("bin_rows_count") or 0)
        _edge_rescued = int((_diag or {}).get("window_edge_rescue_count") or 0)
        _premium_live_yield_override_count = int((_diag or {}).get("premium_live_yield_override_count") or 0)
        _premium_case_hit_live_yield_count = int((_diag or {}).get("premium_case_hit_live_yield_count") or 0)
        _nearest_remaining = _safe_float((_diag or {}).get("nearest_remaining"))
        if _nearest_remaining is None:
            _nearest_remaining = _safe_float((_diag or {}).get("min_seconds_remaining"))
        _strict_window_seconds = _safe_float(
            (_diag or {}).get("strict_window_seconds")
            or (_diag or {}).get("time_check_threshold_seconds")
            or 0.0
        ) or 0.0
        _entry["raw_hits"] = max(int(_entry.get("raw_hits") or 0), _rows_returned)
        _entry["in_window_hits"] = max(
            int(_entry.get("in_window_hits") or 0),
            _strict_within,
        )
        _entry["candidate_hits"] = max(
            int(_entry.get("candidate_hits") or 0),
            int((_diag or {}).get("final_candidate_count") or 0),
        )
        _entry["rows_returned"] = max(int(_entry.get("rows_returned") or 0), _rows_returned)
        _entry["out_of_window_count"] = max(
            int(_entry.get("out_of_window_count") or 0),
            int((_diag or {}).get("out_of_window_count") or (_diag or {}).get("outside_window_count") or 0),
        )
        _entry["strict_within"] = max(int(_entry.get("strict_within") or 0), _strict_within)
        _entry["edge_rescued"] = max(int(_entry.get("edge_rescued") or 0), _edge_rescued)
        _entry["premium_live_yield_override_count"] = max(
            int(_entry.get("premium_live_yield_override_count") or 0),
            _premium_live_yield_override_count,
        )
        _entry["premium_case_hit_live_yield_count"] = max(
            int(_entry.get("premium_case_hit_live_yield_count") or 0),
            _premium_case_hit_live_yield_count,
        )
        _entry["response_scope_valid"] = bool(_entry.get("response_scope_valid") or (_diag or {}).get("response_scope_valid"))
        _entry["api_ignored_window"] = bool(_entry.get("api_ignored_window") or (_diag or {}).get("api_ignored_window"))
        _entry["dead_live_lane"] = bool(_entry.get("dead_live_lane") or (_diag or {}).get("dead_live_lane"))
        _entry["window_viability_score"] = max(
            float(_entry.get("window_viability_score") or 0.0),
            float((_diag or {}).get("window_viability_score") or 0.0),
        )
        if _nearest_remaining is not None:
            _existing_nearest = _safe_float(_entry.get("nearest_remaining"))
            _entry["nearest_remaining"] = (
                _nearest_remaining
                if _existing_nearest is None
                else min(float(_existing_nearest), float(_nearest_remaining))
            )
        _entry["strict_window_seconds"] = max(float(_entry.get("strict_window_seconds") or 0.0), float(_strict_window_seconds or 0.0))
    return _rollup


def _update_lane_yield_metrics(
    specs: List[Dict[str, Any]],
    family_diags: List[Dict[str, Any]],
    final_rows: List[Dict[str, Any]],
) -> Dict[str, Any]:
    _rollup = _aggregate_lane_attempt_rollup(specs, family_diags)
    _comp_backed_counts: Dict[str, int] = {}
    _visible_counts: Dict[str, int] = {}
    _sniper_counts: Dict[str, int] = {}
    _watchlist_counts: Dict[str, int] = {}
    _actionable_counts: Dict[str, int] = {}
    for _row in list(final_rows or []):
        _lane_key = str((_row or {}).get("lane_key") or "") or _lane_metric_key(_row)
        if not _lane_key:
            continue
        if _is_lane_comp_backed_candidate(_row):
            _comp_backed_counts[_lane_key] = int(_comp_backed_counts.get(_lane_key, 0) or 0) + 1
        _bucket = str((_row or {}).get("execution_admission_bucket") or "").strip().lower()
        if _bucket in {"sniper", "watchlist"}:
            _visible_counts[_lane_key] = int(_visible_counts.get(_lane_key, 0) or 0) + 1
        if _bucket == "watchlist":
            _watchlist_counts[_lane_key] = int(_watchlist_counts.get(_lane_key, 0) or 0) + 1
        if _bucket == "sniper":
            _sniper_counts[_lane_key] = int(_sniper_counts.get(_lane_key, 0) or 0) + 1
        _decision = str((_row or {}).get("decision") or (_row or {}).get("execution_decision") or "").strip().upper()
        if _decision in {"EXECUTE_NOW", "PREPARE"}:
            _actionable_counts[_lane_key] = int(_actionable_counts.get(_lane_key, 0) or 0) + 1

    _now_ts = time.time()
    _cooled_logs: List[Tuple[str, int]] = []
    _winner_logs: List[Tuple[str, str, float, int, int, int]] = []
    _player_rollups: Dict[str, Dict[str, Any]] = {}
    _live_checked = 0
    _live_dead = 0
    _live_rescued = 0
    _live_rescued_rows = 0
    _live_strict = 0
    _live_downranked = 0
    _premium_live_rows_rescued = 0
    _premium_live_lanes_rescued = 0
    _premium_live_dead_lanes_blocked = 0
    _premium_case_hit_live_rescued = 0
    with _LANE_YIELD_LOCK:
        _seen_spec_keys = set()
        for _spec in list(specs or []):
            _base = _lane_yield_meta_defaults(_spec)
            _lane_key = str(_base.get("lane_key") or "")
            if not _lane_key or _lane_key in _seen_spec_keys:
                continue
            _seen_spec_keys.add(_lane_key)
            _current = dict(_LANE_YIELD_STATE.get(_lane_key) or {})
            _state = dict(_base)
            _state.update(_current)
            _roll = dict(_rollup.get(_lane_key) or {})
            _raw_hits = int(_roll.get("raw_hits") or 0)
            _in_window_hits = int(_roll.get("in_window_hits") or 0)
            _candidate_hits = int(_comp_backed_counts.get(_lane_key) or 0)
            _visible_hits = int(_visible_counts.get(_lane_key) or 0)
            _sniper_hits = int(_sniper_counts.get(_lane_key) or 0)
            _watchlist_hits = int(_watchlist_counts.get(_lane_key) or 0)
            _actionable_hits = int(_actionable_counts.get(_lane_key) or 0)
            _lane_label = str(_state.get("lane_label") or _base.get("lane_label") or _lane_key)
            _premium_live_override_hits = int(_roll.get("premium_live_yield_override_count") or 0)
            _premium_case_hit_live_hits = int(_roll.get("premium_case_hit_live_yield_count") or 0)
            _live_snapshot = _lane_live_yield_snapshot(
                rows_returned=int(_roll.get("rows_returned") or _raw_hits),
                strict_within=int(_roll.get("strict_within") or _in_window_hits),
                edge_rescued=max(int(_roll.get("edge_rescued") or 0), _premium_live_override_hits),
                nearest_remaining=_roll.get("nearest_remaining"),
                strict_window_seconds=_roll.get("strict_window_seconds"),
            )
            _live_rows = int(_live_snapshot.get("rows_returned") or 0)
            _live_strict_hits = int(_live_snapshot.get("strict_within") or 0)
            _live_rescued_hits = int(_live_snapshot.get("edge_rescued") or 0)
            _live_nearest = _safe_float(_live_snapshot.get("nearest_remaining"))
            _live_strict_window = float(_live_snapshot.get("strict_window_seconds") or 0.0)
            _live_dead_threshold = float(_live_snapshot.get("dead_window_threshold_seconds") or 0.0)
            _response_scope_valid_roll = bool(_roll.get("response_scope_valid"))
            _api_ignored_window_roll = bool(_roll.get("api_ignored_window"))
            _window_out_of_window_count = int(_roll.get("out_of_window_count") or 0)
            _window_viability_score = float(
                _roll.get("window_viability_score")
                or compute_window_viability(
                    _live_rows,
                    _live_strict_hits,
                    _live_nearest,
                    _response_scope_valid_roll,
                )
                or 0.0
            )
            _live_dead_now = bool(_roll.get("dead_live_lane") or _live_snapshot.get("dead_for_live_window"))
            if _premium_live_override_hits > 0 and _live_dead_now:
                _premium_live_dead_lanes_blocked += 1
                _live_dead_now = False
            _live_rescue_band = (
                float(_live_strict_window) + float(_WINDOW_EDGE_RESCUE_GRACE_SECONDS)
                if _live_strict_window > 0.0
                else 0.0
            )
            _live_near_rescue_band = bool(
                _live_nearest is not None
                and _live_rescue_band > 0.0
                and float(_live_nearest) <= float(_live_rescue_band)
            )
            _current_live_cooldown = max(0, int(_current.get("live_cooldown_cycles") or 0))
            _live_checked += 1
            _state["lane_priority"] = float(_base.get("lane_priority") or _current.get("lane_priority") or 0.0)
            _state["live_rows_returned"] = _live_rows
            _state["live_strict_within"] = _live_strict_hits
            _state["live_edge_rescued"] = _live_rescued_hits
            _state["premium_live_yield_override_count"] = _premium_live_override_hits
            _state["premium_case_hit_live_yield_count"] = _premium_case_hit_live_hits
            _state["live_nearest_remaining"] = _live_nearest
            _state["live_strict_window_seconds"] = _live_strict_window
            _state["live_dead_window_threshold_seconds"] = _live_dead_threshold
            _state["live_yield_score"] = float(_live_snapshot.get("live_yield_score") or 0.0)
            _state["window_rows_returned"] = _live_rows
            _state["window_in_window_count"] = _live_strict_hits
            _state["window_out_of_window_count"] = _window_out_of_window_count
            _state["window_nearest_remaining_seconds"] = _live_nearest
            _state["window_response_scope_valid"] = bool(_response_scope_valid_roll)
            _state["window_api_ignored"] = bool(_api_ignored_window_roll)
            _state["window_viability_score"] = float(_window_viability_score)
            _recent_rows_history = _rolling_lane_history(_current.get("recent_rows_returned_history"), _live_rows)
            _recent_in_window_history = _rolling_lane_history(_current.get("recent_in_window_hits_history"), _live_strict_hits)
            _recent_scope_invalid_history = _rolling_lane_history(
                _current.get("recent_scope_invalid_history"),
                0 if _response_scope_valid_roll else 1,
            )
            _recent_dead_history = _rolling_lane_history(
                _current.get("recent_dead_lane_history"),
                1 if _live_dead_now else 0,
            )
            _state["recent_rows_returned_history"] = list(_recent_rows_history)
            _state["recent_in_window_hits_history"] = list(_recent_in_window_history)
            _state["recent_scope_invalid_history"] = list(_recent_scope_invalid_history)
            _state["recent_dead_lane_history"] = list(_recent_dead_history)
            _state["recent_rows_returned"] = int(sum(_recent_rows_history))
            _state["recent_in_window_hits"] = int(sum(_recent_in_window_history))
            _state["recent_scope_invalid_count"] = int(sum(_recent_scope_invalid_history))
            _state["recent_dead_lane_count"] = int(sum(_recent_dead_history))
            print(
                f"[LANE_LIVE_YIELD] lane={_lane_label[:96]} rows={_live_rows} "
                f"strict_within={_live_strict_hits} edge_rescued={_live_rescued_hits} "
                f"nearest_remaining={_live_nearest if _live_nearest is not None else 'None'} "
                f"dead_for_live_window={1 if _live_dead_now else 0}"
            )
            if _premium_live_override_hits > 0:
                _premium_live_rows_rescued += _premium_live_override_hits
                _premium_live_lanes_rescued += 1
                _premium_case_hit_live_rescued += _premium_case_hit_live_hits
                print(
                    f"[PREMIUM_LANE_LIVE_RESCUE] "
                    f"lane={_lane_label[:96]} "
                    f"rescued_rows={_premium_live_override_hits} "
                    f"nearest_remaining={_live_nearest if _live_nearest is not None else 'None'} "
                    f"strict_window={round(_live_strict_window, 2)} "
                    f"reason=premium_live_yield_override"
                )
            if _live_dead_now:
                _state["dead_for_live_window"] = True
                _state["live_cooldown_cycles"] = _LANE_LIVE_COOLDOWN_CYCLES
                _live_dead += 1
                _live_downranked += 1
                print(
                    f"[LANE_DEAD_WINDOW] lane={_lane_label[:96]} reason=no_live_endgame_supply "
                    f"nearest_remaining={_live_nearest if _live_nearest is not None else 'None'} "
                    f"strict_window={round(_live_strict_window, 2)} "
                    f"rescue_grace={round(float(_WINDOW_EDGE_RESCUE_GRACE_SECONDS), 2)} "
                    f"dead_lane_buffer={round(float(_LANE_LIVE_DEAD_BUFFER_SECONDS), 2)}"
                )
            elif _live_strict_hits > 0 or _live_rescued_hits > 0 or _live_near_rescue_band:
                _state["dead_for_live_window"] = False
                _state["live_cooldown_cycles"] = 0
            else:
                _next_live_cooldown = max(0, _current_live_cooldown - 1)
                _state["live_cooldown_cycles"] = _next_live_cooldown
                _state["dead_for_live_window"] = bool(_next_live_cooldown > 0 and bool(_current.get("dead_for_live_window")))
                if _next_live_cooldown > 0:
                    _live_downranked += 1
            if _live_strict_hits > 0:
                _live_strict += 1
            if _live_rescued_hits > 0:
                _live_rescued += 1
                _live_rescued_rows += _live_rescued_hits
            _state["lane_queries"] = int(_state.get("lane_queries") or 0) + 1
            _state["lane_zero_rows"] = int(_state.get("lane_zero_rows") or 0) + (1 if _raw_hits <= 0 else 0)
            _state["lane_raw_hits"] = int(_state.get("lane_raw_hits") or 0) + _raw_hits
            _state["lane_in_window_hits"] = int(_state.get("lane_in_window_hits") or 0) + _in_window_hits
            _state["lane_candidate_hits"] = int(_state.get("lane_candidate_hits") or 0) + _candidate_hits
            _state["lane_visible_hits"] = int(_state.get("lane_visible_hits") or 0) + _visible_hits
            _state["lane_sniper_hits"] = int(_state.get("lane_sniper_hits") or 0) + _sniper_hits
            _state["usable_comp_rows"] = int(_state.get("usable_comp_rows") or 0) + _candidate_hits
            _state["displayable_rows"] = int(_state.get("displayable_rows") or 0) + _visible_hits
            _state["watchlist_rows"] = int(_state.get("watchlist_rows") or 0) + _watchlist_hits
            _state["sniper_rows"] = int(_state.get("sniper_rows") or 0) + _sniper_hits
            _state["actionable_rows"] = int(_state.get("actionable_rows") or 0) + _actionable_hits
            _state["lane_dead_window_queries"] = int(_state.get("lane_dead_window_queries") or 0) + (1 if _in_window_hits <= 0 else 0)
            _state["lane_zero_streak"] = int(_state.get("lane_zero_streak") or 0) + 1 if _raw_hits <= 0 else 0
            _state["lane_dead_window_streak"] = int(_state.get("lane_dead_window_streak") or 0) + 1 if _in_window_hits <= 0 else 0
            _state["zero_scan_streak"] = int(_state.get("zero_scan_streak") or 0) + 1 if _raw_hits <= 0 else 0
            _state["lane_last_query_ts"] = _now_ts
            if _candidate_hits > 0:
                _state["lane_last_candidate_ts"] = _now_ts
            if _visible_hits > 0:
                _state["lane_last_visible_ts"] = _now_ts
            if _sniper_hits > 0:
                _state["lane_last_sniper_ts"] = _now_ts
            _newly_cooled = bool(
                int(_state.get("lane_zero_streak") or 0) >= _LANE_ZERO_COOLDOWN_STREAK
                or int(_state.get("lane_dead_window_streak") or 0) >= _LANE_DEAD_WINDOW_COOLDOWN_STREAK
            )
            _was_cooled = bool(_current.get("lane_cooled"))
            if _newly_cooled and not _was_cooled:
                # Entering cooldown — set full countdown
                _state["lane_cooldown_cycles_remaining"] = _LANE_COOLDOWN_CYCLES
                _state["lane_cooled"] = True
            elif _newly_cooled and _was_cooled:
                # Already in cooldown — decrement
                _cycles_left = max(0, int(_current.get("lane_cooldown_cycles_remaining") or _LANE_COOLDOWN_CYCLES) - 1)
                if _cycles_left <= 0:
                    # Cooldown expired — reset streak and re-admit
                    _state["lane_cooled"] = False
                    _state["lane_cooldown_cycles_remaining"] = 0
                    _state["lane_zero_streak"] = 0
                    _state["lane_dead_window_streak"] = 0
                else:
                    _state["lane_cooled"] = True
                    _state["lane_cooldown_cycles_remaining"] = _cycles_left
            else:
                _state["lane_cooled"] = False
                _state["lane_cooldown_cycles_remaining"] = 0
            _LANE_YIELD_STATE[_lane_key] = _state
            if bool(_state.get("lane_cooled")) and _raw_hits <= 0 and len(_cooled_logs) < 8:
                _cooled_logs.append((str(_state.get("lane_label") or _lane_key), int(_state.get("lane_zero_streak") or 0)))
            if len(_winner_logs) < 12:
                _winner_logs.append((
                    str(_state.get("player_name") or ""),
                    str(_state.get("product_family") or _state.get("lane_product") or ""),
                    _winner_lane_score(_state),
                    int(_state.get("usable_comp_rows") or 0),
                    int(_state.get("displayable_rows") or 0),
                    int(_state.get("watchlist_rows") or 0),
                ))
            _player_key = str(_state.get("player_key") or _lane_player_key(_state))
            if _player_key:
                _agg = _player_rollups.setdefault(_player_key, {
                    "player_name": str(_state.get("player_name") or ""),
                    "sport": str(_state.get("sport") or "").strip().upper(),
                    "positive_lane_hits": 0,
                    "zero_lane_hits": 0,
                })
                if _candidate_hits >= 2 or _visible_hits >= 1 or _watchlist_hits >= 1:
                    _agg["positive_lane_hits"] = int(_agg.get("positive_lane_hits") or 0) + 1
                elif _raw_hits <= 0:
                    _agg["zero_lane_hits"] = int(_agg.get("zero_lane_hits") or 0) + 1

        for _state_lane_key, _saved_state in list(_LANE_YIELD_STATE.items()):
            if _state_lane_key in _seen_spec_keys:
                continue
            _live_cycles_remaining = max(0, int((_saved_state or {}).get("live_cooldown_cycles") or 0))
            if _live_cycles_remaining <= 0 and not bool((_saved_state or {}).get("dead_for_live_window")):
                continue
            _saved = dict(_saved_state or {})
            _next_cycles_remaining = max(0, _live_cycles_remaining - 1)
            _saved["live_cooldown_cycles"] = _next_cycles_remaining
            if _next_cycles_remaining <= 0:
                _saved["dead_for_live_window"] = False
            _LANE_YIELD_STATE[_state_lane_key] = _saved

        _top = sorted(
            list(_LANE_YIELD_STATE.values()),
            key=lambda _meta: (-_lane_yield_score(_meta), -int(_meta.get("lane_visible_hits") or 0), -int(_meta.get("lane_sniper_hits") or 0)),
        )[:8]

    for _lane_label, _zero_streak in _cooled_logs:
        print(f"[LANE_ZERO_COOLDOWN] lane={_lane_label} zero_streak={_zero_streak} cooled=1")
        print(f"[LANE_COOLDOWN] lane={_lane_label} zero_streak={_zero_streak} cycles_blocked={_LANE_COOLDOWN_CYCLES}")
    for _player, _product, _score, _usable, _displayable, _watch in _winner_logs:
        print(
            f"[WINNER_LANE] player={_player} product={_product} score={_score} "
            f"comps={_usable} displayable={_displayable} watchlist={_watch}"
        )
    print(
        f"[LANE_LIVE_BUDGET_SUMMARY] checked={_live_checked} dead={_live_dead} "
        f"rescued={_live_rescued} strict_live={_live_strict} downranked={_live_downranked}"
    )
    print(
        f"[PREMIUM_LIVE_YIELD_SUMMARY] "
        f"premium_rows_rescued={_premium_live_rows_rescued} "
        f"lanes_rescued={_premium_live_lanes_rescued} "
        f"strict_live_rows={_live_strict} "
        f"extended_live_rows={_live_rescued_rows} "
        f"dead_lanes_blocked={_premium_live_dead_lanes_blocked} "
        f"case_hit_live_rescued={_premium_case_hit_live_rescued}"
    )
    with _PLAYER_WINNER_LOCK:
        for _player_key, _agg in _player_rollups.items():
            _current = dict(_PLAYER_WINNER_STATE.get(_player_key) or {})
            _state = dict(_current)
            _state["player_name"] = str(_agg.get("player_name") or _state.get("player_name") or "")
            _state["sport"] = str(_agg.get("sport") or _state.get("sport") or "")
            _positive_hits = int(_agg.get("positive_lane_hits") or 0)
            _zero_hits = int(_agg.get("zero_lane_hits") or 0)
            if _positive_hits > 0:
                _state["zero_scan_streak"] = 0
                _state["cooldown_cycles_remaining"] = 0
                _state["recently_active_cycles"] = int(_state.get("recently_active_cycles") or 0) + 1
            elif _zero_hits > 0:
                _state["zero_scan_streak"] = int(_state.get("zero_scan_streak") or 0) + 1
                if int(_state.get("zero_scan_streak") or 0) >= _PLAYER_ZERO_COOLDOWN_STREAK:
                    _state["cooldown_cycles_remaining"] = _PLAYER_COOLDOWN_CYCLES
            elif int(_state.get("cooldown_cycles_remaining") or 0) > 0:
                _state["cooldown_cycles_remaining"] = max(0, int(_state.get("cooldown_cycles_remaining") or 0) - 1)
            _PLAYER_WINNER_STATE[_player_key] = _state

    _top_summary = [
        (
            str(_meta.get("lane_label") or _meta.get("lane_key") or ""),
            round(_lane_yield_score(_meta), 1),
            int(_meta.get("lane_queries") or 0),
            int(_meta.get("lane_candidate_hits") or 0),
            int(_meta.get("lane_visible_hits") or 0),
            int(_meta.get("lane_sniper_hits") or 0),
        )
        for _meta in _top
    ]
    print(f"[LANE_YIELD] top={_top_summary}")
    return {
        "top": _top_summary,
        "tracked_lanes": len(_rollup),
    }


# ---------------------------------------------------------------------------
# MV enrichment
# ---------------------------------------------------------------------------

_VALUATION_CACHE: Dict[str, Dict[str, Any]] = {}


def _cache_key_for_item(item: Dict[str, Any]) -> str:
    _recovery_phase = str((item or {}).get("comp_recovery_phase") or "").strip().lower()
    _recovery_query = str((item or {}).get("comp_search_query_override") or "").strip().lower()
    _override_contract = (item or {}).get("comp_lookup_contract_override")
    try:
        key = build_canonical_card_key({"title": item.get("title", "")})
    except Exception:
        key = ""
    if key and key != "empty":
        _base_key = f"canon:{key}"
    else:
        title = (item.get("title") or "").strip().lower()
        item_id = str(item.get("item_id") or "").strip()
        _base_key = f"title:{title}|id:{item_id}"
    if _recovery_phase or _recovery_query or isinstance(_override_contract, dict):
        _override_sig = ""
        if isinstance(_override_contract, dict):
            _parts = [
                f"{str(_k).strip()}={str(_v).strip()}"
                for _k, _v in sorted(_override_contract.items(), key=lambda _kv: str(_kv[0]))
                if str(_v or "").strip()
            ]
            _override_sig = ",".join(_parts)[:180]
        return f"{_base_key}|recovery:{_recovery_phase}|q:{_recovery_query[:180]}|ov:{_override_sig}"
    return _base_key


def _extract_grade_context(title: str) -> Dict[str, str]:
    _title = str(title or "")
    _company = ""
    _grade = ""
    _m = re.search(r"\b(psa|bgs|sgc|cgc|hga|gma|ags)\s*(\d{1,2}(?:\.\d)?)\b", _title, flags=re.IGNORECASE)
    if _m:
        _company = str(_m.group(1) or "").upper()
        _grade = str(_m.group(2) or "")
    return {
        "grade_company": _company,
        "grade_value": _grade,
        "grade_bucket": f"{_company} {_grade}".strip() if _company and _grade else ("RAW" if not _company else _company),
        "is_graded": "1" if bool(_company) else "",
    }


def _extract_parallel_from_title(title: str) -> str:
    """
    Return the canonical parallel token found in title, or '' if none.
    Uses _PARALLEL_TOKENS_STRICT; returns longest match so 'blue wave' beats 'blue'.
    """
    return _detect_parallel_in_title(title)


def _parallel_specificity_rank(value: Any) -> int:
    _parallel = str(value or "").strip().lower().replace(" ", "_")
    _ranks = {
        "purple_speckle": 62,
        "black_refractor": 60,
        "gold_refractor": 58,
        "orange_refractor": 56,
        "red_refractor": 54,
        "superfractor": 52,
        "refractor": 20,
        "black": 12,
        "gold": 12,
        "orange": 12,
        "red": 12,
    }
    return int(_ranks.get(_parallel, 0))


def _normalize_parallel_family(title: Any, product_family: Any, raw_parallel: Any) -> Dict[str, str]:
    _title = str(title or "").strip()
    _title_norm = _normalize_product_probe_text(_title)
    _product = _normalize_exact_product_family(str(product_family or ""))
    _raw = _normalize_product_probe_text(raw_parallel)
    _before = _raw.replace(" ", "_")
    _after = _before
    _source = "raw_parallel"
    _signal_terms = (
        "black wave refractor",
        "gold wave refractor",
        "black refractor",
        "gold refractor",
        "orange refractor",
        "red refractor",
        "superfractor",
        "refractor",
    )
    _should_log = bool(_before or any(_term in _title_norm for _term in _signal_terms))
    if _should_log:
        print(
            f"[PARALLEL_FAMILY_RAW] title={_title[:140]} raw_parallel={_before[:32]} "
            f"product_family={str(_product or '').replace(' ', '_')[:64]}"
        )
    _is_topps_chrome_like = bool(
        _product in {
            "topps_chrome",
            "topps chrome",
            "topps_chrome_update",
            "topps chrome update",
            "topps_chrome_logofractor",
            "topps chrome logofractor",
        }
        or "topps chrome" in str(_product or "").replace("_", " ")
        or "topps chrome" in str(_title_norm or "")
    )
    _is_topps_auto_parallel = bool(
        _is_topps_chrome_like
        and re.search(r"\b(auto|autograph|autographs|signed|signature)\b", _title_norm)
    )
    if _is_topps_auto_parallel and (
        "purple speckle" in _title_norm
        or "purple speckle" in _raw
        or _before == "purple_speckle"
    ):
        _parallel_before = _after or _before or "purple"
        _after = "purple_speckle"
        _source = "explicit_phrase"
        if _parallel_before != _after:
            print(
                f"[TOPPS_AUTO_PARALLEL_NORMALIZE] title={_title[:140]} parallel_before={_parallel_before[:24]} "
                f"parallel_after={_after[:24]} reason=explicit_phrase"
            )
    _specific_tokens: Tuple[Tuple[str, str], ...] = (
        ("black wave refractor", "black_refractor"),
        ("gold wave refractor", "gold_refractor"),
        ("black refractor", "black_refractor"),
        ("gold refractor", "gold_refractor"),
        ("orange refractor", "orange_refractor"),
        ("red refractor", "red_refractor"),
        ("superfractor", "superfractor"),
        ("refractor", "refractor"),
    )
    if _source != "explicit_phrase":
        for _needle, _norm in _specific_tokens:
            _raw_hit = _needle.replace(" ", "_") == _before or _needle in _raw
            _title_hit = _needle in _title_norm
            if _title_hit or _raw_hit:
                _after = _norm
                _source = "title_specific_token" if _title_hit else "raw_parallel_specific"
                break
    if _is_cosmic_family_identity_row(_product, _title):
        if "black eclipse" in _title_norm:
            if "refractor" in _title_norm or "refractor" in _raw:
                _after = "black_refractor"
                _source = "cosmic_black_eclipse_refractor"
            else:
                _after = "black"
                _source = "cosmic_black_eclipse"
        elif "black refractor" in _title_norm or "black_refractor" == _before:
            _after = "black_refractor"
            _source = "cosmic_black_refractor"
        elif "orange refractor" in _title_norm or "orange_refractor" == _before:
            _after = "orange_refractor"
            _source = "cosmic_orange_refractor"
    if _after in {"refractor", ""}:
        if ("black" in _raw or " black " in f" {_title_norm} ") and ("refractor" in _raw or "refractor" in _title_norm):
            _after = "black_refractor"
            _source = "color_refractor_promote"
        elif ("gold" in _raw or " gold " in f" {_title_norm} ") and ("refractor" in _raw or "refractor" in _title_norm):
            _after = "gold_refractor"
            _source = "color_refractor_promote"
        elif ("orange" in _raw or " orange " in f" {_title_norm} ") and ("refractor" in _raw or "refractor" in _title_norm):
            _after = "orange_refractor"
            _source = "color_refractor_promote"
        elif ("red" in _raw or " red " in f" {_title_norm} ") and ("refractor" in _raw or "refractor" in _title_norm):
            _after = "red_refractor"
            _source = "color_refractor_promote"
    if not _after and _before:
        _after = _before
        _source = "raw_parallel_fallback"
    if _parallel_specificity_rank(_before) > _parallel_specificity_rank(_after):
        if _after and _after != _before:
            print(
                f"[PARALLEL_FAMILY_OVERWRITE] title={_title[:140]} previous_parallel={_after[:32]} "
                f"new_parallel={_before[:32]} reason=preserve_more_specific_raw"
            )
        _after = _before
        _source = "preserve_more_specific_raw"
    if _should_log:
        print(
            f"[PARALLEL_FAMILY_ASSIGN] title={_title[:140]} parallel_before={_before[:32]} "
            f"parallel_after={_after[:32]} source={_source}"
        )
        if _before and _after and _before != _after:
            print(
                f"[PARALLEL_FAMILY_OVERWRITE] title={_title[:140]} previous_parallel={_before[:32]} "
                f"new_parallel={_after[:32]} reason={_source}"
            )
    return {
        "parallel_family": _after,
        "source": _source,
        "raw_parallel": _before,
    }


def _extract_grade_bucket(title: str) -> str:
    """
    Return strict grade bucket: RAW | PSA_10 | PSA_9 | SGC_10 | OTHER_GRADED.
    Used to enforce cross-grade comp rejection.
    """
    _ctx = _extract_grade_context(title)
    _company = str(_ctx.get("grade_company") or "").strip().upper()
    _value = str(_ctx.get("grade_value") or "").strip()
    if not _company:
        return "RAW"
    if _company == "PSA":
        if _value == "10":
            return "PSA_10"
        if _value == "9":
            return "PSA_9"
        return "OTHER_GRADED"
    if _company == "SGC" and _value == "10":
        return "SGC_10"
    return "OTHER_GRADED"


def _normalize_subset_name(value: str) -> str:
    _raw = str(value or "").strip().lower().replace("-", " ")
    _raw = re.sub(r"[^a-z0-9\s]+", " ", _raw)
    _raw = " ".join(_raw.split())
    if not _raw:
        return ""
    if re.fullmatch(r"\d+(?:\.\d+)?", _raw):
        return ""
    if re.fullmatch(r"(?:psa|gma|sgc|bgs|bvg|csg|cgc)(?:\s+(?:gem mint|mint|pristine|black label))?\s+\d{1,2}(?:\.\d+)?", _raw):
        return ""
    if re.fullmatch(r"(?:gem mint|mint|pristine)\s+\d{1,2}(?:\.\d+)?", _raw):
        return ""
    if re.fullmatch(r"(?:card\s+)?\d{1,4}", _raw):
        return ""
    _map = {
        "all aces": "all_aces",
        "color blast": "color_blast",
        "downtown": "downtown",
        "genesis": "genesis",
        "kaboom": "kaboom",
        "uptown": "uptown",
        "stained glass": "stained_glass",
        "manga": "manga",
        "net marvels": "net_marvels",
        "global reach": "global_reach",
        "emergent": "emergent",
        "fractal": "fractal",
        "fractal insert": "fractal",
        "fireworks": "fireworks",
        "hype": "hype",
        "instant impact": "instant_impact",
        "brilliance": "brilliance",
        "prizmatic": "prizmatic",
        "visionary": "visionary",
        "nfl debut": "nfl_debut",
        "touchdown masters": "touchdown_masters",
        "crusade": "crusade",
        "field level": "field_level",
        "premier level": "premier_level",
        "suite level": "suite_level",
        "concourse": "concourse",
        "image variation": "image_variation",
        "photo variation": "image_variation",
        "variation": "image_variation",
        "ssp": "image_variation",
        "sp": "image_variation",
        "supernova": "supernova",
        "stellar nova": "stella_nova",
        "stella nova": "stella_nova",
        "starfractor": "starfractor",
        "star factor": "starfractor",
        "galactic greatness": "galactic_greatness",
        "star command": "star_command",
        "into the cosmos": "into_the_cosmos",
        "nucleus": "nucleus",
        "equinox": "equinox",
        "eclipse": "eclipse",
    }
    return _map.get(_raw, _raw.replace(" ", "_"))


def _extract_subset_grade_label(title: str) -> str:
    _raw = str(title or "").strip()
    if not _raw:
        return ""
    _patterns = (
        r"\b(?:PSA|GMA|SGC|BGS|BVG|CSG|CGC)\s*(?:GEM\s+MINT\s+|MINT\s+|PRISTINE\s+|BLACK\s+LABEL\s+)?\d{1,2}(?:\.\d)?\b",
        r"\bGEM\s+MINT\s+\d{1,2}(?:\.\d)?\b",
        r"\bMINT\s+\d{1,2}(?:\.\d)?\b",
        r"\bPRISTINE\s+\d{1,2}(?:\.\d)?\b",
    )
    for _pattern in _patterns:
        _match = re.search(_pattern, _raw, flags=re.IGNORECASE)
        if _match:
            return re.sub(r"\s+", " ", str(_match.group(0) or "").strip()).upper()
    return ""


def _subset_identity_noise_token(value: Any, *, title: str = "", card_number: Any = "") -> str:
    _raw = str(value or "").strip()
    if not _raw:
        return ""
    _slug = re.sub(r"[^a-z0-9]+", " ", _raw.lower()).strip()
    if not _slug:
        return ""
    if re.fullmatch(r"\d+(?:\.\d+)?", _slug):
        return _raw
    if re.fullmatch(r"(?:psa|gma|sgc|bgs|bvg|csg|cgc)(?:\s+(?:gem mint|mint|pristine|black label))?\s+\d{1,2}(?:\.\d+)?", _slug):
        return _raw
    if re.fullmatch(r"(?:gem mint|mint|pristine)\s+\d{1,2}(?:\.\d+)?", _slug):
        return _raw
    if re.fullmatch(r"(?:card\s+)?\d{1,4}", _slug):
        return _raw
    _card_no = re.sub(r"[^a-z0-9]+", " ", str(card_number or "").lower()).strip()
    if _card_no and _slug == _card_no:
        return _raw
    _grade_label = re.sub(r"[^a-z0-9]+", " ", _extract_subset_grade_label(title).lower()).strip()
    if _grade_label and _slug == _grade_label:
        return _raw
    return ""


def _is_topps_family_identity_row(product_family: Any, title: str = "") -> bool:
    _hay = f"{str(product_family or '').replace('_', ' ')} {str(title or '').lower()}"
    return any(
        _phrase in _hay
        for _phrase in (
            "topps transcendent icons chrome black",
            "topps transcendent icons",
            "transcendent icons",
            "topps chrome black",
            "topps cosmic chrome",
            "topps chrome sapphire",
            "topps finest",
            "topps chrome",
            "bowman chrome",
        )
    )


_COSMIC_SUBSET_TOKEN_MAP: Tuple[Tuple[str, str], ...] = (
    ("galactic greatness", "galactic_greatness"),
    ("into the cosmos", "into_the_cosmos"),
    ("stellar nova", "stella_nova"),
    ("stella nova", "stella_nova"),
    ("star command", "star_command"),
    ("starfractor", "starfractor"),
    ("star factor", "starfractor"),
    ("supernova", "supernova"),
    ("nucleus", "nucleus"),
    ("equinox", "equinox"),
    ("eclipse", "eclipse"),
)


def _cosmic_subset_tokens_in_title(title: str) -> List[str]:
    _title = re.sub(r"[^a-z0-9\s]+", " ", str(title or "").lower())
    _title = " ".join(_title.split())
    _found: List[str] = []
    for _needle, _norm in _COSMIC_SUBSET_TOKEN_MAP:
        if _needle == "eclipse":
            continue
        if _needle in _title and _norm not in _found:
            _found.append(_norm)
    return _found


def _is_cosmic_family_identity_row(product_family: Any, title: str = "") -> bool:
    _family = str(product_family or "").replace("_", " ").lower()
    _title = str(title or "").lower()
    _hay = f"{_family} {_title}"
    return any(
        _phrase in _hay
        for _phrase in (
            "topps cosmic chrome",
            "topps chrome cosmic",
            "cosmic chrome",
            "chrome cosmic",
        )
    )


def _extract_cosmic_subset_family(title: str, raw_subset: Any = "") -> str:
    _title = re.sub(r"[^a-z0-9\s]+", " ", str(title or "").lower())
    _title = " ".join(_title.split())
    _raw_subset_norm = _normalize_subset_name(str(raw_subset or ""))
    print(f"[COSMIC_SUBSET_RAW] title={str(title or '')[:140]} raw_detected_subset={_raw_subset_norm[:32] if _raw_subset_norm else ''}")
    if _raw_subset_norm in {str(_norm) for _, _norm in _COSMIC_SUBSET_TOKEN_MAP}:
        print(f"[COSMIC_SUBSET_NORMALIZED] title={str(title or '')[:140]} normalized_subset={_raw_subset_norm[:32]}")
        return _raw_subset_norm
    for _needle, _norm in _COSMIC_SUBSET_TOKEN_MAP:
        if _needle == "eclipse" and "black eclipse" in _title:
            continue
        if _needle in _title:
            print(f"[COSMIC_SUBSET_NORMALIZED] title={str(title or '')[:140]} normalized_subset={_norm[:32]}")
            return _norm
    print(f"[COSMIC_SUBSET_NORMALIZED] title={str(title or '')[:140]} normalized_subset=")
    return ""


def _normalize_cosmic_parallel_family(title: str, parallel_family: Any = "") -> str:
    return str(_normalize_parallel_family(title, "topps cosmic chrome", parallel_family).get("parallel_family") or "")


def _cosmic_parallel_compatible(subject_parallel: Any, comp_parallel: Any) -> bool:
    _subject = _normalize_cosmic_parallel_family("", subject_parallel)
    _comp = _normalize_cosmic_parallel_family("", comp_parallel)
    if not _subject or not _comp:
        return True
    if _subject == _comp:
        return True
    if {_subject, _comp} <= {"black", "black_refractor"}:
        return True
    return False


def _cosmic_premium_match_decision(row: Dict[str, Any], *, emit_log: bool = False) -> Tuple[bool, str]:
    _row = dict(row or {})
    _target_meta = player_hub.resolve_effective_product_target_meta(dict(_row.get("target_meta") or {}))
    _title = str(_row.get("title") or _row.get("source_title") or "").strip()
    _subject_subset = _normalize_subset_name(
        str(
            _target_meta.get("subset_name")
            or _row.get("_target_subset_family")
            or _row.get("target_subset_family")
            or _row.get("lane_subset")
            or ""
        )
    )
    _comp_subset = _normalize_subset_name(str(_row.get("subset_name") or _row.get("subset_family") or ""))
    if not _comp_subset and _is_cosmic_family_identity_row(
        _row.get("product_family") or _row.get("target_product_family") or _target_meta.get("set_name") or "",
        _title,
    ):
        _comp_subset = _extract_cosmic_subset_family(_title)
    _subject_parallel = _normalize_cosmic_parallel_family(
        _title,
        _target_meta.get("parallel")
        or _target_meta.get("parallel_name")
        or _target_meta.get("parallel_family")
        or "",
    )
    _comp_parallel = _normalize_cosmic_parallel_family(
        _title,
        _row.get("parallel_bucket")
        or _row.get("parallel_name")
        or _row.get("parallel_family")
        or _row.get("rare_parallel")
        or "",
    )
    _subject_serial = _normalize_serial_bucket(
        str(_target_meta.get("serial_denominator") or _row.get("_target_serial_denominator") or "")
    )
    _comp_serial = _normalize_serial_bucket(
        str(_row.get("serial_bucket") or _row.get("serial_denominator") or "")
    )
    _allowed = True
    _reason = "cosmic_identity_match"
    if _subject_subset and not _comp_subset:
        _allowed = False
        _reason = "premium_identity_mismatch:missing_comp_subset"
    elif _subject_subset and _comp_subset != _subject_subset:
        _allowed = False
        _reason = f"premium_identity_mismatch:subset:{_subject_subset}->{_comp_subset}"
    elif _subject_serial and _comp_serial and _subject_serial != _comp_serial:
        _allowed = False
        _reason = f"premium_bucket_mismatch:serial:{_subject_serial}->{_comp_serial}"
    elif not _cosmic_parallel_compatible(_subject_parallel, _comp_parallel):
        _allowed = False
        _reason = f"premium_bucket_mismatch:parallel:{_subject_parallel}->{_comp_parallel}"
    if emit_log or _is_cosmic_family_identity_row(
        _row.get("product_family") or _row.get("target_product_family") or _target_meta.get("set_name") or "",
        _title,
    ):
        print(
            f"[COSMIC_PREMIUM_MATCH] subject_subset={_subject_subset or ''} "
            f"comp_subset={_comp_subset or ''} subject_parallel={_subject_parallel or ''} "
            f"comp_parallel={_comp_parallel or ''} allowed={1 if _allowed else 0} reason={_reason}"
        )
    return _allowed, _reason


