    print(f"[ES][AUCTION] after_product_filter={_after_product_filter}")
    print(f"[ES][AUCTION] after_parallel_filter={_after_parallel_filter}")
    def _irt_row_key(_r: Dict[str, Any]) -> str:
        return str((_r or {}).get("item_id") or (_r or {}).get("itemId") or (_r or {}).get("source_item_id") or (_r or {}).get("title") or "")[:64]

    _irt_player_keys = {_irt_row_key(_r) for _r in (_player_rows or []) if _irt_row_key(_r)}
    _irt_product_keys = {_irt_row_key(_r) for _r in (_product_rows or []) if _irt_row_key(_r)}
    _irt_parallel_keys = {_irt_row_key(_r) for _r in (_parallel_rows or []) if _irt_row_key(_r)}
    _irt_target_keys = {_irt_row_key(_r) for _r in (_target_rows or []) if _irt_row_key(_r)}
    _irt_title_keys = {_irt_row_key(_r) for _r in (_title_rows or []) if _irt_row_key(_r)}

    for _irt_row in list(_window_rows or []):
        _irt_key = _irt_row_key(_irt_row)
        _irt_egr = str((_irt_row or {}).get("entity_gate_reason") or "").strip().lower()
        _irt_in_title = bool(_irt_key in _irt_title_keys) if _irt_key else False
        _irt_in_player = bool(_irt_key in _irt_player_keys) if _irt_key else False
        _irt_in_product = bool(_irt_key in _irt_product_keys) if _irt_key else False
        _irt_in_parallel = bool(_irt_key in _irt_parallel_keys) if _irt_key else False
        _irt_in_target = bool(_irt_key in _irt_target_keys) if _irt_key else False
        if _irt_in_target:
            _irt_final_stage = "target_pass"
        elif _irt_in_parallel:
            _irt_final_stage = "target_drop"
        elif _irt_in_product:
            _irt_final_stage = "parallel_drop"
        elif _irt_in_player:
            _irt_final_stage = "product_drop"
        else:
            _irt_final_stage = "player_drop"
        _irt_query_player = str(
            (_irt_row or {}).get("_target_player")
            or (_irt_row or {}).get("player_name")
            or (_irt_row or {}).get("target_label")
            or ""
        )[:48]
        _irt_query_product = str(
            (_irt_row or {}).get("_target_product_canonical")
            or (_irt_row or {}).get("lane_product")
            or (_irt_row or {}).get("target_product_family")
            or ""
        )[:48]
        _irt_detected_player = str(
            (_irt_row or {}).get("normalized_entity")
            or (_irt_row or {}).get("canonical_player")
            or (_irt_row or {}).get("entity_player_name")
            or (_irt_row or {}).get("detected_player")
            or ""
        )[:48]
        _irt_detected_product = str(
            (_irt_row or {}).get("detected_product_family")
            or (_irt_row or {}).get("product_family")
            or (_irt_row or {}).get("identity_product_family")
            or (_irt_row or {}).get("_hydrated_product_family")
            or ""
        )[:48]
        _irt_player_match = 0 if _irt_egr == "wrong_entity" else (1 if _irt_in_player or _irt_egr == "" else 0)
        _irt_product_match = 0 if _irt_egr == "wrong_product_family" else (1 if _irt_in_product or _irt_egr in ("", "wrong_entity") else 0)
        _irt_parallel_match = 0 if _irt_egr == "parallel_mismatch" else (1 if _irt_in_parallel or _irt_egr in ("", "wrong_entity", "wrong_product_family") else 0)
        _irt_target_route_reason = str(
            (_irt_row or {}).get("_target_match_reason")
            or (_irt_row or {}).get("entity_gate_reason")
            or (_irt_row or {}).get("route_stage")
            or (_irt_row or {}).get("target_match_status")
            or ""
        )[:64]
        _irt_in_title_flag = "yes" if _irt_in_title else "no"
        print(
            f"[IDENTITY_ROUTING_TRACE] "
            f"item_id={str((_irt_row or {}).get('item_id') or (_irt_row or {}).get('itemId') or (_irt_row or {}).get('source_item_id') or '')[:32]} "
            f"title={str((_irt_row or {}).get('title') or (_irt_row or {}).get('source_title') or '')[:120]} "
            f"in_title_pool={_irt_in_title_flag} "
            f"query_player={_irt_query_player} "
            f"query_product={_irt_query_product} "
            f"detected_player={_irt_detected_player} "
            f"player_match={_irt_player_match} "
            f"detected_product={_irt_detected_product} "
            f"product_match={_irt_product_match} "
            f"parallel_match={_irt_parallel_match} "
            f"target_route_reason={_irt_target_route_reason} "
            f"final_stage={_irt_final_stage}"
        )

    # ── PREPARE-aware identity-routing trace (observability only) ──
    def _phr_is_prepare(_r: Dict[str, Any]) -> bool:
        return bool((_r or {}).get("_prepare_bucket"))
    def _phr_key(_r: Dict[str, Any]) -> str:
        return str(
            (_r or {}).get("item_id")
            or (_r or {}).get("itemId")
            or (_r or {}).get("source_item_id")
            or (_r or {}).get("title")
            or ""
        )[:96]
    _phr_window_prepares = [_r for _r in (_window_rows or []) if _phr_is_prepare(_r)]
    _phr_title_keys = {_phr_key(_r) for _r in (_title_rows or []) if _phr_is_prepare(_r) and _phr_key(_r)}
    _phr_player_keys = {_phr_key(_r) for _r in (_player_rows or []) if _phr_is_prepare(_r) and _phr_key(_r)}
    _phr_product_keys = {_phr_key(_r) for _r in (_product_rows or []) if _phr_is_prepare(_r) and _phr_key(_r)}
    _phr_parallel_keys = {_phr_key(_r) for _r in (_parallel_rows or []) if _phr_is_prepare(_r) and _phr_key(_r)}
    _phr_target_keys = {_phr_key(_r) for _r in (_target_rows or []) if _phr_is_prepare(_r) and _phr_key(_r)}
    print(
        f"[PREPARE_HANDOFF_TRACE] stage=identity_routing "
        f"prepare_in_window={len(_phr_window_prepares)} "
        f"prepare_in_title={len(_phr_title_keys)} "
        f"prepare_in_player={len(_phr_player_keys)} "
        f"prepare_in_product={len(_phr_product_keys)} "
        f"prepare_in_parallel={len(_phr_parallel_keys)} "
        f"prepare_in_target={len(_phr_target_keys)}"
    )
    for _phr_row in _phr_window_prepares:
        _phr_k = _phr_key(_phr_row)
        if not _phr_k:
            continue
        if _phr_k in _phr_target_keys:
            continue  # row made it through to _target_rows
        if _phr_k in _phr_parallel_keys:
            _phr_stage = "target"
        elif _phr_k in _phr_product_keys:
            _phr_stage = "parallel"
        elif _phr_k in _phr_player_keys:
            _phr_stage = "product"
        elif _phr_k in _phr_title_keys:
            _phr_stage = "player"
        else:
            _phr_stage = "title"
        _phr_egr = str((_phr_row or {}).get("entity_gate_reason") or "").strip()
        # OBS-ADD — look up reason from the bridge dict (populated in the routing
        # loop), since the dict()-copy at line ~46726 strips fields stamped on _row.
        _phr_bridged_reason = ""  # OBS-ADD
        try:  # OBS-ADD
            _phr_bridge_k = _ob_routing_row_key(_phr_row)  # OBS-ADD
            if _phr_bridge_k:  # OBS-ADD
                _phr_bridged_reason = str(_prepare_reject_reasons_by_key.get(_phr_bridge_k) or "")  # OBS-ADD
        except Exception:  # OBS-ADD
            _phr_bridged_reason = ""  # OBS-ADD
        _phr_reason = (
            _phr_bridged_reason  # OBS-ADD — survives the parallel_rows dict-copy
            or _phr_egr
            or str((_phr_row or {}).get("_prepare_target_reject_reason") or "")  # OBS-ADD — set at line ~47315 for PREPARE rows rejected at the target contract
            or str((_phr_row or {}).get("_target_match_reason") or "")
            or str((_phr_row or {}).get("target_match_status") or "")
            or str((_phr_row or {}).get("_contamination_granular_reason") or "")  # OBS-ADD — granular contamination reason (plus_separator, lot_title, etc.)
            or str((_phr_row or {}).get("_contaminated_title_reason") or "")
            or str((_phr_row or {}).get("_shared_admission_reject_reason") or "")  # OBS-ADD — set on rows filtered by _shared_admission_reject_reason at the title→player handoff
            or str((_phr_row or {}).get("entity_drop_reason") or "")  # OBS-ADD — set during PLAYER_ROUTING_DROP
            or str((_phr_row or {}).get("entity_gate_detail") or "")  # OBS-ADD — fallback used by PLAYER_ROUTING_DROP
            or str((_phr_row or {}).get("route_reason") or "")  # OBS-ADD — generic route reason set by _stamp_trusted_target_route / ROUTING_REJECT path
            or str((_phr_row or {}).get("_trusted_target_route_reason") or "")  # OBS-ADD
            or "no_reason"
        )
        print(
            f"[PREPARE_DROP] "
            f"item_id={str((_phr_row or {}).get('item_id') or (_phr_row or {}).get('itemId') or (_phr_row or {}).get('source_item_id') or '')[:32]} "
            f"title={str((_phr_row or {}).get('title') or (_phr_row or {}).get('source_title') or '')[:120]} "
            f"stage={_phr_stage} "
            f"reason={str(_phr_reason)[:64]}"
        )
    # ────────────────────────────────────────────────────────────────
    print(
        f"[VALUATION_HANDOFF_GATE] stage=identity_routing "
        f"source_rows={_safe_count(_window_rows)} "
        f"candidate_rows={_safe_count(_target_rows)} "
        f"drop_reason={{'player_pass': {_safe_count(_player_rows)}, "
        f"'product_pass': {_safe_count(_product_rows)}, "
        f"'parallel_pass': {_safe_count(_parallel_rows)}, "
        f"'target_pass': {_safe_count(_target_rows)}, "
        f"'target_route_reasons': {dict(_target_route_reason_counts or {})}}}"
    )
    print(
        f"[ES][HANDOFF] window_rows={len(_window_rows)} player_rows={len(_player_rows)} "
        f"product_rows={len(_product_rows)} parallel_rows={len(_parallel_rows)} "
        f"target_rows={len(_target_rows)} final_rows={len(filtered_auctions) if 'filtered_auctions' in locals() else 0}"
    )
    print(f"[ES][WINDOW_HANDOFF] kept_count={len(_window_rows)} window_rows={len(_window_rows)}")
    print(f"[ES][WINDOW_HANDOFF] title_rows={len(_title_rows)} title_rejects={max(0, len(_window_rows) - len(_title_rows))}")
    print(
        f"[ES][SUPPLY_RECOVERY] fetched={len(_window_rows)} within_window={len(_window_rows)} "
        f"title_pass={len(_title_rows)} player_pass={len(_player_rows)} final_feed={len(filtered_auctions) if 'filtered_auctions' in locals() else 0}"
    )
    if _single_card_reject_samples:
        print(f"[ES][FUNNEL][SAMPLE] single_card_guard -> {_single_card_reject_samples}")
    if _player_reject_samples:
        print(f"[ES][FUNNEL][SAMPLE] player_guard wrong_entity -> {_player_reject_samples}")
    if _product_reject_samples:
        print(f"[ES][FUNNEL][SAMPLE] product_guard wrong_product_family -> {_product_reject_samples}")
    if _parallel_reject_samples:
        print(f"[ES][FUNNEL][SAMPLE] parallel_guard parallel_mismatch -> {_parallel_reject_samples}")
    # ── INTAKE TIME STAMP + PRE-VALUATION DROP ───────────────────────────────
    # Compute true remaining seconds from end_dt for every target row, bypassing
    # the millisecond guard that can corrupt remaining_seconds for >1-day auctions.
    # Rows >24h are dropped here — they must not consume valuation budget.
    # Rows 6–24h are kept as prepare/watch fuel but ranked below sub-6h rows.
    _intake_now_utc = datetime.now(tz=timezone.utc)
    _intake_time_dropped = 0
    _target_rows_timed: List[Dict[str, Any]] = []
    for _trow in _target_rows:
        _end_dt_it = _trow.get("end_dt")
        if _end_dt_it is not None:
            try:
                _true_secs = float(seconds_left(_end_dt_it, _intake_now_utc))
                _trow["_intake_remaining_secs"] = max(0.0, _true_secs)
            except Exception:
                _trow["_intake_remaining_secs"] = float(_trow.get("remaining_seconds") or 999999.0)
        else:
            _trow["_intake_remaining_secs"] = float(
                _trow.get("remaining_seconds") or _trow.get("seconds_remaining") or 999999.0
            )
        _trow["_discovery_urgency_tier"] = _discovery_urgency_tier(_trow.get("_intake_remaining_secs"))
        _trow["_discovery_premium_score"] = _discovery_row_premium_score(_trow)
        if _trow["_intake_remaining_secs"] > 86400:
            _intake_time_dropped += 1
            print(
                f"[INTAKE_TIME_DROP] secs={_trow['_intake_remaining_secs']:.0f} "
                f"({_trow['_intake_remaining_secs'] / 3600:.1f}h) — dropped before valuation "
                f"title={str(_trow.get('title') or '')[:80]}"
            )
            if bool((_trow or {}).get("_prepare_bucket")):  # OBS-ADD
                print(  # OBS-ADD
                    f"[PREPARE_DROP] "  # OBS-ADD
                    f"item_id={str((_trow or {}).get('item_id') or (_trow or {}).get('itemId') or (_trow or {}).get('source_item_id') or '')[:32]} "  # OBS-ADD
                    f"title={str((_trow or {}).get('title') or (_trow or {}).get('source_title') or '')[:120]} "  # OBS-ADD
                    f"stage=intake_time "  # OBS-ADD
                    f"reason=over_24h_secs={_trow['_intake_remaining_secs']:.0f}"  # OBS-ADD
                )  # OBS-ADD
            continue
        _target_rows_timed.append(_trow)
    if _intake_time_dropped:
        print(
            f"[INTAKE_TIME_SUMMARY] dropped_over_24h={_intake_time_dropped} "
            f"remaining_for_valuation={len(_target_rows_timed)} "
            f"of_which_sub6h={sum(1 for _r in _target_rows_timed if _r.get('_intake_remaining_secs', 999999) <= 21600)} "
            f"prepare_6to24h={sum(1 for _r in _target_rows_timed if 21600 < _r.get('_intake_remaining_secs', 999999) <= 86400)}"
        )
    _target_rows_pre_oxygen_count = _safe_count(_target_rows_timed)
    _target_rows = _apply_live_oxygen_bias(_target_rows_timed, stage="target_rows_pre_valuation")
    # OBS-ADD ── per-row PREPARE_DROP for rows removed by oxygen-bias filter
    def _ob_prep_key(_r: Dict[str, Any]) -> str:  # OBS-ADD
        return str(  # OBS-ADD
            (_r or {}).get("item_id")  # OBS-ADD
            or (_r or {}).get("itemId")  # OBS-ADD
            or (_r or {}).get("source_item_id")  # OBS-ADD
            or (_r or {}).get("title")  # OBS-ADD
            or ""  # OBS-ADD
        )[:96]  # OBS-ADD
    _ob_post_oxygen_keys = {_ob_prep_key(_r) for _r in (_target_rows or []) if _ob_prep_key(_r)}  # OBS-ADD
    for _ob_pre in (_target_rows_timed or []):  # OBS-ADD
        if not bool((_ob_pre or {}).get("_prepare_bucket")):  # OBS-ADD
            continue  # OBS-ADD
        _ob_k = _ob_prep_key(_ob_pre)  # OBS-ADD
        if _ob_k and _ob_k not in _ob_post_oxygen_keys:  # OBS-ADD
            print(  # OBS-ADD
                f"[PREPARE_DROP] "  # OBS-ADD
                f"item_id={str((_ob_pre or {}).get('item_id') or (_ob_pre or {}).get('itemId') or (_ob_pre or {}).get('source_item_id') or '')[:32]} "  # OBS-ADD
                f"title={str((_ob_pre or {}).get('title') or (_ob_pre or {}).get('source_title') or '')[:120]} "  # OBS-ADD
                f"stage=oxygen_bias "  # OBS-ADD
                f"reason=oxygen_bias_filter"  # OBS-ADD
            )  # OBS-ADD
    print(
        f"[VALUATION_HANDOFF_GATE] stage=intake_time_and_oxygen_bias "
        f"source_rows={_safe_count(_target_rows_timed) + int(_intake_time_dropped or 0)} "
        f"candidate_rows={_safe_count(_target_rows)} "
        f"drop_reason={{'intake_time_dropped_over_24h': {int(_intake_time_dropped or 0)}, "
        f"'oxygen_bias_dropped': {max(0, _target_rows_pre_oxygen_count - _safe_count(_target_rows))}}}"
    )
    # ─────────────────────────────────────────────────────────────────────────
    _budget_skipped_rows = 0
    _valuation_candidates_auctions: List[Dict[str, Any]] = []
    _supply_filter_drop_counts: Dict[str, int] = {}
    _supply_filter_drop_samples: List[str] = []
    _candidate_drop_counts: Dict[str, int] = {}
    _candidate_survived = 0
    _candidate_relaxed_survived = 0
    _candidate_strict_survived = 0
    _candidate_relaxed_input = sum(1 for _row in _target_rows if bool((_row or {}).get("_target_match_relaxed")))
    # ── INTAKE PRIORITY ENGINE ────────────────────────────────────────────────
    # Tier-4 (generic base / insert / no signal) rows are capped independently
    # so they cannot crowd out premium rows when the total budget is limited.
    # Because _candidate_priority_key now sorts by _intake_priority_tier first,
    # tier-0 through tier-3 rows are always processed before tier-4.
    _INTAKE_LOW_CAP = 8           # max tier-4 rows admitted regardless of total budget
    _admitted_by_tier: Dict[int, int] = {}
    _discovery_admitted_by_tier: Dict[str, int] = {
        "tier_0_1h": 0,
        "tier_1_3h": 0,
        "tier_3_6h": 0,
        "tier_6_24h": 0,
        "tier_over_24h": 0,
    }
    _intake_demote_count = 0
    _admit_cap = int(_cycle_budget.get("candidate_admit_cap") or _MAX_ROWS_ADMITTED_PER_CYCLE)
    for _row in sorted(_target_rows, key=_candidate_priority_key):
        _candidate_ok, _candidate_reason = _candidate_survival_decision(
            _row,
            caller="valuation_intake",
            emit_log=True,
        )
        if not _candidate_ok:
            _candidate_drop_counts[_candidate_reason] = int(_candidate_drop_counts.get(_candidate_reason, 0) or 0) + 1
            _preval_reject_counts[_candidate_reason] = int(_preval_reject_counts.get(_candidate_reason, 0) or 0) + 1
            if bool((_row or {}).get("_prepare_bucket")):  # OBS-ADD
                print(  # OBS-ADD
                    f"[PREPARE_DROP] "  # OBS-ADD
                    f"item_id={str((_row or {}).get('item_id') or (_row or {}).get('itemId') or (_row or {}).get('source_item_id') or '')[:32]} "  # OBS-ADD
                    f"title={str((_row or {}).get('title') or (_row or {}).get('source_title') or '')[:120]} "  # OBS-ADD
                    f"stage=candidate_survival "  # OBS-ADD
                    f"reason={str(_candidate_reason)[:64]}"  # OBS-ADD
                )  # OBS-ADD
            continue
        _row["_candidate_survival_admit"] = True
        _row["_candidate_survival_reason"] = _candidate_reason
        # ── EARLY SUPPLY FILTER ──────────────────────────────────────────────
        # Candidate survival happens before commercial pruning so truthful live rows
        # can reach valuation and fail later for explicit downstream reasons.
        # ── INTAKE PRIORITY TIER + BUDGET ENFORCEMENT ────────────────────────
        _row_tier = _intake_priority_tier(_row)
        _row["_intake_tier"] = _row_tier
        _row_discovery_tier = str(_row.get("_discovery_urgency_tier") or _discovery_urgency_tier(_row.get("_intake_remaining_secs")))
        _row["_discovery_urgency_tier"] = _row_discovery_tier
        _row_title_ip = str(_row.get("title") or "")[:100]
        _row_price_ip = float(_row.get("current_price") or _row.get("current_bid") or 0.0)
        _row_secs_ip = float(_row.get("_intake_remaining_secs") or 999999.0)
        # Tier-4 cap: once we have enough low-signal rows, stop admitting more
        # even if total budget isn't exhausted — preserve slots for premium rows
        # that may appear later in the same cycle from a different player lane.
        if _row_tier >= 4 and _admitted_by_tier.get(4, 0) >= _INTAKE_LOW_CAP:
            _intake_demote_count += 1
            _budget_skipped_rows += 1
            _candidate_drop_counts["tier4_cap"] = int(_candidate_drop_counts.get("tier4_cap", 0) or 0) + 1
            print(
                f"[CANDIDATE_REASON] caller=valuation_intake "
                f"item={str(_row.get('item_id') or _row.get('source_item_id') or '')[:18] or '?'} "
                f"reason=tier4_cap"
            )
            print(
                f"[CANDIDATE_DROP] caller=valuation_intake "
                f"item={str(_row.get('item_id') or _row.get('source_item_id') or '')[:18] or '?'} "
                f"reason=tier4_cap title={_row_title_ip[:120]}"
            )
            print(
                f"[INTAKE_DEMOTE] tier=4 secs={_row_secs_ip:.0f} price={_row_price_ip:.2f} "
                f"low_cap={_INTAKE_LOW_CAP} admitted_t4={_admitted_by_tier.get(4, 0)} "
                f"title={_row_title_ip}"
            )
            if bool((_row or {}).get("_prepare_bucket")):  # OBS-ADD
                print(  # OBS-ADD
                    f"[PREPARE_DROP] "  # OBS-ADD
                    f"item_id={str((_row or {}).get('item_id') or (_row or {}).get('itemId') or (_row or {}).get('source_item_id') or '')[:32]} "  # OBS-ADD
                    f"title={str((_row or {}).get('title') or (_row or {}).get('source_title') or '')[:120]} "  # OBS-ADD
                    f"stage=tier4_cap "  # OBS-ADD
                    f"reason=tier4_cap_admitted={_admitted_by_tier.get(4, 0)}_cap={_INTAKE_LOW_CAP}"  # OBS-ADD
                )  # OBS-ADD
            continue
        # Total budget cap
        if len(_valuation_candidates_auctions) >= _admit_cap:
            _budget_skipped_rows += 1
            _candidate_drop_counts["valuation_cap"] = int(_candidate_drop_counts.get("valuation_cap", 0) or 0) + 1
            print(
                f"[CANDIDATE_REASON] caller=valuation_intake "
                f"item={str(_row.get('item_id') or _row.get('source_item_id') or '')[:18] or '?'} "
                f"reason=valuation_cap"
            )
            print(
                f"[CANDIDATE_DROP] caller=valuation_intake "
                f"item={str(_row.get('item_id') or _row.get('source_item_id') or '')[:18] or '?'} "
                f"reason=valuation_cap title={_row_title_ip[:120]}"
            )
            print(
                f"[INTAKE_SKIP] tier={_row_tier} secs={_row_secs_ip:.0f} "
                f"admitted={len(_valuation_candidates_auctions)} cap={_admit_cap} "
                f"title={_row_title_ip}"
            )
            if bool((_row or {}).get("_prepare_bucket")):  # OBS-ADD
                print(  # OBS-ADD
                    f"[PREPARE_DROP] "  # OBS-ADD
                    f"item_id={str((_row or {}).get('item_id') or (_row or {}).get('itemId') or (_row or {}).get('source_item_id') or '')[:32]} "  # OBS-ADD
                    f"title={str((_row or {}).get('title') or (_row or {}).get('source_title') or '')[:120]} "  # OBS-ADD
                    f"stage=valuation_cap "  # OBS-ADD
                    f"reason=valuation_cap_admitted={len(_valuation_candidates_auctions)}_cap={_admit_cap}"  # OBS-ADD
                )  # OBS-ADD
            continue
        # Admit row — track by tier and log premium confirms
        _admitted_by_tier[_row_tier] = _admitted_by_tier.get(_row_tier, 0) + 1
        if _row_tier <= 1:
            print(
                f"[INTAKE_PRIORITY] tier={_row_tier} secs={_row_secs_ip:.0f} "
                f"price={_row_price_ip:.2f} title={_row_title_ip}"
            )
        # Strip seller/storefront noise from title before valuation consumes it.
        # This prevents tokens like "AutographDen" from creating fake auto signals
        # in entity extraction, comp query construction, and premium classification.
        _strip_title_noise_inplace(_row)
        _valuation_candidates_auctions.append(_row)
        _discovery_admitted_by_tier[_row_discovery_tier] = int(_discovery_admitted_by_tier.get(_row_discovery_tier, 0) or 0) + 1
        _candidate_survived += 1
        if bool(_row.get("_target_match_relaxed")):
            _candidate_relaxed_survived += 1
        else:
            _candidate_strict_survived += 1
        if bool(_row.get("_trusted_target_routed")) and _has_valid_frozen_target_contract(_row):
            print(
                f"[FINAL_TRUTH_ENTRY] caller=valuation_intake "
                f"item={str(_row.get('item_id') or _row.get('source_item_id') or '')[:18] or '?'} "
                f"reason={str(_row.get('_trusted_target_route_reason') or 'trusted_target_route')[:48]}"
            )
    print(
        f"[CANDIDATE_SUMMARY] caller=valuation_intake input={len(_target_rows)} "
        f"survived={_candidate_survived} dropped={max(0, len(_target_rows) - _candidate_survived)} "
        f"strict_survived={_candidate_strict_survived} "
        f"relaxed_input={_candidate_relaxed_input} relaxed_survived={_candidate_relaxed_survived} "
        f"drop_reasons={_candidate_drop_counts}"
    )
    print(
        f"[VALUATION_HANDOFF_GATE] stage=candidate_survival "
        f"source_rows={_safe_count(_target_rows)} "
        f"candidate_rows={_safe_count(_valuation_candidates_auctions)} "
        f"drop_reason={dict(_candidate_drop_counts or {})}"
    )
    print(f"[INTAKE_STAGE] stage=post_candidate_survival count={len(_valuation_candidates_auctions)}")
    # ── Broad intake survival diagnostics ────────────────────────────────────
    _broad_in_targets   = sum(1 for _r in _target_rows                  if str(_r.get("_intake_type") or "") == "broad")
    _broad_in_candidates = sum(1 for _r in _valuation_candidates_auctions if str(_r.get("_intake_type") or "") == "broad")
    print(
        f"[BROAD_INTAKE_SURVIVAL] reached_valuation={_broad_in_targets} "
        f"survived_intake={_broad_in_candidates} "
        f"total_candidates={len(_valuation_candidates_auctions)}"
    )
    _auction_survival_players: Dict[str, Dict[str, int]] = {}
    for _stage_name, _stage_rows in (
        ("title_pass", _title_rows),
        ("identity_survivors", _player_rows),
        ("target_survivors", _target_rows),
        ("valuation_handoff", _valuation_candidates_auctions),
    ):
        for _survival_row in list(_stage_rows or []):
            _player_sv = str(
                (_survival_row or {}).get("_lane_audit_player")
                or (_survival_row or {}).get("target_label")
                or (_survival_row or {}).get("canonical_player")
                or (_survival_row or {}).get("player")
                or (_survival_row or {}).get("player_name")
                or (_survival_row or {}).get("athlete")
                or "unknown"
            ).strip() or "unknown"
            _entry_sv = _auction_survival_players.setdefault(
                _player_sv,
                {
                    "title_pass": 0,
                    "identity_survivors": 0,
                    "target_survivors": 0,
                    "valuation_handoff": 0,
                },
            )
            _entry_sv[_stage_name] = int(_entry_sv.get(_stage_name) or 0) + 1
    print(
        f"[AUCTION_SURVIVAL_FUNNEL] stage=valuation_handoff "
        f"players={len(_auction_survival_players)} "
        f"title_pass={len(_title_rows)} "
        f"identity_survivors={len(_player_rows)} "
        f"target_survivors={len(_target_rows)} "
        f"valuation_handoff={len(_valuation_candidates_auctions)}"
    )
    for _player_sv, _entry_sv in sorted(
        _auction_survival_players.items(),
        key=lambda _item: (-int(_item[1].get("title_pass") or 0), -int(_item[1].get("valuation_handoff") or 0), _item[0]),
    )[:24]:
        print(
            f"[AUCTION_SURVIVAL_FUNNEL] stage=valuation_handoff player={_player_sv[:64]} "
            f"title_pass={int(_entry_sv.get('title_pass') or 0)} "
            f"identity_survivors={int(_entry_sv.get('identity_survivors') or 0)} "
            f"target_survivors={int(_entry_sv.get('target_survivors') or 0)} "
            f"valuation_handoff={int(_entry_sv.get('valuation_handoff') or 0)}"
        )
    # ─────────────────────────────────────────────────────────────────────────
    # ── INTAKE BUDGET SUMMARY ─────────────────────────────────────────────────
    _intake_high = _admitted_by_tier.get(0, 0) + _admitted_by_tier.get(1, 0)
    _intake_secondary = _admitted_by_tier.get(2, 0) + _admitted_by_tier.get(3, 0)
    _intake_low = _admitted_by_tier.get(4, 0)
    print(
        f"[INTAKE_BUCKET] admitted={len(_valuation_candidates_auctions)} "
        f"tier0={_admitted_by_tier.get(0, 0)} tier1={_admitted_by_tier.get(1, 0)} "
        f"tier2={_admitted_by_tier.get(2, 0)} tier3={_admitted_by_tier.get(3, 0)} "
        f"tier4={_intake_low} demoted_t4={_intake_demote_count}"
    )
    print(
        f"[VALUATION_BUDGET_ALLOC] total={len(_valuation_candidates_auctions)} cap={_admit_cap} "
        f"high_priority={_intake_high} secondary={_intake_secondary} low_priority={_intake_low} "
        f"skipped={_budget_skipped_rows} demoted={_intake_demote_count}"
    )
    print(
        f"[DISCOVERY_BUDGET_SUMMARY] tier_0_1h={int(_discovery_admitted_by_tier.get('tier_0_1h') or 0)} "
        f"tier_1_3h={int(_discovery_admitted_by_tier.get('tier_1_3h') or 0)} "
        f"tier_3_6h={int(_discovery_admitted_by_tier.get('tier_3_6h') or 0)} "
        f"tier_6_24h={int(_discovery_admitted_by_tier.get('tier_6_24h') or 0)} "
        f"tier_over_24h={int(_intake_time_dropped or 0)} "
        f"valued_rows={len(_valuation_candidates_auctions)}"
    )
    if _supply_filter_drop_counts:
        print(
            f"[SUPPLY_FILTER_SUMMARY] dropped={sum(_supply_filter_drop_counts.values())} "
            f"reasons={_supply_filter_drop_counts} samples={_supply_filter_drop_samples}"
        )
    _promotion_cap = max(0, min(5, int(_cycle_budget.get("candidate_admit_cap") or _MAX_ROWS_ADMITTED_PER_CYCLE)))
    _promotion_existing_keys = {
        str((_row or {}).get("row_key") or _ending_soon_row_key(_row))
        for _row in (_valuation_candidates_auctions + _target_rows)
    }
    _promotion_eligible = 0
    _promotion_gate_input_raw = list(_parallel_rows) if _parallel_rows else list(_product_rows)
    # ── PROMOTION STATE CLEAN: filter already-admitted rows before entering gate ──
    # Avoids redundant per-row already_admitted accounting that inflates rejection counts.
    _promotion_already_admitted_count = 0
    _promotion_gate_input = []
    for _pr in _promotion_gate_input_raw:
        _pr_key = str((_pr or {}).get("row_key") or _ending_soon_row_key(_pr))
        if _pr_key in _promotion_existing_keys:
            _promotion_already_admitted_count += 1
        else:
            _promotion_gate_input.append(_pr)
    if _promotion_already_admitted_count > 0:
        print(
            f"[PROMOTION_STATE_CLEAN] pre_filtered_admitted={_promotion_already_admitted_count} "
            f"remaining_for_gate={len(_promotion_gate_input)}"
        )
        print(
            f"[PROMOTION_ALREADY_ADMITTED_SKIP] count={_promotion_already_admitted_count} "
            f"total_input={len(_promotion_gate_input_raw)}"
        )
    # ─────────────────────────────────────────────────────────────────────────
    print(
        f"[ES][ENTITY_PRECHECK] input={len(_promotion_gate_input)} "
        f"loose={sum(1 for r in _promotion_gate_input if r.get('entity_loose_match'))}"
    )
    _promotion_gate_reason_counts: Dict[str, int] = {}
    _promotion_gate_reject_samples: List[str] = []
    _trusted_target_bypass_admits = 0
    for _row in sorted(_promotion_gate_input, key=_candidate_priority_key):
        _key = str((_row or {}).get("row_key") or _ending_soon_row_key(_row))
        if _key in _promotion_existing_keys:
            # Safety net: key added between pre-filter and this iteration (shouldn't happen)
            _promotion_gate_reason_counts["already_admitted"] = int(_promotion_gate_reason_counts.get("already_admitted", 0) or 0) + 1
            continue
        _force_promote_true_exact, _force_promote_reason = _promotion_force_true_exact_sniper(
            _row,
            caller="promotion_gate",
        )
        _bucket = ""  # always defined; empty string = row passes
        _title = str((_row or {}).get("title") or "")
        _reason = str((_row or {}).get("entity_gate_reason") or "").strip().lower()
        _target_meta = dict((_row or {}).get("target_meta") or {})
        _scarcity_sensitive = any(
            str(_target_meta.get(k) or "").strip()
            for k in ("subset_name", "serial_denominator", "parallel_name")
        )
        _entity_score = float((_row or {}).get("entity_match_score") or 0.0)
        _entity_status = str((_row or {}).get("entity_match_status") or "").strip().upper()
        _universe_ok, _universe_reason = _promotion_tracked_universe_membership(_row)
        _trusted_bypass_ok, _trusted_bypass_reason = _trusted_target_route_bypass_decision(
            _row,
            caller="promotion_gate",
            emit_log=True,
        )
        if _trusted_bypass_ok:
            _trusted_target_bypass_admits += 1
            if not _universe_ok:
                print(
                    f"[FINAL_TARGET_REDUNDANT_REJECT] caller=promotion_gate "
                    f"item={str((_row or {}).get('item_id') or (_row or {}).get('source_item_id') or '')[:18] or '?'} "
                    f"reason={str(_universe_reason or 'tracked_universe_reject')[:48]}"
                )
            _universe_ok = True
            _universe_reason = "trusted_target_bypass"
        if _force_promote_true_exact:
            _bucket = ""
            print(
                f"[PROMOTION_OVERRIDE_ALLOW] title={_title[:120]} "
                f"reason={_force_promote_reason} trusted_exact={int((_row or {}).get('trusted_exact_comp_count') or 0)} "
                f"target_bid={_row.get('target_bid')} current_price={_row.get('current_price') or _row.get('current_bid')}"
            )
        elif _shared_admission_reject_reason(_row):
            _bucket = "dirty_title"
        elif not _universe_ok and _universe_reason != "family_alias_miss":
            # family_alias_miss is intentionally allowed through — player-matched
            # rows where product-family inference failed still deserve valuation.
            _bucket = _universe_reason
        elif not _trusted_bypass_ok and not (
            bool((_row or {}).get("exact_entity_match"))
            or _entity_status in {"EXACT_MATCH", "STRONG_MATCH"}
            or _entity_score >= 0.65
            or (
                str((_row or {}).get("player_name") or "").strip().lower()
                and str((_row or {}).get("player_name") or "").strip().lower() in str(_title or "").lower()
            )
        ):
            _bucket = "weak_entity"
        elif (
            not _trusted_bypass_ok
            and (
            _entity_score < 0.82
            and not bool((_row or {}).get("exact_entity_match"))
            and _entity_status not in {"EXACT_MATCH", "STRONG_MATCH"}
            )
        ):
            # Row passed via relaxed threshold — stamp for diagnostics
            (_row or {})["entity_loose_match"] = True
        elif _title_cleanliness_score(_title) < 3.5:
            _bucket = "dirty_title"
        elif _reason in {"wrong_entity", "other_player_in_title", "conflicting_seed_player", "oversized_downtown", "nonstandard_subset_variant"}:
            _bucket = "target_conflict"
        elif not _trusted_bypass_ok and _scarcity_sensitive and _reason not in {"parallel_mismatch", "family_valid_fallback", "family_valid_premium", "ok"}:
            _bucket = "scarcity_unclear"
        else:
            _bucket = ""
        if (
            bool((_row or {}).get("_trusted_target_routed"))
            and _has_valid_frozen_target_contract(_row)
            and not _trusted_bypass_ok
            and _bucket
        ):
            print(
                f"[FINAL_TARGET_BYPASS_BLOCK] caller=promotion_gate "
                f"item={str((_row or {}).get('item_id') or (_row or {}).get('source_item_id') or '')[:18] or '?'} "
                f"reason={str(_trusted_bypass_reason or _bucket)[:48]}"
            )
        if _bucket:
            _promotion_gate_reason_counts[_bucket] = int(_promotion_gate_reason_counts.get(_bucket, 0) or 0) + 1
            if len(_promotion_gate_reject_samples) < 3 and _title:
                if _bucket == "sport_not_tracked":
                    _seed = (player_hub.players_by_id() or {}).get(
                        str((_row or {}).get("target_entity_id") or (_row or {}).get("player_id") or "").strip()
                    ) or {}
                    _target_meta = player_hub.resolve_effective_product_target_meta(dict((_row or {}).get("target_meta") or {}))
                    _row_sport_raw = (
                        (_row or {}).get("sport")
                        or (_row or {}).get("target_sport")
                        or (_row or {}).get("sport_name")
                        or _target_meta.get("sport")
                        or ""
                    )
                    _seed_sport_raw = _seed.get("sport") or ""
                    _promotion_gate_reject_samples.append(
                        "title="
                        + " ".join(_title.split())[:56]
                        + f" row_sport={_row_sport_raw} norm_row_sport={_normalize_sport_label(_row_sport_raw)}"
                        + f" tracked_sport={_seed_sport_raw} norm_tracked_sport={_normalize_sport_label(_seed_sport_raw)}"
                    )
                elif _bucket == "family_alias_miss":
                    _target_meta = player_hub.resolve_effective_product_target_meta(dict((_row or {}).get("target_meta") or {}))
                    _tracked_aliases = player_hub._product_family_aliases(_target_meta) if _target_meta else [
                        _normalize_family_probe(str((_row or {}).get("target_product_family") or (_row or {}).get("lane_product") or ""))
                    ]
                    _row_family = str(
                        (_row or {}).get("product_family")
                        or (_row or {}).get("target_product_family")
                        or (_row or {}).get("lane_product")
                        or (_row or {}).get("matched_product_family")
                        or (_row or {}).get("normalized_family")
                        or ""
                    ).strip()
                    _matched_ok, _matched_alias = _family_is_compatible_with_tracked_universe(
                        _row_family,
                        [x for x in _tracked_aliases if x],
                        row=dict(_row or {}),
                    )
                    _promotion_gate_reject_samples.append(
                        "title="
                        + " ".join(_title.split())[:52]
                        + f" row_family={_row_family}"
                        + f" norm_row_family={_normalize_family_probe(_row_family)}"
                        + f" tracked_families={[x for x in _tracked_aliases if x][:4]}"
                        + f" matched_alias={str(_matched_alias or '')}"
                        + f" compatible={int(bool(_matched_ok))}"
                    )
                else:
                    _promotion_gate_reject_samples.append(" ".join(_title.split())[:96])
            continue
        if not _force_promote_true_exact and not _is_promotable_live_candidate(_row):
            _promotion_gate_reason_counts["other_gate"] = int(_promotion_gate_reason_counts.get("other_gate", 0) or 0) + 1
            if len(_promotion_gate_reject_samples) < 3 and _title:
                _promotion_gate_reject_samples.append(" ".join(_title.split())[:96])
            continue
        _promotion_eligible += 1
        if len(_promoted_live_candidates) >= _promotion_cap:
            _promotion_gate_reason_counts["cap_reached"] = int(_promotion_gate_reason_counts.get("cap_reached", 0) or 0) + 1
            continue
        _promoted = dict(_row)
        _promoted["lane_approved"] = True
        _promoted["route_stage"] = "promoted_live_candidate"
        _promoted["route_reason"] = "Truthful live row promoted for premium evaluation"
        _promoted["lane_origin"] = str(_promoted.get("lane_origin") or "premium_review")
        _promoted["recovery_stage"] = str(_promoted.get("recovery_stage") or "primary")
        if _force_promote_true_exact:
            _promoted["promoted_live_candidate"] = True
            _promoted["promotion_override"] = True
            _promoted["promotion_override_reason"] = _force_promote_reason
            _promoted["force_mv_attempt"] = True
        _promoted = _stamp_trusted_target_route(
            _promoted,
            reason="upstream_target_route:promoted_live_candidate",
        )
        _promoted_live_candidates.append(_promoted)
        _promotion_existing_keys.add(_key)
    for _row in _promoted_live_candidates:
        _row["force_mv_attempt"] = True
    _valuation_candidates_auctions.extend(_promoted_live_candidates)
    _promoted_mv_attempted = len(_promoted_live_candidates)
    print(f"[ES][MV_FORCE] {sum(1 for r in _promoted_live_candidates if r.get('force_mv_attempt'))}")
    print(f"[ES][ENTITY] loose={sum(1 for r in _promoted_live_candidates if r.get('entity_loose_match'))}")
    _valuation_candidates_bin: List[Dict[str, Any]] = []
    if include_bin_alerts:
        for _row in sorted(all_bin_items, key=_candidate_priority_key):
            _rej = _pre_valuation_candidate_reject_reason(_row)
            if _rej:
                _preval_reject_counts[_rej] = int(_preval_reject_counts.get(_rej, 0) or 0) + 1
                continue
            if len(_valuation_candidates_bin) >= max(6, int(_cycle_budget.get("candidate_admit_cap") or _MAX_ROWS_ADMITTED_PER_CYCLE) // 2):
                _budget_skipped_rows += 1
                continue
            _valuation_candidates_bin.append(_row)

    _valuation_cap = int(_cycle_budget.get("valuation_cycle_cap") or 0)
    print(
        f"[VALUATION_HANDOFF_GATE] stage=final_pre_valuation "
        f"source_rows={_safe_count(all_auction_items)} "
        f"candidate_rows={_safe_count(_valuation_candidates_auctions)} "
        f"drop_reason={{'all_auction_items': {_safe_count(all_auction_items)}, "
        f"'window_rows': {_safe_count(_window_rows)}, "
        f"'title_rows': {_safe_count(_title_rows)}, "
        f"'player_rows': {_safe_count(_player_rows)}, "
        f"'product_rows': {_safe_count(_product_rows)}, "
        f"'parallel_rows': {_safe_count(_parallel_rows)}, "
        f"'target_rows': {_safe_count(_target_rows)}, "
        f"'candidate_drop_counts': {dict(_candidate_drop_counts or {})}, "
        f"'promoted_live_candidates': {_safe_count(_promoted_live_candidates)}}}"
    )
    _phr_prepare_candidates = sum(
        1 for _r in (_valuation_candidates_auctions or []) if bool((_r or {}).get("_prepare_bucket"))
    )
    print(
        f"[PREPARE_HANDOFF_TRACE] stage=final_pre_valuation "
        f"prepare_candidates={_phr_prepare_candidates} "
        f"valuation_rows={_safe_count(_valuation_candidates_auctions)}"
    )
    print(f"[ENGINE_STAGE] stage=valuation_start rows={len(_valuation_candidates_auctions)}")
    _scan_heartbeat(
        "valuing_rows",
        f"Valuing auction rows ({len(_valuation_candidates_auctions)})",
        progress_current=0,
        progress_total=len(_valuation_candidates_auctions),
        progress_label="valuation",
    )
    try:
        enriched_auctions = _enrich_with_mv(
            _valuation_candidates_auctions,
            max_mv=_valuation_cap,
        )
        enriched_bin = _enrich_with_mv(_valuation_candidates_bin, max_mv=0) if include_bin_alerts and _valuation_candidates_bin else []
    except Exception as e:
        return _safe_failed_scan_return(str(e))
    print(f"[ENGINE_STAGE] stage=valuation_done rows={len(enriched_auctions)}")

    excluded_non_single_card_count = 0
    exclusion_reason_counts: Dict[str, int] = {}

    cleaned_auctions: List[Dict[str, Any]] = []
    for d in enriched_auctions:
        _reason = _ending_soon_exclusion_reason(d)
        if _reason:
            excluded_non_single_card_count += 1
            exclusion_reason_counts[_reason] = exclusion_reason_counts.get(_reason, 0) + 1
            continue
        cleaned_auctions.append(_strengthen_row_valuation_support(d))
    _provisional_supply_seeded = 0
    _provisional_supply_blocked = 0
    for _row in cleaned_auctions:
        _supply_ok, _supply_reason = _provisional_supply_admission_decision(
            _row,
            caller="valuation_supply_gate",
            emit_log=True,
        )
        # Candidate survival already validated window, hard fail, junk, and route.
        # If the ONLY failure is missing_frozen_contract, override — candidate survival is sufficient.
        if not _supply_ok and _supply_reason == "missing_frozen_contract" and bool(_row.get("_candidate_survival_admit")):
            _supply_ok = True
            _supply_reason = "candidate_survival_override"
            print(
                f"[SUPPLY_CANDIDATE_OVERRIDE] title={str(_row.get('title') or '')[:80]} "
                f"reason=candidate_survival_admit overrides missing_frozen_contract"
            )
        _row["_supply_provisional_admit"] = bool(_supply_ok)
        _row["_supply_provisional_reason"] = _supply_reason
        if _supply_ok:
            _needs_provisional = bool(
                not bool(_row.get("mv_resolved"))
                or not bool(_row.get("target_bid_ready"))
                or not str(_row.get("premium_review_status") or "").strip()
                or str(_row.get("target_fit_tier") or "").strip().lower() in {"", "forced_review"}
            )
            if _needs_provisional:
                _row["_supply_provisional_entry"] = True
                _row["_supply_provisional_stage"] = "valuation_supply_gate"
                _provisional_supply_seeded += 1
                print(
                    f"[SUPPLY_PROVISIONAL_ENTRY] title={str(_row.get('title') or '')[:120]} "
                    f"reason={_supply_reason}"
                )
        else:
            _provisional_supply_blocked += 1
    print(
        f"[SUPPLY_GATE_SUMMARY] cleaned={len(cleaned_auctions)} "
        f"provisional_seeded={_provisional_supply_seeded} blocked={_provisional_supply_blocked}"
    )
    _scan_heartbeat(
        "valuing_rows",
        f"Valuation complete ({len(cleaned_auctions)} cleaned rows)",
        progress_current=len(cleaned_auctions),
        progress_total=len(_valuation_candidates_auctions),
        progress_label="valuation",
    )
    if cleaned_auctions:
        _publish_partial_snapshot(cleaned_auctions[:24], "Valuation pass produced partial rows", "valuing_rows")
    _promoted_cleaned_rows = [
        _row for _row in cleaned_auctions
        if str((_row or {}).get("route_stage") or "") == "promoted_live_candidate"
    ]
    _promoted_mv_resolved = sum(1 for _row in _promoted_cleaned_rows if float(_row.get("market_value") or 0.0) > 0)
    _promoted_target_bid_ready = sum(1 for _row in _promoted_cleaned_rows if bool(_row.get("target_bid_ready")) or _row_target_bid_ready(_row))
    _promoted_review_resolved = sum(1 for _row in _promoted_cleaned_rows if str(_row.get("premium_review_status") or "") == "resolved")
    _promoted_review_partial = sum(1 for _row in _promoted_cleaned_rows if str(_row.get("premium_review_status") or "") == "partial")
    _promoted_review_failed = sum(1 for _row in _promoted_cleaned_rows if str(_row.get("premium_review_status") or "") == "failed")

    cleaned_bin: List[Dict[str, Any]] = []
    for d in enriched_bin:
        _reason = _ending_soon_exclusion_reason(d)
        if _reason:
            excluded_non_single_card_count += 1
            exclusion_reason_counts[_reason] = exclusion_reason_counts.get(_reason, 0) + 1
            continue
        cleaned_bin.append(d)

    _valuation_conf_counts: Dict[str, int] = {}
    _valuation_source_counts: Dict[str, int] = {}
    _valuation_with_mv = 0
    _valuation_with_comps = 0
    _valuation_target_bid_ready = 0
    _valuation_action_ready = 0
    _valuation_monitor = 0
    _valuation_suppressed = 0
    _mv_fail_no_mv = 0
    _mv_fail_no_comps = 0
    _mv_fail_low_conf = 0
    _mv_fail_no_target_bid = 0
    _mv_fail_weak_edge = 0
    _mv_failure_samples = 0
    _comp_queries_built = 0
    _comp_raw_candidates = 0
    _comp_after_player_guard = 0
    _comp_after_product_guard = 0
    _comp_after_parallel_guard = 0
    _comp_after_grade_guard = 0
    _comp_usable_rows = 0
    _comp_mv_resolved = 0
    _comp_mv_weak = 0
    _comp_mv_unresolved = 0
    _scarcity_with_subset = 0
    _scarcity_with_card_number = 0
    _scarcity_with_serial = 0
    _scarcity_rare_parallel = 0
    _scarcity_aligned_rows = 0
    _generic_fallback_on_rare = 0
    _scarcity_subset_used_in_query = 0
    _scarcity_serial_used_in_query = 0
    _scarcity_bucket_counts: Dict[str, int] = {}
    _scarcity_samples = 0
    for _row in cleaned_auctions:
        try:
            _mv = float(_row.get("mv_value") or _row.get("market_value") or 0.0)
        except (TypeError, ValueError):
            _mv = 0.0
        if _mv > 0:
            _valuation_with_mv += 1
        if int(_row.get("mv_comp_count") or _row.get("comp_count") or 0) > 0:
            _valuation_with_comps += 1
        if _row_target_bid_ready(_row):
            _valuation_target_bid_ready += 1
        _conf_key = str(_row.get("valuation_confidence") or _normalize_mv_confidence(_row) or "unknown").strip().lower() or "unknown"
        _valuation_conf_counts[_conf_key] = int(_valuation_conf_counts.get(_conf_key, 0) or 0) + 1
        _source_key = str(_row.get("mv_source") or _row.get("market_value_source") or "unknown").strip().lower() or "unknown"
        _valuation_source_counts[_source_key] = int(_valuation_source_counts.get(_source_key, 0) or 0) + 1
        if str(_row.get("subset_name") or "").strip():
            _scarcity_with_subset += 1
        if str(_row.get("card_number") or "").strip():
            _scarcity_with_card_number += 1
        if str(_row.get("serial_bucket") or "").strip():
            _scarcity_with_serial += 1
            _serial_bucket_key = str(_row.get("serial_bucket") or "").strip()
            _scarcity_bucket_counts[_serial_bucket_key] = int(_scarcity_bucket_counts.get(_serial_bucket_key, 0) or 0) + 1
        if str(_row.get("rare_parallel") or "").strip():
            _scarcity_rare_parallel += 1
        if str(_row.get("market_value_source") or "").strip().lower() in {"scarcity_aligned_comp_engine", "scarcity_supported_comp_engine"}:
            _scarcity_aligned_rows += 1
        if (
            (str(_row.get("subset_name") or "").strip() or str(_row.get("rare_parallel") or "").strip() or str(_row.get("serial_bucket") or "").strip())
            and str(_row.get("market_value_source") or "").strip().lower() in {"medium_comp_engine", "fallback_comp_support", "scarcity_fallback"}
        ):
            _generic_fallback_on_rare += 1
        if bool(_row.get("subset_used_in_query")):
            _scarcity_subset_used_in_query += 1
        if bool(_row.get("serial_used_in_query")):
            _scarcity_serial_used_in_query += 1
        _passes_raw = str(_row.get("debug_comp_passes_json") or "").strip()
        if _passes_raw:
            try:
                _passes = json.loads(_passes_raw)
                if isinstance(_passes, list):
                    _comp_queries_built += len(_passes)
            except Exception:
                pass
        _comp_raw_candidates += int(_row.get("debug_fetched_count") or 0)
        _comp_after_player_guard += int(_row.get("debug_accepted_count") or 0)
        _comp_after_product_guard += int(_row.get("mv_relaxed_comp_count") or _row.get("mv_strict_comp_count") or 0)
        _comp_after_parallel_guard += int(_row.get("mv_strict_comp_count") or 0)
        _comp_after_grade_guard += int(_row.get("exact_grade_comp_count") or _row.get("fallback_grade_comp_count") or 0)
        _comp_usable_rows += int(_row.get("mv_comp_count") or _row.get("comp_count") or 0)
        _bucket = _valuation_bucket_for_row(_row)
        if _bucket == "action_ready":
            _valuation_action_ready += 1
        elif _bucket == "monitor":
            _valuation_monitor += 1
        else:
            _valuation_suppressed += 1
        if _source_key in {"strong_comp_engine", "medium_comp_engine", "exact_comp_engine"}:
            _comp_mv_resolved += 1
        elif _source_key in {"scarcity_supported_comp_engine"}:
            _comp_mv_resolved += 1
        elif _source_key in {"fallback_comp_support", "structured_fallback"}:
            _comp_mv_weak += 1
        else:
            _comp_mv_unresolved += 1
        _fail_reasons = _valuation_failure_reasons(_row)
        if "no_mv" in _fail_reasons:
            _mv_fail_no_mv += 1
        if "no_comps" in _fail_reasons:
            _mv_fail_no_comps += 1
        if "low_conf" in _fail_reasons:
            _mv_fail_low_conf += 1
        if "no_target_bid" in _fail_reasons:
            _mv_fail_no_target_bid += 1
        if "weak_edge" in _fail_reasons:
            _mv_fail_weak_edge += 1
        if _bucket != "action_ready" and _mv_failure_samples < 5:
            _log_mv_failure_sample(_row, reasons=_fail_reasons or ["monitor_only"])
            _mv_failure_samples += 1
        if _scarcity_samples < 5 and (
            str(_row.get("subset_name") or "").strip()
            or str(_row.get("serial_bucket") or "").strip()
            or str(_row.get("rare_parallel") or "").strip()
        ):
            _log_scarcity_sample(_row, query_text=str(_row.get("debug_search_query") or ""))
            _scarcity_samples += 1
        if _mv_failure_samples < 5 and str(_row.get("debug_rejections_top") or "").strip():
            _top_reject = str(_row.get("debug_rejections_top") or "").split(",")[0].strip()
            _parts = _top_reject.split(":")
            _reason = _parts[0] if _parts else _top_reject
            _log_comp_reject_sample(
                {
                    "title": _row.get("title"),
                    "comp_title_sample": str(_row.get("debug_search_query") or "")[:84],
                    "comp_reject_reason": _reason,
                }
            )
    print(
        f"[ES][VALUATION] matched_rows={len(cleaned_auctions)} with_mv={_valuation_with_mv} "
        f"without_mv={max(0, len(cleaned_auctions) - _valuation_with_mv)} with_comps={_valuation_with_comps} "
        f"no_comps={max(0, len(cleaned_auctions) - _valuation_with_comps)} conf_counts={_valuation_conf_counts} "
        f"target_bid_ready={_valuation_target_bid_ready} primary_ready={_valuation_action_ready} "
        f"suppressed={_valuation_suppressed}"
    )
    print(
        f"[ES][COMP] matched_for_comp={len(cleaned_auctions)} comp_queries_built={_comp_queries_built} "
        f"raw_comp_candidates={_comp_raw_candidates} after_player_guard={_comp_after_player_guard} "
        f"after_product_guard={_comp_after_product_guard} after_parallel_guard={_comp_after_parallel_guard} "
        f"after_grade_guard={_comp_after_grade_guard} usable_comp_rows={_comp_usable_rows} "
        f"mv_resolved={_comp_mv_resolved} mv_weak={_comp_mv_weak} mv_unresolved={_comp_mv_unresolved} "
        f"source_counts={_valuation_source_counts}"
    )
    print(
        f"[ANCHOR_SUMMARY] fetched={len(_window_rows)} within_window={len(_window_rows)} "
        f"title_pass={len(_title_rows)} parallel_entity_present={sum(1 for _r in _parallel_rows if _has_tracked_anchor(_r))} "
        f"route_pass={len(_target_rows)} comp_ready={len(cleaned_auctions)} final_feed={len(filtered_auctions) if 'filtered_auctions' in locals() else 0}"
    )
    print(
        f"[ENTITY_SUMMARY] fetched={len(_window_rows)} within_window={len(_window_rows)} "
        f"title_pass={len(_title_rows)} entity_present={sum(1 for _r in _parallel_rows if str(_r.get('normalized_entity') or '').strip())} "
        f"comp_ready={len(cleaned_auctions)} final_feed={len(filtered_auctions) if 'filtered_auctions' in locals() else 0}"
    )
    print(
        f"[ES][PROMOTION] eligible={_promotion_eligible} promoted={len(_promoted_live_candidates)} "
        f"mv_attempted={_promoted_mv_attempted} mv_resolved={_promoted_mv_resolved} "
        f"target_bid_ready={_promoted_target_bid_ready}"
    )
    print(
        f"[ES][PROMOTION_GATE] input={len(_promotion_gate_input)} eligible={_promotion_eligible} "
        f"rejected={max(0, len(_promotion_gate_input) - _promotion_eligible)} reasons={_promotion_gate_reason_counts}"
    )
    if _promotion_gate_reject_samples:
        print(f"[ES][FUNNEL][SAMPLE] promotion_gate -> {_promotion_gate_reject_samples}")
    print(
        f"[ES][PROMOTION_OUTPUT] promoted={len(_promoted_cleaned_rows)} resolved={_promoted_review_resolved} "
        f"partial={_promoted_review_partial} failed={_promoted_review_failed} "
        f"target_bid_ready={_promoted_target_bid_ready}"
    )
    print(
        f"[ES][SCARCITY] matched_rows={len(cleaned_auctions)} with_subset={_scarcity_with_subset} "
        f"with_card_number={_scarcity_with_card_number} with_serial={_scarcity_with_serial} "
        f"rare_parallel_rows={_scarcity_rare_parallel} subset_used_in_query={_scarcity_subset_used_in_query} "
        f"serial_used_in_query={_scarcity_serial_used_in_query} scarcity_aligned_rows={_scarcity_aligned_rows} "
        f"generic_fallback_on_rare={_generic_fallback_on_rare} exact_serial_bucket_counts={_scarcity_bucket_counts}"
    )
    print(
        f"[ES][MV_FAIL] no_mv={_mv_fail_no_mv} no_comps={_mv_fail_no_comps} low_conf={_mv_fail_low_conf} "
        f"no_target_bid={_mv_fail_no_target_bid} weak_edge={_mv_fail_weak_edge} source_counts={_valuation_source_counts}"
    )

    # Filter auctions: GOOD+ scored deals AND UNKNOWN (no MV yet); hide PASS/WEAK
    _scan_heartbeat(
        "finalizing_board",
        "Building final Ending Soon board",
        progress_current=len(cleaned_auctions),
        progress_total=len(cleaned_auctions),
        progress_label="board",
    )
    try:
        filtered_auctions, _auction_feed_reject_counts = _es_safe_guard_tuple2(
            _build_ending_soon_feed(
                cleaned_auctions,
                min_edge_pct=min_edge_pct,
                min_deal_classes=min_deal_classes,
            ),
            fn_name="_build_ending_soon_feed",
        )
    except Exception as e:
        return _safe_failed_scan_return(str(e))
    for _row in list(filtered_auctions or []):
        if isinstance(_row, dict):
            _maybe_apply_real_live_actionable_rescue(_row, stage="post_normalization_live_row")
    _premium_scarcity_mode_active = bool(int((_auction_feed_reject_counts or {}).get("__premium_scarcity_mode__") or 0))
    _existing_feed_keys = {
        str((_row or {}).get("row_key") or _ending_soon_row_key(_row))
        for _row in filtered_auctions
    }
    _premium_backfill_candidates: List[Dict[str, Any]] = []
    for _row in cleaned_auctions:
        _base = _stamp_feed_row(dict(_row or {}), feed_type="auction", scan_source="ending_soon")
        _row_key = str(_base.get("row_key") or _ending_soon_row_key(_base))
        if _row_key in _existing_feed_keys:
            continue
        _route = str(_base.get("route_stage") or "").strip().lower()
        _match_status = str(_base.get("target_match_status") or "").strip().lower()
        _mv_source = str(_base.get("mv_source") or _base.get("market_value_source") or "").strip().lower()
        _conf = str(_base.get("mv_confidence_strict") or _base.get("valuation_confidence") or _base.get("confidence") or "").strip().upper()
        _comp_count = _normalize_mv_comp_count(_base)
        _true_mv = _safe_float(_base.get("market_value_true")) or 0.0
        _rem = _base.get("source_time_remaining_seconds")
        if _rem is None:
            _rem = _row_remaining_seconds(_base)
        try:
            _remaining_val = float(_rem) if _rem is not None else None
        except (TypeError, ValueError):
            _remaining_val = None
        try:
            _base_hours = float(_base.get("scan_time_window_hours") or 0.0)
        except (TypeError, ValueError):
            _base_hours = 0.0
        try:
            _ext_hours = float(_base.get("premium_window_extension_hours") or 0.0)
        except (TypeError, ValueError):
            _ext_hours = 0.0
        _premium_window_ok = bool(_base.get("premium_window_kept"))
        if not _premium_window_ok and _remaining_val is not None:
            _window_hours = _base_hours + (_ext_hours if bool(_base.get("premium_window_allowed")) else 0.0)
            _premium_window_ok = _window_hours <= 0 or (-30.0 <= _remaining_val <= (_window_hours * 3600.0 + 30.0))
        _mem_junk, _ = _is_memorabilia_junk(_base)
        _vet_non_chase, _ = _is_veteran_non_chase(_base)
        _plain_parallel_block, _ = _is_plain_parallel_without_endgame_support(_base)
        _chase_class = str(_base.get("chase_class") or _classify_true_chase_class(_base)[0] or "").strip().upper()
        _trusted_mv = _premium_row_has_trusted_mv(_base)
        if not _is_premium_identity_row(_base):
            continue
        if not (_match_status == "premium_soft_valid" or _route in {"tracked_exact", "family_valid_premium", "premium_soft_valid", "card_number_rescue", "promoted_live_candidate"}):
            continue
        if not _trusted_mv or not _premium_window_ok:
            continue
        if _mem_junk or _vet_non_chase or _plain_parallel_block or bool(_is_common_rookie_commodity(_base)):
            continue
        _premium_backfill_candidates.append(_base)
    if _premium_scarcity_mode_active and _premium_backfill_candidates:
        for _row in sorted(_premium_backfill_candidates, key=_candidate_priority_key):
            _row_key = str(_row.get("row_key") or _ending_soon_row_key(_row))
            if _row_key in _existing_feed_keys:
                continue
            filtered_auctions.append(_row)
            _existing_feed_keys.add(_row_key)
            print(
                f"[FINAL_HANDOFF_KEEP] item={str(_row.get('item_id') or _row.get('source_item_id') or '')[:18] or '?'} "
                f"source={'promoted' if bool(_row.get('promoted_live_candidate')) or str(_row.get('route_stage') or '').strip().lower() == 'promoted_live_candidate' else 'exact' if str(_row.get('route_stage') or '').strip().lower() in {'tracked_exact', 'card_number_rescue'} else 'recovery'}"
            )
    _spillover_prepare_pool: List[Dict[str, Any]] = []
    _spillover_raw_unique: List[Dict[str, Any]] = []
    _spillover_seen_keys = set()
    _spillover_duplicate_title_seen: set[str] = set()
    _spillover_rank_candidates: List[Dict[str, Any]] = []
    print(
        f"[SPILLOVER_SOURCE_FINAL] strict_rows={len(_window_rows)} "
        f"spillover_source_rows={len(_spillover_source_rows)} "
        f"source_from_expanded={_spillover_source_from_expanded} "
        f"source_from_strict_partition={_spillover_source_from_strict_partition}"
    )
    for _row in list(_spillover_source_rows or []):
        _row_key = str((_row or {}).get("row_key") or _ending_soon_row_key(_row))
        _title_key = str((_row or {}).get("title") or (_row or {}).get("source_title") or "").strip().lower()
        if _row_key in _spillover_seen_keys:
            print(f"[SPILLOVER_DROP] title={str((_row or {}).get('title') or '')[:120]} reason=duplicate_listing")
            continue
        if _row_key in _existing_feed_keys:
            print(f"[SPILLOVER_DROP] title={str((_row or {}).get('title') or '')[:120]} reason=duplicate_listing")
            continue
        if _title_key and _title_key in _spillover_duplicate_title_seen:
            print(f"[SPILLOVER_DROP] title={str((_row or {}).get('title') or '')[:120]} reason=duplicate_title")
            continue
        _spillover_seen_keys.add(_row_key)
        if _title_key:
            _spillover_duplicate_title_seen.add(_title_key)
        _base = dict(_row or {})
        _strip_title_noise_inplace(_base)
        _spillover_raw_unique.append(_base)
    _spillover_enrich_kept = 0
    _spillover_enrich_dropped = 0
    if _spillover_raw_unique:
        _spillover_enriched = _enrich_with_mv(
            _spillover_raw_unique,
            max_mv=min(_ES_SPILLOVER_ENRICH_CAP, max(_ES_VISIBLE_BOARD_FLOOR, len(_spillover_raw_unique))),
        )
        for _row in list(_spillover_enriched or []):
            if _ending_soon_exclusion_reason(_row):
                _log_spillover_identity_gate(_row)
                if not _apply_downstream_truth_authority_immunity(_row):
                    _spillover_enrich_dropped += 1
                    print(f"[SPILLOVER_DROP] title={str((_row or {}).get('title') or '')[:120]} reason=bad_identity")
                    continue
            _prepared = _prepare_spillover_row(_row)
            _ok, _reason = _spillover_prepare_eligible(
                _prepared,
                strict_window_hours=_strict_time_window_hours,
                fetch_window_hours=_spillover_fetch_window_cap,
            )
            if not _ok:
                if _reason in {"junk_or_non_chase", "identity_mismatch"}:
                    _log_spillover_identity_gate(_prepared)
                    if _apply_downstream_truth_authority_immunity(_prepared):
                        _ok = True
                        _reason = "truth_valid_row_cannot_bad_identity_drop"
                if _ok:
                    pass
                else:
                    _spillover_enrich_dropped += 1
                    _drop_reason_map = {
                        "not_auction": "not_auction",
                        "outside_fetch_window": "outside_fetch_window",
                        "inside_strict_window": "inside_strict_window",
                        "junk_or_non_chase": "bad_identity",
                        "identity_mismatch": "bad_identity",
                        "commercially_suppressed": "commercial_hidden",
                        "not_commercial": "commercial_hidden",
                        "no_meaningful_edge": "weak_edge",
                    }
                    print(
                        f"[SPILLOVER_DROP] title={str((_prepared or {}).get('title') or '')[:120]} "
                        f"reason={_drop_reason_map.get(_reason, _reason or 'bad_identity')}"
                    )
                    continue
            _prepared["_spillover_prepare"] = True
            _prepared["_spillover_reason"] = _reason
            _prepared["spillover_prepare"] = True
            _prepared["spillover_window_hours"] = float(_spillover_fetch_window_cap or 0.0)
            _within_fetch_window = bool(
                _row_window_membership(
                    _prepared,
                    window_hours=_effective_fetch_window_hours,
                    caller="spillover_source_mark",
                ).get("keep")
            )
            _prepared["spillover_source"] = "fetch_window" if _within_fetch_window else "extended_window"
            _spillover_rank_candidates.append(_prepared)
            _spillover_prepare_pool.append(_prepared)
            _spillover_enrich_kept += 1
    print(
        f"[SPILLOVER_ENRICH] input={len(_spillover_raw_unique)} "
        f"kept={_spillover_enrich_kept} dropped={_spillover_enrich_dropped}"
    )
    for _row in filtered_auctions:
        _row["recovery_stage"] = str(_row.get("recovery_stage") or "primary")
        _row["recovery_reason"] = str(_row.get("recovery_reason") or "")
        _row["lane_origin"] = str(_row.get("lane_origin") or "tracked_exact")
    _starvation_gate_summary = _build_auction_starvation_summary(
        fetched_rows=len(_window_rows),
        within_window_rows=len(_window_rows),
        tracked_targets=configured_target_lanes,
        final_rows=len(filtered_auctions),
        after_player_filter=_after_player_filter,
        after_product_filter=_after_product_filter,
        after_parallel_filter=_after_parallel_filter,
    )
    _recovery_stage_counts: Dict[str, int] = {}
    _existing_row_keys = {
        str(_row.get("row_key") or _ending_soon_row_key(_row))
        for _row in filtered_auctions
    }
    if bool(_starvation_gate_summary.get("starved")):
        _recovery_raw: List[Dict[str, Any]] = []
        _tracked_expand_candidates: List[Dict[str, Any]] = []
        for _row in sorted(_window_rows, key=_candidate_priority_key):
            if bool(_row.get("lane_approved")):
                continue
            if str(_row.get("entity_gate_reason") or "").strip().lower() in {"wrong_entity", "oversized_downtown", "nonstandard_subset_variant"}:
                continue
            if not (bool(_row.get("exact_entity_match")) or float(_row.get("entity_match_score") or 0.0) >= 0.9):
                continue
            _key = _ending_soon_row_key(_row)
            if _key in _existing_row_keys:
                continue
            _tracked_expand_candidates.append(
                _stamp_recovery_row(
                    _row,
                    recovery_stage="tracked_expand",
                    recovery_reason="Recovered from thin tracked target coverage",
                    lane_origin="tracked_fallback",
                )
            )
            _existing_row_keys.add(_key)
            if len(_tracked_expand_candidates) >= 4:
                break
        _recovery_raw.extend(_tracked_expand_candidates)
        if not _recovery_raw:
            for _row in sorted(all_expanded_window_items, key=_candidate_priority_key):
                if not bool(_row.get("lane_approved")):
                    continue
                _key = _ending_soon_row_key(_row)
                if _key in _existing_row_keys:
                    continue
                _recovery_raw.append(
                    _stamp_recovery_row(
                        _row,
                        recovery_stage="window_expand",
                        recovery_reason="Recovered from thin live ending window",
                        lane_origin="expanded_window",
                    )
                )
                _existing_row_keys.add(_key)
                if len(_recovery_raw) >= 4:
                    break
        if not _recovery_raw:
            for _row in sorted(_window_rows, key=_candidate_priority_key):
                if bool(_row.get("lane_approved")):
                    continue
                if not (bool(_row.get("exact_entity_match")) or float(_row.get("entity_match_score") or 0.0) >= 0.9):
                    continue
                if str(_row.get("lane_tier") or "").strip().lower() not in {"secondary"} and str(_row.get("query_recall_stage") or "").strip().lower() == "precise":
                    continue
                _key = _ending_soon_row_key(_row)
                if _key in _existing_row_keys:
                    continue
                _recovery_raw.append(
                    _stamp_recovery_row(
                        _row,
                        recovery_stage="discovery_fallback",
                        recovery_reason="Recovered from thin live supply using discovery fallback",
                        lane_origin="discovery",
                    )
                )
                _existing_row_keys.add(_key)
                if len(_recovery_raw) >= 4:
                    break
        if _recovery_raw:
            _recovery_enriched = _enrich_with_mv(
                _recovery_raw,
                max_mv=max(0, min(6, int(_cycle_budget.get("candidate_admit_cap") or 6))),
            )
            _recovery_cleaned: List[Dict[str, Any]] = []
            for _row in _recovery_enriched:
                _reason = _ending_soon_exclusion_reason(_row)
                if _reason:
                    continue
                _recovery_cleaned.append(_strengthen_row_valuation_support(_row))
            _recovered_feed, _ = _es_safe_guard_tuple2(
                _build_ending_soon_feed(
                    _recovery_cleaned,
                    min_edge_pct=min_edge_pct,
                    min_deal_classes=min_deal_classes,
                ),
                fn_name="_build_ending_soon_feed",
            )
            for _row in _recovered_feed:
                _stage = str(_row.get("recovery_stage") or "primary")
                _recovery_stage_counts[_stage] = int(_recovery_stage_counts.get(_stage, 0) or 0) + 1
            filtered_auctions.extend(_recovered_feed)
    _after_quality_suppression = len(filtered_auctions)
    print(
        f"[ES][FUNNEL] quality_suppression in={len(cleaned_auctions)} out={len(filtered_auctions)} "
        f"rejects={max(0, len(cleaned_auctions) - len(filtered_auctions))}"
    )
    print(f"[ES][AUCTION] filtered_auctions={len(filtered_auctions)}")

    # ── Target heat diagnostic ─────────────────────────────────────────────────
    _exact_route_count  = sum(1 for _d in filtered_auctions if str(_d.get("route_stage") or "") == "tracked_exact")
    _family_valid_count = sum(1 for _d in filtered_auctions if str(_d.get("route_stage") or "") in {"family_valid_fallback", "family_valid_premium", "premium_soft_valid", "card_number_rescue"})
    print(
        f"[ES][TARGET_HEAT] exact={_exact_route_count} family_valid={_family_valid_count} "
        f"total_pre_forced={len(filtered_auctions)}"
    )

    _forced_surface_active = False
    _forced_surface_stage = ""
    _forced_surface_count = 0
    _forced_cap_rejected = 0
    _FORCED_SURFACE_QUALITY_MIN = 32   # forced rows below this score do not fill the board
    if not filtered_auctions:
        _forced_surface_raw, _forced_surface_stage = _pick_forced_window_rows(
            target_rows=_target_rows,
            parallel_rows=_parallel_rows,
            product_rows=_product_rows,
            player_rows=_player_rows,
            title_rows=_title_rows,
            window_rows=_window_rows,
            limit=5,
        )
        if _forced_surface_raw:
            print(f"[ES][FORCED_SURFACE] source_stage={_forced_surface_stage} count={len(_forced_surface_raw)}")
            _log_row_contract("forced_surface", _forced_surface_raw)
            _forced_surface_rows: List[Dict[str, Any]] = []
            _forced_cap_reasons: Dict[str, int] = {}
            for _row in _forced_surface_raw:
                _base = _strengthen_row_valuation_support(_row)
                _base["forced_surface"] = True
                _base["forced_surface_stage"] = _forced_surface_stage
                _base["forced_surface_reason"] = "Premium board empty; showing truthful live candidates."
                _base["recovery_stage"] = str(_base.get("recovery_stage") or "primary")
                _base["lane_origin"] = str(_base.get("lane_origin") or "forced_window")
                _base["route_reason"] = str(_base.get("route_reason") or _base["forced_surface_reason"])
                _base = _stamp_feed_row(_base, feed_type="auction", scan_source="ending_soon")
                _base = _stamp_alert_contract(_base, expected_feed="auction", expected_scan_source="ending_soon")
                # Quality gate on forced rows: weak filler must not dominate the board
                _fqs = _auction_quality_score(_base)
                _base["auction_quality_score"] = _fqs
                if _fqs < _FORCED_SURFACE_QUALITY_MIN:
                    _forced_cap_reasons["below_forced_min"] = _forced_cap_reasons.get("below_forced_min", 0) + 1
                    _forced_cap_rejected += 1
                    continue
                _forced_surface_rows.append(_base)
            # Safety valve: if all forced rows were rejected, keep top-2 by score
            if not _forced_surface_rows and _forced_surface_raw:
                _all_scored = []
                for _row in _forced_surface_raw:
                    _base = _strengthen_row_valuation_support(_row)
                    _base["forced_surface"] = True
                    _base["forced_surface_stage"] = _forced_surface_stage
                    _base["forced_surface_reason"] = "Premium board empty; showing truthful live candidates."
                    _base["recovery_stage"] = str(_base.get("recovery_stage") or "primary")
                    _base["lane_origin"] = str(_base.get("lane_origin") or "forced_window")
                    _base["route_reason"] = str(_base.get("route_reason") or _base["forced_surface_reason"])
                    _base = _stamp_feed_row(_base, feed_type="auction", scan_source="ending_soon")
                    _base = _stamp_alert_contract(_base, expected_feed="auction", expected_scan_source="ending_soon")
                    _base["auction_quality_score"] = _auction_quality_score(_base)
                    _all_scored.append(_base)
                _all_scored.sort(key=lambda x: -float(x.get("auction_quality_score") or 0.0))
                _forced_surface_rows = _all_scored[:2]
                _forced_cap_reasons["restored_top2_empty_guard"] = len(_forced_surface_rows)
            print(
                f"[ES][FORCED_CAP] input={len(_forced_surface_raw)} kept={len(_forced_surface_rows)} "
                f"rejected={_forced_cap_rejected} reasons={_forced_cap_reasons}"
            )
            if _forced_surface_rows:
                _forced_surface_active = True
                _forced_surface_count = len(_forced_surface_rows)
                filtered_auctions = _forced_surface_rows
            else:
                print("[ES][FORCED_SURFACE] source_stage=none count=0 (all filtered by quality cap)")
        else:
            print("[ES][FORCED_SURFACE] source_stage=none count=0")

    # Keep BIN diagnostic counts available, but do not mix them into the auction feed by default.
    filtered_bin: List[Dict[str, Any]] = []
    _bin_feed_reject_counts: Dict[str, int] = {}
    for d in cleaned_bin:
        if str(d.get("deal_class") or "UNKNOWN").strip().upper() not in ("BIN_DEAL", "BIN_WATCH", "UNKNOWN"):
            continue
        _row = _stamp_feed_row(d, feed_type="bin", scan_source="ending_soon")
        _reject_reason = _shared_admission_reject_reason(_row)
        if _reject_reason:
            _bin_feed_reject_counts[_reject_reason] = int(_bin_feed_reject_counts.get(_reject_reason, 0) or 0) + 1
            continue
        filtered_bin.append(_row)
    # ── Listing truth: ensure source_* fields are stamped on every auction row ──
    # Also re-derive source_time_remaining_seconds live (accurate even on cached rows)
    _listing_truth_kept: List[Dict[str, Any]] = []
    _listing_truth_rejected = 0
    _listing_truth_reject_reasons: Dict[str, int] = {}
    _premium_listing_truth_rejects: Dict[str, str] = {}
    for _d in filtered_auctions:
        _stamp_source_listing_truth(_d)   # re-stamp so remaining_seconds is fresh
        _row_key = str(_d.get("row_key") or _ending_soon_row_key(_d))
        _is_premium_row = _is_premium_identity_row(_d)
        # Hard rejection: must be an auction listing
        _lmode = str(_d.get("source_listing_type") or _parse_browse_listing_mode(_d))
        if _lmode not in {"auction", "auction_or_bin"}:
            _listing_truth_reject_reasons["not_auction"] = _listing_truth_reject_reasons.get("not_auction", 0) + 1
            _listing_truth_rejected += 1
            if _is_premium_row:
                _premium_listing_truth_rejects[_row_key] = "not_auction"
            print(f"[ES][LISTING_MISMATCH] item_id={_d.get('source_item_id') or _d.get('item_id')} reason=not_auction listing_type={_lmode}")
            continue
        # Hard rejection: must have a parseable end time
        if not _d.get("source_end_time"):
            _listing_truth_reject_reasons["missing_end_time"] = _listing_truth_reject_reasons.get("missing_end_time", 0) + 1
            _listing_truth_rejected += 1
            if _is_premium_row:
                _premium_listing_truth_rejects[_row_key] = "missing_end_time"
            print(f"[ES][TIME_MISMATCH] item_id={_d.get('source_item_id') or _d.get('item_id')} reason=missing_end_time")
            continue
        # Hard rejection: use authoritative window contract if present; only recompute when missing.
        _window_contract = _resolve_window_contract(_d, caller="listing_truth")
        _stt = _safe_float(_window_contract.get("remaining_seconds"))
        _window_threshold = _safe_float(_window_contract.get("threshold_seconds"))
        if (
            bool(_window_contract.get("keep"))
            and _stt is not None
            and _window_threshold is not None
            and _stt <= _window_threshold
        ):
            pass
        if not bool(_window_contract.get("keep")):
            _listing_truth_reject_reasons["missed_window"] = _listing_truth_reject_reasons.get("missed_window", 0) + 1
            _listing_truth_rejected += 1
            if _is_premium_row:
                _premium_listing_truth_rejects[_row_key] = "missed_window"
            print(
                f"[ES][TIME_MISMATCH] item_id={_d.get('source_item_id') or _d.get('item_id')} "
                f"reason=missed_window remaining={round(float(_stt), 1) if _stt is not None else 'na'} "
                f"threshold={round(float(_window_threshold), 1) if _window_threshold is not None else 'na'}"
            )
            continue
        # Price truth check: log mismatch if current_price looks like BIN
        _src_bid = float(_d.get("source_current_bid") or _d.get("current_price") or 0.0)
        _src_bin = _d.get("source_buy_now_price")
        _display_p = float(_d.get("source_display_price") or _d.get("current_price") or 0.0)
        if _src_bin is not None and _display_p > 0 and abs(_display_p - float(_src_bin)) < 0.01 and _src_bid > 0 and abs(_display_p - _src_bid) > 0.01:
            print(f"[ES][PRICE_MISMATCH] item_id={_d.get('source_item_id') or _d.get('item_id')} auction_bid={_src_bid} buy_now={_src_bin} display={_display_p}")
        _listing_truth_kept.append(_d)
    filtered_auctions = _listing_truth_kept
    print(
        f"[ES][LISTING_TRUTH] kept={len(filtered_auctions)} rejected={_listing_truth_rejected} "
        f"reasons={_listing_truth_reject_reasons}"
    )
    print(
        f"[ES][STARVATION_SUMMARY] raw_rows_total={_raw_fetch_rows} within_window_total={auction_within_window} "
        f"parallel_rows={len(_parallel_rows)} forced_rows={int(_forced_surface_count or 0)} "
        f"listing_truth_kept={len(filtered_auctions)} final_rows={len(filtered_auctions)}"
    )
    filtered_auctions = [_stamp_alert_contract(d, expected_feed="auction", expected_scan_source="ending_soon") for d in filtered_auctions]
    for _row in list(filtered_auctions or []):
        if isinstance(_row, dict):
            _maybe_apply_real_live_actionable_rescue(_row, stage="post_evidence_value")
    filtered_bin = [_stamp_alert_contract(d, expected_feed="bin", expected_scan_source="ending_soon") for d in filtered_bin]
    _inventory_quality_raw_seen = len(filtered_auctions)
    _inventory_quality_kept: List[Dict[str, Any]] = []
    _inventory_quality_blocked = 0
    _inventory_quality_pass_count = 0
    _subscription_grade_blocked = 0
    _subscription_tier_a_count = 0
    _subscription_tier_b_count = 0
    _subscription_tier_blocked = 0
    for _row in filtered_auctions:
        _quality_ok, _quality_reason = _inventory_quality_gate(_row)
        _row["inventory_quality_ok"] = _quality_ok
        _row["inventory_quality_reason"] = _quality_reason
        if not _quality_ok:
            print(
                f"[INVENTORY_QUALITY_BLOCK] title={str((_row or {}).get('title') or '')[:160]} "
                f"reason={_quality_reason}"
            )
            _row["_inventory_quality_blocked"] = True
            _row["_inventory_quality_block_reason"] = _quality_reason
            _inventory_quality_blocked += 1
            continue
        print(
            f"[INVENTORY_QUALITY_ALLOW] title={str((_row or {}).get('title') or '')[:160]} "
            f"reason={_quality_reason}"
        )
        _inventory_quality_pass_count += 1
        _tier, _tier_reason = _classify_subscription_lane_tier(_row)
        # ── TRUTH-RESCUE TIER OVERRIDE ────────────────────────────────────────
        # A row already certified by the accelerator (truth=TRUE + trusted_exact>=1
        # and perma_block not set) must NOT be silently dropped by the
        # market-priority classifier. Re-route such rows to TIER_B so
        # surface_intent gets stamped and the row reaches _live_board_rows.
        if _tier == "BLOCKED" and not bool(_row.get("exact_rescue_perma_block")) and (
            str(_row.get("valuation_truth_tier") or _row.get("_valuation_truth_tier") or "").strip().upper() == "TRUE"
            and int(_row.get("trusted_exact_comp_count") or 0) >= 1
            and bool(
                _row.get("_hydrated_identity_is_clean")
                or _row.get("identity_is_clean")
                or _row.get("identity_clean")
            )
        ):
            print(
                f"[TIER_TRUTH_RESCUE_OVERRIDE] title={str((_row or {}).get('title') or '')[:160]} "
                f"prior_tier=BLOCKED prior_reason={_tier_reason} new_tier=TIER_B "
                f"trusted_exact={_row.get('trusted_exact_comp_count')} "
                f"truth={_row.get('valuation_truth_tier')}"
            )
            _tier = "TIER_B"
            _tier_reason = "truth_rescue_override"
        _row["subscription_lane_tier"] = _tier
        _row["subscription_lane_tier_reason"] = _tier_reason
        _row["subscription_grade_ok"] = bool(_tier != "BLOCKED")
        _row["subscription_grade_reason"] = _tier_reason
        _truth = str(
            _row.get("truth")
            or _row.get("valuation_truth_tier")
            or _row.get("_valuation_truth_tier")
            or ""
        ).strip().upper()
        _truth_level = str(
            _row.get("truth_level")
            or _row.get("valuation_truth_level")
            or ""
        ).strip().upper()
        _trusted_exact = int(_row.get("trusted_exact_comp_count") or 0)
        _identity_is_clean = bool(
            _row.get("_hydrated_identity_is_clean")
            or _row.get("identity_is_clean")
        )
        _exact_truth_rescued = bool(_row.get("exact_truth_rescued") or _row.get("_exact_truth_rescued"))

        _truth_authority_override = bool(
            _identity_is_clean
            and (
                _truth == "TRUE"
                or _truth_level == "EXACT_RESCUE"
                or _trusted_exact >= 1
                or _exact_truth_rescued
            )
        )

        if (
            (_tier == "BLOCKED" and _truth_authority_override)
            or (_tier == "TIER_B" and _tier_reason == "truth_rescue_override")
        ):
            _tier = "TIER_B"
            _tier_reason = "truth_authority_override"
            _row["subscription_lane_tier"] = _tier
            _row["subscription_lane_tier_reason"] = _tier_reason
            _row["subscription_grade_ok"] = True
            _row["subscription_grade_reason"] = _tier_reason
            _row["surface_intent"] = "watchlist"
            _row["_truth_authority_override"] = True

            print(
                f"[TRUTH_AUTHORITY_OVERRIDE] title={str((_row or {}).get('title') or '')[:160]} "
                f"truth={_truth} "
                f"truth_level={_truth_level} "
                f"trusted_exact={_trusted_exact} "
                f"identity_is_clean={_identity_is_clean} "
                f"new_tier={_tier}"
            )
        _live_allow_reason = str(_row.get("_subscription_grade_live_allow_reason") or _subscription_grade_live_allow_reason(_row) or "").strip()
        if _live_allow_reason and _tier == "BLOCKED":
            _tier = "TIER_B"
            _tier_reason = f"subscription_grade_live_allow:{_live_allow_reason}"
            _row["subscription_lane_tier"] = _tier
            _row["subscription_lane_tier_reason"] = _tier_reason
            _row["subscription_grade_ok"] = True
            _row["subscription_grade_reason"] = _tier_reason
            _row["_subscription_grade_live_allow"] = True
            _row["_subscription_grade_live_allow_reason"] = _live_allow_reason
            _live_allow_key = str((_row or {}).get("row_key") or _ending_soon_row_key(_row) or id(_row))
            if _live_allow_key not in _subscription_grade_live_seen:
                _subscription_grade_live_seen.add(_live_allow_key)
                _subscription_grade_live_counts["premium_kept"] += 1
                if _live_allow_reason in _subscription_grade_live_counts:
                    _subscription_grade_live_counts[_live_allow_reason] += 1
            print(
                f"[SUBSCRIPTION_GRADE_LIVE_ALLOW] "
                f"title={str((_row or {}).get('title') or (_row or {}).get('source_title') or '')[:160]} "
                f"player={_row.get('player') or _row.get('player_name') or _row.get('target_player_name')} "
                f"product_family={_row.get('product_family') or _row.get('_hydrated_product_family') or _row.get('target_product_family')} "
                f"lane_type={_row.get('lane_type') or _row.get('_hydrated_lane_type')} "
                f"insert_family={_row.get('insert_family') or _row.get('_hydrated_insert_family')} "
                f"parallel_family={_row.get('parallel_family') or _row.get('_hydrated_parallel_family')} "
                f"serial_denominator={_row.get('serial_denominator') or _row.get('_hydrated_serial_denominator') or _row.get('serial')} "
                f"reason={_live_allow_reason}"
            )
        _stamp_hydrated_identity_snapshot(_row, emit_log=True)
        _fake_serial_block, _fake_serial_reason = _is_fake_serial_base_promo_row(_row)
        print(
            f"[FAKE_SERIAL_CHECK] title={str((_row or {}).get('title') or '')[:160]} "
            f"block={_fake_serial_block} "
            f"reason={_fake_serial_reason} "
            f"lane_type={_row.get('lane_type')} "
            f"parallel_family={_row.get('parallel_family')} "
            f"serial={_row.get('serial_denominator') or _row.get('serial')} "
            f"card_number={_row.get('card_number')}"
        )
        if _fake_serial_block:
            _row["_inventory_quality_blocked"] = True
            _row["_inventory_quality_block_reason"] = _fake_serial_reason
            print(
                f"[FAKE_SERIAL_HARD_BLOCK] title={str((_row or {}).get('title') or '')[:160]} "
                f"reason={_fake_serial_reason}"
            )
            _inventory_quality_blocked += 1
            continue
        print(
            f"[TIER_CLASSIFY_TRACE] title={str((_row or {}).get('title') or '')[:160]} "
            f"player={_row.get('player')} "
            f"sport={_row.get('sport')} "
            f"tracked={_row.get('tracked_player') or _row.get('is_tracked_target')} "
            f"heat={_row.get('heat') or _row.get('player_heat')} "
            f"rookie={_row.get('is_rookie') or _row.get('rookie') or _row.get('rc')} "
            f"identity_is_clean={_row.get('identity_is_clean')} "
            f"product_family={_row.get('product_family')} "
            f"parallel_family={_row.get('parallel_family')} "
            f"serial={_row.get('serial_denominator') or _row.get('serial')} "
            f"grade={_row.get('grade')} "
            f"tier={_row.get('subscription_lane_tier')} "
            f"reason={_row.get('subscription_lane_tier_reason')}"
        )
        print(
            f"[SUBSCRIPTION_CONTINUE_GATE] title={str((_row or {}).get('title') or '')[:160]} "
            f"tier={_row.get('subscription_lane_tier')} "
            f"tier_reason={_row.get('subscription_lane_tier_reason')} "
            f"truth={_row.get('truth') or _row.get('valuation_truth_tier') or _row.get('_valuation_truth_tier')} "
            f"truth_level={_row.get('truth_level') or _row.get('valuation_truth_level')} "
            f"trusted_exact={_row.get('trusted_exact_comp_count')} "
            f"override={_row.get('_truth_authority_override')}"
        )
        if _tier == "BLOCKED":
            print(
                f"[SUBSCRIPTION_TIER_BLOCK] title={str((_row or {}).get('title') or '')[:160]} "
                f"reason={_tier_reason}"
            )
            _row["_subscription_grade_blocked"] = True
            _row["_subscription_grade_block_reason"] = _tier_reason
            _subscription_grade_blocked += 1
            _subscription_tier_blocked += 1
            continue
        print(
            f"[SUBSCRIPTION_TIER_ALLOW] title={str((_row or {}).get('title') or '')[:160]} "
            f"tier={_tier} reason={_tier_reason}"
        )
        _row["mass_feed_candidate"] = True
        if _tier == "TIER_A":
            _row["surface_intent"] = "sniper"
            _subscription_tier_a_count += 1
        elif _tier == "TIER_B":
            _row["surface_intent"] = "watchlist"
            _subscription_tier_b_count += 1
        print(
            f"[SURFACE_INTENT_STAMP] title={str((_row or {}).get('title') or '')[:160]} "
            f"tier={_row.get('subscription_lane_tier')} intent={_row.get('surface_intent')}"
        )
        _stamp_mass_market_liquidity(_row, _quality_ok)
        _inventory_quality_kept.append(_row)
    filtered_auctions = _inventory_quality_kept
    print(
        f"[INVENTORY_QUALITY_SUMMARY] raw_seen={_inventory_quality_raw_seen} "
        f"inventory_blocked={_inventory_quality_blocked} "
        f"subscription_blocked={_subscription_grade_blocked} "
        f"surviving={len(filtered_auctions)}"
    )
    print(
        f"[SUBSCRIPTION_TIER_SUMMARY] "
        f"tier_a={_subscription_tier_a_count} "
        f"tier_b={_subscription_tier_b_count} "
        f"blocked={_subscription_tier_blocked}"
    )
    print(
        f"[COMMODITY_GRADED_SUMMARY] "
        f"suppressed={_commodity_graded_suppressed} "
        f"kept={_commodity_graded_kept}"
    )
    print(
        f"[SUBSCRIPTION_GRADE_LIVE_SUMMARY] "
        f"premium_kept={int(_subscription_grade_live_counts.get('premium_kept') or 0)} "
        f"case_hit={int(_subscription_grade_live_counts.get('case_hit') or 0)} "
        f"animal={int(_subscription_grade_live_counts.get('animal') or 0)} "
        f"low_serial={int(_subscription_grade_live_counts.get('low_serial') or 0)} "
        f"auto={int(_subscription_grade_live_counts.get('auto') or 0)} "
        f"premium_psa10={int(_subscription_grade_live_counts.get('premium_psa10') or 0)}"
    )
    print(
        f"[FEED_STARVATION_DIAG] "
        f"raw_rows={_raw_fetch_rows} "
        f"within_window={auction_within_window} "
        f"inventory_quality_pass={_inventory_quality_pass_count} "
        f"tier_a={_subscription_tier_a_count} "
        f"tier_b={_subscription_tier_b_count} "
        f"blocked={_inventory_quality_blocked + _subscription_tier_blocked} "
        f"final_rows={len(filtered_auctions)}"
    )
    _recovery_support_attempts = 0
    _recovery_support_success = 0
    _recovered_auctions: List[Dict[str, Any]] = []
    for _row in filtered_auctions:
        _resolved_row = dict(_row)
        if _can_attempt_premium_comp_support_recovery(_row):
            _recovery_support_attempts += 1
            _resolved_row = _recover_premium_comp_support(_row)
            if bool(_resolved_row.get("comp_support_recovered")):
                _recovery_support_success += 1
            _resolved_row = _stamp_feed_row(_resolved_row, feed_type="auction", scan_source="ending_soon")
            _resolved_row = _stamp_alert_contract(_resolved_row, expected_feed="auction", expected_scan_source="ending_soon")
        _recovered_auctions.append(_resolved_row)
    filtered_auctions = _recovered_auctions
    print(
        f"[RECOVERY_SUPPORT] attempted={_recovery_support_attempts} "
        f"recovered={_recovery_support_success}"
    )

    # ── Hybrid MV fallback (Lane 2) ───────────────────────────────────────────
    # Runs AFTER strict stamping. Only fires when has_valid_mv=False.
    # Writes mv_value/max_bid/valuation_confidence_label then re-stamps truth contract
    # so downstream actionability fields reflect the new values.
    _mvfb_input = len(filtered_auctions)
    _mvfb_used = 0
    _mvfb_edge = 0
    for _d in filtered_auctions:
        if not _d.get("has_valid_mv"):
            _applied = _fast_mv_fallback(_d)
            if _applied:
                _mvfb_used += 1
                if _d.get("fallback_mv_has_edge"):
                    _mvfb_edge += 1
                # Re-derive truth contract fields so has_valid_mv / has_positive_edge /
                # has_valid_target_bid / is_actionable_bid reflect the fallback MV.
                _stamp_ending_soon_truth_contract(_d)
                # Log per-item estimate
                _cp_log = float(_d.get("current_price") or _d.get("current_bid") or 0.0)
                print(
                    f"[MV_ESTIMATE] item={str(_d.get('item_id') or _d.get('listing_id') or '')[:16]} "
                    f"price={_cp_log:.2f} mv={float(_d.get('mv_value') or 0):.2f} "
                    f"max_bid={float(_d.get('max_bid') or 0):.2f} "
                    f"confidence={_d.get('valuation_confidence_label')} "
                    f"demand={_d.get('fallback_mv_demand')} "
                    f"tier={_d.get('fallback_mv_product_tier')} "
                    f"edge={_d.get('fallback_mv_has_edge')}"
                )
    print(f"[MV_FALLBACK] input={_mvfb_input} fallback_used={_mvfb_used} edge_positive={_mvfb_edge}")

    for _d in filtered_auctions:
        try:
            _premium_mv = float(_d.get("market_value") or _d.get("mv_value") or 0.0)
        except (TypeError, ValueError):
            _premium_mv = 0.0
        try:
            _premium_price = float(_d.get("current_price") or _d.get("current_bid") or 0.0)
        except (TypeError, ValueError):
            _premium_price = 0.0
        try:
            _premium_edge = float(_d.get("edge_pct") or _d.get("edge_percent") or 0.0)
        except (TypeError, ValueError):
            _premium_edge = 0.0
        if _row_exact_surface_candidate(_d) and _premium_mv > 0 and _premium_price > 0 and _premium_edge >= 8.0:
            _d["premium_board_eligible"] = True
            _d["display_bucket"] = "premium"
            _d["review_only"] = False
            _d["premium_review_status"] = "resolved"
            if str(_d.get("rescue_trust_tier") or "none").strip().lower() == "review_only":
                _d["rescue_trust_tier"] = "none"
                _d["rescue_reason"] = "exact_fallback_override"
                _d["is_rescue_row"] = False

    _rt_none = sum(1 for _d in filtered_auctions if str(_d.get("rescue_trust_tier") or "none") == "none")
    _rt_review = sum(1 for _d in filtered_auctions if str(_d.get("rescue_trust_tier") or "none") == "review_only")
    _rt_reject = sum(1 for _d in filtered_auctions if str(_d.get("rescue_trust_tier") or "none") == "reject")
    _rt_reasons: Dict[str, int] = {}
    for _d in filtered_auctions:
        _rr = str(_d.get("rescue_reason") or "")
        _rt_reasons[_rr] = _rt_reasons.get(_rr, 0) + 1
    print(f"[ES][RESCUE_TRUST] none={_rt_none} review_only={_rt_review} reject={_rt_reject} reasons={_rt_reasons}")
    _ag_blocked = sum(1 for _d in filtered_auctions if bool(_d.get("_rescue_blocked_action")))
    _ag_allowed = sum(1 for _d in filtered_auctions if bool(_d.get("is_actionable_bid")))
    print(f"[ES][ACTION_GUARD] blocked_by_rescue={_ag_blocked} allowed_clean={_ag_allowed}")
    _pb_premium = sum(1 for _d in filtered_auctions if str(_d.get("display_bucket") or "") == "premium")
    _pb_review = sum(1 for _d in filtered_auctions if str(_d.get("display_bucket") or "") == "review")
    _pb_reject = sum(1 for _d in filtered_auctions if str(_d.get("display_bucket") or "") == "reject")
    print(f"[ES][PREMIUM_BOARD] premium={_pb_premium} review={_pb_review} reject={_pb_reject}")
    print(
        f"[ES][DECISION_TRUTH] "
        f"review_only={sum(1 for d in filtered_auctions if d.get('is_review_candidate') and not d.get('is_actionable_bid'))} "
        f"actionable={sum(1 for d in filtered_auctions if d.get('is_actionable_bid'))} "
        f"no_edge={sum(1 for d in filtered_auctions if not d.get('has_positive_edge'))} "
        f"invalid_target_bid={sum(1 for d in filtered_auctions if not d.get('has_valid_target_bid'))}"
    )
    _promoted_final_count = sum(
        1
        for d in filtered_auctions
        if bool(d.get("promoted_live_candidate"))
        or bool(d.get("mv_resolved"))
        or bool(d.get("target_bid_ready"))
        or str(d.get("premium_review_status") or "").strip().lower() in {"resolved", "partial"}
    )
    _raw_final_count = sum(1 for d in filtered_auctions if bool(d.get("forced_surface")))
    _using_promoted_board = bool(_promoted_final_count > 0)

    # ── Auction quality gate ───────────────────────────────────────────────────
    # Stamp auction_quality_score on every row, then filter weak rows.
    for _d in filtered_auctions:
        _d["auction_quality_score"] = _auction_quality_score(_d)

    _pre_gate = len(filtered_auctions)
    _quality_reject_reasons: Dict[str, int] = {}
    _strong_row_count = sum(1 for _d in filtered_auctions if float(_d.get("auction_quality_score") or 0.0) >= 55.0)
    _inventory_thin = _strong_row_count < _QUALITY_ROWS_THRESHOLD
    _actionable_min = _QUALITY_ACTIONABLE_MIN if not _inventory_thin else _QUALITY_THIN_FLOOR
    _review_min     = _QUALITY_REVIEW_MIN     if not _inventory_thin else _QUALITY_THIN_FLOOR

    _quality_kept: List[Dict[str, Any]] = []
    for _d in filtered_auctions:
        _qs  = float(_d.get("auction_quality_score") or 0.0)
        _act = bool(_d.get("is_actionable_bid"))
        _rev = bool(_d.get("is_review_candidate"))
        # Hard floor — reject obvious junk regardless of inventory state
        if _qs < _QUALITY_HARD_MIN:
            _quality_reject_reasons["below_hard_min"] = _quality_reject_reasons.get("below_hard_min", 0) + 1
            continue
        # Actionable rows need higher quality bar (bad identity = dangerous bid)
        if _act and _qs < _actionable_min:
            _quality_reject_reasons["actionable_below_min"] = _quality_reject_reasons.get("actionable_below_min", 0) + 1
            continue
        # Review-only rows need minimum quality bar
        if not _act and _qs < _review_min:
            _quality_reject_reasons["review_below_min"] = _quality_reject_reasons.get("review_below_min", 0) + 1
            continue
        _quality_kept.append(_d)

    # If gate wiped all rows, restore best-quality rows (never leave board empty)
    if not _quality_kept and filtered_auctions:
        _quality_kept = sorted(filtered_auctions, key=lambda x: -float(x.get("auction_quality_score") or 0.0))[:3]
        _quality_reject_reasons["restored_top3_empty_guard"] = len(_quality_kept)

    filtered_auctions = _quality_kept
    _post_gate = len(filtered_auctions)
    _total_rejected = _pre_gate - _post_gate

    print(
        f"[ES][QUALITY_GATE] input={_pre_gate} kept={_post_gate} rejected={_total_rejected} "
        f"thin_inventory={int(_inventory_thin)} reasons={_quality_reject_reasons}"
    )

    # [DISPLAY_PRICE_FLOOR] — eBay starting-bid auctions can list at $0.99 and
    # the search-time MIN_PRICE filter (set on listing price) doesn't always
    # catch them when current_price is below the floor. A $200/mo sniping
    # platform shouldn't surface $0.99/$1.50/$3.00 cards regardless of how
    # well they fit a tracked target. Cards that rise above the floor through
    # bidding are fine — but until they do, they don't deserve a board slot.
    # Vintage/Tier 0 rows are exempt (sometimes a 1986 Fleer Jordan junk-wax
    # base does sit at $4 and that's a legitimate find).
    _DISPLAY_PRICE_FLOOR = 10.0
    _floor_kept: List[Dict[str, Any]] = []
    _floor_rejected_low_price = 0
    for _r_floor_chk in filtered_auctions:
        try:
            _cp_chk = float((_r_floor_chk or {}).get("current_price") or 0.0)
        except Exception:
            _cp_chk = 0.0
        # Tier 0 / Vintage exemption — preserved to allow legitimate vintage finds
        _tier_label_chk = str((_r_floor_chk or {}).get("tier_label") or "").strip().upper()
        _is_vintage_exempt = _tier_label_chk == "0"
        if _cp_chk > 0 and _cp_chk < _DISPLAY_PRICE_FLOOR and not _is_vintage_exempt:
            _floor_rejected_low_price += 1
            continue
        _floor_kept.append(_r_floor_chk)
    if _floor_rejected_low_price > 0:
        try:
            print(
                f"[DISPLAY_PRICE_FLOOR] floor=${_DISPLAY_PRICE_FLOOR:.2f} "
                f"pre={len(filtered_auctions)} post={len(_floor_kept)} "
                f"rejected_below_floor={_floor_rejected_low_price}"
            )
        except Exception:
            pass
    filtered_auctions = _floor_kept

    # [SYNTHETIC_MV_BLOCK] — drop rows whose MV is synthetic / fallback /
    # unconfirmed. Without a real MV, "PASS — overpriced" is a half-truth: the
    # target was derived from a price anchor or single weak comp, not from
    # priced evidence. Show the user only rows we can stand behind.
    # Markers checked:
    #   _synthetic_no_mv              — set by SYNTHETIC_MV_SCRUB
    #   _synthetic_trusted_exact      — set when trusted_exact_comp_count was
    #                                   1 but the single comp echoed current
    #   mv_valid is False             — engine-side "no MV" flag
    # Rows that survive must have either a trusted MV or at least one real
    # exact/support comp count > 0 (so the COMPS box can show a real number).
    _synth_kept: List[Dict[str, Any]] = []
    _synth_rejected = 0
    _synth_reasons: Dict[str, int] = {}
    for _r_synth in filtered_auctions:
        _is_synth = bool(
            (_r_synth or {}).get("_synthetic_no_mv")
            or (_r_synth or {}).get("_synthetic_trusted_exact")
        )
        _mv_valid = (_r_synth or {}).get("mv_valid")
        # Treat explicit False as a hard signal; treat None / missing as neutral
        _mv_invalid = (_mv_valid is False)
        try:
            _trusted_exact_n = int(float((_r_synth or {}).get("trusted_exact_comp_count") or 0))
        except Exception:
            _trusted_exact_n = 0
        try:
            _support_n = int(float((_r_synth or {}).get("support_comp_count") or 0))
        except Exception:
            _support_n = 0
        try:
            _mv_comp_n = int(float((_r_synth or {}).get("mv_comp_count") or 0))
        except Exception:
            _mv_comp_n = 0
        _has_real_comp = (_trusted_exact_n + _support_n + _mv_comp_n) > 0
        # [SYNTHETIC_MV_BLOCK_TIGHTENING] — Apr 2026: original "synthetic AND
        # no real comp" was leaking rows like "Bo Nix Pink Wave $60" that had
        # _synthetic_no_mv=True AND mv_comp_count=1 (the single junk comp that
        # triggered the scrub in the first place). The synthetic_no_mv flag
        # is the engine's authoritative "this MV is fake" signal; if it's set,
        # the row should be rejected regardless of any comp-count residue.
        # Equivalent for _synthetic_trusted_exact (trusted_exact=1 but single
        # comp echoed current price).
        if _is_synth:
            _synth_rejected += 1
            _synth_reasons["synthetic_marker"] = _synth_reasons.get("synthetic_marker", 0) + 1
            continue
        # [HAS_TARGET_NO_MV_BLOCK] — Apr 2026: rows with target_bid > 0 but
        # no real MV anywhere on the row are upstream-provisional
        # frankenrows (target was computed when MV briefly existed; MV got
        # cleared but target survived). Visible symptom: "(no MV)" badge.
        # User screenshots showed 5 such rows ($102.50 PCA /25, $25 Skenes
        # Blue /199, $20.70 Holliday Gold /50, $305 Skenes TC Black Auto,
        # etc.) all rendering as PASS — OVERPRICED with REFERENCE VALUE,
        # MAX BID, and COMPS columns all blank. They're not synthetic in
        # the sense SYNTHETIC_MV_SCRUB defines, but they ARE definitionally
        # untrustworthy: an alleged "target" without a market value to back
        # it up is just noise. Reject them.
        try:
            _row_mv = float(
                (_r_synth or {}).get("market_value")
                or (_r_synth or {}).get("true_market_value")
                or (_r_synth or {}).get("mv_value")
                or (_r_synth or {}).get("true_mv")
                or 0.0
            )
        except Exception:
            _row_mv = 0.0
        try:
            _row_target = float(
                (_r_synth or {}).get("target_bid_price")
                or (_r_synth or {}).get("target_bid")
                or (_r_synth or {}).get("bid_ceiling_value")
                or 0.0
            )
        except Exception:
            _row_target = 0.0
        if _row_target > 0 and _row_mv <= 0:
            _synth_rejected += 1
            _synth_reasons["target_without_mv"] = _synth_reasons.get("target_without_mv", 0) + 1
            continue
        # A row is rejected if mv_valid was explicitly stamped False AND no
        # real comps exist (less strict than synthetic flag — engine just
        # didn't confirm MV but didn't flag it as fake either).
        if (_is_synth or _mv_invalid) and not _has_real_comp:
            _synth_rejected += 1
            if _is_synth and not _mv_invalid:
                _synth_reasons["synthetic_marker_no_comps"] = _synth_reasons.get("synthetic_marker_no_comps", 0) + 1
            elif _mv_invalid and not _is_synth:
                _synth_reasons["mv_invalid_no_comps"] = _synth_reasons.get("mv_invalid_no_comps", 0) + 1
            else:
                _synth_reasons["synthetic_and_invalid_no_comps"] = _synth_reasons.get("synthetic_and_invalid_no_comps", 0) + 1
            continue
        _synth_kept.append(_r_synth)
    if _synth_rejected > 0:
        try:
            print(
                f"[SYNTHETIC_MV_BLOCK] pre={len(filtered_auctions)} post={len(_synth_kept)} "
                f"rejected={_synth_rejected} reasons={_synth_reasons}"
            )
        except Exception:
            pass
    # Safety: if the synth block wiped everything, keep the top 3 by quality
    # score so the board doesn't go fully blank — flagged so downstream code
    # knows these survived only via the empty-board guard.
    if not _synth_kept and filtered_auctions:
        _synth_kept = sorted(
            list(filtered_auctions),
            key=lambda _x: -float(_x.get("auction_quality_score") or 0.0),
        )[:3]
        for _r_g in _synth_kept:
            if isinstance(_r_g, dict):
                _r_g["_synth_block_empty_guard"] = True
        try:
            print(
                f"[SYNTHETIC_MV_BLOCK] empty_board_guard_restored={len(_synth_kept)}"
            )
        except Exception:
            pass
    filtered_auctions = _synth_kept
    _top_quality_samples = sorted(
        [
            (
                str(_d.get("source_item_id") or _d.get("item_id") or "?")[:12],
                round(float(_d.get("auction_quality_score") or 0.0), 1),
                "A" if bool(_d.get("is_actionable_bid")) else "R",
                round(float(_d.get("edge_pct") or 0.0), 1),
                str(_d.get("mv_confidence") or "?"),
            )
            for _d in filtered_auctions
        ],
        key=lambda x: -x[1],
    )[:5]
    print(f"[ES][QUALITY_SCORE] top={_top_quality_samples}")
    _avg_qs = (
        sum(float(_d.get("auction_quality_score") or 0.0) for _d in filtered_auctions) / len(filtered_auctions)
        if filtered_auctions else 0.0
    )
    _top_qs = max((float(_d.get("auction_quality_score") or 0.0) for _d in filtered_auctions), default=0.0)
    print(
        f"[ES][BOARD_QUALITY] actionable={sum(1 for _d in filtered_auctions if _d.get('is_actionable_bid'))} "
        f"review={sum(1 for _d in filtered_auctions if _d.get('is_review_candidate') and not _d.get('is_actionable_bid'))} "
        f"avg_score={round(_avg_qs, 1)} top_score={round(_top_qs, 1)}"
    )

    # ── Desirability gate: stamp + filter graded/low-desirability/forced-review junk ──
    for _d in filtered_auctions:
        _stamp_desirability_contract(_d)

    _desirability_reject_reasons: Dict[str, int] = {}
    _desirability_kept: List[Dict[str, Any]] = []
    for _d in filtered_auctions:
        _fit      = str(_d.get("target_fit_tier") or "forced_review")
        _is_graded = bool(_d.get("is_graded_card"))
        _is_low_fmt = bool(_d.get("is_low_desirability_format"))
        _ds       = float(_d.get("desirability_score") or 0.0)
        _act      = bool(_d.get("is_actionable_bid"))
        _qs_d     = float(_d.get("auction_quality_score") or 0.0)

        # Hard reject: non-single-card formats (lots, breaks, reprints, digital)
        if _is_low_fmt:
            _desirability_reject_reasons["low_desirability_format"] = _desirability_reject_reasons.get("low_desirability_format", 0) + 1
            continue

        # Graded/slabbed cards: only survive if exact/strong_family + actionable + high quality
        if _is_graded:
            if _fit not in {"exact", "strong_family"} or not _act or _qs_d < 55:
                _desirability_reject_reasons["graded_weak_fit"] = _desirability_reject_reasons.get("graded_weak_fit", 0) + 1
                continue

        # forced_review: only survive if desirability score clears a strict floor
        if _fit == "forced_review" and _ds < 35.0:
            _desirability_reject_reasons["forced_review_weak"] = _desirability_reject_reasons.get("forced_review_weak", 0) + 1
            continue

        # weak_family: only survive if economics are compelling or card number is present
        if _fit == "weak_family":
            _edge_pct_d = float(_d.get("edge_pct") or 0.0)
            _has_cn = bool(re.search(r"#\s*\d+", str(_d.get("source_title") or _d.get("title") or "").lower()))
            if not _act and _edge_pct_d < 5.0 and not _has_cn:
                _desirability_reject_reasons["weak_family_sloppy"] = _desirability_reject_reasons.get("weak_family_sloppy", 0) + 1
                continue

        _desirability_kept.append(_d)

    # Safety valve: never wipe the board entirely
    if not _desirability_kept and filtered_auctions:
        _desirability_kept = sorted(filtered_auctions, key=lambda x: -float(x.get("desirability_score") or 0.0))[:3]
        _desirability_reject_reasons["restored_top3_desirability_guard"] = len(_desirability_kept)

    # [SAME_CARD_DEDUP] — collapse multiple listings of the SAME CARD to a single
    # representative. Two auctions of "Caleb Williams 2025 Mosaic #253 Orange
    # Prizm /199" are the same card — they should produce ONE board row, not two.
    # The card identity is (player + product_family + parallel_family + serial
    # denominator + card_number). When duplicates exist we keep the one with
    # the lowest current_price (best snipe) and drop the rest. Runs BEFORE the
    # PER_PLAYER_DISPLAY_CAP so the cap budget is spent on different cards, not
    # different listings of the same card.
    def _same_card_key(_r_dc: Dict[str, Any]) -> str:
        _ck_player = str(
            (_r_dc or {}).get("player_name")
            or (_r_dc or {}).get("canonical_player")
            or (_r_dc or {}).get("normalized_entity")
            or (_r_dc or {}).get("_target_player")
            or ""
        ).strip().lower()
        _ck_product = str(
            (_r_dc or {}).get("product_family")
            or (_r_dc or {}).get("target_product_family")
            or (_r_dc or {}).get("lane_product")
            or ""
        ).strip().lower()
        _ck_parallel = str(
            (_r_dc or {}).get("parallel_family")
            or (_r_dc or {}).get("_hydrated_parallel_family")
            or ""
        ).strip().lower()
        _ck_serial_raw = str(
            (_r_dc or {}).get("serial")
            or (_r_dc or {}).get("serial_denominator")
            or ""
        ).strip()
        # Normalize serial to denominator only (strip "X/Y" → "Y")
        _ck_serial = _ck_serial_raw
        if "/" in _ck_serial_raw:
            try:
                _ck_serial = _ck_serial_raw.split("/")[-1].strip()
            except Exception:
                _ck_serial = _ck_serial_raw
        _ck_cardno = str(
            (_r_dc or {}).get("identity_card_number")
            or (_r_dc or {}).get("fingerprint_card_number")
            or (_r_dc or {}).get("card_number")
            or (_r_dc or {}).get("target_card_number")
            or ""
        ).strip().lower()
        # Need at minimum player + product to dedup. Without that we can't
        # confidently say two rows are the same card, so we treat them as
        # unique (use listing id as tiebreaker so they don't collide).
        if not (_ck_player and _ck_product):
            _ck_listing_id = str(
                (_r_dc or {}).get("listing_id")
                or (_r_dc or {}).get("auction_id")
                or (_r_dc or {}).get("item_id")
                or id(_r_dc)
            )
            return f"__unique__|{_ck_listing_id}"
        return f"{_ck_player}|{_ck_product}|{_ck_parallel}|{_ck_serial}|{_ck_cardno}"

    def _same_card_price(_r_dc: Dict[str, Any]) -> float:
        try:
            _p = (_r_dc or {}).get("current_price")
            if _p is None:
                _p = (_r_dc or {}).get("price")
            return float(_p) if _p is not None else 999999.0
        except Exception:
            return 999999.0

    _same_card_groups: Dict[str, List[Dict[str, Any]]] = {}
    for _r_card in list(_desirability_kept or []):
        _ck = _same_card_key(_r_card)
        _same_card_groups.setdefault(_ck, []).append(_r_card)

    _same_card_deduped: List[Dict[str, Any]] = []
    _same_card_suppressed_count = 0
    _same_card_collapsed_keys: List[str] = []
    for _ck, _grp in _same_card_groups.items():
        if len(_grp) <= 1 or _ck.startswith("__unique__|"):
            _same_card_deduped.extend(_grp)
            continue
        # Pick cheapest current_price as the representative (best snipe)
        _grp_sorted = sorted(_grp, key=_same_card_price)
        _winner = _grp_sorted[0]
        _winner["_same_card_dup_count"] = len(_grp)
        _same_card_deduped.append(_winner)
        _same_card_suppressed_count += (len(_grp) - 1)
        _same_card_collapsed_keys.append(f"{_ck}(x{len(_grp)})")

    if _same_card_suppressed_count > 0:
        try:
            print(
                f"[SAME_CARD_DEDUP] pre={len(_desirability_kept)} "
                f"post={len(_same_card_deduped)} "
                f"suppressed={_same_card_suppressed_count} "
                f"collapsed={_same_card_collapsed_keys[:5]}"
            )
        except Exception:
            pass
    _desirability_kept = _same_card_deduped

    # [PER_PLAYER_DISPLAY_CAP] — force diversity at the display layer. Cap to
    # max N rows per player so a single player's lane (James Wood, Anthony
    # Richardson, etc.) can't monopolize the board even when their inventory
    # is rich. Rows above the cap are bumped to an overflow pool, which the
    # subsequent DISPLAY_FLOOR step can pull from EXCLUDING already-capped-
    # out players. Net effect: user sees at most 2 of any one player, and
    # remaining slots fill with other players' rows from the broader
    # filtered_auctions pool.
    _PER_PLAYER_DISPLAY_CAP = 2
    _capped_kept: List[Dict[str, Any]] = []
    _overflow_kept: List[Dict[str, Any]] = []
    _player_count: Dict[str, int] = {}
    for _r_pcap in list(_desirability_kept or []):
        _p_key = str(
            (_r_pcap or {}).get("player_name")
            or (_r_pcap or {}).get("canonical_player")
            or (_r_pcap or {}).get("normalized_entity")
            or (_r_pcap or {}).get("_target_player")
            or ""
        ).strip().lower()
        if not _p_key:
            _capped_kept.append(_r_pcap)
            continue
        _cnt = _player_count.get(_p_key, 0)
        if _cnt < _PER_PLAYER_DISPLAY_CAP:
            _capped_kept.append(_r_pcap)
            _player_count[_p_key] = _cnt + 1
        else:
            _overflow_kept.append(_r_pcap)
    if _overflow_kept:
        try:
            print(
                f"[PER_PLAYER_DISPLAY_CAP] cap={_PER_PLAYER_DISPLAY_CAP} "
                f"pre_cap={len(_desirability_kept)} post_cap={len(_capped_kept)} "
                f"overflowed={len(_overflow_kept)} "
                f"player_counts={dict(_player_count)}"
            )
        except Exception:
            pass
    _capped_overflow_player_keys = {
        str(
            (_r_o or {}).get("player_name")
            or (_r_o or {}).get("canonical_player")
            or ""
        ).strip().lower()
        for _r_o in _overflow_kept
        if (_r_o or {}).get("player_name") or (_r_o or {}).get("canonical_player")
    }
    _desirability_kept = _capped_kept

    # [DISPLAY_FLOOR] — when inventory passed all earlier engine filters but
    # the desirability gate culled most rows down to <5, restore the highest-
    # desirability rejected rows to give the user something to look at.
    # These rows have already passed: graded gate, fringe brand gate, oversized
    # gate, raw_title brand guard, premium shape gate, exact/support comp lane
    # checks. Desirability is the LAST gate, and it's the most subjective. The
    # restored rows are marked `_display_floor_restored=True` so downstream UI
    # / audit code can flag them as "filled to floor" rather than primary
    # action_ready inventory. The trust contract stays intact — the rows are
    # still labeled honestly (PASS / WATCH / REVIEW per their actual state),
    # the user just gets MORE evaluable options when inventory is thin.
    # NOW also excludes players who were just per-player-capped, so the floor
    # restores OTHER players' rows rather than reintroducing the same player.
    _DISPLAY_FLOOR_TARGET = 5
    _floor_input_count = len(filtered_auctions)
    if len(_desirability_kept) < _DISPLAY_FLOOR_TARGET and filtered_auctions:
        _existing_ids = set(id(_r) for _r in _desirability_kept)
        # [SAME_CARD_DEDUP_FLOOR_GUARD] — already-surfaced card identities. The
        # floor restorer must not bring back a different listing of a card we
        # already have on the board (the very dup the dedup step just killed).
        _existing_card_keys = set()
        for _r_existing in _desirability_kept:
            try:
                _existing_card_keys.add(_same_card_key(_r_existing))
            except Exception:
                pass
        _gap = _DISPLAY_FLOOR_TARGET - len(_desirability_kept)
        _restore_pool = []
        _floor_skipped_same_card = 0
        for _r_pool in filtered_auctions:
            if id(_r_pool) in _existing_ids:
                continue
            _r_pool_player = str(
                (_r_pool or {}).get("player_name")
                or (_r_pool or {}).get("canonical_player")
                or ""
            ).strip().lower()
            if _r_pool_player and _r_pool_player in _capped_overflow_player_keys:
                # Already at cap for this player — skip; we want diversity.
                continue
            # Don't restore another listing of an already-surfaced card.
            try:
                _pool_card_key = _same_card_key(_r_pool)
            except Exception:
                _pool_card_key = None
            if _pool_card_key and not _pool_card_key.startswith("__unique__|") and _pool_card_key in _existing_card_keys:
                _floor_skipped_same_card += 1
                continue
            _restore_pool.append(_r_pool)
        _restore_pool.sort(key=lambda _x: -float(_x.get("desirability_score") or 0.0))
        # Dedup WITHIN the restore_pool too — the same-card key must not admit
        # two listings of the same card from the pool itself. Highest
        # desirability already wins by virtue of pre-sort; among ties at
        # equal desirability, prefer the cheapest current_price.
        _restore_seen_card_keys = set()
        _restore_pool_deduped: List[Dict[str, Any]] = []
        for _r_rp in _restore_pool:
            try:
                _rp_key = _same_card_key(_r_rp)
            except Exception:
                _rp_key = None
            if _rp_key and not _rp_key.startswith("__unique__|"):
                if _rp_key in _restore_seen_card_keys:
                    _floor_skipped_same_card += 1
                    continue
                _restore_seen_card_keys.add(_rp_key)
            _restore_pool_deduped.append(_r_rp)
        _restored = _restore_pool_deduped[:_gap]
        if _restored:
            for _r_floor in _restored:
                _r_floor["_display_floor_restored"] = True
                _r_floor["_display_floor_reason"] = "below_target_count_per_player_diversity"
            _desirability_kept = list(_desirability_kept) + list(_restored)
            _desirability_reject_reasons["display_floor_restored"] = len(_restored)
            try:
                print(
                    f"[DISPLAY_FLOOR] restored={len(_restored)} "
                    f"target={_DISPLAY_FLOOR_TARGET} "
                    f"pre_restore={len(_desirability_kept) - len(_restored)} "
                    f"post_restore={len(_desirability_kept)} "
                    f"diversity_cap_excluded={len(_capped_overflow_player_keys)} "
                    f"same_card_skipped={_floor_skipped_same_card}"
                )
            except Exception:
                pass

    _desirability_input = len(filtered_auctions)
    filtered_auctions = _desirability_kept
    _desirability_kept_n = len(filtered_auctions)
    print(
        f"[ES][DESIRABILITY] input={_desirability_input} kept={_desirability_kept_n} "
        f"rejected={_desirability_input - _desirability_kept_n} reasons={_desirability_reject_reasons}"
    )
    _tf_counts: Dict[str, int] = {}
    for _d in filtered_auctions:
        _tf = str(_d.get("target_fit_tier") or "forced_review")
        _tf_counts[_tf] = _tf_counts.get(_tf, 0) + 1
    print(
        f"[ES][TARGET_FIT] exact={_tf_counts.get('exact', 0)} "
        f"strong_family={_tf_counts.get('strong_family', 0)} "
        f"weak_family={_tf_counts.get('weak_family', 0)} "
        f"forced_review={_tf_counts.get('forced_review', 0)}"
    )
    # [ES][PREMIUM_RECOVERY] — breakdown by target_validation_outcome on board rows
    _tvo_counts: Dict[str, int] = {}
    for _d in filtered_auctions:
        _tvo = str(_d.get("target_validation_outcome") or "unknown")
        _tvo_counts[_tvo] = _tvo_counts.get(_tvo, 0) + 1
    _pr_premium = sum(1 for _d in filtered_auctions if str(_d.get("display_bucket") or "") == "premium")
    _pr_review = sum(1 for _d in filtered_auctions if str(_d.get("display_bucket") or "") == "review")
    _pr_reject = sum(1 for _d in filtered_auctions if str(_d.get("display_bucket") or "") == "reject")
    print(
        f"[ES][PREMIUM_RECOVERY] premium_eligible={_pr_premium} review_only={_pr_review} reject={_pr_reject} "
        f"outcomes={_tvo_counts}"
    )
    _raw_kept_n   = sum(1 for _d in filtered_auctions if bool(_d.get("is_raw_preferred")))
    _graded_kept_n = sum(1 for _d in filtered_auctions if bool(_d.get("is_graded_card")))
    _graded_rej_n  = sum(_desirability_reject_reasons.get(k, 0) for k in _desirability_reject_reasons if "graded" in k)
    print(f"[ES][RAW_PREF] raw_kept={_raw_kept_n} graded_kept={_graded_kept_n} graded_rejected={_graded_rej_n}")
    for _d in filtered_auctions:
        _stamp_commercial_profile(_d)
        _stamp_endgame_tier(_d)

    _premium_action_rescued_bids = 0
    _premium_action_surface_allowed = 0
    _premium_action_watchlist_promoted = 0
    _premium_action_sniper_promoted = 0
    _premium_action_pass_blocked = 0
    _exact_comp_value_rescued_rows = 0
    _exact_comp_value_surface_allowed = 0
    _exact_comp_value_watchlist_promoted = 0
    _exact_comp_value_sniper_promoted = 0
    _exact_comp_value_pass_remaining = 0
    for _d in filtered_auctions:
        _had_exact_value_rescue = bool(_d.get("_exact_comp_value_rescue"))
        _exact_comp_value_rescue(_d)
        if bool(_d.get("_exact_comp_value_rescue")) and not _had_exact_value_rescue:
            _exact_comp_value_rescued_rows += 1
            _finalize_missing_target_bid_for_survivor(_d)
            print(
                f"[EXACT_COMP_VALUE_ASSERT] "
                f"title={str(_d.get('title') or _d.get('source_title') or '')[:160]} "
                f"true_mv={_d.get('true_mv') or _d.get('true_market_value')} "
                f"review_estimate={_d.get('review_estimate') or _d.get('review_estimate_value')} "
                f"reference_value={_d.get('reference_value')} "
                f"target_bid={_d.get('target_bid')} "
                f"display_mode={_d.get('display_mode')} "
                f"rescue_reason={_d.get('_exact_comp_value_rescue_reason')}"
            )
        _had_premium_action_bid = bool(_d.get("_premium_actionability_bid_rescue"))
        _premium_actionability_bid_rescue(_d)
        if bool(_d.get("_premium_actionability_bid_rescue")) and not _had_premium_action_bid:
            _premium_action_rescued_bids += 1

    # ── VALUATION-DRIVEN COMMERCIAL OVERRIDE ─────────────────────────────────
    # SYSTEM LAW: Valuation truth is the highest authority.
    # If comp engine proves a card is genuinely valuable (TRUE tier, MV >= $50,
    # comp_count >= 2, target_bid > 0), no classification layer is allowed to
    # downgrade it to WEAK / commodity-suppressed.
    # This runs AFTER _stamp_commercial_profile so it can read the original bucket
    # (for logging) and BEFORE _compute_execution_decision and
    # _compute_sniper_board_profile so both functions see the corrected values.
    for _d in filtered_auctions:
        _vo_truth = str(_d.get("valuation_truth_tier") or "").strip().upper()
        _vo_mv = _safe_float(_d.get("true_market_value") or _d.get("market_value_true"))
        _vo_bid = _safe_float(_d.get("target_bid"))
        _vo_comps = int(_d.get("comp_count") or _d.get("usable_comp_count") or 0)
        _is_high_value_truth = bool(
            _vo_truth == "TRUE"
            and _vo_mv is not None and _vo_mv >= 50.0
            and _vo_comps >= 2
            and _vo_bid is not None and _vo_bid > 0
        )
        if not _is_high_value_truth:
            continue
        _vo_old_bucket = str(_d.get("commercial_bucket") or "WEAK").strip().upper()
        _vo_was_suppressed = bool(_d.get("commercially_suppressed")) or bool(_d.get("commodity_suppressed"))
        # Upgrade to STRONG if currently below — never downgrade from ELITE
        if _vo_old_bucket not in {"ELITE", "STRONG"}:
            _d["commercial_bucket"] = "STRONG"
        # Clear suppression flags that were based on classification, not valuation
        _d["commercially_suppressed"] = False
        _d["commodity_suppressed"] = False
        _d["commodity_quality_floor_met"] = True
        _d["_valuation_override"] = True
        print(
            f"[VALUATION_OVERRIDE] title={str(_d.get('title') or '')[:100]} "
            f"true_mv={_vo_mv:.2f} comps={_vo_comps} target_bid={_vo_bid:.2f} "
            f"old_bucket={_vo_old_bucket} was_suppressed={int(_vo_was_suppressed)} "
            f"override_applied=1"
        )

    _commercial_counts = {"ELITE": 0, "STRONG": 0, "MID": 0, "WEAK": 0}
    _commercial_suppressed = 0
    for _d in filtered_auctions:
        _bucket = str(_d.get("commercial_bucket") or "WEAK").strip().upper()
        _commercial_counts[_bucket] = _commercial_counts.get(_bucket, 0) + 1
        if bool(_d.get("commercially_suppressed")):
            _commercial_suppressed += 1
    _commercial_sample_rows = [
        (
            str(_d.get("item_id") or _d.get("source_item_id") or "")[:16],
            _d.get("commercial_score"),
            _d.get("commercial_bucket"),
            _d.get("commercial_reasons"),
        )
        for _d in filtered_auctions[:8]
    ]
    print(
        f"[COMMERCIAL_GATE] total={len(filtered_auctions)} elite={_commercial_counts.get('ELITE', 0)} "
        f"strong={_commercial_counts.get('STRONG', 0)} mid={_commercial_counts.get('MID', 0)} "
        f"weak={_commercial_counts.get('WEAK', 0)} suppressed={_commercial_suppressed}"
    )
    print(f"[COMMERCIAL_SAMPLE] {_commercial_sample_rows}")
    # ── Visible quality breakdown by premium lane tier ─────────────────────────
    _vq_counts = {"elite": 0, "strong": 0, "speculative": 0, "commodity": 0, "unknown": 0}
    _vq_suppressed = 0
    _vq_commodity_floor = 0
    for _d in filtered_auctions:
        _lt = str(_d.get("lane_tier") or "unknown").strip().lower()
        _vq_counts[_lt] = _vq_counts.get(_lt, 0) + 1
        if bool(_d.get("commercially_suppressed")):
            _vq_suppressed += 1
        if bool(_d.get("commodity_quality_floor_met")):
            _vq_commodity_floor += 1
    print(
        "[VISIBLE_QUALITY] elite={} strong={} speculative={} commodity={} unknown={} "
        "suppressed={} commodity_floor_exception={}".format(
            _vq_counts.get("elite", 0), _vq_counts.get("strong", 0),
            _vq_counts.get("speculative", 0), _vq_counts.get("commodity", 0),
            _vq_counts.get("unknown", 0), _vq_suppressed, _vq_commodity_floor
        )
    )

    # ── Execution decision: stamp on every board row ───────────────────────────
    for _d in filtered_auctions:
        # Stamp heat score first — used inside execution decision upgrade gate below
        _d["whatnot_heat_score"] = _whatnot_heat_score(_d)
        _exec = _compute_execution_decision(_d)
        _d["execution_decision"] = _exec["execution_decision"]
        _d["decision"] = _exec.get("decision", _d["execution_decision"])
        _d["decision_reason"] = _exec.get("decision_reason", "")
        _d["execution_score"] = _exec["execution_score"]
        _d["execution_pressure"] = _exec["execution_pressure"]
        _d["sniper_candidate"] = bool(_exec.get("sniper_candidate"))
        _d["endgame_sniper_admission"] = str(_exec.get("endgame_sniper_admission") or "")
        _d["endgame_bid_gap_pct"] = _exec.get("endgame_bid_gap_pct")
        _premium_action_decision_before = str(_d.get("execution_decision") or "PASS").strip().upper()
        _premium_action_allow, _premium_action_reason = _premium_actionability_surface_allow(_d)
        if _premium_action_allow and _premium_action_decision_before in {"", "PASS", "SKIP", "HIDDEN", "LOW_HEAT_HIDDEN"}:
            _d["execution_decision"] = "WATCH"
            _d["decision"] = "WATCH"
            _d["decision_reason"] = _premium_action_reason
            _d["surface_intent"] = "watchlist"
            _d["execution_admission_bucket"] = "watchlist"
            _d["commercial_visibility"] = "watchlist"
            _d["_surface_bucket"] = "watchlist"
            _d["final_visible_append_reason"] = _premium_action_reason
            _d["board_visible"] = True
            _d["commercially_visible"] = True
            _d["_premium_actionability_surface_allow"] = True
            _d["_rescued_watchlist"] = True
            _d["_soft_watchlist"] = True
            _premium_action_surface_allowed += 1
            _premium_action_watchlist_promoted += 1
        elif _premium_action_allow:
            _d["_premium_actionability_surface_allow"] = True
            _premium_action_surface_allowed += 1
            if _premium_action_decision_before in {"EXECUTE_NOW", "SNIPE", "PREPARE"}:
                _premium_action_sniper_promoted += 1
        else:
            _premium_action_pass_blocked += 1
        if _premium_action_allow or bool(_d.get("_premium_actionability_bid_rescue")):
            print(
                f"[PREMIUM_ACTION_SURFACE_ALLOW] "
                f"title={str(_d.get('title') or '')[:160]} "
                f"allow={int(bool(_premium_action_allow))} "
                f"reason={_premium_action_reason} "
                f"current_price={_d.get('current_price') or _d.get('authoritative_current_price') or _d.get('_board_current_price')} "
                f"target_bid={_d.get('target_bid')} "
                f"truth={_d.get('truth') or _d.get('valuation_truth_tier')} "
                f"trusted_exact={_d.get('trusted_exact_comp_count')} "
                f"premium_lane={_d.get('premium_lane')} "
                f"decision_before={_premium_action_decision_before} "
                f"decision_after={_d.get('execution_decision')}"
            )
        _exact_comp_surface_allow, _exact_comp_surface_reason = _exact_comp_value_surface_allow(_d)
        if _exact_comp_surface_allow and not bool(_d.get("_exact_comp_value_surface_allow")):
            _exact_decision_before = str(_d.get("execution_decision") or "PASS").strip().upper()
            _d["_exact_comp_value_surface_allow"] = True
            _d["surface_intent"] = "watchlist"
            _d["execution_admission_bucket"] = "watchlist"
            _d["commercial_visibility"] = "watchlist"
            _d["_surface_bucket"] = "watchlist"
            _d["final_visible_append_reason"] = _exact_comp_surface_reason
            _d["board_visible"] = True
            _d["commercially_visible"] = True
            if _exact_decision_before in {"", "PASS", "SKIP", "HIDDEN", "LOW_HEAT_HIDDEN"}:
                _d["execution_decision"] = "WATCH"
                _d["decision"] = "WATCH"
                _d["decision_reason"] = _exact_comp_surface_reason
                _d["_rescued_watchlist"] = True
                _d["_soft_watchlist"] = True
                _exact_comp_value_watchlist_promoted += 1
            elif _exact_decision_before in {"EXECUTE_NOW", "SNIPE", "PREPARE"}:
                _exact_comp_value_sniper_promoted += 1
            _exact_comp_value_surface_allowed += 1
        # Valuation-override rows are always sniper-eligible regardless of endgame gate
        if bool(_d.get("_valuation_override")) and not _d["sniper_candidate"]:
            _d["sniper_candidate"] = True
        # ── Controlled heat upgrade: MEDIUM-conf + exact identity + high heat ──
        # Relaxes comps requirement from 5→3 when heat score is strong enough.
        # Guards: mv_valid, no rescue rows, exact/strong match only.
        if _d["execution_decision"] in {"WATCH", "PASS"}:
            _heat_upgrade_ok = (
                bool(_d.get("mv_valid", False))
                and float(_d.get("edge_pct") or 0.0) >= 22.0
                and float(_d.get("edge_dollars") or 0.0) >= 12.0
                and str(_d.get("mv_confidence_strict") or _d.get("mv_confidence") or "").strip().upper() in {"HIGH", "MEDIUM"}
                and int(_d.get("comp_count") or _d.get("mv_comp_count") or 0) >= 3
                and _row_target_bid_ready(_d)
                and not bool(_d.get("commercially_suppressed"))
                and str(_d.get("commercial_bucket") or "WEAK").strip().upper() in {"ELITE", "STRONG"}
                and str(_d.get("entity_match_status") or "").strip().upper() in {"EXACT_MATCH", "STRONG_MATCH"}
                and str(_d.get("rescue_trust_tier") or "none").strip().lower() == "none"
                and float(_d["whatnot_heat_score"]) >= 62.0
            )
            if _heat_upgrade_ok:
                _d["execution_decision"] = "EXECUTE_NOW"
                _d["decision"] = "EXECUTE NOW"
                _d["decision_reason"] = "heat_upgrade_exact_medium_confidence"
                # Re-compute score so sort reflects the upgrade
                _d["execution_score"] = float(max(
                    _d["execution_score"],
                    float(_d.get("edge_pct") or 0.0) * 0.5
                    + min(int(_d.get("comp_count") or 0), 20) * 0.2
                    + 0.5 * 20.0  # MEDIUM weight
                    + float(_d["execution_pressure"] == "URGENT") * 20.0
                    + float(_d["execution_pressure"] == "HIGH") * 10.0,
                ))
                _d["heat_upgraded"] = True
        # ── Boost execution score by heat contribution (improves ranking) ──────
        _heat_boost = float(_d["whatnot_heat_score"]) * 0.15  # max +15
        _d["execution_score"] = float(min(100.0, _d["execution_score"] + _heat_boost))
        _d["heat_fill"] = False  # default; overridden in fill pass below
        # Action summary: pre-computed for the UI action box (no re-derivation needed at render time)
        try:
            _tb_a = float(_d.get("bid_ceiling_value") or _d.get("target_bid_price") or _d.get("target_bid") or 0.0) or None
        except (TypeError, ValueError):
            _tb_a = None
        try:
            _mv_a = float(_d.get("market_value") or _d.get("mv_value") or 0.0) or None
        except (TypeError, ValueError):
            _mv_a = None
        try:
            _price_a = float(_d.get("current_price") or _d.get("current_bid") or 0.0)
        except (TypeError, ValueError):
            _price_a = 0.0
        _edge_dollars_a = round(_mv_a - _price_a, 2) if _mv_a and _price_a > 0 else None
        _mv_conf_a = str(_d.get("mv_confidence_strict") or _d.get("mv_confidence") or "LOW").strip().upper()
        if _mv_conf_a not in {"HIGH", "MEDIUM", "LOW"}:
            _mv_conf_a = "LOW"
        _comps_a = int(_d.get("comp_count") or _d.get("mv_comp_count") or 0)
        _tb_conf_a = str(_d.get("bid_ceiling_confidence") or _d.get("target_bid_confidence") or "NONE").strip().upper()
        _tb_src_a = str(_d.get("bid_ceiling_source") or _d.get("target_bid_source_detail") or _d.get("target_bid_source") or "unavailable").strip()
        _d["action_summary"] = {
            "buy_under": round(_tb_a, 2) if _tb_a else None,
            "ideal_range": [round(_tb_a * 0.9, 2), round(_tb_a, 2)] if _tb_a else None,
            "expected_profit": _edge_dollars_a,
            "confidence": _mv_conf_a,
            "comps": _comps_a,
            "target_bid_confidence": _tb_conf_a,
            "target_bid_source_detail": _tb_src_a,
            "bid_ceiling_value": round(_tb_a, 2) if _tb_a else None,
            "bid_ceiling_confidence": _tb_conf_a,
            "bid_ceiling_source": _tb_src_a,
        }
        _hero_profile = _compute_sniper_board_profile(_d)
        _d.update(_hero_profile)
        _commercial_visibility = _compute_commercial_visibility(_d)
        _d.update(_commercial_visibility)
        _d["execution_admission_score"] = round(_final_execution_admission_score(_d), 1)
        _d["execution_admission_bucket"] = "hidden"
        _d["execution_admission_reason"] = str(_d.get("commercial_visibility_reason") or "")

    _admission_hidden_counts: Dict[str, int] = {"low_value": 0, "low_trust": 0, "weak_edge": 0, "junk": 0}
    _admission_candidates: List[Dict[str, Any]] = []
    _watch_salvage_candidates = 0
    def _direct_watchlist_rescue(row: Dict[str, Any]) -> bool:
        _title = str((row or {}).get("title") or "").lower()

        _junk_terms = [
            "lot", "bundle", "break", "case break", "team break",
            "sealed", "blaster", "mega box", "fat pack", "hobby box",
            "custom", "reprint",
        ]
        if any(_term in _title for _term in _junk_terms):
            return False

        _positive_terms = [
            "auto", "autograph", "patch", "rpa", "relic",
            "kaboom", "downtown", "color blast", "genesis", "stained glass",
            "gold", "black", "zebra", "shimmer", "vinyl",
            "prizm", "select", "optic", "spectra", "contenders",
            "national treasures", "immaculate", "flawless", "chrome", "finest",
        ]

        _hits = sum(1 for _term in _positive_terms if _term in _title)

        if (
            bool((row or {}).get("exact_entity_match"))
            or bool((row or {}).get("entity_exact_match"))
            or bool((row or {}).get("tracked_anchor"))
        ):
            _hits += 1

        try:
            _price = float((row or {}).get("current_price") or 0)
        except Exception:
            _price = 0.0

        return bool(_hits >= 1 and _price >= 5.0)

    def _has_any_valuation_anchor(row: Dict[str, Any]) -> bool:
        for _field in (
            "true_market_value",
            "market_value_true",
            "review_estimate_value",
            "anchored_estimate_value",
            "market_value_raw",
            "market_value",
            "mv_value",
            "target_bid",
            "target_bid_price",
            "bid_ceiling_value",
        ):
            _value = _safe_float((row or {}).get(_field))
            if _value is not None and _value > 0:
                return True
        return False

    def _row_passes_frozen_target_contract(row: Dict[str, Any], *, emit_log: bool = False) -> Tuple[Optional[bool], str]:
        _row = dict(row or {})
        _title = str(_row.get("title") or _row.get("source_title") or "")
        _title_lower = _title.lower()
        _contract_id = str(_row.get("_target_contract_id") or "").strip()
        _target_player = str(_row.get("_target_player") or "").strip()
        _target_sport = str(_row.get("_target_sport") or "").strip()
        _target_product = str(_row.get("_target_product_canonical") or "").strip()
        _target_subset = _normalize_subset_name(str(_row.get("_target_subset_family") or "").strip())
        _target_scope = str(_row.get("_target_match_scope") or "product_bound").strip().lower()
        _target_query = str(_row.get("_target_source_query") or "").strip()
        _route_stage = str(_row.get("route_stage") or "").strip().lower()
        _target_status = str(_row.get("target_match_status") or "").strip().lower()
        _entity_reason = str(_row.get("entity_gate_reason") or "").strip().lower()
        _reason_blob = " ".join(
            str(_row.get(_field) or "")
            for _field in (
                "target_match_reason",
                "product_match_reason",
                "reject_reason",
                "hidden_reason",
                "live_board_reject_reason",
                "execution_admission_reason",
                "entity_gate_reason",
            )
        ).lower()
        _contract_present = bool(
            _contract_id or _target_player or _target_sport or _target_product or _target_subset or _target_scope
        )
        if emit_log:
            print(
                f"[FINAL_TARGET_SCOPE] item={str(_row.get('item_id') or _row.get('source_item_id') or '')[:18] or '?'} "
                f"contract_id={_contract_id[:24] or 'none'} player={_target_player[:24] or 'none'} "
                f"sport={_target_sport or 'none'} product={_target_product[:28] or 'none'} "
                f"subset={_target_subset[:24] or 'none'} scope={_target_scope or 'none'} "
                f"query={_target_query[:48] or 'none'}"
            )
        if not _contract_present:
            if emit_log:
                print(
                    f"[FINAL_TARGET_CONTRACT_MISSING] item={str(_row.get('item_id') or _row.get('source_item_id') or '')[:18] or '?'} "
                    f"title={_title[:100]}"
                )
            return None, "missing_frozen_contract"

        _shape_reject = _hard_shape_reject_reason(_title)
        if _shape_reject:
            if emit_log:
                print(
                    f"[FINAL_TARGET_DROP] item={str(_row.get('item_id') or _row.get('source_item_id') or '')[:18] or '?'} "
                    f"reason={_shape_reject} title={_title[:100]}"
                )
            return False, _shape_reject
        _nonstandard_variant, _nonstandard_reason = _is_nonstandard_subset_variant(_title)
        if _nonstandard_variant:
            if emit_log:
                print(
                    f"[FINAL_TARGET_DROP] item={str(_row.get('item_id') or _row.get('source_item_id') or '')[:18] or '?'} "
                    f"reason={_nonstandard_reason or 'nonstandard_subset_variant'} title={_title[:100]}"
                )
            return False, _nonstandard_reason or "nonstandard_subset_variant"
        if any(_term in _title_lower for _term in ("lot", "bundle", "break", "case break", "team break", "sealed", "blaster", "mega box", "fat pack", "hobby box", "custom", "reprint")):
            if emit_log:
                print(
                    f"[FINAL_TARGET_DROP] item={str(_row.get('item_id') or _row.get('source_item_id') or '')[:18] or '?'} "
                    f"reason=obvious_junk title={_title[:100]}"
                )
            return False, "obvious_junk"

        _row_sport = _normalize_sport_label(
            _row.get("sport") or _row.get("target_sport") or _row.get("sport_name") or ""
        )
        _contract_sport = _normalize_sport_label(_target_sport)
        if _contract_sport and _row_sport and _contract_sport != _row_sport:
            if emit_log:
                print(
                    f"[FINAL_TARGET_DROP] item={str(_row.get('item_id') or _row.get('source_item_id') or '')[:18] or '?'} "
                    f"reason=wrong_sport contract={_contract_sport} row={_row_sport}"
                )
            return False, "wrong_sport"

        _target_player_key = _normalize_person_key(_target_player)
        _row_player_key = _normalize_person_key(
            _row.get("player_name") or _row.get("target_player_name") or _row.get("normalized_entity") or ""
        )
        _entity_valid = bool(
            _row.get("entity_exact_match")
            or _row.get("exact_entity_match")
            or _row.get("tracked_anchor")
            or _row.get("_target_match_relaxed")
            or _target_status == "premium_soft_valid"
            or _route_stage in {"tracked_exact", "family_valid_premium", "premium_soft_valid", "card_number_rescue", "promoted_live_candidate"}
            or (_target_player_key and _row_player_key and _target_player_key == _row_player_key)
        )
        if (
            not _entity_valid
            or _entity_reason in {"wrong_entity", "player_mismatch", "other_player_in_title", "conflicting_seed_player", "negative_alias_conflict"}
            or any(_term in _reason_blob for _term in ("wrong_entity", "player_mismatch", "other_player_in_title", "conflicting_seed_player", "negative_alias_conflict"))
        ):
            if emit_log:
                print(
                    f"[FINAL_TARGET_DROP] item={str(_row.get('item_id') or _row.get('source_item_id') or '')[:18] or '?'} "
                    f"reason=wrong_player title={_title[:100]}"
                )
            return False, "wrong_player"

        _subset_text = " ".join(
            str(_row.get(_field) or "")
            for _field in ("subset_name", "lane_subset", "target_subset_family", "title", "source_title")
        ).lower()
        _subset_guard = _subset_identity_noise_token(
            _target_subset,
            title=_title,
            card_number=str(_row.get("card_number") or _row.get("target_card_number") or ""),
        )
        if _subset_guard:
            print(
                f"[WRONG_SUBSET_GUARD] title={_title[:140]} dropped_subset={_subset_guard[:40]} "
                f"reason=noisy_subset_identity"
            )
            _target_subset = ""
        _subset_required = bool(_target_subset)
        if _target_scope == "player_subset_only":
            if _subset_required and _target_subset not in _subset_text:
                if emit_log:
                    print(
                        f"[FINAL_TARGET_DROP] item={str(_row.get('item_id') or _row.get('source_item_id') or '')[:18] or '?'} "
                        f"reason=wrong_subset scope=player_subset_only subset={_target_subset[:24]}"
                    )
                return False, "wrong_subset"
            if emit_log:
                print(
                    f"[FINAL_TARGET_CONTRACT_USED] item={str(_row.get('item_id') or _row.get('source_item_id') or '')[:18] or '?'} "
                    f"scope=player_subset_only reason=entity_plus_subset"
                )
            return True, "player_subset_only_contract"

        _contract_product_norm = _normalize_family_probe(_target_product)
        _row_products = {
            _normalize_family_probe(_row.get("product_family") or ""),
            _normalize_family_probe(_row.get("target_product_family") or ""),
            _normalize_family_probe(_row.get("lane_product") or ""),
            _normalize_family_probe(_row.get("matched_product_family") or ""),
        }
        _row_products.discard("")
        _product_ok = not _contract_product_norm or _contract_product_norm in _row_products
        if not _product_ok and _target_product:
            _product_ok = _product_family_close_enough(
                {"title": _title},
                {
                    "product": _target_product,
                    "subset": _target_subset,
                    "query": _target_query,
                    "seed_text": _target_query,
                },
            )
        if not _product_ok:
            if emit_log:
                print(
                    f"[FINAL_TARGET_DROP] item={str(_row.get('item_id') or _row.get('source_item_id') or '')[:18] or '?'} "
                    f"reason=wrong_product contract={_target_product[:28] or 'none'} "
                    f"row={str(_row.get('product_family') or _row.get('target_product_family') or _row.get('lane_product') or '')[:28] or 'none'}"
                )
            return False, "wrong_product"

        if _subset_required and _target_scope in {"product_bound", "player_product_subset"} and _target_subset not in _subset_text:
            if emit_log:
                print(
                    f"[FINAL_TARGET_DROP] item={str(_row.get('item_id') or _row.get('source_item_id') or '')[:18] or '?'} "
                    f"reason=wrong_subset scope={_target_scope or 'product_bound'} subset={_target_subset[:24]}"
                )
            return False, "wrong_subset"

        if emit_log and any(_term in _reason_blob for _term in ("product_mismatch", "family_exact_miss", "off_target_subset_family", "product_variant_mismatch")):
            print(
                f"[FINAL_TARGET_REBUILD_BYPASS] item={str(_row.get('item_id') or _row.get('source_item_id') or '')[:18] or '?'} "
                f"scope={_target_scope or 'product_bound'} reason_blob={_reason_blob[:64]}"
            )
        if emit_log:
            print(
                f"[FINAL_TARGET_CONTRACT_USED] item={str(_row.get('item_id') or _row.get('source_item_id') or '')[:18] or '?'} "
                f"scope={_target_scope or 'product_bound'} reason=frozen_contract_pass"
            )
        return True, "frozen_contract_pass"

    def _visible_survival_product_ok(row: Dict[str, Any]) -> bool:
        _contract_ok, _contract_reason = _row_passes_frozen_target_contract(row, emit_log=False)
        if _contract_ok is True:
            return True
        if _contract_ok is False:
            return False
        _status = str(
            (row or {}).get("target_match_status")
            or (row or {}).get("product_match_status")
            or (row or {}).get("target_fit")
            or ""
        ).strip().lower()
        _reason_blob = " ".join(
            str((row or {}).get(_field) or "")
            for _field in (
                "target_match_reason",
                "product_match_reason",
                "reject_reason",
                "hidden_reason",
            )
        ).lower()
        if "product_mismatch" in _reason_blob or "family_exact_miss" in _reason_blob:
            return False
        if _status in {"exact", "clean_exact", "premium_soft_valid", "target_validate_recovered"}:
            return True
        return bool((row or {}).get("_target_match_relaxed") or (row or {}).get("tracked_anchor") or (row or {}).get("entity_exact_match") or (row or {}).get("exact_entity_match"))

    def _final_admission_contract(row: Dict[str, Any], *, emit_log: bool = False) -> Tuple[bool, str]:
        _row = dict(row or {})
        _title = str(_row.get("title") or _row.get("source_title") or "").lower()
        _contract_ok, _contract_reason = _row_passes_frozen_target_contract(_row, emit_log=emit_log)
        _contract_used = _contract_ok is not None
        _reason_blob = " ".join(
            str(_row.get(_field) or "")
            for _field in (
                "target_match_reason",
                "product_match_reason",
                "reject_reason",
                "hidden_reason",
                "live_board_reject_reason",
                "execution_admission_reason",
            )
        ).lower()
        _source = str(_row.get("valuation_source_clean") or _row.get("mv_source") or _row.get("market_value_source") or "").strip().lower()
        _entity_valid = bool(
            _row.get("entity_exact_match")
            or _row.get("exact_entity_match")
            or _row.get("tracked_anchor")
            or _row.get("_target_match_relaxed")
        )
        if _contract_ok is True:
            _entity_valid = True
        _product_valid = _visible_survival_product_ok(_row)
        if _contract_ok is True:
            _product_valid = True
        _non_junk = not any(_term in _title for _term in ("lot", "bundle", "break", "case break", "team break", "sealed", "blaster", "mega box", "fat pack", "hobby box", "custom", "reprint"))
        _explicit_invalid_terms = ("no_match", "conflicting_seed_player", "other_player_in_title", "negative_alias_conflict")
        if _contract_ok is not True:
            _explicit_invalid_terms = ("product_mismatch", "family_exact_miss", "off_target_subset_family") + _explicit_invalid_terms
        _explicit_invalid = any(_term in _reason_blob for _term in _explicit_invalid_terms)
        _review_value = _safe_float(_row.get("review_estimate_value"))
        _true_value = _safe_float(_row.get("true_market_value"))
        _target_bid = _safe_float(_row.get("target_bid") or _row.get("target_bid_price") or _row.get("bid_ceiling_value"))
        _has_anchor = bool((_true_value and _true_value > 0) or (_review_value and _review_value > 0))
        _has_bid_or_review = bool((_target_bid and _target_bid > 0) or (_review_value and _review_value > 0))
        if _contract_used and _contract_ok is False:
            _ok = False
            _reason = _contract_reason
        else:
            _ok = bool(_entity_valid and _product_valid and _non_junk and not _explicit_invalid and _has_anchor and _has_bid_or_review)
            _reason = "ok" if _ok else (
                "invalid_entity" if not _entity_valid else
                "invalid_product" if not _product_valid else
                "junk" if not _non_junk else
                "explicit_invalid" if _explicit_invalid else
                "no_anchor" if not _has_anchor else
                "no_bid_or_review"
            )
        if _source in {"structured_fallback", "fallback", "fallback_comp_support", "structured_review", "fallback_review", "price_anchor_fallback"}:
            print(f"[REVIEW_ONLY_SOURCE] title={str(_row.get('title') or '')[:120]} source={_source}")
        if emit_log:
            print(
                f"[FINAL_ADMISSION_CHECK] title={str(_row.get('title') or '')[:120]} "
                f"truth={str(_row.get('valuation_truth_tier') or '')} review={_review_value} "
                f"true_mv={_true_value} target_bid={_target_bid} ok={1 if _ok else 0}"
            )
            if _ok:
                print(
                    f"[FINAL_TARGET_ADMIT] title={str(_row.get('title') or '')[:120]} "
                    f"reason={_reason}"
                )
                print(f"[FINAL_ADMISSION_PASS] title={str(_row.get('title') or '')[:120]} reason={_reason}")
            else:
                print(
                    f"[FINAL_TARGET_DROP] title={str(_row.get('title') or '')[:120]} "
                    f"reason={_reason}"
                )
                print(f"[FINAL_ADMISSION_FAIL] title={str(_row.get('title') or '')[:120]} reason={_reason}")
        return _ok, _reason

    def _review_board_visible(row: Dict[str, Any], *, emit_log: bool = False) -> bool:
        _row = dict(row or {})
        _truth = str(_row.get("valuation_truth_tier") or "").strip().upper()
        _review_value = _safe_float(_row.get("review_estimate_value"))
        _ok, _reason = _final_admission_contract(_row, emit_log=False)
        _review_ok = bool(_truth == "REVIEW" and _review_value and _review_value > 0 and _ok)
        if emit_log:
            if _review_ok:
                print(
                    f"[REVIEW_BOARD_ELIGIBLE] title={str(_row.get('title') or '')[:120]} "
                    f"review={_review_value}"
                )
            else:
                print(
                    f"[REVIEW_BOARD_BLOCK] title={str(_row.get('title') or '')[:120]} "
                    f"reason={_reason}"
                )
        return _review_ok

    def _debug_board_handoff(stage, rows):
        try:
            _rows = list(rows or [])
            _sample = []
            for _r in _rows[:5]:
                _sample.append({
                    "title": str((_r or {}).get("title") or (_r or {}).get("raw_title") or "")[:100],
                    "commercially_visible": (_r or {}).get("commercially_visible"),
                    "board_visible": (_r or {}).get("board_visible"),
                    "execution_admission_bucket": (_r or {}).get("execution_admission_bucket"),
                    "commercial_visibility": (_r or {}).get("commercial_visibility"),
                    "final_bucket": (_r or {}).get("_final_bucket") or (_r or {}).get("final_bucket"),
                    "target_bid": (_r or {}).get("target_bid"),
                    "true_mv": (_r or {}).get("true_mv"),
                    "review_estimate": (_r or {}).get("review_estimate"),
                })
            print(f"[BOARD_HANDOFF] stage={stage} count={len(_rows)} sample={_sample}")
        except Exception as e:
            print(f"[BOARD_HANDOFF_ERROR] stage={stage} error={e}")

    # PATCH 5: fallback lane board cap (20% of total board slots)
    _board_total_cap = 5 + 12  # sniper_target max + watchlist max
    _fallback_board_count = 0
    _fallback_board_max = max(2, int(_board_total_cap * 0.20))
    _fallback_blocked_count = 0
    # PATCH 8: [VISIBLE_CHASE_GATE] counters
    _vcg_kept = 0
    _vcg_dropped_junk = 0      # GENERIC_PREMIUM_JUNK class (insert junk, junk product family, etc.)
    _vcg_dropped_mem = 0       # memorabilia_junk filter
    _vcg_dropped_veteran = 0   # veteran_non_chase filter
    for _d in filtered_auctions:
        _title_lower = f" {str(_d.get('source_title') or _d.get('title') or '').strip().lower()} "
        _not_junk = not any(_tok in _title_lower for _tok in _NOISY_TOKENS)
        _identity_clean = _is_clean_bid_identity(_d)
        _weak_mv_override_ok = False
        _weak_mv_override_reason = "uninitialized_fail_closed"
        _weak_mv_title = str(_d.get("title") or _d.get("source_title") or "")
        _weak_mv_item = str(_d.get("item_id") or _d.get("source_item_id") or _d.get("itemId") or "")[:24] or "?"
        print(
            f"[WEAK_MV_SCOPE_FIX] title={_weak_mv_title[:120]} item={_weak_mv_item} "
            f"default_initialized=1"
        )
        _premium_force_visible = False
        if _is_premium_card(_d) and _is_premium_identity_row(_d):
            _weak_mv_override_ok = bool(_weak_mv_override_allowed(_d, emit_log=True))
            _weak_mv_override_reason = str(
                _d.get("_weak_mv_override_reason")
                or ("helper_allow" if _weak_mv_override_ok else "helper_fail_closed")
            )
            print(
                f"[WEAK_MV_SCOPE_ASSIGN] title={_weak_mv_title[:120]} item={_weak_mv_item} "
                f"allow={1 if _weak_mv_override_ok else 0} reason={_weak_mv_override_reason}"
            )
            _premium_force_visible = _weak_mv_override_ok
        else:
            print(
                f"[WEAK_MV_SCOPE_GUARD] title={_weak_mv_title[:120]} item={_weak_mv_item} "
                f"crash_prevented=1 field=_weak_mv_override_allowed"
            )
            print(
                f"[WEAK_MV_SCOPE_ASSIGN] title={_weak_mv_title[:120]} item={_weak_mv_item} "
                f"allow={1 if _weak_mv_override_ok else 0} reason={_weak_mv_override_reason}"
            )
        _exact_surface = _row_exact_surface_candidate(_d)
        _suppressed = str(_d.get("row_quality_state") or "").strip().lower() == "suppressed"
        _rescue = str(_d.get("rescue_trust_tier") or "none").strip().lower()
        _target_bid_ready = bool(_d.get("bid_ceiling_ready")) or bool(_d.get("target_bid_ready"))
        _mv_resolved = bool(_d.get("mv_resolved")) or bool(_d.get("mv_valid")) or float(_d.get("mv_value") or _d.get("market_value") or 0.0) > 0
        _comp_count = int(_d.get("comp_count") or _d.get("mv_comp_count") or 0)
        _commercial = float(_d.get("commercial_signal_score") or 0.0)
        _score = float(_d.get("execution_admission_score") or 0.0)
        _edge_pct = float(_d.get("edge_pct") or _d.get("edge_percent") or 0.0)
        try:
            _edge_dollars = float(
                _d.get("edge_dollars")
                or (_d.get("action_summary") or {}).get("expected_profit")
                or 0.0
            )
        except (TypeError, ValueError):
            _edge_dollars = 0.0
        _price = float(_d.get("current_price") or _d.get("current_bid") or 0.0)
        _bid_conf = str(_d.get("bid_ceiling_confidence") or _d.get("target_bid_confidence") or "NONE").strip().upper()
        _mv_source = str(_d.get("mv_source") or _d.get("market_value_source") or "").strip().lower()
        _unresolved_reasons = _unresolved_board_reasons(_d)
        _soft_watchlist = False
        _soft_watch_reasons = set(_unresolved_reasons)
        _soft_watch_triggered = bool(_soft_watch_reasons.intersection({"no_true_mv", "no_comps", "no_target_bid", "anchor_source"}))
        _stamp_hydrated_identity_snapshot(_d, emit_log=False)
        _early_rescue_keep, _early_rescue_reason = _is_late_hydrated_tier_b_survivor(_d)
        _early_drop_candidates = [
            str(_d.get("exact_truth_rescue_reason") or "").strip().lower(),
            str(_d.get("accelerator_reason") or "").strip().lower(),
            str(_d.get("commodity_reason") or "").strip().lower(),
            str(_d.get("execution_decision") or _d.get("decision") or "").strip().lower(),
            str(_d.get("review_reason") or "").strip().lower(),
            str(_d.get("review_execution_final") or "").strip().lower(),
            str(_d.get("drop_reason") or "").strip().lower(),
        ]
        _early_drop_reason = next(
            (
                _candidate
                for _candidate in _early_drop_candidates
                if _candidate in {"commodity_lane", "pass", "not_review_promoted", "spillover_drop"}
            ),
            "",
        )
        print(
            f"[EARLY_RESCUE_CHECK] title={str((_d or {}).get('title') or '')[:160]} "
            f"eligible={_early_rescue_keep} "
            f"reason={_early_rescue_reason} "
            f"tier={_d.get('subscription_lane_tier')} "
            f"identity_is_clean={_d.get('identity_is_clean')} "
            f"lane_type={_d.get('lane_type')} "
            f"insert_family={_d.get('insert_family')} "
            f"parallel_family={_d.get('parallel_family')} "
            f"card_number={_d.get('card_number')} "
            f"grade={_d.get('grade')}"
        )
        if _early_rescue_keep and _early_drop_reason in {"commodity_lane", "pass", "not_review_promoted", "spillover_drop"}:
            _d["_early_tier_b_rescue"] = True
            _d["_early_tier_b_rescue_reason"] = _early_rescue_reason
            _d["surface_intent"] = "watchlist"
            _d["_rescued_watchlist"] = True
            _d["_soft_watchlist"] = True
            _d["commercially_suppressed"] = False
            _d["commodity_suppressed"] = False
            _d["commercially_visible"] = True
            _d["board_visible"] = True
            _d["commercial_visibility"] = "watchlist"
            _d["execution_admission_bucket"] = "watchlist"
            _d["hidden_reason"] = ""
            _d["execution_decision"] = "WATCH"
            _d["decision"] = "WATCH"
            _d["decision_reason"] = "early_tier_b_rescue"
            _d["_visible_route"] = str(_d.get("_visible_route") or "EARLY_TIER_B_RESCUE")
            _suppressed = False
            _soft_watchlist = True
            print(
                f"[EARLY_TIER_B_RESCUE] title={str((_d or {}).get('title') or '')[:160]} "
                f"reason={_early_rescue_reason} "
                f"lane_type={_d.get('lane_type')} "
                f"insert_family={_d.get('insert_family')} "
                f"parallel_family={_d.get('parallel_family')} "
                f"card_number={_d.get('card_number')} "
                f"grade={_d.get('grade')}"
            )
        if _unresolved_reasons:
            _unresolved_keep, _unresolved_reason = _is_late_hydrated_tier_b_survivor(_d)
            _keep_row = True
            _unresolved_fatal = True
            _drop_reason = "unresolved"
            _reason = "unresolved"
            print(
                f"[UNRESOLVED_GATE_CHECK] title={str((_d or {}).get('title') or '')[:160]} "
                f"eligible={_unresolved_keep} "
                f"reason={_unresolved_reason} "
                f"identity_is_clean={_d.get('identity_is_clean')} "
                f"lane_type={_d.get('lane_type')} "
                f"insert_family={_d.get('insert_family')} "
                f"parallel_family={_d.get('parallel_family')} "
                f"card_number={_d.get('card_number')} "
                f"grade={_d.get('grade')} "
                f"tier={_d.get('subscription_lane_tier')}"
            )
            if _unresolved_keep:
                _d["_unresolved_tier_b_immunity"] = True
                _d["_unresolved_tier_b_immunity_reason"] = _unresolved_reason
                _d["surface_intent"] = "watchlist"
                _d["_rescued_watchlist"] = True
                _d["_soft_watchlist"] = True
                _d["commercially_suppressed"] = False
                _d["commodity_suppressed"] = False
                _d["commercially_visible"] = True
                _d["board_visible"] = True
                _d["commercial_visibility"] = "watchlist"
                _d["execution_admission_bucket"] = "watchlist"
                _d["hidden_reason"] = ""
                _d["execution_decision"] = "WATCH"
                _d["decision"] = "WATCH"
                _d["decision_reason"] = "unresolved_tier_b_immunity"
                _d["_visible_route"] = str(_d.get("_visible_route") or "UNRESOLVED_TIER_B_IMMUNITY")
                _keep_row = True
                _suppressed = False
                _unresolved_fatal = False
                _drop_reason = ""
                _reason = "unresolved_tier_b_immunity"
                _soft_watchlist = True
                print(
                    f"[UNRESOLVED_TIER_B_IMMUNITY] title={str((_d or {}).get('title') or '')[:160]} "
                    f"reason={_unresolved_reason}"
                )
            else:
                print(
                    f"[UNRESOLVED_HARD_KILL] title={str((_d or {}).get('title') or '')[:160]} "
                    f"reason={_drop_reason or _reason or 'unresolved'}"
                )
            _d["display"] = None
            _d["blocked_reason"] = "no_trusted_mv"
            print(f"[SUPPRESSION_BEFORE] display={_d.get('display')} blocked_reason={_d.get('blocked_reason')} target_bid={_d.get('target_bid')}")
            if _direct_watchlist_rescue(_d) and _identity_clean and _not_junk and not _suppressed and _rescue == "none":
                _commercial_watch_ok, _commercial_watch_reason = _is_commercial_watchlist_row(_d)
                if not _commercial_watch_ok:
                    print(
                        f"[WATCHLIST_RESCUE_BLOCKED_NON_COMMERCIAL] title={str(_d.get('title') or '')[:140]} "
                        f"review_estimate_value={_d.get('review_estimate_value')} current_price={_d.get('current_price') or _d.get('current_bid')}"
                    )
                else:
                    _d["display"] = "watchlist"
                    _d["blocked_reason"] = None
                    _d["_rescued_watchlist"] = True
                    if not _d.get("target_bid"):
                        try:
                            _cp_rescue = float(_d.get("current_price") or 0)
                        except Exception:
                            _cp_rescue = 0.0

                        _fallback_mv = (
                            _d.get("market_value_true")
                            or _d.get("market_value")
                            or _d.get("anchored_estimate_value")
                            or _d.get("estimated_value")
                        )

                        try:
                            _mv_rescue = float(_fallback_mv) if _fallback_mv is not None else None
                        except Exception:
                            _mv_rescue = None

                        if _mv_rescue and _mv_rescue > 0:
                            _d["target_bid"] = round(_mv_rescue * 0.72, 2)
                        elif _cp_rescue and _cp_rescue > 0:
                            _d["target_bid"] = round(_cp_rescue * 1.18, 2)

                        _d["_soft_target_bid"] = True

                    _rescue_bid = _safe_float(_d.get("target_bid"))
                    if _rescue_bid and _rescue_bid > 0:
                        _d["target_bid_price"] = round(float(_rescue_bid), 2)
                        _d["bid_ceiling_value"] = round(float(_rescue_bid), 2)
                        _d["adjusted_max_bid"] = round(float(_rescue_bid), 2)
                        _d["target_max_bid"] = round(float(_rescue_bid), 2)
                        _d["max_bid"] = round(float(_rescue_bid), 2)
                        _d["target_bid_ready"] = True
                        _d["bid_ceiling_ready"] = True
                        _d["target_bid_source"] = "soft_watchlist"
                        _d["target_bid_source_detail"] = "soft_watchlist_estimate"
                        _d["bid_ceiling_source"] = "soft_watchlist"
                        if str(_d.get("target_bid_confidence") or "").strip().upper() in {"", "NONE"}:
                            _d["target_bid_confidence"] = "LOW"
                        if str(_d.get("bid_ceiling_confidence") or "").strip().upper() in {"", "NONE"}:
                            _d["bid_ceiling_confidence"] = "LOW"

                    _rescue_mv = _safe_float(_d.get("market_value_true"))
                    if not _rescue_mv or _rescue_mv <= 0:
                        _rescue_mv = _safe_float(_d.get("market_value"))
                    if not _rescue_mv or _rescue_mv <= 0:
                        _rescue_mv = _safe_float(_d.get("anchored_estimate_value"))
                    if not _rescue_mv or _rescue_mv <= 0:
                        _rescue_mv = _safe_float(_d.get("estimated_value"))
                    if (not _rescue_mv or _rescue_mv <= 0) and _safe_float(_d.get("target_bid")):
                        _rescue_mv = _safe_float(_d.get("target_bid"))
                    if _rescue_mv and _rescue_mv > 0:
                        _rescue_mv = round(float(_rescue_mv), 2)
                        _d["true_market_value"] = None
                        _d["market_value_true"] = None
                        _d["review_estimate_value"] = _rescue_mv
                        _d["anchored_estimate_value"] = _rescue_mv
                        _d["market_value"] = None
                        _d["mv_value"] = None
                        _d["mv_resolved"] = False
                        _d["mv_valid"] = False
                        _d["has_valid_mv"] = False
                        _d["_soft_market_value_true"] = False
                        _d["valuation_truth_tier"] = "REVIEW"
                        _d["_valuation_truth_tier"] = "REVIEW"
                        _stamp_review_truth_class(_d)
                        _d["valuation_source_clean"] = "soft_watchlist_estimate"
                        try:
                            _cp_truth = float(_d.get("current_price") or 0.0)
                        except Exception:
                            _cp_truth = 0.0
                        if _cp_truth > 0 and abs(_cp_truth - _rescue_mv) < 0.01:
                            _d["_estimate_equals_current"] = True
                            if int(_d.get("comp_count") or _d.get("mv_comp_count") or 0) < 2:
                                _d["whatnot_heat_score"] = max(0.0, float(_d.get("whatnot_heat_score") or 0.0) - 6.0)
                                _d["commercial_signal_score"] = max(0.0, float(_d.get("commercial_signal_score") or 0.0) - 4.0)
                            print(
                                f"[MV_CLONE_BLOCK] title={str(_d.get('title') or '')[:120]} "
                                f"current={_d.get('current_price')} review={_rescue_mv}"
                            )
                            _stamp_research_only_price_check(_d)

                    if int(_d.get("comp_count") or _d.get("mv_comp_count") or 0) <= 0:
                        _d["comp_count"] = 1
                        _d["mv_comp_count"] = 1
                    _d["commercially_visible"] = True
                    _d["board_visible"] = True
                    _d["commercial_visibility"] = "watchlist"
                    _d["execution_admission_bucket"] = "watchlist"
                    _d["hidden_reason"] = ""
                    _d["execution_admission_reason"] = "Rescued to watchlist — thin MV or no target bid"
                    _d["commercial_visibility_reason"] = _d["execution_admission_reason"]
                    if str(_d.get("mv_source") or _d.get("market_value_source") or "").strip().lower() in {"", "none", "price_anchor_fallback"}:
                        _d["mv_source"] = "soft_watchlist_estimate"
                        _d["market_value_source"] = "soft_watchlist_estimate"
                    _d["valuation_source"] = str(_d.get("market_value_source") or _d.get("mv_source") or "soft_watchlist_estimate")
                    _soft_watchlist = True
                    print(f"[DIRECT_WATCHLIST_RESCUE] title={_d.get('title','')[:140]} target_bid={_d.get('target_bid')}")
                    print(f"[SUPPRESSION_AFTER] display={_d.get('display')} blocked_reason={_d.get('blocked_reason')} target_bid={_d.get('target_bid')} rescued={_d.get('_rescued_watchlist')}")
            elif _soft_watch_triggered and _is_watchlist_worthy(_d) and _identity_clean and _not_junk and not _suppressed and _rescue == "none":
                _soft_commercial_ok, _soft_commercial_reason = _is_commercial_watchlist_row(_d)
                if not _soft_commercial_ok:
                    print(f"[SOFT_WATCHLIST_COMMERCIAL_BLOCK] title={str(_d.get('title',''))[:140]} reason={_soft_commercial_reason} review={_d.get('review_estimate_value')} current={_d.get('current_price')}")
                else:
                    _soft_watchlist = True
                    _d["_soft_watchlist"] = True
                    _d["_soft_watchlist_reason"] = "thin_mv_or_no_target_bid"
                    print(f"[SUPPRESSION_AFTER] display={_d.get('display')} blocked_reason={_d.get('blocked_reason')} target_bid={_d.get('target_bid')} rescued={_d.get('_rescued_watchlist')}")
            elif bool(_d.get("_early_tier_b_rescue")) or bool(_d.get("_unresolved_tier_b_immunity")):
                _soft_watchlist = True
                _d["display"] = "watchlist"
                _d["blocked_reason"] = None
                _d["hidden_reason"] = ""
                _d["commercial_visibility_reason"] = "Unresolved Tier B immunity to watchlist" if bool(_d.get("_unresolved_tier_b_immunity")) else "Early Tier B rescue to watchlist"
                _d["execution_admission_reason"] = _d["commercial_visibility_reason"]
                print(f"[SUPPRESSION_AFTER] display={_d.get('display')} blocked_reason={_d.get('blocked_reason')} target_bid={_d.get('target_bid')} rescued={_d.get('_early_tier_b_rescue') or _d.get('_unresolved_tier_b_immunity')}")
            else:
                # ── FALLBACK PROMOTION PATH (hard-kill bypass) ─────────────────
                # Rows that failed all existing rescue paths (no rescue eligibility,
                # no soft-watch trigger, non-commercial) can still reach the board if
                # they carry a structural quality signal: serial, premium player,
                # premium product, or a large price-to-anchor gap.
                # These are tagged SPECULATIVE and routed to watchlist — they NEVER
                # block sniper slots, but they give users real opportunities instead
                # of an empty board when comps are thin.
                if (
                    _fallback_promotion_eligible(_d)
                    and _identity_clean
                    and _not_junk
                    and not _suppressed
                    and _rescue == "none"
                ):
                    _d["_fallback_promoted"] = True
                    _d["_valuation_mode"] = "fallback"
                    _d["_deal_type"] = "SPECULATIVE"
                    _d["_confidence"] = "LOW"
                    _soft_watchlist = True
                    print(
                        f"[FALLBACK_PROMO] title={str(_d.get('title') or '')[:120]} "
                        f"source={_mv_source} reason=signal_rescue_hard_kill_bypass"
                    )
                elif bool(_d.get("_supply_provisional_admit")) and bool(_d.get("_candidate_survival_admit")) and _not_junk and not _suppressed:
                    # ── SUPPLY PROVISIONAL PASS ──────────────────────────────────
                    # Row has valid frozen contract + candidate survival but no MV yet.
                    # Route to watchlist as provisional — never sniper.
                    # Hard blockers (wrong player, junk, suppressed) still kill it.
                    _d["_provisional_watchlist_only"] = True
                    _d["_supply_pass"] = True
                    _d["_supply_stage"] = "provisional"
                    _d["_soft_watchlist"] = True
                    _d["_mv_untrusted_but_allowed"] = True
                    _d["commercially_visible"] = True
                    _d["board_visible"] = True
                    _d["commercial_visibility"] = "watchlist"
                    _d["execution_admission_bucket"] = "watchlist"
                    _d["hidden_reason"] = ""
                    _d["execution_admission_reason"] = "Supply provisional: valid contract, pending MV"
                    _soft_watchlist = True
                    print(
                        f"[SUPPLY_PASS] title={str(_d.get('title') or '')[:100]} "
                        f"contract={str(_d.get('_target_contract_id') or 'none')[:24]} "
                        f"player={str(_d.get('_target_player') or _d.get('player_name') or '')[:24]}"
                    )
                else:
                    _d["execution_admission_bucket"] = "hidden"
                    _d["commercial_visibility"] = "hidden"
                    _d["commercially_visible"] = False
                    _d["board_visible"] = False
                    _d["hidden_reason"] = "unresolved_no_trusted_mv"
                    _d["commercial_visibility_reason"] = "Hidden — unresolved, no trusted market value"
                    _d["execution_admission_reason"] = _d["commercial_visibility_reason"]
                    _d["recovery_pool"] = "recovery_rows_hidden"
                    _admission_hidden_counts["low_trust"] = int(_admission_hidden_counts.get("low_trust", 0) or 0) + 1
                    print(
                        f"[SUPPLY_DROP] item={str(_d.get('item_id') or _d.get('source_item_id') or '')[:24] or '?'} "
                        f"reason=unresolved_no_trusted_mv provisional_admit={bool(_d.get('_supply_provisional_admit'))} candidate_admit={bool(_d.get('_candidate_survival_admit'))}"
                    )
                    print(f"[SUPPRESSION_AFTER] display={_d.get('display')} blocked_reason={_d.get('blocked_reason')} target_bid={_d.get('target_bid')} rescued={_d.get('_rescued_watchlist')}")
                    print(
                        f"[EARLY_CONTINUE_TRACE] title={str((_d or {}).get('title') or '')[:160]} "
                        f"reason={_early_drop_reason or _d.get('hidden_reason') or _d.get('blocked_reason') or 'unknown'} "
                        f"tier={_d.get('subscription_lane_tier')} "
                        f"early_rescue={_d.get('_early_tier_b_rescue')}"
                    )
                    continue
            print(
                f"[POST_UNRESOLVED_ASSERT] title={str((_d or {}).get('title') or '')[:160]} "
                f"keep_row={_keep_row} "
                f"suppressed={_suppressed} "
                f"drop_reason={_drop_reason or _reason} "
                f"immunity={_d.get('_unresolved_tier_b_immunity')}"
            )
        # Post-unresolved fallback check: rows that passed watchlist gate condition
        # but failed the commercial screen still need a fallback promotion check.
        # (e.g. direct-rescue-eligible but _is_commercial_watchlist_row returned False)
        if _unresolved_reasons and not _soft_watchlist and not bool(_d.get("_fallback_promoted")):
            if (
                _fallback_promotion_eligible(_d)
                and _identity_clean
                and _not_junk
                and not _suppressed
                and _rescue == "none"
            ):
                _d["_fallback_promoted"] = True
                _d["_valuation_mode"] = "fallback"
                _d["_deal_type"] = "SPECULATIVE"
                _d["_confidence"] = "LOW"
                _soft_watchlist = True
                print(
                    f"[FALLBACK_PROMO_RESCUE] title={str(_d.get('title') or '')[:120]} "
                    f"source={_mv_source} reason=commercial_gate_bypass"
                )
        _fallback_mv = "fallback" in _mv_source
        _commercial_bucket = str(_d.get("commercial_bucket") or "WEAK").strip().upper()
        _commercially_suppressed = bool(_d.get("commercially_suppressed"))
        _commodity_suppressed_d = bool(_d.get("commodity_suppressed"))
        _commodity_reason = str(_d.get("commodity_reason") or "").strip()
        _endgame_tier = str(_d.get("endgame_tier") or "").strip().lower()
        _lane_tier = str(_d.get("lane_tier") or "").strip().lower()
        _confidence_gate = _premium_confidence_gate(_d, emit_log=True)
        _mv_truth_decision = str(_confidence_gate.get("mv_truth_decision") or "visible")
        _mv_truth_reason = str(_confidence_gate.get("mv_truth_reason") or "")
        _endgame_gate = _endgame_sniper_gate(_d, emit_log=True)
        _single_comp_clone_block = _stamp_single_comp_clone_hero_block(_d)
        _common_insert = bool(_d.get("commercial_common_insert"))
        _support_flags = dict(_d.get("commercial_support_flags") or {})
        _has_support = bool(_support_flags.get("serial") or _support_flags.get("auto") or _support_flags.get("scarcity"))
        _mv_conf = str(_d.get("mv_confidence_strict") or _d.get("valuation_confidence") or _d.get("confidence") or "LOW").strip().upper()
        _premium_secondary_floor = _passes_non_endgame_watchlist_floor(_d)
        _commodity_watch_block = bool(
            _commodity_suppressed_d
            and _endgame_tier != "endgame"
            and _lane_tier != "elite"
            and _commercial_bucket != "ELITE"
        )
        # PATCH 2: hard block LOW/MID rows without premium signals
        _product_tier_d = str(_d.get("product_tier") or "LOW").strip().upper()
        _product_tier_block = bool(
            _product_tier_d in {"LOW", "MID"}
            and not _has_support
            and _endgame_tier != "endgame"
        )
        # PATCH 5: track fallback lane rows for board cap
        _is_fallback_lane_row = str(_d.get("target_lane_type") or _d.get("spec_lane_class") or "").strip().lower() in {"product_base", "broad_fallback"}
        _fallback_floor_ok = bool(
            _price >= 50.0
            or bool(str(_d.get("serial") or _d.get("serial_denominator") or "").strip())
            or "auto" in str(_d.get("source_title") or _d.get("title") or "").lower()
        )
        # PATCHES 5+6: chase class gate
        _chase_class_d = str(_d.get("chase_class") or "COMMODITY").strip().upper()
        _mem_junk_d = bool(_d.get("memorabilia_junk"))
        _vet_non_chase_d = bool(_d.get("veteran_non_chase"))
        if _mem_junk_d and _premium_force_visible:
            if _apply_fake_serial_base_promo_hard_block(_d, stage="junk_override_board_gate", junk_override_allowed=0):
                _premium_force_visible = False
                _mem_junk_d = True
                _d["memorabilia_junk"] = True
            else:
                print(f"[JUNK_OVERRIDE] Keeping premium card: {_d.get('title')}")
                _mem_junk_d = False
                _d["memorabilia_junk"] = False
        if _premium_force_visible and not _mv_resolved:
            _mv_resolved = True
            _d["mv_resolved"] = True
            _d["_mv_untrusted_but_allowed"] = True
        if _premium_force_visible and not _target_bid_ready:
            _target_bid_ready = True
            _d["target_bid_ready"] = True
        if (
            not _soft_watchlist
            and _is_watchlist_worthy(_d)
            and _identity_clean
            and _not_junk
            and not _suppressed
            and _rescue == "none"
            and (
                not _mv_resolved
                or _comp_count <= 0
                or not _target_bid_ready
                or _soft_watch_triggered
            )
        ):
            _soft_commercial_ok, _soft_commercial_reason = _is_commercial_watchlist_row(_d)
            if not _soft_commercial_ok:
                print(f"[SOFT_WATCHLIST_COMMERCIAL_BLOCK] title={str(_d.get('title',''))[:140]} reason={_soft_commercial_reason} review={_d.get('review_estimate_value')} current={_d.get('current_price')}")
            else:
                _soft_watchlist = True
                _d["_soft_watchlist"] = True
                _d["_soft_watchlist_reason"] = "thin_mv_or_no_target_bid"
        if _soft_watchlist:
            _soft_mv = _safe_float(_d.get("review_estimate_value"))
            if not _soft_mv or _soft_mv <= 0:
                _soft_mv = _safe_float(_d.get("anchored_estimate_value"))
            if not _soft_mv or _soft_mv <= 0:
                _soft_mv = _safe_float(_d.get("market_value_true"))
            if not _soft_mv or _soft_mv <= 0:
                _soft_mv = _safe_float(_d.get("market_value"))
            if not _soft_mv or _soft_mv <= 0:
                _soft_mv = _safe_float(_d.get("estimated_value"))
            if _soft_mv and _soft_mv > 0:
                _soft_mv = round(float(_soft_mv), 2)
                _d["true_market_value"] = None
                _d["market_value_true"] = None
                _d["review_estimate_value"] = _soft_mv
                _d["anchored_estimate_value"] = _soft_mv
                _d["market_value"] = None
                _d["mv_value"] = None
                _d["mv_resolved"] = False
                _d["mv_valid"] = False
                _d["has_valid_mv"] = False
                _d["_soft_market_value_true"] = False
                _d["valuation_truth_tier"] = "REVIEW"
                _d["_valuation_truth_tier"] = "REVIEW"
                _stamp_review_truth_class(_d)
            _soft_bid = _build_soft_target_bid(_d)
            if (not _soft_mv or _soft_mv <= 0) and _soft_bid and _soft_bid > 0:
                _soft_mv = round(float(_soft_bid), 2)
                _d["review_estimate_value"] = _soft_mv
                _d["anchored_estimate_value"] = _soft_mv
                _d["true_market_value"] = None
                _d["market_value_true"] = None
                _d["market_value"] = None
                _d["mv_value"] = None
                _d["mv_resolved"] = False
                _d["mv_valid"] = False
                _d["has_valid_mv"] = False
                _d["_soft_market_value_true"] = False
                _d["valuation_truth_tier"] = "REVIEW"
                _d["_valuation_truth_tier"] = "REVIEW"
                _stamp_review_truth_class(_d)
            if not _d.get("target_bid") and _soft_bid:
                _d["target_bid"] = _soft_bid
                _d["target_bid_price"] = _soft_bid
                _d["bid_ceiling_value"] = _soft_bid
                _d["adjusted_max_bid"] = _soft_bid
                _d["target_max_bid"] = _soft_bid
                _d["max_bid"] = _soft_bid
                _d["_soft_target_bid"] = True
                print(f"[SOFT_TARGET_BID] title={str(_d.get('title') or '')[:140]} bid={_soft_bid}")
            if _soft_bid and _soft_bid > 0:
                _d["target_bid_ready"] = True
                _d["bid_ceiling_ready"] = True
                _d["target_bid_source"] = "soft_watchlist"
                _d["target_bid_source_detail"] = "soft_watchlist_estimate"
                _d["bid_ceiling_source"] = "soft_watchlist"
                if str(_d.get("target_bid_confidence") or "").strip().upper() in {"", "NONE"}:
                    _d["target_bid_confidence"] = "LOW"
                if str(_d.get("bid_ceiling_confidence") or "").strip().upper() in {"", "NONE"}:
                    _d["bid_ceiling_confidence"] = "LOW"
            if int(_d.get("comp_count") or _d.get("mv_comp_count") or 0) <= 0:
                _d["comp_count"] = 1
                _d["mv_comp_count"] = 1
                _d["_soft_comp_proxy"] = True
            if str(_d.get("mv_source") or _d.get("market_value_source") or "").strip().lower() in {"", "none", "structured_fallback", "price_anchor_fallback"}:
                _d["mv_source_raw"] = str(_d.get("mv_source") or _d.get("market_value_source") or "")
                _d["mv_source"] = "soft_watchlist_estimate"
                _d["market_value_source"] = "soft_watchlist_estimate"
            _d["valuation_source"] = str(_d.get("market_value_source") or _d.get("mv_source") or "soft_watchlist_estimate")
            _d["valuation_source_clean"] = str(_d.get("valuation_source") or "").strip().lower()
            try:
                _cp_truth = float(_d.get("current_price") or 0.0)
            except Exception:
                _cp_truth = 0.0
            if _soft_mv and _cp_truth > 0 and abs(_cp_truth - _soft_mv) < 0.01:
                _d["_estimate_equals_current"] = True
                if int(_d.get("comp_count") or _d.get("mv_comp_count") or 0) < 2:
                    _d["whatnot_heat_score"] = max(0.0, float(_d.get("whatnot_heat_score") or 0.0) - 6.0)
                    _d["commercial_signal_score"] = max(0.0, float(_d.get("commercial_signal_score") or 0.0) - 4.0)
                print(
                    f"[MV_CLONE_BLOCK] title={str(_d.get('title') or '')[:120]} "
                    f"current={_d.get('current_price')} review={_soft_mv}"
                )
                _stamp_research_only_price_check(_d)
            if str(_d.get("execution_decision") or "PASS").strip().upper() == "PASS":
                _d["execution_decision"] = "WATCH"
                _d["decision"] = "WATCH"
                _d["decision_reason"] = "thin_mv_or_no_target_bid"
            _target_bid_ready = bool(_d.get("bid_ceiling_ready")) or bool(_d.get("target_bid_ready"))
            _mv_resolved = bool(_d.get("mv_resolved")) or bool(_d.get("mv_valid")) or float(_d.get("mv_value") or _d.get("market_value") or 0.0) > 0
            _comp_count = int(_d.get("comp_count") or _d.get("mv_comp_count") or 0)
            _mv_source = str(_d.get("mv_source") or _d.get("market_value_source") or "").strip().lower()
            _fallback_mv = "fallback" in _mv_source
            print(
                f"[SOFT_WATCHLIST] title={str(_d.get('title') or '')[:140]} "
                f"reason={str(_d.get('_soft_watchlist_reason') or 'thin_mv_or_no_target_bid')} "
                f"target_bid={_d.get('target_bid')}"
            )
        # GENERIC_PREMIUM_JUNK and COMMODITY are always hidden from the board
        _chase_class_block = bool(
            _chase_class_d in {"GENERIC_PREMIUM_JUNK", "COMMODITY"}
            or _mem_junk_d
            or _vet_non_chase_d
        )
        # PATCH 8: track per-reason drop counts for [VISIBLE_CHASE_GATE]
        if _chase_class_block:
            if _mem_junk_d:
                _vcg_dropped_mem += 1
            elif _vet_non_chase_d:
                _vcg_dropped_veteran += 1
            else:
                _vcg_dropped_junk += 1
        else:
            _vcg_kept += 1
        # PATCH 6: ENDGAME_CHASE rows can become sniper; PREMIUM_SECONDARY watchlist-only
        # (additional restriction: PREMIUM_SECONDARY needs stronger comp/edge for sniper)
        _is_endgame_chase = _chase_class_d == "ENDGAME_CHASE"
        _is_premium_secondary = _chase_class_d == "PREMIUM_SECONDARY"
        _watch_salvage_candidate = bool(_is_watchlist_salvage_candidate(_d))
        if _watch_salvage_candidate:
            _watch_salvage_candidates += 1
        _monitor_candidate = bool(
            _final_monitor_eligible(_d)
            and _identity_clean
            and _not_junk
            and not _suppressed
            and _rescue == "none"
            and float(_d.get("edge_pct") or _d.get("edge_percent") or 0.0) < 0.0
        )
        _review_watch_candidate = bool(
            _review_watchlist_eligible(_d)
            and _identity_clean
            and _not_junk
            and not _suppressed
            and _rescue == "none"
            and not _commodity_watch_block
            and not _product_tier_block
            and not _chase_class_block
        )
        _watchlist_quality = _watchlist_quality_floor_decision(_d, emit_log=True)
        _watchlist_quality_ok = bool(_watchlist_quality.get("allow"))
        _commercial_review_floor_required = _review_fallback_commercial_floor_applies(_d)
        _commercial_review_floor_ok = True
        _commercial_review_floor_reason = "not_applicable"
        if _commercial_review_floor_required:
            _commercial_review_floor_ok, _commercial_review_floor_reason = _passes_commercial_review_floor(_d)
            if not _commercial_review_floor_ok:
                _stamp_commercial_review_floor_fail(_d, _commercial_review_floor_reason, caller="admission_classify")
                _soft_watchlist = False
                _watch_salvage_candidate = False
                _review_watch_candidate = False
                _watchlist_quality_ok = False
        if _review_watch_candidate:
            _d["_review_watchlist"] = True
            _d["_review_watchlist_reason"] = "premium_review_estimate"
            _d["execution_decision"] = "WATCH"
            _d["decision"] = "WATCH"
            _d["decision_reason"] = "premium_review_estimate"
            _cw_ok, _cw_reason = _is_commercial_watchlist_row(_d)
            if _cw_ok:
                print(
                    f"[COMMERCIAL_WATCH_KEEP] title={str(_d.get('title') or '')[:120]} "
                    f"reason={_cw_reason} review={_d.get('review_estimate_value')} bid={_d.get('target_bid')}"
                )
            else:
                # Flag for UI-side secondary demotion; engine still surfaces but marked weak
                _d["_commercial_watch_weak"] = True
                _d["_commercial_watch_weak_reason"] = _cw_reason
                print(
                    f"[COMMERCIAL_WATCH_DEMOTE] title={str(_d.get('title') or '')[:120]} "
                    f"reason={_cw_reason} review={_d.get('review_estimate_value')} bid={_d.get('target_bid')}"
                )
            print(
                f"[REVIEW_WATCHLIST] title={str(_d.get('title') or '')[:120]} "
                f"review={_d.get('review_estimate_value')} bid={_d.get('target_bid')}"
            )
        _watch_candidate = bool(
            (bool(_d.get("_rescued_watchlist")) or _watch_salvage_candidate or _review_watch_candidate or str(_endgame_gate.get("admission_decision") or "") == "watch" or _mv_truth_decision == "watch" or _soft_watchlist)
            and (bool(_confidence_gate.get("allow_watch")) or _soft_watchlist or _review_watch_candidate)
            and _identity_clean
            and _not_junk
            and not _suppressed
            and _rescue == "none"
            and (_premium_secondary_floor or _mv_truth_decision == "watch" or _soft_watchlist or _review_watch_candidate)
            and (_target_bid_ready or _mv_truth_decision == "watch" or _soft_watchlist or _review_watch_candidate)
            and not _commodity_watch_block
            and not _product_tier_block  # PATCH 2
            and not _chase_class_block    # PATCHES 5+6: GENERIC_PREMIUM_JUNK/COMMODITY blocked
            and _watchlist_quality_ok
        )
        if _premium_force_visible and _identity_clean and _not_junk and not _suppressed and _rescue == "none":
            _watch_candidate = bool(_watchlist_quality_ok)
        _prepare_candidate = bool(
            (_exact_surface or bool(_endgame_gate.get("sniper_candidate")))
            and bool(_confidence_gate.get("allow_execute"))
            and _identity_clean
            and _mv_resolved
            and _price > 0
            and (_edge_dollars >= 8.0 or bool(_endgame_gate.get("sniper_candidate")))
            and _target_bid_ready
            and (_comp_count >= 2 or bool(_endgame_gate.get("sniper_candidate")))
            and (_commercial_bucket in {"MID", "STRONG"} or bool(_endgame_gate.get("sniper_candidate")))
            and not _commercially_suppressed
            and not _commodity_suppressed_d
            and not _commodity_watch_block
            and not _product_tier_block  # PATCH 2
            and not _chase_class_block    # PATCHES 5+6
            and (_premium_secondary_floor or bool(_endgame_gate.get("sniper_candidate")))
            and _mv_source != "price_anchor_fallback"
            and _not_junk
            and not _suppressed
            and _rescue == "none"
            and not _single_comp_clone_block
        )
        _hero_candidate = bool(
            not _single_comp_clone_block
            and (
                (
                    _prepare_candidate
                    and bool(_d.get("is_actionable_bid"))
                    and bool(_confidence_gate.get("allow_sniper"))
                    and _commercial_bucket in {"ELITE", "STRONG"}
                    and _mv_source != "price_anchor_fallback"
                    and _comp_count >= 3
                    and _mv_conf in {"HIGH", "MEDIUM"}
                    and not _commodity_suppressed_d  # commodity rows never reach hero
                )
                or bool(_endgame_gate.get("sniper_candidate"))
            )
        )
        _hero_soft_reject = bool(
            not _hero_candidate
            and not _commercially_suppressed
            and _mv_source != "price_anchor_fallback"
            and _comp_count >= 2
            and _mv_resolved
            and _target_bid_ready
            and (
                _commercial_bucket == "MID"
                or _edge_dollars < 8.0
                or (_common_insert and not _commercially_suppressed and _fallback_mv)
            )
        )
        _d["hero_rejected"] = bool(_d.get("hero_rejected") or _hero_soft_reject)
        if _d["hero_rejected"] and not str(_d.get("hero_reject_reason") or "").strip():
            _d["hero_reject_reason"] = "not_hero_quality"
        _elite_low_dollar_exception = bool(
            _price >= 6.0
            and _score >= 76.0
            and _commercial >= 26.0
            and _edge_dollars >= 15.0
            and _target_bid_ready
            and _mv_resolved
            and _bid_conf in {"HIGH", "MEDIUM", "REVIEW"}
            and bool(_d.get("is_actionable_bid"))
        )
        if not _not_junk:
            _reason_key = "junk"
        elif bool(_d.get("_rescued_watchlist")):
            _reason_key = ""
        elif _premium_force_visible:
            _reason_key = ""
        elif _mv_truth_decision == "hidden" and not _soft_watchlist:
            _reason_key = "low_trust"
        elif _commercially_suppressed:
            _reason_key = "low_trust"
        elif _commodity_watch_block:
            _reason_key = "junk"
        elif _product_tier_block:
            # PATCH 2: LOW/MID rows without serial/auto/scarcity support — hard excluded
            _reason_key = "junk"
        elif _chase_class_block:
            # PATCHES 5+6: GENERIC_PREMIUM_JUNK / COMMODITY / mem_junk / veteran_non_chase
            _reason_key = "junk"
        elif _commercial_bucket == "WEAK" and not bool(_d.get("_fallback_promoted")):
            _reason_key = "low_trust"
        elif _mv_source == "price_anchor_fallback" and not bool(_d.get("_fallback_promoted")):
            _reason_key = "low_trust"
        elif bool(_confidence_gate.get("force_drop")) and not _soft_watchlist:
            _reason_key = "low_trust"
        elif _comp_count < 1 and not _soft_watchlist and not bool(_d.get("_fallback_promoted")):
            _reason_key = "low_trust"
        elif _monitor_candidate:
            _reason_key = ""
        elif _edge_dollars < 4.0:
            _reason_key = "weak_edge"
        elif _price <= 3.0 and _edge_dollars < 8.0:
            _reason_key = "low_value"
        elif _common_insert and _fallback_mv and not _has_support:
            _reason_key = "low_trust"
        elif _review_watch_candidate or _watch_candidate or _prepare_candidate or _hero_candidate:
            _reason_key = ""
        elif not _identity_clean or _suppressed or _rescue != "none" or ((not _target_bid_ready or not _mv_resolved) and not _soft_watchlist):
            _reason_key = "low_trust"
        elif _edge_pct <= 0.0 and _edge_dollars <= 0.0:
            _reason_key = "weak_edge"
        else:
            _reason_key = ""
        _visible_survival = bool(
            _identity_clean
            and _visible_survival_product_ok(_d)
            and _not_junk
            and not _suppressed
            and _rescue == "none"
            and _has_any_valuation_anchor(_d)
            and (not _commercial_review_floor_required or _commercial_review_floor_ok)
        )
        _final_admission_ok, _final_admission_reason = _final_admission_contract(_d, emit_log=True)
        _review_board_ok = _review_board_visible(_d, emit_log=True)
        if _visible_survival:
            _d["_visible_survival"] = True
            print(
                f"[VISIBLE_SURVIVAL] title={str(_d.get('title') or '')[:120]} "
                f"anchor=1 reason={_reason_key or 'visible'}"
            )
            if not (_hero_candidate or _prepare_candidate or _monitor_candidate or _watch_candidate):
                _watch_candidate = True
                _d["_visible_route"] = "WATCHLIST_VISIBLE"
            if _reason_key in {"low_value", "low_trust", "weak_edge"}:
                _reason_key = ""
                _watch_candidate = True
                _d["_visible_route"] = "WATCHLIST_VISIBLE"
                print(
                    f"[VISIBLE_ROUTE] title={str(_d.get('title') or '')[:120]} "
                    f"route={str(_d.get('_visible_route') or 'WATCHLIST_VISIBLE')}"
                )
        if _reason_key and (_final_admission_ok or _review_board_ok) and (not _commercial_review_floor_required or _commercial_review_floor_ok):
            _reason_key = ""
            _watch_candidate = True
            _d["_review_watchlist"] = True
            _d["_review_watchlist_reason"] = str(_d.get("_review_watchlist_reason") or "final_admission_contract")
            _d["_visible_route"] = str(_d.get("_visible_route") or "WATCHLIST_VISIBLE")
            print(
                f"[SUPPRESSION_OVERRIDE] title={str(_d.get('title') or '')[:120]} "
                f"route={str(_d.get('_visible_route') or 'WATCHLIST_VISIBLE')}"
            )
        _late_keep, _late_reason = _is_late_hydrated_tier_b_survivor(_d)
        _late_drop_candidates = [
            str(_commodity_reason or "").strip().lower(),
            str((_confidence_gate or {}).get("review_reason") or "").strip().lower(),
            str((_confidence_gate or {}).get("review_execution_final") or "").strip().lower(),
            str((_confidence_gate or {}).get("reason") or "").strip().lower(),
            str(_d.get("execution_decision") or _d.get("decision") or "").strip().lower(),
            str(_reason_key or "").strip().lower(),
        ]
        _late_drop_reason = next(
            (
                _candidate
                for _candidate in _late_drop_candidates
                if _candidate in {"commodity_lane", "not_review_promoted", "pass", "spillover_drop"}
            ),
            str(_reason_key or "").strip().lower(),
        )
        _keep_row = not bool(_reason_key)
        if (
            not _keep_row
            and _late_keep
            and _late_drop_reason in {
                "commodity_lane",
                "not_review_promoted",
                "pass",
                "spillover_drop",
            }
        ):
            _keep_row = True
            _reason_key = ""
            _watch_candidate = True
            _prepare_candidate = False
            _hero_candidate = False
            _monitor_candidate = False
            _d["_watch_candidate"] = True
            _d["_prepare_candidate"] = False
            _d["_hero_candidate"] = False
            _d["_monitor_candidate"] = False
            _d["_rescued_watchlist"] = True
            _d["_late_tier_b_rescue"] = True
            _d["_late_tier_b_rescue_reason"] = _late_reason
            _d["surface_intent"] = "watchlist"
            _d["execution_decision"] = "WATCH"
            _d["decision"] = "WATCH"
            _d["decision_reason"] = "tier_b_liquid_survivor"
            _d["_visible_route"] = str(_d.get("_visible_route") or "LATE_TIER_B_RESCUE")
            print(
                f"[LATE_TIER_B_RESCUE] title={str((_d or {}).get('title') or '')[:160]} "
                f"lane_type={_d.get('lane_type')} "
                f"insert_family={_d.get('insert_family')} "
                f"parallel_family={_d.get('parallel_family')} "
                f"card_number={_d.get('card_number')} "
                f"grade={_d.get('grade')} "
                f"tier={_d.get('subscription_lane_tier')} "
                f"reason={_late_reason}"
            )
        print(
            f"[FINAL_DROP_TRACE] title={str((_d or {}).get('title') or '')[:160]} "
            f"keep_row={_keep_row} "
            f"drop_reason={_late_drop_reason} "
            f"tier={_d.get('subscription_lane_tier')} "
            f"lane_type={_d.get('lane_type')} "
            f"insert_family={_d.get('insert_family')} "
            f"parallel_family={_d.get('parallel_family')} "
            f"card_number={_d.get('card_number')} "
            f"grade={_d.get('grade')} "
            f"late_rescue={_d.get('_late_tier_b_rescue')}"
        )
        if _reason_key:
            print(
                f"[SUPPRESSION_KEEP] title={str(_d.get('title') or '')[:120]} "
                f"reason={_reason_key}"
            )
            print(
                f"[VISIBLE_DROP_BLOCK] title={str(_d.get('title') or '')[:120]} "
                f"reason={_reason_key}"
            )
            _admission_hidden_counts[_reason_key] = int(_admission_hidden_counts.get(_reason_key, 0) or 0) + 1
            _d["execution_admission_bucket"] = "hidden"
            if _mem_junk_d:
                _d["hidden_reason"] = "generic_mem_junk"
            elif _mv_truth_reason:
                _d["hidden_reason"] = _mv_truth_reason
            _d["execution_admission_reason"] = {
                "low_value": "Hidden — commercial value too low",
                "low_trust": "Hidden — bid trust/support too weak",
                "weak_edge": "Hidden — edge too thin after friction",
                "junk": "Hidden — noisy inventory",
            }.get(_reason_key, "Hidden")
            if _mem_junk_d:
                _d["execution_admission_reason"] = "Hidden — generic memorabilia junk"
            if _mv_truth_reason == "anchor_only_no_real_mv":
                _d["execution_admission_reason"] = "Hidden — anchor-only pricing has no trusted market value"
            _d["commercially_visible"] = False
            _d["commercial_visibility_reason"] = _d["execution_admission_reason"]
            print(
                f"[EARLY_CONTINUE_TRACE] title={str((_d or {}).get('title') or '')[:160]} "
                f"reason={_late_drop_reason or _reason_key or 'unknown'} "
                f"tier={_d.get('subscription_lane_tier')} "
                f"early_rescue={_d.get('_early_tier_b_rescue')}"
            )
            continue
        if _elite_low_dollar_exception:
            _d["floor_exception"] = True
            _d["floor_exception_reason"] = "Elite execution exception — low-dollar but strong executable edge"
        _d["_watch_candidate"] = _watch_candidate
        _d["_review_watch_candidate"] = _review_watch_candidate
        _d["_monitor_candidate"] = _monitor_candidate
        _d["_prepare_candidate"] = _prepare_candidate
        _d["_hero_candidate"] = _hero_candidate
        _d["sniper_candidate"] = bool(_d.get("sniper_candidate") or _endgame_gate.get("sniper_candidate")) and not _single_comp_clone_block
        if _single_comp_clone_block:
            _d["_monitor_candidate"] = True
            _d["_prepare_candidate"] = False
            _d["_hero_candidate"] = False
            _d["hero_board_eligible"] = False
            _d["hero_tier"] = ""
            _d["execution_decision"] = "WATCH"
            _d["decision"] = "WATCH"
            _log_hero_assert(_d)
        _d["endgame_sniper_admission"] = str(_d.get("endgame_sniper_admission") or _endgame_gate.get("admission_decision") or "")
        # BOARD TRUST GATE: pure fallback REVIEW rows with zero real edge never reach the board
        _frd_tier = str(_d.get("valuation_truth_tier") or "").strip().upper()
        _frd_mv_true = _d.get("market_value_true")
        _frd_edge = float(_d.get("edge_pct") or _d.get("edge_percent") or 0.0)
        _frd_actionable = bool(_d.get("is_actionable_bid"))
        _frd_mv_src = str(_d.get("mv_source") or _d.get("market_value_source") or "").strip().lower()
        _fallback_review_dead = bool(
            not bool(_d.get("_fallback_promoted"))  # SPECULATIVE fallback-promoted rows bypass this gate
            and _frd_tier != "TRUE"
            and not _frd_mv_true
            and _frd_edge <= 0.0
            and not _frd_actionable
            and (
                "fallback" in _frd_mv_src
                or _frd_mv_src in {"soft_watchlist_estimate", "price_anchor_fallback", "review_estimate", "none", ""}
            )
        )
        if _fallback_review_dead:
            _d["execution_admission_bucket"] = "hidden"
            _d["commercially_visible"] = False
            _d["board_visible"] = False
            _d["hidden_reason"] = "fallback_review_dead"
            _d["execution_admission_reason"] = "Hidden — fallback REVIEW with zero edge"
            _d["commercial_visibility_reason"] = _d["execution_admission_reason"]
            _admission_hidden_counts["low_trust"] = int(_admission_hidden_counts.get("low_trust", 0) or 0) + 1
            print(
                f"[FALLBACK_REVIEW_DEAD] title={str(_d.get('title',''))[:140]} "
                f"mv_src={_frd_mv_src} edge_pct={_frd_edge} tier={_frd_tier}"
            )
            continue
        # ── COMMERCIAL VIABILITY FLOOR ──────────────────────────────────────────────
        # Cards below these thresholds cannot produce meaningful profit and must not
        # reach the board regardless of valuation quality.
        # Exemption: rows already flagged as premium force-visible, endgame/elite,
        # OR fallback-promoted (SPECULATIVE path) — their value is structural.
        #
        # NOTE: For REVIEW/soft-watchlist rows, market_value_true is zeroed by design
        # and review_estimate_value carries the anchor. Use review_estimate as MV fallback
        # so the floor uses the correct price signal.
        _cvf_mv = _safe_float(_d.get("market_value_true") or _d.get("true_market_value"))
        if not _cvf_mv or _cvf_mv <= 0:
            _cvf_mv = _safe_float(_d.get("review_estimate_value") or _d.get("anchored_estimate_value"))
        _cvf_bid = _safe_float(_d.get("target_bid") or _d.get("bid_ceiling_value") or _d.get("adjusted_max_bid"))
        _cvf_price = _safe_float(_d.get("current_price") or _d.get("current_bid") or _d.get("price")) or 0.0
        _cvf_profit = (
            _safe_float(_d.get("edge_dollars") or (_d.get("action_summary") or {}).get("expected_profit"))
            or ((_cvf_mv - _cvf_price) if _cvf_mv and _cvf_mv > 0 else None)
        )
        _cvf_exempt = bool(
            _premium_force_visible
            or str(_d.get("endgame_tier") or "").strip().lower() == "endgame"
            or str(_d.get("commercial_bucket") or "").strip().upper() == "ELITE"
            or bool(_d.get("_fallback_promoted"))   # SPECULATIVE path: structural signal overrides dollar floor
        )
        # Absolute baseline override: any row with real MV > 0 AND target_bid > 0 AND not junk
        # is allowed to reach the board. This is the minimum viable admission rule.
        if not _cvf_exempt and _cvf_mv and _cvf_mv > 0 and _cvf_bid and _cvf_bid > 0 and _not_junk and _identity_clean:
            _cvf_exempt = True
            print(
                f"[BASIC_VIABLE_ADMIT] title={str(_d.get('title',''))[:120]} "
                f"mv={_cvf_mv:.2f} bid={_cvf_bid:.2f} — basic viable override"
            )
        if not _cvf_exempt:
            _cvf_fail_reason = (
                f"mv_too_low:{_cvf_mv:.2f}" if (_cvf_mv is not None and _cvf_mv < 20.0)
                else f"bid_too_low:{_cvf_bid:.2f}" if (_cvf_bid is not None and _cvf_bid < 10.0)
                else f"profit_too_low:{_cvf_profit:.2f}" if (_cvf_profit is not None and _cvf_profit < 15.0)
                else ""
            )
            if _cvf_fail_reason:
                _d["execution_admission_bucket"] = "hidden"
                _d["commercially_visible"] = False
                _d["board_visible"] = False
                _d["hidden_reason"] = "commercial_viability_floor"
                _d["execution_admission_reason"] = f"Hidden — below commercial viability floor ({_cvf_fail_reason})"
                _d["commercial_visibility_reason"] = _d["execution_admission_reason"]
                _admission_hidden_counts["low_value"] = int(_admission_hidden_counts.get("low_value", 0) or 0) + 1
                print(
                    f"[COMMERCIAL_FLOOR_DROP] title={str(_d.get('title',''))[:140]} "
                    f"mv={_cvf_mv} bid={_cvf_bid} profit={_cvf_profit} reason={_cvf_fail_reason}"
                )
                continue
        _maybe_apply_real_live_actionable_rescue(_d, stage="pre_final_classify")
        _admission_candidates.append(_d)

    _admission_candidates.sort(
        key=lambda _d: (
            -float(_d.get("execution_admission_score") or 0.0),
            {"HIGH": 0, "MEDIUM": 1, "REVIEW": 2, "NONE": 3}.get(str(_d.get("bid_ceiling_confidence") or "NONE").upper(), 3),
            -float(_d.get("sniper_board_score") or 0.0),
            -float(_d.get("execution_score") or 0.0),
            float(_row_remaining_seconds(_d) or 999999.0),
        )
    )
    # ── BOARD TIER CLASSIFICATION ────────────────────────────────────────────────
    # Stamp every admission candidate with a decision tier and urgency weight
    # BEFORE routing so EXECUTE_NOW rows get first access to sniper slots.
    #   EXECUTE_NOW     — edge ≥ $150 AND premium lane (massive opportunity)
    #   SNIPER_CANDIDATE — edge ≥ $40  (real flip, act soon)
    #   PREPARE_WATCH   — everything else
    _BOARD_TIER_RANK: Dict[str, int] = {"EXECUTE_NOW": 0, "SNIPER_CANDIDATE": 1, "PREPARE_WATCH": 2}
    for _d in _admission_candidates:
        _bt_edge = float(_d.get("edge_dollars") or (_d.get("action_summary") or {}).get("expected_profit") or 0.0)
        _bt_title = str(_d.get("title") or _d.get("source_title") or "").lower()
        _bt_lane = str(_d.get("target_lane_type") or _d.get("spec_lane_class") or "").strip().lower()
        _bt_is_premium_lane = bool(
            _bt_lane not in {"product_base", "broad_fallback", "base", ""}
            or any(_t in _bt_title for _t in (
                "/10", "/25", "/49", "/50", "rpa", "patch auto",
                "national treasures", "immaculate", "flawless", "1/1", "/5 ", "/1 "
            ))
        )
        _bt_single_comp_clone_block = _stamp_single_comp_clone_hero_block(_d)
        if _bt_single_comp_clone_block:
            _bt_tier = "PREPARE_WATCH"
        elif _bt_edge >= 150.0 and _bt_is_premium_lane:
            _bt_tier = "EXECUTE_NOW"
        elif _bt_edge >= 40.0:
            _bt_tier = "SNIPER_CANDIDATE"
        else:
            _bt_tier = "PREPARE_WATCH"
        # Urgency weight: higher = more urgent = ranks first within tier
        _bt_secs = _row_remaining_seconds(_d)
        try:
            _bt_secs_f = float(_bt_secs) if _bt_secs is not None else 999999.0
        except (TypeError, ValueError):
            _bt_secs_f = 999999.0
        if _bt_secs_f <= 1800:          # 0-30 min
            _bt_urgency = 100
        elif _bt_secs_f <= 3600:        # 30 min - 1 h
            _bt_urgency = 85
        elif _bt_secs_f <= 10800:       # 1 h - 3 h
            _bt_urgency = 70
        elif _bt_secs_f <= 21600:       # 3 h - 6 h
            _bt_urgency = 50
        elif _bt_secs_f <= 86400:       # 6 h - 24 h
            _bt_urgency = 25
        else:                           # > 24 h
            _bt_urgency = 5
        _d["_board_tier"] = _bt_tier
        _d["_urgency_weight"] = _bt_urgency
        _d["_board_tier_rank"] = _BOARD_TIER_RANK[_bt_tier]
        print(
            f"[BOARD_TIER_ASSIGNMENT] tier={_bt_tier} edge=${_bt_edge:.2f} "
            f"premium_lane={_bt_is_premium_lane} urgency={_bt_urgency} "
            f"secs={_bt_secs_f:.0f} title={_bt_title[:100]}"
        )
        print(
            f"[URGENCY_WEIGHT] weight={_bt_urgency} secs={_bt_secs_f:.0f} "
            f"({_bt_secs_f / 3600:.1f}h) title={_bt_title[:100]}"
        )
        if _bt_single_comp_clone_block:
            _log_hero_assert(_d)
    # Re-sort: EXECUTE_NOW first, then SNIPER_CANDIDATE, then PREPARE_WATCH.
    # Within each tier: most urgent first, then highest edge.
    _admission_candidates.sort(
        key=lambda _d: (
            int(_d.get("_board_tier_rank") or 2),
            -int(_d.get("_urgency_weight") or 0),
            -float(_d.get("edge_dollars") or (_d.get("action_summary") or {}).get("expected_profit") or 0.0),
        )
    )
    _sniper_target = 5 if len(_admission_candidates) >= 10 else (4 if len(_admission_candidates) >= 6 else min(3, len(_admission_candidates)))
    _sniper_rows: List[Dict[str, Any]] = []
    _watchlist_rows: List[Dict[str, Any]] = []
    _monitor_rows: List[Dict[str, Any]] = []

    for _d in _admission_candidates:
        if bool((_d or {}).get("_authoritative_feed_seed") or (_d or {}).get("_rescued_from_authoritative_window")):
            _d = _normalize_row_price_fields(_d, stage="execution_admission_price_math")
        _score = float(_d.get("execution_admission_score") or 0.0)
        _bid_conf = str(_d.get("bid_ceiling_confidence") or _d.get("target_bid_confidence") or "NONE").strip().upper()
        _is_actionable = bool(_d.get("is_actionable_bid"))
        _watch_candidate = bool(_d.get("_watch_candidate"))
        _monitor_candidate = bool(_d.get("_monitor_candidate"))
        _prepare_candidate = bool(_d.get("_prepare_candidate"))
        _hero_candidate = bool(_d.get("_hero_candidate"))
        _sniper_candidate = bool(_d.get("sniper_candidate"))
        _single_comp_clone_block = _stamp_single_comp_clone_hero_block(_d)
        if _single_comp_clone_block:
            _hero_candidate = False
            _prepare_candidate = False
            _sniper_candidate = False
            _d["_hero_candidate"] = False
            _d["_prepare_candidate"] = False
            _d["sniper_candidate"] = False
            _d["hero_board_eligible"] = False
            _d["hero_tier"] = ""
            _log_hero_assert(_d)
        # PATCH 6: ENDGAME_CHASE can snipe normally; PREMIUM_SECONDARY needs stronger conditions
        _d_chase_class = str(_d.get("chase_class") or "COMMODITY").strip().upper()
        _d_is_endgame_chase = _d_chase_class == "ENDGAME_CHASE"
        _d_is_premium_secondary = _d_chase_class == "PREMIUM_SECONDARY"
        _d_comp_count = int(_d.get("comp_count") or _d.get("mv_comp_count") or 0)
        _d_edge_dollars = float(_d.get("edge_dollars") or (_d.get("action_summary") or {}).get("expected_profit") or 0.0)
        # PREMIUM_SECONDARY must meet higher bar for sniper (comps≥4, edge≥$20) — otherwise watchlist only
        _premium_secondary_sniper_ok = bool(
            _d_is_endgame_chase
            or (_d_is_premium_secondary and _d_comp_count >= 4 and _d_edge_dollars >= 20.0)
        )
        # TRUE rows with valid comp-backed MV + target_bid bypass the commercial-bucket gate.
        # These rows have earned sniper eligibility through valuation signal, not commercial score.
        _is_true_comp_backed = bool(
            str(_d.get("valuation_truth_tier") or "").strip().upper() == "TRUE"
            and float(_d.get("true_market_value") or _d.get("market_value_true") or 0.0) > 0
            and float(_d.get("target_bid") or 0.0) > 0
            and int(_d.get("comp_count") or _d.get("usable_comp_count") or 0) >= 1
            and not _single_comp_clone_block
        )
        _sniper_like = bool(
            len(_sniper_rows) < _sniper_target
            and not _single_comp_clone_block
            and (
                _sniper_candidate
                or
                (_hero_candidate and _premium_secondary_sniper_ok)
                or (_prepare_candidate and _score >= 56.0 and _premium_secondary_sniper_ok)
                or (_is_actionable and _hero_candidate and _bid_conf in {"HIGH", "MEDIUM", "REVIEW"} and _premium_secondary_sniper_ok)
                or bool(_d.get("hero_board_eligible"))
                or _is_true_comp_backed  # TRUE + comp-backed MV → always sniper-eligible
            )
        )
        # ── URGENCY GATE ────────────────────────────────────────────────────────────
        # Sniper Board is an immediate-action surface. Cards ending in >6 hours are
        # not actionable right now — demote them to watchlist so the hero experience
        # stays urgent. Endgame-tier rows are exempt (structural chase value).
        if _sniper_like:
            _urg_secs = _row_remaining_seconds(_d)
            try:
                _urg_secs_f = float(_urg_secs) if _urg_secs is not None else 999999.0
            except (TypeError, ValueError):
                _urg_secs_f = 999999.0  # unknown time → treat as far-future, never promote to sniper
            _urg_endgame_exempt = bool(
                str(_d.get("endgame_tier") or "").strip().lower() == "endgame"
                or _d_is_endgame_chase
            )
            _URGENCY_SNIPER_MAX_SECS = 21600  # 6 hours
            if not _urg_endgame_exempt and _urg_secs_f > _URGENCY_SNIPER_MAX_SECS:
                _sniper_like = False
                print(
                    f"[URGENCY_DEMOTE] title={str(_d.get('title', ''))[:120]} "
                    f"secs={_urg_secs_f:.0f} ({_urg_secs_f / 3600:.1f}h) — demoted sniper→watchlist"
                )
        # PATCH 5: fallback lane cap — max 20% of board, must pass floor (price≥50 or serial or auto)
        _d_is_fallback = str(_d.get("target_lane_type") or _d.get("spec_lane_class") or "").strip().lower() in {"product_base", "broad_fallback"}
        if _d_is_fallback:
            _d_price = _coerce_price_scalar(_d.get("current_price") or _d.get("current_bid") or 0.0)
            if _d_price is None:
                print(f"[PRICE_SCALAR_ASSERT] stage=fallback_lane_cap_missing_scalar title={str(_d.get('title') or '')[:160]} current_price={_d.get('current_price')} current_price_type={type(_d.get('current_price')).__name__ if _d.get('current_price') is not None else 'None'} authoritative_current_price={_d.get('authoritative_current_price')} authoritative_current_price_type={type(_d.get('authoritative_current_price')).__name__ if _d.get('authoritative_current_price') is not None else 'None'} _board_current_price={_d.get('_board_current_price')} _board_current_price_type={type(_d.get('_board_current_price')).__name__ if _d.get('_board_current_price') is not None else 'None'} rescued_source_current_price={_d.get('_rescued_source_current_price')} rescued_source_current_price_type={type(_d.get('_rescued_source_current_price')).__name__ if _d.get('_rescued_source_current_price') is not None else 'None'}")
                _d_price = 0.0
            _d_has_serial = bool(str(_d.get("serial") or _d.get("serial_denominator") or "").strip())
            _d_has_auto = "auto" in str(_d.get("source_title") or _d.get("title") or "").lower()
            _d_fallback_ok = _d_price >= 50.0 or _d_has_serial or _d_has_auto
            if not _d_fallback_ok or _fallback_board_count >= _fallback_board_max:
                _fallback_blocked_count += 1
                continue
            _fallback_board_count += 1
        # ── URGENCY-AWARE COMMERCIAL SIGNIFICANCE GATE ──────────────────────────────
        # Cards inside the execution window must also be economically meaningful.
        # Urgency alone is not sufficient — a $3 card ending in 60 seconds is not a
        # board opportunity. This gate fires before all three append paths.
        _UCF_MIN_TRUE_MV = 15.0       # minimum market value worth surfacing
        _UCF_MIN_TARGET_BID = 10.0    # minimum bid worth placing
        _UCF_MIN_EDGE_DOLLARS = 5.0   # minimum expected profit
        _UCF_WINDOW_SECS = 21600.0    # same 6-hour window as sniper eligibility
        _ucf_raw_secs = _row_remaining_seconds(_d)
        try:
            _ucf_secs_f = float(_ucf_raw_secs) if _ucf_raw_secs is not None else 999999.0
        except (TypeError, ValueError):
            _ucf_secs_f = 999999.0
        _ucf_is_urgent = 0.0 < _ucf_secs_f <= _UCF_WINDOW_SECS
        _ucf_true_mv = float(_d.get("true_market_value") or _d.get("market_value_true") or 0.0)
        _ucf_target_bid = float(_d.get("target_bid") or 0.0)
        _ucf_edge_dollars = float(_d.get("edge_dollars") or (_d.get("action_summary") or {}).get("expected_profit") or 0.0)
        _ucf_current_price = _coerce_price_scalar(_d.get("current_price") or _d.get("current_bid") or 0.0)
        if _ucf_current_price is None:
            print(f"[PRICE_SCALAR_ASSERT] stage=urgent_commercial_filter_missing_scalar title={str(_d.get('title') or '')[:160]} current_price={_d.get('current_price')} current_price_type={type(_d.get('current_price')).__name__ if _d.get('current_price') is not None else 'None'} authoritative_current_price={_d.get('authoritative_current_price')} authoritative_current_price_type={type(_d.get('authoritative_current_price')).__name__ if _d.get('authoritative_current_price') is not None else 'None'} _board_current_price={_d.get('_board_current_price')} _board_current_price_type={type(_d.get('_board_current_price')).__name__ if _d.get('_board_current_price') is not None else 'None'} rescued_source_current_price={_d.get('_rescued_source_current_price')} rescued_source_current_price_type={type(_d.get('_rescued_source_current_price')).__name__ if _d.get('_rescued_source_current_price') is not None else 'None'}")
            _ucf_current_price = 0.0
        _ucf_title_lower = str(_d.get("title") or _d.get("source_title") or "").lower()
        _ucf_exempt = bool(
            str(_d.get("endgame_tier") or "").strip().lower() == "endgame"
            or _d_is_endgame_chase
            or str(_d.get("commercial_bucket") or "").strip().upper() in {"ELITE", "STRONG"}
            or bool(str(_d.get("serial") or _d.get("serial_denominator") or "").strip())
            or "auto" in _ucf_title_lower
            or "rpa" in _ucf_title_lower
            or bool(_d.get("_fallback_promoted"))
        )
        _ucf_passes_floor = bool(
            _ucf_true_mv >= _UCF_MIN_TRUE_MV
            or _ucf_target_bid >= _UCF_MIN_TARGET_BID
            or _ucf_edge_dollars >= _UCF_MIN_EDGE_DOLLARS
        )
        _ucf_drop = _ucf_is_urgent and not _ucf_exempt and not _ucf_passes_floor
        print(
            f"[URGENT_COMMERCIAL_FILTER] title={_ucf_title_lower[:100]} "
            f"current_price={_ucf_current_price:.2f} true_mv={_ucf_true_mv:.2f} "
            f"target_bid={_ucf_target_bid:.2f} edge_dollars={_ucf_edge_dollars:.2f} "
            f"urgent_window={'YES' if _ucf_is_urgent else 'NO'} secs={_ucf_secs_f:.0f} "
            f"admit_or_drop={'DROP' if _ucf_drop else 'ADMIT'} "
            f"reason={'below_commercial_floor' if _ucf_drop else ('exempt' if _ucf_exempt else ('passes_floor' if _ucf_passes_floor else 'not_urgent'))}"
        )
        if _ucf_drop:
            continue
        if _sniper_like:
            _append_bound_board_row_to_many([_sniper_rows], _d, append_tag="strict_visible_sniper")
            continue
        if len(_watchlist_rows) < _ES_MAX_WATCHLIST_ROWS and _watchlist_quality_ok and (_watch_candidate or _prepare_candidate or bool(_d.get("_rescued_watchlist")) or bool(_d.get("_review_watchlist"))):
            _append_bound_board_row_to_many([_watchlist_rows], _d, append_tag="strict_visible_watchlist")
            continue
        if _monitor_candidate:
            _append_bound_board_row_to_many([_monitor_rows], _d, append_tag="strict_visible_monitor")

    if len(_sniper_rows) + len(_watchlist_rows) + len(_monitor_rows) > _ES_MAX_VISIBLE_BOARD_ROWS:
        _overflow = max(0, len(_sniper_rows) + len(_watchlist_rows) + len(_monitor_rows) - _ES_MAX_VISIBLE_BOARD_ROWS)
        if _overflow > 0 and _monitor_rows:
            _trim = min(_overflow, len(_monitor_rows))
            _monitor_rows = _monitor_rows[: max(0, len(_monitor_rows) - _trim)]
            _overflow -= _trim
        if _overflow > 0 and _watchlist_rows:
            _watchlist_rows = _watchlist_rows[: max(0, len(_watchlist_rows) - _overflow)]

    _strict_rows = list(_sniper_rows) + list(_watchlist_rows) + list(_monitor_rows)
    _strict_ids = {
        str(_d.get("item_id") or _d.get("source_item_id") or id(_d))
        for _d in _strict_rows
    }
    _board_recovered_rows: List[Dict[str, Any]] = []
    _survivor_pool: List[Dict[str, Any]] = []
    if len(_strict_rows) < 3:
        for _d in filtered_auctions:
            _rid = str(_d.get("item_id") or _d.get("source_item_id") or id(_d))
            if _rid in _strict_ids:
                continue
            if not _board_recovery_eligible(_d):
                continue
            if _is_unresolved_no_trusted_mv(_d):
                continue
            if bool(_d.get("memorabilia_junk")) or bool(_d.get("veteran_non_chase")):
                continue
            if bool(_d.get("commodity_suppressed")) or bool(_d.get("commercially_suppressed")):
                continue
            _survivor_pool.append(_d)

        def _board_recovery_rank_key(_row: Dict[str, Any]) -> tuple:
            _title = str(_row.get("title") or _row.get("source_title") or "").lower()
            _exact_anchor_score = (
                2 if bool(_row.get("entity_exact_match") or _row.get("exact_entity_match"))
                else 1 if bool(_row.get("tracked_anchor") or _row.get("_target_match_relaxed"))
                else 0
            )
            _signal_count = _commercial_listing_signal_count(_row)
            _remaining_val = _row.get("seconds_remaining")
            if _remaining_val is None:
                _remaining_val = _row_remaining_seconds(_row)
            try:
                _remaining = float(_remaining_val) if _remaining_val is not None else 999999.0
            except (TypeError, ValueError):
                _remaining = 999999.0
            _serial_patch_auto = 1 if (
                bool(str(_row.get("serial") or _row.get("serial_denominator") or _row.get("serial_bucket") or "").strip())
                or "patch" in _title
                or "auto" in _title
                or "autograph" in _title
                or "rpa" in _title
            ) else 0
            return (-_exact_anchor_score, -_signal_count, _remaining, -_serial_patch_auto)

        _recovery_limit = max(0, 8 - len(_strict_rows))
        for _d in sorted(_survivor_pool, key=_board_recovery_rank_key)[:_recovery_limit]:
            _d["_board_recovered"] = True
            _d["_board_recovery_reason"] = "commercial_survivor"
            _d["_board_row_source"] = "rescued_remainder"
            _d["_rescued_remainder"] = True
            _board_recovered_rows.append(_d)
            print(
                f"[BOARD_RECOVERY_ROW] title={str(_d.get('title') or '')[:140]} "
                f"reason={str(_d.get('_board_recovery_reason') or '')}"
            )
            print(
                f"[RESCUED_ROW] source=rescued_remainder "
                f"title={str(_d.get('title') or '')[:120]}"
            )
        if _board_recovered_rows:
            _watchlist_rows = _bound_board_rows(
                list(_watchlist_rows) + list(_board_recovered_rows),
                append_tag="board_recovered_watchlist_rows",
            )
    _fresh_support_rows = [
        _d for _d in (_sniper_rows + _watchlist_rows + _monitor_rows)
        if _valuation_source_clean(_d) in _SUPPORT_TRUTH_SOURCES and not bool(_d.get("_board_recovered"))
    ]
    for _d in _fresh_support_rows[:5]:
        print(
            f"[FRESH_SUPPORT_SURVIVE] title={str(_d.get('title') or '')[:120]} "
            f"truth={str(_d.get('valuation_truth_tier') or '')} bucket={str(_d.get('execution_admission_bucket') or '')}"
        )
    if _fresh_support_rows:
        print(
            f"[RESCUE_BACKUP_ONLY] fresh_support={len(_fresh_support_rows)} "
            f"rescued={len(_board_recovered_rows)}"
        )
    print(
        f"[BOARD_RECOVERY] strict_final={len(_strict_rows)} "
        f"survivor_pool={len(_survivor_pool)} recovered={len(_board_recovered_rows)}"
    )

    _admitted_ids = {
        str(_d.get("item_id") or _d.get("source_item_id") or id(_d))
        for _d in (_sniper_rows + _watchlist_rows + _monitor_rows)
    }
    for _d in filtered_auctions:
        _rid = str(_d.get("item_id") or _d.get("source_item_id") or id(_d))
        if _rid in _admitted_ids:
            _bucket = "sniper" if _d in _sniper_rows else "watchlist" if _d in _watchlist_rows else "monitor"
            _d["execution_admission_bucket"] = _bucket
            _d["commercial_visibility"] = _bucket
            _d["commercially_visible"] = True
            _d["board_visible"] = True
            _d["main_board_pool"] = "main_visible_rows"
            _d["commercial_visibility_reason"] = (
                "Admitted to sniper board — strongest executable setup"
                if _bucket == "sniper"
                else "Admitted to watchlist — executable but second tier" if _bucket == "watchlist"
                else "Admitted to monitor lane — comp-backed but currently over market"
            )
            _d["execution_admission_reason"] = _d["commercial_visibility_reason"]
            if bool(_d.get("_review_watchlist")) and _bucket != "sniper":
                _d["commercial_visibility_reason"] = "Admitted to review watchlist — premium review estimate"
                _d["execution_admission_reason"] = _d["commercial_visibility_reason"]
            if bool(_d.get("_board_recovered")) and _bucket != "sniper":
                _d["commercial_visibility_reason"] = "Recovered to board â€” commercial survivor"
                _d["execution_admission_reason"] = _d["commercial_visibility_reason"]
            if _bucket == "sniper" and not bool(_d.get("hero_board_eligible")):
                _d["hero_board_eligible"] = True
                _d["hero_tier"] = "ACTIONABLE_HERO" if bool(_d.get("is_actionable_bid")) else "SNIPER_CANDIDATE_HERO"
                _d["hero_reason"] = str(_d.get("hero_reason") or _d["commercial_visibility_reason"])
            if bool(_d.get("_board_recovered")) and _bucket != "sniper":
                _d["commercial_visibility_reason"] = "Recovered to board: commercial survivor"
                _d["execution_admission_reason"] = _d["commercial_visibility_reason"]
        else:
            if str(_d.get("execution_admission_bucket") or "") != "hidden":
                _d["execution_admission_bucket"] = "hidden"
                _d["execution_admission_reason"] = "Hidden — outranked by stronger executable rows"
                _d["commercially_visible"] = False
                _d["commercial_visibility"] = "hidden"
                _d["board_visible"] = False
                _d["commercial_visibility_reason"] = _d["execution_admission_reason"]

    _admission_sample = [
        (
            str(_d.get("source_item_id") or _d.get("item_id") or "?")[:12],
            round(float(_d.get("execution_admission_score") or 0.0), 1),
            str(_d.get("execution_admission_bucket") or "hidden"),
            str(_d.get("bid_ceiling_confidence") or "NONE"),
            round(float(_d.get("edge_dollars") or (_d.get("action_summary") or {}).get("expected_profit") or 0.0), 2),
            round(float(_d.get("current_price") or _d.get("current_bid") or 0.0), 2),
        )
        for _d in (_sniper_rows + _watchlist_rows)[:6]
    ]
    _watchlist_recovery_suppressed = sum(
        1
        for _d in filtered_auctions
        if str(_d.get("execution_admission_bucket") or "").strip().lower() == "hidden"
    )
    print(
        f"[WATCHLIST_RECOVERY_SUMMARY] sniper={len(_sniper_rows)} "
        f"watchlist={len(_watchlist_rows)} suppressed={_watchlist_recovery_suppressed}"
    )
    print(
        f"[EXECUTION_ADMISSION] input={len(filtered_auctions)} "
        f"sniper={len(_sniper_rows)} watchlist={len(_watchlist_rows)} "
        f"hidden={max(0, len(filtered_auctions) - len(_sniper_rows) - len(_watchlist_rows))}"
    )
    # PATCH 8 — [VISIBLE_CHASE_GATE] summary: how many rows passed/failed the chase class gate
    print(
        f"[VISIBLE_CHASE_GATE] kept={_vcg_kept} "
        f"dropped_junk={_vcg_dropped_junk} "
        f"dropped_mem={_vcg_dropped_mem} "
        f"dropped_veteran={_vcg_dropped_veteran}"
    )
    # PATCH 8 — Board composition and fallback limit logs
    print(f"[FALLBACK_LIMIT] used={_fallback_board_count} blocked={_fallback_blocked_count} max={_fallback_board_max}")
    _board_rows = _sniper_rows + _watchlist_rows
    _bc_endgame = sum(1 for _d in _board_rows if str(_d.get("product_tier") or "") == "ENDGAME")
    _bc_premium = sum(1 for _d in _board_rows if str(_d.get("product_tier") or "") == "PREMIUM")
    _bc_mid = sum(1 for _d in _board_rows if str(_d.get("product_tier") or "") == "MID")
    _bc_low = sum(1 for _d in _board_rows if str(_d.get("product_tier") or "") == "LOW")
    print(
        f"[BOARD_COMPOSITION] total={len(_board_rows)} "
        f"endgame={_bc_endgame} premium={_bc_premium} mid={_bc_mid} low={_bc_low}"
    )
    # PATCH 8 — Per admitted row product tier
    for _d in _board_rows[:8]:
        _pt_log = str(_d.get("product_tier") or "?")
        _lp_log = str(_d.get("lane_product") or _d.get("target_product_family") or "")[:20]
        _sub_log = str(_d.get("lane_subset") or _d.get("subset_name") or "")[:16]
        _item_log = str(_d.get("source_item_id") or _d.get("item_id") or "?")[:12]
        print(f"[PRODUCT_TIER] item={_item_log} tier={_pt_log} product={_lp_log} subset={_sub_log}")
    _watch_salvage_kept = sum(1 for _d in _watchlist_rows if bool(_d.get("_watch_candidate")))
    _watch_salvage_buried = max(0, _watch_salvage_candidates - _watch_salvage_kept)
    _watch_salvage_sample = [
        (
            str(_d.get("item_id") or _d.get("source_item_id") or "?")[:12],
            str(_d.get("commercial_bucket") or ""),
            round(float(_d.get("edge_dollars") or 0.0), 2),
            int(_d.get("comp_count") or _d.get("mv_comp_count") or 0),
            str(_d.get("mv_source") or _d.get("market_value_source") or ""),
        )
        for _d in filtered_auctions
        if bool(_is_watchlist_salvage_candidate(_d))
    ][:8]
    print(f"[WATCH_SALVAGE] candidates={_watch_salvage_candidates} kept={_watch_salvage_kept} buried={_watch_salvage_buried}")
    print(f"[WATCH_SALVAGE_SAMPLE] {_watch_salvage_sample}")
    _premium_secondary_kept = sum(
        1 for _d in filtered_auctions
        if str(_d.get("endgame_tier") or "").strip().lower() == "premium_secondary"
        and bool(_d.get("commercially_visible"))
    )
    _premium_secondary_dropped_common = sum(
        1 for _d in filtered_auctions
        if str(_d.get("commodity_reason") or "").strip() == "common_rookie_non_endgame"
    )
    print(
        f"[PREMIUM_SECONDARY_GATE] kept={_premium_secondary_kept} "
        f"dropped_common={_premium_secondary_dropped_common}"
    )
    print(
        f"[COMMERCIAL_HERO] hero={len(_sniper_rows)} watch={len(_watchlist_rows)} "
        f"hidden={max(0, len(filtered_auctions) - len(_sniper_rows) - len(_watchlist_rows))}"
    )
    print(f"[EXECUTION_SCORE] admitted_top={_admission_sample}")
    print(
        f"[COMMERCIAL_VISIBLE] sniper={len(_sniper_rows)} "
        f"watchlist={len(_watchlist_rows)} "
        f"hidden={max(0, len(filtered_auctions) - len(_sniper_rows) - len(_watchlist_rows))}"
    )
    for _d in filtered_auctions:
        _review_supply_keep, _review_supply_reason = _review_commercial_pass_decision(
            _d,
            caller="supply_pass",
            emit_log=False,
        )
        if not _review_supply_keep:
            continue
        if not bool(_d.get("_supply_pass")):
            _d["_supply_pass"] = True
            _d["_supply_stage"] = "review_commercial"
            _d["_soft_watchlist"] = True
            _d["_mv_untrusted_but_allowed"] = True
            _d["_review_watchlist"] = True
            _d["_review_commercial_reason"] = _review_supply_reason
            print(
                f"[SUPPLY_REVIEW_OVERRIDE] title={str(_d.get('title') or '')[:120]} "
                f"truth=REVIEW review={round(float(_safe_float(_d.get('review_estimate_value')) or 0.0), 2)} "
                f"bid={round(float(_safe_float(_d.get('target_bid') or _d.get('target_bid_price') or _d.get('bid_ceiling_value')) or 0.0), 2)} "
                f"source={str(_d.get('market_value_source') or '')[:48]}"
            )
    _pre_display_rows = list(filtered_auctions)
    _main_visible_rows = [
        _d for _d in filtered_auctions
        if bool(_d.get("board_visible"))
        and str(_d.get("execution_admission_bucket") or "").strip().lower() in {"sniper", "watchlist", "monitor"}
        and (
            bool(_d.get("_rescued_watchlist"))
            or bool(_d.get("_fallback_promoted"))       # SPECULATIVE path: structural signal overrides unresolved gate
            or bool(_d.get("_soft_watchlist"))           # soft-watchlist rows carry review_estimate as anchor
            or bool(_d.get("_mv_untrusted_but_allowed")) # premium override already fired
            or bool(_d.get("_provisional_watchlist_only"))  # SUPPLY PROVISIONAL: valid contract, no MV yet
            or not _is_unresolved_no_trusted_mv(_d)
        )
    ]
    def _premium_board_row(row: Dict[str, Any]) -> bool:
        _title = str(row.get("title") or row.get("source_title") or "").lower()
        _product = " ".join(
            filter(
                None,
                [
                    str(row.get("product_family") or "").strip(),
                    str(row.get("set_name") or "").strip(),
                    str(row.get("lane_product") or "").strip(),
                    str(row.get("target_product") or "").strip(),
                ],
            )
        ).lower()
        _lane_type = str(row.get("target_lane_type") or row.get("spec_lane_class") or "").strip().lower()
        _serial = str(row.get("serial") or row.get("serial_denominator") or row.get("serial_bucket") or "").strip().lower()
        if bool(row.get("commodity_suppressed")) or bool(row.get("commercially_suppressed")):
            return False
        if _lane_type in {"auto", "patch", "serial_parallel", "premium_parallel", "premium_subset", "ssp_case_hit"}:
            return True
        if _serial:
            return True
        if any(
            _term in _title
            for _term in (
                "auto",
                "autograph",
                "patch",
                "rpa",
                "relic",
                "kaboom",
                "downtown",
                "color blast",
                "stained glass",
                "manga",
                "gold",
                "black",
                "zebra",
                "elephant",
                "tiger",
                "checkerboard",
                "tie dye",
                "tie-dye",
                "/99",
                "/75",
                "/50",
                "/49",
                "/25",
                "/10",
                "/5",
                "1/1",
            )
        ):
            return True
        return any(
            _term in _product
            for _term in (
                "prizm",
                "select",
                "optic",
                "spectra",
                "national treasures",
                "immaculate",
                "flawless",
                "topps chrome",
                "bowman chrome",
                "topps finest",
                "topps chrome black",
            )
        )

    def _stamp_board_row_source(row: Dict[str, Any]) -> str:
        if bool(row.get("_board_recovered")):
            _source = "rescued_remainder"
        elif bool(row.get("_rescued_watchlist")):
            _source = "rescued_watch"
        elif _premium_board_row(row):
            _source = "fresh_premium"
        else:
            _source = "fresh_scan"
        row["_board_row_source"] = _source
        row["board_source"] = _source
        row["fresh_scan"] = bool(_source.startswith("fresh"))
        row["rescued_remainder"] = bool(_source.startswith("rescued"))
        return _source

    def _force_monitor_visible(row: dict) -> bool:
        if not row:
            return False

        _truth = row.get("valuation_truth_tier")
        _title = str(row.get("title") or "").lower()

        try:
            _true_mv = float(row.get("true_market_value")) if row.get("true_market_value") is not None else None
        except Exception:
            _true_mv = None

        try:
            _target_bid = float(row.get("target_bid")) if row.get("target_bid") is not None else None
        except Exception:
            _target_bid = None

        try:
            _comp_count = int(row.get("usable_comp_count", row.get("comp_count", 0)) or 0)
        except Exception:
            _comp_count = 0

        _premium_hit = any(_term in _title for _term in [
            "national treasures", "immaculate", "flawless", "spectra",
            "patch", "auto", "rpa", "gold", "holo", "/10", "/25", "/49",
        ])

        return bool(_truth == "TRUE" and _true_mv is not None and _target_bid is not None and _comp_count >= 1 and _premium_hit)

    _final_sniper_rows: List[Dict[str, Any]] = []
    _final_watchlist_rows: List[Dict[str, Any]] = []
    _final_monitor_rows: List[Dict[str, Any]] = []
    _live_board_rows: List[Dict[str, Any]] = []
    _other_visible_rows: List[Dict[str, Any]] = []
    _final_dropped_count = 0

    def _force_final_visible_append_authority_row(row: Dict[str, Any], *, append_tag: str = "final_visible_append_authority") -> bool:
        if not isinstance(row, dict):
            return False
        row = _persist_review_gate_state(row)
        row = _bind_authoritative_live_price(row)
        row = _carry_authoritative_current_price(row)
        _allow, _reason = _has_final_visible_append_authority(row)
        if not _allow:
            return False
        row["_final_visible_append_authority"] = True
        row["final_visible_append_reason"] = _reason
        row["_stale_subscription_lane_tier"] = row.get("subscription_lane_tier")
        _surface_intent = str(row.get("surface_intent") or "").strip().lower()
        if _surface_intent not in {"watchlist", "sniper", "snipe", "execute_now", "execute now"}:
            _surface_intent = "monitor"
        row["surface_intent"] = "watchlist" if _surface_intent == "watchlist" else "monitor"
        row["main_board_pool"] = "main_visible_rows"
        if row["surface_intent"] == "watchlist":
            row["execution_admission_bucket"] = "watchlist"
            row["commercial_visibility"] = "watchlist"
            row["final_bucket"] = "watchlist"
            row["_final_bucket"] = "WATCHLIST"
            _stamp_live_watchlist_route(row, reason=_reason)
            _targets = [_final_watchlist_rows, _live_board_rows]
        else:
            row["execution_admission_bucket"] = "monitor"
            row["commercial_visibility"] = "monitor"
            row["final_bucket"] = "monitor"
            row["_final_bucket"] = "MONITOR"
            row["_monitor_reason"] = str(row.get("_monitor_reason") or _reason)
            _targets = [_final_monitor_rows, _live_board_rows]
        if not _append_bound_board_row_to_many(_targets, row, append_tag=append_tag):
            return False
        print(
            f"[FINAL_VISIBLE_APPEND_ASSERT] "
            f"title={str((row or {}).get('title') or '')[:160]} "
            f"live_board_in={1 if row in _live_board_rows else 0 if '_live_board_rows' in locals() else -1} "
            f"board_visible={row.get('board_visible')} "
            f"commercially_visible={row.get('commercially_visible')} "
            f"surface_intent={row.get('surface_intent')} "
            f"append_reason={row.get('final_visible_append_reason')}"
        )
        return True

    def _board_authoritative_auction_gate(row: Dict[str, Any], *, append_tag: str = "") -> bool:
        _contract = _authoritative_auction_contract(row)
        _auth_ok = bool(_contract.get("ok"))
        _auth_reason = str(_contract.get("reason") or "unknown")
        print(
            f"[AUCTION_CONTRACT_CHECK] title={str((row or {}).get('title') or '')[:160]} "
            f"ok={_auth_ok} "
            f"reason={_auth_reason} "
            f"listing_type={row.get('listing_type') or row.get('format') or row.get('buying_option') or _contract.get('listing_type')} "
            f"current_price={row.get('current_price')} "
            f"bid_count={row.get('bid_count') if row.get('bid_count') is not None else _contract.get('bid_count')} "
            f"end_time={row.get('end_time') or row.get('end_datetime') or row.get('auction_end_time') or _contract.get('end_time')} "
            f"url={str(row.get('url') or row.get('item_web_url') or row.get('itemWebUrl') or _contract.get('url') or '')[:120]}"
        )
        if not _auth_ok:
            _listing_type_blank = not str(
                row.get("listing_type")
                or row.get("format")
                or row.get("buying_option")
                or _contract.get("listing_type")
                or ""
            ).strip()
            _survivor_allow = False
            _survivor_reason = "not_checked"
            if _auth_reason in {"not_auction", "not_auction_listing_type"} and _listing_type_blank:
                _survivor_allow, _survivor_reason = _board_bind_auction_survivor(row)
                print(
                    f"[BOARD_BIND_SURVIVOR] title={str((row or {}).get('title') or '')[:160]} "
                    f"allow={1 if _survivor_allow else 0} "
                    f"reason={_survivor_reason} "
                    f"item_id={row.get('item_id') or row.get('listing_id') or row.get('source_item_id') or _contract.get('item_id')} "
                    f"url_present={1 if bool(str(row.get('listing_url') or row.get('url') or row.get('item_url') or row.get('canonical_url') or row.get('ebay_url') or row.get('_board_url') or row.get('source_url') or row.get('item_web_url') or row.get('itemWebUrl') or row.get('source_view_url') or _contract.get('url') or '').strip()) else 0} "
                    f"remaining_seconds={row.get('remaining_seconds') if row.get('remaining_seconds') is not None else _contract.get('remaining_seconds')} "
                    f"current_price={row.get('current_price') if row.get('current_price') is not None else row.get('authoritative_current_price') or row.get('_board_current_price') or _contract.get('current_price')} "
                    f"board_visible={row.get('board_visible')} "
                    f"commercially_visible={row.get('commercially_visible')} "
                    f"listing_type_before={row.get('listing_type') or row.get('format') or row.get('buying_option') or _contract.get('listing_type')} "
                    f"price_source_before={row.get('current_price_source') or row.get('price_source') or row.get('display_price_source') or _contract.get('price_source')}"
                )
            if _survivor_allow:
                row["_board_bind_auction_survivor"] = True
                row["_board_bind_reason_override"] = "board_bind_auction_survivor"
                row["listing_type"] = "AUCTION"
                row["format"] = str(row.get("format") or "AUCTION")
                row["buying_option"] = str(row.get("buying_option") or "AUCTION")
                row["source_listing_type"] = str(row.get("source_listing_type") or "AUCTION")
                if not str(row.get("current_price_source") or row.get("price_source") or row.get("display_price_source") or "").strip():
                    row["current_price_source"] = "authoritative_row_survivor"
                    row["price_source"] = "authoritative_row_survivor"
                    row["display_price_source"] = "authoritative_row_survivor"
                _contract = _authoritative_auction_contract(row)
                _auth_ok = bool(_contract.get("ok"))
                _auth_reason = str(_contract.get("reason") or "unknown")
            if _auth_ok:
                print(
                    f"[BOARD_BIND_SURVIVOR_ASSERT] title={str((row or {}).get('title') or '')[:160]} "
                    f"final_ok=1 "
                    f"final_reason={_auth_reason} "
                    f"listing_type={row.get('listing_type')} "
                    f"price_source={row.get('current_price_source') or row.get('price_source')} "
                    f"live_board_candidate={1 if bool(row.get('board_visible') or row.get('commercially_visible')) else 0}"
                )
            else:
                row["_auction_contract_blocked"] = True
                row["_auction_contract_block_reason"] = _auth_reason
                print(
                    f"[AUCTION_CONTRACT_BLOCK] title={str((row or {}).get('title') or '')[:160]} "
                    f"reason={_auth_reason}"
                )
                return False

        if not _auth_ok:
            row["_auction_contract_blocked"] = True
            row["_auction_contract_block_reason"] = _auth_reason
            print(
                f"[AUCTION_CONTRACT_BLOCK] title={str((row or {}).get('title') or '')[:160]} "
                f"reason={_auth_reason}"
            )
            return False

        _price_source = str(
            row.get("current_price_source")
            or row.get("price_source")
            or row.get("display_price_source")
            or row.get("source_price_kind")
            or _contract.get("price_source")
            or ""
        ).strip().lower()
        if _price_source in {
            "bin_price",
            "buy_now_price",
            "fallback_price",
            "anchor_price",
            "display_fallback",
            "fixed_price",
        }:
            row["_auction_contract_blocked"] = True
            row["_auction_contract_block_reason"] = f"price_source:{_price_source}"
            print(
                f"[AUCTION_PRICE_SOURCE_BLOCK] title={str((row or {}).get('title') or '')[:160]} "
                f"price_source={_price_source}"
            )
            return False

        row, _bind_ok, _bind_reason = _bind_authoritative_board_listing(row)
        if not _bind_ok:
            row["_auction_contract_blocked"] = True
            row["_auction_contract_block_reason"] = f"board_bind:{_bind_reason}"
            print(
                f"[AUCTION_CONTRACT_BLOCK] title={str((row or {}).get('title') or '')[:160]} "
                f"reason=board_bind:{_bind_reason}"
            )
            return False

        _hydrate_bound_board_display(row)
        print(
            f"[BOARD_AUCTION_ASSERT] title={str((row or {}).get('title') or '')[:160]} "
            f"listing_type={row.get('listing_type') or row.get('format') or row.get('buying_option') or _contract.get('listing_type')} "
            f"current_price={row.get('current_price')} "
            f"price_source={row.get('current_price_source') or row.get('price_source') or row.get('source_price_kind') or _contract.get('price_source')} "
            f"bid_count={row.get('bid_count') if row.get('bid_count') is not None else _contract.get('bid_count')} "
            f"remaining_seconds={row.get('remaining_seconds') if row.get('remaining_seconds') is not None else _contract.get('remaining_seconds')}"
        )
        return True

    def _min_visible_watchlist_candidate(row: Dict[str, Any]) -> bool:
        if not row:
            return False
        _title = str(row.get("title") or row.get("source_title") or "").lower()
        if any(_term in _title for _term in ("lot", "bundle", "break", "case break", "team break", "sealed", "blaster", "mega box", "fat pack", "hobby box", "custom", "reprint")):
            return False
        _entity_valid = bool(row.get("entity_exact_match") or row.get("exact_entity_match") or row.get("tracked_anchor") or row.get("_target_match_relaxed"))
        _product_valid = _visible_survival_product_ok(row)
        _review_value = _safe_float(row.get("review_estimate_value"))
        _true_value = _safe_float(row.get("true_market_value"))
        _target_bid = _safe_float(row.get("target_bid"))
        return bool(
            _entity_valid
            and _product_valid
            and (_true_value or _review_value)
            and (_target_bid or _review_value)
        )

    def _append_final_surface_authority_row(row: Dict[str, Any], *, append_tag: str = "final_surface_authority") -> bool:
        row = _persist_review_gate_state(row)
        row = _bind_authoritative_live_price(row)
        row = _carry_authoritative_current_price(row)
        row = _normalize_row_price_fields(row, stage=f"final_surface_authority_pre_append:{append_tag}")
        _visible_allow, _visible_reason = _has_final_visible_append_authority(row)
        if _visible_allow:
            row["_final_visible_append_authority"] = True
            row["final_visible_append_reason"] = _visible_reason
            row["_stale_subscription_lane_tier"] = row.get("subscription_lane_tier")
            row["surface_intent"] = str(row.get("surface_intent") or "monitor")
            if row["surface_intent"] == "watchlist":
                row["execution_admission_bucket"] = "watchlist"
                row["commercial_visibility"] = "watchlist"
                row["final_bucket"] = "watchlist"
                row["_final_bucket"] = "WATCHLIST"
                _stamp_live_watchlist_route(row, reason=_visible_reason)
                _targets = [_final_watchlist_rows, _live_board_rows]
            else:
                row["surface_intent"] = "monitor"
                row["execution_admission_bucket"] = "monitor"
                row["commercial_visibility"] = "monitor"
                row["final_bucket"] = "monitor"
                row["_final_bucket"] = "MONITOR"
                row["_monitor_reason"] = str(row.get("_monitor_reason") or _visible_reason)
                _targets = [_final_monitor_rows, _live_board_rows]
            row["main_board_pool"] = "main_visible_rows"
            if not _append_bound_board_row_to_many(_targets, row, append_tag=f"{append_tag}:visible_authority"):
                return False
            print(
                f"[FINAL_VISIBLE_APPEND_ASSERT] "
                f"title={str((row or {}).get('title') or '')[:160]} "
                f"live_board_in={1 if row in _live_board_rows else 0 if '_live_board_rows' in locals() else -1} "
                f"board_visible={row.get('board_visible')} "
                f"commercially_visible={row.get('commercially_visible')} "
                f"surface_intent={row.get('surface_intent')} "
                f"append_reason={row.get('final_visible_append_reason')}"
            )
            return True
        if not isinstance(row, dict) or not _stamp_final_surface_authority(row):
            return False
        _execution_final = str(
            row.get("execution_final")
            or row.get("execution_contract_final")
            or row.get("_execution_final")
            or ""
        ).strip().upper()
        _target_bucket_name = "final_watchlist" if _execution_final == "WATCHLIST" else "final_monitor"
        if _target_bucket_name == "final_watchlist":
            row["execution_admission_bucket"] = "watchlist"
            row["commercial_visibility"] = "watchlist"
            row["final_bucket"] = "watchlist"
            row["_final_bucket"] = "WATCHLIST"
            row["main_board_pool"] = "main_visible_rows"
            _stamp_live_watchlist_route(row, reason="final_surface_authority")
            _targets = [_final_watchlist_rows, _live_board_rows]
        else:
            row["execution_admission_bucket"] = "monitor"
            row["commercial_visibility"] = "monitor"
            row["final_bucket"] = "monitor"
            row["_final_bucket"] = "MONITOR"
            row["_monitor_reason"] = str(row.get("_monitor_reason") or "truth_valid_review_kept_execution_final")
            row["main_board_pool"] = "main_visible_rows"
            _targets = [_final_monitor_rows, _live_board_rows]
        if not _board_authoritative_auction_gate(row, append_tag=append_tag):
            return False
        row = _persist_review_gate_state(row)
        row = _bind_authoritative_live_price(row)
        row = _carry_authoritative_current_price(row)
        row = _normalize_row_price_fields(row, stage=f"final_surface_authority_append:{append_tag}")
        print(
            f"[FINAL_APPEND_PRICE_ASSERT] title={str((row or {}).get('title') or '')[:160]} "
            f"current_price={row.get('current_price')} "
            f"authoritative_current_price={row.get('authoritative_current_price') or row.get('_authoritative_current_price')} "
            f"surface_intent={row.get('surface_intent')}"
        )
        if not _append_bound_board_row_to_many(_targets, row, append_tag=append_tag):
            return False
        print(
            f"[FINAL_VISIBLE_APPEND] title={str((row or {}).get('title') or '')[:160]} "
            f"bucket={_target_bucket_name} "
            f"surface_intent={row.get('surface_intent')} "
            f"truth={row.get('truth')} "
            f"trusted_exact={row.get('trusted_exact_comp_count')}"
        )
        return True

    def _other_bucket_promotable_to_watchlist(row: Dict[str, Any]) -> Tuple[bool, List[str]]:
        if not isinstance(row, dict):
            return False, ["not_dict"]
        try:
            _latest_row = _persist_review_gate_state(row)
            if isinstance(_latest_row, dict) and _latest_row is not row:
                row.update(_latest_row)
        except Exception as _exc:
            row["_other_bucket_review_persist_error"] = str(_exc)[:160]
        try:
            _latest_row = _bind_authoritative_live_price(row)
            if isinstance(_latest_row, dict) and _latest_row is not row:
                row.update(_latest_row)
        except Exception as _exc:
            row["_other_bucket_live_bind_error"] = str(_exc)[:160]
        try:
            _latest_row = _carry_authoritative_current_price(row)
            if isinstance(_latest_row, dict) and _latest_row is not row:
                row.update(_latest_row)
        except Exception as _exc:
            row["_other_bucket_price_carry_error"] = str(_exc)[:160]
        try:
            _latest_row = _normalize_row_price_fields(row, stage="other_bucket_promotable")
            if isinstance(_latest_row, dict) and _latest_row is not row:
                row.update(_latest_row)
        except Exception as _exc:
            row["_other_bucket_price_normalize_error"] = str(_exc)[:160]
        try:
            _authority_allow, _authority_reason = _has_final_visible_append_authority(row)
        except Exception as _exc:
            _authority_allow, _authority_reason = False, f"authority_error:{str(_exc)[:120]}"
        if _authority_allow:
            row["_final_visible_append_authority"] = True
            row["final_visible_append_reason"] = str(_authority_reason or row.get("final_visible_append_reason") or "")
            row["_stale_subscription_lane_tier"] = row.get("subscription_lane_tier")
        _board_visible = bool(row.get("board_visible") is True or str(row.get("board_visible")).strip().lower() in {"1", "true", "yes"})
        _commercially_visible = bool(row.get("commercially_visible") is True or str(row.get("commercially_visible")).strip().lower() in {"1", "true", "yes"})
        _premium_lane_raw = row.get("premium_lane")
        _premium_lane = str(_premium_lane_raw).strip().lower() in {"1", "true", "yes", "premium"}
        try:
            _trusted_exact = int(row.get("trusted_exact_comp_count") or row.get("exact_comp_count") or 0)
        except Exception:
            _trusted_exact = 0
        _current_price = _safe_float(row.get("current_price") if row.get("current_price") is not None else row.get("current_bid"))
        _target_bid = _safe_float(row.get("target_bid") if row.get("target_bid") is not None else row.get("target_bid_price"))
        _failed_checks: List[str] = []
        if not _board_visible:
            _failed_checks.append("board_visible_false")
        if not _commercially_visible:
            _failed_checks.append("commercially_visible_false")
        if not (_premium_lane or _trusted_exact >= 1):
            _failed_checks.append("no_premium_lane_or_trusted_exact")
        if _current_price is None:
            _failed_checks.append("current_price_not_numeric")
        if _target_bid is None:
            _failed_checks.append("target_bid_not_numeric")
        return not _failed_checks, _failed_checks

    def _price_above_bid_monitor_display_row(row: Dict[str, Any]) -> bool:
        if not isinstance(row, dict):
            return False
        _identity_is_clean = bool(
            row.get("identity_is_clean")
            or row.get("_hydrated_identity_is_clean")
            or row.get("identity_clean")
        )
        try:
            _trusted_exact = int(row.get("trusted_exact_comp_count") or row.get("exact_comp_count") or 0)
        except Exception:
            _trusted_exact = 0
        _premium_lane = str(row.get("premium_lane") or "").strip().lower() in {"1", "true", "yes", "premium"}
        _current_price = _safe_float(
            row.get("current_price")
            if row.get("current_price") is not None
            else row.get("authoritative_current_price")
            or row.get("_authoritative_current_price")
            or row.get("current_bid")
        )
        _target_bid = _safe_float(
            row.get("target_bid")
            if row.get("target_bid") is not None
            else row.get("target_bid_price")
            or row.get("bid_ceiling_value")
            or row.get("adjusted_max_bid")
        )
        _reason_blob = " ".join(
            str(row.get(_key) or "")
            for _key in (
                "final_visible_append_reason",
                "decision_reason",
                "_execution_contract_reason",
                "premium_final_gate_reason",
                "final_review_gate_reason",
                "_final_review_gate_reason",
                "live_board_reject_reason",
            )
        ).lower()
        return bool(
            _identity_is_clean
            and (_trusted_exact >= 1 or _premium_lane)
            and _current_price is not None
            and _target_bid is not None
            and _current_price > _target_bid
            and (
                bool(row.get("_price_above_bid_monitor"))
                or "price_above_bid" in _reason_blob
            )
        )

