    def _actionable_now_watchlist_contract(row: Dict[str, Any]) -> Tuple[bool, str]:
        """
        Promote rows that are commercially interesting AND priced for action now.
        """
        try:
            if not isinstance(row, dict):
                return False, "not_dict"

            _identity_is_clean = bool(
                row.get("identity_is_clean")
                or row.get("_hydrated_identity_is_clean")
                or row.get("identity_clean")
            )
            try:
                _trusted_exact = int(row.get("trusted_exact_comp_count") or row.get("exact_comp_count") or 0)
            except Exception:
                _trusted_exact = 0
            _premium_lane = bool(
                str(row.get("premium_lane") or "").strip().lower() in {"1", "true", "yes", "premium"}
                or _trusted_exact >= 1
            )
            _current = _safe_float(
                row.get("current_price")
                if row.get("current_price") is not None
                else row.get("authoritative_current_price")
                or row.get("_authoritative_current_price")
                or row.get("current_bid")
            )
            _reference = _safe_float(
                row.get("review_estimate")
                or row.get("review")
                or row.get("true_mv")
                or row.get("reference_value")
                or row.get("review_estimate_value")
                or row.get("true_market_value")
                or row.get("market_value_true")
            )
            _target = _safe_float(
                row.get("target_bid")
                if row.get("target_bid") is not None
                else row.get("target_bid_price")
                or row.get("bid_ceiling_value")
                or row.get("adjusted_max_bid")
            )
            _remaining = _safe_float(
                row.get("remaining_seconds")
                or row.get("seconds_remaining")
                or row.get("source_time_remaining_seconds")
            )
            if _remaining is None:
                _remaining = _safe_float(_row_remaining_seconds(row))
            _window = _safe_float(row.get("window_seconds") or row.get("_window_threshold_seconds")) or 43200.0

            _has_prices = bool(_current is not None and _reference is not None and _target is not None)
            _in_window = bool(_remaining is not None and _window is not None and _remaining <= _window)
            _priced_below_reference = bool(_has_prices and _current < _reference)
            _priced_near_or_below_target = bool(_has_prices and _current <= (_target * 1.08))

            if (
                _identity_is_clean
                and _premium_lane
                and _in_window
                and _priced_below_reference
                and _priced_near_or_below_target
            ):
                return True, "actionable_now_watchlist"

            return False, "not_actionable_now"
        except Exception:
            return False, "exception"

    def _stamp_actionable_now_watchlist(row: Dict[str, Any]) -> Dict[str, Any]:
        row["execution_admission_bucket"] = "watchlist"
        row["commercial_visibility"] = "watchlist"
        row["_surface_bucket"] = "watchlist"
        row["surface_intent"] = "watchlist"
        row["_actionable_now_watchlist"] = True
        row["_actionable_now_reason"] = "actionable_now_watchlist"
        row["board_visible"] = True
        row["commercially_visible"] = True
        row["final_bucket"] = "watchlist"
        row["_final_bucket"] = "WATCHLIST"
        row["final_visible_append_reason"] = "actionable_now_watchlist"
        _stamp_live_watchlist_route(row, reason="actionable_now_watchlist")
        return row

    def _live_negative_edge_monitor(row: dict) -> bool:
        if not row:
            return False

        _truth = row.get("valuation_truth_tier")
        _title = str(row.get("title") or "").lower()

        try:
            _true_mv = float(row.get("true_market_value")) if row.get("true_market_value") is not None else None
        except Exception:
            _true_mv = None

        try:
            _target_bid = float(row.get("target_bid")) if row.get("target_bid") is not None else None
        except Exception:
            _target_bid = None

        try:
            _comp_count = int(row.get("usable_comp_count", row.get("comp_count", 0)) or 0)
        except Exception:
            _comp_count = 0

        _premium_hit = any(_term in _title for _term in [
            "national treasures", "immaculate", "flawless", "spectra",
            "patch", "auto", "rpa", "gold", "holo", "/10", "/25", "/49",
        ])

        return bool(_truth == "TRUE" and _true_mv is not None and _target_bid is not None and _comp_count >= 1 and _premium_hit)

    _premium_override_terms = [
        "rpa",
        "patch auto",
        "kaboom",
        "downtown",
        "1/1",
        "/10",
        "/5",
        "national treasures",
        "immaculate",
        "flawless",
    ]
    for _d in _main_visible_rows:
        _title = str(_d.get("title") or _d.get("source_title") or "")
        _title_lower = _title.lower()
        _score = _endgame_signal_score(_d)
        _bad_row = _is_bad_recovery_row(_d)
        if "identity_clean" not in _d:
            _d["identity_clean"] = bool(_is_clean_bid_identity(_d))
        _stamp_review_truth_class(_d, emit_log=False)
        _premium_override = any(_term in _title_lower for _term in _premium_override_terms)
        _rescued_watchlist = bool(_d.get("_rescued_watchlist"))
        _review_watchlist = bool(_d.get("_review_watchlist"))
        _visible_survival = bool(_d.get("_visible_survival"))
        _final_admission_ok, _final_admission_reason = _final_admission_contract(_d, emit_log=True)
        _review_board_now = _review_board_visible(_d, emit_log=True)
        _sniper_now = bool(_final_sniper_eligible(_d))
        _watch_now = bool(_final_watchlist_eligible(_d))
        _monitor_now = bool(_final_monitor_eligible(_d))
        _watchlist_quality = _watchlist_quality_floor_decision(_d, emit_log=True)
        _watchlist_quality_ok = bool(_watchlist_quality.get("allow"))
        _review_commercial_keep, _review_commercial_reason = _review_commercial_pass_decision(
            _d,
            caller="board_handoff",
            emit_log=False,
        )
        _comp_count_now = int(_d.get("usable_comp_count", _d.get("comp_count", 0)) or 0)
        _conf_now = str(_d.get("valuation_confidence") or _d.get("confidence") or _d.get("mv_confidence") or "").strip().upper()
        _edge_pct_now = float(_d.get("edge_pct") or _d.get("edge_percent") or 0.0)
        _edge_dollars_now = float(_d.get("edge_dollars") or (_d.get("action_summary") or {}).get("expected_profit") or 0.0)
        _fast_snipe_ok, _fast_snipe_reason = _fast_snipe_eligibility(_d)
        _stamp_final_surface_tier_contract(_d)
        _surface_tier_now = str(_d.get("_surface_tier") or "").strip()
        _final_visible_allow_now, _final_visible_reason_now = _has_final_visible_append_authority(_d)
        if _final_visible_allow_now:
            _d["_final_visible_append_authority"] = True
            _d["final_visible_append_reason"] = _final_visible_reason_now
            _d["_stale_subscription_lane_tier"] = _d.get("subscription_lane_tier")
            _d["surface_intent"] = str(_d.get("surface_intent") or "monitor")
            _d["board_visible"] = True
            _d["commercially_visible"] = True
            _monitor_now = str(_d.get("surface_intent") or "").strip().lower() != "watchlist"
            _watch_now = not _monitor_now
            _watchlist_quality_ok = True
            _d["main_board_pool"] = "main_visible_rows"
        _premium_action_final_allow, _premium_action_final_reason = _premium_actionability_surface_allow(_d)
        if _premium_action_final_allow:
            _d["_premium_actionability_surface_allow"] = True
            _d["surface_intent"] = "watchlist"
            _d["execution_admission_bucket"] = "watchlist"
            _d["commercial_visibility"] = "watchlist"
            _d["_surface_bucket"] = "watchlist"
            _d["final_visible_append_reason"] = _premium_action_final_reason
            _d["board_visible"] = True
            _d["commercially_visible"] = True
            _watch_now = True
            _monitor_now = False
            _watchlist_quality_ok = True
            _bad_row = False
        _exact_comp_final_allow, _exact_comp_final_reason = _exact_comp_value_surface_allow(_d)
        if _exact_comp_final_allow:
            _d["_exact_comp_value_surface_allow"] = True
            _d["surface_intent"] = "watchlist"
            _d["execution_admission_bucket"] = "watchlist"
            _d["commercial_visibility"] = "watchlist"
            _d["_surface_bucket"] = "watchlist"
            _d["final_visible_append_reason"] = _exact_comp_final_reason
            _d["board_visible"] = True
            _d["commercially_visible"] = True
            _watch_now = True
            _monitor_now = False
            _watchlist_quality_ok = True
            _bad_row = False
        if _surface_tier_now in {"verified_watchlist", "review_watchlist_verify"}:
            _watch_now = True
            _monitor_now = False
            _watchlist_quality_ok = True
            if bool(_d.get("_surface_tier_blocks_sniper")):
                _sniper_now = False
                _fast_snipe_ok = False
                _fast_snipe_reason = "surface_tier_watchlist_only"
                _d["fast_snipe_candidate"] = False
                _d["fast_snipe_fail_reason"] = "surface_tier_watchlist_only"
        elif _surface_tier_now == "research_only":
            _sniper_now = False
            _watch_now = False
            _monitor_now = True
            _fast_snipe_ok = False
            _fast_snipe_reason = "research_only_price_check"
        _d["fast_snipe_candidate"] = bool(_fast_snipe_ok)
        _d["fast_snipe_fail_reason"] = "" if _fast_snipe_ok else str(_fast_snipe_reason)
        _window_edge_rescue = bool(_d.get("window_edge_rescue") or _d.get("_window_edge_rescue"))
        _premium_family_now = any(
            _term in _title_lower
            for _term in ("national treasures", "immaculate", "flawless", "spectra", "prizm", "select", "optic", "topps chrome", "bowman chrome")
        )
        print(
            f"[FINAL_CLASSIFY] title={_title[:120]} truth={_d.get('valuation_truth_tier')} "
            f"true_mv={_d.get('true_market_value')} review={_d.get('review_estimate_value')} "
            f"comps={_d.get('usable_comp_count', _d.get('comp_count'))} target_bid={_d.get('target_bid')}"
        )
        # ── FALLBACK PROMOTION OVERRIDE in final classify ─────────────────────────
        # Fallback-promoted rows with review_estimate > 0 + target_bid > 0 must
        # reach watchlist. Override _watch_now = True regardless of truth tier
        # so the SPECULATIVE path bypasses the strict TRUE/REVIEW gating.
        if bool(_d.get("_fallback_promoted")):
            _fb_review = _safe_float(_d.get("review_estimate_value") or _d.get("anchored_estimate_value"))
            _fb_bid = _safe_float(_d.get("target_bid"))
            if _fb_review and _fb_review > 0 and _fb_bid and _fb_bid > 0:
                if not _sniper_now and _watchlist_quality_ok:
                    _watch_now = True
                    _d["_visible_route"] = str(_d.get("_visible_route") or "FALLBACK_PROMO_WATCHLIST")
                    print(
                        f"[FALLBACK_PROMO_FINAL_ADMIT] title={_title[:120]} "
                        f"review={_fb_review:.2f} bid={_fb_bid:.2f} — forced watchlist"
                    )
        if _sniper_now and _comp_count_now == 1 and _conf_now == "LOW":
            if not (_premium_family_now and (_edge_pct_now > 0.0 or _edge_dollars_now > 0.0)):
                _sniper_now = False
                _watch_now = True
        if _monitor_now and (_edge_pct_now > 0.0 or _edge_dollars_now > 0.0):
            _monitor_now = False
        _review_execution_contract = _premium_review_execution_contract(_d)
        if (
            not _bad_row
            and str(_review_execution_contract.get("reason") or "").strip() == "no_renderable_evidence"
        ):
            _stamp_research_only_price_check(_d)
        if not _bad_row and bool(_review_execution_contract.get("keep_visible")):
            _contract_bucket = str(_review_execution_contract.get("bucket") or "prepare").strip().lower()
            if _contract_bucket == "monitor":
                _monitor_now = True
                _watch_now = False
                _sniper_now = False
            else:
                _watch_now = True
                _monitor_now = False
                _sniper_now = False
            _watchlist_quality_ok = True
            _d["_execution_contract_override"] = True
            _d["_execution_contract_reason"] = str(_review_execution_contract.get("reason") or "review_contract_visible")
            if str(_review_execution_contract.get("reason") or "").strip() == "review_force_promoted":
                _d["review_force_promoted"] = True
                _stamp_live_watchlist_route(_d, reason="review_force_promoted")
        if _stamp_final_surface_authority(_d):
            _sniper_now = False
            _watch_now = str(_d.get("surface_intent") or "").strip().lower() == "watchlist"
            _monitor_now = not _watch_now
            _watchlist_quality_ok = True
            _bad_row = False
        elif str(_review_execution_contract.get("reason") or "") in {
            "price_above_bid",
            "support_quality_fail",
            "premium_support_lane_invalid",
            "commercial_floor_fail",
            "no_target_bid",
            "no_exact_no_support",
        }:
            _d["execution_decision"] = "PASS"
            _d["decision_reason"] = str(_review_execution_contract.get("reason") or "execution_pass_demote")
        if _monitor_now:
            _watch_now = False
        if _review_commercial_keep and not _sniper_now and not _monitor_now:
            _watch_now = True
            _watchlist_quality_ok = True
            _d["_supply_pass"] = True
            _d["_supply_stage"] = str(_d.get("_supply_stage") or "review_commercial")
            _d["_soft_watchlist"] = True
            _d["_mv_untrusted_but_allowed"] = True
            _d["_review_watchlist"] = True
            _d["_review_commercial_reason"] = _review_commercial_reason
            if not bool(_d.get("_supply_review_override_logged")):
                print(
                    f"[SUPPLY_REVIEW_OVERRIDE] title={_title[:120]} "
                    f"truth=REVIEW review={round(float(_safe_float(_d.get('review_estimate_value')) or 0.0), 2)} "
                    f"bid={round(float(_safe_float(_d.get('target_bid') or _d.get('target_bid_price') or _d.get('bid_ceiling_value')) or 0.0), 2)} "
                    f"source={str(_d.get('market_value_source') or '')[:48]}"
                )
                _d["_supply_review_override_logged"] = True
        if (_visible_survival or _final_admission_ok or _review_board_now) and not _sniper_now and not _monitor_now and _watchlist_quality_ok:
            _watch_now = True
            _d["_visible_route"] = str(_d.get("_visible_route") or "WATCHLIST_VISIBLE")
            print(
                f"[VISIBLE_ROUTE] title={_title[:120]} "
                f"route={str(_d.get('_visible_route') or 'WATCHLIST_VISIBLE')}"
            )
        if _watch_now and not _watchlist_quality_ok:
            _watch_now = False
        if _window_edge_rescue and not _bad_row:
            _sniper_now = False
            _monitor_now = False
            _watch_now = True
            _watchlist_quality_ok = True
            _d["_prepare_candidate"] = True
            _d["window_edge_rescue"] = True
            _d["window_edge_display_state"] = str(_d.get("window_edge_display_state") or "PREPARE")
            _d["window_edge_label"] = str(_d.get("window_edge_label") or "PREPARE")
            _d["execution_decision"] = "PREPARE"
            _d["decision"] = "PREPARE"
            _d["decision_reason"] = "window_edge_rescue"
            _d["_watch_price_state"] = "GOOD_PRICE_PREPARE"
            _d["_visible_route"] = str(_d.get("_visible_route") or "WINDOW_EDGE_RESCUE")
            print(
                f"[WINDOW_EDGE_CLASSIFY] title={_title[:120]} "
                f"item={str(_d.get('item_id') or _d.get('source_item_id') or '')[:18] or '?'} "
                f"bucket=prepare_watchlist sniper_eligible=0 watchlist_eligible=1"
            )
        if _bad_row:
            _sniper_now = False
            _watch_now = False
            _monitor_now = False
        # ── SUPPLY PROVISIONAL OVERRIDE ───────────────────────────────────────────
        # Rows with valid frozen contracts that survived candidate selection but have
        # no MV yet bypass watchlist quality gates and go to watchlist only.
        # Bad rows, junk, wrong player are still excluded (caught at supply_pass stamp).
        if bool(_d.get("_provisional_watchlist_only")) and not _bad_row and not _fast_snipe_ok:
            _sniper_now = False
            _monitor_now = False
            _watch_now = True
            _d["_visible_route"] = "SUPPLY_PROVISIONAL_WATCHLIST"
            print(
                f"[SUPPLY_PASS_WATCHLIST] title={_title[:100]} "
                f"player={str(_d.get('_target_player') or _d.get('player_name') or '')[:24]}"
            )
        if _fast_snipe_ok and not _bad_row:
            _sniper_now = True
            _watch_now = False
            _monitor_now = False
            _watchlist_quality_ok = True
            _d["fast_snipe_candidate"] = True
            _d["fast_snipe_fail_reason"] = ""
            _d["execution_admission_bucket"] = "sniper"
            _d["commercial_visibility"] = "sniper"
            _d["final_bucket"] = "sniper"
            _d["board_visible"] = True
            _d["commercially_visible"] = True
            _d["_render_live_watchlist"] = False
            _d["visible_route"] = "fast_snipe_candidate"
        elif _bad_row and _fast_snipe_ok:
            _d["fast_snipe_candidate"] = False
            _d["fast_snipe_fail_reason"] = "bad_row"
            print(f"[FAST_SNIPE_FAIL] title={_title[:120]} reason=bad_row")
        if not _bad_row and _d.get("_research_only_price_check"):
            _apply_research_only_presentation(_d)
            _sniper_now = False
            _watch_now = False
            _monitor_now = True
            _watchlist_quality_ok = True
            _d["execution_decision"] = "WATCH"
            _d["decision"] = "WATCH"
            _d["decision_reason"] = str(_d.get("_research_only_reason") or "mv_clone_or_no_renderable_evidence")
        if (_sniper_now or _watch_now or _monitor_now or _is_live_watchlist_row(_d)) and not _board_authoritative_auction_gate(
            _d,
            append_tag="final_admission",
        ):
            continue
        if not _bad_row and _live_negative_edge_monitor(_d) and (_edge_pct_now < 0.0 or _edge_dollars_now < 0.0):
            _d["_final_bucket"] = "MONITOR"
            _d["_monitor_reason"] = "true_mv_but_over_market"
            _d["main_board_pool"] = "main_visible_rows"
            _d["execution_admission_bucket"] = "monitor"
            _d["commercial_visibility"] = "monitor"
            _d["commercially_visible"] = True
            _d["board_visible"] = True
            if not _append_bound_board_row_to_many([_final_monitor_rows, _live_board_rows], _d, append_tag="live_negative_edge_monitor"):
                continue
            print(
                f"[LIVE_MONITOR_HIT] title={_title[:120]} "
                f"true_mv={_d.get('true_market_value')} target_bid={_d.get('target_bid')} edge={_d.get('edge_pct')}"
            )
            continue
        if _sniper_now:
            _watch_now = False
            _monitor_now = False
        elif _watch_now:
            _monitor_now = False
        _promote_flag = bool(
            (_sniper_now or _watch_now or _monitor_now)
            and (
                _rescued_watchlist
                or _review_watchlist
                or _score >= 4
                or (_premium_override and _score >= 3)
                or _sniper_now
                or _watch_now
                or _monitor_now
                or _visible_survival
                or _final_admission_ok
                or _review_board_now
            )
        )
        _d["_endgame_signal_score"] = int(_score)
        _d["_endgame_promoted"] = bool(_promote_flag)
        # ── [FINAL_ADMISSION_DECISION] ───────────────────────────────────────────
        _fad_mv = _safe_float(_d.get("true_market_value") or _d.get("market_value_true") or _d.get("review_estimate_value") or _d.get("market_value"))
        _fad_bid = _safe_float(_d.get("target_bid"))
        _fad_result = "SNIPER" if (_promote_flag and _sniper_now) else "WATCHLIST" if (_promote_flag and _watch_now) else "MONITOR" if (_promote_flag and _monitor_now) else "REJECTED"
        _fad_reject_reason = "" if _promote_flag else (
            "bad_row" if _bad_row else
            "not_sniper_watch_monitor" if not (_sniper_now or _watch_now or _monitor_now) else
            "score_gate"
        )
        print(
            f"[FINAL_ADMISSION_DECISION] title={_title[:100]} "
            f"mv={round(_fad_mv, 2) if _fad_mv else 'None'} "
            f"target_bid={round(_fad_bid, 2) if _fad_bid else 'None'} "
            f"premium_flag={int(_premium_family_now)} "
            f"fallback_promoted={int(bool(_d.get('_fallback_promoted')))} "
            f"admission_result={_fad_result} "
            f"rejection_reason={_fad_reject_reason or 'none'}"
        )
        print(f"[FINAL_ROUTE] title={_title[:120]} sniper={_sniper_now} watch={_watch_now}")
        print(f"[FINAL_MONITOR_ROUTE] title={_title[:120]} edge={_d.get('edge_pct')} truth={_d.get('valuation_truth_tier')} monitor={_monitor_now}")
        print(f"[ENDGAME_GATE] score={_score} promote={1 if _promote_flag else 0} title={_title[:140]}")
        # ── [EXECUTION_ROUTE_DECISION] ───────────────────────────────────────────
        _erd_truth = str(_d.get("valuation_truth_tier") or "").strip().upper()
        _erd_mv = _safe_float(_d.get("true_market_value") or _d.get("market_value_true") or _d.get("review_estimate_value"))
        _erd_bid = _safe_float(_d.get("target_bid"))
        _erd_price = _safe_float(_d.get("current_price") or _d.get("current_bid"))
        _erd_secs = _row_remaining_seconds(_d)
        try:
            _erd_secs_f = float(_erd_secs) if _erd_secs is not None else -1.0
        except (TypeError, ValueError):
            _erd_secs_f = -1.0
        _erd_edge_pct = float(_d.get("edge_pct") or _d.get("edge_percent") or 0.0)
        _erd_edge_dollars = float(_d.get("edge_dollars") or (_d.get("action_summary") or {}).get("expected_profit") or 0.0)
        _erd_bucket = _fad_result
        _erd_why_parts = []
        if _bad_row:
            _erd_why_parts.append("bad_row_killed")
        if not (_sniper_now or _watch_now or _monitor_now) and not _bad_row:
            _erd_why_parts.append("no_eligible_flag")
        if _promote_flag and _sniper_now:
            _erd_why_parts.append("sniper_promoted")
        if _promote_flag and _watch_now and not _sniper_now:
            _erd_why_parts.append("watchlist_promoted")
        if not _promote_flag and not _bad_row:
            _erd_why_parts.append(f"score_gate={_score}")
        print(
            f"[EXECUTION_ROUTE_DECISION] title={_title[:100]} "
            f"truth={_erd_truth} mv={round(_erd_mv, 2) if _erd_mv else 'None'} "
            f"target_bid={round(_erd_bid, 2) if _erd_bid else 'None'} "
            f"current_price={round(_erd_price, 2) if _erd_price else 'None'} "
            f"secs_remaining={_erd_secs_f:.0f} "
            f"edge_pct={_erd_edge_pct:.1f}% edge_dollars=${_erd_edge_dollars:.2f} "
            f"final_bucket={_erd_bucket} "
            f"why={','.join(_erd_why_parts) or 'ok'}"
        )
        if _promote_flag and _sniper_now:
            _d["main_board_pool"] = "main_visible_rows"
            _d_tier_final = str(_d.get("_board_tier") or "SNIPER_CANDIDATE")
            _d["execution_admission_bucket"] = "sniper" if bool(_d.get("fast_snipe_candidate")) else ("execute_now" if _d_tier_final == "EXECUTE_NOW" else "sniper")
            _d["commercial_visibility"] = _d["execution_admission_bucket"]
            _d["final_bucket"] = "sniper" if bool(_d.get("fast_snipe_candidate")) else _d["execution_admission_bucket"]
            _d["commercially_visible"] = True
            _d["board_visible"] = True
            _d["_render_live_watchlist"] = False
            if not _append_bound_board_row_to_many([_final_sniper_rows, _live_board_rows], _d, append_tag="final_sniper"):
                continue
        elif _promote_flag and _watch_now:
            _d["main_board_pool"] = "main_visible_rows"
            # ── WATCHLIST PRICE-STATE SPLIT ───────────────────────────────────
            # Differentiate "good card / bad price" from "good card / near target".
            # BAD_PRICE_WATCH: current price has already overtaken the opportunity.
            # GOOD_PRICE_PREPARE: still room between current price and target bid.
            _wps_price = _safe_float(_d.get("current_price") or _d.get("current_bid") or 0)
            _wps_target = _safe_float(_d.get("target_bid"))
            _wps_review = _safe_float(_d.get("review_estimate_value") or _d.get("true_market_value") or _d.get("market_value_true"))
            _wps_edge = _safe_float(_d.get("edge_dollars") or 0)
            if _wps_edge is None:
                _wps_edge = 0.0
            # Three conditions any one of which makes it a bad-price row:
            #   1. current price reached or exceeded review estimate (at fair value)
            #   2. current price materially above target bid (>5% over — not worth bidding)
            #   3. no remaining edge
            _wps_at_review = bool(_wps_price and _wps_review and _wps_price >= _wps_review * 0.98)
            _wps_over_target = bool(_wps_price and _wps_target and _wps_price >= _wps_target * 1.05)
            _wps_no_edge = bool(_wps_edge <= 0)
            _wps_bad_price = bool(_wps_at_review or _wps_over_target or _wps_no_edge)
            _wps_state = "BAD_PRICE_WATCH" if _wps_bad_price else "GOOD_PRICE_PREPARE"
            _d["_watch_price_state"] = _wps_state
            _d["_watch_bad_price"] = _wps_bad_price
            _stamp_live_watchlist_route(_d, reason="final_route_watchlist")
            print(
                f"[WATCHLIST_PRICE_STATE] title={_title[:100]} "
                f"review_estimate={round(_wps_review, 2) if _wps_review else 'None'} "
                f"target_bid={round(_wps_target, 2) if _wps_target else 'None'} "
                f"current_price={round(_wps_price, 2) if _wps_price else 'None'} "
                f"edge_dollars={round(_wps_edge, 2)} "
                f"watch_state={_wps_state}"
            )
            if not _append_bound_board_row_to_many([_final_watchlist_rows, _live_board_rows], _d, append_tag="final_watchlist"):
                continue
            if bool(_d.get("_final_surface_authority")):
                print(
                    f"[FINAL_VISIBLE_APPEND] title={str((_d or {}).get('title') or '')[:160]} "
                    f"bucket=final_watchlist "
                    f"surface_intent={_d.get('surface_intent')} "
                    f"truth={_d.get('truth')} "
                    f"trusted_exact={_d.get('trusted_exact_comp_count')}"
                )
        elif _promote_flag and _monitor_now:
            _d["main_board_pool"] = "main_visible_rows"
            _d["execution_admission_bucket"] = "monitor"
            _d["commercial_visibility"] = "monitor"
            _d["commercially_visible"] = True
            _d["board_visible"] = True
            _d["_final_bucket"] = "MONITOR"
            _d["_monitor_reason"] = "price_check_needed" if _d.get("_research_only_price_check") else "true_mv_but_over_market"
            if not _append_bound_board_row_to_many([_final_monitor_rows, _live_board_rows], _d, append_tag="final_monitor"):
                continue
            if bool(_d.get("_final_surface_authority")):
                print(
                    f"[FINAL_VISIBLE_APPEND] title={str((_d or {}).get('title') or '')[:160]} "
                    f"bucket=final_monitor "
                    f"surface_intent={_d.get('surface_intent')} "
                    f"truth={_d.get('truth')} "
                    f"trusted_exact={_d.get('trusted_exact_comp_count')}"
                )
        else:
            if _is_live_watchlist_row(_d):
                _stamp_live_watchlist_route(_d, reason="other_redirect_block")
                if not _append_bound_board_row_to_many([_final_watchlist_rows, _live_board_rows], _d, append_tag="other_redirect_watchlist"):
                    continue
                print(
                    f"[OTHER_LISTING_REDIRECT_BLOCK] title={str(_d.get('title') or _d.get('source_title') or '')[:120]} "
                    f"reason=live_watchlist_row"
                )
                continue
            _other_reason = "endgame_quality_gate"
            print(
                f"[OTHER_BUCKET_TRACE] "
                f"title={_title[:160]} "
                f"surface_intent={_d.get('surface_intent')} "
                f"board_visible={_d.get('board_visible')} "
                f"commercially_visible={_d.get('commercially_visible')} "
                f"premium_lane={_d.get('premium_lane')} "
                f"trusted_exact_comp_count={_d.get('trusted_exact_comp_count')} "
                f"current_price={_d.get('current_price')} "
                f"target_bid={_d.get('target_bid')} "
                f"execution_final_decision={_d.get('execution_final_decision')} "
                f"execution_admission_bucket={_d.get('execution_admission_bucket')} "
                f"commercial_visibility={_d.get('commercial_visibility')} "
                f"_surface_bucket={_d.get('_surface_bucket')} "
                f"reason_candidate={_other_reason}"
            )
            _d["main_board_pool"] = "other_listings"
            _d["secondary_board_visible"] = True
            _d["live_board_rejected"] = True
            _d["live_board_reject_reason"] = _other_reason
            _other_visible_rows.append(_d)
            _final_dropped_count += 1
            print(f"[ENDGAME_REJECT] bad_row={1 if _bad_row else 0} score={_score} title={_title[:140]}")
    _weak_mv_override_checked = sum(1 for _d in filtered_auctions if bool(_d.get("_weak_mv_override_checked")))
    _weak_mv_override_allowed_count = sum(1 for _d in filtered_auctions if bool(_d.get("_weak_mv_override_allow")))
    _weak_mv_override_blocked_count = sum(
        1 for _d in filtered_auctions
        if bool(_d.get("_weak_mv_override_checked")) and not bool(_d.get("_weak_mv_override_allow"))
    )
    print(
        f"[WEAK_MV_OVERRIDE_FINAL] checked={_weak_mv_override_checked} "
        f"allowed={_weak_mv_override_allowed_count} blocked={_weak_mv_override_blocked_count}"
    )
    # ── FINAL SAFETY ADMISSION LAYER ─────────────────────────────────────────
    # If the classify loop produced no watchlist or sniper rows, sweep all
    # filtered_auctions for any unboarded row that is a genuine deal:
    #   true_market_value > 0 (and >= commercial floor)
    #   target_bid > 0
    #   (true_market_value - current_price) > 0   ← positive edge
    # This overrides structural kill gates (bad_row flag, score gate,
    # unresolved check, visibility filter) without touching valuation logic.
    # _FAO_MIN_TRUE_MV mirrors the UCF floor so we never re-admit commercial junk.
    _FAO_MIN_TRUE_MV = 15.0
    _FAO_MAX_OVERRIDES = 5     # cap: this is a safety net, not a second board
    _fao_live_ids = {
        str(_r.get("item_id") or _r.get("source_item_id") or id(_r))
        for _r in _live_board_rows
    }
    _fao_override_count = 0
    for _fao_row in filtered_auctions:
        if _fao_override_count >= _FAO_MAX_OVERRIDES:
            break
        _fao_id = str(_fao_row.get("item_id") or _fao_row.get("source_item_id") or id(_fao_row))
        if _fao_id in _fao_live_ids:
            continue
        _fao_mv = _safe_float(_fao_row.get("true_market_value") or _fao_row.get("market_value_true"))
        _fao_bid = _safe_float(_fao_row.get("target_bid"))
        _fao_price = _safe_float(_fao_row.get("current_price") or _fao_row.get("current_bid") or 0)
        _fao_edge = (_fao_mv - _fao_price) if (_fao_mv and _fao_price is not None) else 0.0
        _fao_title = str(_fao_row.get("title") or _fao_row.get("source_title") or "")
        _fao_title_lower = _fao_title.lower()
        # Skip structural junk regardless of MV
        if any(
            _jt in _fao_title_lower
            for _jt in ("lot", "bundle", "break", "case break", "team break",
                        "sealed", "blaster", "mega box", "hobby box", "custom", "reprint")
        ):
            continue
        # Three required conditions + commercial floor
        if not (
            _fao_mv and _fao_mv >= _FAO_MIN_TRUE_MV
            and _fao_bid and _fao_bid > 0
            and _fao_edge > 0
        ):
            continue
        # Stamp and force to watchlist (with price-state split)
        _fao_row["_final_admission_override"] = True
        _fao_row["_forced_reason"] = "valid_deal_override"
        _fao_row["main_board_pool"] = "main_visible_rows"
        _fao_wps_price = _safe_float(_fao_row.get("current_price") or _fao_row.get("current_bid") or 0)
        _fao_wps_target = _safe_float(_fao_row.get("target_bid"))
        _fao_wps_review = _safe_float(_fao_row.get("review_estimate_value") or _fao_row.get("true_market_value") or _fao_row.get("market_value_true"))
        _fao_wps_edge = float(_fao_edge)
        _fao_bad_price = bool(
            (_fao_wps_price and _fao_wps_review and _fao_wps_price >= _fao_wps_review * 0.98)
            or (_fao_wps_price and _fao_wps_target and _fao_wps_price >= _fao_wps_target * 1.05)
            or _fao_wps_edge <= 0
        )
        _fao_row["_watch_price_state"] = "BAD_PRICE_WATCH" if _fao_bad_price else "GOOD_PRICE_PREPARE"
        _fao_row["_watch_bad_price"] = _fao_bad_price
        _stamp_live_watchlist_route(_fao_row, reason="final_admission_override")
        if not _board_authoritative_auction_gate(_fao_row, append_tag="final_admission_override"):
            continue
        if not _append_bound_board_row_to_many([_final_watchlist_rows, _live_board_rows], _fao_row, append_tag="final_admission_override"):
            continue
        _fao_live_ids.add(_fao_id)
        _fao_override_count += 1
        print(
            f"[FINAL_ADMISSION_OVERRIDE] title={_fao_title[:100]} "
            f"mv={_fao_mv:.2f} price={_fao_price:.2f} "
            f"target_bid={_fao_bid:.2f} edge={_fao_edge:.2f} "
            f"reason=valid_deal_override"
        )
    if _fao_override_count > 0:
        print(
            f"[FINAL_ADMISSION_OVERRIDE_SUMMARY] overridden={_fao_override_count} "
            f"board_total={len(_live_board_rows)} watchlist_total={len(_final_watchlist_rows)}"
        )
    _final_surface_authority_live_ids = {
        str(_r.get("item_id") or _r.get("source_item_id") or _r.get("row_key") or _ending_soon_row_key(_r))
        for _r in list(_live_board_rows or [])
    }
    for _fsa_row in list(filtered_auctions or []):
        if not _has_final_surface_authority(_fsa_row):
            continue
        _fsa_id = str(_fsa_row.get("item_id") or _fsa_row.get("source_item_id") or _fsa_row.get("row_key") or _ending_soon_row_key(_fsa_row))
        if _fsa_id in _final_surface_authority_live_ids:
            continue
        if _append_final_surface_authority_row(_fsa_row, append_tag="final_surface_authority_sweep"):
            _final_surface_authority_live_ids.add(_fsa_id)
    if not _final_sniper_rows and not _final_watchlist_rows:
        # NO IMMEDIATE SNIPES — do not manufacture conviction with fallback REVIEW rows.
        # When there are no real actionable candidates, the correct product answer is an empty board.
        print(
            f"[NO_IMMEDIATE_SNIPES] sniper={len(_final_sniper_rows)} watchlist={len(_final_watchlist_rows)} "
            f"main_visible={len(_main_visible_rows)} — suppressing min_visible fallback"
        )
    _recovery_rows_hidden = [
        _d for _d in filtered_auctions
        if str(_d.get("hidden_reason") or "").strip() == "unresolved_no_trusted_mv"
        or str(_d.get("recovery_pool") or "").strip() == "recovery_rows_hidden"
    ]
    def _render_monitor_row(row: dict) -> bool:
        if not row:
            return False
        if not _apply_domestic_board_gate(row, caller="render_monitor_row"):
            return False

        try:
            _truth = row.get("valuation_truth_tier")
            _true_mv = float(row.get("true_market_value")) if row.get("true_market_value") is not None else None
            _target_bid = float(row.get("target_bid")) if row.get("target_bid") is not None else None
            _comp_count = int(row.get("usable_comp_count", row.get("comp_count", 0)) or 0)
        except Exception:
            return False

        _title = str(row.get("title") or "").lower()
        _premium_hit = any(_term in _title for _term in [
            "national treasures", "immaculate", "flawless", "spectra",
            "patch", "auto", "rpa", "gold", "holo", "/10", "/25", "/49",
        ])

        return bool(_truth == "TRUE" and _true_mv is not None and _target_bid is not None and _comp_count >= 1 and _premium_hit)

    def _fast_snipe_sort_key(_r: Dict[str, Any]) -> tuple:
        _current = _safe_float(
            _r.get("current_price")
            or _r.get("current_bid")
            or _r.get("price")
            or _r.get("listing_price")
        )
        _target = _safe_float(_r.get("target_bid"))
        _seconds = _safe_float(_r.get("remaining_seconds") or _r.get("seconds_remaining"))
        if _seconds is None:
            _seconds = _row_remaining_seconds(_r)
        return (
            0 if (_current is not None and _target is not None and _current <= _target) else 1,
            1 if bool(_r.get("exact_truth_rescued")) else 0,
            -int(_r.get("trusted_exact_comp_count") or 0),
            -int(_r.get("support_comp_count") or 0),
            -float(_r.get("edge_pct") or _r.get("edge_percent") or 0.0),
            float(_seconds if _seconds is not None else 10 ** 9),
        )

    _fast_sniper_rows = sorted(
        [_row for _row in _final_sniper_rows if bool((_row or {}).get("fast_snipe_candidate"))],
        key=_fast_snipe_sort_key,
    )
    if not _fast_sniper_rows:
        print("[FAST_SNIPE_EMPTY] reason=no_rows_cleared_truth_contract")
    _fast_sniper_ids = {
        _cross_sport_row_id(_row)
        for _row in _fast_sniper_rows
    }
    _strict_sniper_rows = list(_fast_sniper_rows) + [
        _row for _row in _final_sniper_rows
        if _cross_sport_row_id(_row) not in _fast_sniper_ids
    ]
    _strict_watchlist_rows = sorted(
        _final_watchlist_rows,
        key=lambda _r: (
            1 if bool(_r.get("_watch_bad_price")) else 0,
            -float(_r.get("edge_dollars") or _r.get("edge_value") or 0.0),
        ),
    )
    _strict_monitor_rows = list(_final_monitor_rows)

    def _is_prepare_watch_row(_row: Dict[str, Any]) -> bool:
        _decision = str((_row or {}).get("execution_decision") or "").strip().upper()
        _watch_state = str((_row or {}).get("_watch_price_state") or "").strip().upper()
        return bool(_decision == "PREPARE" or _watch_state == "GOOD_PRICE_PREPARE")

    _strict_prepare_rows = [_row for _row in _strict_watchlist_rows if _is_prepare_watch_row(_row)]
    _strict_other_watch_rows = [_row for _row in _strict_watchlist_rows if not _is_prepare_watch_row(_row)]
    _strict_visible_count = len(_strict_sniper_rows) + len(_strict_prepare_rows) + len(_strict_monitor_rows)
    _spillover_needed = max(0, _ES_VISIBLE_BOARD_FLOOR - _strict_visible_count)
    _spillover_prepare_rows: List[Dict[str, Any]] = []
    _spillover_ranked = sorted(_spillover_prepare_pool, key=_spillover_prepare_rank_key)
    if _spillover_needed <= 0:
        for _row in _spillover_ranked:
            print(f"[SPILLOVER_DROP] title={str((_row or {}).get('title') or '')[:120]} reason=board_floor_already_met")
    if _spillover_needed > 0:
        _spillover_promoted_keys: set[str] = set()
        for _row in _spillover_ranked[:_spillover_needed]:
            _title = str(_row.get("title") or _row.get("source_title") or "")
            _truth = str(_row.get("valuation_truth_tier") or "").strip().upper() or "REVIEW"
            _seconds_left = _safe_float(_row_remaining_seconds(_row))
            _hours_left = round((_seconds_left or 0.0) / 3600.0, 2) if _seconds_left is not None else None
            _edge_signal = _spillover_edge_signal(_row)
            _spillover_promoted_keys.add(str(_row.get("row_key") or _ending_soon_row_key(_row)))
            _row["_spillover_prepare"] = True
            _row["_final_bucket"] = "SPILLOVER_PREPARE"
            _row["_watch_price_state"] = "GOOD_PRICE_PREPARE"
            _row["_visible_route"] = "SPILLOVER_PREPARE"
            _row["execution_decision"] = "PREPARE"
            _row["decision"] = "PREPARE"
            _row["decision_reason"] = "window_spillover_prepare"
            _row["main_board_pool"] = "main_visible_rows"
            _stamp_live_watchlist_route(_row, reason="spillover_prepare")
            _row["spillover_prepare"] = True
            _row["spillover_window_hours"] = float(_spillover_fetch_window_cap or 0.0)
            if not _board_authoritative_auction_gate(_row, append_tag="spillover_prepare"):
                continue
            if not _append_bound_board_row_to_many([_spillover_prepare_rows, _final_watchlist_rows, _live_board_rows], _row, append_tag="spillover_prepare"):
                continue
            filtered_auctions.append(_row)
            print(
                f"[SPILLOVER_PREPARE_KEEP] title={_title[:120]} "
                f"hours_left={_hours_left if _hours_left is not None else 'na'} "
                f"edge={round(_edge_signal, 2)} truth={_truth}"
            )
        for _row in _spillover_ranked[_spillover_needed:]:
            if str(_row.get("row_key") or _ending_soon_row_key(_row)) in _spillover_promoted_keys:
                continue
            print(f"[SPILLOVER_DROP] title={str((_row or {}).get('title') or '')[:120]} reason=rank_cut")
    print(
        f"[WINDOW_SPILLOVER] strict_window={round(_strict_time_window_hours, 2)} "
        f"fetch_window={round(_spillover_fetch_window_cap, 2)} "
        f"strict_rows={len(_window_rows)} spillover_candidates={len(_spillover_prepare_pool)} "
        f"promoted={len(_spillover_prepare_rows)}"
    )
    _strict_guard_count = sum(
        1
        for _row in _strict_sniper_rows
        if not bool((_row or {}).get("_strict_window_eligible"))
    )
    print(f"[SNIPE_STRICT_GUARD] count={_strict_guard_count}")
    _sniper_rows = _bound_board_rows(list(_strict_sniper_rows), append_tag="strict_sniper_rows")
    _watchlist_rows = _bound_board_rows(
        list(_strict_prepare_rows) + list(_spillover_prepare_rows) + list(_strict_other_watch_rows),
        append_tag="strict_watchlist_rows",
    )
    _monitor_rows = _bound_board_rows(list(_strict_monitor_rows), append_tag="strict_monitor_rows")
    _surface_suppressed_watch_rows: List[Dict[str, Any]] = []
    _surface_allowed_watch_rows: List[Dict[str, Any]] = []
    for _row in _watchlist_rows:
        _stamped = _stamp_final_surface_gate(_row, emit_log=True)
        _row.update(_stamped)
        if int(_row.get("final_surface_allowed") or 0) > 0:
            _surface_allowed_watch_rows.append(_row)
        else:
            _surface_suppressed_watch_rows.append(_row)
            print(
                f"[FINALIZER_DROP_TRACE] title={str(_row.get('title') or _row.get('source_title') or '')[:120]} "
                f"sport={_final_board_sport(_row) or 'UNKNOWN'} "
                f"reason={str(_row.get('final_surface_reason') or 'final_surface_gate')}"
            )
    _watchlist_rows = _bound_board_rows(list(_surface_allowed_watch_rows), append_tag="surface_allowed_watch_rows")
    if _surface_suppressed_watch_rows:
        _monitor_rows = _bound_board_rows(
            list(_monitor_rows) + list(_surface_suppressed_watch_rows),
            append_tag="surface_suppressed_monitor_rows",
        )
    # ── FINAL BOARD SORT ─────────────────────────────────────────────────────────
    # EXECUTE_NOW dominates hero slots. Within tier: urgency first, edge second.
    # A $150-edge card ending in 20 minutes beats a $200-edge card ending tomorrow.
    def _board_sort_key(_r: Dict[str, Any]) -> tuple:
        return (
            int(_r.get("_board_tier_rank") or 2),
            -int(_r.get("_urgency_weight") or 0),
            -float(_r.get("edge_dollars") or (_r.get("action_summary") or {}).get("expected_profit") or 0.0),
        )
    _non_fast_sniper_rows = [_row for _row in _sniper_rows if not bool((_row or {}).get("fast_snipe_candidate"))]
    _non_fast_sniper_rows.sort(key=_board_sort_key)
    _sniper_rows = list(_fast_sniper_rows) + list(_non_fast_sniper_rows)
    _strict_prepare_rows.sort(key=_board_sort_key)
    _strict_other_watch_rows.sort(key=_board_sort_key)
    _spillover_prepare_rows.sort(key=_spillover_prepare_rank_key)
    _watchlist_rows = _bound_board_rows(
        list(_strict_prepare_rows) + list(_spillover_prepare_rows) + list(_strict_other_watch_rows),
        append_tag="sorted_watchlist_rows",
    )
    _sport_floor_pool: List[Dict[str, Any]] = []
    _sport_floor_pool.extend(list(_sniper_rows or []))
    _sport_floor_pool.extend(list(_watchlist_rows or []))
    _sport_floor_pool.extend(list(_monitor_rows or []))
    _sport_floor_pool.extend(list(_final_sniper_rows or []))
    _sport_floor_pool.extend(list(_final_watchlist_rows or []))
    _sport_floor_pool.extend(list(_final_monitor_rows or []))
    _sport_floor_pool.extend(list(filtered_auctions or []))
    if "_admission_candidates" in locals():
        _sport_floor_pool.extend(list(_admission_candidates or []))
    _sport_preserved_rows, _sport_leftover_rows = _preserve_cross_sport_survivors(_sport_floor_pool)
    _visible_ids = {
        _cross_sport_row_id(_row)
        for _row in (_sniper_rows + _watchlist_rows + _monitor_rows)
    }
    for _row in _sport_preserved_rows:
        _rid = _cross_sport_row_id(_row)
        if _rid in _visible_ids:
            continue
        if not _board_authoritative_auction_gate(_row, append_tag="cross_sport_preserved"):
            continue
        _visible_ids.add(_rid)
        _bucket = str(_row.get("execution_admission_bucket") or _row.get("final_bucket") or "").strip().lower()
        if _bucket in {"sniper", "snipe", "execute_now", "execute now"}:
            _append_bound_board_row_to_many([_sniper_rows, _final_sniper_rows], _row, append_tag="cross_sport_preserved_sniper")
        elif _bucket == "monitor":
            _append_bound_board_row_to_many([_monitor_rows, _final_monitor_rows], _row, append_tag="cross_sport_preserved_monitor")
        else:
            _stamp_live_watchlist_route(_row, reason="cross_sport_preserved")
            _append_bound_board_row_to_many([_watchlist_rows, _final_watchlist_rows], _row, append_tag="cross_sport_preserved_watchlist")
    _board_fill_source_mix = (
        f"strict_snipe={len(_sniper_rows)} "
        f"strict_prepare={len(_strict_prepare_rows)} "
        f"strict_monitor={len(_monitor_rows)} "
        f"spillover_prepare={len(_spillover_prepare_rows)} "
        f"other_watch={len(_strict_other_watch_rows)}"
    )
    print(
        f"[BOARD_FILL_FLOOR] strict_visible={_strict_visible_count} "
        f"final_visible={len(_sniper_rows) + len(_strict_prepare_rows) + len(_monitor_rows) + len(_spillover_prepare_rows)} "
        f"floor={_ES_VISIBLE_BOARD_FLOOR} source_mix={_board_fill_source_mix}"
    )
    _logged_board_sources: set[str] = set()
    for _row in _sniper_rows + _watchlist_rows + _monitor_rows:
        _row_id = str(_row.get("item_id") or _row.get("source_item_id") or id(_row))
        _row_source = _stamp_board_row_source(_row)
        if _row_id in _logged_board_sources:
            continue
        _logged_board_sources.add(_row_id)
        if _row_source.startswith("fresh"):
            print(
                f"[FRESH_ROW] source={_row_source} "
                f"title={str(_row.get('title') or '')[:120]}"
            )
        else:
            print(
                f"[RESCUED_ROW] source={_row_source} "
                f"title={str(_row.get('title') or '')[:120]}"
            )
    _existing_render_ids = {
        str(_d.get("item_id") or _d.get("source_item_id") or id(_d))
        for _d in (_sniper_rows + _watchlist_rows + _monitor_rows)
    }
    forced_monitor_rows: List[Dict[str, Any]] = []
    normal_rows: List[Dict[str, Any]] = []
    for _row in _main_visible_rows:
        _rid = str(_row.get("item_id") or _row.get("source_item_id") or id(_row))
        if _rid in _existing_render_ids:
            normal_rows.append(_row)
            continue
        if _render_monitor_row(_row):
            _row["_final_bucket"] = "MONITOR"
            _row["_monitor_reason"] = "true_mv_but_over_market"
            _row["main_board_pool"] = "main_visible_rows"
            _row["execution_admission_bucket"] = "monitor"
            _row["commercial_visibility"] = "monitor"
            _row["commercially_visible"] = True
            _row["board_visible"] = True
            forced_monitor_rows.append(_row)
            print(
                f"[REAL_RENDER_MONITOR] title={str(_row.get('title') or '')[:120]} "
                f"true_mv={_row.get('true_market_value')} bid={_row.get('target_bid')}"
            )
        else:
            normal_rows.append(_row)
    if forced_monitor_rows:
        for _row in forced_monitor_rows:
            _append_bound_board_row_to_many(
                [_monitor_rows, _watchlist_rows, _final_monitor_rows],
                _row,
                append_tag="forced_monitor_rows",
            )
    _watchlist_rows.sort(
        key=lambda _row: (
            0 if str(_stamp_board_row_source(_row)) == "fresh_premium" else 1 if str(_stamp_board_row_source(_row)).startswith("fresh") else 2,
            -float(_row.get("execution_admission_score") or 0.0),
            -float(_row.get("sniper_board_score") or 0.0),
            float(_row_remaining_seconds(_row) or 999999.0),
        )
    )
    _fresh_premium_rows = [
        _row for _row in (_sniper_rows + _watchlist_rows + _monitor_rows)
        if str(_stamp_board_row_source(_row)) == "fresh_premium"
    ]
    _rescued_render_rows = [
        _row for _row in _watchlist_rows
        if str(_stamp_board_row_source(_row)).startswith("rescued")
    ]
    print(f"[FRESH_PREMIUM_COUNT] count={len(_fresh_premium_rows)} rescued={len(_rescued_render_rows)}")
    if _fresh_premium_rows:
        print(
            f"[BOARD_PRIORITY_FRESH] fresh={len(_fresh_premium_rows)} "
            f"rescued={len(_rescued_render_rows)}"
        )
